INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(310835, 'koKR', '', '의외로 로르테마르는... 수긍하는 눈치였습니다. 음.\n\n영원노래 숲의 안전은 이웃과의 좋은 관계에 달려 있다는 말에 설득이 된 걸지도 모르겠습니다. 그 이웃이 누구든 간에 말이죠.', 66384),
(310653, 'koKR', '', '칸자가 불꽃돌이를 쓰다듬습니다.', 66384),
(310490, 'koKR', '다친 데 없이 성하게 도착했다니 정말 다행이군!\n\n고마워. 잠깐 앉아서 쉬는 건 어떻겠어?\n\n온종일 뛰어다니다 보면 삶의 소소한 것들이 그리워지곤 하거든.', '다친 데 없이 성하게 도착했다니 정말 다행이군!\n\n고마워. 잠깐 앉아서 쉬는 건 어떻겠어?\n\n온종일 뛰어다니다 보면 삶의 소소한 것들이 그리워지곤 하거든.', 66384),
(310484, 'koKR', '<혼자 공포에 질려 있는 새끼 카파라>', '', 66384),
(310480, 'koKR', '근데 부탁 하나만 들어주겠나?\n\n저기 마지막 하나 남은 새끼 카파라가 겁을 단단히 먹은 탓에, 온 세상이 두려운 것마냥 웅크리고 있거든. 아무리 달래도 나오질 않아. 녀석을 필로의 제단으로 데려가 줄 수 있겠나? 마음껏 놀 수 있는 좋은 웅덩이를 찾아 줘.\n\n특히 덩치 큰 생물을 무서워하니, 탈것을 타고 가기는 어려울 거야. 걸어서 데려가야 하니 꽤 긴 여정이 되겠지...\n\n마음만 같아서는 같이 가고 싶은데, 이 꼬마들을 두고 자리를 비울 수가 없어서 말이야!', '근데 부탁 하나만 들어주겠나?\n\n저기 마지막 하나 남은 새끼 카파라가 겁을 단단히 먹은 탓에, 온 세상이 두려운 것마냥 웅크리고 있거든. 아무리 달래도 나오질 않아. 녀석을 필로의 제단으로 데려가 줄 수 있겠나? 마음껏 놀 수 있는 좋은 웅덩이를 찾아 줘.\n\n특히 덩치 큰 생물을 무서워하니, 탈것을 타고 가기는 어려울 거야. 걸어서 데려가야 하니 꽤 긴 여정이 되겠지...\n\n마음만 같아서는 같이 가고 싶은데, 이 꼬마들을 두고 자리를 비울 수가 없어서 말이야!', 66384),
(310265, 'koKR', '<어린아이 손에 맞을 법한 단검이 부러진 채로 커다란 뿔개구리와 작은 카파라 사체 옆에 놓여 있습니다.\n\n개구리에 여러 카파라의 이빨 자국과, 근처의 부러진 단검처럼 다급하지만 작은 무기 자국이 수십 개 남아 있습니다.\n\n카파라의 발자국과 작은 트롤 아이의 발자국이 개구리 쪽으로 갔다가 다시 돌아간 흔적이 있으며, 개구리가 아이와 카파라들의 산책을 방해한 것으로 보입니다.\n\n누군가가 죽은 카파라 주위에 꽃을 놓아두었는데, 죽음을 추모하는 의미인 듯합니다.\n\n아이의 발자국은 길에서 벗어나 강 쪽으로 이어지며, 따라가는 카파라의 수는 하나 줄어 있습니다.>', '<어린아이 손에 맞을 법한 단검이 부러진 채로 커다란 뿔개구리와 작은 카파라 사체 옆에 놓여 있습니다.\n\n개구리에 여러 카파라의 이빨 자국과, 근처의 부러진 단검처럼 다급하지만 작은 무기 자국이 수십 개 남아 있습니다.\n\n카파라의 발자국과 작은 트롤 아이의 발자국이 개구리 쪽으로 갔다가 다시 돌아간 흔적이 있으며, 개구리가 아이와 카파라들의 산책을 방해한 것으로 보입니다.\n\n누군가가 죽은 카파라 주위에 꽃을 놓아두었는데, 죽음을 추모하는 의미인 듯합니다.\n\n아이의 발자국은 길에서 벗어나 강 쪽으로 이어지며, 따라가는 카파라의 수는 하나 줄어 있습니다.>', 66384),
(310237, 'koKR', '장비를 준비하느라 바쁜 거 안 보이나?', '', 66384),
(310202, 'koKR', '', '사정은 아라토르에게 들었어요. 투랄리온은...\n\n<알레리아의 얼굴에 순간 고뇌가 스쳐 지나갑니다.>\n\n대체 왜 말해주지 않은 걸까요? 이 긴 시간이 흐르도록?', 66384),
(310200, 'koKR', '아마니 고개에서 있었던 일을 알레리아에게 알리는 건, 잘아타스를 쓰러뜨린 뒤에 하고 싶었습니다.\n\n강대한 적과의 결전을 앞두고 마음이 어지러워선 안 될 일이니까요.', '', 66384),
(310045, 'koKR', '잘 지냈나, $n?', '', 66384),
(310030, 'koKR', '', '도울 일이라도 있나, $n?', 66384),
(309797, 'koKR', '환영하네, 하쉬우라. 우리 마른나무껍질은 할라지의 총아를 감사한 마음으로 맞이한다네.', '', 66384),
(309796, 'koKR', '할라지께서는 마른나무껍질 절벽에서 당신의 은혜가 도움이 된 것에 대해 만족하고 계신다네.\n\n이젠 자네를 돕고 싶어 하시지. 다만, 자네가 먼저 그분을 도와야 하네, 하쉬우라.\n\n할라지께서는 당신을 돕는 게 곧 자네에게 도움이 될 거라고 생각하시더군!', '', 66384),
(309775, 'koKR', '아... 독의 어머니를 알고 싶다는 건가? 좋네.\n\n그 이름은 트롤의 수많은 분파와 부족 전체에 알려져 있지. 전쟁 때마다 지나치게 자주 불려 오는데, 아무래도 그분의 독은 신들도 두려워할 정도니 어쩔 수 없지.\n\n그래도 선조들의 이야기에 따르면 샤드라의 근간은 아마니에 있다네. 그래서 할라지나 필로만큼 그분을 향한 신앙을 지키는 이들도 많지.\n\n수년 전에 샤드라께서 세상을 떠났다는 소문이 돌았었네. 하지만 훨씬 전에도 같은 소문이 돈 적 있었지. 거미줄을 엮어 몸을 감춰도, 죽음은 어떻게든 샤드라를 찾아내는 것 같더군.', '', 66384),
(309774, 'koKR', '무시무시한 깜짝도마뱀의 형상을 한 모트암라는 전염병의 로아일세.\n\n모트암라와 쿨지는 한 칼날의 양면과도 같지. 전염병이 퍼지면 해독제도 퍼지기 마련이니까. 의술과 약초채집, 연금술, 독에 관심이 많은 이들은 깜짝도마뱀 로아도 함께 모신다네.\n\n신도들이 부서진 왕좌 아래 복잡한 납골당에 있는 단출한 사원으로 향했다고 하던데... 어쩌면 끔찍한 공허의 침략자들에게 맞서고 있는 건 아닐까?', '', 66384),
(309773, 'koKR', '일단 \"위기\"가 무엇인지부터 생각해야 해.\n\n하쉬우라여, 위기는 곧 기회라네.\n\n믿기 어렵겠지만 바다의 낚시꾼들이야말로 위험과 기회의 경계에 서 있는 자들이라고 생각해.\n\n더 멀리 나아가야만, 믿기 어려운 물고기를 잡을 기회를 얻으니까.', '', 66384),
(309759, 'koKR', '장인부터 농부까지 많은 이가 풍요의 로아를 모신다네. 자네가 자격을 갖춘 신도라면 대우받겠지만, 그렇지 않다면 흙 한 줌과 다르지 않지.\n\n번성의 향기가 바람을 타고 날아와 코끝을 자극하는 것도 시간문제라고 하더군!', '', 66384),
(309757, 'koKR', '자네가 의술이나 약초채집, 연금술을 익혔다면 쿨지는 저 북쪽의 제단에서 늘 자네를 지켜보고 계실 것이야. 내가 그 길을 걸어본 적은 없지만, 도루 장로가 그 모습을 묘사해 준 적 있네.\n\n저 멀리 아마니자르가 나무들 사이로 고개를 내미는 하늘다리를 한눈에 볼 수 있다더군.', '', 66384),
(309754, 'koKR', '위대한 매머드는 고향을 떠나는 아마니를 굽어살피시지.\n\n그분과 동족의 보살핌이 없었다면 우리는 사냥이나 순례, 마을 교역에 나설 때마다 겁먹은 카파라처럼 떨고 있었을 게야.', '', 66384),
(309748, 'koKR', '역사가들의 말로는 오에께서 우리가 사막의 전장을 지나 이 줄아만의 길들지 않은 땅에 이르기까지 지켜줬다고 하시네. 우리는 그 모습을 보지 못했고, 알지도 못했지. 하지만 분명 있었다네.\n\n지금 오에를 모시는 이들은 사당이나 제단도 아닌 거대한 소나무 아래에서만 기도를 올린다고 하더군.\n\n오에께서 성장의 영혼을 먹고 거대해진다 말하지만, 나무가 욕심을 부려 영혼을 과하게 들이켜면... 생명을 얻은 듯 날뛰며 광포하게 행동한다고 하네.', '', 66384),
(309747, 'koKR', '필로의 제단은 따뜻한 온천이 있는 작은 섬일세. 마이사라 늪지대 너머 세쌍둥이 섬 중 가장 남쪽에 있지.\n\n아마 자네는 그 모습을 직접 보진 못할 게야. 두세 명의 아이가 옷에 들어가 겹쳐 서 있는 게 아니라면 말이야.', '', 66384),
(309718, 'koKR', '섭정 각하의 명에 따라, 실버문의 경계 수준은 격상되었소.\n\n북쪽에서는 공허가, 남쪽에서는 빛만개가 사방에서 우리 도시를 압박하고 있소. 함선과 용매는 그대처럼 쿠엘탈라스를 수호하는 이들에게 우선적으로 할당될 것이오.\n\n민간인이 도시를 떠나려면 반드시 차원문을 경유해야 하오.', '섭정 각하의 명에 따라, 실버문의 경계 수준은 격상되었소.\n\n북쪽에서는 공허가, 남쪽에서는 빛만개가 사방에서 우리 도시를 압박하고 있소. 함선과 용매는 그대처럼 쿠엘탈라스를 수호하는 이들에게 우선적으로 할당될 것이오.\n\n민간인이 도시를 떠나려면 반드시 차원문을 경유해야 하오.', 66384),
(309717, 'koKR', '훈련을 따라가느라 정신이 없지만, 내 가마솥을 사용하고 싶으면 마음대로 하시오.', '', 66384),
(309716, 'koKR', '', '우리가 이곳 지상에서 벌인 일의 결과를 장로들이 이해하려면 시간이 좀 걸릴 걸세.\n\n그래도 안심하게나, $n. 자넨 우리 하란다르가 마주한 위협을 알아보지 못할 때도 도움을 줬어. 이 은혜를 쉽게 잊진 않을 걸세.\n\n때가 되면 하라니르도 자네의 적들과 맞서 싸우는 데 힘을 보탤 걸세. 내 장담하지.', 66384),
(309702, 'koKR', '<축복의 제단은 휴면 상태입니다.>', '<축복의 제단은 휴면 상태입니다.>', 66384),
(309690, 'koKR', '일단... 일단 아이들이라도 내보내야 해.\n\n차원문을 사용한다든지? \n\n수라마르가 우리한테 빚진 게 있잖아.', '일단... 일단 아이들이라도 내보내야 해.\n\n차원문을 사용한다든지? \n\n수라마르가 우리한테 빚진 게 있잖아.', 66384),
(309689, 'koKR', '아마니와 이교도가 남쪽에서 올라오고 있다고 들었어. 대피하기엔 너무 늦은 건가?\n\n어디로 도망치지?', '아마니와 이교도가 남쪽에서 올라오고 있다고 들었어. 대피하기엔 너무 늦은 건가?\n\n어디로 도망치지?', 66384),
(309678, 'koKR', '', '아군과 그 아군의 적의 관계를 이해하는 건 비늘사령관의 책무다. 그런데 이 세계에서 각축전을 벌이는 세력들에 대해 많이 배웠다고 생각하는데도, 막상 이곳에 오니 생각이 많이 흔들리는군.\n\n얼라이언스든 호드든, 어느 쪽에도 속하지 않은 자들이든, 이들은 증오나 소속이 아니라 좋은 술과 음식, 대화를 향한 건전한 갈증을 품고 있을 뿐이다.\n\n많은 금지된 해안의 드랙티르가 민간인의 삶을 택한 이유를 조금은 알 것 같다. 아주라텔은 아직 이해 못 하는 눈치지만, 언젠가는 알게 되겠지. 깃발이나 신념, 웨이른을 떠나, 우린 모두 드랙티르니까.', 66384),
(309677, 'koKR', '점점 더 많은 동족이 민간인의 삶을 받아들이고 있다는 건 알지만, 솔직히... 난 아직 완전히 이해하지는 못하겠다.\n\n병사가 무기를 내려놓고 평범하게 살아간다는 건 절대 쉬운 일이 아니니까. 그런데 이곳에서는 많은 영웅이 바로 그 선택을 하고 있더군. \"인생\"을 살고 있어! 낯설면서도 흥미로운 발상이다. 비록 내가 온전히 받아들이지는 못한다 해도 말이지.\n\n흑요석 수호병단에게도 병사의 삶이 아닌 다른 길이 있다는 걸 보여줘야 할지도 모르겠다. 자신들의 비늘사령관이 잠시 숨을 고르는 모습을 보여주면, 다른 이들도 뒤따르지 않겠나.', '', 66384),
(309669, 'koKR', '$n 님! 대총독님과 얘기 나누셨습니까? 장군과는요?\n\n언제 진군할지 알고 계십니까? 이 상태는... 이대로 오래 지속될 수 없습니다.', '$n 님! 대총독님과 얘기 나누셨습니까? 장군과는요?\n\n언제 진군할지 알고 계십니까? 이 상태는... 이대로 오래 지속될 수 없습니다.', 66384),
(309668, 'koKR', '아르거스 이후로, 이토록 정당한 싸움은 없었습니다. 선과 악의 대립. 모호함도, 타협도 없습니다.\n\n우리는 적의 요새에서 파멸을 안기고 단죄할 것입니다. 우리에게 필요한 건 단 하나, 공격할 기회를 열어 줄 길입니다.', '아르거스 이후로, 이토록 정당한 싸움은 없었습니다. 선과 악의 대립. 모호함도, 타협도 없습니다.\n\n우리는 적의 요새에서 파멸을 안기고 단죄할 것입니다. 우리에게 필요한 건 단 하나, 공격할 기회를 열어 줄 길입니다.', 66384),
(309667, 'koKR', '또 다른 원정대가 공허폭풍으로 날아들다 궤멸했다고 들었습니다. 빛으로 놈들을 몰아낼 수는 있지만, 하늘에 뚫린 틈을 통해 적의 영토로 진격하는 길은 현재 막혀 있는 듯합니다.\n\n괜찮습니다. 우리의 위대한 지도자들께서 병력을 공허폭풍 안으로 들일 방법을 반드시 찾아내실 것이라 믿습니다.', '또 다른 원정대가 공허폭풍으로 날아들다 궤멸했다고 들었습니다. 빛으로 놈들을 몰아낼 수는 있지만, 하늘에 뚫린 틈을 통해 적의 영토로 진격하는 길은 현재 막혀 있는 듯합니다.\n\n괜찮습니다. 우리의 위대한 지도자들께서 병력을 공허폭풍 안으로 들일 방법을 반드시 찾아내실 것이라 믿습니다.', 66384),
(309666, 'koKR', '빛께 감사드립니다. 우리 모두 함께 이곳으로 소환되었고, 다른 교단에서 신념을 수호하는 방패들도 나란히 서 있습니다.\n\n이제 우리는 단순한 빛의 군대가 아니라, 선봉대입니다. 장엄하면서도 두렵지 않습니까, 용사님?\n\n만물의 종말에 맞서 어깨를 나란히 할 날을 고대하고 있습니다.', '빛께 감사드립니다. 우리 모두 함께 이곳으로 소환되었고, 다른 교단에서 신념을 수호하는 방패들도 나란히 서 있습니다.\n\n이제 우리는 단순한 빛의 군대가 아니라, 선봉대입니다. 장엄하면서도 두렵지 않습니까, 용사님?\n\n만물의 종말에 맞서 어깨를 나란히 할 날을 고대하고 있습니다.', 66384),
(309643, 'koKR', '', '네 지역 가운데, 진정으로 풍요로울 수 있는 곳은 하나뿐이라네.\n\n어느 지역이 풍요 상태에 들면, 풍요의 군주 둔둔께서 가장 희귀한 보물을 내려주시지. 바로 순수한 풍요라네.\n\n그 보상을 받으려면, 먼저 노고를 증명해야 하지. 둔둔의 조각 하나를 그분께 바치게.\n\n둔둔의 조각은 로아의 힘이 부서져 나온 조각일세. 전문 기술 물품을 제작하거나 풍요 지역에 있는 광석, 약초, 가죽, 물고기를 채집하다 보면 얻을 수 있지.\n\n줄아만에서는 이 조각이 더 흔한 편이라네. 숨겨진 보물 속에서, 혹은 희귀한 야수의 사체에서 발견할 수도 있을 걸세!', 66384),
(309642, 'koKR', '우리의 공허 엘프 동맹은 현재 공허폭풍에 위태로운 거점을 구축하고 있소. 가서 공허 엘프가 끝없는 적에 맞서 입지를 굳히는 데 힘을 보태시오.', '', 66384),
(309641, 'koKR', '그대가 하란다르에서 맹활약을 펼친 덕분에 앙갚음 걱정 없이 하라니르와 어깨를 나란히 할 기회를 얻었소. 아주 소중한 기회지. 하라니르의 이야기와 전통에서 배울 것이 많으리라 생각하오.\n\n가서 배우고, 그 뒤에 내게 돌아오시오.', '', 66384),
(309640, 'koKR', '아마니는 자연에서 온갖 자원을 추출하는 방법을 발견했소. 나는 도시의 안락함을 선호하는 편이지만, 동맹이 제공할 수 있는 것을 외면하는 건 분명 낭비일 것이오.\n\n설령 손이 조금 지저분해지는 일이라도 말이오.', '', 66384),
(309639, 'koKR', '살데릴의 연회는... 다소 복잡한 행사요. 상류 사회, 극적인 소란까지. 그렇다 해도, 영원노래 숲을 질서정연하고 평온하게 유지하는 데 이바지하고 있는 자들인 것도 사실이지. 가서 방비를 거드는 것이 좋겠소.', '', 66384),
(309634, 'koKR', '세상으로 나가 적을 찾아 맞서 싸우시오! 우리의 적은 셀 수 없이 많지만, 아군 또한 적지 않소. 힘이 닿는 데까지 그대의 방식으로 아군을 도우시오.\n\n물론, 그 이후에는 나에게 보고하도록 하시오.', '', 66384),
(309633, 'koKR', '', '풍요의 축복은 자네를 강화하고, 채집과 기여를 거듭할수록 성장한다네.\n\n어떤 방식으로든 풍요를 채집하면, 자네의 기본 능력이 강화되지. 이동 속도나 전투력 같은 능력치 말일세.\n\n풍요를 충분히 기여하면, 축복 자체가 진화한다네. 더 먼 거리에서도 풍요의 구슬을 채집할 수 있고, 한 번에 보유할 수 있는 풍요의 양도 늘어나며, 기본 능력치 증가량도 상승하지.\n\n다만 연약한 필멸자의 육신으로는 이 힘을 오래 유지할 수 없네. 풍요의 지역에 들어설 때마다 축복이 새롭게 부여된다네.', 66384),
(309631, 'koKR', '', '자네가 채집한 풍요는 어느 풍요의 제단에서든 기여할 수 있다네.\n\n기여된 모든 풍요는 둔둔 님께 전달되어, 다른 수행사제들의 기여분과 함께 모이게 되지.\n\n충분한 양이 모이면, 로아께서 이 자리에 있는 모두에게 장엄한 보상을 내려주신다네!', 66384),
(309630, 'koKR', '', '풍요는 생명체를 처치하거나 약초나 광석 같은 자원 지점을 채집해 얻을 수 있다네.\n\n생성된 모든 풍요는 로아의 힘을 통해 구슬로 응집되지. 가까이 다가가기만 해도 자동으로 수집된다네.\n\n지금 얼마나 지니고 있는지는 풍요 가방을 확인하면 알 수 있을 걸세.', 66384),
(309623, 'koKR', '', '구체적으로 말하자면?', 66384),
(309622, 'koKR', '', '번영이 함께하길, 수행사제여.\n\n필요한 거라도 있나?', 66384),
(309612, 'koKR', '로서의 후예들이 이곳에 돌아오는 일이 쉽지 않다는 건 알고 있네만, 여기에 꼭 필요한 물건이 있네.', '', 66384),
(309607, 'koKR', '수년간 섭정을 지지해 왔어.\n\n하지만 이젠 파멸의 예언자들의 말이 더 설득력 있게 들리기 시작할 지경이야.', '수년간 섭정을 지지해 왔어.\n\n하지만 이젠 파멸의 예언자들의 말이 더 설득력 있게 들리기 시작할 지경이야.', 66384),
(309606, 'koKR', '그림자 속에서 목소리를 들었어. 공허가 와 있단 말이야.\n\n놈들은 하늘에만 있는 게 아니야. 이 주변을 기어다니고 있어. 어디에나.\n\n보고 있지 않으면, 그림자가 움직여.', '그림자 속에서 목소리를 들었어. 공허가 와 있단 말이야.\n\n놈들은 하늘에만 있는 게 아니야. 이 주변을 기어다니고 있어. 어디에나.\n\n보고 있지 않으면, 그림자가 움직여.', 66384),
(309605, 'koKR', '하늘이 무너지고 있어. 말 그대로 하늘이 떨어지고 있다고.\n\n왜 이 상황을 심각하게 여기지 않는 거야?!', '하늘이 무너지고 있어. 말 그대로 하늘이 떨어지고 있다고.\n\n왜 이 상황을 심각하게 여기지 않는 거야?!', 66384),
(309604, 'koKR', '우리가 가진 모든 걸 빛의 선봉대에 내놓으라잖아!\n\n뭘 보고 믿으라는 거지? 많은 수가 한때 얼라이언스를 섬겼고, 지금도 그렇잖아!', '우리가 가진 모든 걸 빛의 선봉대에 내놓으라잖아!\n\n뭘 보고 믿으라는 거지? 많은 수가 한때 얼라이언스를 섬겼고, 지금도 그렇잖아!', 66384),
(309603, 'koKR', '우린 오늘 이곳에 서기까지, 눈 깜짝할 사이에 믿기 어려운 거리를 넘어왔습니다. 빛 그 자체의 뜻에 이끌려, 이 장소를 지키기 위해서 말입니다.\n\n이렇게 뵙게 되어 영광입니다, 용사 $p 님. 당신 역시 빛의 부름을 받았다는 사실이 큰 힘이 됩니다.', '우린 오늘 이곳에 서기까지, 눈 깜짝할 사이에 믿기 어려운 거리를 넘어왔습니다. 빛 그 자체의 뜻에 이끌려, 이 장소를 지키기 위해서 말입니다.\n\n이렇게 뵙게 되어 영광입니다, 용사 $p 님. 당신 역시 빛의 부름을 받았다는 사실이 큰 힘이 됩니다.', 66384),
(309594, 'koKR', '잠시 쉬고 있었습니다, 용사님.\n\n얼마 전에 태양샘에 제가 가진 모든 마력을 쏟아부었고, 잠시 숨을 돌릴 시간을 얻었습니다.\n\n하지만 이 도시는 제가 기대한 안식처는 아닌 듯합니다.', '잠시 쉬고 있었습니다, 용사님.\n\n얼마 전에 태양샘에 제가 가진 모든 마력을 쏟아부었고, 잠시 숨을 돌릴 시간을 얻었습니다.\n\n하지만 이 도시는 제가 기대한 안식처는 아닌 듯합니다.', 66384),
(309593, 'koKR', '사실 빛을 다루는 이들이 충분하진 않습니다. 거의 전원이 이곳에 모여 있지만, 영혼 깊은 곳에서 지금 상태로는 부족하다는 걸 알고 있습니다.\n\n그래도 이 전쟁에 우리가 가진 모든 것을 바칠 것입니다.', '사실 빛을 다루는 이들이 충분하진 않습니다. 거의 전원이 이곳에 모여 있지만, 영혼 깊은 곳에서 지금 상태로는 부족하다는 걸 알고 있습니다.\n\n그래도 이 전쟁에 우리가 가진 모든 것을 바칠 것입니다.', 66384),
(309592, 'koKR', '공허는 실버문과 쿠엘탈라스 전역을 집어삼키려 할 것입니다. 그리고 아무것도 남지 않을 때까지 멈추지 않겠지요.\n\n여긴 이 세계의 교두보입니다. 어떤 희생을 치르더라도 반드시 부숴야 합니다.', '공허는 실버문과 쿠엘탈라스 전역을 집어삼키려 할 것입니다. 그리고 아무것도 남지 않을 때까지 멈추지 않겠지요.\n\n여긴 이 세계의 교두보입니다. 어떤 희생을 치르더라도 반드시 부숴야 합니다.', 66384),
(309591, 'koKR', '실버문 시민들을 생각하면 마음이 무겁습니다. 이미 너무 많은 고통을 겪었으니까요.\n\n빛과 공허가 맞부딪히는 최전선에 보금자리를 두고 산다는 것이 결코 쉬울 리 없겠지요.\n\n우리가 어떤 대가를 치르더라도 아제로스를 지키려 애쓰는 동안, 그분들의 신념이 끝까지 버텨 주기만을 바랄 뿐입니다.', '실버문 시민들을 생각하면 마음이 무겁습니다. 이미 너무 많은 고통을 겪었으니까요.\n\n빛과 공허가 맞부딪히는 최전선에 보금자리를 두고 산다는 것이 결코 쉬울 리 없겠지요.\n\n우리가 어떤 대가를 치르더라도 아제로스를 지키려 애쓰는 동안, 그분들의 신념이 끝까지 버텨 주기만을 바랄 뿐입니다.', 66384),
(309587, 'koKR', '', '망치 주둔지에 보탬이 될 걸세, $p. 고맙네.', 66384),
(309584, 'koKR', '', '무슨 일인가, $c 친구?', 66384),
(309557, 'koKR', '더는 혈기사로서 버틸 수 없을 것 같습니다.\n\n끝이 보이지 않는 훈련, 매번 얻어맞고 쓰러지는 나날, 선스트라이커 교관님의 호된 꾸중까지... 이젠 저한테 혈기사가 될 자격이 남아 있는지조차 모르겠습니다. 매일 그만두고 싶다는 생각뿐이고, 지금 이 순간에도 임무를 피하려 숨어 있습니다.\n\n실패자가 된 기분입니다. 위대한 전사가 되겠다고 다짐했는데, 지금은 집으로 돌아가 어머니와 술잔을 기울이며 걱정을 잊고 싶다는 생각밖에 들지 않습니다. 게다가 이 수련을 받으며 쌓인 빚을 떠올리면 더더욱 그렇습니다.\n\n절 응원해 주는 사람들이 있다는 것도 잘 알고 있습니다. 부모님도, 친구들도, 심지어 선스트라이커 교관님조차 제가 성공하길 바라시죠. 그래서 더 괴롭습니다. 제가 그분들을 모두 실망시킨 것만 같아서요.\n\n어디로 가야 할지 모르겠습니다.', '', 66384),
(309536, 'koKR', '서둘러라. 이 가루는 부으면 곧바로 녹기 시작하거든!', '서둘러라. 이 가루는 부으면 곧바로 녹기 시작하거든!', 66384),
(309535, 'koKR', '각 병에 조금씩 붓는 거다. 내가 표시한 선까지 채우면 돼. 용기를 다 채우거든 말해라. 내가 수호물을 완성할 테니.', '각 병에 조금씩 붓는 거다. 내가 표시한 선까지 채우면 돼. 용기를 다 채우거든 말해라. 내가 수호물을 완성할 테니.', 66384),
(309481, 'koKR', '오늘 물살이 영 사납네.', '', 66384),
(309479, 'koKR', '', '아, 몬테. 자네가 상상한 환영과는 다를 거야.', 66384),
(309478, 'koKR', '지상을 정찰하던 이들이 육지와 물, 하늘을 가리지 않고 이동하는 놀라운 생물에 대한 이야기를 들고 돌아왔어.\n\n몸집은 작지만, 섬뜩한 부리를 지녔고 밤마다 울음소리가 멀리까지 울려 퍼진다더군.\n\n그 이야기를 듣고 나니, 그 모습을 본뜬 장난감을 만들지 않을 수 없었지.', '', 66384),
(309476, 'koKR', '난 요즘 장난감을 다시 보충하고 있어. 원래 무기가 대부분이었는데, 죄다 젊은 친구들 손에 들어가 버렸거든.\n\n<흐뭇한 표정으로 웃는 임하요>', '', 66384),
(309448, 'koKR', '아, 이 근육은 신경 쓰지 마세요. 주문이 뜻대로 움직여주지 않을 때가 있잖아요. 그럴 때는... 뭔가 말을 들어주는 게 있어야죠.\n\n그래요, 알아요. 힘에 의지하는 블러드 엘프라니, 별종이죠. 제 스승님들도 누구보다 경악했어요. 하지만 전 제대로 된 주문을 시전할 수 있게 되기도 전에 연습용 허수아비를 더 많이 박살 냈어요. 그래서 몸을 단련하는 길을 택했죠.\n\n언젠가는 마법 실력도 올라올 거예요. 그때까지는 공중 부양으로 띄울 수 없는 것들을 제 손으로 들어 올릴 뿐입니다.', '', 66384),
(309432, 'koKR', '사실... 저는 예전부터 할아버지를 정말 깊이 따랐습니다.\n\n어릴 때 부모님은 바쁘실 때가 잦았습니다. 책무에, 기대에, 끝없는 요구까지. 딱히 원망하는 건 아니지만, 그래서 누이와 전 거의 할아버지 손에서 자랐습니다.\n\n제게 처음 비전 마법을 가르쳐주신 분도 할아버지였고, 언젠가는 자신을 능가할 거라며 말씀하시던 모습이 떠오릅니다.\n\n그분 이야기를 꺼내는 것만으로도 곁에 함께 있는 것 같습니다. 그분의 기억이 아직 제 안에서 빛처럼 남아 있는 것처럼요.', '', 66384),
(309378, 'koKR', '도움이 필요하십니까?', '도움이 필요하십니까?', 66384),
(309330, 'koKR', '', '연구를 도우러 오셨습니까?', 66384),
(309291, 'koKR', '', '반갑습니다. 무두질에 대한 지도가 필요하십니까?', 66384),
(309290, 'koKR', '', '반갑습니다. 약초채집에 대한 지도가 필요하십니까?', 66384),
(309289, 'koKR', '반갑습니다. 마법부여에 대한 지도가 필요하십니까?', '', 66384),
(309288, 'koKR', '', '반갑습니다. 재봉술에 대한 지도가 필요하십니까?', 66384),
(309287, 'koKR', '반갑습니다. 보석세공에 대한 지도가 필요하십니까?', '', 66384),
(309286, 'koKR', '반갑습니다. 가죽세공에 대한 지도가 필요하십니까?', '', 66384),
(309285, 'koKR', '', '반갑습니다. 기계공학에 대한 지도가 필요하십니까?', 66384),
(309284, 'koKR', '반갑습니다. 대장기술에 대한 지도가 필요하십니까?', '', 66384),
(309283, 'koKR', '', '반갑습니다. 주문각인에 대한 지도가 필요하십니까?', 66384),
(309282, 'koKR', '반갑습니다. 연금술에 대한 지도가 필요하십니까?', '', 66384),
(309271, 'koKR', '이즈켄이 도망간 이유가 사실이었나 보구먼.', '이즈켄이 도망간 이유가 사실이었나 보구먼.', 66384),
(309270, 'koKR', '어미와 자식 관계에 내가 말을 얹으면 안 되겠지.', '어미와 자식 관계에 내가 말을 얹으면 안 되겠지.', 66384),
(309269, 'koKR', '차나는 참 훌륭한 지도자였어. 자식들에게도 좋은 부모였겠지.', '차나는 참 훌륭한 지도자였어. 자식들에게도 좋은 부모였겠지.', 66384),
(309268, 'koKR', '차나 말이 사실이 아니면 좋겠군. 이즈켄이 떠나기 전에 물어봐야겠어.', '차나 말이 사실이 아니면 좋겠군. 이즈켄이 떠나기 전에 물어봐야겠어.', 66384),
(309267, 'koKR', '차나는 우리 모두를 잘 대했어. 저런 말은 믿고 싶지 않아.', '차나는 우리 모두를 잘 대했어. 저런 말은 믿고 싶지 않아.', 66384),
(309266, 'koKR', '고인의 맹렬한 성격 덕분에 많은 아마니가 목숨을 건졌지.', '고인의 맹렬한 성격 덕분에 많은 아마니가 목숨을 건졌지.', 66384),
(309265, 'koKR', '차나가 그런 말을 할 줄은... 하긴, 그 사람을 더 잘 아는 사람이 어디 있겠어?', '차나가 그런 말을 할 줄은... 하긴, 그 사람을 더 잘 아는 사람이 어디 있겠어?', 66384),
(309264, 'koKR', '둘의 어머니는 훌륭한 지도자였지. 보고 싶을 거야.', '둘의 어머니는 훌륭한 지도자였지. 보고 싶을 거야.', 66384),
(309263, 'koKR', '오, 큰 친구 왔네! 꼬질이 신경 쓰지 마! 꼬질이 지금 쉬는 중!\n\n꼬질이 쏜살이랑 같이 왔어. 여기 엄청 바쁘더라! 바쁘면 양초도 계속 새로 켜야 하잖아!\n\n의자에 앉은 회색 인간이 양초랑 횃불은 알아서 켜진다는데, 꼬질이는 알아. 그런 거 마법 아니야.\n\n코볼트들이 갈아 끼우는 거지, 마법이 아니라고!\n\n혹시 살래? 꼬질이 없는 게 없어!', '', 66384),
(309262, 'koKR', '난 인간 선술집을 자주 찾는 편이 아닐세. 술은 밍밍하고, 의자는 삐걱대고. 미샤도... 누가 같이 있는 걸 별로 안 좋아해서 말이야.\n\n하지만 여긴 다르네. 술도 괜찮고, 의자도 튼튼하고. 그리고 미샤는?\n\n<뒤돌아 불가 근처에서 자는 거대한 곰을 힐끗 보는 렉사르>\n\n이곳이 마음에 드는 모양이야. 한두 잔은 더 걸칠 생각일세. 저 문을 열고 들어오는 반가운 얼굴들 보는 것도 좋고.', '', 66384),
(309261, 'koKR', '살아오면서 선술집을 참 많이도 돌아다녔지. 술도 수도 없이 맛봤고, 친구도 많이 사귀었고, 주먹이나 잔이 날아다닌 싸움도 좀 있었다네.\n\n근데 그런 선술집들 중에서도 여기처럼 특별한 곳은 거의 없었지.\n\n<첸이 의자에서 돌려 앉아 손님들을 잠시 훑어보더니, 다시 술을 마시기 시작합니다.>\n\n촌 포가 네 바람의 계곡에서 돌아오면 여기를 소개시켜 줘야겠어. 스톰스타우트 양조장이 아르칸티나만을 위한 특별한 맥주를 만들 수 있을지도 모르잖나, 응?', '', 66384),
(309260, 'koKR', '', '삼촌이 또 \'마법 같은 선술집\'을 찾았다며 꼭 가봐야 한다고 했을 때는 솔직히 반신반의했어요. 삼촌은 마음에 드는 술만 있으면 낡은 가을 축제 천막도 \'마법 같다\'고 하실 분이거든요.\n\n저는 차라리 오빠와 아버지께 네 바람의 계곡을 보여드리고 싶었고요... 근데 이번만큼은 삼촌 말씀을 인정해야겠네요. 여긴 정말 마법 같은 선술집이에요. 막 도착했을 뿐인데 벌써 반가운 얼굴들도 몇 명이나 만났어요!\n\n양조장에서 할 일을 끝내고 나면 가족들도 여기로 데려와 보고 싶어요. 삼촌은 벌써 이곳에만 내놓을 특별한 맥주를 몇 가지 구상하고 계신 것 같기도 하네요.', 66384),
(309259, 'koKR', '', '여긴 참 독특한 곳이지요?\n\n카즈 알가르를 떠난 뒤로 여러 땅을 여행하며 각기 다른 문화와 사람들을 만났습니다.\n\n수많은 이야기와 역사를 들었고, 놀라움으로 가득한 곳도 있었고 갈등으로 얼룩진 곳도 있었지요.\n\n그런데 이곳은, 이렇게 먼 곳에서 온 이들이 한 지붕 아래 모였는데도 단순함과 편안한 기운만이 흐르고 있습니다. 참 놀라울 정도예요. 물론, 저는 이런 분위기가 좋습니다.\n\n<부드러운 미소로 주위를 둘러보는 던>\n\n이번에는 다른 음료를 한번 마셔볼까 합니다.', 66384),
(309210, 'koKR', '저 지금 찌릿구름 연습 중이에요! 지금은 물방울 조금 떨어뜨리는 정도지만요.\n\n언젠가는 모두가 놀랄 만큼 큰 폭풍을 일으켜서, 집안에도 도움이 되고 싶어요.\n\n열심히 연습할게요!', '저 지금 찌릿구름 연습 중이에요! 지금은 물방울 조금 떨어뜨리는 정도지만요.\n\n언젠가는 모두가 놀랄 만큼 큰 폭풍을 일으켜서, 집안에도 도움이 되고 싶어요.\n\n열심히 연습할게요!', 66384),
(309207, 'koKR', '', '이름난 전사들이 모였는데 싸움 한 번 안 난 걸 보면, 내가 처음 어둠의 문을 지나왔던 때와 비교해 아제로스가 많이 달라졌다는 뜻이겠지. 평화를 위해 싸우는 건 고귀한 일이야. 어쩌면 몇몇은 이번에는 평화가 오래 갈 거라 믿고 있을지도 모르지.\n\n하지만 난 진실을 안다. 칼을 한 번 제대로 휘두르면, 왕국 하나쯤은 모래성처럼 무너지기 마련이거든.\n\n전선이 그어지면, 네가 설 곳이 어디인지 확실히 정해. 나는 늘 그렇게 하니까.', 66384),
(309178, 'koKR', '안녕하세요. 저는 애인 라후파를 기다리고 있답니다.\n\n무슨 일로 오셨나요?', '안녕하세요. 저는 애인 라후파를 기다리고 있답니다.\n\n무슨 일로 오셨나요?', 66384),
(309164, 'koKR', '', '공허방랑자 놈에게 공허 엘프를 건드리면 어떻게 되는지 분명히 보여줬군요. 하지만 그놈의 계략 때문에 많은 사람을 잃었어요.\n\n대의를 위해 싸우러 여기 왔지만, 이런 걸 마주하게 될 줄은 몰랐습니다. 이 어둠을 감당할 준비가 되어 있지도 않았고요.\n\n렌도레이는 공허와 얽혀 있지만, 그걸 후회하진 않습니다. 다만 공허폭풍은 절 내면에서부터 갉아먹는 것 같습니다.\n\n해야 할 일을 하고, 돌아갑시다.', 66384),
(309157, 'koKR', '', '가증스러운 놈이 처음부터 우릴 노리고 있다는 건 알고 있었습니다.\n\n그래도 희망을 가지고 싶었죠. 공허폭풍은 희망이란 게 없는 곳이 되어 버렸으니까요.\n\n저 괴물이 무슨 속셈을 품고 있든, 이젠 대비되어 있습니다.', 66384),
(309152, 'koKR', '', '온순한 공허방랑자가 존재한다는 얘기는 들어본 적 없습니다. 그래도 다른 이들을 찾아낼 가능성이 아주 조금이라도 있다면, 고려해 봐야겠죠.\n\n공허폭풍에서 너무나 큰 고통에 시달렸습니다. 이제는 정말 한 번쯤은 이겨보고 싶네요.', 66384),
(309147, 'koKR', '', '엘프들의 환영이 절 이 공허방랑자에게로 이끌었습니다!\n\n겉보기엔 위협적이지 않아 보이지만, 방심하지 마세요. 어둠은 정교한 거미줄처럼 속임수를 엮어 내니까요.', 66384),
(309132, 'koKR', '이제 알겠습니다... 지나친 폭력은 끝없는 죽음의 순환만 낳는다는 것을요.\n\n끝이 없죠. 공허처럼.', '', 66384),
(309128, 'koKR', '최상위 포식자의 흔적은 없지만, 분명 절 지켜보고 있습니다. 저 밖에 있어요!\n\n켈리아가 못 봤다면 눈이 먼 겁니다! 수평선 너머에 무엇인가 도사리고 있다는 걸 전 켈리아의 눈을 보고 읽었습니다.', '', 66384),
(309120, 'koKR', '이 야수들의 살점은 이상하게도 공허의 맛이 전혀 나지 않더군요.\n\n그런데 한입 베어 물자마자, 주변의 공기가 들뜬 듯 떨렸습니다.', '', 66384),
(309118, 'koKR', '', '공간 연구원이 된다는 것은 렌도레이와 공허의 관계를 이해한다는 뜻입니다.\n\n공허의 힘은 우리를 앞으로 이끌어 주었지만... 위험 또한 분명합니다.\n\n<고개를 기울여 초점을 잃은 눈빛을 드러내는 켈리아>\n\n마트리안과 제가 함께 연구하는 이유도 그런 점에서 서로를 보완하기 때문이에요. 그는 기꺼이 공허를 품고, 저는... 보다 현실적이고, 신중하게 접근합니다.\n\n함께 미지의 광기를 마주할 수도 있다는 사실을 알고 연구에 임하고 있는 거예요.\n\n그래서 서로가 필요한 겁니다. 언젠가 그 광기가 제게 닿는 날이 온다면, 마땅히 해야 할 일을 해줄 사람이 옆에 있다는 사실에 감사하게 될 테니까요.', 66384),
(309100, 'koKR', '성기사 상당수가 태양샘으로 왔으니 희망의 빛 예배당 상황이 좋을 리가 없는데, 예상 못 한 내 패착일세, $p.\n\n자네와 아라토르가 늦지 않게 와서 티로서스를 도와서 다행이구먼.', '', 66384),
(309088, 'koKR', '', '의회를 설득해야 해. 가만히 손 놓기 있기엔 상황이 너무 위태로워.', 66384),
(309008, 'koKR', '전 공허와의 싸움이 익숙한 사람입니다만... 이런 규모는 처음 봅니다. 불타는 군단의 요새를 공격할 때와는 달리, 공허와의 교전은 훨씬 산발적인 편이었거든요.\n\n가장 외딴 전장에서도 공허의 병력은 시야 끝자락의 그림자처럼 숨어 있었습니다. 로스락시온이 공허의 전술에 대해 알려준 건 많지만, 지금 마주한 이 병력은 우리가 겪어 온 모든 것을 뛰어넘습니다.', '', 66384),
(309007, 'koKR', '', '저는 공허의 군세가 움직이는 모습을 직접 본 적 있습니다. 끝없는 악마 군대와 충돌하는 장면도 지켜봤고요. 불타는 군단이 거친 힘을 앞세웠다면, 공허는 스며들고 번져 나가는 그림자처럼 모든 것을 집어삼켰습니다.\n\n그런데... 이번에는 완전히 새로운 모습이었어요. 상대가 공허임을 감안해도 말이죠.', 66384),
(309005, 'koKR', '빛이 없는 곳에 그림자는 존재할 수 없습니다.', '빛이 없는 곳에 그림자는 존재할 수 없습니다.', 66384),
(308999, 'koKR', '', '저는 아리입니다. 카드가의 친구이지요. 한때는 보랏빛 성채 수호자의 전당을 제 보금자리처럼 여기며 살았습니다.\n\n조용하고 방해받지 않는 책장과 독서 공간들 사이에서 참 오랫동안 머물렀지요.\n\n하지만 달라란이 네루비안의 공격을 받았을 때 저는...\n\n<잠시 말을 멈추는 아리>\n\n많은 사람처럼, 도시가 무너진 뒤 제자리를 찾지 못했습니다. 제게 바깥세상은 너무 크고, 너무 소란스러웠죠.\n\n그때 카드가가 절 이곳으로 데려왔습니다. 안전하고, 조용한 곳으로요. 참 많은 빚을 졌습니다.', 66384),
(308996, 'koKR', '', '카드가가 도르노갈에서 회복한 후에 이 성소를 알려줬어요.\n\n수호자의 전당처럼 웅장하지는 않지만, 조용한 게 어디예요.\n\n여기엔 어떤 비밀이 숨겨져 있을지 궁금하긴 하군요.', 66384),
(308995, 'koKR', '', '모르둔이 죽었으니, 잘아타스와의 싸움도 훨씬 유리하게 흘러갈 겁니다.', 66384),
(308994, 'koKR', '예전에는 수많은 영웅에게 샤트라스를 안내하곤 했습니다. 도시 전반을 보여주는 일이라 시간을 꽤 잡아먹었죠!\n\n일을 끝내고 해방될 때의 기분은 늘 좋습니다.', '', 66384),
(308993, 'koKR', '', '뭐야? 아제로스에서 내로라는 양반들 사이에서 날 보게 될 줄은 몰랐어?\n\n뭐, 아직까진 아무도 날 쫓아내진 않았어. 그게 내 덕이라기보단 세실리아의 고운 미소 덕일 거라는 건 나도 알아.\n\n데피아즈 결사단은 스스로 길을 정했어. 나도 내 길을 선택했고. 녀석들은 우리 아버지의 유산을 약탈하고 방화하는 걸로 지키고 싶다지. 그러라고 해. 난 서부 몰락지대 농부들을 제대로 돕는 걸로 지킬 거야.\n\n세실리아는 무슨 일이든 \"정석\"대로 하려고 해. 그렇다고 멍청하다는 얘기는 아니야. 상대가 더럽게 나오면 우리도 가끔은 그렇게 해야 한다는 걸 잘 알고 있거든.\n\n그래서 내가 지금 이렇게 백작하고 어깨를 나란히 하는 거지, 별 수 있나.\n\n<순간적으로 미소를 지어 보이는 바네사>\n\n그래도 생각보다 나쁘진 않아. 전혀 나쁘지 않더라고.', 66384),
(308992, 'koKR', '', '또 뵙네요, $p 님!\n\n여정은 순조로우셨나요? 전 스톰윈드에서 서부 몰락지대 곡창 조합을 지지할 사람들을 모으느라 분주했습니다.\n\n지금 같은 상황에서는 그조차 쉽지 않지만요. 귀족 평의회는 왕이 자리에 없다는 이유로 마음에 들지 않는 안건은 지연시키고, 자신들에게 유리한 안건은 같은 이유를 내세워 서둘러 통과시키곤 합니다.\n\n<한숨을 내쉬는 세실리아>\n\n용서하세요, 여행자님. 바네사에게는 이런 이야기로 아르칸티나에서까지 마음을 어지럽히지 않겠다고 약속했거든요. 정말 편히 쉴 수 있는 멋진 곳이지 않나요? 바네사가 여기로 들어오는 방법을 어떻게 알아냈는지 절대 말해주지 않더군요. 물론 바네사답게, 겉으로 말하는 것보단 훨씬 은밀한 수법을 썼을 것 같긴 하지만요. 언젠가는 꼭 진실을 털어놓게 만들 겁니다.', 66384),
(308991, 'koKR', '', '안녕하세요, 여행자님.\n\n저는 세실리아 클레싱턴이라고 합니다. 스톰윈드에서는 서부 몰락지대의 곡창 조합 농가들을 지원하며, 공정한 정치를 위해 힘쓰고 있습니다.\n\n지금 같은 상황에서는 그조차 쉽지 않지만요. 귀족 평의회는 왕이 자리에 없다는 이유로 마음에 들지 않는 안건은 지연시키고, 자신들에게 유리한 안건은 같은 이유를 내세워 서둘러 통과시키곤 합니다.\n\n<한숨을 내쉬는 세실리아>\n\n용서하세요, 여행자님. 바네사에게는 이런 이야기로 아르칸티나에서까지 마음을 어지럽히지 않겠다고 약속했거든요. 정말 편히 쉴 수 있는 멋진 곳이지 않나요? 바네사가 여기로 들어오는 방법을 어떻게 알아냈는지 절대 말해주지 않더군요. 물론 바네사답게, 겉으로 말하는 것보단 훨씬 은밀한 수법을 썼을 것 같긴 하지만요. 언젠가는 꼭 진실을 털어놓게 만들 겁니다.', 66384),
(308990, 'koKR', '아르칸티나는 멋진 곳입니다, $p 님. 가끔 한 번씩 들르세요!\n\n누구든 한 번씩 쉬면서 마음의 부담을 해소할 필요는 있으니까요.', '', 66384),
(308988, 'koKR', '데즈코와 함께 지내며 많은 걸 배웠소. 광야 한복판에서는 햇살 한 줄기도 헛되지 않으며, 우리가 해내는 작은 일 하나도 무의미하지 않다는 걸 말이오.\n\n게다가... 안쉬의 뜻에서 무엇이 가치 있고 없는지를 판단하는 건 우리 몫이 아니오.\n\n이곳에서 데즈코와 함께 사람들을 돕다 보니, 지금 하는 일이야말로 가장 보람 있는 일이라 느꼈소.', '', 66384),
(308987, 'koKR', '이번엔 광채 경비병이랑 싸울 거야. 녀석들은 항상 이긴다는데... 음, 그 얘기는 안 하는 게 좋겠다. $p 기분 나빠질 수도 있어.\n\n그래도 모타는 생각해. $p 너라면 광채 경비병을 이길 수도 있다고. $p 너 정말 강하고, 동료들도 많이 단련했잖아.\n\n모타가 $p에게 행운을 빌어줄게. 이길지도 모르잖아!\n\n어쩌면 항상 이기는 녀석들 자리를 빼앗을지도? 우린 도망친 적 있지만.\n\n그래도 너라면 광채 경비병을 이길 수 있어!', '', 66384),
(308986, 'koKR', '왜 다들 달아났어? 그렇게 하면 제일 빨리 지는데. 좋은 계획은 아니야.\n\n아니면 애초에 계획이 없었던 건가?\n\n모타도 예전에 소속이 있었어. 구덩이는 무서워.\n\n모타도 한 번 도망쳤고, 다들 많이 화냈지.\n\n그래서 모타는 이제 안전한 데만 있어. 다시는 구덩이에 안 들어가.\n\n너는 또 들어갈 거야?', '', 66384),
(308985, 'koKR', '이름을 정한 건 알겠어.\n\n근데 모타는... 잘 모르겠어. 유행 탄 포자 친구들이 뭐야?\n\n구덩이에서 크게 외치기엔 너무 어려운데. 그냥 \"$p의 친구들\" 이렇게 하면 훨씬 쉬웠겠다.\n\n그래도 모타는 열심히 외칠 거야.', '', 66384),
(308984, 'koKR', '이름 정했다며? 멋진데!\n\n좋은 선택이야. 모타는 마음에 들어.\n\n이제 구덩이에 들어가면 사람들이 \"$p의 친구들! $p의 친구들!\" 이게 아니라 그 이름을 크게 외칠 거야.', '', 66384),
(308983, 'koKR', '만나서 반갑소, 대영주! 인생이 참, 생각했던 것과 많이 달라졌소. 처음에는 은빛 손을 회수했고, 이젠 믿기 어렵게도 위대한 티탄 수호자 티르 님이 돌아오셨지.\n\nIt이렇게 아르칸티나에서 당신을 비롯해... 상상조차 어려운 일을 직접 본 사람들과 쉬고 있는 게 위안이 되는구려.', '', 66384),
(308982, 'koKR', '난 트래바드라고 하오, $p. 정말 예상치 못한 삶을 살고 있지.\n\n위대한 티탄 수호자 티르 님이 돌아온 걸 아시오? 꿈도 못 꾸던 일이었는데.\n\n이렇게 아르칸티나에서... 상상조차 어려운 일을 직접 본 사람들과 쉬고 있는 게 위안이 되는구려.', '', 66384),
(308980, 'koKR', '$p, 우리가 만난 이후로 있었던 일이 공상처럼 느껴질 때가 있다오. 티르의 무덤에서 코라노스를 만나고, 티르의 수호병을 재결성해 그분의 기억을 회수하고, 이젠 아제로스를 다시 활보하는 모습을 보다니. 얘기로 전해 들었으면 절대 안 믿었을 거요.\n\n이렇게 아르칸티나에서... 상상조차 어려운 일을 직접 본 사람들과 쉬고 있는 게 위안이 되는구려.', '', 66384),
(308865, 'koKR', '슬슬 집에 가야 하지만...\n\n있잖아? 됐어. 그냥 여기 있고 싶어.\n\n고마워. 이제는 도망치지 말고, 이 순간을 즐길 거야.', '슬슬 집에 가야 하지만...\n\n있잖아? 됐어. 그냥 여기 있고 싶어.\n\n고마워. 이제는 도망치지 말고, 이 순간을 즐길 거야.', 66384),
(308863, 'koKR', '난 지금 공동체의 편안함을 벗어나 혼자 살아보는 도전에 임하고 있다.\n\n쉽지 않더군. 뾰족한 막대기 하나랑 내 머리만 믿고 확실한 죽음을 피하는 기분이랄까.\n\n근데 이젠 막대기 하나만 남은 것 같아.', '', 66384),
(308862, 'koKR', '전 신경 쓰지 마세요. 엘프들이 어떻게 이런 걸 만들어 냈는지 좀 살펴보고 있었어요.\n\n도시를 재건하면서도, 오래된 건축 양식을 그대로 남긴다? 마법을 썼다 해도 대단한 기계공학적 지식이 들어갔다고 봐도 되거든요.\n\n이렇게 큰 구조물이 하중에 무너져 내리지 않는다는 게 말이 되겠어요? 심지어 사람들의 체중까지 견디는 건데.\n\n환영 마법을 썼다에 5 코퍼를 걸죠. 다는 아니고, 손을 안 대고는 자세히 볼 수도 없는 부분만 슬쩍 감춰 놓은 거겠죠.', '', 66384),
(308861, 'koKR', '가끔은 인형이 된 게 좀 후회돼. 할 수 있는 게 없거든!\n\n맞다, 그러니까... 우리랑 하나가 되어라!\n\n아무튼 그렇다고!', '가끔은 인형이 된 게 좀 후회돼. 할 수 있는 게 없거든!\n\n맞다, 그러니까... 우리랑 하나가 되어라!\n\n아무튼 그렇다고!', 66384),
(308859, 'koKR', '또 고쳐지고 싶은가 보네?', '', 66384),
(308857, 'koKR', '축제에 어서 와!', '', 66384),
(308851, 'koKR', '다른 녀석들도 데려와. 내... 아니, 우리 공동체 이야기를 널리 퍼뜨려 줘!', '', 66384),
(308849, 'koKR', '우리와 하나!', '우리와 하나!', 66384),
(308845, 'koKR', '그 단추면 충분해. 이제 바늘로 꿰매 줄게.\n\n운 좋은 줄 알아. 이 바늘 꽤 날카롭거든.\n\n준비됐지?', '', 66384),
(308843, 'koKR', '죄송하지만 여기 물품 대부분은 용매 관리를 위한 것들입니다, $c님. 필요한 게 있으시면 근처에 있는 제 동생 사라의 가게를 찾아가 보세요.', '죄송하지만 여기 물품 대부분은 용매 관리를 위한 것들입니다, $c님. 필요한 게 있으시면 근처에 있는 제 동생 사라의 가게를 찾아가 보세요.', 66384),
(308838, 'koKR', '<아마라크의 두건 아래로 옅은 미소가 번집니다.>\n\n오르웨냐의 친구답게 여기저기 많이 돌아다녔군. 그럼 하나 묻지. 믿음이라는 건 거리가 멀어지면 흐려지는 걸까?\n\n그래, 술카의 길은 외롭다. 그렇다고 우리가 믿음이 없는 건 아니야. 난 지금도 알른하라를 누구보다 깊이 믿는다. 비록 들을 수는 없어도, 여전히 날 부르고 있다는 걸 알기에.', '', 66384),
(308836, 'koKR', '아니. 우리의 입회 의식은 영혼에 상처를 남긴다. 우릴 바꿔 놓지. 그리고 여신의 노랫소리를 듣지 못하게 만들어.\n\n고독한 삶이야. 그래도 그 덕에 다른 이들이 가지 못하는 곳을 걸을 수 있다. 침묵에 잠겨 있기에, 우린 균열의 광기 어린 울부짖음에서 벗어날 수 있거든.', '', 66384),
(308833, 'koKR', '술카는 사냥꾼이자 치유자, 안내자다. 우리는 영혼과 그림자에 기도하며 알른의 균열 속 위험을 헤치고 살아 돌아오지. 그리고 그 위험이 저주의 땅을 벗어나지 못하게 막는 역할도 하고 있다.\n\n쉽게 익힐 수 있는 기술은 아니다. 여신의 노랫소리는 거친 야성으로, 넘치는 생명력으로 우리를 이끌지. 그렇지만 지금의 우리는 그 부름을 들을 수 없다. 그래서 다른 목소리와 교감하는 것이야. 아직 우리의 귀에 닿는 목소리들과 말이다.', '', 66384),
(308823, 'koKR', '알른가루는 희귀할 뿐 아니라 채집 자체가 위험한 일이오. 순수한 형태일 때는 알른하라의 은총과 우리의 연결을 강화해 주고, 후대에 남길 역사를 기록하게 해 주며, 뿌리 밖 세계의 타락으로부터 우리를 보호해 주지.\n\n하라니르 장로들은 이 알른가루의 관리와 사용을 엄격히 책임지고 있소. 우리조차 신성한 의식이나 중대한 위기 상황에서만 사용할 수 있는 자원이라오.\n\n장로들이 오르웨냐의 요청을 거절했다 해서 놀랍지는 않소. 장로들에게는 뿌리 밖의 세계는 사실상 존재하지 않는 것이나 마찬가지니까. 한 번도 밟아볼 일 없는 땅을 위해 소중한 자원을 소모할 이유가 없다고 생각하는 것도 이해는 가지.', '', 66384),
(308821, 'koKR', '', '바텐더가 독한 술로 들겠냐고 묻거둔. 이미 죽은 몸인데, 좀 독하게 마신다고 뭐가 달라지겠나.\n\n<주변을 훑으며 잔을 천천히 한 모금 마시는 릴리안>\n\n이곳은 시끄럽고, 탄 맥주 냄새가 가득하네... 그런데 기묘하게도 고향처럼 푸근해. 더 이상한 건, 호드와 얼라이언스 바로 옆에 앉아 있으면서도 묘한 평온을 느낀다는 걸세. 이곳의 활기찬 분위기는 특이하지만, 참 반갑구먼.\n\n우리 모두가 공유하는 건 단 하나, 쉴 수 있는 순간은 천금과도 같다는 걸세. 쉽게 사라지니까 더욱더 열심히 붙들게 되지.\n\n혹시 술에서 독 맛이 난다면, 내 탓은 아닐세. 오늘은 정말 쉬고 싶거든.', 66384),
(308786, 'koKR', '하셰이의 길은 길고도 험난하지, 온갖 시련과 위험이 가득하네.\n\n하쉬우라는 하셰이의 수행사제일세. 그 길을 따르고, 함께 싸우며, 그들을 위해 죽기도 하지.\n\n보통은, 음, 둘이 함께하지. 하지만 나는 늙었고, 병사들은 다쳤고, 줄잔은 결코 찬성하지 않을 테니...\n\n리아드린이 부관이 되어야겠군.\n\n<머쓱하게 웃는 킨두루>\n\n하쉬우라의 영예가 신도레이와 칼도레이에게 돌아가다니... 막상 생각해 보니 조금 어지럽군. 하지만 내가 뭐라고 로아의 뜻에 의문을 품겠는가?', '', 66384),
(308783, 'koKR', '하셰이의 길은 길고도 험난하지, 온갖 시련과 위험이 가득하네.\n\n하쉬우라는 하셰이의 수행사제일세. 그 길을 따르고, 함께 싸우며, 그들을 위해 죽기도 하지.\n\n보통은, 음, 둘이 함께하지. 하지만 나는 늙었고, 병사들은 다쳤고, 줄잔은 결코 찬성하지 않을 테니...\n\n리아드린이 부관이 되어야겠군.\n\n<머쓱하게 웃는 킨두루>\n\n하쉬우라의 영예가 엘프에게 돌아가다니... 그래도 두 번째는 $n 자네 아닌가. 줄아만의 자손은 아닐지언정, 아득히 먼 친척의 자손은 되지!', '', 66384),
(308778, 'koKR', '토룬도가 보낸 건가? 빛나무 무기 배송이 왜 늦는지 알아보라고? 그렇다면 잘 찾아왔네.\n\n황혼의 칼날단이 우리 야영지를 알아냈고, 아마니에게 강력한 빛나무 무기를 공급한다는 것도 눈치챘지. 그래서 요즘은 수시로 들이닥쳐서 일만 방해하고 있어.\n\n그 와중에 어떤 엘프 아이가 야영지에 들이닥쳐서는 여동생 얘기를 하며 고래고래 소리를 지르지 뭔가. 지금 황혼의 칼날단 상대하기도 바쁜데, 화난 엘프 농부가 잃어버린 자식까지 돌볼 시간은 없네!\n\n나이도 어리고, 뭐든 다 안다고 착각해. 하지만 나라고 다 모르는 건 아니거든...\n\n자네가 이 두 가지 문제를 한꺼번에 해결해 줄 수 있을지도 모르겠군.', '', 66384),
(308777, 'koKR', '', '쏜살이 양초가 꺼지면 미리트가 도와줘. 이 양초들 전부 쏜살이가 찾은 거야!\n\n이렇게 많은데, 하나쯤 빌려 가도 모르지 않을까?', 66384),
(308776, 'koKR', '우리 만난 적 없지? 난 미리트고, 이쪽은 쏜살이야. 새로운 보물을 찾는 것처럼 새로운 친구를 만나는 걸 좋아해.\n\n같이 앉을래? 우리가 여기 몰래 들어온 걸 누가 알아차릴 때까지 잠깐 쉬려고 했거든. 여긴 정말 근사해!', '', 66384),
(308775, 'koKR', '여긴 내가 찾아낸 동굴 중에 제일 근사한 곳이야. 제일 좋은 건 친구들이 같이 있다는 거고! $n 너도 있고, 쏜살이도 있고, 멋진 자리까지 있거든.\n\n이 폭신한 방석들은 두 번째로 좋은 거야. 우리랑 같이 앉을래? 너랑 냄새 추적을 다니던 때가 그리웠어.\n\n언제든 같이 앉아도 돼. 환영이야!', '', 66384),
(308774, 'koKR', '자고로 모험가라면 선술집에서 보내는 시간도 좀 있어야 하지 않겠습니까? 뭐, 많으면 많을수록 좋고요.\n\n항상 위험한 일을 겪다 보면, 눈앞에 삶이 주마등처럼 지나가곤 하죠. 제 경우에는 한동안은 이 포도주를 맛보는 제 모습이 보이더군요. 이걸 어찌 거부하겠습니까?', '', 66384),
(308624, 'koKR', '', '오히려 새로운 승리로 기억을 다시 쓸 기회가 됐지.', 66384),
(308623, 'koKR', '', '고맙네, 하쉬우라. 반백 녀석에게 이번 싸움이 과거의 실패를 부끄러워하는 자리가 아니라는 걸 일깨워줘서 말이야.', 66384),
(308620, 'koKR', '남 말 하지 마라, 늙은이! 광전사에게 세월은 아무 의미 없다는 걸 똑똑히 보여주지!', '', 66384),
(308613, 'koKR', '어디까지나 아탈아만의 기억일 뿐, 고통도 죽음도 느끼지 않아.', '', 66384),
(308612, 'koKR', '', '저 중에 자네의 진짜 동료는 없네.', 66384),
(308600, 'koKR', '', '공허는 역겨워. 내게 너무 많은 고통을 안겼지! 황혼의 칼날단 이교도들이 공허를 이용해 내 가장 소중한 것들... 마을과 어머니를 파멸로 몰아넣었네.\n\n그런데 또 공허가 우리 게잡이 터 근처에 나타나 피난민들에게 피해를 주고 있으니... 그때의 끔찍한 기억이 계속 떠올라 견디기 힘들군.\n\n어서 이 모든 일의 근원을 밝혀야 하네.', 66384),
(308593, 'koKR', '', '그림자소나무의 수완은 따라올 자가 없지. 필요하다면 우리는 수년이고 버티며 제단을 지킬 수 있다네.', 66384),
(308592, 'koKR', '문제는 식량 조달이야. 보급품만 충분하면 한동안은 모두 배불리 먹고, 또 싸울 수 있을 걸세!', '', 66384),
(308588, 'koKR', '어린 독수리들이 둥지를 떠나 훨훨 날 수 있게 할 수만 있다면 어떤 상처든 감수할 가치가 있지.', '', 66384),
(308587, 'koKR', '', '방벽은 견고히 유지되고 있다고 전해주게. 지금 우리가 상대해야 하는 적은 이 감옥에서 기다리는 인내심뿐일세.', 66384),
(308586, 'koKR', '저희에게 머물 곳을 제공해 주신 데 대한 감사의 뜻으로, 여러분의 거주구에 저희가 가진 예술적 지식을 나누고 싶습니다. 여러분의 미적 감각이 어떤지 보는 것도 정말 기대되고요.\n\n집을 한번 꾸며보실 생각은 있으신가요? 여러분이 어떤 식으로 장식을 활용하는지 보고, 새로운 장식을 들여오신다면 함께 살펴보고 싶습니다!\n\n또, 실버문 공격으로 다친 분들도 있어서요. 치유를 도와주실 수 있다면 큰 도움이 될 것 같네요.\n\n참, 코를렌이 영감을 얻는 걸 도와줄 사람을 찾고 있다고 들었습니다. 별난 구석이 있긴 하지만 정말 뛰어난 화가예요.', '저희에게 머물 곳을 제공해 주신 데 대한 감사의 뜻으로, 여러분의 거주구에 저희가 가진 예술적 지식을 나누고 싶습니다. 여러분의 미적 감각이 어떤지 보는 것도 정말 기대되고요.\n\n집을 한번 꾸며보실 생각은 있으신가요? 여러분이 어떤 식으로 장식을 활용하는지 보고, 새로운 장식을 들여오신다면 함께 살펴보고 싶습니다!\n\n또, 실버문 공격으로 다친 분들도 있어서요. 치유를 도와주실 수 있다면 큰 도움이 될 것 같네요.\n\n참, 코를렌이 영감을 얻는 걸 도와줄 사람을 찾고 있다고 들었습니다. 별난 구석이 있긴 하지만 정말 뛰어난 화가예요.', 66384),
(308585, 'koKR', '', '팔 휘적거리면서 지껄이지 마라! 자꾸 그러니까 치료를 못 하겠잖아!', 66384),
(308584, 'koKR', '영원노래 숲은 지금 공허와 빛의 공격을 동시에 받고 있습니다.\n\n그 위협을 억제하는 일도, 우리의 일상을 지켜내는 일도 모두 필요하지요.\n\n살데릴 님이 연회장에서 도와줄 사람을 찾고 있다고 들었고, 빛만개 정리를 도와줄 사람도 필요합니다.\n\n말하기는 괴롭지만, 아마니 트롤도 지금은 지원이 필요하고... 새롭게 모습을 드러낸 종족도 도움을 요청하고 있다고 들었습니다.\n\n지금 우린 공허를 상대로 직접 반격에 나선 상황이기에, 그곳에서도 용사님의 힘이 필요합니다.\n\n할 일이... 정말 많습니다. 힘닿는 데까지 도와주시면 감사하겠습니다.', '영원노래 숲은 지금 공허와 빛의 공격을 동시에 받고 있습니다.\n\n그 위협을 억제하는 일도, 우리의 일상을 지켜내는 일도 모두 필요하지요.\n\n살데릴 님이 연회장에서 도와줄 사람을 찾고 있다고 들었고, 빛만개 정리를 도와줄 사람도 필요합니다.\n\n말하기는 괴롭지만, 아마니 트롤도 지금은 지원이 필요하고... 새롭게 모습을 드러낸 종족도 도움을 요청하고 있다고 들었습니다.\n\n지금 우린 공허를 상대로 직접 반격에 나선 상황이기에, 그곳에서도 용사님의 힘이 필요합니다.\n\n할 일이... 정말 많습니다. 힘닿는 데까지 도와주시면 감사하겠습니다.', 66384),
(308582, 'koKR', '', '상황이 위태롭네.\n\n과거의 메아리들은 하나하나 쓰러뜨리기는 쉽지만, 잠시 후면 다시 살아나 공격해 오거든.', 66384),
(308576, 'koKR', '우리 예술가 공동체에게 머물 곳을 제공해 주시고, 거주구를 꾸미는 데 동참할 기회를 주셔서 감사합니다.\n\n정말 멋진 거주구입니다. 예술가라면 누구나 꿈꿀 만한 곳이에요.', '우리 예술가 공동체에게 머물 곳을 제공해 주시고, 거주구를 꾸미는 데 동참할 기회를 주셔서 감사합니다.\n\n정말 멋진 거주구입니다. 예술가라면 누구나 꿈꿀 만한 곳이에요.', 66384),
(308575, 'koKR', '우리 예술가 공동체에게 머물 곳을 제공해 주시고, 거주구를 꾸미는 데 동참할 기회를 주셔서 감사합니다.\n\n아직 세상을 알아가는 중이신 것 같군요. 아제로스를 좀 더 둘러보시고 나서 오시는 게 어떨까요? 당신의 여정을 방해하고 싶지는 않습니다.', '우리 예술가 공동체에게 머물 곳을 제공해 주시고, 거주구를 꾸미는 데 동참할 기회를 주셔서 감사합니다.\n\n아직 세상을 알아가는 중이신 것 같군요. 아제로스를 좀 더 둘러보시고 나서 오시는 게 어떨까요? 당신의 여정을 방해하고 싶지는 않습니다.', 66384),
(308573, 'koKR', '', '늙은 천산갑처럼 불평만 늘어놓긴. 다시 방벽 밖으로 나가기 전에 잠깐 쉬든지.', 66384),
(308572, 'koKR', '아무리 쓰러뜨려도 적의 무리가 계속해서 도시 안으로 밀려드는군.', '', 66384),
(308569, 'koKR', '젊었을 때라면 끝없이 몰려드는 적도 즐겁게 상대했겠지.\n\n하지만 이제는... 이 늙은 몸뚱이가 예전처럼 따라주질 않는구먼.', '', 66384),
(308568, 'koKR', '', '아탈아만에서 익숙한 얼굴들을 보게 될 수도 있지만... 예전처럼 반가운 모습일 거라 기대하진 마.', 66384),
(308566, 'koKR', '', '얼마 전에 마른나무껍질 여자아이가 왔다 갔습니다. 아쉽게도 제가 과일이나 버섯으로 교환을 받아주진 않아서...', 66384),
(308565, 'koKR', '', '아, 제 골동품 투스카르 찻주전자 말이죠. 안 그래도 먼저 물어본 사람이 있었는데...', 66384),
(308564, 'koKR', '', '바다 건너에서 온 물건입니다! \"바다\"를 두 눈에 담아보세요!', 66384),
(308511, 'koKR', '이건 평범한 알이 아닙니다.\n\n벨로렌은 공허의 첫 공격 당시 쓰러졌습니다. 잘아타스의 병력은 우리가 가장 약한 지점을 정확히 알고 있었지요.\n\n위대한 불사조는 결국 알로 돌아갈 수밖에 없었습니다. 금방 깨어날 줄 알았지만, 태양샘에 빛이 쇄도한 이후 회복하는 과정에서... 형태를 바꾸고 있습니다.\n\n다시 하늘로 날아오를 때까지, 우리는 알을 수호할 것입니다.', '이건 평범한 알이 아닙니다.\n\n벨로렌은 공허의 첫 공격 당시 쓰러졌습니다. 잘아타스의 병력은 우리가 가장 약한 지점을 정확히 알고 있었지요.\n\n위대한 불사조는 결국 알로 돌아갈 수밖에 없었습니다. 금방 깨어날 줄 알았지만, 태양샘에 빛이 쇄도한 이후 회복하는 과정에서... 형태를 바꾸고 있습니다.\n\n다시 하늘로 날아오를 때까지, 우리는 알을 수호할 것입니다.', 66384),
(308509, 'koKR', '물러서십시오, $c님.\n\n당신은 지금 알라르의 마지막 알 앞에 있습니다. 우리가 쓰러지더라도 꼭 지켜야 할 존재이지요.', '물러서십시오, $c님.\n\n당신은 지금 알라르의 마지막 알 앞에 있습니다. 우리가 쓰러지더라도 꼭 지켜야 할 존재이지요.', 66384),
(308503, 'koKR', '<비웃음을 터뜨리는 루이아>\n\n너희는 비가 내릴 때마다 하늘이 무너진다고 탄식하더냐?\n\n뿌리는 어떨 때는 늘고, 어떨 때는 줄고, 또 어떨 때는 모양이나 기질이 달라지지. 하지만 언제나 요람을 향한다. 하란다르의 뿌리가 온전하기만 하다면, 지상에서 무슨 일이 일어나든 우리가 신경 쓸 이유가 있을까?\n\n또 다른 어리석은 질문은 없나? 아니면 심판을 조금이라도 늦춰보려는 것이냐?', '', 66384),
(308501, 'koKR', '너느 샬라드라실의 뿌리감시관 루이아 앞에 서 있다. 나는 이 저주받은 뿌리들을 지키며 85년을 보냈다. 내 스승께서 흙으로 돌아가기 전 그렇게 했던 것처럼 말이다.', '', 66384),
(308500, 'koKR', '', '아자이가 블러드 엘프 놈을 해치워야 했어.\n\n<무심한 눈빛으로 당신을 위아래로 훑는 라카니>\n\n낯선 자는 여기서 환영받지 못하네. 특히 문제를 일으키려고 오는 자라면 더더욱.\n\n처신 잘하는 게 좋을 거야.', 66384),
(308496, 'koKR', '<당신을 향해 송곳니를 드러내며, 노골적인 혐오를 드러내는 루이아>\n\n감히 뿌리감시관의 눈을 똑바로 마주하느냐? 네 뼈를 암영스라소니의 먹잇감으로 내줘도 될 노릇이군.', '', 66384),
(308495, 'koKR', '그 사람을 입에 담지 말아요.\n\n레이니아는 죽었어요.\n\n<결박된 채로 주먹을 움켜 쥐는 켈러>\n\n꼭 밤의 유령 같았어요...\n\n아마니였을 거예요. 틀림없어요.\n\n그냥 닥치는 대로 공격했어요. 그렇다면 우리도 똑같이 하면 되잖아요? 아무 아마니나 상관없잖아요.\n\n왜 안 되죠?', '', 66384),
(308494, 'koKR', '<눈을 가늘게 뜨고 당신을 바라보는 켈러>\n\n놈들하고 한패가 아니군요?\n\n...늦기 전에 이거 좀 풀어주세요.', '', 66384),
(308436, 'koKR', '우리가 되려면 중요한 게 몇 가지 필요해.\n\n일단은... 단추!', '', 66384),
(308435, 'koKR', '우리의 일원이 아니야.\n\n\n우리의 일원.', '우리의 일원이 아니야.\n\n\n우리의 일원.', 66384),
(308429, 'koKR', '참 예쁘지 않나? 난 정말 마음에 들어.\n\n무릎 위에서 카파라가 자고 있을 때는 움직이면 안 된다는 규칙이 있어.\n\n...지금 내가 만든 규칙이지만, 그래도 좋은 규칙이야.', '참 예쁘지 않나? 난 정말 마음에 들어.\n\n무릎 위에서 카파라가 자고 있을 때는 움직이면 안 된다는 규칙이 있어.\n\n...지금 내가 만든 규칙이지만, 그래도 좋은 규칙이야.', 66384),
(308413, 'koKR', '빛은 너무 세게 붙들면 손가락 사이로 빠져나갑니다. 힘을 빼고, 몸에 흐르게 해야 합니다.', '빛은 너무 세게 붙들면 손가락 사이로 빠져나갑니다. 힘을 빼고, 몸에 흐르게 해야 합니다.', 66384),
(308412, 'koKR', '고요한 순간에야 우리는 빛의 따스함과 경이를 느낄 수 있습니다.', '고요한 순간에야 우리는 빛의 따스함과 경이를 느낄 수 있습니다.', 66384),
(308411, 'koKR', '성장의 로아 오에. 우리 신들을 통틀어 알려진 바가 가장 적은 분이지.\n\n절벽에서 거대한 숲을 찾아보게. 그루터기라는 곳이지. 바위소나무에게 도전하게. 자네의 자격은 오에께서 판단하실 것이야.', '', 66384),
(308404, 'koKR', '아, 푸울. 위기의 로아. 가장 무서운 바다 괴물, 상어의 모습을 갖추고 대담한 이들 앞에만 나타나지.\n\n그분은 흉포한 줄아만 해역에서 물고기를 낚는 용감한 이들을 총애하신다네.', '', 66384),
(308399, 'koKR', '둔둔. 풍요의 쥐 로아는... 신들 중에서도 독특한 성격의 보유자라네.\n\n마른나무껍질 마을 서쪽의 로아니트 소굴에 있을 가능성이 커.', '', 66384),
(308398, 'koKR', '아... 샤드라. 기만의 로아.\n\n요즘은 샤드라 숭배자들이 박해받는 일이 잦다네. 자세한 사정이 궁금하거든 깨진엄니의 펠나 톤터스크를 찾아가게.\n\n마른나무껍질 절벽에서 어떤 소문을 조사하고 있다던데.', '', 66384),
(308397, 'koKR', '빛은 고통이 없는 존재가 되라고 요구하지 않습니다. 그저 고통이 지나가게 두라고 할 뿐이죠.', '빛은 고통이 없는 존재가 되라고 요구하지 않습니다. 그저 고통이 지나가게 두라고 할 뿐이죠.', 66384),
(308396, 'koKR', '고요함 역시 헌신의 한 형태입니다.', '고요함 역시 헌신의 한 형태입니다.', 66384),
(308395, 'koKR', '빛이 당신의 부담을 짊어질 겁니다.', '빛이 당신의 부담을 짊어질 겁니다.', 66384),
(308394, 'koKR', '슬픔을 중심에 두세요. 빛은 견딜 것이니.', '슬픔을 중심에 두세요. 빛은 견딜 것이니.', 66384),
(308393, 'koKR', '때로는 침묵이 빛에 이르는 진정한 길이 되기도 합니다.', '때로는 침묵이 빛에 이르는 진정한 길이 되기도 합니다.', 66384),
(308392, 'koKR', '나그네의 로아 윌라마는 많은 숲부족의 마음속에 살아 있네.\n\n우리 종족의 아군임을 증명해 보이면, 틀림없이 위대한 매머드 본인께서 모습을 드러낼 걸세.', '', 66384),
(308391, 'koKR', '무시무시한 깜짝도마뱀의 형상을 한 모트암라는 전염병의 로아일세.\n\n풍문으로는 황혼 놈들이 우리의 로아에게 추악한 짓을 했다더군. 부서진 왕좌 지하 납골당에 내려가 직접 확인해 보게.', '', 66384),
(308389, 'koKR', '아, 필로 말인가. 동심을 관장하는 로아지. 필로는 나이 든 카파라의 모습을 하고 계시네.\n\n마른나무껍질 절벽에 옛날 방식대로 그분을 숭배하는 아이가 한두 명쯤 있을지도 모르지.', '', 66384),
(308386, 'koKR', '', '오른샨은 아미드랏실 뿌리 근처에 있을 거다. 자신의 실수를 곱씹고 있을 터.', 66384),
(308385, 'koKR', '의술의 로아 쿨지께서는 고귀한 천산갑의 형상을 하고 계시네.\n\n그분의 제단은 아탈아만 동쪽 언덕에 자리하고 있지. 좀 낡긴 했지만.', '', 66384),
(308338, 'koKR', '나라고 로아를 무조건 남들보다 더 잘 알거나... 덜 아는 건 아니라네.\n\n대신 각각의 로아를 어디에서 찾을 수 있는지 안내해 주는 건 가능하지.\n\n어느 쪽에 관심이 있나?', '', 66384),
(308335, 'koKR', '축복의 제단은 줄아만의 모든 로아를 숭배할 수 있는 곳이네.\n\n각 로아에게 바쳐진 제단과 사원도 있지만, 그곳까지 순례하는 건 쉽지 않지. 특히 신도가 적은 로아는 더더욱 그렇다네.\n\n동시에 여러 로아를 섬기는 걸 불쾌하게 여기는 로아도 일부 있네만, 하쉬우라 자네는 특별한 존재야.\n\n로아들은 자네의 비범함을 보았고, 여러 로아를 한꺼번에 모실 수 있도록 허락한 걸세. 그만큼 자네에게 축복도 내리려는 게야.', '', 66384),
(308331, 'koKR', '하쉬우라를 만나 영광일세.\n\n어떻게 도우면 되겠나?', '', 66384),
(308316, 'koKR', '', '어디 한번 보죠.', 66384),
(308314, 'koKR', '<룬이 또다시 눈앞에서 글자로 변화합니다.>\n\n내 무기가 지나간 자리엔... 전쟁이 끝났다.\n\n...모든 게 끝났다... 도시들은 불타 사라지고... 더는 전쟁도... 아무것도...\n\n오직... 가장 미약한 생명만이 살아남아... 수억 년을 지나며 진화해... 지금의 괴물과 짐승이 되었지...\n\n...마지막 물결이 닥치기 전에... 끝나기 직전... 나를... 배신...\n\n...나를 가뒀다...\n\n벌을 주기 위해... 원한 것을 내놓았다는 이유로...', '<룬이 또다시 눈앞에서 글자로 변화합니다.>\n\n내 무기가 지나간 자리엔... 전쟁이 끝났다.\n\n...모든 게 끝났다... 도시들은 불타 사라지고... 더는 전쟁도... 아무것도...\n\n오직... 가장 미약한 생명만이 살아남아... 수억 년을 지나며 진화해... 지금의 괴물과 짐승이 되었지...\n\n...마지막 물결이 닥치기 전에... 끝나기 직전... 나를... 배신...\n\n...나를 가뒀다...\n\n벌을 주기 위해... 원한 것을 내놓았다는 이유로...', 66384),
(308313, 'koKR', '', '이런, 이 시간의 길은 제가 본 그 어떤 곳보다도 뒤죽박죽이네요.', 66384),
(308312, 'koKR', '<룬이 다시 눈앞에서 형태를 바꾸더니, 읽을 수 있는 몇 줄의 문장으로 변화합니다.>\n\n제국의... 첫 공격...\n\n...도시... 사라지고... 또 하나... 더 남지 않을 때까지...\n\n...\n\n...나를 필요로 했다. 나에게 부탁했다... 위대한 아킨툰데에게...\n\n...무기를 만들어... 모두를 구해 달라고...', '<룬이 다시 눈앞에서 형태를 바꾸더니, 읽을 수 있는 몇 줄의 문장으로 변화합니다.>\n\n제국의... 첫 공격...\n\n...도시... 사라지고... 또 하나... 더 남지 않을 때까지...\n\n...\n\n...나를 필요로 했다. 나에게 부탁했다... 위대한 아킨툰데에게...\n\n...무기를 만들어... 모두를 구해 달라고...', 66384),
(308190, 'koKR', '이봐, 왔군! 모타는 네가 오길 바랐다.\n\n구덩이에서 싸우는 거 봤다.\n\n저번에는 잘했다. 하지만 응어리의 구덩이는 위험한 곳이야! 죽지 마라, $p!\n\n그래서 모타는 안전한 곳에만 머무르지.', '', 66384),
(308181, 'koKR', '', '선봉대가 공허첨탑을 향한 공격에 나서려고 집결하고 있습니다. 용사님도 합류하러 오셨습니까?\n\n경고드리지만, 공격이 시작되면 돌이킬 수 없습니다.', 66384),
(308176, 'koKR', '그래. 내 동족 말이다. 소용돌이에 들어가면 모든 걸 알 수 있을 것이야.', '', 66384),
(308162, 'koKR', '<낯선 룬이 공허의 마력에 빛을 내며 형태가 변화합니다. 이윽고 끊어진 문장이 읽히기 시작합니다.>\n\n위대한 종족...\n\n...우리가 세운 도시들... 헤아릴 수 없는 장대함... 하늘에서 빛나던...\n\n프레다케아... 지식과 학문이 찬란했던...\n\n...다가올 전쟁을 위한... 최강의 병기...', '', 66384),
(308154, 'koKR', '이제 지아단과 나는 못다 한 승부를 이어 나가야겠군. 고맙다. 전장에서 다시 볼 수 있길 바라지, $c|1이여;여;.', '', 66384),
(308153, 'koKR', '차로누스가 자기 투기장에서 최후를 맞다니, 이 얼마나 걸맞은 최후인가. 너희 세계에서 그렇게 많은 필멸자를 납치해 갔으니, 천벌을 받아 마땅했다.', '', 66384),
(308152, 'koKR', '', '실력이 대단하구나. 전장에서 다시 보길 바라지.', 66384),
(308151, 'koKR', '', '잘 싸워줬구나, 필멸자여. 차로누스는 더 이상 학살자의 오름길을 위협하지도, 너희 세계의 필멸자들을 붙잡아 투기장에 끌고 가지도 못할 것이다.', 66384),
(308132, 'koKR', '', '비디우스의 하수인들을 해치워라. 얼라이언스와 원한이 없다면 공허의 하수인들에게 집중하도록.', 66384),
(308130, 'koKR', '지아단에게 얼라이언스의 분노를 보여줘라, $c. 호드의 피를 덜 흘리고 싶다면, 해치울 공허의 하수인들은 얼마든지 있다.', '', 66384),
(308129, 'koKR', '', '어쩔 수 없을 때는 그렇지. 아니면 여기 없었겠지. 잘아타스가 아주 분명히 못 박았거든.\n\n그럼에도 비디우스와 나는 학살자의 오름길을 지배하고 있다. 우리의 다툼이 계속해서 분쟁과 고통을 낳아... 잘아타스의 공허폭풍에 더 많은 공허 마력을 만들어내는 한, 그 여자는 우릴 내버려둘 거다. 우리 기준으로 아주 괜찮은 거래지.\n\n도마나르 중에 기쁜 마음으로 섬기는 자는 없다.\n\n지금은... 그 여자 눈에 안 띄고 있을 뿐이다.', 66384),
(308127, 'koKR', '', '우리 도마나르는 투쟁을 좋아한다. 직접 싸우는 것도, 지켜보는 것도. 우리는 종종 세계들 사이의 틈으로 미끄러져 들어가 다른 세계에서 전사들을 데려와 우리 투기장에서 싸우게 한다.\n\n아제로스는 한동안 출입 금지의 영역이었지. 하지만 잘아타스의 침공 이후로는 아니다.\n\n비디우스는 얼라이언스를 찾았고, 나는 호드를 찾았다. 나는 영광에 대한 너희의 야망에 끌렸다. 증오를 놓지 않는 가장 가치 있는 자들. 평화 회담이나 조약 따위는 받아들이지 않는 자들을 찾아냈다.\n\n놈들을 이곳으로 데려와 가장 큰 소원을 이루게 해줬다. 얼라이언스를 해치우는 것. 놈들은 내게 감사해하고 있다. 나는 증오의 맛을 즐길 뿐.', 66384),
(308125, 'koKR', '<고개를 한쪽으로 갸웃거리는 비디우스>\n\n굳이 따지고 보면 그렇지.\n\n모든 도마나르는 잘아타스에게 굴복하도록 강요받았다. 도마나르의 본성에 반하는 일이지만, 그렇지 않으면 완전한 멸망뿐이었지. 그게 뭐가 재미있겠나?\n\n하지만 잘아타스는 자기 도구들 중 누가 가장 쓸모 있는지 잘 안다. 지아단과 나는... 별다른 쓸모를 못 느끼게 조처를 해뒀지. 잘아타스가 더 쉽게 휘두를 수 있는, 더 강하거나 더 협조적인 도마나르들이 따로 있거든.\n\n그래서 지아단과 나는 잘아타스의 간섭 없이 우리의 전쟁을 계속하고 있다. 우리는 그저... 그 여자의 눈에 띄지 않을 뿐이다.\n\n지금은 말이지.', '', 66384),
(308124, 'koKR', '먹을 가치도 없군...', '', 66384),
(308122, 'koKR', '아, 우리 도마나르를 두려움의 대상으로 만들어준 힘 덕분이지. 우리는 다른 세계로 들어가 마음껏 전투원을 가로챌 수 있다. 자발적인 이들이 가장 희귀하지만, 가장 재미있지...\n\n아제로스는 한동안... 출입 금지의 영역이었다. 하지만 잘아타스가 우리를 장악한 뒤로는 달라졌다.\n\n지아단과 나는 즉시 호드와 얼라이언스에 관심을 가졌다. 난 얼라이언스 중 가장 피에 굶주리고, 가장 분노로 들끓는 자들을 찾아 나섰다. 공허로부터 아제로스를 구하는 싸움 따위는 내던지고, 오직 호드를 해치울 기회만 보고 여기에 오길 원하는 놈들 말이다.\n\n얼마나 많았는지 보고 정말 즐거웠다.\n\n그래서, 놈들은 스스로 여기에 왔다. 내 이름 아래 스스로의 의지로 싸우지. 나는 즐길 뿐이야.', '', 66384),
(308120, 'koKR', '호드와의 대결을 원치 않는다면, 지아단이 아제로스까지 정복하지 못하게 막는다는 생각으로 날 돕는 것도 고려해라.', '', 66384),
(308110, 'koKR', '당신도 그 목소리를 들으셨나요, $p 님?', '', 66384),
(308098, 'koKR', '', '비디우스는 교활한 적이다. 온갖 무기에 능숙하다. 놈과의 대련은 어느 것도 이전과 같았던 적이 없다.\n\n최근 우리의 충돌은 규모가 큰 전투가 되었다. 결투라기보다 전쟁이지. 나는 결투를 더 좋아하지만, 이런 방식도 비디우스의 지성을 날카롭게 유지하거든. 영겁의 세월을 보내다 보면 어쩌다 한 번씩 방식에 변주를 줘야 하는 법.\n\n호드와 얼라이언스의 등장은 우리의 승부를 더욱 흥미롭게 만들었을 뿐이다.', 66384),
(308059, 'koKR', '그럼 정해졌군. 투기장에서 보자, $c.', '', 66384),
(308058, 'koKR', '', '그런 다음 우리는 끝없는 전쟁을 이어가겠다, 비디우스. 새로운 열정으로 말이다.', 66384),
(308057, 'koKR', '꽤 유쾌한 구경거리가 되겠는데. 네 투기장에서 스스로 최후를 맞이하겠구나, 차로누스.', '', 66384),
(308054, 'koKR', '그래, 내 투기장을 완전히 난장판으로 만들었군! 실로 즐겁구나! 이런 실력을 가진 필멸자가 올 줄은 몰랐다. 제안을 하나 하지.', '', 66384),
(308053, 'koKR', '', '차로누스! 역시 네놈이었군. 어둠접목에 사족을 못 쓰더니. 네 접목사는 죽었다.', 66384),
(308052, 'koKR', '아, 드디어 왔구나! 자리를 비운 걸 용서해라. 어떤 이들과는 달리, 나는 잘아타스가 부르면 응하거든.', '', 66384),
(308047, 'koKR', '잘 숙성됐네요.', '잘 숙성됐네요.', 66384),
(308045, 'koKR', '이건 숙성 기간이 얼마 안 되는 품종에 속해요. 겨우 천이백 년밖에 안 됐거든요.', '이건 숙성 기간이 얼마 안 되는 품종에 속해요. 겨우 천이백 년밖에 안 됐거든요.', 66384),
(308044, 'koKR', '오, 치즈네요! 숙성된 건가요?', '오, 치즈네요! 숙성된 건가요?', 66384),
(308034, 'koKR', '지금까지 공허를 연구할 이런 기회는 한 번도 없었어요.', '', 66384),
(308031, 'koKR', '', '우리와 멀어진다면 그래선 안 되지.', 66384),
(308030, 'koKR', '', '당연히 그분이 이끄는 곳으로 가야지요!', 66384),
(308029, 'koKR', '', '그분의 목소리를 들었습니다!', 66384),
(308028, 'koKR', '네 오만이 우리가 쌓아 올린 걸 위태롭게 하고 있다!', '', 66384),
(308027, 'koKR', '하지만 오만과... 경솔함이 뒤따르는군.', '', 66384),
(308026, 'koKR', '알른하라의 손길이 너에게 닿은 건 분명하구나.', '', 66384),
(308025, 'koKR', '', '여신님?', 66384),
(308024, 'koKR', '', '(숨을 헐떡임)', 66384),
(308023, 'koKR', '', '그렇게 동굴에 틀어박혀, 시들어버린 과거를 한탄하기만 할 겁니까?', 66384),
(308022, 'koKR', '', '우리가 이미 놓아버린 과업이죠.', 66384),
(308021, 'koKR', '', '여신을 지키려고 싸웁니다!', 66384),
(308020, 'koKR', '', '우리처럼 여신의 노래를 듣는 자들입니다!', 66384),
(308019, 'koKR', '', '...이 성지가 부정을 타게 했지.', 66384),
(308018, 'koKR', '', '이곳에 이방인을 불러들여...', 66384),
(308017, 'koKR', '신성한 전통을 마구잡이로 무시해 놓고 그런 소리를 해?', '', 66384),
(308016, 'koKR', '', '그런 건 오래전에 내쳤잖느냐, 오르웨냐.', 66384),
(308015, 'koKR', '', '존중?', 66384),
(308014, 'koKR', '', '다만, 굳이 폭력을 고집하겠다면...', 66384),
(308013, 'koKR', '', '존중하는 태도로.', 66384),
(308012, 'koKR', '', '대화를 하러 왔다.', 66384),
(308011, 'koKR', '', '모습을 드러내라.', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(308010, 'koKR', '', '이제 그만하지.', 66384),
(307978, 'koKR', '...돌이킬 수 없는 일도 있다.', '', 66384),
(307977, 'koKR', '아들아, 세상에는...', '', 66384),
(307976, 'koKR', '(한숨)', '', 66384),
(307975, 'koKR', '포기하지 마세요, 아버지.', '', 66384),
(307974, 'koKR', '전부는 아니잖아요.', '', 66384),
(307973, 'koKR', '그 시절의 나는 로서와 함께 죽었다.', '', 66384),
(307972, 'koKR', '(한숨) 못 해.', '', 66384),
(307971, 'koKR', '나는...', '', 66384),
(307970, 'koKR', '진정한 성기사로 돌아오세요.', '', 66384),
(307969, 'koKR', '다시 들어 주세요.', '', 66384),
(307968, 'koKR', '어떻게? 네가 왜...', '', 66384),
(307967, 'koKR', '이건.. 내... 방패.', '', 66384),
(307966, 'koKR', '이제 그만 놓아주세요.', '', 66384),
(307965, 'koKR', '...줄곧 가슴에 담아두셨겠죠.', '', 66384),
(307964, 'koKR', '...분노를...', '', 66384),
(307963, 'koKR', '죄책감과...', '', 66384),
(307962, 'koKR', '로서께서 쓰러진 날, 무슨 일이 있었는지 압니다.', '', 66384),
(307961, 'koKR', '스스로를 용서하실 때가 됐어요.', '', 66384),
(307960, 'koKR', '제가 봤을 땐...', '', 66384),
(307959, 'koKR', '용서해 줄 수 있겠느냐?', '', 66384),
(307958, 'koKR', '자제심을 잃으셨죠.', '', 66384),
(307957, 'koKR', '그런데 그 순간,', '', 66384),
(307956, 'koKR', '일부러 저를 해칠 분이 아니라는 건 압니다.', '', 66384),
(307955, 'koKR', '아버지.', '', 66384),
(307954, 'koKR', '우리가...', '', 66384),
(307953, 'koKR', '나는 그저...', '', 66384),
(307952, 'koKR', '아라토르, 나는...', '', 66384),
(307951, 'koKR', '아들아...', '', 66384),
(307933, 'koKR', '<작은 트롤 발자국이 산산조각 난 도자기 찻주전자까지 듬성듬성 이어져 있습니다.\n\n운반하던 이가 걸려 넘어뜨린 듯 보입니다.\n\n주전자의 뚜껑은 두 조각으로 깨져 있고, 손잡이는 떨어져 나갔으며, 금이 간 모양새로 보아 다시는 물을 담을 수 없을 것입니다.\n\n운반자는 이를 여기 두고 간 듯하며, 카파라들이 호기심 가득하게 살펴보고 있습니다.>', '<작은 트롤 발자국이 산산조각 난 도자기 찻주전자까지 듬성듬성 이어져 있습니다.\n\n운반하던 이가 걸려 넘어뜨린 듯 보입니다.\n\n주전자의 뚜껑은 두 조각으로 깨져 있고, 손잡이는 떨어져 나갔으며, 금이 간 모양새로 보아 다시는 물을 담을 수 없을 것입니다.\n\n운반자는 이를 여기 두고 간 듯하며, 카파라들이 호기심 가득하게 살펴보고 있습니다.>', 66384),
(307916, 'koKR', '', '흠... 그래. 그렇겠군. 훼방꾼이라.', 66384),
(307906, 'koKR', '', '솔직히 저도 잘 모르겠어요. 달라란이 바다에 가라앉은 뒤, 은빛 서약단이 수습할 수 있는 걸 찾으려고 나섰거든요. 그중 한 번에, 살아남은 이들과 함께 이 비룡들을 발견했어요! 달라란이 파괴될 때 비룡들이 구해줬다고 하더라고요. 그 후로 저희가 이 아이들을 돌보고 있어요.\n\n달라란의 어느 예술가가 비룡들을 만들었다는 소문도 있었어요. 이 비룡들을 꿈에서 보고 그림으로 많이 그렸는데, 단 한 점도 팔지 않았대요. 이유를 묻자, 달라란을 위해 그린 그림이니, 달라란 사람들이 그들을 필요로 할 때 그림에서 깨어나 도울 거라고 했다더군요.\n\n말도 안 되는 이야기죠? 검증도 안 된 이야기이기도 해요.', 66384),
(307904, 'koKR', '', '아, 전 신경 쓰지 않으셔도 돼요, $n 용사님.\n\n이 삽질도 신화 속 야수들을 돌보는 기쁨의 일부일 뿐이거든요.', 66384),
(307903, 'koKR', '지아단은 셀 수 없는 세월 동안 내 숙적이었다. 참혹하고도 매혹적인 살육의 물결 속에서 학살자의 오름길을 두고 패권 경쟁을 펼쳤지.\n\n서로를 파괴하기 직전까지 몰아간 적만 해도 무수히 많다. 넓은 땅덩어리의 주인이 수없이 바뀌었지.\n\n참으로 즐거운 승부다. 달리 바랄 게 없다.', '', 66384),
(307902, 'koKR', '<죽은 개구리를 기점으로 과일 조각과 작은 카파라, 트롤의 발자국이 흘러가 비어 있는 바구니로 이어집니다.\n\n바구니에는 커다란 구멍이 나 있는데, 개구리와 실랑이를 벌이다 생긴 것으로 보입니다.\n\n카파라들은 과일을 좋아하는 듯하며, 바구니가 망가진 일을 그저 즐거운 우연으로 받아들이고 있습니다.>', '<죽은 개구리를 기점으로 과일 조각과 작은 카파라, 트롤의 발자국이 흘러가 비어 있는 바구니로 이어집니다.\n\n바구니에는 커다란 구멍이 나 있는데, 개구리와 실랑이를 벌이다 생긴 것으로 보입니다.\n\n카파라들은 과일을 좋아하는 듯하며, 바구니가 망가진 일을 그저 즐거운 우연으로 받아들이고 있습니다.>', 66384),
(307901, 'koKR', '물건이 전부 불타 없어졌는데도, 그 목소리가 계속 귓가에 들렸다.\n\n하지만 지금은 조용하다. 드디어 내 스스로 생각할 수 있게 됐다!', '', 66384),
(307897, 'koKR', '아직도 날로라크를 본 충격이 가시질 않는다. 푸르그를 치유하는 걸 보고도 실감이 안 나!\n\n그분이 어떤 주문을 써야 하는지 알려주셨다.\n\n이제 다른 이들을 돕는 방법을 알겠다. 푸르그가 도와주면, 우리 둘이서 고쳐낼 수 있을 거다.', '', 66384),
(307892, 'koKR', '아, 안 돼! 푸르그!\n\n푸르그를 구하려면 어떻게 해야 하지?', '', 66384),
(307858, 'koKR', '', '그 외에 무슨 이유가 더 있겠나?\n\n꼬마 $rs, 너희 지도자들이 우리가 가진 싸움의 가치를 보지 못하는 건 비극이다. 여기서 목적은 단 하나다. 우린 싸우기 위해 존재한다.\n\n용감한 자, 가치 있는 자, 그리고 정신 나간 자만이 이곳에서 무기를 들 용기를 아는 법이지. 그런 자들만이 치열한 전장의 기쁨을 맛보게 된다.\n\n이 전장에서, 너는 호드를 위해 싸우는 게 아니다. 나를 위해 싸우는 거다. 너는 내 뜻에 따라 싸우고 죽을 것이며, 함께 비디우스와의 싸움을 즐기게 되겠지.\n\n훌륭히 싸우면 영광을 선사하마.', 66384),
(307854, 'koKR', '크아레쉬에서 참 멀리도 왔군요. 분쟁에 이렇게 휘말릴 생각은 추호도 없었습니다. \n\n고요한 삶이란 발상 자체가 저 지평선의 아득한 신기루처럼 보입니다.', '크아레쉬에서 참 멀리도 왔군요. 분쟁에 이렇게 휘말릴 생각은 추호도 없었습니다. \n\n고요한 삶이란 발상 자체가 저 지평선의 아득한 신기루처럼 보입니다.', 66384),
(307853, 'koKR', '이런 삶을 제가 감당할 수 있을지 모르겠어요. 다른 이들의 도움에 의지해야겠죠...\n\n<공허가 붕대를 밀어내듯 일렁이자, 에테리얼이 얼굴을 찡그립니다>.\n\n엘프에게 이 떨림을 어떻게 버티는지 배울 수 있을지도 모르겠네요.', '이 고통은 견딜 수가 없어요... 제 본질이 두 방향으로 비틀리고 끌려가는 것 같아요.\n\n어둠수호병이 디멘시우스를 되살리려 했던 일을 기억해요... 그때 벌어질 뻔한 참혹한 파괴도요.\n\n<몸을 떠는 에테리얼>\n\n...그런데도 제 안의 어둠이 공허의 뜻을 따르라고 속삭여요. 우리는 결국 영원히 그 명령에 묶여 살아야 하는 걸까요?', 66384),
(307852, 'koKR', '', '내 부름에 응한 호드 배신자들은 얼라이언스의 살점을 갈망하며 피가 들끓고 있다. 너도 그렇느냐?', 66384),
(307850, 'koKR', '과거를 돌아볼수록 더욱 분명해져요.\n\n우리 내면의 이 어둠과 함께 살아가는 건 쉽지 않겠지만... 그래도 혼자가 아니라는 사실이 큰 위안이 돼요.', '', 66384),
(307849, 'koKR', '이 얼라이언스 배신자들의 가슴속에서 불타는 증오... 정말 감미롭군. 너도 복수를 위해 싸우는 거냐?', '', 66384),
(307848, 'koKR', '우리 공허 엘프는 공허가 속삭이는 유혹을 누구보다 잘 알고 있어요.\n\n일부는 우리를 곱지 않게 보지만, 얼라이언스의 환대 덕분에 추방자로서 살아갈 운명에서 벗어날 수 있었죠.\n\n그렇다면 이 에테리얼들을 받아들이지 않는 건 잔인한 위선이겠죠. 공허의 손길이 닿는 삶이라도... 여전히 살아갈 가치가 있고, 구할 가치가 있으니까요.', '우리 공허 엘프는 공허가 속삭이는 유혹을 누구보다 잘 알고 있어요.\n\n일부는 우리를 곱지 않게 보지만, 얼라이언스의 환대 덕분에 추방자로서 살아갈 운명에서 벗어날 수 있었죠.\n\n그렇다면 이 에테리얼들을 받아들이지 않는 건 잔인한 위선이겠죠. 공허의 손길이 닿는 삶이라도... 여전히 살아갈 가치가 있고, 구할 가치가 있으니까요.', 66384),
(307846, 'koKR', '', '그 전투! 그 전율!\n\n다 봤다, $c. 너도 피가 들끓었겠지? 나랑 똑같아.\n\n쓰러져 간 많은 깨진엄니의 죽음을 애도하마. 하지만 우리가 서로 칼을 맞댄 건 사실이고, 줄아만의 모든 트롤은 칼을 뽑는다는 게 무슨 뜻인지 안다.', 66384),
(307845, 'koKR', '가족과 맺은 유대는 무엇과도 바꿀 수 없어요. 여동생과 다시 만나도록 도와주셔서 정말 감사드려요.\n\n가능하면 베란 같은 이들을 더 찾아볼 거예요. 어둠의 끝에서 끌어낼 수 있는 이들이 분명 더 있을 테니까요.', '', 66384),
(307842, 'koKR', '', '주위를 보십시오. 이 우주의 폐허 같은 곳에서도 도마나르는 호드와 얼라이언스를 구분해 냈습니다. 붉은색과 파란색을 나눴습니다. 원래 그런 법입니다.\n\n전쟁이 있든 없든, 용서하지 않는 이들은 늘 존재합니다. 잊지 않는 이들도 그렇습니다. 제 가족도 브렌나담에 있었습니다. 외가가 농사꾼이었죠. 그분들도 잊지 않을 것이고, 저도 잊지 않았습니다.\n\n전쟁은 끝났어도, 아직 싸움이 필요한 사람들에게는 싸움이 계속됩니다.', 66384),
(307836, 'koKR', '크아레쉬에서 참 멀리도 왔군요. 분쟁에 이렇게 휘말릴 생각은 추호도 없었습니다. \n\n고요한 삶이란 발상 자체가 저 지평선의 아득한 신기루처럼 보입니다.', '크아레쉬에서 참 멀리도 왔군요. 분쟁에 이렇게 휘말릴 생각은 추호도 없었습니다. \n\n고요한 삶이란 발상 자체가 저 지평선의 아득한 신기루처럼 보입니다.', 66384),
(307834, 'koKR', '오래전 우리 종족은 전장에서 영광을 얻었지. 지금은 의회에서 말로 영광을 얻고 있네. 그것도 좋은 삶이지만, 내 길은 아니었지.\n\n나는 우리 종족을 위협할 다음 전쟁에 대비하고자 이 이질적인 세계까지 왔다네. 그날이 오면 나는 이미 강해져 있을 것이고, 전투로 단련되어 있을 걸세.\n\n자네가 이곳에 와 있는 걸 보면, 자네 역시 스스로 영광을 쟁취할 용기가 있는 것 같네. 선조들이 전장에서 자네를 지켜보기를 바라지.', '', 66384),
(307832, 'koKR', '특이점 고정기 작업을 돕는 건 정말 즐거웠습니다. 이 장치는 공허의 비정상적인 마력을 엔트로피 흡수원 주위에 응축시켜 무효화하는데, 아주 무시무시한 제습기 같다고나 할까요. 참으로 흥미롭습니다!\n\n물론 응축 매트릭스는 온전해야 합니다. 그렇지 않으면 마력이 안쪽으로 붕괴할 겁니다.\n\n그래도 구원호의 왜곡 발생기를 제작하면서 매트릭스 보강과 내부 붕괴에 대해 이것저것 배웠으니 걱정하지 마십시오!', '', 66384),
(307831, 'koKR', '복수가 제 여동생을 지배하고 있어요. 그 아이는 깨닫지 보지 못해요.\n\n공허의 속박에 맞서 더 강하게 버티고 있지만, 지금은 분노밖에 눈에 들어오지 않아요.', '', 66384),
(307823, 'koKR', '나는 어두운 시절을 많이 봐왔네, $p. 정말 많이 말이네.\n\n확실히 하늘을 나는 건 내게 큰 도움이 돼. 하지만 모두가 그리핀을 가진 건 아니잖나!\n\n그렇지 않다면, 나만의 그리핀을 찾아내야 하지.\n\n나한테는... 농담이 도움이 되네. 힘겨운 때에 웃지 못한다면... 글쎄, 힘든 시기는 결국 닥치게 되어 있지. 그렇다면 차라리 웃어넘기는 편이 낫지 않겠나.\n\n그리고 친구들이랑 마시는 술 한 잔은 어떤 문제든 작아 보이게 만든다네. 술보다 친구들이 더 그렇지!\n\n그리고 어떤 때는 준비가 됐든 안 됐든 그냥 앞으로, 창공으로 나아가야 할 때가 있어. 그렇지 않나?', '', 66384),
(307821, 'koKR', '나는 오래전 이곳에서 둠해머와 함께 로서의 군대에 맞서 싸웠지.\n\n그리고 지금은 그의 이름을 잇는 이들과 함께 일하고 있으니... 인간들과 협력하고 있다는 것 자체가 참 기묘한 일이네.\n\n하지만 내게 변화를 불러온 것도 바로 그런 인간의 기묘함이었지. 티리온 폴드링. 그전까지 내가 아는 인간이란 우리가 그네들의 땅에 전쟁을 가져왔다는 이유로 우리를 증오하는 존재뿐이었네.\n\n그런데 다른 이들은 사냥해야 할 짐승 정도로만 본 나에게서, 폴드링은 다른 무언가를 보았지. 우리의 첫 만남에서 서로 죽이려 들었음에도, 티리온은 나한테 친절과 연민을 보여줬네.\n\n티리온을 통해 나는 인간도 오크와 다르지 않다는 걸 깨닫게 되었지. 명예를 지닌 자도 있고, 그렇지 않은 자도 많아. 세월이 흐르며 보니 로서의 후예들은 명예를 지닌 쪽이더군. \n\n그리고 티리온도 그 말에 동의했을 걸세.', '', 66384),
(307819, 'koKR', '$p, 이 지역은 암흑 호드 사기꾼으로 가득하네. 명예에 따라 몰아내야 해.', '', 66384),
(307806, 'koKR', '바닷가에서 아침 식삿거리를 낚는 마른나무껍질 아이들도 포함해서 말이다!', '', 66384),
(307805, 'koKR', '줄아만 곳곳의 마른나무껍질들이 할라지의 사원으로 순례를 와, 사냥에서 얻은 것을 한 조각 바치며 숭배를 올리곤 해.', '', 66384),
(307804, 'koKR', '그녀는 우리가 이 땅에 왔을 때부터 아마니를 이끌었으며, 지금까지도 우리 부족의 상징이자 정신으로 남아 있습니다.', '', 66384),
(307803, 'koKR', '', '그림자소나무는 오래전에 잔알라이의 핵심 숭배 부족이었지. 옛 로아 전령이 사원의 불길에서 본 환영을 따라 부족을 안전한 곳으로 이끌었기 때문이야.', 66384),
(307802, 'koKR', '', '용사가 기력을 되찾으면 다시 도전하게나.', 66384),
(307801, 'koKR', '', '신병! 이 시험은 무식한 힘만 보이려는 게 아니라, 절제를 아는지 보는 자리였네.', 66384),
(307800, 'koKR', '잠깐 , 아뇨! 죄송합니다. 제 의미는...', '', 66384),
(307799, 'koKR', '', '깨진엄니는 네 위대한 로아 중에서도, 그분의 단도직입적인 성격과 전장에서의 훌륭한 무예를 가장 높게 평가하지.', 66384),
(307797, 'koKR', '처음에는 내가 하는 말을 전혀 믿지 않더이다. 롬매스는 내가 자기를 조롱하는 거라고 생각했소. 하지만 에온카의 씨앗이 그들의 흥미를 끌었지.\n\n그들이 내놓을 수 있었던 것은 모두 가설뿐이었소. 가장 그럴듯한 설명은 이렇소. 태양샘이 과도하게 활성화되면서 빛의 영향이 땅을 타고 퍼져, 영원노래 숲의 나무와 뿌리까지 스며들었다는 것이오. 그리고 모든 뿌리는 하란다르로 이어지니...\n\n<샬라드라실의 뿌리를 가리키는 할두런>\n\n군단척결군 시절, 샬라드라실의 뿌리는 어둠에 잠식되었소. 어쩌면 그 때문에 태양샘에서 번져 나온 빛에 더욱 쉽게 물들었는지도 모르오.', '', 66384),
(307796, 'koKR', '제가 바란 건 단 하나였습니다. 고향을 지킬 힘.\n\n덤으로 멋진 창 하나쯤 더 생기면 좋겠지요.\n\n근데 지금 제 모습을 보십쇼.', '', 66384),
(307794, 'koKR', '', '왜 멍하니 서 있는 건가, 흠?\n\n전사의 수련은 끝이 없지. 자네처럼 숙련된 전사라도 마찬가지라네, $n.', 66384),
(307793, 'koKR', '아, 요만큼 마법에 손대고, 저만큼 건드리기도 했고. 몸을 잃어버려서 새 몸이 필요했거든. 늘 있는 일이지!\n\n근데 우리 초면이잖아. 지금 다 털어놓을 이유는 없지.\n\n남서쪽 해변가 근처에 특별한 곳이 있어. 시간 되면 한번 와주겠어?', '', 66384),
(307791, 'koKR', '그래, 인형 몸에 갇혔다. 근데 그게 뭐 어쨌다고?', '', 66384),
(307784, 'koKR', '서둘러요. 할 일이 태산인데.', '서둘러요. 할 일이 태산인데.', 66384),
(307780, 'koKR', '행운을 빌어요. 찾아도 으르렁거리거나, 또 도망치겠지만!', '', 66384),
(307779, 'koKR', '칸자요? 같이 놀던 나무다리 쪽으로 뛰어가는 걸 봤어요.', '', 66384),
(307773, 'koKR', '', '이 괴물들은 다른 이들을 공허 속에 빠뜨리려 해요... 그런 운명은 누구에게도 일어나선 안 돼요.', 66384),
(307771, 'koKR', '진정해라, 베란. 복수에 너 자신을 잃는 건 공허에 너 자신을 잃는 것보다 나을 게 없다.', '', 66384),
(307769, 'koKR', '태양샘이 공격당한 지역 부근에서 숨겨진 갑옷과 무기 저장고가 발견됐다는 말, 들었을지 모르겠네요.\n\n음, 트리암 말로는 무장 대부분이 손상된 부분 하나 없다고 해요. 긴 세월 방치되어 있었던 거죠. 저는 본격적으로 사용하기 전에 온전히 사용할 수 있는지 점검하고 있고요.\n\n이곳에 대장간을 마련하고 기동대 병력을 도우라는 지시를 받았으니, 필요한 게 있으면 말씀하세요!', '', 66384),
(307767, 'koKR', '반가워요, $r 친구. 뭘 도와드릴까요?', '', 66384),
(307760, 'koKR', '', '네 영혼 일부가 아직도 과거, 격전이 벌어지던 때에 머물러 있는 게 보이는군.\n\n이 순간 이전의 시점으로 이동하고 싶나?\n\n|cFF0000FF(언제든 다시 잔알라이의 형상과 대화하여 이 시기의 아탈아만으로 돌아올 수 있습니다.)|r', 66384),
(307757, 'koKR', '', '네 영혼은 이미 이 전투를 겪은 또 다른 존재와 연결되어 있구나.\n\n시간을 넘어, 이 순간을 넘어가고 싶느냐?\n\n|cFF0000FF(언제든 다시 잔알라이의 형상과 대화하여 이 전투를 재개할 수 있습니다.)|r', 66384),
(307751, 'koKR', '', '비디우스가 내 전언을 받았군. 오래 걸리지 않을 거다. 놈은 유리한 협상을 아주 좋아하니까. 뭘 알아냈나?', 66384),
(307750, 'koKR', '이 고통은 견딜 수가 없어요... 제 본질이 두 방향으로 비틀리고 끌려가는 것 같아요.\n\n어둠수호병이 디멘시우스를 되살리려 했던 일을 기억해요... 그때 벌어질 뻔한 참혹한 파괴도요.\n\n<몸을 떠는 에테리얼>\n\n...그런데도 제 안의 어둠이 공허의 뜻을 따르라고 속삭여요. 우리는 결국 영원히 그 명령에 묶여 살아야 하는 걸까요?', '이 고통은 견딜 수가 없어요... 제 본질이 두 방향으로 비틀리고 끌려가는 것 같아요.\n\n어둠수호병이 디멘시우스를 되살리려 했던 일을 기억해요... 그때 벌어질 뻔한 참혹한 파괴도요.\n\n<몸을 떠는 에테리얼>\n\n...그런데도 제 안의 어둠이 공허의 뜻을 따르라고 속삭여요. 우리는 결국 영원히 그 명령에 묶여 살아야 하는 걸까요?', 66384),
(307746, 'koKR', '놈들이 제 안에 주입한 공허는 아직도 안에서 울부짖지만... 이 펜던트를 보면 크아레쉬에서 살던 기억이 어둠을 가르고 떠오릅니다.\n\n이 보석은 어머니의 것이었어요... 아버지가 주신 선물이자, 두 분의 조건 없는 사랑을 나타내는 상징이었죠.\n\n어둠은 여전히 제게 굴복하라고... 파괴하라고 속삭이지만, 이제는 더 아득하게 느껴집니다. 제 마음을 옥죄던 그 부패한 힘도 전보다 느슨해졌어요.', '', 66384),
(307743, 'koKR', '아, 네. 저는 기동대 동물 조련사예요. 언제든 비행 병력을 받아들일 수 있도록 준비해야 하거든요.\n\n게다가 그것만으로도 모자라서, 기동대가 확보할 수도 있는 표본까지 제가 맡으라네요. 순찰대장도 그게 뭐가 될지는 전혀 모르겠다고 하셨지만요.\n\n이게 바로 하사관의 삶이죠. 더 없으시면 저는 다시 일하러 가볼게요.', '', 66384),
(307740, 'koKR', '서둘러 주세요. 할 일이 많아요.', '', 66384),
(307738, 'koKR', '당연하죠. 하지만 대가가 따르지 않습니까?\n\n우리의 것을 보존하면서 눈앞의 적을 물리칠 방법이 틀림없이 있을 겁니다.\n\n여군주 다크글렌이 어떻게 생각하든, 둘 다 해낼 수 있습니다. 저 사람은 어둠의 힘에 집착한 나머지 섬세했던 자신의 접근 방식을 완전히 잃어버린 겁니다.', '', 66384),
(307736, 'koKR', '모든 일에... 그런 방식으로 접근하니까 그렇죠! 유적 조사든, 생소한 마법 탐구든, 강력한 유물 보존이든 말입니다!\n\n\'여군주\' 다크글렌은 역사를 보존하려 한다기보다, 역사를 위협하는 어둠을 이해하는 데 관심이 더 많습니다. 그 과정에서 파괴적인 방법을 택하는 경우도 있고 말이죠.', '', 66384),
(307734, 'koKR', '여군주 다크글렌의 편을 들어주러 오신 건가요, $C님?', '', 66384),
(307732, 'koKR', '', '성물회 소속이냐고요? 제가요? 아닙니다.\n\n물론 성물회의 연구를 늘 흥미롭게 지켜보고 있긴 합니다. 태더란이 주최하는 원정 후원 행사에도 몇 번이나 기부했을 정도니까요.\n\n다만 안타깝게도, 대검사관께서 가입을 허락하신 적은 단 한 번도 없습니다. 어딘가 마음에 들지 않게 굴었나 봅니다.\n\n<슬며시 웃는 여군주 다크글렌>\n\n그런데도 암흑 마법과 역사 양쪽에 조예가 있는 사람이 필요해졌고, 결국 저 이상으로 자격을 갖춘 사람이 없었죠.\n\n제 능력을 부정할 순 없었는지, 대신 안도렌을 붙여서는 잔소리를 늘어놓게 하고 있답니다. 뭐, 솔직히 말하면 이젠 거의 귀에 들어오지도 않지만요.', 66384),
(307730, 'koKR', '', '<한숨을 내쉬는 여군주 다크글렌>\n\n지금 실버문 분위기에... 제 평소 수행원들을 데리고 다니는 건 현명하지 않겠더군요.\n\n블록치니우스가 자리를 비운 동안 대신할 사람을 구했어요. 될 수 있으면 예의를 지켜 주시겠어요? 아주 성실한 친구라서요.', 66384),
(307728, 'koKR', '', '<당신을 훑어보며 고개를 갸웃거리는 여군주 다크글렌>\n\n자, $C님처럼 중요하신 분이 무슨 일로 절 찾아오셨을까요?', 66384),
(307727, 'koKR', '', '어리다니요... 기지에서는 제가 탐험가 훈련생 중에서 제일 나이가 많았어요.\n\n그리고 레아나와 함께 유물을 연구하기 시작했는데, 수습생으로 받아주겠다고도 했죠.\n\n실버문 같은 도시는 처음 와봐요. 정말 웅장해요! 발드라켄도 가봤지만, 여기는 사람이 훨씬 더 많아요.', 66384),
(307725, 'koKR', '', '아, 안녕하세요!', 66384),
(307724, 'koKR', '', '순찰대장께서는 제 유물 연구 경험이 앞으로 닥칠 여러 위협에 대응하는 데 큰 도움이 될 것이라 판단하셨습니다.\n\n원래는 저는 용비늘 원정대 소속으로 유물을 분류하고 있었는데, 야영지에 태양샘 습격 소식이 날아들었어요. 그래서 고향 실버문으로 급히 귀환하는 이들에 합류했죠.\n\n옛날 쿠엘탈라스 주민이 수라마르 방어에 힘을 모았던 때를 아직도 잊지 않았습니다. 저도 힘닿는 데까지 도울 겁니다.', 66384),
(307722, 'koKR', '', '반가워요, $r 친구.', 66384),
(307720, 'koKR', '얼마 전 도시가 공격받은 이후로 회수한 유물들을 저희 소수 인원이 조사하고 있습니다. 이 유물들에 잠재된 공허 마력이 스며든 듯한데, 덕택에 잠재력이 크게 높아진 것으로 보이더군요.\n\n물리적 성질도 변해 외형까지 눈에 띄게 달라졌습니다! 흥미롭지 않나요?\n\n우리에게 위협이 되지 않는다는 것이 확실해지면, 이 힘을 우리 병력도 활용할 수 있도록 장비로 만들어 보려고 합니다.', '', 66384),
(307718, 'koKR', '정말 흥미로운 발견이에요!', '', 66384),
(307717, 'koKR', '', '잘아타스가 태양샘을 공격했을 당시, 근처 건물이 손상되었습니다. 구조대가 생존자를 찾기 위해 진입했을 때, 수년 전 불타는 군단의 침공 당시 숨겨졌던 무기와 방어구 은닉처가 발견되었죠.\n\n현재 그중 어떤 장비가 안전하고 실용적인지 분류하고 있습니다. 우리에겐 무기와 방어구가 절실히 필요합니다. 특히 순찰대장이 새로 조직한 기동대와 함께라면 더욱 그렇죠.', 66384),
(307715, 'koKR', '', '안녕하세요. 조금 바쁜데, 필요하신 거라도 있나요?', 66384),
(307712, 'koKR', '', '가라, $rs. 네 일이 끝나면 합류해라. 우리는 비디우스를 직접 상대하겠다.', 66384),
(307708, 'koKR', '', '내게 와라, $n. 내 숙적 비디우스의 병력이 전진 중이다.', 66384),
(307706, 'koKR', '', '어찌 됐든 증오의 첨탑으로 가라, $rs. 가서 보자.', 66384),
(307691, 'koKR', '이 $c|1이;가; 내 접목사를 해치우고 거처를 쑥대밭으로 만들었단 말이지. 감탄스럽군. 이 필멸자가 동료들을 모아 내 투기장에서 싸운다면, 너희 둘의 대결에서 빠져 주겠다.', '', 66384),
(307689, 'koKR', '속박되어 있어서 다행이야. $C, 너는 그 접목사를 찾아서 처리해라. 우리가 이 괴물을 약화시키겠다. 마지막 일격은 네 몫이다.', '', 66384),
(307688, 'koKR', '', '우리 힘을 합쳐도 이 괴물, 비디우스를 끝내기엔 부족할지도 모른다.', 66384),
(307687, 'koKR', '내 가죽세공 용품들은 칼리카 것만큼 화려하진 않아도 훨씬 튼튼한 물건일세!', '내 가죽세공 용품들은 칼리카 것만큼 화려하진 않아도 훨씬 튼튼한 물건일세!', 66384),
(307686, 'koKR', '바늘이랑 실도 가죽만큼이나 중요하네!', '바늘이랑 실도 가죽만큼이나 중요하네!', 66384),
(307683, 'koKR', '', '조만간 결투를 재개할 수 있을 거다. 그때까지는... 함께 싸우는 걸 참아줘야겠다.', 66384),
(307681, 'koKR', '방해를 받으니 짜증 나는군. 호드랑 얼라이언스가 싸우는 걸 즐기고 있었는데.', '', 66384),
(307671, 'koKR', '', '공허가 태양샘을 공격한 이후로, 우리 병력은 쿠엘탈라스 전역에서 벌어지는 적의 주요한 공격을 막는 데 집중하고 있습니다.\n\n순찰대 사령관 할두런 브라이트윙 님께서는 새로운 공격이 발생하는 즉시 대응할 수 있는 민첩한 기동대를 꾸리라고 명하셨습니다. 혼란을 틈타 움직이는 오랜 적들도 있으니, 그들 역시 우리가 주시해야 한다고 말이죠.\n\n첫 임무가 정해지면 바로 연락드리겠습니다.', 66384),
(307669, 'koKR', '', '안녕하세요, $c님. 등록하러 오셨습니까?', 66384),
(307666, 'koKR', '사업 때문에 왔죠.\n\n당신이 관여할 바는 아닙니다.', '사업 때문에 왔죠.\n\n당신이 관여할 바는 아닙니다.', 66384),
(307663, 'koKR', '이 세계의 식생은... 충격적으로 흉포합니다!\n\n이곳엔 조용히 피어나는 꽃 한 송이조차 없어요. 공허폭풍의 식물들은 서로를 서서히 집어삼키고, 질식시키며, 이웃에게 독을 퍼뜨려 느리게 숨통을 끊어버립니다.\n\n전 이 야만적인 생태에 종지부를 찍기 위해 공허를 받아들였습니다. 이 세계의 혹독한 삶을 견딜 수 있으면서도, 스스로 포식자가 되지 않을 식물을 기를 수 있을까요?\n\n그래서 실버문에서 가져온 평온의 꽃을 이곳저곳에 이식했어요. 아마 본 적 있으실지도 모르겠네요! 지금까지는 제법 유망해 보이지만, 사실 소량의 공허 마력을 주입해야만 뿌리를 내릴 수 있었습니다.\n\n꽃이 만개한 걸 보면 가지치기를 부탁드릴게요. 그쯤이면 이미 포자는 퍼졌을 테니까요.', '', 66384),
(307642, 'koKR', '', '공허폭풍 주변에 있는 저 이상한 소용돌이들, 보셨어요? 묘하게 바다 냄새가 나요.\n\n전 맛있는 회 한 점을 위해서라면 뭐든 할 수 있는 사람이에요. 뭐요, 전 바닷가에서 자랐거든요.\n\n소용돌이에는 미세한 중력장이 형성돼 있어요. 낚싯대를 드리우고 잠자코 기다려 봤죠... 그랬더니 정말로, 입질이 왔어요!\n\n물 밑 괴물이라도 걸려 나오려나 했는데... 막상 나온 건 생각보다 평범하지만 나름 흥미로운 물고기들이더군요.\n\n그런데 말이에요, 이 주변엔 물이라고는 눈을 씻고 찾아봐도 없잖아요? 이 소용돌이들이 공간을 비틀어서, 어딘가 물이 가득한 곳과 연결돼 있는 게 분명해요.\n\n혹시 이 세계 어딘가에 바다가 숨어 있는 걸까요? 아니면 이 소용돌이들이 다른 세계까지 닿아 있는 걸까요?', 66384),
(307635, 'koKR', '', '이 제단들에서는 죽음과 공허 마법이 겹치는 지점이 있는 것 같아요.\n\n인정하긴 싫지만... 이 현상이 어떻게 가능한지 이해하는 데 어려움을 겪고 있어요. 제단은 명백히 도마나르가 만든 것이지만, 마법 자체는 완전히 공허의 것이라, 죽음의 힘은 아니에요.\n\n그나마 유일하게 접촉한 도마나르 동맹자는 이 주제에 대해 말을 아끼고 있단 말이죠. 도마나르 특유의 문화적 미신이나 의식 때문일까요? 아니면 제단을 통해 죽음의 마법을 불러오려는 의도가 없었던 걸까요? 어쩌면 그냥 우연일 수도 있겠네요.\n\n<얼굴을 찌푸리는 차리>\n\n이런 애매모호한 수수께끼는 정말 싫은데.', 66384),
(307634, 'koKR', '잘 싸워라, $rs. 나는 직접 지아단을 상대하러 가겠다. 네 일이 끝나면 합류해라.', '', 66384),
(307605, 'koKR', '내게 와라, $n. 내 숙적 지아단이 예상치 못한 공격을 가했다.', '', 66384),
(307604, 'koKR', '', '<근처 피난민들을 유심히 지켜보고 있는 장로 도루>\n\n모든 사람이 무사히 대피했는지 확인하고, 내가 가장 마지막에 나가겠네.', 66384),
(307602, 'koKR', '태양이 당신을 인도하길.', '태양이 당신을 인도하길.', 66384),
(307589, 'koKR', '전승지기 중 한 분이 실버문에 이야기 장소를 마련하셨다고 들었어요. 그분께 가면 우리 종족과 태양샘의 역사에 대한 이야기를 들을 수 있을 거예요.', '전승지기 중 한 분이 실버문에 이야기 장소를 마련하셨다고 들었어요. 그분께 가면 우리 종족과 태양샘의 역사에 대한 이야기를 들을 수 있을 거예요.', 66384),
(307562, 'koKR', '', '이것이야말로 알른하라가 주신 가장 큰 선물일세. 함께 나누는 삶. 그러니 계속 나아가게. 자네의 발걸음마다 알른하라의 은혜가 깃들기를 바라네. 고맙네, $n.', 66384),
(307561, 'koKR', '', '하지만 자네가 보여준 길 덕분에, 그 선택은 틀리지 않았다는 걸 알았지. 이제 우리는 알른하라의 땅뿐 아니라, 사람들과 문화도 알게 되었네. 그리고 그들도 우리를 알게 되었지.', 66384),
(307560, 'koKR', '', '다른 종족들에게 모습을 드러낼 때가 되었을 때, 나는 망설였네. 오랜 전통을 깨도 되는 걸까?', 66384),
(307558, 'koKR', '', '우리 하라니르는 오래도록 이 세상을 떠돌았지만, 언제나 그림자 속에서 은밀히 움직였지.', 66384),
(307554, 'koKR', '투하카, 내 심장. 이 투구를 가져가렴. 좋은 투구야. 너를 지켜줄 거다. 제발... 제발 무사하기만 해.', '', 66384),
(307553, 'koKR', '엘프들은 알아서 도시를 지키라고 하세요. 호드는 소수의 배신자 따위는 아쉽지 않습니다. 얼라이언스의 버릇을 반드시 고쳐 놓아야 합니다. 당신도 이해할 텐데요...', '엘프들은 알아서 도시를 지키라고 하세요. 호드는 소수의 배신자 따위는 아쉽지 않습니다. 얼라이언스의 버릇을 반드시 고쳐 놓아야 합니다. 당신도 이해할 텐데요...', 66384),
(307552, 'koKR', '알겠습니다.', '', 66384),
(307551, 'koKR', '그리고 제 친구 할라나도 그 전투에서 죽었습니다. 그 아이를 어떻게 잔인하게 죽였는지 잊을 수 없습니다!', '그리고 제 친구 할라나도 그 전투에서 죽었습니다. 그 아이를 어떻게 잔인하게 죽였는지 잊을 수 없습니다!', 66384),
(307550, 'koKR', '알아요.', '', 66384),
(307549, 'koKR', '놈들은 라스타칸을 죽였습니다. 제 왕을! 제가 지키겠다고 맹세했던 분을! 이런 상황에서 물러서라고 말하지 마십시오.', '놈들은 라스타칸을 죽였습니다. 제 왕을! 제가 지키겠다고 맹세했던 분을! 이런 상황에서 물러서라고 말하지 마십시오.', 66384),
(307542, 'koKR', '<당신을 노려보는 붉은눈>\n\n이곳에 온 목적이 전투와 영광, 호드를 꺾는 궁극의 승리가 아니라면 썩 물러나십시오.\n\n\"호드와 얼라이언스가 함께 공동의 적에 맞서야 한다\" 운운하는 것들은 전부 방심을 유발하려는 미끼에 불과합니다. 아마 호드가 꾸민 계략일 겁니다.\n\n놈들은 우리의 땅을 유린하고 사람들을 학살했습니다. 용서는 있을 수 없습니다.', '', 66384),
(307541, 'koKR', '나도 전장에서 짐만 된다는 걸 안다. 그래서 여기서 할 수 있는 일을 하는 거야. 그보다 못하면 비겁한 거지. 비겁한 넌 내 아들이 아니다.', '', 66384),
(307540, 'koKR', '제발요, 아버지. 이건 의미 없는 복수일 뿐이에요. 전투에 나설 상태가 아니에요! 어머니도 걱정하고 계십니다. 그냥 집으로 돌아가요.', '', 66384),
(307539, 'koKR', '너는 동족의 희생을 그렇게 가볍게 여기느냐? 네 할아버지는 아쉬란에서 전사했는데, 여기서 괴물들과 빵이나 나누며 가만히 있겠다는 게냐?', '', 66384),
(307538, 'koKR', '톰이 한숨을 내쉽니다.', '', 66384),
(307537, 'koKR', '고민이 좀 있다.\n\n한쪽은 이렇게 말해. 때가 왔으니 지켜보며 배워야 한다고. 누님이 문제를 어떻게 해결하는지 보고 배워야 한다고.\n\n하지만 다른 한쪽은... 이 길이 옳지 않다고 외치고 있어. 경계를 늦춘다면, 이 길은 우리 종족을 나약함의 시대로 이끌게 될 거라고 말이다.', '', 66384),
(307535, 'koKR', '', '저는 이곳 줄아만에 돌아와 머무르기로 했습니다.\n\n피비린내 나는 갈등 때문에 오랜 세월 아마니와 맞서 싸워 왔지만, 이곳에서 보낸 시간은 아마니를 새로운 시각으로 바라보게 해주었습니다.\n\n과거의 상처와 증오가 쉽게 사라지지 않는다는 걸 저는 잘 알고 있습니다. 지금도 여전히 그 길을 걷고 있으니까요.\n\n하지만... 앞으로 나아가는 길은 단 하나뿐입니다. 한 걸음씩, 천천히요.', 66384),
(307523, 'koKR', '크아레쉬인들의 영혼을 사로잡아 공허에 귀속시킨 에테리얼, 영혼술사 나진드리란 자가 있었습니다. 아제로스의 병력이 마나괴철로 종극점에서 어둠수호병을 제압했을 때, 나진드리도 마침내 저지당했지요.\n\n하지만 이미 너무 많은 동족이 어둠에 물들고 말았습니다. 베란도 그중 하나였어요... 동생의 붕대는 공허의 기운으로 가득했고, 영혼은 공허의 의지에 묶여 있었죠.\n\n지금 일부가 반기를 들고 있다면... 어둠수호병 내부에도 비슷한 이들이 더 있는 걸까요?', '', 66384),
(307517, 'koKR', '', '좋아. 나머지 사체는 내가 가져가겠네.', 66384),
(307516, 'koKR', '줄잔의 두 눈에 복수심이 불타오릅니다.', '', 66384),
(307496, 'koKR', '', '봤지, 코부? 해낼 줄 알았어.', 66384),
(307495, 'koKR', '저 친구?$B$B내가 노인 네이쿠네를 발견했을 땐 중상을 입은 상태였고, 거대한 샙터 한 마리가 덮치고 있었어. 간신히 짐승의 목덜미에 화살을 꽂을 수 있었지.$B$B그 순간, 네이쿠네를 끝내 주는 게 좋겠단 생각이 스쳤어. 긴 안식을 주는 거지. 하지만 마치 대자연이 내 손을 붙든 듯, 그럴 수 없었네. 그날 내가 내린 판단은 옳았다고 지금도 믿고 있지.', '', 66384),
(307480, 'koKR', '', '이 균류의 자실체는 처치했지만, 이걸로 끝났다고는 생각되지는 않는군.\n\n알른하라께서 창조하신 생명이라면 그 어떤 존재라도 존중하라 배웠지만, 이 녀석들은...\n\n<길게 한숨을 내쉬는 지칼>\n\n내가 너무 예민하게 구는 걸지도 모르겠군. 당분간 이곳에 남아, 이것들이 더 퍼지지 않게 하겠다.', 66384),
(307473, 'koKR', '', '이방인! 우리가 찾은 것 좀 봐요!', 66384),
(307459, 'koKR', '그 외에 무슨 이유가 더 있겠나?\n\n꼬마 $rs, 너희 지도자들이 우리가 가진 싸움의 가치를 보지 못하는 건 비극이다. 여기서 목적은 단 하나다. 우린 싸우기 위해 존재한다.\n\n용감한 자, 가치 있는 자, 그리고 정신 나간 자만이 이곳에서 무기를 들 용기를 아는 법이지. 그런 자들만이 치열한 전장의 기쁨을 맛보게 된다.\n\n이 전장에서, 너는 얼라이언스를 위해 싸우는 게 아니다. 나를 위해 싸우는 거다. 너는 내 뜻에 따라 싸우고 죽을 것이며, 함께 지아단과의 싸움을 즐기게 되겠지.\n\n그리고 그것만으로 부족하다면, 내가 너에게 줄 영광스러운 보상은 네 소중한 세계를 잘아타스에게서 지키는 데 큰 도움이 될 거다.', '', 66384),
(307455, 'koKR', '그래도 네 도움이 필요하다. 비탄의 첨탑으로 가라, $rs. 거기서 만나겠다.', '', 66384),
(307421, 'koKR', '복수를 위하여!', '', 66384),
(307418, 'koKR', '너는 참 이상해, 여행자. 그래도 알른하라의 뿌리 아래에서는 누구나 안전하게 쉴 수 있지.', '너는 참 이상해, 여행자. 그래도 알른하라의 뿌리 아래에서는 누구나 안전하게 쉴 수 있지.', 66384),
(307404, 'koKR', '원래 난 뿌리에서 혼자 있을 때가 좋았어.', '', 66384),
(307390, 'koKR', '저는 지금 내장이 튀어나오거나, 증발하거나, 특이점에 삼켜지지 않으려고 애쓰는 중이에요.\n\n당신을 따라 차원문을 넘어온 뒤, 이곳에 거점을 확보했어요. 덕분에 포식의 군단은 출입로를 눈치채지 못하고 있어요. 실버문의 중심부로 이어지는 차원문을 빼앗기는 일만은 막아야 하니까요.\n\n한편, 우리 연구진은 이곳 전역에서 우리 모두를 산산조각 내려는 수많은 공허 변형물을 제거하려 사투를 벌이고 있어요.', '', 66384),
(307320, 'koKR', '', '우리는 예술가이자 역사가라고 할 수 있다. 붓으로 그림을 그려 시대의 진실을 기록하고, 그 전통은 세대를 거쳐 이어져 왔다.', 66384),
(307317, 'koKR', '', '붓질로 역사를 수집하려면 고요한 마음과 흔들림 없는 손이 필요하다. 조상들이 그렇게 가르쳐 주셨지.', 66384),
(307312, 'koKR', '처음에는 안전한 거리를 두고 일대를 정찰했습니다. 그러다 이곳 생명체들이 별다른 위협이 되지 않는다는 판단이 들자, 다양한 표본을 수집하기 시작했지요. 이후 적대적인 생명체들이 공격해 왔을 때도 손쉽게 처치했습니다. 하지만 그 피를 흘린 일로 모두의 파멸이 시작되었습니다.\n\n균열방랑자 로른이 가장 먼저 감염됐지만, 증상을 알아챘을 때는 이미 늦은 뒤였습니다. 병원체의 영향력은 은밀했고, 사람들의 판단력을 흐려놓았지요. 그렇게 저희는 안에서 자라나는 병원체에 휘둘려, 하나둘 임무를 버리고 서로를 외면하게 되었습니다.\n\n저희는 스스로의 힘을 과신했고, 결국 안에 숨어 있던 적에게 무너졌습니다. 부디 방심하지 마십시오.', '', 66384),
(307311, 'koKR', '끔찍한 경험에서 벗어나 다행이군.', '', 66384),
(307309, 'koKR', '', '정말 가야 해?', 66384),
(307308, 'koKR', '', '엄마랑 얘기해야 하는 건 알아. 근데 목소리를 내려고 하면... 언니 목소리만 들려.', 66384),
(307304, 'koKR', '', '<칸자가 카파라를 위해 깔아놓은 담요를 가리킵니다.\n\n담요 한가운데에 물건을 놓아 달라는 눈치입니다.\n\n카파라를 위해 칸자가 차려놓은 접시와 요리들을 보니, 필로의 관심을 끌기 위해 다과회를 준비한 모양입니다.>', 66384),
(307303, 'koKR', '', '<칸자는 당신을 바라보며 미소 짓더니, 머리카락을 손가락으로 쓸어 넘기고는 시선을 발끝으로 내립니다.>', 66384),
(307291, 'koKR', '어둠 속에 남겨야 하는 역사도 있는 법이죠.', '', 66384),
(307285, 'koKR', '줄아만에는 작은 영역을 관장하는 로아도 많다네. 찾아낸 다음 이곳으로 오면 축복을 받을 수 있지.', '줄아만에는 작은 영역을 관장하는 로아도 많다네. 찾아낸 다음 이곳으로 오면 축복을 받을 수 있지.', 66384),
(307283, 'koKR', '당신 동족이 자유와 생존을 위해 싸우고 있는데, 그런 말이 입에서 나옵니까? 저리 가십시오!', '당신 동족이 자유와 생존을 위해 싸우고 있는데, 그런 말이 입에서 나옵니까? 저리 가십시오!', 66384),
(307282, 'koKR', '저치들에게 주도권을 넘기자고요? 영광은 신도레이의 것이 되어야 합니다. 잊으셨습니까?', '저치들에게 주도권을 넘기자고요? 영광은 신도레이의 것이 되어야 합니다. 잊으셨습니까?', 66384),
(307281, 'koKR', '동족이 여기서 쓰러지고 있는데, 어떻게 그런 말을 하십니까?', '동족이 여기서 쓰러지고 있는데, 어떻게 그런 말을 하십니까?', 66384),
(307280, 'koKR', '역사를 잊으셨습니까? 기회만 생기면 아마니는 망설임 없이 우리의 땅과 생명을 빼앗을 겁니다!', '역사를 잊으셨습니까? 기회만 생기면 아마니는 망설임 없이 우리의 땅과 생명을 빼앗을 겁니다!', 66384),
(307279, 'koKR', '정신이 나간 겁니까? 당신 입도 아마니처럼 닫아버려야 할지도 모르겠군요!', '정신이 나간 겁니까? 당신 입도 아마니처럼 닫아버려야 할지도 모르겠군요!', 66384),
(307278, 'koKR', '제정신이십니까? 놈들은 대대로 우리를 위협해 왔습니다!', '제정신이십니까? 놈들은 대대로 우리를 위협해 왔습니다!', 66384),
(307277, 'koKR', '날 죽이면, 내 무기의 비밀도 같이 사라진다. 날 받아들여라. 세상을 파괴할 힘을 주마.', '', 66384),
(307276, 'koKR', '', '진심인가요? 참, 라이시카스랑 여러모로 닮으셨네요.\n\n<고개를 젓는 마엘라>\n\n다 같이 날아가지 않은 것만 해도 감사할 일입니다. 제발 더 이상 아무것도 건드리지 마세요. 두 번이나 운이 따라주진 않을 테니까요.', 66384),
(307268, 'koKR', '알겠어요. 그래도 재밌었다는 건 인정하시죠?', '', 66384),
(307253, 'koKR', '멈추라고요? 이제야 전세를 뒤집었는데!', '멈추라고요? 이제야 전세를 뒤집었는데!', 66384),
(307252, 'koKR', '아마니가 퇴각하고 있습니다. 승리가 코앞까지 왔군요.', '아마니가 퇴각하고 있습니다. 승리가 코앞까지 왔군요.', 66384),
(307251, 'koKR', '저들에게 주도권을 넘기자고요? 절대 안 됩니다! 신도레이에 영광을!', '저들에게 주도권을 넘기자고요? 절대 안 됩니다! 신도레이에 영광을!', 66384),
(307250, 'koKR', '아마니는 공격하고, 신도레이는 막는다. 수천 년 동안 늘 그래왔습니다!', '아마니는 공격하고, 신도레이는 막는다. 수천 년 동안 늘 그래왔습니다!', 66384),
(307249, 'koKR', '빛도, 투랄리온 님도 저버리지 않겠습니다! 밀고 나아가십시오!', '', 66384),
(307248, 'koKR', '빛이 우리의 길을 비추고 인도하기를.', '', 66384),
(307247, 'koKR', '놈들의 만행을 보십시오! 반드시 복수할 겁니다!', '놈들의 만행을 보십시오! 반드시 복수할 겁니다!', 66384),
(307246, 'koKR', '웬 아마니가 등 뒤에서 창으로 찌르고 도망쳤습니다... 비겁한 자식!', '웬 아마니가 등 뒤에서 창으로 찌르고 도망쳤습니다... 비겁한 자식!', 66384),
(307245, 'koKR', '눈앞에 있는 적을 왜 못 보는 겁니까? 저들이 먼저 공격했고, 우리는 응징할 뿐입니다!', '', 66384),
(307244, 'koKR', '빛이 우리가 나아갈 길을 밝히고 있습니다!', '', 66384),
(307243, 'koKR', '이런 날이 올 줄 알고 있었습니다! 쿠엘탈라스를 위하여!', '이런 날이 올 줄 알고 있었습니다! 쿠엘탈라스를 위하여!', 66384),
(307242, 'koKR', '아마니가 위협처럼 보이지 않을 수도 있겠지요. 하지만 기회만 생기면 우리의 땅을 빼앗고 사람들을 해칠 겁니다!', '아마니가 위협처럼 보이지 않을 수도 있겠지요. 하지만 기회만 생기면 우리의 땅을 빼앗고 사람들을 해칠 겁니다!', 66384),
(307241, 'koKR', '멈추라니요? 멈춰야 할 쪽은 우리 신도레이가 아니라 저 작자들입니다!', '멈추라니요? 멈춰야 할 쪽은 우리 신도레이가 아니라 저 작자들입니다!', 66384),
(307240, 'koKR', '놈들의 마법을 모조리 침묵시키겠습니다!', '놈들의 마법을 모조리 침묵시키겠습니다!', 66384),
(307239, 'koKR', '진짜 위협이 아니라고요? 저치들은 세대를 거쳐 위협이 되어 왔습니다. 이대로 둘 수는 없습니다!', '진짜 위협이 아니라고요? 저치들은 세대를 거쳐 위협이 되어 왔습니다. 이대로 둘 수는 없습니다!', 66384),
(307238, 'koKR', '언제나 명중하기를!', '언제나 명중하기를!', 66384),
(307222, 'koKR', '이 목소리는 뭐죠? 괴물들은 왜 돌을 먹는 걸까요? 좀 더 알아보죠. 서둘러요!', '', 66384),
(307203, 'koKR', '', '필로 님은 참 상냥한 분이죠?', 66384),
(307197, 'koKR', '', '칸자는... 남달라요.\n\n어렸을 때는 말을 하지도 않고, 웃지도 않고, 누구와 눈도 마주치려 하지 않았죠.\n\n하지만 제 어머니와 칸자의 아버지, 쌍둥이 자매의 도움으로 조금씩 말도 하고, 놀기도 하고, 또래 아이들처럼 지낼 수 있게 되었어요.\n\n그런데 제 어머니가 세상을 떠났고, 아버지는 일로 점점 더 바빠졌고, 자나카는 혈액 질병으로 목숨을 잃었죠.\n\n자나카가 떠난 이후로, 칸자는 다시 입을 닫았어요. 지금껏 시간을 주고 있었는데... 벌써 3년이 흘렀네요.', 66384),
(307150, 'koKR', '<짐운반꾼이 고개를 숙여 당신을 섬기겠다는 뜻을 내비칩니다.>', '<짐운반꾼이 고개를 숙여 당신을 섬기겠다는 뜻을 내비칩니다.>', 66384),
(307133, 'koKR', '동력 과부하!', '', 66384),
(307127, 'koKR', '', '고마워요, 하쉬우라... 이렇게 도와주셔서.', 66384),
(307126, 'koKR', '뭐? 좋아. 어차피 잘됐네. 네 음식은 맛대가리 없거든.', '', 66384),
(307125, 'koKR', '', '맞아요, 아버지. 변명은 이제 필요 없으니까... 그만 제 집에서 나가 주세요!', 66384),
(307124, 'koKR', '허튼소리! 둘러대지 마! 거짓말! 네가 필로를 불러냈을 리 없잖아!', '', 66384),
(307123, 'koKR', '', '저... 언니를 보고 싶었어요. 마지막으로요.', 66384),
(307122, 'koKR', '왜 이제 와서 말을 해? 왜 그렇게 오랫동안 엄마를 걱정하게 만들어?', '', 66384),
(307121, 'koKR', '', '칸자! 무사히 돌아왔구나. 잠깐... 지금 뭐라고?', 66384),
(307120, 'koKR', '', '엄마...', 66384),
(307113, 'koKR', '필로가 기분 좋게 낄낄 웃으며 인사한 뒤, 음식을 먹기 시작합니다.', '', 66384),
(307112, 'koKR', '', '잘 가, 언니. 언젠가... 다시 만날 수 있겠지.', 66384),
(307111, 'koKR', '', '자나카가 칸자를 향해 고개를 끄덕이고 손을 흔든 뒤, 필로를 따라갑니다.', 66384),
(307108, 'koKR', '필로가 하품을 하고 기지개를 켠 뒤, 천천히 자리를 뜹니다.', '', 66384),
(307105, 'koKR', '', '자나카는 미소를 지으며 고개를 끄덕이다가, 이내 허리에 손을 얹습니다.', 66384),
(307104, 'koKR', '', '정말... 괜찮아?', 66384),
(307103, 'koKR', '', '자나카가 칸자를 보자 따스한 미소를 짓습니다.', 66384),
(307102, 'koKR', '가시버섯을 입에 잔뜩 욱여넣은 필로가 천천히 고개를 끄덕입니다.', '', 66384),
(307101, 'koKR', '', '언니가... 옆에 있다고요?', 66384),
(307100, 'koKR', '', '필로...', 66384),
(307086, 'koKR', '먼저 저 끝까지 가서 살펴보고 있겠소.', '', 66384),
(307085, 'koKR', '...', '...', 66384),
(307083, 'koKR', '두고 보면 알겠죠.', '', 66384),
(307079, 'koKR', '저게 전부 사실이라면, 아킨툰데의 지식은 사라지는 게 나아요. 이번에 알게 된 건 전부 보고할게요. 무기에 관한 세세한 내용은 전부 사라졌지만요.', '', 66384),
(307070, 'koKR', '', '<칸자가 잠시 얼굴 가득 환한 미소를 지어 보입니다.\n\n자신의 말에 귀 기울여 주고 이해해 주는 사람이 있어서 기쁜 듯합니다.>', 66384),
(307054, 'koKR', '', '<칸자가 떠나려는 당신을 막아 세우고, 헛기침을 합니다. 당신은 칸자가 말을 하려는 줄 알고 화들짝 놀랍니다.\n\n그렇지만 칸자는 멧돼지가 돌진할 때 내는 소리와 똑같은 괴성을 질러 당신을 깜짝 놀라게 합니다.\n\n가시버섯을 두고 멧돼지들이 싸움을 걸어올 수도 있다는 경고 같습니다.>', 66384),
(307052, 'koKR', '', '<칸자가 발치에 난 버섯을 가리키고는, 가시가 난 갓을 피해 줄기로 집어 듭니다.\n\n그러고는 조막만 한 손으로 능숙하게 버섯의 가시를 떼어냅니다.\n\n칸자가 냄새를 맡아보라며 버섯을 내밉니다.\n\n향긋한 송로버섯과 마늘이 섞인 냄새가 납니다.>', 66384),
(307041, 'koKR', '여기예요! 이 서판이 잔해의 출처인가 봐요. 보세요. 읽을 수 있겠어요?', '', 66384),
(307039, 'koKR', '', '칸자가 당신에게 따라오라고 손짓합니다.', 66384),
(307034, 'koKR', '너희는 두려움이 없고 강하다. 내 지식을 주마. 이 세계는 한때 프레다케아라는 이름으로 불렸다.', '', 66384),
(307031, 'koKR', '반갑습니다, $c|1이여;여;', '', 66384),
(307030, 'koKR', '이 희생은 $c 그대가 할 게 아닙니다.', '', 66384),
(307029, 'koKR', '그래, 여기다. 소용돌이로 들어와라.', '', 66384),
(307027, 'koKR', '이 장작이 우리에게도 그런 역할이 됐으면.', '', 66384),
(307022, 'koKR', '여러 관심 지점에 대한 길 안내를 해드릴 수 있습니다.', '여러 관심 지점에 대한 길 안내를 해드릴 수 있습니다.', 66384),
(307019, 'koKR', '', '<칸자가 열정적으로 온천을 가리키며 당신의 시선을 끕니다.\n\n곧이어 칸자가 팔을 날개처럼 퍼덕이더니, 날아다니는 무언가를 지켜보는 흉내를 냅니다. 그러고는 상상 속 생물을 붙잡아 두 손으로 짓이기는 시늉을 합니다.\n\n당신은 독침벌들이 웅덩이 주변을 맴돌며, 섬 밖에서 온 카파라가 접근하지 못하게 막고 있음을 알아차립니다.\n\n칸자는 이 독침벌을 없애 카파라들이 온천에서 편히 쉴 수 있게 해달라는 것 같습니다.>', 66384),
(306896, 'koKR', '', '칸샤가 묵은 독을 털어내려고 이 가지를 떨어뜨렸지.', 66384),
(306895, 'koKR', '지식을 추구하는 어린 지성이여... 너희가 찾는 답은 내게 있다. 나를 찾아라...', '', 66384),
(306894, 'koKR', '그 로아가 칸자한테 말을 걸지 않게 되면, 그제야 우리랑 대화할 마음이 생길지도 모르지!', '', 66384),
(306893, 'koKR', '', '아버지... 제발요. 아이도 어쩔 수 없었겠죠.', 66384),
(306886, 'koKR', '', '힘줄 정도면 불이 꺼질 때까지 통나무를 잘 묶어줄 거야.', 66384),
(306885, 'koKR', '엄청 단단해. 자매랑 비슷하군.', '', 66384),
(306884, 'koKR', '', '잘 어울리네... 어머니도 어떤 사람한테는 든든한 바위였겠지. 우리한테는 싸늘한 돌덩어리였지만.', 66384),
(306883, 'koKR', '우선 돌을 놓아야 해. 그분의 생명을 상징하지.', '', 66384),
(306865, 'koKR', '어떤 기술 전문가를 찾으십니까?', '어떤 기술 전문가를 찾으십니까?', 66384),
(306863, 'koKR', '찾는 거라도 있습니까, $c님?', '찾는 거라도 있습니까, $c님?', 66384),
(306860, 'koKR', '', '<칸자가 당신을 위아래로 훑어보며 눈을 가늘게 뜹니다.\n\n두 주먹을 불끈 쥐고 땅을 꾹꾹 밟습니다.\n\n선뜻 당신과 함께 돌아갈 생각은 전혀 없어 보입니다.>', 66384),
(306856, 'koKR', '', '아마니는 언제나 널 환영할 것이다, $n.', 66384),
(306852, 'koKR', '', '그래도 썩은가지한테 잡히진 않았고, 아버지도 무사히 돌아오셨으니 다행이죠.\n\n우리 작은 가족은 이미 겪을 만큼 겪었어요. 더는 안 돼요.\n\n그나저나, 칸자는 또 어디 갔지?', 66384),
(306851, 'koKR', '', '칸자가 간 방향...\n\n그리고 챙겨 간 물건들...\n\n필로를 부를 수 있는 건 아이뿐이고, 아이의 마음으로 불러야 해요.\n\n찻주전자, 소풍 바구니... 칸자는 필로랑 놀고 싶었던 거예요.\n\n근데 찻주전자는 깨졌고, 음식을 가득 담은 바구니는 떨어뜨려 버렸으니, 이젠 어쩌려는지...', 66384),
(306849, 'koKR', '', '칸자가 저 죽을 때까지 단 한마디도 안 해도 전 괜찮아요.\n\n돌아와 줘서 기쁘네요. 칸자가 제게 하고 싶었던 말을 듣지 않은 게 마음 아파요.\n\n칸자는 자신만의 공간, 있는 그대로의 자신으로 쉴 수 있는 공간이 필요했던 거예요. ', 66384),
(306842, 'koKR', '', '오랜 시간 숨었다. 도망쳤고. 힘들었어.\n\n계획을 세웠다. 사죄하는 만아리들과 거짓말도 꾸렸다. 죽었다고 생각하게 만들었다. 하지만 아니었다.\n\n평화는 아니야. 그래도 전보다는 좀 낫지.', 66384),
(306841, 'koKR', '', '수백 년 동안, 우리가 할 수 있는 건 살아남는 것뿐이었다. 우리 세계에 사는 거대한 짐승들 또한 군단에 저항했고, 악마와 드레나이를 똑같이 사냥했다. 우리에게 다행이었던 건, 군단의 악마화 시도가 언제나 토착 종족들의 죽음으로 끝났다는 점이야.\n\n그래서 난 몇몇 뒤틀린 추격자들과 필사적인 계책을 꾸몄다. 그중 몇몇은 자신들의 처지에 불만을 품고 있었지. 우리는 마지막 항전을 꾸미고, 군단 지휘부가 우리 전원이 말살되었다고 믿게 속였어. 그 잿더미에서 새로운 것이 태어났다.\n\n그게 우리 세계의 전쟁이 끝난 날은 아니었다. 다만 처음으로 우리가 칼을 내려놓은 날이었지.', 66384),
(306840, 'koKR', '', '이 엘프 덕분에 마침내 소통이 가능해졌군. 제대로 인사도 하고, 감사를 전하고 싶다.\n\n나는 황천사자의 툴아마르라 한다. 아르거스에서 태어나 벨렌을 따라 제네다르에 올랐지. 내 동족 대부분처럼, 차원선을 타고 피신한 행성에서 불타는 군단의 기습을 받고 결국 그곳에 남겨졌다. 그것도 벌써 수천 년 전의 일이로군.\n\n네 덕분에 동족을 지킬 수 있었다. 이 은혜는 잊지 않으마.', 66384),
(306834, 'koKR', '', '무엇을 도와드릴까요, $c님?', 66384),
(306819, 'koKR', '잠깐, 저기 간다! 저 작은 괴물 좀 잡아요!', '', 66384),
(306818, 'koKR', '그래도 운동은 됐겠네요, 뭐.', '', 66384),
(306816, 'koKR', '물 밖에선 오래 버티지 못해요. 서두르세요!', '', 66384),
(306801, 'koKR', '', '과연... 자네는 자격이 있을까? 아니면 선물을 받기도 전에 관둘까?', 66384),
(306781, 'koKR', '공허의 자취는 정화됐습니다. 이 힘은 강력하고... 응용하기도 좋고... 부작용도... 감당할 만하군요.', '', 66384),
(306779, 'koKR', '전 전사지, 춤꾼이 아닙니다! 어떻게 우아하게 움직이라는 겁니까?\n\n전사가 할 일은 전투를 준비하는 겁니다.\n\n이건 시간 낭비라고요.', '', 66384),
(306777, 'koKR', '<선율에 완전히 몰입한 코부가 멈추지 않고 춤을 춥니다. 이내 코부가 윙크를 보냅니다.>\n\n이제야 알겠네요. 춤은 괜히 있는 게 아니었어요.', '', 66384),
(306766, 'koKR', '', '이런 환경에선 도저히 수업을 할 수가 없어요!', 66384),
(306765, 'koKR', '', '저기예요! 저기 있어요! 시장으로 통하는 순간이동기로 가고 있어요!', 66384),
(306753, 'koKR', '이제 그릇 차례입니다. 효력을 증폭시키겠습니다. 조심스럽게 여기 두십시오.', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(306750, 'koKR', '먼저 정화의 소금을 준비하십시오. 우리 기사를 고뇌의 가장 잔혹한 부작용으로부터 지켜줄 겁니다.', '', 66384),
(306749, 'koKR', '고뇌는 다루기 쉬운 힘입니다... 이 힘이 어디까지 닿을 수 있는지 살펴봅시다.', '', 66384),
(306746, 'koKR', '이 혈기사는 부정한 공허의 피조물이 침공했을 때 부상을 입었습니다. 그리고 제 연구에 몸을 기증했지요.\n\n고뇌의 힘을 살펴봅시다.', '', 66384),
(306742, 'koKR', '저리 꺼져라, 호드 돼지야.', '', 66384),
(306741, 'koKR', '공기에서 오크 냄새와 살육의 악취가 진동하오. 저 호드 괴물들은 자신들이 이 세계의 주민들보다 나은 줄 아는 모양이오.\n\n천만에. 우린 잊지 않았소.', '', 66384),
(306740, 'koKR', '', '한심한 얼라이언스 놈들은 옛 원한을 갚을 구실만 찾고 있지.\n\n싸움을 원한다고? 기꺼이 받아주지.', 66384),
(306739, 'koKR', '', '할 말 따윈 없다, 얼라이언스의 개야.', 66384),
(306738, 'koKR', '투기장에서 정상을 지키는 비결이요?\n\n연구와 연습, 실패를 감수하고 배우며 또 하루를 살아남을 인내심이요.\n\n예전 원한을 불태우러 오는 자들은 자존심만 앞서는 이들이에요. 전 그런 괴물들에게 얕잡아보면 끝장이라는 걸 보여주러 왔어요. 우리가 더 강해져야 하고, 그 힘을 유지해야 해요.\n\n계속 싸워 나가요, $c님.', '투기장에서 정상을 지키는 비결이요?\n\n연구와 연습, 실패를 감수하고 배우며 또 하루를 살아남을 인내심이요.\n\n예전 원한을 불태우러 오는 자들은 자존심만 앞서는 이들이에요. 전 그런 괴물들에게 얕잡아보면 끝장이라는 걸 보여주러 왔어요. 우리가 더 강해져야 하고, 그 힘을 유지해야 해요.\n\n계속 싸워 나가요, $c님.', 66384),
(306716, 'koKR', '다나스가 손을 들어 당신을 가리킵니다.', '', 66384),
(306712, 'koKR', '', '외부인이 보기엔 별일 아닌 것처럼 느껴질 수도 있어. 하지만 확실히 달라. 그리고 위험해.\n\n난 오랫동안 버섯전사를 지켜봐 왔어. 확실히 부패는 녀석들의 영역이지. 근데 평소 포식하는 습성을 보면 이유가 있었단 말이야. 늘 주변을 의식하면서 움직였거든. 지나치게 퍼지거나 너무 많이 집어삼키면, 결국 자신들의 멸망을 초래한다는 걸 알고 있었으니까.\n\n그런데 지금 저... 버섯전사들은... 달라. 눈빛은 텅 비었고, 굶주림에는 끝이 없어. 마치 부식과 부패라는 개념 자체가 몸을 빌려 움직이는 인형 같아.\n\n하라니르는 쉽게 겁먹는 종족은 아니야, $c 친구. 그런데 이번에는... \n\n문제의 원인을 찾아야 해. 망설일 시간 없어.', 66384),
(306709, 'koKR', '<알레리아와 아라토르의 대화를 듣느라 당신을 무시하는 데시무스>', '', 66384),
(306690, 'koKR', '', '이 버섯전사 녀석들, 평소보다 훨씬 더 적대적인데. 게다가 아무런 소리도 안 내. 눈빛도 텅 비었고...\n\n애초에 살아 있는 존재조차 아닌 것 같아.', 66384),
(306689, 'koKR', '', '버섯전사는 시끄러워. 아주 성가실 만큼 시끄럽지. 그런데 요즘 펑가라 마을이 조용해졌어.', 66384),
(306642, 'koKR', '참 실망스러운 질문이군요.\n\n그냥 과제를 포기하고 다시 실버문으로 오시면 됩니다. 찾아보면 당신 취향에 맞는 과제가 있긴 할 겁니다.\n\n\n[사냥을 포기하려면 퀘스트 목록을 연 다음, 퀘스트를 선택하고 포기를 누르십시오. 이후 실버문에 있는 아스탈로르를 찾아가 새로운 사냥을 수주할 수 있습니다.]', '', 66384),
(306641, 'koKR', '목표의 위치를 좁혀갈수록 제 수정은 대상의 고뇌로 차오릅니다. 고뇌가 충분히 모이면 구체적인 위치가 드러납니다.\n\n다만 고뇌의 힘은 변덕스럽고 불안정합니다. 어떤 사냥은 금세 끝나지만, 더 큰 노력이 필요한 사냥도 있습니다.', '', 66384),
(306640, 'koKR', '목표가 은신처에서 잠시라도 모습을 드러내거나, 당신의 위치로 주의를 끌게 만들 수 있는 활동이면 뭐든 제 마법으로 목표의 위치를 좁히는 데 도움이 됩니다.\n\n\n[사냥 진척도 획득처로는 매복 격퇴, 덫 상호작용, 응축된 고뇌 처치, 전역 퀘스트 완료, 보물획득, 해당 지역에서 희귀 적 처치 등이 있습니다.]', '', 66384),
(306583, 'koKR', '', '이번 게 위기는 꼭 해결해야 했네. 굶주리는 동족을 위해서도, 그리고 어머니를 위해서도 말이지.\n\n어머니는 깨진엄니를 깊이 아끼셨고, 우리 가문이 대대로 마을을 지켜온 걸 무척 자랑스러워하셨지. 사람들도 우리가 항상 먹을 걸 마련해줄 거라고 믿었고 말이야. 그런데 그 믿음을, 약속을 저버렸다면 어땠을지. 다행히 그런 일은 없었네.\n\n이젠 나도 선조들처럼 훌륭한 지도자라는 확신이 생겼어.', 66384),
(306582, 'koKR', '', '아직 잡아야 할 게가 많아. 우리 어머니는 전설적인 강물방랑자이자 지도자셨고, 게잡이에 관한 모든 지식을 내게 전수하셨네.\n\n그러다 황혼의 칼날단에게 어머니를 잃었고, 난 남겨진 모든 걸 떠맡게 되었지. 어머니 생각에 몰두해 버리면, 이 위기를 해결할 집중력을 잃진 않을까 걱정이 되네.', 66384),
(306581, 'koKR', '카하네아 님은 우리를 이번 기근에서 구하며 진정한 자질을 증명했습니다. 처음엔 어떻게 봐야 할지 몰랐지만, 이젠 그분께 자랑스러운 부하가 되고 싶습니다.\n\n카하네아 님 같은 지도자를 만난 건 정말 행운이에요. 이제는 역사상 가장 훌륭한 강물방랑자 중 하나로 당당히 자리매김했다고 생각합니다.', '', 66384),
(306580, 'koKR', '전 신임 강물방랑자입니다. 카하네아 님의 어머님이 훌륭한 지도자였다고 다들 입을 모아 말하지만, 사실 전 그분께 직접 배우지 못했습니다.\n\n어떨 때는 사람들이 순전히 혈통만 보고 카하네아 님을 믿는 건 아닌지 걱정이 들기도 합니다. 전 아직 그분에 대한 확신이 없어서요.', '', 66384),
(306579, 'koKR', '', '역시 카하네아가 게 문제도 해결할 줄 알았어! 단순히 마을 사람들 위해서가 아니라, 집안의 자존심을 위해서도 꼭 해야 할 일이었거든.\n\n카하네아에게 어머니는 세상의 전부였어... 지금 딸아이를 보면 자랑스러워했을 거야. 놀라진 않았겠지만.\n\n선대 수석 강물방랑자도 카하네아를 믿었으니까. 나처럼 말이야.', 66384),
(306578, 'koKR', '', '요즘 힘든 시기지만, 난 카하네아를 믿어. 카하네아의 집안은 예로부터 강물방랑자들을 이끌어 왔거든. 카하네아의 어머니는 역대 지도자 중에서도 최고였지.\n\n그러니 이 위기를 잘 넘길 거야.', 66384),
(306556, 'koKR', '스승 말을 들어라. 아니면 말고. 나는 네 본질을 집어삼키는 걸 기대하고 있겠다.', '', 66384),
(306546, 'koKR', '분쟁에는 막대한 비용이 들지. 하지만 계산은 내가 하고, 누가 언제 대가를 치르게 할지도 내가 정한다.', '', 66384),
(306545, 'koKR', '잘아타스! 오늘 빛이 완벽한 승리를 거둘 것이다!', '', 66384),
(306544, 'koKR', '', '이렇게 함께해 줘서 정말 고맙네요, 투랄리온. 이 가엾은 엘프들이 외롭게 죽는 일은 없겠군요.', 66384),
(306543, 'koKR', '', '손에 닿지 않는 것처럼 보여도 말이에요.', 66384),
(306542, 'koKR', '', '그리고 그 모든 미래에서, 당신의 세계는 제 것이 되죠.', 66384),
(306540, 'koKR', '', '주위를 둘러보세요. 하늘을 올려다봐요. 공허는 모든 미래의 가능성을 보여준답니다.', 66384),
(306539, 'koKR', '', '이름 높은 아제로스의 용사님, 그 결의와 승리에 대한 집념은 진심으로 존경스럽네요.', 66384),
(306480, 'koKR', '', '아버지! 그런 아이인 걸 어떡해요. 손주를 두고 또 그런 말씀을 하시면, 저녁밥을 머리 위에 부어버릴 줄 아세요.', 66384),
(306473, 'koKR', '죽은 순례자가 보급품 가방을 꽉 움켜쥔 채 누워 있습니다.', '죽은 순례자가 보급품 가방을 꽉 움켜쥔 채 누워 있습니다.', 66384),
(306467, 'koKR', '녀석이 떠나서 차라리 잘된 걸지도 모르겠군. 제 언니랑은 달랐지. 원체 제멋대로인 데다, 어른을 공경할 줄도 몰랐으니 말이야.', '', 66384),
(306455, 'koKR', '도마나르들이 의외로 동맹이 되어 주는군요. 대부분은 잘아타스에게 어떤 식으로든 피해를 입었거나, 그녀가 줄 수 있는 것 이상의 야망을 지니고 있습니다.\n\n적의 적은 동지라는 말도 있잖아요.', '', 66384),
(306448, 'koKR', '잔잔함을 불러오는 향의 냄새가 공기를 가득 채웁니다.', '잔잔함을 불러오는 향의 냄새가 공기를 가득 채웁니다.', 66384),
(306447, 'koKR', '안타깝군. 저번과 같은 상황을 되풀이하고 싶진 않은데.', '', 66384),
(306441, 'koKR', '너희 아제로스 놈들이 시기를 아주 잘 골라서 나타났더군. 잘아타스가 등장한 뒤로, 우리 도마나르의 서열이 완전히 뒤흔들렸거든.\n\n예전엔 힘과 꾀만 있으면 충분했는데, 이제는 잘아타스한테 충성하라고, 머릴 조아리라고 강요당하고 있다. 역겹지.\n\n그딴 압제에 굴복한 도마나르는 살 가치도 없다. 해치워라. 가진 걸 모조리 빼앗아 버려라.', '', 66384),
(306412, 'koKR', '스스로를 지킬 힘이 있는 건 알고 있었지만... 방금 건 눈을 뗄 수 없을 정도로 인상 깊었습니다.', '', 66384),
(306410, 'koKR', '마음이 급한 사냥꾼은 물리기 마련이고요...', '', 66384),
(306408, 'koKR', '유능한 사냥꾼은 어떤 덫이라도 해체할 수 있는 법이죠.', '', 66384),
(306406, 'koKR', '수정이 당신 손길에 호의적으로 반응하는군요. 확실히 알겠습니다.', '', 66384),
(306377, 'koKR', '', '원정순찰대? 진심인가? 흙밭이나 구르는 불한당들을 왜 그렇게 좋게 보는지 모르겠네...', 66384),
(306263, 'koKR', '', '무사히 돌아와서 다행이야, 낙텍! 지금은 전망대로 돌아가서 식량 문제 해결을 돕게.', 66384),
(306262, 'koKR', '', '강 상류에 놓은 덫이 공허에 완전히 삼켜졌어! 하나 세척하려고 했더니 정신 나간 게가 공격하더군!', 66384),
(306260, 'koKR', '', '카가라는 정말 재밌어. 날 감동시키려고 허둥대는 게 오히려 귀엽더라.\n\n그렇게까지 날 생각해 주는 걸 몰랐지. 나도 같이 축제에 가는 게 너무 기대돼!\n\n<잠시 말을 멈추는 나마지>\n\n자크캐쉬가 분명 실망했을 거야. 나중에 꼭 얘기하고, 예쁜 머리장식을 줘서 고맙다고 말할 거야. 자크캐쉬도 함께 갈 다른 사람을 찾을 수 있으면 좋겠어.', 66384),
(306259, 'koKR', '', '자크캐쉬가 같이 가게 됐다고 무척 기뻐하더라. 나도 기대돼!\n\n자크캐쉬가 이렇게 다정한 줄은 몰랐어. 이 머리장식도 너무 예쁘고... 축제 때 꼭 하고 갈 거야!\n\n<잠시 말을 멈추는 나마지>\n\n카가라가 분명 실망했을 거야. 나중에 꼭 얘기하고, 예쁜 목걸이를 줘서 고맙다고 말할 거야. 카가라도 함께 갈 다른 사람을 찾을 수 있으면 좋겠어.', 66384),
(306258, 'koKR', '새끼를 더 잃기 전에 어서 아드지켈을 처치하시오, $n.', '', 66384),
(306244, 'koKR', '게가 거의 없잖아! 게다가 좀... 아픈 것 같기도 하고? 그래도 없는 것보단 낫지!', '', 66384),
(306243, 'koKR', '', '테나지, 이 통발을 전망대로 가져가게. 낙텍은 배회지를 정찰하도록. 그리고 아이들과 어른들이 먼저 식사하게 해!', 66384),
(306239, 'koKR', '카하네아는 이제 막 일을 시작한 참이라, 자네 도움이 절실할 게야.', '', 66384),
(306237, 'koKR', '', '카가라! 목걸이 고마워! 같이 축제에 가게 돼서 정말 좋아!', 66384),
(306236, 'koKR', '', '자크캐쉬! 머리장식 고마워! 같이 축제에 가게 돼서 정말 좋아!', 66384),
(306227, 'koKR', '전 사만이라고 해요. 마침 동물 다루는 데 능숙한 사람이 필요한데요.', '', 66384),
(306212, 'koKR', '아마 이 근처 북쪽 정원에서 티프를 찾을 수 있을 거예요. 꽤 약삭빠르니까 조심하세요.', '', 66384),
(306206, 'koKR', '나는 젊은 아마니 전사 중에서 최고라네! 곧 있으면 동족을 지키는 전사들과 함께할 수 있을 거야.\n\n그래도 내 친구들, 나마지와 카가라는 그리울 거야. 항상 서로를 챙겨줬거든. 항상 함께하던 두 사람이 없을 거라 생각하니 싱숭생숭하군.', '', 66384),
(306205, 'koKR', '티프가 즐겁게 짹짹거립니다.', '', 66384),
(306204, 'koKR', '<이곳에서 싸움이 있었던 것 같습니다. 감자꺼비들이 서로 싸우는 모양입니다.>', '<이곳에서 싸움이 있었던 것 같습니다. 감자꺼비들이 서로 싸우는 모양입니다.>', 66384),
(306203, 'koKR', '티프한테 운동이 좀 필요했던 것 같아요. 그렇지?', '', 66384),
(306202, 'koKR', '마로 말인가? 뭐, 그렇게 볼 수도 있지.\n\n아탈아만에서 도망치던 중 숲에서 마로를 발견했어. 무서워하길래 내가 챙겼지.\n\n이곳으로 데려와 먹을 것도 줬는데, 다시 숲으로 돌아갈 줄 알았거든. 근데 안 가더라고.\n\n이 두루마리 보이지? 스라소니를 제대로 돌보는 법에 대해 적혀 있어. 마로가 여기에 남겠다면, 내가 제대로 돌봐야지.\n\n만져도 돼. 쓰다듬는 거 좋아해! 물론... 싫어지면 얘기가 달라지지만.', '', 66384),
(306165, 'koKR', '<두루마리에서 고개를 드는 카가라>\n\n다른 젊은 아마니들은 날 놀려. 난 싸움을 못 하거든. 힘도 없고, 빠르지도 않고, 피만 봐도 속이 울렁거려.\n\n그래도 나마지랑 자크캐쉬는 그런 걸 신경 안 써. 우리는 어릴 때부터 친구였지.\n\n난 전사는 아닐지 몰라도 머리는 좋아. 언젠가는 로아의 말씀을 전령이 될 수 있을지도 몰라!', '', 66384),
(306164, 'koKR', '', '외곽에서 만나자. 왠지 불길한 예감이 들어.', 66384),
(306163, 'koKR', '', '펑가라 마을은 절대 침묵에 잠길 곳이 아니야. 무슨 변화가 있었던 거지.', 66384),
(306160, 'koKR', '<이 발자국은 생명체의 흔적으로 보입니다. 더 깊은 곳으로 이어지는 듯합니다.>', '<이 발자국은 생명체의 흔적으로 보입니다. 더 깊은 곳으로 이어지는 듯합니다.>', 66384),
(306148, 'koKR', '왔군. 아마니 사냥지배자는 아직 안 나타났어.\n\n그렇다면 남은 건 우리 둘뿐이군. 싸움판을 그렇게 헤집고 다녔으니, 이제 제법 지쳤을 테지?\n\n<켈부조가 당신의 눈을 속일 수 있을 거란 듯이, 서서히 무기로 손을 뻗습니다.>', '', 66384),
(306146, 'koKR', '뭔가 필요한 게 있나?', '', 66384),
(306145, 'koKR', '줄자라 님과 얘기해 봤나?', '', 66384),
(306137, 'koKR', '', '비디우스의 저항은 하찮은 장애물일 뿐이다. 나를 도와 놈을 제거하고, 내 지배를 확고히 하도록.\n\n지금 공격하라! 전쟁 모드에 진입해 비디우스의 대리인을 쓸어버려라.', 66384),
(306122, 'koKR', '지아단이 감히 내게 맞선다고? 학살자의 오름길은 내 것이 될 운명이거늘.\n\n오만방자한 지아딘을 끝장내라. 전쟁 모드에 진입해 지아단의 대리인을 쓸어버려라.', '', 66384),
(306100, 'koKR', '이 소란은 잠식하는 꽃송이에 너무 가까웠소.', '', 66384),
(305956, 'koKR', '', '드디어 우리에게 필요한 날카로운 발톱을 찾았네요.', 66384),
(305948, 'koKR', '', '끝났습니다. 이 재료들을 알라리에게 가져가겠습니다.', 66384),
(305938, 'koKR', '', '등불이 강한 마력으로 진동하는군요.', 66384),
(305905, 'koKR', '어머니는 내게 실수할 기회조차 허락하지 않으셨거든.', '', 66384),
(305901, 'koKR', '', '수중에서 얼마나 오래 호흡할 수 있는지 신경 써야 해요. 익사하면 안 되잖아요!', 66384),
(305892, 'koKR', '', '거의 다 모였어요, $n 님. 조금만 더 수확하면 됩니다.', 66384),
(305891, 'koKR', '', '이 생명체들은 강력합니다! 마력이 점점 더 많이 모이는군요.', 66384),
(305890, 'koKR', '', '이 등불에 공허 마력이 모이는 게 느껴집니다, $n 님.', 66384),
(305889, 'koKR', '엄청 컸어. 내가 본 멀록 중에 제일 컸다니까. 설마... 로아일까? 직접 내려가서 확인할 생각은 없지만!', '', 66384),
(305888, 'koKR', '이 지역을 탐색하면서 오염되지 않은 표본을 더 발견하면 알려주세요. 여기서 배울 건 아주 많아요.', '', 66384),
(305887, 'koKR', '방금 느끼셨나요? 희미한... 허기의 고동 같은.', '', 66384),
(305886, 'koKR', '조심하세요, $p 님!', '', 66384),
(305882, 'koKR', '', '트레버를 찾아가 보세요.\n\n여기서 트레버만큼 식물에 밝은 사람은 없어요. 원하는 게 있다면 분명 도와드릴 겁니다.', 66384),
(305881, 'koKR', '이방인! 잠시 얘기 좀 할 수 있나?', '', 66384),
(305867, 'koKR', '쉿! 잠깐 시간 괜찮나?', '', 66384),
(305855, 'koKR', '밖에서는 눈 똑바로 뜨고 다녀요. 애완동물 친구를 찾는 건 쉬운 일이 아니거든요.', '', 66384),
(305818, 'koKR', '', '지도자가 코비스였다고요? 흥미롭군요...\n\n전 코비스들이 빛을 싫어하고 어둠 속에만 머무는 존재라고 알고 있었는데, 왜 이렇게 지상 가까이 올라왔을까요?\n\n게다가 자신이 거느린 멀록에게 강령술을 가르쳤다니, 이런 식의 행동은 지금껏 본 적이 없습니다.\n\n단순히 돌발적인 행동이었을까요? 아니면 코비스들이 더 사악한 계획을 세우고 있는 걸까요?\n\n<조수 그르긇 그르긇이 저 멀리 허공을 응시하며 생각에 잠긴 듯 보이지만, 멀록 위장장의 눈은 움직이지 않아 진짜 그런지는 알 수 없습니다.>', 66384),
(305809, 'koKR', '<목소리를 낮춰 속삭이는 멀록왕 아옳아옳>\n\n여기서 당분간은 꼼짝 못 할 것 같습니다. 그런데 이 속임수를 얼마나 더 오래 유지할 수 있을까요? 영원히 머물 수는 없어요. 그러다 굶어 죽고 말 겁니다!\n\n언젠가는 제가 채식주의자라는 걸 눈치채겠죠. 아니면 제가 멀록이 아니라는 걸 깨달을지도요. 아니면... 저를 흉내 내려 들 수도 있습니다.\n\n멀록은 대체로 육식을 하니까요. 식단을 바꾸는 건 분명 건강에 치명적일 겁니다.\n\n<멀록왕 아옳아옳은 걱정스러운 말투지만, 입고 있는 멀록 위장복 탓에 아무 감정도 보이지 않고, 서로 다른 방향을 바라보는 눈으로 당신을 응시하고 있습니다.>\n\n뭐, 그래도 이번 기회를 활용해 멀록들을 가까이에서 연구할 수는 있겠네요. 어쩌면 조언도 해 줄 수 있을지 모르고요... 그리고 다른 부족들을 돕기 위해 떠나야 한다는 걸 설득할 수도 있습니다. 멀록의 로아로서 말이죠!', '', 66384),
(305791, 'koKR', '', '우린, 실패했구나...', 66384),
(305790, 'koKR', '', '(숨을 헐떡임)', 66384),
(305789, 'koKR', '', '(헐떡이는 소리)', 66384),
(305788, 'koKR', '', '(비명)', 66384),
(305787, 'koKR', '', '(외침)', 66384),
(305786, 'koKR', '', '(신음 소리)', 66384),
(305785, 'koKR', '', '(거친 호흡)', 66384),
(305784, 'koKR', '', '(신음 소리)', 66384),
(305783, 'koKR', '', '이런 걸 보여주고 싶진 않았는데...', 66384),
(305782, 'koKR', '', '그리고 넌, 그자를 어둠으로 끌어낼 것이야.', 66384),
(305780, 'koKR', '', '그도 네가 괴물임을 알겠지.', 66384),
(305779, 'koKR', '', '(신음 소리)', 66384),
(305774, 'koKR', '여기서 보는 풍경은 숨 막힐 정도야. 새싹일 때부터 계속 왔던 곳이거든. 하란다르 전체가 다 보여. 좋은 것도, 나쁜 것도, 거친 것도, 부드러운 것도. \n\n가니도 이 자리를 좋아해서, 그냥 여기서 살기로 했어.', '여기서 보는 풍경은 숨 막힐 정도야. 새싹일 때부터 계속 왔던 곳이거든. 하란다르 전체가 다 보여. 좋은 것도, 나쁜 것도, 거친 것도, 부드러운 것도. \n\n가니도 이 자리를 좋아해서, 그냥 여기서 살기로 했어.', 66384),
(305772, 'koKR', '당신 앞에 기괴한 도마나르의 장치가 놓여 있으며, 공허 속에서 낮게 진동하고 있습니다.', '당신 앞에 기괴한 도마나르의 장치가 놓여 있으며, 공허 속에서 낮게 진동하고 있습니다.', 66384),
(305768, 'koKR', '', '아마니 제국의 성세가 정점에 도달했을 때, 우린 단 하나의 부족이었다. 하지만 옛날이야기지. 남쪽의 깨진엄니는 독자 노선을 택했어.\n\n심지어 호드에 들어가 진타알로를 차지했다더군. 여기 있는 깨진엄니는 어떻냐고? 우리는 아직도 아마니의 길을 따르고 있다.', 66384),
(305766, 'koKR', '', '톤터스크란 이름은 내 긍지다.', 66384),
(305760, 'koKR', '<목소리를 낮춰 속삭이는 멀록왕 아옳아옳>\n\n심해지느러미의 침입만 어떻게든 막아낼 수 있다면, 이 멀록들도 억지로나마 트롤들과 맺었던 평화로운 공존 상태로 돌아갈 겁니다.\n\n그러면 더는 저 같은 \"멀록의 로아\"도 필요 없어질 테고, 떠날 수 있습니다!', '', 66384),
(305743, 'koKR', '나의 용사를 보내 심해의 로아를 처단하겠다! 우린 승리하리라!', '', 66384),
(305742, 'koKR', '', '흠... 혹시... 코비스...', 66384),
(305741, 'koKR', '영웅이 돌아왔군... 승전보를 갖고 왔겠지? 그렇다고 해다오. 서 있기 지치니까.', '', 66384),
(305739, 'koKR', '아니면... 말고! 며칠 정도는 더 머물러도 괜찮을 것 같으니...', '', 66384),
(305738, 'koKR', '위협이 사라졌으니, 난 이제 떠나야 한다, 아이들아! 나아가 영토를 되찾아라!', '', 66384),
(305737, 'koKR', '위풍당당한 영웅이여! 그대는 심해의 로아를 처단하여 나 멀록왕 아옳아옳이 진정한 멀록의 로아임을 증명해 보였다!', '', 66384),
(305734, 'koKR', '<심해지느러미 지도자를 위한 공물이 놓여 있습니다. 공물로 관심을 끌면 지도자가 나타날지도 모릅니다.>', '<심해지느러미 지도자를 위한 공물이 놓여 있습니다. 공물로 관심을 끌면 지도자가 나타날지도 모릅니다.>', 66384),
(305620, 'koKR', '간식을 보자 강물비늘이 일어나 주목합니다.', '', 66384),
(305612, 'koKR', '드디어... 이곳에 남아 있던 영혼들이 평화를 찾았군요. 언젠가 누님들도 같은 선택을 할 수 있기를 바라요. 저는... 누님들이 돌아올 때까지 이 전당을 음악으로 채우겠습니다. 고맙습니다, 용사 여러분.', '', 66384),
(305562, 'koKR', '', '이 주변의 모든 건 세계수가 있기에 튼튼하고 건강하게 자라난다. 그래서 우리가 보답으로 세계수를 가꿔야 하는 거다.', 66384),
(305561, 'koKR', '', '우린 세계수가 하란다르에 뿌리를 내리기도 전에 이곳에 정착했다.', 66384),
(305559, 'koKR', '<숲포복자가 당신의 얼굴을 핥습니다.>', '', 66384),
(305558, 'koKR', '<당신을 무시하는 강물비늘>', '', 66384),
(305553, 'koKR', '', '장애물들을 치우는 동안, 제  조상들이 짊어진 세월의 무게를 느낄 수 있었길 바라.', 66384),
(305552, 'koKR', '', '당신은 세계수를 건강하게 유지하는 데 힘을 보태고 있을 뿐 아니라, 무엇보다도 전통을 따르고 있어.', 66384),
(305550, 'koKR', '', '강물비늘에게 필요한 건, 침체에서 벗어날 수 있도록 도와줄 친구 하나였어. 고마워, $p.', 66384),
(305535, 'koKR', '상자를 만지자, 인근 탑 쪽에서 당신을 끌어당기는 듯한 기이한 감각이 느껴집니다.', '상자를 만지자, 인근 탑 쪽에서 당신을 끌어당기는 듯한 기이한 감각이 느껴집니다.', 66384),
(305531, 'koKR', '', '$p|1과;와; 즐겁게 어울려라, 강물비늘!', 66384),
(305497, 'koKR', '한심한 쓰레기로다. 어둠접목은 사라져야 해. 이 근처에 접목사가 있을 거다.', '', 66384),
(305496, 'koKR', '', '저 멋진 야수를! 어둠접목 같은 걸로 더럽히다니!', 66384),
(305482, 'koKR', '보아라! 멀록의 영웅의 개선 행진을!', '', 66384),
(305481, 'koKR', '', '절 찾아주셔서 진심으로 감사해요, $n 님. 곧 연구를 다시 이어갈 수 있을지도 모르겠어요.\n\n물론, 그 전에... 음, 로아 문제부터 해결해야겠지만요.', 66384),
(305480, 'koKR', '그야 극적인 재미를 위함이오.\n\n죽음의 골목은... 뭐랄까, 실버문에서 그리 점잖지만은 않은 구역이라 할 수 있소. 거칠면서도 은밀한 그곳은 도적과 세상에서 좋지 않은 평판을 얻은 자들이 즐겨 찾는 장소이지요.\n\n묘하게도 나는 그런 이들과 꽤 잘 어울리는 편이오. 대체로 훌륭한 술과 더 훌륭한 대화를 곁들여주기 때문이지만 말이오.\n\n그곳에서는 \"무역상\"으로 알려진 조직과도 매우 친밀한 관계를 유지하고 있소. 겉보기엔 군대가 아니나, 속단하지 마시오. 그대가 전장에서 마주할 전사 못지않게, 그림자 속에서 값진 몫을 해내는 이들이오.', '', 66384),
(305479, 'koKR', '원정순찰대는 영원노래 숲의 국경을 지키는 용맹한 수호자들이오. 그들만큼 이 숲을 잘 아는 이도 없지요. 알다시피 순찰대 사령관이라는 지위는 예부터 매우 명예로운 직책이었지.\n\n정치와는 거리를 두는 듯 행동하지만, 실상은 여느 귀족 못지않게 이면이 많은 이들이오.', '', 66384),
(305478, 'koKR', '혈기사는 우리의 무력 집단이오. 불굴의 영웅이자 태양이 택한 용사들로, 여군주 리아드린을 따라 전장에 나서서 신도레이의 적을 베어 넘기지요.\n\n과거에 묻힌 골칫거리들은 우리 모두를 합친 것보다 많지만, 이제 와서 놀려본들 재미도 없소. 오히려 스스로 그 상처 많은 역사에 자부심을 느끼는 듯하니 말이오.', '', 66384),
(305477, 'koKR', '마법학자는 실버문의 빛나는 보석과도 같소. 가장 총명한 학자이자 마술사이며 정치가들로, 수백 년에 걸친 수련 끝에 그 지성과 통찰력은 비수처럼 날카로워졌소.\n\n마법학자 롬매스가 이끌고 있긴 하나, 존경은 쉽게 얻어지는 것이 아니오. 마법학자 하나하나가 동부 왕국 전체보다 큰 자존심을 지녔고, 서로 뜻이 맞는 경우는 한 번도 본 적이 없소.', '', 66384),
(305476, 'koKR', '', '감사합니다. 정말 감사해요. 지금 바로 가볼게요!', 66384),
(305471, 'koKR', '', '저는 멀록왕 아옳아옳 님의 조수예요! 그르긇 그르긇이라고 불러주세요.\n\n멀록에 대한 관심 덕분에 멀록왕 아옳아옳 님의 연구를 돕게 됐습니다. 사실 이번이 제 첫 임무예요!\n\n물론 신분을 감추려면 멀록 복장을 입어야 해서 정말 힘들어요. 타우렌이 이런 옷을 입는 게 얼마나 어려운지 상상 가시죠? 지퍼도 끝까지 올리기 힘들 정도예요!', 66384),
(305468, 'koKR', '', '정말 다행입니다! 혹시 멀록왕 아옳아옳 님이 어디 있는지 아시나요?\n\n저희는 작은 유적에 숨어서 토착 멀록들을 관찰하고 있었어요. 그런데 심해지느러미 멀록들을 염탐하러 갔다가 들켜서 쫓겨났죠!\n\n겨우 도망쳐 야영지로 돌아왔을 땐, 멀록왕 아옳아옳 님은 사라지고 침입한 멀록들이 일대를 완전히 장악한 상태였어요!\n\n결국 저도 목숨을 부지하려고 이렇게 숨어들 수밖에 없었습니다. 혹시 멀록왕님이 어디로 간 건지 아시나요? 설마 잡혀버렸나요?', 66384),
(305467, 'koKR', '', '그 망할 괴물을 해치워 주세요. 전 생존자들을 보살피며 안전한 곳으로 데려갈게요.', 66384),
(305462, 'koKR', '', '따라오게!', 66384),
(305460, 'koKR', '', '효과적이지.', 66384),
(305459, 'koKR', '그래, 네가 너무 잘해서 탈이었지. 너는 그 창 좀 치울 생각이 없나? 보기만 해도 성가시다.', '', 66384),
(305458, 'koKR', '', '여전히 쌍검을 고집하나, 비디우스? 난 네 오래된 지팡이에서 나오는 마력을 튕겨내는 쪽이 더 좋았는데.', 66384),
(305456, 'koKR', '', '그렇게 주장했죠. 아주 확고하게. 어떻게 됐는지 직접 보고 싶으신가요?', 66384),
(305450, 'koKR', '<종이들의 위치와 주변 발자국을 보면 누군가 급히 자리를 떴고, 여러 멀록에게 쫓긴 것으로 보입니다.>\n\n심해지느러미가 벌인 토착민 습격은 계획 중 일부에 불과했던 것 같다. 또 다른 목표는 아탈아바시의 무덤이었다.\n\n심해지느러미는 지금까지 멀록에게서 볼 수 없었던 강력한 강령술을 갖추고 있다. 트롤의 유해를 되살려 언데드로 만들 정도니까! 이 힘을 어디서 배운 걸까? 근처의 썩은가지 트롤에게서 전수받은 걸지도 모르겠다.\n\n어쨌든, 이건 단순한 습격이 아니다. 심해지느러미는 언데드 군대를 일으키고 있습니다. 목적이 무엇인지는 아직 알 수 없다.\n\n<발자국은 북서쪽으로 이어져 있습니다.>', '<종이들의 위치와 주변 발자국을 보면 누군가 급히 자리를 떴고, 여러 멀록에게 쫓긴 것으로 보입니다.>\n\n심해지느러미가 벌인 토착민 습격은 계획 중 일부에 불과했던 것 같다. 또 다른 목표는 아탈아바시의 무덤이었다.\n\n심해지느러미는 지금까지 멀록에게서 볼 수 없었던 강력한 강령술을 갖추고 있다. 트롤의 유해를 되살려 언데드로 만들 정도니까! 이 힘을 어디서 배운 걸까? 근처의 썩은가지 트롤에게서 전수받은 걸지도 모르겠다.\n\n어쨌든, 이건 단순한 습격이 아니다. 심해지느러미는 언데드 군대를 일으키고 있습니다. 목적이 무엇인지는 아직 알 수 없다.\n\n<발자국은 북서쪽으로 이어져 있습니다.>', 66384),
(305442, 'koKR', '공허가 부른다...\n\n삼켜야 한다. 집어삼켜야 한다. 채워야만 해.\n\n복종은 내 허기를 멈추게 하지 않아. 단지 너를 집어삼키고 싶은 충동에서 \"해방된 척\"하게 만들 뿐이지.\n\n주인의 속박 때문에 너를 지금 당장 씹어먹을 수는 없으니, 대신 술 섞는 일을 하고 있을 뿐이야.\n\n내 고통은 그냥 내버려둬라.', '', 66384),
(305439, 'koKR', '<배낭의 상태를 보아, 전투 도중에 버려진 것으로 보입니다.\n\n열어보니 여행자에게서 흔히 볼 수 있는 식량, 옷가지, 서류가 들어 있습니다. 당신은 한 장의 종이를 꺼내 읽습니다.>\n\n멀록왕 아옳아옳과 나는 함께 이 지역의 멀록들을 조용히 관찰하고 있었다. 그때, 완전히 다른 심해 멀록 부족이 바다에서 나타나 토착 멀록들을 잔인하게 습격하고 바다로 끌고 갔다. 멀록들이 어떻게 되었을지 생각만 해도 끔찍하다.\n\n게다가 이 침입자들은 이 지역의 트롤 유적에 큰 관심을 보이고 있다. 녀석들이 무슨 짓을 벌이는지 더 가까이에서 확인해 봐야 할 것 같다.', '<배낭의 상태를 보아, 전투 도중에 버려진 것으로 보입니다.\n\n열어보니 여행자에게서 흔히 볼 수 있는 식량, 옷가지, 서류가 들어 있습니다. 당신은 한 장의 종이를 꺼내 읽습니다.>\n\n멀록왕 아옳아옳과 나는 함께 이 지역의 멀록들을 조용히 관찰하고 있었다. 그때, 완전히 다른 심해 멀록 부족이 바다에서 나타나 토착 멀록들을 잔인하게 습격하고 바다로 끌고 갔다. 멀록들이 어떻게 되었을지 생각만 해도 끔찍하다.\n\n게다가 이 침입자들은 이 지역의 트롤 유적에 큰 관심을 보이고 있다. 녀석들이 무슨 짓을 벌이는지 더 가까이에서 확인해 봐야 할 것 같다.', 66384),
(305434, 'koKR', '어머니가 돌아가셨다고 들었어. 이 $rl|1은;는; 누구지?', '', 66384),
(305433, 'koKR', '흠... 장비는 괜찮고, 자세도 나쁘지 않아. 기술도 그럭저럭 쓸만하군.\n\n완벽한 졸개감이야!\n\n안타깝게도... 술 취한 타우렌, 마법서, 카드가의 휠체어 사건 이후로 아르칸티나에서 계약을 못 맺게 됐지만 말이야.\n\n그래도 세상 돌아다니다가 일회용 졸개 자리 찾으면 나한테 와. 그때쯤이면 계약 다시 맺을 수 있을 거야.', '', 66384),
(305431, 'koKR', '그리고 또 빛의 힘을 갖고 설치는 광신자들에게 뒤통수나 맞으란 말인가?\n\n이보게, 내가 스컬지에 시달렸던 건 사실이지. 하지만 날 죽인 건 성기사의 칼이었어. 그 짓을 또 당할 생각은 없어.\n\n마리우스를 꼬드겨서 공허를 잡아먹는 사냥꾼들과 한번 훈련이나 해보자고 할 참이었지. 우리만의 비책을 좀 마련해 보려던 참이었는데, 그 바보 같은 선봉대가 날 체포하려 드는 바람에 말이야.\n\n도와줘서 고맙네. 다음 술값은 내가 내겠네.', '', 66384),
(305428, 'koKR', '오, 자네였군.\n\n악마를 사냥한다든지, 지옥 유물을 찾겠다든지... 그런 일로 왔다면 나한텐 묻지 말게. 지금은 휴식 중이거든.\n\n일 중독자 마리우스 양반은 술 한 잔이 필요하고, 나는 말이야... 속에 들끓는 내 악마들을 좀 달래야겠어. 말 그대로도, 비유적으로도 말이지.\n\n우리가 불타는 군단 이후로 해치우거나, 잡거나, 봉인한 악마가 백 마리하고 열다섯 마리나 된다네.\n\n이 정도면 술 몇 잔 마실 자격은 있잖은가?', '', 66384),
(305426, 'koKR', '이번... 휴식은... 꽤 여유롭군요.\n\n심지어 도움이 되기도 했고요.\n\n그래서 더 싫습니다.\n\n살게라스가 쓰러진 지금, 불타는 군단은 예전과 같은 위세는 없지만 여전히 어둠 속에 숨어 살아남고 있습니다. 놈들을 뒤틀린 황천 끝까지 쫓아가야 합니다.\n\n...하지만 그 전에 테드가 교수형 방울주라는 음료에 대해 설명해 줬습니다. 상당히 기괴하던데요. 꼭 마셔봐야겠습니다.', '', 66384),
(305419, 'koKR', '', '고맙네, $p. 혼자서 하긴 싫었거든.', 66384),
(305403, 'koKR', '아니! 내 힘을 받지 않겠다면 지식도 받을 수 없다!', '', 66384),
(305401, 'koKR', '아제로스는 전쟁에 전쟁을 거듭하며 피폐해졌죠. 우리 역시 이런 황폐한 최후를 맞게 되는 걸까요?', '', 66384),
(305400, 'koKR', '정말로 이곳에 제국이 존재했던 걸까요? 오직 지식 하나만 바라보았던 한 사람 때문에 사라진 걸까요?', '', 66384),
(305399, 'koKR', '그렇게 네 의지의 노예가 되라고? 아니. 네 지식은 너와 함께 사라져야 해.', '', 66384),
(305397, 'koKR', '수수께끼가 너무 많아요! 이 글은 뭘까요? 도마나르 언어? 에테리얼? 아니면 그보다 더 오래된 무언가?', '', 66384),
(305393, 'koKR', '유령, 당신의 지식을 알려줘요! 당신이 있는 곳을 알려줘요!', '', 66384),
(305390, 'koKR', '주문은 금방 끝나요. 유령, 말해봐요. 과거 프레다케아에는 지성을 지닌 존재들이 살았나요?', '', 66384),
(305387, 'koKR', '또 그런 질문하면 몇 대 더 맞게 될 거다. 당장 일이나 해, 졸개 주제에. 제 자리는 알고 움직여야지.', '', 66384),
(305386, 'koKR', '나의 축복을 받은 용사를 보아라! 그대들을 대신해 나아가 싸울 자다!', '', 66384),
(305377, 'koKR', '모르지. 예전에도 네놈들이 와서 똑같이 물어봤을 때도 그랬으니까.\n\n걱정 마라. 우릴 이끌 주인님들은 어딜 가야 할지 다 알고 계시니까.', '', 66384),
(305375, 'koKR', '처음도 아니고 마지막도 아니지. 듣자 하니, 이 호드와 얼라이언스도 비슷한 모양이더군.', '', 66384),
(305374, 'koKR', '', '그러니 또다시 싸움을 멈추고 공통의 적을 쓰러뜨리기 위해 손을 잡아야 한다.', 66384),
(305373, 'koKR', '', '나약해 빠진 놈! 어둠접목 따위나 써먹다니! 너는 잘아타스와 다를 바 없다!', 66384),
(305372, 'koKR', '감히 그런 말을...! 아, 알겠다. 조종당하고 있었군. 다른 도마나르가 끼어들었다.', '', 66384),
(305370, 'koKR', '지아단이 곧 도착한다. 나와 칼을 맞댈 기회를 그냥 지나칠 리 없지. 뭘 가져온 거지?', '', 66384),
(305368, 'koKR', '됐어요! 저 춤추고 있어요!', '', 66384),
(305365, 'koKR', '리카리 교관님께서 우리 모두를 춤 수업에 끌고 가셨어요. \"절제\", \"협응\", \"전투의 춤\"이 어쩌고 하셨는데.\n\n차라리 여기 말고 다른 아무 데나 가는 게 낫겠어요. 머리랑 발이 따로 노는 기분이거든요.\n\n이게 다 무슨 의미인지.', '', 66384),
(305354, 'koKR', '당신은 할 수 있습니까? ...이건 불가능해요. 절대 내려놓을 수 없어요.', '', 66384),
(305353, 'koKR', '<목소리를 낮춰 속삭이는 멀록왕 아옳아옳>\n\n제발 도와주십시오!\n\n저는 줄아만에 사는 멀록들을 연구하러 왔는데, 다른 부족이 이들을 습격했고, 제가 방어에 나서자 멀록들이 절 신인지 로아인지 모를 존재로 여기기 시작했어요!\n\n하지만 저는 신 같은 존재가 아닙니다! 이 복장을 입고 멀록 흉내나 내는 것도 겨우 하고 있습니다!\n\n게다가 연구자로서 이런 상황은 명백히 금기 사항이기도 하고요!', '', 66384),
(305351, 'koKR', '내 왕국에 온 걸 환영한다, 여행자여. 평화와 번영이 함께하기를!', '', 66384),
(305340, 'koKR', '아니, 그럴 리가... 당신의 무기가 프레다케아의 모든 문명을 멸망시켰다고요? 그걸 안고 어떻게 살아온 거죠? 어떻게 아직도 남아 있는 거지?', '', 66384),
(305321, 'koKR', '내 제국은 전쟁을 끝낼 무기를 요구했다. 그래서 만들어 주었다.', '', 66384),
(305320, 'koKR', '유령... 당신이 아킨툰데인가요? 무기 제작자 같은 존재였던 거죠?', '', 66384),
(305307, 'koKR', '지독한 냄새를 풍기는 혼합물이 가마솥에서 보글거리며 끓고 있습니다.', '지독한 냄새를 풍기는 혼합물이 가마솥에서 보글거리며 끓고 있습니다.', 66384),
(305247, 'koKR', '이 석판을 새긴 게 당신이에요? 당신의 종족... 당신의 문명은... 전쟁으로 사라진 건가요?', '', 66384),
(305229, 'koKR', '어쩌면 그럴지도 모르겠습니다. 어떤 이유에서든 이곳에 있는 동안은 성스러운 빛을 섬기는 데 최선을 다하겠습니다.\n\n다만, 왜 전 부름이 없었는지 아직도 마음에 걸리는군요.', '', 66384),
(305228, 'koKR', '그럴 수도 있겠지요. 사실이라면 반가운 일입니다. 그렇게 믿는 편이 마음이 한결 편할 것 같기도 합니다.\n\n확신을 얻을 방법은 없지만, 그런 확신이 없더라도 제가 걸어야 할 길은 분명합니다. 지금처럼 변함없는 믿음과 헌신으로 성스러운 빛을 따르겠습니다.', '', 66384),
(305077, 'koKR', '', '내기에 참여하러 오셨습니까?', 66384),
(305070, 'koKR', '너 싸우는구나. 좋다.\n\n우린 네가 싸우길 원한다. 더 싸워라. 피 흘려라. 죽음을 위해 싸워라.\n\n우린 네가 마음에 든다.', '', 66384),
(305067, 'koKR', '상황이... 복잡해요.\n\n이곳 학살자의 오름길에서 세 도마나르 세력이 각축전을 벌이고 있는데, 우리와 싸우려는 것보단 자기들 싸움에 끌어들이려는 눈치예요. 특히 호드와 얼라이언스 사이의 오랜 분쟁에 묘한 흥미를 보이고 있어요.\n\n얼마 전부터는 호드와 얼라이언스 소속에서 이탈한 구성원들까지 모습을 드러내기 시작했습니다. 도마나르가 가장 증오에 사로잡힌, 피에 굶주린 전사들을 골라 싸움을 붙이고는 유흥으로 삼는 것 같더군요.\n\n<고개를 젓는 균열감시자 테레멘>\n\n지금 같은 때에 이런 충돌을 감당할 여력은 없습니다. 호드와 얼라이언스의 공식 대표들 중 그 누구도 이 일을 승인하지 않았어요. 많은 일이 벌어지고 있어서, 정작 이 사태를 알고 있는지조차 확신이 들지 않네요.\n\n증오라는 감정은 깊이 뿌리를 내릴 때도 있으니까요.', '', 66384),
(305062, 'koKR', '강한 자만 살아남는다. 내 동족은 약했다. 나는 죽음마저 넘어섰다! 그리고 이제, 너희가 내 부활을 도울 것이다.', '', 66384),
(305061, 'koKR', '피바람을 멈출 수 있었던 건 오직 내가 만든 아름다운 무기뿐이었다.', '', 66384),
(305014, 'koKR', '제단에서 기도를 올리고 싶으면, 얼마든지 하게나.', '제단에서 기도를 올리고 싶으면, 얼마든지 하게나.', 66384),
(304995, 'koKR', '이 야수들이 서식지를 벗어나 잠식하는 꽃송이 깊은 곳으로 향하고 있소. 놈들이 병력을 강화하도록 놔둬선 안 되오.', '', 66384),
(304994, 'koKR', '잘아타스는 우리 도시 하나를 앗아 갔습니다. 또 빼앗기지 않을 겁니다.', '잘아타스는 우리 도시 하나를 앗아 갔습니다. 또 빼앗기지 않을 겁니다.', 66384),
(304993, 'koKR', '이상하네... 누가 말하는 소리가 들린 것 같았는데... 바람이었나...', '이상하네... 누가 말하는 소리가 들린 것 같았는데... 바람이었나...', 66384),
(304992, 'koKR', '배신자의 말 따위는 듣고 싶지 않습니다.', '배신자의 말 따위는 듣고 싶지 않습니다.', 66384),
(304990, 'koKR', '테라모어에 있을 때, 호드의 폭격으로 친구와 사랑하는 이들을 잃었습니다. 우린 그저 필요에 의한 동맹일 뿐입니다. 그 이상은 아닙니다.', '테라모어에 있을 때, 호드의 폭격으로 친구와 사랑하는 이들을 잃었습니다. 우린 그저 필요에 의한 동맹일 뿐입니다. 그 이상은 아닙니다.', 66384),
(304988, 'koKR', '지금도 당신에게서 지옥 마력이 느껴집니다. 당장은 공동의 적이 있으니 다행이지요.', '지금도 당신에게서 지옥 마력이 느껴집니다. 당장은 공동의 적이 있으니 다행이지요.', 66384),
(304987, 'koKR', '저는 실버문을 지키기 위해 싸우겠습니다. 하지만 당신이 호드에 가담해 우리를 배신한 일을 잊지는 않았습니다.', '저는 실버문을 지키기 위해 싸우겠습니다. 하지만 당신이 호드에 가담해 우리를 배신한 일을 잊지는 않았습니다.', 66384),
(304985, 'koKR', '호드에 가담해 우리를 배신한 기분이 어떻습니까?', '호드에 가담해 우리를 배신한 기분이 어떻습니까?', 66384),
(304984, 'koKR', '포세이큰이 마을에서 살고 있고, 트롤과 조약을 맺었으며, 오크와는 평화를 유지하고 있다니.\n\n이곳은 제가 떠났던 쿠엘탈라스가 아닙니다. 그래도 전 쿠엘탈라스의 자손으로서, 이 땅을 지킬 겁니다.\n\n하지만 더 이상 제 고향처럼 느껴지진 않네요.', '포세이큰이 마을에서 살고 있고, 트롤과 조약을 맺었으며, 오크와는 평화를 유지하고 있다니.\n\n이곳은 제가 떠났던 쿠엘탈라스가 아닙니다. 그래도 전 쿠엘탈라스의 자손으로서, 이 땅을 지킬 겁니다.\n\n하지만 더 이상 제 고향처럼 느껴지진 않네요.', 66384),
(304983, 'koKR', '전 처음에 영원노래 숲을 전쟁으로부터 지키기 위해 떠났습니다.\n\n그리고 지금, 같은 이유로 돌아왔군요. 남아 있었던 이들이 우리가 왜 떠났는지, 또 왜 돌아왔는지 이해해 주길 바랄 뿐입니다.', '전 처음에 영원노래 숲을 전쟁으로부터 지키기 위해 떠났습니다.\n\n그리고 지금, 같은 이유로 돌아왔군요. 남아 있었던 이들이 우리가 왜 떠났는지, 또 왜 돌아왔는지 이해해 주길 바랄 뿐입니다.', 66384),
(304982, 'koKR', '쿠엘탈라스의 숲을 오래간만에 보는군요.\n\n바람에 실려 들려오는 노랫소리를 잊고 있었습니다.', '쿠엘탈라스의 숲을 오래간만에 보는군요.\n\n바람에 실려 들려오는 노랫소리를 잊고 있었습니다.', 66384),
(304975, 'koKR', '흥미롭군. 필멸자가 그런 음식을 먹는다는 얘기는 들어본 적 없다. 케이크 같은 건가? 아제로스인의 제작 기술을 연구할 당시, 제빵이 가장 흥미롭게 다가왔지. 그래, 너도 빵은 즐겨 먹겠지? 그렇다고 하자고. \n\n나는 온갖 풍미를 즐긴다. 비통함, 질투, 공포...\n\n<낮게 콧노래를 흥얼거리며 입술을 핥는 데시무스>\n\n그다음은 뭐지? 너희 필멸자들이 흔히 나누는 사소한 화제라면... 좋아, 이번엔 이렇게 묻지.\n\n네가 두려워하는 건 무엇이냐?', '', 66384),
(304971, 'koKR', '', '놈들이 공격하려 했다고 단정 짓지 마, 펠나. 도와달라고 하는 것처럼 보였어.', 66384),
(304931, 'koKR', '$n, 기억의 만에 또다시 빛만개가 밀려들고 있다. 이번엔 포자사우루스 무리가 앞장서고 있지.\n\n놈들은 덩치만 거대한 게 아니야. 몸에서 흘러나오는 포자가 땅에 닿는 순간 걷잡을 수 없이 자라나기 시작하지.\n\n하지만 포자가 퍼지기 전에 먼저 잡을 수 있다면, 그 힘을 되려 놈들한테 돌려줄 수 있을 거다.', '$n, 기억의 만에 또다시 빛만개가 밀려들고 있다. 이번엔 포자사우루스 무리가 앞장서고 있지.\n\n놈들은 덩치만 거대한 게 아니야. 몸에서 흘러나오는 포자가 땅에 닿는 순간 걷잡을 수 없이 자라나기 시작하지.\n\n하지만 포자가 퍼지기 전에 먼저 잡을 수 있다면, 그 힘을 되려 놈들한테 돌려줄 수 있을 거다.', 66384),
(304930, 'koKR', '', '지금은 매우 바쁩니다, 용사님. 중요한 일입니까?', 66384),
(304922, 'koKR', '썩은가지가 스튜를 끓이고 있었던 듯합니다. 여러 고기와 약초 냄새가 강하게 풍깁니다.', '썩은가지가 스튜를 끓이고 있었던 듯합니다. 여러 고기와 약초 냄새가 강하게 풍깁니다.', 66384),
(304906, 'koKR', '처음 망령을 만든 것보단 덜 끔찍하죠. 그건 망가졌어요, $p 님. 계속 고통을 퍼뜨릴 거예요. 우리가 끝내지 않는 한은.', '', 66384),
(304901, 'koKR', '어서 가요. 균열은 제가 유지하겠습니다. 무슨 일이라도 생기면 바로 끌어내 드릴게요.', '', 66384),
(304900, 'koKR', '망령이 뭐냐고요? 균열방랑자 열두 명에게 물어보면 스물네 가지 대답이 돌아올 겁니다. 누군가는 현신이라 하고, 누군가는 어둠의 잔상이나 환영이라 하죠. 그걸 이해하려는 건 손으로 그림자를 붙잡으려는 것과 같습니다.\n\n몇 주 전만 해도 저는 망령을 안다고 생각했어요. 심지어 직접 만들어낼 수도 있다고 믿었죠. 그런데 제가 불러낸 건 고통과 절망만을 아는 무언가였어요.\n\n그러니 이제는 솔직히 모르겠습니다. 다만 확실한 건, 사라졌으면 좋겠다는 것뿐이에요.', '', 66384),
(304897, 'koKR', '', '시범을 보여줘야겠네요. 위대한 $c|1이;가; 어떻게 춤을 추는지 보여주세요!', 66384),
(304895, 'koKR', '여기 온 것만으로도 인정해 주면 좋습니다만, 이게 춤이랑 무슨 상관이 있는지는 모르겠습니다.', '', 66384),
(304894, 'koKR', '잠깐, 박자를 알 것 같습니다.', '', 66384),
(304872, 'koKR', '', '오래전, 놀드랏실이라는 나무가 마력이 깃든 물 위에 뿌리를 내렸어요. 우리는 지켜봤죠. 뿌리가 대지를 꿰뚫는 것을. 그리고 기다렸어요. 알른하라의 빛을 찾기를. 세상의 모든 뿌리가 그러하듯 말이에요.\n\n놀드랏실의 뿌리가 하란다르에 닿았을 때, 반짝이는 비도 함께 내렸어요. 수년 동안 졸졸 흐르던 물줄기들이 폭포와 호수로 변화한 게 지금 당신 앞에 있는 모습이에요.\n\n하르쿠아이에 오신 걸 환영해요, 나그네여. 잘 오셨습니다.', 66384),
(304841, 'koKR', '', '당신이 있어야 해요, 레오나. 이 향을 받아서 제단 주변 동서남북 지점에 놓아주세요.', 66384),
(304837, 'koKR', '원정대가 어떤 특이한 표본을 발견했을지 궁금하군요.', '', 66384),
(304827, 'koKR', '', '함께하겠습니다, $n 님.', 66384),
(304824, 'koKR', '마력을 충분히 모으면, 이 도마나르 장치들을 통해 정찰병들을 찾아낼 수 있을 거다.', '', 66384),
(304812, 'koKR', '잠시만요. 죄, 죄송해요.', '', 66384),
(304811, 'koKR', '', '저도 잘 모르겠습니다. 어쩌면 당신이 더 잘 아실지도 모르죠. 경험 많은 균열방랑자조차도 당신만큼 기이한 유물들을 많이 다뤄본 적은 없을 겁니다.\n\n제 조언은 하나예요. 의지를 다잡고, 공허를 지배하세요. 라이시카스의 말대로, 조준하고 쏘면 됩니다.', 66384),
(304809, 'koKR', '', '렌도레이 대부분은 자유분방하지만, 라이시카스는 반항에 가깝습니다.\n\n꽁무니를 쫓느라 자리를 비워야 하는 건 영 마음에 들지 않네요. 사격을 그렇게 잘하지 않았다면 차원문을 열어 텔로그러스로 되돌려 보냈을 겁니다.\n\n제발 쓸데없이 시간 낭비만 하지 않길 바랄 뿐이에요.', 66384),
(304789, 'koKR', '하라시르는 오래된 마을이지. 세대에 걸쳐 우리는 아른가루를 갈아내 기억을 품을 수 있는 선명한 안료를 만들어 왔다네. 하란다르의 모든 역사는 바로 이곳에서 돌에 새겨지는 여정을 시작하지.\n\n요즘은 새로운 영광도 얻었지. 자네들이 아미드랏실이라 부르는 나무의 뿌리가 이제 이 요람을 향해 뻗고 있네. 나는 뿌리감시관으로서 이 뿌리들이 하란다르에 깃든 모든 생명을 위해 안전하고 잘 자라도록 돌보고 있다네.', '', 66384),
(304782, 'koKR', '<최근에 죽은 시신입니다. 빛 포자가 뿌리를 내린 지는 얼마 안 됐습니다.>', '<최근에 죽은 시신입니다. 빛 포자가 뿌리를 내린 지는 얼마 안 됐습니다.>', 66384),
(304754, 'koKR', '일리다리는 마법사 지구 북서쪽 구역에 있습니다. 소톤 둠렌더를 찾아가 보십시오.\n\n대신 제가 보냈다는 말은 하지 마십시오.', '일리다리는 마법사 지구 북서쪽 구역에 있습니다. 소톤 둠렌더를 찾아가 보십시오.\n\n대신 제가 보냈다는 말은 하지 마십시오.', 66384),
(304740, 'koKR', '', '밖에서 뭘 하셨는지 몰라도, 효과가 있었던 것 같아요.', 66384),
(304644, 'koKR', '어머니가 보낸 건가요?\n\n저녁에는 집에 간다고 전해주세요.\n\n아주 중요한 일을 해야 하거든요!', '', 66384),
(304641, 'koKR', '여긴 제가 사색하고 지켜보는 곳이에요.\n\n똑같은 걸 하러 온 거라면, 알아서 자리 찾든가!', '', 66384),
(304602, 'koKR', '', '도움을 청하려고 한 걸지도 몰라. 근데 마을이 가까우니, 매복이었을 수도 있지. 조심해라, $n.', 66384),
(304599, 'koKR', '', '날로라크의 소굴에서 살아 돌아왔군. 생각보다 강하잖아. 우리와 함께할 자격은 있어.\n\n그래도 고킨예이긴 하지만.', 66384),
(304597, 'koKR', '', '무심한 척하지만, 줄자라의 마음속에는 여전히 신이 직접 나타나길 바라는 깊은 열망이 느껴집니다.', 66384),
(304593, 'koKR', '환영한다, 여행자여.\n\n처음 보는 종족이로군. 알른하라께서 우리의 길을 엮어주신 걸까?', '환영한다, 여행자여.\n\n처음 보는 종족이로군. 알른하라께서 우리의 길을 엮어주신 걸까?', 66384),
(304592, 'koKR', '스토마리온은 단순한 요새가 아니라 의식 장소예요. 포식의 군단이 이곳에서 공허를 실험하고 있죠. 어떻게 우리의 목숨을 빼앗을 수 있을지 말입니다. 이 공간을 아주 누더기로 만들어 놨어요. 마치 낡은 돛처럼요. 수백 개의 작은 균열이 생겨서 시간이 갈수록 점점 더 벌어지고 있죠.\n\n그중에서도 특이점이 가장 위험해요. 스스로 유지될 만큼 커져 버렸는데, 물질과 마력을 삼켜서 다른 어딘가에 뱉어내고 있어요.\n\n안정적인 상태일 때는 차원문처럼 유용해요. 목적지를 예측할 수 없어서 그렇지. 그런데 특이점은 대체로 불안정해져서 터지는 경향이 있거든요.\n\n해결 방안은 있긴 하지만, 비용이 많이 들고 오래 가지도 않습니다.', '', 66384),
(304529, 'koKR', '해냈다! 아, 감사합니다, 리카리 님. 훌륭한 스승님을 둔 덕분이죠.', '', 66384),
(304528, 'koKR', '', '다르락, 인상 깊었네. 축하하네, 병사여.', 66384),
(304523, 'koKR', '', '충분하네. 둘 다 잘했어.', 66384),
(304522, 'koKR', '', '다르락, 실력을 보여주게! $n 자네도 봐주지 말게나!', 66384),
(304521, 'koKR', '상관과 함께 위층에서 뵙겠습니다. 겉모습만큼 강한 분이길 바라죠!', '', 66384),
(304513, 'koKR', '', '아아아아아아아!', 66384),
(304510, 'koKR', '', '이번엔 할 수 있어요. 용사님 응원이 너무 약했던 걸지도 모르죠.', 66384),
(304509, 'koKR', '', '닥쳐, 브웜!', 66384),
(304508, 'koKR', '거봐요!', '', 66384),
(304507, 'koKR', '', '셋!', 66384),
(304505, 'koKR', '', '알았어. 하나... 둘...', 66384),
(304504, 'koKR', '', '그렇죠, $n 님?', 66384),
(304503, 'koKR', '', '아, 아냐! 이번엔 새 친구가 응원해 줄 거야!', 66384),
(304502, 'koKR', '에이, 또 겁먹은 거야, 꼬마 아니?', '', 66384),
(304490, 'koKR', '', '촉매는 물건에 강력한 힘을 불어넣어 강화하고 잠재력을 최대한으로 끌어올릴 수 있습니다!', 66384),
(304489, 'koKR', '', '눈부시지 않습니까?\n\n다트리마 시대 이래로 엘프들은 이 위대한 가열로를 이용해 강력한 방어구를 제작해 왔습니다. 처음 이 불꽃을 지핀 건 이곳을 둥지로 삼은 불사조의 영혼이었다고 전해지지요. 지금도 그 힘이 모든 창조물에 깃들어 있다고들 합니다.\n\n당신도 이 불꽃의 축복을 누릴 수 있도록 허락하겠습니다.', 66384),
(304488, 'koKR', '해냈다, $n. 드디어 카다니가 됐다. 전부 네 덕분이야.\n\n하지만 큰 축하의 순간에는 슬픔도 함께 찾아오지. 사냥이란 원래 그런 거다. 사냥꾼이 살아가려면 먹잇감은 반드시 여정을 마쳐야 해.\n\n사냥꾼은 사냥 그 자체에서 즐거움을 찾아선 안 된다. 작고 연약한 떠돌이든, 거대한 짐승이든 사냥의 이치 앞에서는 모두 같다.\n\n라두니의 몸은 앞으로 일주일 동안 우리에게 재료와 식량을 선사할 거다. 위대한 야수의 희생에 감사해야겠지.', '해냈다, $n. 드디어 카다니가 됐다. 전부 네 덕분이야.\n\n하지만 큰 축하의 순간에는 슬픔도 함께 찾아오지. 사냥이란 원래 그런 거다. 사냥꾼이 살아가려면 먹잇감은 반드시 여정을 마쳐야 해.\n\n사냥꾼은 사냥 그 자체에서 즐거움을 찾아선 안 된다. 작고 연약한 떠돌이든, 거대한 짐승이든 사냥의 이치 앞에서는 모두 같다.\n\n라두니의 몸은 앞으로 일주일 동안 우리에게 재료와 식량을 선사할 거다. 위대한 야수의 희생에 감사해야겠지.', 66384),
(304487, 'koKR', '', '이건 정상이 아니야.\n\n여기서 보고 있는 것들, 메아리를 보고 연구한 모든 걸 다 종합해 보면 딱 하나의 진실이 보여. 이 도시는 지금 스스로 정화 중일세.\n\n수십 년 사이 아탈아만은 말라크라스의 암흑 마법, 모르둔의 역겨운 공허 마력, 그리고 우리 로아와의 재결합까지 겪었지.\n\n이제야 반응하는 거야. 마치 불꽃축제 전야에 단 열매를 너무 많이 먹고 속을 다 게워 내는 아이처럼.\n\n차이가 있다면 이번에는 한참 지나간 세월의 전사와 모험가들의 기억을 쏟아내고 있다는 거지만...', 66384),
(304486, 'koKR', '도루의 말을 들어보면, 이 메아리들이 왜 여기 모여 있는지 이유가 아주 분명하더군.\n\n하지만 내 생각은 좀 다르네. 선조들이 우리 뒤통수를 딱 한 대 갈기러 온 거라고 봐.\n\n우린 진실을 마주한 적이 없었다네. 줄진이랑 말라크라스가 저지른 짓에 뭔가 잘못됐단 걸 다들 알고는 있었지. 설명은 못 해도... 결국, 그 둘 주변에 어둠이 따라다니고 있었거든.', '', 66384),
(304457, 'koKR', '', '조심해서 가게! 지금 우리가 상대하는 게 뭔지 확실치 않네.', 66384),
(304438, 'koKR', '', '녀석한테 잘 죽으라고.', 66384),
(304437, 'koKR', '', '하하! 아니. 이제 너한테 붙었어. 이젠 전적으로 \"네\" 문제인 셈이지. 난 빠질 거야!', 66384),
(304436, 'koKR', '', '<칸자는 당신과 눈을 맞추지 않습니다. 자신의 발끝만 바라보며 손을 꼬아 쥡니다.>', 66384),
(304435, 'koKR', '', '내 고향은 여전히 울창하고 생명력이 넘치네. 하지만 하라티는 안일해져선 안 돼.\n\n여신의 피조물은 익숙한 환경만이 아니라 전부를 지켜야 하네.', 66384),
(304434, 'koKR', '', '이건 통하지 않을 것 같은데.\n\n그래도 더 이상 나를 쫓아오진 않으니까... 이걸로 만족할게.', 66384),
(304429, 'koKR', '', '솔직히 그게 너한테 집중해서 한시름 놨어. 슬슬 힘이 돌아오는 것 같아.', 66384),
(304428, 'koKR', '이 장소에서의 사냥은 끝났다. 그래도 한 곳만 더 가면 만족스러울 것 같군.', '이 장소에서의 사냥은 끝났다. 그래도 한 곳만 더 가면 만족스러울 것 같군.', 66384),
(304427, 'koKR', '', '하! 늙은이가 큰소리를 떵떵 내지르니까 진지하게 받아들이기 어렵구먼!', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(304426, 'koKR', '우리의 목숨을 걸고 아탈아만에 영광을 돌려놓자!', '', 66384),
(304425, 'koKR', '', '저 양반 참...', 66384),
(304424, 'koKR', '이번에도 숲 부족이 자네에게 감사를 표하네, 하쉬우라.', '', 66384),
(304423, 'koKR', '몇 가지 재료를 더 찾아야 합니다. 하라시르에서 뵙겠습니다.', '몇 가지 재료를 더 찾아야 합니다. 하라시르에서 뵙겠습니다.', 66384),
(304422, 'koKR', '$n, 사냥은 잘 되고 있지?\n\n나는 하라시르의 대장장이 알리아트에게 줄 덩굴을 모으고 있다. 장인의 도움을 구할 땐 예물을 바치는 게 우리 전통이거든.\n\n덩굴손 덩굴은 구하기 힘들지만, 그만큼 질기면서 사치스러운 재료지. 알리아트가 만족할 거야.', '$n, 사냥은 잘 되고 있지?\n\n나는 하라시르의 대장장이 알리아트에게 줄 덩굴을 모으고 있다. 장인의 도움을 구할 땐 예물을 바치는 게 우리 전통이거든.\n\n덩굴손 덩굴은 구하기 힘들지만, 그만큼 질기면서 사치스러운 재료지. 알리아트가 만족할 거야.', 66384),
(304419, 'koKR', '', '제일 좋은 사체를 상에 올리게. 리샨과 내가 손질을 시작할 테니.', 66384),
(304413, 'koKR', '', '제 영혼을 바치겠습니다, 마법학자님.', 66384),
(304412, 'koKR', '렌도레이는 사방에서 위협에 시달리고 있습니다, 옛 제자여. 당신과, 당신을 따를 만큼 강인한 이들이 우리의 미래를 지켜줄 거란 사실이 참으로 든든하군요.', '', 66384),
(304411, 'koKR', '', '이제 이 힘으로 더 많은 동족을 제 길로 이끌 수 있게 됐고요.', 66384),
(304410, 'koKR', '', '그렇습니다, 엄브릭 님. 일리다리의 강인함과 결단력이 레오나의 일부가 됐어요.', 66384),
(304409, 'koKR', '레이브노어의 사악한 기운이 갑자기 사라지더군요. 성공하신 겁니까?', '', 66384),
(304408, 'koKR', '', '레오나, 여기서 실패하면 당신은 죽습니다. 구해주지 않을 겁니다.', 66384),
(304404, 'koKR', '', '여기가 바로 전환점입니다, $n 님.', 66384),
(304403, 'koKR', '조금만 물러나 주십시오. 공간이 좀 필요합니다.', '', 66384),
(304402, 'koKR', '이런 데 초대받는 것도 참 기분 좋네! 늑대인간의 털은 마셔봤나? 끝내주게 독해!\n\n우리 오래된 여행 일지에도 새로운 이야기들이 쓰이고 있다네. 술값 탕감 도와준 거, 고맙게 생각하네.', '', 66384),
(304401, 'koKR', '이곳에서 기디와 한두 번쯤 시원하게 붙어볼까도 했지만, 여긴 그런 분위기의 장소는 아닌 듯하오.\n\n그럼에도 오래된 유물들에서 흘러나오는 이야기들은 많소. 아, 기분 나빠하지는 마시오.', '', 66384),
(304400, 'koKR', '이런 데 초대받는 것도 참 기분 좋네! 늑대인간의 털은 마셔봤나? 끝내주게 독해!', '', 66384),
(304399, 'koKR', '쳇! 자네 얘긴 허점투성이야. 리치 왕이 그 많은 죽음의 기사들을 어떻게 부활시켰다는 거지?', '', 66384),
(304398, 'koKR', '기디를 알겠지만, 기사들이 멋졌다면 그중 몇이 언데드였는지는 중요하지 않을 거요.', '', 66384),
(304395, 'koKR', '오르웨냐가 어디서 왔는지 알고 나니까, 이제야 여러 가지가 이해가 돼. 나도 한곳에서 벗어나고 싶어 하다가 결국 다시 제자리로 돌아온 기분이 어떤 건지 잘 알거든.\n\n그래서 여기 온 게 내게는 큰 의미가 있지.', '', 66384),
(304394, 'koKR', '', '몬테가 자기 고향 언더마인을 구경시켜 줬지. 그곳에서 나는 모두와 달라 보였네.\n\n이곳에서는 몬테가 환영받는 기분을 느끼게 해주고 싶어. 그게 내가 해줄 수 있는 최소한의 도리니 말일세.', 66384),
(304388, 'koKR', '', '하르쿠아이는 비밀과 신화의 마을이지. 주르아샤르가 기억을 보존하고, 장로들이 전통을 지키지만, 우리 흐느끼는 뿌리는 아직 완전히 이해하지 못한 여신의 피조물에 가장 자주 경의를 표하네.', 66384),
(304387, 'koKR', '빛만개의 새순이 아무리 제거해도 계속 자라나고 있다.\n\n이 알른나방들을 데려가라. 특이한 생리 구조와 왕성한 식욕 덕분에, 새순이 더 자라기 전에 갉아먹을 수 있을 거다.\n\n다만 나방들이 먹고 나면 약간의 부작용이 있을지도 모른다. 그래도 너라면 잘 버틸 테니까.', '빛만개의 새순이 아무리 제거해도 계속 자라나고 있다.\n\n이 알른나방들을 데려가라. 특이한 생리 구조와 왕성한 식욕 덕분에, 새순이 더 자라기 전에 갉아먹을 수 있을 거다.\n\n다만 나방들이 먹고 나면 약간의 부작용이 있을지도 모른다. 그래도 너라면 잘 버틸 테니까.', 66384),
(304375, 'koKR', '한창 들떠 있던 케탄의 표정이 급격히 엄중하게 굳어집니다.', '한창 들떠 있던 케탄의 표정이 급격히 엄중하게 굳어집니다.', 66384),
(304373, 'koKR', '라두니가 죽었다. 우리가 해냈어! 야수를 쓰러뜨렸어!', '라두니가 죽었다. 우리가 해냈어! 야수를 쓰러뜨렸어!', 66384),
(304372, 'koKR', '', '금방, 조용히 끝낼 수 있을 거라 생각했지. 멀록은 완전히 다른 계획이 있었던 모양이야.', 66384),
(304342, 'koKR', '우리한테도 무서울 때 강해지는 법을 가르쳐줬지.', '', 66384),
(304341, 'koKR', '자이니는 $p에게 고마워하고 있어. 무서운 구덩이에서도 강하게 싸우는 법을 가르쳐줬으니까.', '', 66384),
(304339, 'koKR', '웅덩이 근처에 포자활공자가 있어. 가는 길에 싸우면 철퍽하게 만들 수 있을 거야!', '', 66384),
(304338, 'koKR', '이봐, 웅덩이로 돌아갈래? 따뜻하고 기분 좋아. 축축해!', '', 66384),
(304337, 'koKR', '', '포식의 군단이 이 지역 동물을 포획해서 개조하고 있어요. 아마 적에게 풀어놓으려는 속심이겠죠. 조심해야 합니다.', 66384),
(304336, 'koKR', '진균수호자라. 이보다 더 좋은 이름은 없지, $p!', '', 66384),
(304335, 'koKR', '포자신도도 좋은 이름이야. 덕분에 더 열심히 할 수 있겠어. 이제 진짜로 맹세했으니까.', '', 66384),
(304334, 'koKR', '고리갓이 정답이었지. 우리 중 가장 멋진 부분이 갓이잖아!', '', 66384),
(304332, 'koKR', '다음엔 꼭 제대로 고르자. 이름 정하기가 쉽지 않아.', '', 66384),
(304331, 'koKR', '우린 포자에서 태어나 서로에게 맹세했지. 그래서 최고의 조야!', '', 66384),
(304330, 'koKR', '고리갓이라는 이름은 브라코의 갓에서 땄어. 멋지지?', '', 66384),
(304328, 'koKR', '', '가서 뵙겠습니다, $n 님.', 66384),
(304324, 'koKR', '작은 숲포복자가 뿌리 아래에서 울부짖습니다.', '작은 숲포복자가 뿌리 아래에서 울부짖습니다.', 66384),
(304302, 'koKR', '<용액을 섞자 거품이 부글거리는 혼합물이 만들어집니다. 강하게 들러붙는 물질도 녹일 수 있을 것 같습니다.>', '<용액을 섞자 거품이 부글거리는 혼합물이 만들어집니다. 강하게 들러붙는 물질도 녹일 수 있을 것 같습니다.>', 66384),
(304301, 'koKR', '<용액을 섞자 빠르게 증발해 버리고는 아무 흔적도 남지 않습니다.>', '<용액을 섞자 빠르게 증발해 버리고는 아무 흔적도 남지 않습니다.>', 66384),
(304300, 'koKR', '<혼합물이 안정되자, 두 용액이 서로의 효과를 상쇄하며 쓸모없는 갈색 덩어리로 변합니다. 아무 쓸모 없습니다.>', '<혼합물이 안정되자, 두 용액이 서로의 효과를 상쇄하며 쓸모없는 갈색 덩어리로 변합니다. 아무 쓸모 없습니다.>', 66384),
(304283, 'koKR', '고맙습니다, 장로님. 장로님께도, $n에게도 실망을 안겨드리지 않겠습니다.', '고맙습니다, 장로님. 장로님께도, $n에게도 실망을 안겨드리지 않겠습니다.', 66384),
(304277, 'koKR', '<이 꽃병이라면 산성 용액을 담을 수 있을 만큼 튼튼해 보입니다.>', '<이 꽃병이라면 산성 용액을 담을 수 있을 만큼 튼튼해 보입니다.>', 66384),
(304268, 'koKR', '간절히 바라던 걸 눈앞에서 놓쳐본 적 있나? 그것도 내 잘못이 아닌 일로 말이야.\n\n<팔짱을 끼고 한숨을 내쉬는 케탄>\n\n이제 와서 내가 할 수 있는 건 아무것도 없어.', '간절히 바라던 걸 눈앞에서 놓쳐본 적 있나? 그것도 내 잘못이 아닌 일로 말이야.\n\n<팔짱을 끼고 한숨을 내쉬는 케탄>\n\n이제 와서 내가 할 수 있는 건 아무것도 없어.', 66384),
(304266, 'koKR', '반갑다, 이방인. 하라니르라면 카다니의 시련에 대해 들어봤겠지?\n\n<팔짱을 끼고 한숨을 내쉬는 케탄>\n\n이 시련은 하라시르가 카다니라는 정예 사냥꾼 집단에 들어갈 기회를 얻는 자리다. 시련은 한 주기가 돌아올 때마다 한 번 열리고, 참가하려면 자신을 이끌어줄 카다니를 직접 찾아야 하지.\n\n나도 이번 시련에 나설 수 있었는데, 결국 선택받지 못했어. 다음 주기를 기다릴 수밖에 없겠네.', '반갑다, 이방인. 하라니르라면 카다니의 시련에 대해 들어봤겠지?\n\n<팔짱을 끼고 한숨을 내쉬는 케탄>\n\n이 시련은 하라시르가 카다니라는 정예 사냥꾼 집단에 들어갈 기회를 얻는 자리다. 시련은 한 주기가 돌아올 때마다 한 번 열리고, 참가하려면 자신을 이끌어줄 카다니를 직접 찾아야 하지.\n\n나도 이번 시련에 나설 수 있었는데, 결국 선택받지 못했어. 다음 주기를 기다릴 수밖에 없겠네.', 66384),
(304264, 'koKR', '입 밖에 내기보다 속삭이는 게 더 안전한 종류죠.\n\n뭐, 여긴 조용한 곳이에요. 걱정하실 필요 없어요.', '', 66384),
(304261, 'koKR', '시 낭독회에 오신 걸 환영해요, 용사님.\n\n초청한 시인들이 도시 곳곳에서... 마음이 통하는 이들과 시를 나누고 있답니다.\n\n좋은 시 한 편은 많은 생각할 거리를 안겨주니까요. 그렇지 않나요?', '', 66384),
(304260, 'koKR', '이 새싹은 빛이 닿지 않아 자라지 못하고 있습니다.', '이 새싹은 빛이 닿지 않아 자라지 못하고 있습니다.', 66384),
(304258, 'koKR', '어서 오세요. 편하게 구경하세요\n\n 마음에 드시는 게 있으면 포장해 드릴게요.', '', 66384),
(304254, 'koKR', '생전에 우릴 욕되게 했던 자들이지만, 자네의 활약 덕에 언젠가는 명예를 회복할 수 있을지 모르지.', '', 66384),
(304253, 'koKR', '', '동정심은 갖다 버리게, $n.', 66384),
(304252, 'koKR', '여기서 봐도 전세가 다시 우리 쪽으로 기우는 게 보이는군.', '', 66384),
(304251, 'koKR', '', '하! 그 소리를 들으니 전장에 나갔다가 너덜너덜한 채로 끌려오던 자네 꼴이 떠오르는구먼.', 66384),
(304250, 'koKR', '인정하라고, 도루. 이 모든 게 옛날 생각나서 은근히 좋지 않나.', '', 66384),
(304249, 'koKR', '', '돌아왔군. 좋아. 제단도 잘 버티고 있나?', 66384),
(304248, 'koKR', '항상 조심하게, $n. 메아리들은 약하지만, 방심했다간 머릿수로 밀리게 될 걸세.', '', 66384),
(304236, 'koKR', '', '하라니르의 또 다른 전통을 보여주고 싶네. 이쪽일세. 벽화가 그려진 곳으로 가지.', 66384),
(304232, 'koKR', '', '이리 오게, 우리 굴 더 깊은 곳으로 내려가 보세.', 66384),
(304231, 'koKR', '우리 손으로 부수게 해주려나 봐!', '', 66384),
(304230, 'koKR', '', '그럼 그 말씀의 뜻이?', 66384),
(304229, 'koKR', '그럼, 애들아. 너희도 금방 이 기계 전투복의 구조적 안정성을 박살 낼 수 있을 거다!', '', 66384),
(304228, 'koKR', '', '나중에 다시 오겠네! 몬테, 지금은 소굴을 좀 더 보여주고 싶군.', 66384),
(304219, 'koKR', '', '...네, 아빠.', 66384),
(304218, 'koKR', '다음번엔 혼자서 할 거지, 응?', '', 66384),
(304217, 'koKR', '', '아, 안녕하세요! 돌아오셨네요! 다 찾으셨어요?', 66384),
(304216, 'koKR', '안잘리, 어서 안으로 들어오너라! 친절한 $c님이 약초를 가져오셨어.', '', 66384),
(304215, 'koKR', '숙제를 다 끝내기 전엔 안 된다. 배운 걸 보여다오.', '', 66384),
(304214, 'koKR', '', '아빠, 다른 애들이랑 놀고 싶단 말이에요!', 66384),
(304213, 'koKR', '수행사제를 도와주셔서 감사합니다.', '', 66384),
(304212, 'koKR', '힘든 일은 저 토템을 통해 로아께서 하실 걸세. 자네는 그분들의 힘을 전달하기만 하면 돼.', '', 66384),
(304211, 'koKR', '아킬존. 승리의 로아. 하늘과 바람, 비와 천둥의 군주!', '', 66384),
(304210, 'koKR', '할라지. 사냥의 로아. 민첩하고, 교활하고, 인내심이 많지. 어떤 땅에서든, 어떤 먹잇감이든 완벽한 사냥꾼이다.', '', 66384),
(304209, 'koKR', '', '잔알라이. 불의 로아. 마법과 모든 생명 안의 불꽃을 다스린다.', 66384),
(304208, 'koKR', '', '날로라크. 전쟁의 로아. 완고하고 용서 없지만, 신도들에게는 사납게 충성하지.', 66384),
(304207, 'koKR', '붓질할 때마다 목적과 희망이 담기고... 네가 나눈 것도 녹아나거든.', '', 66384),
(304206, 'koKR', '너 없이는 해낼 수 없었을 거야. 네 배려 덕분에 다시 나 자신을 찾았어.', '', 66384),
(304200, 'koKR', '네가 도와주면 이 재료들이 다시 생명을 불어넣을 거야... 파멸을 초래한 나와 다르게.', '', 66384),
(304199, 'koKR', '신뢰라, 참 어려운 문제인데... 넌 나한테 진솔한 아량을 베풀었으니까.', '', 66384),
(304197, 'koKR', '난 모두를 실망시켰어. 무엇보다 나 자신을. 그런데 네가 나서서 중심을 잡아줬지. 고마워.', '', 66384),
(304195, 'koKR', '', '우릴 찾아와 줘서 고마워.\n\n재미있는 이야기야. 내가 다른 공허 교란 사례를 조사하던 중에 저 생물을 데려갔는데, 그 덕에 다른 이들도 관심을 가지고 나타났지! 다들 꽤나 호기심이 많은 모양이야.\n\n혹은 악의가 있을지도 모르지. 서로 잡아먹고 싶어서 그런 걸 수도... 그 부분은 아직 조사 중이야.\n\n퇴마 사업으로 돈 좀 벌 수 있을지도 모르겠어. 원래 목적은 공부였지만 말이지.\n\n조만간 이 생물들을 모아 진열할 수 있을 만큼 수집이 쌓일 거야. 보관할 장소도 마련해야겠군!', 66384),
(304191, 'koKR', '', '난 온갖 이상한 공허 현상을 조사하고 있어. 수수께끼는 언제나 환영이지.', 66384),
(304159, 'koKR', '안잘리, 잠깐! 그건 네가 직접 해야지! ...또 이러면 안 되는데.', '', 66384),
(304150, 'koKR', '', '마을 주변에서 약초를 찾을 수 있어요! 알겠죠? 그럼 안녕!', 66384),
(304143, 'koKR', '', '준비되면 도전하도록.', 66384),
(304110, 'koKR', '$n, 이쪽이오.', '', 66384),
(304060, 'koKR', '', '내가 가보겠네. 자네는 임하요에게 가서, 나후트가 고블린보다 더 끌릴 만한 걸 갖고 있는지 알아보게.', 66384),
(304059, 'koKR', '이상하군! 당최 무슨 얘기인지 하나도 모르겠어.', '', 66384),
(304058, 'koKR', '쿠르드란, 저기 $p|1이;가; 오고 있네. 그런데 저 도끼들은 뭐지?', '', 66384),
(304056, 'koKR', '<판자와 밧줄로 엮인 이 묶음은 깨진엄니의 게 통발이 부서진 잔해로 보입니다.\n\n거대한 발톱 자국이 여기저기 새겨져 있고, 일부러 부순 듯 거칠게 산산이 부서져 있습니다. 또, 나무에는 부서진 공허 유물의 파편이 박혀 있습니다.\n\n강을 따라 떠내려오며 뒤섞인 것처럼 보이지만, 물살이 오염을 씻어내진 못했습니다. 나무는 완전히 공허의 기운에 잠식되어 있고, 표면은 검게 변색되어 있습니다.>', '', 66384),
(304047, 'koKR', '<게 사체들이 땅에 흩어져 있습니다. 몇몇은 다리가 뜯겨 나갔고, 다른 것들은 거대한 턱이나 발톱 같은 것에 으깨져 있습니다.\n\n상처에서 공허 유물의 파편이 보입니다. 또, 시체 주변에도 공허의 기운이 맥동하고 있습니다.>', '', 66384),
(304005, 'koKR', '', '덫은 버틸 거다.', 66384),
(304002, 'koKR', '', '가자, 징크스. 여길 빠져나가야 해!', 66384),
(304001, 'koKR', '<이 도마뱀은 바위에 머리를 맞아 함몰됐습니다.>', '<이 도마뱀은 바위에 머리를 맞아 함몰됐습니다.>', 66384),
(304000, 'koKR', '그림자소나무 사람들이 대표로서 아마니와의 회담에 나가달라고 부탁하긴 했습니다만, 그렇다고 스스로 지도자라고 생각하진 않습니다.', '', 66384),
(303999, 'koKR', '', '알아!', 66384),
(303997, 'koKR', '<과거의 메아리를 통해 이 모루를 사용할 수 있습니다.>', '<과거의 메아리를 통해 이 모루를 사용할 수 있습니다.>', 66384),
(303996, 'koKR', '', '우와, 정말 용감한데!', 66384),
(303994, 'koKR', '', '이 큰 바위로 눈을 정통으로 내리쳤지!', 66384),
(303993, 'koKR', '으아!', '', 66384),
(303990, 'koKR', '', '이렇게요. 쾅!', 66384),
(303989, 'koKR', '', '그래서 그다음에 어떻게 했어, 아니?', 66384),
(303988, 'koKR', '', '그러더니 갑자기 저한테 뛰어드는 거 있지!', 66384),
(303986, 'koKR', '', '그 어떤 마른나무껍질도 잊히게 하지 않겠다! 마이사라 동굴에서 만나지.', 66384),
(303974, 'koKR', '이 메아리들은 어린 카파라만큼 약하구먼! 전사들이 실력을 갈고닦기에 딱 좋은 기회야!', '', 66384),
(303973, 'koKR', '보급은 고맙게 받겠네. 안 그래도 전사들이 독수리를 보호하다 심각한 부상을 입었거든.', '', 66384),
(303972, 'koKR', '도루와 반백이 어떤 소식을 보냈나?', '', 66384),
(303970, 'koKR', '끝없이 몰려오는 적이라? 하하! 단련할 기회로 더없이 좋군!', '', 66384),
(303969, 'koKR', '', '이번 사냥은 역사와 맞붙는 싸움이네. 함께할 텐가, 하쉬우라?', 66384),
(303968, 'koKR', '', '도루는 늘 절묘하구먼. 주술사들의 보급품이 바닥날 참이었어.', 66384),
(303966, 'koKR', '', '고맙네, 하쉬우라. 도루에게도 감사 인사를 전해주게.', 66384),
(303963, 'koKR', '', '불꽃이 인사하네, 하쉬우라.', 66384),
(303954, 'koKR', '절... 막으셔야 합니다.', '', 66384),
(303925, 'koKR', '내 딸은 약초학과 조제에 천부적인 재능이 있지만, 집중력이 부족하지. 목숨이 오갈 때 주의가 산만해지면 안 되잖나.\n\n이 정신 나간 세상에서는 언젠가 그런 상황이 올지도 모른단 말일세.\n\n자식에게 너무 엄하게 굴고 싶진 않지만... 꼭 익혀야 하는 기술이네. 우리가 만드는 연고와 물약은 사람들을 보호하고, 목숨을 구하니까.', '', 66384),
(303923, 'koKR', '제가 바란 건 단 하나였습니다. 고향을 지킬 힘.\n\n덤으로 멋진 창 하나쯤 더 생기면 좋겠지요.', '', 66384),
(303911, 'koKR', '', '연금술사가 되면 재미있을 줄 알았어요. 식물을 돌보는 건 좋아하니까요.\n\n그런데 생각보다 일이 많네요.', 66384),
(303910, 'koKR', '늙은이도 로아 전령의 가르침에서 배울 점은 많습니다.\n\n저는 이제 못 싸우지만, 로아와 가까이할 방법은 여전히 있습니다.', '', 66384),
(303904, 'koKR', '', '처음엔 다르락의 열정이 걱정됐네. 지나치게 의욕적인 전사들은 대개 무모하고, 훌륭한 전사가 되는 데 꼭 필요한 절제가 결핍되어 있거든.\n\n하지만 그 녀석은 날 깜짝 놀라게 했어. 늘 가장 먼저 도착하고, 가장 늦게까지 남더군. 질문도 제대로 하고, 내 다른 제자들보다 훨씬 열심히 수련했지.\n\n제자 중 누가 내 존경을 받을 만하냐고? 다르락일세. 나도 이 말 하고 있는 게 좀 놀라워.', 66384),
(303902, 'koKR', '', '뭔가 심상치 않아.', 66384),
(303901, 'koKR', '', '블러드 엘프랑은 말 안 해요, 고킨예. 저리 가요.', 66384),
(303898, 'koKR', '', '황혼의 칼날단 보셨어요? 흥, 저한테는 안 될걸요. 더 무서운 녀석들도 봤어요. 블러드 엘프랑은 비교도 안 돼요.\n\n아빠가 저한테 도끼 쓰는 법을 가르쳐 주셨거든요. 아마니 영토를 뺏으려는 사람 있으면 다 베어버릴 거예요!', 66384),
(303897, 'koKR', '', '자꾸 꿈에서 뱀으로 변해요. 전 뱀 싫은데... 이제 밤에 잠드는 게 무서워요.', 66384),
(303895, 'koKR', '', '혹부리나무족을 봤어요! 강 근처 마을 지나가던데, 오빠는 거짓말하지 말래요. 진짜로 봤는데!', 66384),
(303893, 'koKR', '', '항상 그렇게 입고 다녀요? 장화 같은 건 안 신어요? 전 장화가 좀 웃긴 것 같아요.', 66384),
(303892, 'koKR', '', '새가 제 활을 훔쳐 갔어요! 엄마 싸움 도와주고 싶어서 연습하려고 했는데... 엄마가 빨리 돌아오게 하고 싶어요. 보고 싶어요!', 66384),
(303891, 'koKR', '', '우아아악! 놀랐어요? 아빠가 내가 날로라크랑 비슷한 소리 낸대요!', 66384),
(303890, 'koKR', '', '아빠가 나중에 큰 잔치가 열린대요! 당신도 올 거예요? 애들이 먼저 먹는데, 당신은 다음 차례예요.', 66384),
(303887, 'koKR', '', '마을에 아마니가 너무 많아서 여동생이랑 침대를 같이 써야 해요. 으으!', 66384),
(303885, 'koKR', '', '엄마가 고킨예랑 말하지 말랬어요. 미안해요.', 66384),
(303870, 'koKR', '', '물러서요!', 66384),
(303869, 'koKR', '', '뭘 기다리는 거예요? 어서 가요!\n\n<아나이스의 발밑이 피로 흠뻑 물들어 있습니다. 출혈을 막으려는 시도는 아무런 효과가 없습니다.>\n\n저나 용사님이나 더 할 수 있는 건 없습니다. 성스러운 빛이라고 모든 걸 치유할 수 있는 건 아니니까요.', 66384),
(303860, 'koKR', '', '제가 어떻게 하는지 보여드릴게요. 그다음엔 용사님 차례예요!', 66384),
(303856, 'koKR', '', '안녕하세요! 음식 가져오셨어요?\n\n배고파요.', 66384),
(303852, 'koKR', '이미 연금술이나 주문각인에 능숙한 분이라면, 기본 조제법은 어려움 없이 다룰 수 있을 거예요.\n\n직접 해보며 배우는 게 가장 좋습니다. 어서 작업대 앞으로 가 보세요!', '', 66384),
(303851, 'koKR', '우선 차원문을 통해 오그리마로 돌아가세요. 골목길 2층에 가면 칼보다 강한 펜이라는 상점이 있습니다. 그곳의 전문가들이 주문각인사의 길을 걷는 데 필요한 도움을 줄 거예요.\n\n혹시 찾기 어려우면 경비병에게 부탁해서 지도에 표시해 달라고 하세요.', '', 66384),
(303846, 'koKR', '잘했다. 네가 싸우는 걸 보면 늘 짜릿하더군.\n\n그 친구 일은 안타깝게 됐어. 빛의 족속은 왜 그리 쉽게 목숨을 내던질까?', '', 66384),
(303844, 'koKR', '빛의 족속과 끝없는 공허의 무리의 대결이라... 구경거리로는 꽤 괜찮겠는걸.', '', 66384),
(303837, 'koKR', '', '기초는 제가 가르쳐드릴 수 있어요. 이 염료 작업대를 다루기에 충분할 정도로요. 그 이상은 어렵습니다. 진정한 연금술사가 되고 싶다면 스톰윈드로 가야 해요. 우선 차원문을 통해 스톰윈드로 이동하세요. 마법사의 성소 바로 동쪽에 연금술의 모든 것이라는 상점이 있습니다. 그곳의 전문가들은 저보다 훨씬 깊이 있는 연금술 지식을 가지고 있을 거예요.\n\n혹시 찾기 어려우면 경비병에게 부탁해서 지도에 표시해 달라고 하세요.', 66384),
(303836, 'koKR', '', '기초는 제가 가르쳐드릴 수 있어요. 이 염료 작업대를 다루기에 충분할 정도로요. 그 이상은 어렵습니다. 진정한 주문각인사가 되고 싶다면, 스톰윈드로 가셔야 합니다. 우선 차원문을 통해 스톰윈드로 이동하세요. 지하감옥 맞은편 교역소 근처에 스톰윈드 각인소라는 상점이 있을 거예요. 그곳의 전문가들이 제게 배울 수 있는 것보다 훨씬 더 많은 걸 가르쳐 줄 겁니다.\n\n혹시 찾기 어려우면 경비병에게 부탁해서 지도에 표시해 달라고 하세요.', 66384),
(303825, 'koKR', '', '어둠수호병을 처리하는 거라면 문제없어. 시체에 표시를 하면 어떻게 되는지 지켜봐.', 66384),
(303823, 'koKR', '<이 시체는 빛만개 포자로 뒤덮여 있습니다.>', '<이 시체는 빛만개 포자로 뒤덮여 있습니다.>', 66384),
(303816, 'koKR', '자격을 증명하려면, 로아의 성역에 있는 위대한 옛 전사들이 잠든 안식처에서 각각 징표 네 개를 가져와야 합니다.', '자격을 증명하려면, 로아의 성역에 있는 위대한 옛 전사들이 잠든 안식처에서 각각 징표 네 개를 가져와야 합니다.', 66384),
(303814, 'koKR', '<사냥꾼의 영혼이 고개를 숙여 존경의 뜻을 보입니다. 사냥꾼은 다음 사냥을 완벽히 준비하고 있으며, 그것은 인생이라는 위대한 여정에 또 하나의 발자취가 될 것입니다.>', '<사냥꾼의 영혼이 고개를 숙여 존경의 뜻을 보입니다. 사냥꾼은 다음 사냥을 완벽히 준비하고 있으며, 그것은 인생이라는 위대한 여정에 또 하나의 발자취가 될 것입니다.>', 66384),
(303813, 'koKR', '<어린아이 같은 영혼이 마치 오랜 잠에서 막 깨어난 듯 몸을 길게 기지개 켭니다. 천천히 눈을 깜빡이며 주위를 둘러보던 영혼은 자신이 어디에 있는지 몰라 잠시 머뭇거리다가, 당신을 발견하자 환한 미소를 짓습니다.>', '<어린아이 같은 영혼이 마치 오랜 잠에서 막 깨어난 듯 몸을 길게 기지개 켭니다. 천천히 눈을 깜빡이며 주위를 둘러보던 영혼은 자신이 어디에 있는지 몰라 잠시 머뭇거리다가, 당신을 발견하자 환한 미소를 짓습니다.>', 66384),
(303812, 'koKR', '나루를 잃다니!', '', 66384),
(303811, 'koKR', '게다가 야수가 풀려났잖습니까!', '', 66384),
(303788, 'koKR', '환생이 찾아오리라.', '환생이 찾아오리라.', 66384),
(303787, 'koKR', '죽음에 이르노니.', '죽음에 이르노니.', 66384),
(303786, 'koKR', '생명에서 출발하여.', '생명에서 출발하여.', 66384),
(303785, 'koKR', '여신을 이해하기 위함이라.', '여신을 이해하기 위함이라.', 66384),
(303784, 'koKR', '여정이 시작되었으니.', '여정이 시작되었으니.', 66384),
(303783, 'koKR', '시작은 미약했도다.', '시작은 미약했도다.', 66384),
(303775, 'koKR', '철사덫 제어판 주변에서 비전 마력이 진동하고 있습니다.\n\n안타깝게도, 이 장치의 세부 구조는 당신에게 익숙하지 않습니다.', '철사덫 제어판 주변에서 비전 마력이 진동하고 있습니다.\n\n안타깝게도, 이 장치의 세부 구조는 당신에게 익숙하지 않습니다.', 66384),
(303774, 'koKR', '철사덫 제어판 주변에서 비전 마력이 진동하고 있습니다.', '철사덫 제어판 주변에서 비전 마력이 진동하고 있습니다.', 66384),
(303773, 'koKR', '', '그렇 그렇지.', 66384),
(303772, 'koKR', '', '발리라가 한숨을 내쉽니다.', 66384),
(303770, 'koKR', '반갑네, 젊은 친구. 야수를 맡기러 왔나? 아니면 잃어버린 친구를 찾나?', '반갑네, 젊은 친구. 야수를 맡기러 왔나? 아니면 잃어버린 친구를 찾나?', 66384),
(303769, 'koKR', '반갑네, 젊은 친구. 잃어버린 친구를 찾는 데 도움이 필요한가?', '반갑네, 젊은 친구. 잃어버린 친구를 찾는 데 도움이 필요한가?', 66384),
(303767, 'koKR', '거 말인데, 옛날에 토르톨란 배 한 척이 여기서 실종됐단 말이지. 잘하면 우리 유물을 낚을 수도 있을 거야!', '거 말인데, 옛날에 토르톨란 배 한 척이 여기서 실종됐단 말이지. 잘하면 우리 유물을 낚을 수도 있을 거야!', 66384),
(303766, 'koKR', '아. 반갑네, 여행자여. 조촐하긴 하지만 쉬고 싶으면 얼마든지 그렇게 하게나.\n\n나는 발견을 정리하느라 시간이 없거든!', '아. 반갑네, 여행자여. 조촐하긴 하지만 쉬고 싶으면 얼마든지 그렇게 하게나.\n\n나는 발견을 정리하느라 시간이 없거든!', 66384),
(303764, 'koKR', '당신은 커서 뭐가 되고 싶어요? 전 마른나무껍질이 좋아요. 나중에 그 사람들처럼 큰 엄니를 가질 수 있을지도 모르잖아요!', '', 66384),
(303763, 'koKR', '스테기를 쫓는 건 너무 힘들어요! 당신은 다리가 길잖아요. 대신 쫓아가 줄 수 있나요? 전 너무 피곤해요!', '', 66384),
(303762, 'koKR', '야, 나 바빠! 점박이가 마을에서 숨기 좋은 데 알려달라고 해서 말이야. 딴 사람 귀찮게 해!', '야, 나 바빠! 점박이가 마을에서 숨기 좋은 데 알려달라고 해서 말이야. 딴 사람 귀찮게 해!', 66384),
(303761, 'koKR', '내 낚싯줄이랑 엉키지 마, 고킨예! 형보다 더 많이 잡아야 한단 말이야!', '내 낚싯줄이랑 엉키지 마, 고킨예! 형보다 더 많이 잡아야 한단 말이야!', 66384),
(303760, 'koKR', '젤 이모가 나랑 나라한테는 작살 낚시 금지라고 하셨거든! 근데 물고기 백 마리 잡으면, 그때 알려주신댔어!', '젤 이모가 나랑 나라한테는 작살 낚시 금지라고 하셨거든! 근데 물고기 백 마리 잡으면, 그때 알려주신댔어!', 66384),
(303756, 'koKR', '도와주십시오! 핀리가 납치당했습니다!', '', 66384),
(303754, 'koKR', '똑똑히 봐라...', '', 66384),
(303751, 'koKR', '어서 놔줘!', '', 66384),
(303750, 'koKR', '동료들이 도망치면 우승자가 될 수 없어. 중요한 규칙이지.', '', 66384),
(303749, 'koKR', '도망치는 건 초보나 하는 실수다, $p.', '', 66384),
(303747, 'koKR', '이름 정했어, $p? 어떤 걸로 할래?', '', 66384),
(303746, 'koKR', '$p! 단체 이름을 정해야 해. 이름 없이 구덩이에 못 나가!', '', 66384),
(303745, 'koKR', '버섯전사에게 $r의 능력을 보여줘라. 강하다는 걸 보여줘.', '', 66384),
(303744, 'koKR', '응어리의 구덩이로 가라, $p.', '', 66384),
(303743, 'koKR', '장로 영혼이 둥글게 말아놓은 베개를 제단에 놓습니다.', '장로 영혼이 둥글게 말아놓은 베개를 제단에 놓습니다.', 66384),
(303742, 'koKR', '인간이라, 너무 평범한데. 요즘은 이런 것들만 보게 되는구먼.', '', 66384),
(303741, 'koKR', '지켜보겠다.', '', 66384),
(303740, 'koKR', '오호라! 수집품으로 삼기 딱 좋은 흥미로운 표본이군.', '', 66384),
(303739, 'koKR', '사냥꾼 영혼이 칼을 제단에 내려놓습니다.', '사냥꾼 영혼이 칼을 제단에 내려놓습니다.', 66384),
(303738, 'koKR', '어린아이 영혼이 공을 제단에 놓습니다.', '어린아이 영혼이 공을 제단에 놓습니다.', 66384),
(303737, 'koKR', '공허첨탑의 힘이 퍼져 나가리라!', '', 66384),
(303727, 'koKR', '<따뜻한 모닥불가에 앉은 사냥꾼의 환영이 마음속에 떠오릅니다. 곁에는 사냥에서 얻은 가죽과 뼈, 그리고 여러 자원이 가지런히 쌓여 있습니다. 사냥꾼은 몸을 기대어 쉬며, 가끔 불 위의 커다란 고깃덩이를 천천히 돌립니다. 오늘의 사냥은 분명 성공이었습니다.>', '<따뜻한 모닥불가에 앉은 사냥꾼의 환영이 마음속에 떠오릅니다. 곁에는 사냥에서 얻은 가죽과 뼈, 그리고 여러 자원이 가지런히 쌓여 있습니다. 사냥꾼은 몸을 기대어 쉬며, 가끔 불 위의 커다란 고깃덩이를 천천히 돌립니다. 오늘의 사냥은 분명 성공이었습니다.>', 66384),
(303726, 'koKR', '<당신의 환영은 눈부신 빛으로 시작됩니다. 곧 깊은 잠에 빠진 아이의 모습이 마음속에 그려집니다. 곁에는 너덜너덜한 공이 놓여 있고, 아이는 피곤에 지쳐 잠들었지만 얼굴에는 여전히 미소가 남아 있습니다. 공을 가지고 놀다 잠든 아이의 표정에는 행복과 평온이 깃들어 있습니다.>', '<당신의 환영은 눈부신 빛으로 시작됩니다. 곧 깊은 잠에 빠진 아이의 모습이 마음속에 그려집니다. 곁에는 너덜너덜한 공이 놓여 있고, 아이는 피곤에 지쳐 잠들었지만 얼굴에는 여전히 미소가 남아 있습니다. 공을 가지고 놀다 잠든 아이의 표정에는 행복과 평온이 깃들어 있습니다.>', 66384),
(303725, 'koKR', '', '썩어 문드러지게 둘 순 없지.', 66384),
(303710, 'koKR', '무슨 일이 있었는지 알려 주십시오.', '무슨 일이 있었는지 알려 주십시오.', 66384),
(303709, 'koKR', '놈이 핀리 므르글턴 경을 납치했습니다!\n\n구해줘야 합니다!', '', 66384),
(303708, 'koKR', '', '가만히 잡고 있어요! 다시 해볼게요.', 66384),
(303707, 'koKR', '<어둠접목이 야수의 가죽에 융합되어 있습니다. 임페리아는 이 야수를 완전히 통제해, 자신의 오락거리로 삼았을 것입니다.\n\n아나이스가 이 어둠의 금속을 제거하려 시도한 흔적이 보이지만, 야수는 그 과정을 버텨내지 못했습니다.>', '<어둠접목이 야수의 가죽에 융합되어 있습니다. 임페리아는 이 야수를 완전히 통제해, 자신의 오락거리로 삼았을 것입니다.\n\n아나이스가 이 어둠의 금속을 제거하려 시도한 흔적이 보이지만, 야수는 그 과정을 버텨내지 못했습니다.>', 66384),
(303702, 'koKR', '잡담할 시간 없네. 뭘 원하나?', '잡담할 시간 없네. 뭘 원하나?', 66384),
(303701, 'koKR', '가죽을 벗기는 데 능숙하지 않으면, 자네가 벗겨질 걸세, 고킨예.', '가죽을 벗기는 데 능숙하지 않으면, 자네가 벗겨질 걸세, 고킨예.', 66384),
(303699, 'koKR', '완벽한 사냥이란 마음가짐과 기술이 하나가 되는 순간을 말하지. 사냥꾼은 언제나 차분하고 집중해야 해. 무기는 그저 도구가 아니라, 자기 몸의 연장선이어야 하지. 사냥감이 더 이상 주변의 자연과 사냥꾼을 구분하지 못할 때를 완벽한 사냥이라고 한다.\n\n즉 자기 자신의 한계를 넘어야 해. 그래야만 진정으로 사냥의 영혼에게 축복을 받을 수 있지.', '완벽한 사냥이란 마음가짐과 기술이 하나가 되는 순간을 말하지. 사냥꾼은 언제나 차분하고 집중해야 해. 무기는 그저 도구가 아니라, 자기 몸의 연장선이어야 하지. 사냥감이 더 이상 주변의 자연과 사냥꾼을 구분하지 못할 때를 완벽한 사냥이라고 한다.\n\n즉 자기 자신의 한계를 넘어야 해. 그래야만 진정으로 사냥의 영혼에게 축복을 받을 수 있지.', 66384),
(303697, 'koKR', '플릭스가 텃세하는 떠돌이에게 쫓기고 있습니다!', '', 66384),
(303696, 'koKR', '성난 덩굴손이 날라를 잡아먹으려 합니다!', '', 66384),
(303695, 'koKR', '기회주의적인 숲포복자가 트옴을 공격하고 있습니다!', '', 66384),
(303692, 'koKR', '불퉁이가 텃세하는 떠돌이의 존재에 분노하고 있습니다.', '', 66384),
(303649, 'koKR', '', '알고 있어요. 크아레쉬에서 있었던 일 이후로...\n\n공간 방랑자가 잘아타스와 협력하자고 설득했지만, 전 공허의 괴물을 믿는다는 그 말 하나하나에 반대했어요.\n\n그리고 그게 옳았을까요? 공간 방랑자는 이제 없습니다. 다만 우리가 잘아타스와 협력하지 않았다면, 디멘시우스가 모든 걸 삼켜버렸을 거예요. 아니면... 다른 길을 찾을 수도 있었을까요?\n\n처음부터 공간 방랑자를 믿었다면, 그의 죽음을 막을 수 있었을까요?\n\n이 혹한 속에서 밤을 보낼 때마다, 잠들지 못하고 그 질문만 되뇌었어요.\n\n전 공간 방랑자에게 당신은 더 이상 제 스승이 아니라고 했습니다. 근데 거짓말이었어요. 지금 이곳에서... 다시 한번 그 사람의 가르침을 받아들이려 합니다.\n\n공허의 피조물은 단 하나의 목표만을 가지고 있죠. 생존입니다. 그리고 그 지식을 우리의 무기로 삼을 수 있을 거예요.', 66384),
(303647, 'koKR', '데솔름이 오염의 주된 근원이었어요. 도시 근처는 나아졌지만 남쪽은 오랫동안 방치됐습니다. 이제야 원정순찰대가 다시 순찰할 수 있게 되었죠.\n\n그래서 부정한 마법이 여전히 흙에 스며들었고, 흔적이 식물에까지 남아 자라납니다. 동물들이 그 식물을 먹고, 오염은 조금씩 농축되지요.\n\n그리고 그 동물들이 또 다른 동물을 먹게 되면... 어떤 결과가 되는지 짐작하실 수 있을 거예요.', '', 66384),
(303645, 'koKR', '이런 투박한 일들이야말로 원정순찰대의 본분이죠! 전 절대 물러서지 않아요.', '', 66384),
(303644, 'koKR', '정말 다양하죠!\n\n약초와 잎채소가 가장 먼저 돋고, 그다음엔 열매 덤불과 견과를 맺는 나무들이 자라납니다. 이들이 흙 위에 그늘을 드리우면, 뿌리 밑에서 버섯이 피어나죠. 하지만 그건 시작일 뿐이에요!\n\n덤불은 토끼와 새들의 보금자리가 되고, 그들을 먹는 스라소니와 매타조는 씨앗을 멀리 퍼뜨립니다. 모든 게 순환이에요. 우리가 먹으면, 모두가 함께 살아가는 거죠.', '', 66384),
(303611, 'koKR', '', '더 많은 크아레쉬인을 구하고, 서약을 지켜 나갈 수 있을지도 몰라.', 66384),
(303610, 'koKR', '', '맞아, 키판. 서약을 지켜줘서 고마워.', 66384),
(303609, 'koKR', '', '좋아요. 네가 말한 그 저항자들에게 데려가 줘.', 66384),
(303608, 'koKR', '', '선택...', 66384),
(303607, 'koKR', '네 힘은 눈부시게 타올랐어. 아직도 맞서 싸우는 이들이 있잖아. 살아가기를 선택해. 내가 보여줄게!', '', 66384),
(303606, 'koKR', '베란, 제발! 도관을 다루는 방법은 드자르의 시체와 함께 묻어버려. 이렇게 할 필요 없잖아!', '', 66384),
(303605, 'koKR', '', '내면에 타오르는 불길에 집중해. 도관을 찢어버려!', 66384),
(303604, 'koKR', '$n 님, 가세요! 저희는 피해 있겠습니다!', '', 66384),
(303603, 'koKR', '지금까지 어둠을 잘 억눌러왔잖아! 이제 와서 목숨까지 내던지지 마... 제발...', '', 66384),
(303602, 'koKR', '', '지금까지 인도해 줘서 고마워, 키판. 근데 이젠 헤어져야 해.', 66384),
(303601, 'koKR', '', '느껴져요... 언제라도 터질 것 같은...', 66384),
(303595, 'koKR', '그럼 전... 빗자루에 마법이나 부여하러 가야겠네요.', '', 66384),
(303594, 'koKR', '', '미리 연락을 드렸어야 했는데, 보시다시피 지금 일손이 너무 부족합니다.', 66384),
(303593, 'koKR', '가자, 곰들아! 원정순찰대를 위하여!', '', 66384),
(303573, 'koKR', '<이 통통한 새끼 히드라는 가까운 덤불 아래 어두운 곳에 시선을 고정하고 있습니다. 가까이 다가가자 쉭쉭 소리를 내며 건드리지 말라는 신호를 보냅니다.>', '<이 통통한 새끼 히드라는 가까운 덤불 아래 어두운 곳에 시선을 고정하고 있습니다. 가까이 다가가자 쉭쉭 소리를 내며 건드리지 말라는 신호를 보냅니다.>', 66384),
(303572, 'koKR', '<이 새끼 히드라는 머리를 높이 치켜들고 있습니다. 세 개의 머리가 당신을 위아래로 훑어보더니, 비웃듯 코로 짧게 콧김을 뿜습니다. 그러고는 지루해졌는지 시선을 들어 요람 쪽을 바라보며, 마치 여신이 자신에게 강림해 주길 기다리는 듯한 모습을 보입니다.>', '<이 새끼 히드라는 머리를 높이 치켜들고 있습니다. 세 개의 머리가 당신을 위아래로 훑어보더니, 비웃듯 코로 짧게 콧김을 뿜습니다. 그러고는 지루해졌는지 시선을 들어 요람 쪽을 바라보며, 마치 여신이 자신에게 강림해 주길 기다리는 듯한 모습을 보입니다.>', 66384),
(303571, 'koKR', '<새끼 히드라가 금세 잠듭니다. 처음에는 울음소리 같았는데, 듣고 보니 커다란 코골이 소리였습니다.>', '<새끼 히드라가 금세 잠듭니다. 처음에는 울음소리 같았는데, 듣고 보니 커다란 코골이 소리였습니다.>', 66384),
(303570, 'koKR', '<이 새끼 히드라는 가만히 있지를 못합니다. 들려오는 소리, 땅의 미세한 떨림, 스치는 냄새까지 궁금한 모양입니다.>', '<이 새끼 히드라는 가만히 있지를 못합니다. 들려오는 소리, 땅의 미세한 떨림, 스치는 냄새까지 궁금한 모양입니다.>', 66384),
(303568, 'koKR', '꽃봉오리는 네 개만 있으면 된다. 히드라 한 마리당 하나씩. 아니, 열둘이라고 해야 하나. 머리를 어떻게 세느냐에 따라 달라지니까.', '꽃봉오리는 네 개만 있으면 된다. 히드라 한 마리당 하나씩. 아니, 열둘이라고 해야 하나. 머리를 어떻게 세느냐에 따라 달라지니까.', 66384),
(303567, 'koKR', '놀란 눈치로군! 하지만 알았으면 좋겠어... 녀석들 안에는, 그러니까... 깊은 곳에는 우리가 모르는 면이 있지. 본디 다정하고 충직한 야수들이야. 물론 아침에 어떻게 깨느냐에 따라 달라지긴 하지만 말이지. 대부분은 그냥 위험한 야수로만 취급받아.\n\n하지만 녀석들은 더 나은 대우를 받아야 해. 그리고 본래의 터전으로 돌아갈 자격이 있어.', '놀란 눈치로군! 하지만 알았으면 좋겠어... 녀석들 안에는, 그러니까... 깊은 곳에는 우리가 모르는 면이 있지. 본디 다정하고 충직한 야수들이야. 물론 아침에 어떻게 깨느냐에 따라 달라지긴 하지만 말이지. 대부분은 그냥 위험한 야수로만 취급받아.\n\n하지만 녀석들은 더 나은 대우를 받아야 해. 그리고 본래의 터전으로 돌아갈 자격이 있어.', 66384),
(303565, 'koKR', '정말 고맙다. 네가 큰 도움이 됐어.\n\n이 위엄 넘치는 야수들이 다시 돌아오면 지역 생태계가 다시 조화를 이룰 거다.\n\n내 아름다운 새끼 히드라들도 어렵지 않게 적응할 테지. 히드라는 강인하고 영리하거든. 예전의 개체수를 회복하는 건 시간문제야.', '정말 고맙다. 네가 큰 도움이 됐어.\n\n이 위엄 넘치는 야수들이 다시 돌아오면 지역 생태계가 다시 조화를 이룰 거다.\n\n내 아름다운 새끼 히드라들도 어렵지 않게 적응할 테지. 히드라는 강인하고 영리하거든. 예전의 개체수를 회복하는 건 시간문제야.', 66384),
(303564, 'koKR', '반갑다, 이방인. 내가 이렇게 아름다운 식물 히드라들에 둘러싸여 있는 이유가 궁금하겠군.내 이름은 네이타르라고 한다. 이 근처 폭포들을 지키는 수호자로서 일하고 있지.\n\n혹시 이 주변에서 히드라를 못 봤나? 인정하기는 어렵지만, 난초 히드라가 사라진 건 내 책임이다. 사냥과 관리 소홀로 개체 수가 크게 줄어들고 말았어.\n\n그래서 그 잘못을 바로잡고자, 장엄한 난초 히드라를 다시 놀드랏실의 뿌리 폭포에 들여놓으려고 하는 거다.', '반갑다, 이방인. 내가 이렇게 아름다운 식물 히드라들에 둘러싸여 있는 이유가 궁금하겠군.내 이름은 네이타르라고 한다. 이 근처 폭포들을 지키는 수호자로서 일하고 있지.\n\n혹시 이 주변에서 히드라를 못 봤나? 인정하기는 어렵지만, 난초 히드라가 사라진 건 내 책임이다. 사냥과 관리 소홀로 개체 수가 크게 줄어들고 말았어.\n\n그래서 그 잘못을 바로잡고자, 장엄한 난초 히드라를 다시 놀드랏실의 뿌리 폭포에 들여놓으려고 하는 거다.', 66384),
(303562, 'koKR', '전투 경험이 있는 전쟁 마법사들과 마법학자들은 모두 최전선으로 파견됐고, 나머지는 실버문이나 이곳으로 피신했어요.\n\n저는 공명 비전 이론이 전공이지, 다른 세계에서 온 야수들한테 불덩이를 던지는 법은 배우지 않았거든요.', '전투 경험이 있는 전쟁 마법사들과 마법학자들은 모두 최전선으로 파견됐고, 나머지는 실버문이나 이곳으로 피신했어요.\n\n저는 공명 비전 이론이 전공이지, 다른 세계에서 온 야수들한테 불덩이를 던지는 법은 배우지 않았거든요.', 66384),
(303553, 'koKR', '전 여길 정리하겠습니다. 당신은 남쪽 탑으로 먼저 가서 태민에게 도움이 필요한지 확인해 보세요.', '전 여길 정리하겠습니다. 당신은 남쪽 탑으로 먼저 가서 태민에게 도움이 필요한지 확인해 보세요.', 66384),
(303550, 'koKR', '', '우린 동물의 모든 부위를 요리하지.\n\n멧돼지 심장 먹어본 적 있나? 어릴 때 들은 말인데, 그렇게 질긴 걸 먹으면 멧돼지의 힘이 생긴다나 뭐라나.\n\n진짜인지는 모르겠지만, 맛은 끝내 줘.', 66384),
(303549, 'koKR', '', '허물 벗기 때문이에요! 마나 지룡은 일 년에 몇 번씩 허물을 벗습니다. 충분히 마나를 흡수하면 낡은 껍질을 벗고 새로운 외피를 만들어내죠.\n\n벗겨진 껍질은 서서히 사라지면서 비전 마력을 숲 전역으로 흩뿌리고, 결국 그 마력은 지맥으로 되돌아갑니다. 영원노래 숲 생태계의 중요한 순환 과정이에요!\n\n하지만 지금처럼 혼란으로 마나의 흐름이 막히면, 원정순찰대가 나서야 합니다.', 66384),
(303541, 'koKR', '', '마나 지룡의 개체 수가 예상보다 훨씬 많네요.\n\n빛만개가 녀석들의 이주 경로에 영향을 주고 있는 걸까요? 우리가 와서 다행이에요. 평소보다 훨씬 많은 도움이 필요할지도 모르겠어요.', 66384),
(303539, 'koKR', '', '남쪽 탑의 태민도 우리가 여기서 거둔 것만큼 좋은 결과를 내고 있기를 바랄 뿐이에요.', 66384),
(303538, 'koKR', '', '발사린이 일을 끝냈는지 궁금하네요. 북쪽 탑에도 한 번 들러보세요.', 66384),
(303537, 'koKR', '', '이번엔 정말 큰 변화를 만들어낸 것 같습니다!', 66384),
(303532, 'koKR', '남쪽 탑의 태민이 무사히 잘하고 있어야 할 텐데요.', '', 66384),
(303530, 'koKR', '아스타레이도 아직 도움이 필요할 겁니다. 저는 여기서 마무리할 테니 중앙 탑에 들러보세요.', '', 66384),
(303529, 'koKR', '정말 훌륭한 성과였다고 생각합니다!', '', 66384),
(303523, 'koKR', '구덩이에서 싸우는 거 봤다. 저번에는 잘했다.\n\n하지만 응어리의 구덩이는 위험한 곳이야! 죽지 마라, $p!\n\n그래서 모타는 안전한 곳에만 머무르지.', '', 66384),
(303515, 'koKR', '아마 죽겠지. 그래도 모타는 널 응원하겠다. 그럼 안 죽을 수도 있지!', '', 66384),
(303514, 'koKR', '반갑다, $p. 응어리의 구덩이에서 네가 싸우는 모습을 지켜보마.', '', 66384),
(303505, 'koKR', '난 가족의 노래를 만들고 싶다. 내 마음에서, 어릴 적 우리를 돌보며 어머니가 우리에게 바랐던 선율로 시작하는 거다.\n\n그리고 나중에는 내가 어머니를 돌보던 시절의 선율로 이어질 거다. 이 길을 걸으면서 난 내 노래와 우리 삶을 잇는 실을 떠올리고 있다.', '', 66384),
(303504, 'koKR', '우린 그림자소나무다. 싸움에 휘말리기엔 너무 적어. 생존이 우선이지.', '', 66384),
(303503, 'koKR', '난 야생의 노래를 만들고 싶다. 경이로움의 음도 있어야 하지만, 통제할 수 없음에서 오는 짜릿함도 담아야 해.\n\n길 자체를 품으며, 그 위에서 벌어지는 흥미로운 일들을 모두 담을 거다.', '', 66384),
(303502, 'koKR', '이 숲은 위험으로 가득하다. 길에서 벗어나지 마라.', '', 66384),
(303499, 'koKR', '정말 좋은 이름이야.', '', 66384),
(303495, 'koKR', '$p|1이;가; 광채 경비병을 꺾어서 다들 놀랐어.\n\n광채 경비병은 절대 안 지거든.\n\n$p|1이;가; 동료들을 훈련시키기 전까진 그랬지.\n\n그 후에 진 거고.', '', 66384),
(303494, 'koKR', '물약이 필요한가? 아니면 직접 조제하는 법을 찾으러 왔나?', '물약이 필요한가? 아니면 직접 조제하는 법을 찾으러 왔나?', 66384),
(303493, 'koKR', '먼지가 많더라도 양해해 주세요, $n 님.\n\n이 첨탑을 방어 거점으로 복구하려는 시도는... 그다지 성공적이지 않았습니다.\n\n그래도 계속 나아가고 있지만요.', '', 66384),
(303492, 'koKR', '뿌리와 포자의 지식을 찾는가?', '뿌리와 포자의 지식을 찾는가?', 66384),
(303491, 'koKR', '기억은 중요하지만 과거에만 머물 순 없지. 우린 미래를 위한 노래를 만든다!', '', 66384),
(303489, 'koKR', '난 유산의 노래를 만들고 싶다. 그러려면 우리가 원치 않더라도 과거를 돌아봐야 해. 우리의 승리뿐 아니라, 뒤에 질질 끌고 다니는 실수까지 모두 포함한다.\n\n우리가 떠날 때, 처음 왔을 때보다 이곳을 더 나은 곳으로 만들어두고 가는가를 봐야지.\n\n이 노래는 그런 이야기가 될 거다.', '', 66384),
(303485, 'koKR', '난 슬픔의 노래를 만들고 싶다. 슬픔에 머무르려는 게 아니라, 무감각을 넘는 감정을 느끼기 위해 이 자리에 머무르는 거다.\n\n어쩌면 사랑의 노래일지도 모르지. 슬픔이 그토록 크다는 건, 사랑이 그보다 더 컸다는 뜻이니까.', '', 66384),
(303484, 'koKR', '난 봉우리의 노래를 만들고 싶다. 이 노래는 자신이 뒤처졌다고 느끼는 이들에게 희망을 줘야 해. 자존감 낮은 이들에게도 말이다.\n\n용기를 가진 자에게도 승리가 찾아온다는 걸 알려줄 거다! 난 그 영감을 얻으러 왔다.', '', 66384),
(303477, 'koKR', '이 문양들은 우리 그림과 크게 다르지 않다.\n이리 와라. 깃펜을 잉크에 적시고, 말에 힘을 새기자.', '이 문양들은 우리 그림과 크게 다르지 않다.\n이리 와라. 깃펜을 잉크에 적시고, 말에 힘을 새기자.', 66384),
(303473, 'koKR', '용서해 주세요. 지금은 수평선 너머에서 밀려오는 빛만개의 침공 때문에 정신이 없습니다.\n\n이 망할 피조물만 제대로 작동했다면, 이 전초기지에 방어선을 구축하는 것도 훨씬 쉬웠을 거예요.\n\n하지만 지나간 일을 탓해 봐야 소용없죠. 지금 우리가 할 수 있는 일에 집중하죠.', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(303472, 'koKR', '하필 지금...', '', 66384),
(303471, 'koKR', '적어도 몇 시간은 더 필요합니다, 마법학자님!', '적어도 몇 시간은 더 필요합니다, 마법학자님!', 66384),
(303470, 'koKR', '골렘 수리 작업은 얼마나 진행됐어요?', '', 66384),
(303469, 'koKR', '요원을 하나 제거했어요. 좋아요. 이제 부정한 빗물로 가죠.\n\n이쪽으로 들어갈 수 있어요.', '', 66384),
(303460, 'koKR', '<녹슨 격자가 빛 하나 들지 않는 감방 입구를 덮고 있습니다.\n\n아래에 무엇이 있는지 보이지 않지만, 무언가 꿈틀거리는 소리가 납니다. 쇠사슬이 부딪히는 소리와 축축한 발소리가 어둠에서 울려 퍼집니다.\n\n어딘가 깊은 곳에서 가늘고 굶주린 목소리가 들려옵니다.\n\n고기... 먹여...', '<녹슨 격자가 빛 하나 들지 않는 감방 입구를 덮고 있습니다.\n\n아래에 무엇이 있는지 보이지 않습니다.\n\n어딘가 깊은 곳에서 가늘고 굶주린 목소리가 들려옵니다.>\n\n고기... 먹여...', 66384),
(303459, 'koKR', '우린 그림자소나무다. 이 땅 구석구석, 가장 높은 봉우리에도 흩어져 있지.', '', 66384),
(303458, 'koKR', '너무 많은 이가 계곡을 걷고 있어. 오늘은 노래가 안 떠오르네.', '', 66384),
(303457, 'koKR', '', '꼭 그래야 할 필요는 없잖아요. 재밌는 데 가면 안 돼요?', 66384),
(303456, 'koKR', '이 여정은 목적지에 도달하는 게 끝이 아니란다, 테이사.', '', 66384),
(303455, 'koKR', '', '갈 길이 너무 멀어요, 아버지. 바다는 지루하단 말이에요.', 66384),
(303454, 'koKR', '알았어, 알았어. 지금 마음 다잡는 중이야!', '', 66384),
(303453, 'koKR', '', '지난번엔 내가 불붙였잖아. 이번엔 네 차례야.', 66384),
(303449, 'koKR', '', '아직 멀었나?', 66384),
(303448, 'koKR', '아버지께서 여긴 신성한 곳이라고 하셨어. 조용히 해야 해!', '', 66384),
(303446, 'koKR', '그림자소나무는 정착지가 없다. 우리는 떠돌며 가는 길 위에 삶의 터전을 만들지.', '', 66384),
(303443, 'koKR', '', '원정순찰대는 크든 작든 모든 위협으로부터 영원노래 숲을 지키기 위해 존재합니다. 그리고 큰 위협이 있다고 해서 작은 문제가 사라지는 건 아닙니다.\n\n그런 점을 이해하는 태민에게 저는 한 번 걸어봤습니다. 다소 낭만적인 생각을 가지고 있긴 하지만요.', 66384),
(303437, 'koKR', '$p|1이;가; 툭툭을 다시 데려왔어.\n\n툭툭이 설득당했지. 져도 $p하고 계속 친구로 남을 거라고.\n\n응어리의 구덩이에서 다시 보자!', '', 66384),
(303436, 'koKR', '브라코는 포자활공자가 무서웠어. $p|1이;가; 도와줘서 싸울 수 있게 됐어!', '', 66384),
(303431, 'koKR', '자이니는 폐 끼칠까 봐 겁났는데, $p하고 훈련하면서 용기가 생겼어!', '', 66384),
(303428, 'koKR', '지더라도 계속 함께 훈련하는 친구일 거야!', '', 66384),
(303427, 'koKR', '우리가 이기면 브라코는 계속 툭툭의 친구로 남을 거야!', '', 66384),
(303426, 'koKR', '이제 조금만 더 축축해지면 돼.', '', 66384),
(303420, 'koKR', '응어리의 구덩이는 무서워. 웅덩이는 따뜻하고 안전해.', '', 66384),
(303419, 'koKR', '$p? 왜 여기 있어? 툭툭은 그만뒀어.', '', 66384),
(303415, 'koKR', '보렐투스는 이길 거라 생각 안 했어.\n\n기분 나쁘진 않아.\n\n하지만 구덩이에서 도망치면 안 되는데, 동료들이 도망쳤잖아.\n\n그래서 $p|1이;가; 진 거야.', '', 66384),
(303414, 'koKR', '버섯 폭포가 새로운 바람총꾼을 영입하길 바라지.', '', 66384),
(303413, 'koKR', '그게 이름으로는 최고였는데.', '', 66384),
(303412, 'koKR', '진균수호자가 새로운 바람총꾼을 영입하길 바라지.', '', 66384),
(303411, 'koKR', '포자신도가 새로운 바람총꾼을 영입하길 바라지.', '', 66384),
(303375, 'koKR', '죄송합니다, 대장님! $n 님에게 도서관을 보여주다 또 얘기가 옆으로 샜습니다.', '', 66384),
(303368, 'koKR', '', '저에게 무슨 일이 있었냐고요? 뻔한 일 아닌가요. 전 죽었답니다.\n\n배신자 왕자와의 전쟁에서 수많은 원정순찰대원이 쓰러졌죠. 그 뒤에도 스컬지 잔당으로부터 고향을 지키느라 더 많은 이가 목숨을 잃었습니다. 어떤 이는 죽음이라는 자비를 받았고, 어떤 이는... 그조차 허락받지 못했죠.\n\n탈란드라는 원래 마법학자였어요. 하지만 지금은 남은 우리들의 고통을 덜어주기 위해 훨씬 금기된 기술을 탐구하고 있고요.', 66384),
(303364, 'koKR', '', '오? 모험가께서 하찮은 밴시에게 말을 걸어주실 줄이야. 탈란드라가 당신을 마음에 들어 한 이유를 알겠네요.', 66384),
(303350, 'koKR', '이 순찰자 일을 같이 익혀 나가요!', '', 66384),
(303346, 'koKR', '<플릭스의 머리들이 서로 으르렁거림과 낮은 울음소리, 목 끓는 소리로 이루어진 깊은 대화를 나누고 있습니다.\n\n당신의 기척을 느낀 난초 히드라가 타액이 질질 흐르는 혓바닥을 내밉니다. 당신을 봐서 기쁜 건지, 배가 고픈 건지 모르겠습니다.>', '<플릭스의 머리들이 서로 으르렁거림과 낮은 울음소리, 목 끓는 소리로 이루어진 깊은 대화를 나누고 있습니다.\n\n당신의 기척을 느낀 난초 히드라가 타액이 질질 흐르는 혓바닥을 내밉니다. 당신을 봐서 기쁜 건지, 배가 고픈 건지 모르겠습니다.>', 66384),
(303342, 'koKR', '<난초 히드라가 코를 골며 자고 있습니다. 식물 히드라치고도 더 통통해 보입니다. 트옴이 푸드덕거리며 머리 하나를 들어 당신 주변 냄새를 맡아보지만, 곧 다시 잠들어 버립니다.>', '<난초 히드라가 코를 골며 자고 있습니다. 식물 히드라치고도 더 통통해 보입니다. 트옴이 푸드덕거리며 머리 하나를 들어 당신 주변 냄새를 맡아보지만, 곧 다시 잠들어 버립니다.>', 66384),
(303341, 'koKR', '', '편지는 빈껍데기가 아니었어. 줄아만으로 통하는 지도가 담겨 있었지.', 66384),
(303339, 'koKR', '<당신이 다가가자, 야수가 몸을 돌리며 세 개의 머리로 먹잇감을 노리듯 응시합니다. 불퉁이가 쉭쉭거리며 불만을 토해냅니다.\n\n느닷없는 방문을 어떻게 받아들이는지는 알 수 없습니다.>', '<당신이 다가가자, 야수가 몸을 돌리며 세 개의 머리로 먹잇감을 노리듯 응시합니다. 불퉁이가 쉭쉭거리며 불만을 토해냅니다.\n\n느닷없는 방문을 어떻게 받아들이는지는 알 수 없습니다.>', 66384),
(303336, 'koKR', '<난초 히드라가 당신을 알아봅니다. 몸을 곧게 세운 채, 여러 머리가 당신을 내려다봅니다. 가운데 머리가 주변의 공기를 맡더니 당신의 어깨를 가볍게 건드립니다.>', '<난초 히드라가 당신을 알아봅니다. 몸을 곧게 세운 채, 여러 머리가 당신을 내려다봅니다. 가운데 머리가 주변의 공기를 맡더니 당신의 어깨를 가볍게 건드립니다.>', 66384),
(303335, 'koKR', '물론입니다!\n\n저는 각 룬석에 적합한 비전 수정이 제대로 전달되도록 물류를 책임지는... 매우 중요한, 그리고... 유쾌한 임무를 맡고 있습니다.\n\n하지만 빛만개로 인해 각 거점에 부하가 걸리면서, 보급품이 점점 바닥나고 있어요. 그런데도 그 빌어먹을 마법학자들은 여전히...\n\n<코를 움켜쥐며 인상을 찌푸리다가 다시 침착을 되찾는 테렐>\n\n푸념은 무시해 주세요. 업무의 부담감을 견디는 제 방식일 뿐이거든요.', '', 66384),
(303334, 'koKR', '이래서는... 연결이 끊어진다!', '', 66384),
(303333, 'koKR', '잠깐, 이런. 연결이...', '', 66384),
(303332, 'koKR', '', '목걸이가... 날 악몽에서 깨웠어. 하지만, 내 안에는 아직 공허가 타올라. 우리랑 있으면 위험해!', 66384),
(303329, 'koKR', '보이나? 마법이...', '', 66384),
(303327, 'koKR', '하필이면 지금 룬석 수정 공급에 문제가 생기다니! 바보 같은 마법학자들은 대체 뭘 하고 있는 거야?\n\n결국 책임은 늘 테렐에게 돌아오고...\n\n어머! 죄송합니다. 얼마나 오래 서 계셨나요?', '', 66384),
(303326, 'koKR', '베란... 목걸이를 회수했을 때, 너였던 거 알아. 자...', '', 66384),
(303324, 'koKR', '', '조심하세요. 귀한 물건이거니와, 인화성이 꽤 강해요. 뭐, 불타는 색이 참 예쁘긴 하지만요.', 66384),
(303323, 'koKR', '네이타르가 깊은 생각에 잠깁니다.', '네이타르가 깊은 생각에 잠깁니다.', 66384),
(303322, 'koKR', '어린 녀석들이 사라지니 너무 적적해. 떠돌이라도 하나 들일까 생각 중이다.', '어린 녀석들이 사라지니 너무 적적해. 떠돌이라도 하나 들일까 생각 중이다.', 66384),
(303321, 'koKR', '부탁이니 어린 녀석들을 잘 지켜다오.', '부탁이니 어린 녀석들을 잘 지켜다오.', 66384),
(303320, 'koKR', '밀폐된 곳에서는 절대 열지 마세요. 죽은 자도 깨울 정도로 독한 연기거든요.', '', 66384),
(303318, 'koKR', '툭툭은 어릴 때 항상 마지막으로 뽑혔어.\n\n뽑아줘서 고마워.\n\n구덩이에서 툭툭이 $p의 선택이 옳았다는 걸 보여줄게.', '', 66384),
(303317, 'koKR', '자이니는 우리가 구덩이에서 잘하길 바라!\n\n구덩이는 위험해, 강한 버섯전사가 많거든.\n\n그래서 $p 곁에 있을 거야.', '', 66384),
(303315, 'koKR', '어린 개체들은 어떻지? 잘 있나?', '어린 개체들은 어떻지? 잘 있나?', 66384),
(303313, 'koKR', '브라코는 응어리의 구덩이에 나가는 게 너무 신난다!\n\n$p, 자이니, 툭툭을 지켜줄 거야.', '', 66384),
(303312, 'koKR', '저 에테리얼들이 어둠수호병에게 반란을 일으켰다고 해도, 여전히 공허가 몸에 흐르고 있어요.\n\n그리고 베란은... 절 쳐다보려 하지도 않네요...', '', 66384),
(303311, 'koKR', '정말 감사합니다.', '', 66384),
(303310, 'koKR', '당신의 용기와 흔들림 없는 의지가 영원노래 숲을 또다시 지켜낸 겁니다.', '', 66384),
(303309, 'koKR', '내가 생각한 이름이 맞아. 진균수호자. 너희 둘은 딴소리하잖아!', '', 66384),
(303308, 'koKR', '$p... 우리 도움이 필요해. 다들 조 이름을 바꾸고 싶어 해!', '', 66384),
(303307, 'koKR', '둘 다 이름이 틀렸잖아.', '', 66384),
(303306, 'koKR', '잠깐, 뭐야?', '', 66384),
(303282, 'koKR', '솔직히 말해 보세요. 제대로 알고 한 건가요, 아니면 그냥 도구를 들이대고 아무쪼록 잘되길 바란 건가요?', '', 66384),
(303280, 'koKR', '', '놀랍군요. 뭘 어떻게 하셨는지 몰라도 효과가 있었던 것 같습니다. 이 특이점은 당분간 안정된 상태를 유지할 겁니다.\n\n용사님이 나서주셔서 다행입니다. 라이시카스가 도구를 들었으면 지금 이렇게 얘기도 못 하고 있었을 거예요.', 66384),
(303279, 'koKR', '솔직히 처음 봤을 때보다 훨씬 더... 활발해진 것 같네요. 이 정도면 좀 허둥지둥할 만하네.', '', 66384),
(303278, 'koKR', '', '이 특이점은 이미 스스로 붕괴를 시작했어요. 사전 경고 같은 건 없을 거예요. 대피를 명령할 수도 있지만...\n\n<눈을 가늘게 뜨고 렌도레이 병력을 머릿속으로 계산하는 마엘라>\n\n아니, 너무 오래 걸리겠네요. 그러면 전력이 그대로 폭발에 휘말려요. 당신, 나, 라이시카스. 우리가 처리해야 해요. 지금요.', 66384),
(303277, 'koKR', '마엘라 눈을 피해 몰래 빠져나갈 수 있을 거라 생각한 게 잘못이었네요. 확실해지기 전까지는 누구도 걱정시키고 싶지 않았는데. 성채 하부에 불안정한 특이점이 하나 더 있는 것 같아요.', '', 66384),
(303266, 'koKR', '', '라이시카스, 어디로 가는 겁니까?', 66384),
(303265, 'koKR', '도랑을 따라 이동하면서 노출된 목표를 제압한 뒤, 아래에서 성채를 치죠.', '', 66384),
(303264, 'koKR', '시기를 잘 맞춰 오셨네요. 공격 중간에 정찰을 좀 다녀왔는데, 이 특이점을 뛰어넘는 걱정거리가 생긴 것 같아요. 적진 배후로 잠입하는 것 정도는 괜찮죠?\n\n어차피 여기서 보초를 서든 잠입을 하든 위험한 건 매한가지잖아요. 마엘라야 적을 직접 마주하는 걸 좋아하겠지만, 전 조준경 너머로만 보고 싶거든요.', '', 66384),
(303263, 'koKR', '', '라이시카스... 계속 정찰하십시오. 단, 다음에 위험한 걸 발견하면 기다리지 말고 바로 말해야 합니다.', 66384),
(303262, 'koKR', '', '특이점 고정기를 지키는 데 $p 님이 힘을 보태 주신다면 환영입니다.', 66384),
(303246, 'koKR', '', '지금은 괜찮습니다. 하지만 상부 성채에도 특이점이 남아 있습니다.', 66384),
(303245, 'koKR', '안정적인 것... 같은데요?', '', 66384),
(303242, 'koKR', '갓 부수기는 이긴다. 연습을 제일 많이 했으니까.\n\n그리고 조언도 제일 많이 하지.\n\n\"칼 피해!\", \"칼로 쳐!\" 서로 외치면서 함께 훈련하거든.', '', 66384),
(303241, 'koKR', '건드리지 마. 집중해야 해.\n\n조언을 크게 외쳐야 하거든.\n\n소리치지 않고 어떻게 나아지겠어?', '', 66384),
(303231, 'koKR', '최악의 상황이 닥쳐서... 베란이 어둠수호병에게 완전히 사로잡힌 건 아닐까 걱정했어요.\n\n그런데, 아직 희망이 남아 있을지도 모르겠군요...', '', 66384),
(303230, 'koKR', '새 방패는 부서지지 않아!\n\n여러 번 시험해 봤어.\n\n갓 부수기가 충분히 모이면 이길 거야.', '', 66384),
(303200, 'koKR', '부식수렁은 포자 폭풍이야. 자유 따윈 원하지 않아.\n\n게다가 부식수렁 주위엔 울타리도 있잖아.\n\n바보 같은 질문이야, $r.', '', 66384),
(303198, 'koKR', '부식수렁 봤어?\n\n부식수렁이 준비되면, 포자 폭풍이 다 이길 거야.\n\n광채 경비병조차 상대가 안 되지.\n\n지금은 싸움을 가르치고, 먹여서 키우는 중이야.\n\n그러면... 응어리의 구덩이에서 이기게 된다.\n\n아무도 부식수렁을 막지 못해.', '', 66384),
(303196, 'koKR', '바람총을 다 만들고 나면 버섯의 힘이 무조건 응어리의 구덩이에서 이길 거야.\n\n더 멀리 쏠 수 있지.\n\n더 곧게 날아가.\n\n더 많은 화살을 담을 수 있고 말이야.\n\n우린 반드시 이겨.', '', 66384),
(303185, 'koKR', '이동한다!', '', 66384),
(303184, 'koKR', '다들 명령 들었겠지!', '', 66384),
(303183, 'koKR', '바로 당신...', '', 66384),
(303182, 'koKR', '전 마침내 갈망하던 걸 손에 넣었습니다.', '', 66384),
(303181, 'koKR', '그 긴 세월을 어머니 홀로...', '', 66384),
(303180, 'koKR', '전 이 어둠이 감히 건드리지 못할 무언가를 갖고 있으니까요...', '', 66384),
(303179, 'koKR', '그런 일은 없을 겁니다.', '', 66384),
(303178, 'koKR', '', '나 역시 그러하니.', 66384),
(303177, 'koKR', '', '마음 단단히 먹거라...', 66384),
(303176, 'koKR', '', '네가 이곳의 끔찍한 괴물들과 싸우며 몸도 마음도 피폐해지진 않을까 걱정했다.', 66384),
(303175, 'koKR', '어머니, 전...', '', 66384),
(303174, 'koKR', '', '장성한 네 모습을, 내가 얼마나 대견하게 생각하는지.', 66384),
(303173, 'koKR', '', '부디 알아다오...', 66384),
(303172, 'koKR', '', '너는 내 보물이란다, 아라토르.', 66384),
(303171, 'koKR', '역시 될 줄 알았어.', '', 66384),
(303170, 'koKR', '나는 약속은 지킨다, 필멸자.', '', 66384),
(303169, 'koKR', '이제 약속을 지켜...', '', 66384),
(303168, 'koKR', '수정탑 연결망을 불안정하게 만들었다, 데시무스.', '', 66384),
(303144, 'koKR', '지금 당장은 데려올 수 없지만, 우리가 있는 위치를 알릴 수 있도록 신호기를 설치할 수 있을 겁니다.', '', 66384),
(303143, 'koKR', '미안. 최고의 독은 버섯의 힘 전용이야.\n\n구덩이에서 이기려면 필요하거든.\n\n나눠줄 수도 없고, 살 수도 없어.', '', 66384),
(303142, 'koKR', '그동안 내게 베풀어준 모든 은혜에 감사를 표한다, $n. 사냥의 행운이 언제나 함께하길 바라지.', '그동안 내게 베풀어준 모든 은혜에 감사를 표한다, $n. 사냥의 행운이 언제나 함께하길 바라지.', 66384),
(303141, 'koKR', '사냥에 나서라, 카다니 케탄. 앞으로의 사냥에 여신의 인도가 함께하길 기원하마.', '사냥에 나서라, 카다니 케탄. 앞으로의 사냥에 여신의 인도가 함께하길 기원하마.', 66384),
(303140, 'koKR', '케탄, 네 뜻과 열정, 그리고 끈기가 너를 이 자리까지 이끌었다.', '케탄, 네 뜻과 열정, 그리고 끈기가 너를 이 자리까지 이끌었다.', 66384),
(303139, 'koKR', '$n, 이제 넌 카다니의 일원이다. 앞으로의 사냥에 여신의 인도가 함께하길 기원하마.', '$n, 이제 넌 카다니의 일원이다. 앞으로의 사냥에 여신의 인도가 함께하길 기원하마.', 66384),
(303134, 'koKR', '', '가능한 한 빨리 목적지에서 만나요, $n 님.', 66384),
(303130, 'koKR', '', '나루가 공허에 맞서기 위해 일리단을 영입하려 했다? 흥미롭군요.', 66384),
(303127, 'koKR', '', '좋아요. 해독제를 써보고 효과가 있는지 확인해 주세요.', 66384),
(303122, 'koKR', '$n 님, 진심으로 감사드립니다. 당신이 함께한다면 아스트레가 동족과 충돌하는 일은 없으리라 확신합니다.', '', 66384),
(303120, 'koKR', '절 믿으세요. 저도 제가 틀렸으면 하는데, 우리가 그렇게 운이 좋을 것 같진 않네요. 앞장서시죠.', '', 66384),
(303119, 'koKR', '', '이동하죠. 어디 그 직감이 시간 낭비인 걸로 드러나기만 해봐요.', 66384),
(303118, 'koKR', '카다니는 정예 사냥꾼 집단이야. 사냥과 먹잇감에 있어 완벽을 추구하지. 수는 많지 않지만, 우리 하라시르 사람들 사이에서 명성이 자자해. 물론 술카가 그 위에 있긴 하지만, 보는 관점에 따라 악명일 수도 있으니까.\n\n가장 뛰어난 카다니만이 다른 이를 가르칠 수 있고, 여러 번의 사냥철이 지나야 한 번 있을까 말까 한 일이야. 하라시르의 사냥꾼이라면 누구나 카다니가 되기를 꿈꾸지.', '카다니는 정예 사냥꾼 집단이야. 사냥과 먹잇감에 있어 완벽을 추구하지. 수는 많지 않지만, 우리 하라시르 사람들 사이에서 명성이 자자해. 물론 술카가 그 위에 있긴 하지만, 보는 관점에 따라 악명일 수도 있으니까.\n\n가장 뛰어난 카다니만이 다른 이를 가르칠 수 있고, 여러 번의 사냥철이 지나야 한 번 있을까 말까 한 일이야. 하라시르의 사냥꾼이라면 누구나 카다니가 되기를 꿈꾸지.', 66384),
(303116, 'koKR', '저 능선 위에서 기어다니는 놈은 누구냐? 감히 내 복수를 막을 수는 없다!', '', 66384),
(303114, 'koKR', '제 말도 들어 주세요. 몇 시간 전까지만 해도 훨씬 작았거든요.', '', 66384),
(303113, 'koKR', '', '이걸 보고도 보고할 생각을 안 했습니까?', 66384),
(303108, 'koKR', '', '위협이 있다면 먼저 알리십시오. 단순한 직감만으로 임무 지역을 이탈해선 안 됩니다.', 66384),
(303106, 'koKR', '혼란을 피하는 게 좋을 거라 판단했어요.', '', 66384),
(303056, 'koKR', '케탄이 아니라, 카다니 케탄으로서 아카지 장로께 돌아가겠다.', '케탄이 아니라, 카다니 케탄으로서 아카지 장로께 돌아가겠다.', 66384),
(303052, 'koKR', '나도 카다니가 될 수 있다는 걸 증명할 차례다.', '나도 카다니가 될 수 있다는 걸 증명할 차례다.', 66384),
(303050, 'koKR', '<커다란 진홍빛 수정이 손끝에 닿자 따뜻합니다. 표면에서는 힘이 느껴집니다. 수정이 당신 앞에 떠올라, 기대와 허기가 뒤섞인 듯한 기운을 내뿜습니다.>', '<커다란 진홍빛 수정이 손끝에 닿자 따뜻합니다. 표면에서는 힘이 느껴집니다. 수정이 당신 앞에 떠올라, 기대와 허기가 뒤섞인 듯한 기운을 내뿜습니다.>', 66384),
(303048, 'koKR', '라두니는 하라시르 외곽을 떠도는 가장 위험한 야수 중 하나로 유명하지.\n\n두렵진 않다. 다만 경외할 뿐.\n\n<당신을 바라보며 고개를 끄덕이는 케탄>\n\n준비되면 말해라, $n. 스승인 네가 사냥을 시작해야 한다. 난 그 뒤를 따르겠다.', '라두니는 하라시르 외곽을 떠도는 가장 위험한 야수 중 하나로 유명하지.\n\n두렵진 않다. 다만 경외할 뿐.\n\n<당신을 바라보며 고개를 끄덕이는 케탄>\n\n준비되면 말해라, $n. 스승인 네가 사냥을 시작해야 한다. 난 그 뒤를 따르겠다.', 66384),
(303047, 'koKR', '', '황혼의 칼날단은 목숨 하나하나 죗값을 치를 겁니다.', 66384),
(303040, 'koKR', '', '영구적인 건... 안 되고요. 성기사들의 위치를 알아내야 해요.', 66384),
(303039, 'koKR', '', '사람들이 어디 있는지 말해라, 쓰레기 이교도 자식! 험한 꼴 보고 싶어?!', 66384),
(303035, 'koKR', '', '<하늘에서 무언가 움직이는 것을 바라보며 음료를 한 모금 마시는 트라야니스>\n\n시간 문제야... 반드시 널 잡을 거야.', 66384),
(303022, 'koKR', '가만히 찢겨 죽어라.', '', 66384),
(303021, 'koKR', '네 고통을 보며 즐거워하는 걸 보아라!', '', 66384),
(303020, 'koKR', '오늘 애완동물들의 기운이 넘치는군.', '', 66384),
(303011, 'koKR', '네놈들은 절대 이곳에서 나가지 못한다.', '', 66384),
(303004, 'koKR', '와라, 그리고 삼켜지거라.', '', 66384),
(303003, 'koKR', '나는 전령이요, 너는 만찬이다.', '', 66384),
(302997, 'koKR', '라두니에 대한 이야기는 들었다. 그래도 명예롭게 임무를 받아들이겠다!', '라두니에 대한 이야기는 들었다. 그래도 명예롭게 임무를 받아들이겠다!', 66384),
(302996, 'koKR', '넌 거대한 라두니를 사냥해야 한다. 이 시련을 끝내면, 너도 진정한 카다니로 인정받겠지.', '넌 거대한 라두니를 사냥해야 한다. 이 시련을 끝내면, 너도 진정한 카다니로 인정받겠지.', 66384),
(302995, 'koKR', '케탄, 카다니는 사냥감을 두려워하지 않는다. 하지만 오늘 네 상대는 두려워할 만한 놈이지.', '케탄, 카다니는 사냥감을 두려워하지 않는다. 하지만 오늘 네 상대는 두려워할 만한 놈이지.', 66384),
(302963, 'koKR', '', '락툴은 부서졌다. 네가 풀어준 자들은 살아 있고, 길 잃은 자들은 평온을 찾았다. 이 동굴도 당분간은 잠잠하겠지.', 66384),
