(296295, 'koKR', '', '슬픔...', 66384),
(296294, 'koKR', '', '이 고통을... 받아라!', 66384),
(296293, 'koKR', '', '여기서 도망쳐라!', 66384),
(296292, 'koKR', '내 분노는 무한하다!', '', 66384),
(296291, 'koKR', '뼈를 으스려뜨려 주마!', '', 66384),
(296288, 'koKR', '파멸!', '', 66384),
(296287, 'koKR', '찢어 주마!', '', 66384),
(296286, 'koKR', '쳐라!', '', 66384),
(296285, 'koKR', '내게로!', '', 66384),
(296284, 'koKR', '똑바로 서라!', '', 66384),
(296283, 'koKR', '저리 비켜!', '', 66384),
(296282, 'koKR', '내 도끼를 받아라!', '', 66384),
(296281, 'koKR', '내 검을 받아라!', '', 66384),
(296279, 'koKR', '죽어라, 약골!', '', 66384),
(296278, 'koKR', '명예도 모르는... 쓰레기...', '', 66384),
(296275, 'koKR', '시간만 낭비했군.', '', 66384),
(296274, 'koKR', '고개를 처박아라!', '', 66384),
(296273, 'koKR', '직접 콧대를 꺾어주지!', '', 66384),
(296272, 'koKR', '윈드러너! 죗값을 치러라!', '', 66384),
(296269, 'koKR', '메스꺼워...', '', 66384),
(296268, 'koKR', '내장걸쇠 속이 이상해...', '', 66384),
(296267, 'koKR', '놀자!', '', 66384),
(296266, 'koKR', '잡았다!', '', 66384),
(296265, 'koKR', '이런.', '', 66384),
(296264, 'koKR', '어이쿠!', '', 66384),
(296262, 'koKR', '이리 와!', '', 66384),
(296261, 'koKR', '내장걸쇠가... 미안해...', '', 66384),
(296259, 'koKR', '다 죽었어?', '', 66384),
(296258, 'koKR', '아야.', '', 66384),
(296257, 'koKR', '잘 가.', '', 66384),
(296255, 'koKR', '', '어둠은 사라지지 않는다!', 66384),
(296254, 'koKR', '', '어둠이 내려온다!', 66384),
(296251, 'koKR', '', '대체 무슨 짓을 한 거냐!', 66384),
(296250, 'koKR', '', '멍청하긴!', 66384),
(296249, 'koKR', '', '정신을 꿰뚫어 주마!', 66384),
(296247, 'koKR', '', '여왕님... 저희가... 실패했습니다...', 66384),
(296246, 'koKR', '', '여왕님의 성소는 순수하다.', 66384),
(296245, 'koKR', '', '네놈은 자격이 없다.', 66384),
(296244, 'koKR', '', '비극적인 최후로다.', 66384),
(296242, 'koKR', '', '여왕님의 전당을 더럽히지 마라!', 66384),
(296241, 'koKR', '', '감히 여왕님의 성소를 더럽혀? 썩 꺼져라!', 66384),
(296236, 'koKR', '겉보기에는 심각하진 않은데... 저희가 신경 쓸 곳이 너무 많다 보니 여기가 이렇게 된 겁니다.\n\n<한숨을 내쉬는 대장 던러너>\n\n그래도 원정순찰대 초소는 저희를 대표하는 얼굴입니다. 최소한 깔끔하게는 관리해야죠.', '', 66384),
(296235, 'koKR', '잠깐만요. 또 그 이상한 마법이에요!', '', 66384),
(296234, 'koKR', '조금은 더... 영웅적인 걸 기대했는데.', '', 66384),
(296230, 'koKR', '', '오늘 훌륭한 일을 해냈네요. 이 결과가 태민의 기대에 부응했으면 합니다.', 66384),
(296229, 'koKR', '언제까지 로아를 기다릴 순 없었어. 내 손으로라도 결단을 내리게 할 수밖에!', '', 66384),
(296228, 'koKR', '나한테 도전하겠다고? 하! 네놈 힘으론 내 방벽조차 깨뜨리지 못한다!', '', 66384),
(296227, 'koKR', '너희 발버둥은... 보는 재미는 있군. 그래도 잘아타스 님의 영광을 위해 죽게 될 거다!', '', 66384),
(296226, 'koKR', '오라! 내 하수인은 고깃덩이일 뿐이다. 마음껏 썰어봐라!', '', 66384),
(296225, 'koKR', '', '하! 도망쳐라, 병아리들아! 진정한 불꽃의 힘 앞에선 눈도 못 마주치겠지!', 66384),
(296224, 'koKR', '', '와라, 하쉬우라! 네 안의 불꽃을 놈들에게 보여줘라!', 66384),
(296223, 'koKR', '이 공허에 취한 잡종들만큼 재밌는 장난감이 없거든!', '', 66384),
(296222, 'koKR', '반갑다, 작은 하쉬우라여. 우리와 어울리러 왔느냐?', '', 66384),
(296221, 'koKR', '', '훌륭하군. 이제 우리의 발톱이 저 약한 몸뚱이를 찢어발길 수 있겠구나.', 66384),
(296220, 'koKR', '', '내 바람이 황혼의 칼날단을 쓸어버릴 거다. 도관을 파괴해라!', 66384),
(296219, 'koKR', '진짜 아마니처럼 싸우는군, 하쉬우라!', '', 66384),
(296218, 'koKR', '드디어 전투에 끼는 건가? 내가 가르쳐준 걸 적들한테 보여줘라!', '', 66384),
(296196, 'koKR', '어이! 자네 지금 무슨 생각 하는지 다 알지.\n\n그래, 난 덫에 걸렸네. 이 상황에 대해선 더는 말하지 않겠어.\n\n\"탐험가 연맹에 들어가라. 재밌을 거다. 세상에 도움이 된다.\" 그런 얘기를 들었어. 괜히 주워듣지 말고 할머니 말씀을 따를 걸 그랬지. 우리 레그스턱 가문은 가만히 있는 게 몸에 맞아.\n\n야영지 녀석들이 이 일을 두고두고 놀릴 게 뻔해.\n\n내 꼴을 본보기로 삼아서 자네도 조심하게. 덫도 많고 황혼의 칼날단 놈들도 우글거리거든. 발밑을 조심해!', '', 66384),
(296180, 'koKR', '히에론을 비롯한 많은 공허 엘프들에게 그건 선택이 아니었어요. 엄브릭을 따른 이들은 텔로그러스 균열 속 유물에 의해 의도치 않게 변모했죠. 되돌아갈 수 없었고, 결국 대다수는 변화를 받아들이며 공허의 힘을 품었어요.\n\n그런데 저 같은 다른 사람들은 후발 주자로서 엄브릭을 따랐어요. 이전의 삶은 이미 정해진 길이었고, 그게 싫었죠. 그래서 스스로 선택한 길에서 위안을 찾고, 공허를 다스리는 데서 삶의 목적을 발견했어요. 텔로그러스로 가서 스스로 변화했고, 선택을 통해 렌도레이가 되었어요.\n\n공허는 가능성과 변화를 상징해요. 위험하지만, 원래 무기란 그런 것이죠.', '', 66384),
(296170, 'koKR', '', '어련하겠어요, 외숙부. 하지만 그때조차 로아는 아무 말도 없었습니다.', 66384),
(296156, 'koKR', '', '전장이 조용하군요. 당신의 전사들이 황혼의 칼날단 잔당을 마무리한 것 같습니다.', 66384),
(296154, 'koKR', '빛나무, 로아, 외부인... 모두 합쳤지만, 아마니의 피로 바다를 채울 만큼 쏟아내고 승리를 얻었군.', '', 66384),
(296153, 'koKR', '', '끝이다. 드디어.', 66384),
(296148, 'koKR', '네놈들 따위는 날 건드리지 못한다, 필멸자들아. 나를 죽일 수 있는 건 신뿐이다!', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(296147, 'koKR', '내 검이 그자를 먼저 베어버릴 거다!', '', 66384),
(296146, 'koKR', '', '그럼 네 로아의 축복을 받은 필멸자는 어떠냐?', 66384),
(296143, 'koKR', '네놈들 시체는 내가 직접 잘아타스 님께 바쳐주마!', '', 66384),
(296134, 'koKR', '', '뿌리가 이미 더 강해진 듯하군. 도와줘서 고맙네.', 66384),
(296133, 'koKR', '', '하르마라의 뿌리지기들에게 도움이 필요하다네. 일손을 보태 주겠나?', 66384),
(296128, 'koKR', '', '미안해요, 자기. 요청은 한 사람당 한 건만 가능해요! 내일 다시 오세요.', 66384),
(296120, 'koKR', '', '대피를 계속 진행해.', 66384),
(296119, 'koKR', '', '안녕, 자기. 요청할 거라도 있나요? 마침 여유도 생겼는데.', 66384),
(296110, 'koKR', '태양과를 넣은 유령화 차입니다.\n\n살면서 가장 힘들었던 때를 떠올리면서 들이켜십시오.', '태양과를 넣은 유령화 차입니다.\n\n살면서 가장 힘들었던 때를 떠올리면서 들이켜십시오.', 66384),
(296107, 'koKR', '', '좋아. 모르둔의 공허 방벽을 제거하겠다.', 66384),
(296106, 'koKR', '전부 감사해요, $n 님. 내일 울부짖는 능선에서 다시 봬요.', '', 66384),
(296104, 'koKR', '<아스트레와 세도나가 함께 사랑했던 한 남자를 그리워하며 대화를 나눕니다.>', '', 66384),
(296103, 'koKR', '생각보다 훨씬 잘 풀렸네요.', '', 66384),
(296099, 'koKR', '', '모르둔의 공허 방벽을 무너뜨려 달라고 로아께 간절히 기도드렸다.\n\n로아가 아니었다면 여기까지 오지도 못했을 터.\n\n하지만 마지막 전투는 우리 힘으로 싸워야 해.\n\n방벽은 곧 무너질 거다. 그러면 전투가 시작되겠지.\n\n준비는 됐나, 하쉬우라?', 66384),
(296097, 'koKR', '', '아스트레와 세도나가 대화를 이어가며 공동의 기억 속에 잠깁니다.', 66384),
(296096, 'koKR', '하! 텔로그러스에서 찻잎을 구하기가 정말 힘들었죠.', '', 66384),
(296095, 'koKR', '', '그 사람이 엉겅퀴 차를 포교하진 않던가요?', 66384),
(296094, 'koKR', '', '괜찮아요. 그냥 두세요. 아스트레, 당신만 괜찮다면 조금 더 차를 즐기고 싶어요.', 66384),
(296093, 'koKR', '히에론의 편지를 혼자 읽을 시간을 드릴게요, 세도나.', '', 66384),
(296092, 'koKR', '', '세도나와 아스트레가 함께 웃습니다.', 66384),
(296091, 'koKR', '태양과를 넣으니 훨씬 부드럽네요. 좋은 선택이에요, 세도나. 역시 입맛이 잘 맞는 것 같아요.', '', 66384),
(296089, 'koKR', '혼돈이 머물 곳은 구덩이뿐이다. 잠재워 줘서 고맙다.', '', 66384),
(296087, 'koKR', '', '모르둔은 방벽 뒤에 숨어 있으면 안전할 거라 믿는 모양이야. 그 착각, 내가 깨주지.', 66384),
(296086, 'koKR', '응어리의 구덩이는 언제나 위협을 끌어모은다. 밖으로 넘치지 않게 막아라.', '', 66384),
(296083, 'koKR', '', '좋네요. 깔끔해요. 옛 추억을 떠올리게 하네요.', 66384),
(296081, 'koKR', '', '히에론도 똑같이 말했어요. 받아들이려고 애썼지만... 도저히 안 되겠더군요.', 66384),
(296079, 'koKR', '차를 마셔봐요. 도움이 될 거예요. $n 님도 마셔볼래요? 손수 끓였잖아요.', '', 66384),
(296074, 'koKR', '성스러운 빛도 나름의 대가를 요구하죠. 엄격한 질서. 숨 막히고, 억압적이에요. 우린 예전과 달라졌죠.', '', 66384),
(296072, 'koKR', '', '공허의 유혹. 대가를 치르고 얻은 힘. 대가라는 게 참 야속하죠? 태양샘은 다시 태어났고, 마나 중독은 치유됐어요. 우리 종족의 투쟁이 부족했던 걸까요?', 66384),
(296071, 'koKR', '공허폭풍 속에서는 차가 부정적인 감정을 망령의 형태로 실체화하더군요. 그래도 도움이 되긴 했어요.', '', 66384),
(296068, 'koKR', '', '쓴 약 냄새가 나네요. 영원노래 숲에서 나는 감귤을 조금 넣으면 균형이 맞을 것 같아요.', 66384),
(296063, 'koKR', '용사님도 히에론에게 전해 받은 게 있어요. 찻잎은 아직 넉넉하죠, $n 님?', '', 66384),
(296058, 'koKR', '', '당신도 폭풍에 들어갔군요? 어서 들어와요.', 66384),
(296057, 'koKR', '세도나, 이쪽은 $n 님이에요. 동행해도 괜찮을까요?', '', 66384),
(296044, 'koKR', '멍청한 빛머리들이 싸움을 걸더니, 다 죽었네!', '', 66384),
(296043, 'koKR', '폭탄 포자를 가져와라! 가시아귀들을 거름으로 만들어 버릴 거다.', '', 66384),
(296038, 'koKR', '필요하신 거라도 있나요?\n\n주군의 매타조를 보살피느라 바빠서요.', '', 66384),
(296035, 'koKR', '난 아닐세.\n\n내가 뭘 했다고 착각하는진 모르겠지만, 확실히 난 아니야. 확실해.\n\n이 선봉대란 작자들, 흑마법사를 처음 보는 것처럼 들러붙고 있네.\n\n언데드라서 그러는 건지, 보라색 옷을 입어서 그러는 건지, 아니면 공허방랑자를 소환한 일 때문인지... 도통 모르겠군.', '', 66384),
(296034, 'koKR', '이 성기사들은 제 지휘하에 있고, 이들이 가장 필요한 곳으로 보낼 것입니다.\n\n실버문의 지도부가 이 악을 척결할 의지가 없다면, 우리가 나설 겁니다.', '', 66384),
(296033, 'koKR', '도시에 침투 요원이 들끓고 있습니다. 공허는 언제나 친구의 얼굴을 뒤집어쓰고 빈틈을 파고드는 걸 즐기지요.\n\n저는 이 도시가 배신에 무너지는 꼴을 보고 싶지 않습니다.', '', 66384),
(296032, 'koKR', '초소에 녀석들을 돌봐줄 사람이 있을 수도 있고... 으앗! 또 뭐지?', '', 66384),
(296021, 'koKR', '위험하긴 한데... 원정순찰대원이라면 위험을 마주할 줄 알아야겠죠!', '', 66384),
(296020, 'koKR', '저 장치가 생명체에 깃든 타락을 측정할 거예요. 흩어져서 수색하죠.', '', 66384),
(296001, 'koKR', '당신이 히에론의 소지품에서 찾은 편지는 세도나 더스크스파이어 앞으로 보내는 거였어요. 히에론의 전처죠. 그 사람이 렌도레이가 된 뒤, 몇 년 전 갈라섰고요.\n\n배신 같은 말도 오갔다고 해요. 그럼에도 히에론은 여전히 사랑했어요. 함께할 수 없게 된 뒤에도요.\n\n<아스트레는 세도나를 향해 시선을 던지며, 감추려 해도 감춰지지 않는 쓴 감정을 드러냅니다.>\n\n실버문에서 추방당한 일은 우리 모두에게 상처였어요. 토지와 유산을 빼앗기고, 가정은 뿔뿔이 흩어졌죠.\n\n우리가 선택한 게 아니에요. 저들이 그렇게 만든 거예요.', '', 66384),
(295994, 'koKR', '아름다운 꽃이네요. 토양이 건강하다는 뜻이겠지요. 우리의 노력이 빛을 본 겁니다.', '', 66384),
(295975, 'koKR', '', '빛이시여, 아스트레... 정말 미안해요. 안으로 들어올래요? 우리 얘기 좀 해요.', 66384),
(295971, 'koKR', '우린 공허폭풍으로 파견됐어요. 임무는... 그건 중요한 건 아니고. 히에론은 동족을 지키다 눈을 감았어요.', '', 66384),
(295969, 'koKR', '히에론은 세상을 떠났어요, 세도나.', '', 66384),
(295968, 'koKR', '', '스라소니를 든든히 먹이고 장로들까지 만족시켰군. 잘했네, 친구여.', 66384),
(295964, 'koKR', '', '소굴이 해충에게 유린당했네. 이 문제를 해결하면 장로들이 좀 더 호의적인 시선으로 우릴 봐줄 걸세. 암영스라소니를 데려가게. 녀석들이 먹이를 마다하진 않을 테니.', 66384),
(295963, 'koKR', '이 싸움을 멈추어야 하오.', '', 66384),
(295962, 'koKR', '', '훌륭하네. 이걸로 멋진 화해의 식사를 준비할 수 있을 걸세. 고맙네!', 66384),
(295961, 'koKR', '', '루타니와 버섯전사, 우리가 함께 나눌 화해의 식사를 만드는 데 쓸 재료가 필요하네. 함께 모아주게.', 66384),
(295960, 'koKR', '나도 동의하네. 이 도시는 언제 터져도 이상하지 않은 화약고야.', '', 66384),
(295959, 'koKR', '', '뭐죠? 동정하러 왔나요? 그 사람도 당신을 버렸나요?', 66384),
(295957, 'koKR', '그냥 편지를 전하러 왔을 뿐이에요. 근데 어쩌면... 할 말이 남아 있는 걸지도 모르겠네요.\n\n곁에 있고 싶지 않다면 굳이 안 남아도 돼요, $n 님. 개인적인 일이 될 수도 있으니까요. 어쨌든 괜찮을 거예요. 약속해요.', '', 66384),
(295956, 'koKR', '저들의 광신은 존경할 만했습니다. 그 희생이 헛되지 않도록 하겠습니다.', '', 66384),
(295955, 'koKR', '마법학자 엄브릭이 아스트레와 당신을 번갈아 바라봅니다.', '', 66384),
(295951, 'koKR', '저 또한 실버문에서 여러 차례 언쟁을 겪었습니다. 그렇지만 신도레이 형제들과는 예의를 지키는 편이 훨씬 낫다고 믿습니다.\n\n아스트레는 저와 생각을 달리합니다. 그래서 그 친구가 홀로 실버문으로 가는 게 걱정됩니다.', '', 66384),
(295949, 'koKR', '훌륭합니다! 단 한 번의 타격으로 포식의 군단을 약화시키고 방어를 강화했군요.', '', 66384),
(295947, 'koKR', '강자의 사냥이란 당연히 이런 거죠.', '', 66384),
(295946, 'koKR', '비참한 삶에서 우리 도시를 지킬 힘을 끌어냈으니, 한 편의 시 같지 않나요?', '', 66384),
(295945, 'koKR', '상대의 고통을 끝내 주고 동시에 우리의 힘을 채웠군요. 아주 효율적이네요!', '', 66384),
(295944, 'koKR', '바닷물 한 방울, 공허 속의 깜빡이는 불빛... 그걸로 충분할지도 모르죠...', '', 66384),
(295943, 'koKR', '엄청난 마력입니다! 이 힘의 일부분만이라도 다룰 수 있다면...', '', 66384),
(295942, 'koKR', '풍성한 수확이로군요. 잘했습니다.', '', 66384),
(295941, 'koKR', '안타깝지만 해야 할 일이었어요. 희생은 기억될 것입니다.', '', 66384),
(295939, 'koKR', '정령? 비전? 고뇌가 흘러나오는 근원은 중요하지 않아요.', '', 66384),
(295938, 'koKR', '아, 분노하던 모습이란! 실로 즐거웠습니다.', '', 66384),
(295937, 'koKR', '암살자를 암살하다니... 운명의 장난 같네요.', '', 66384),
(295936, 'koKR', '이 엄청난 힘... 정말 렌도레이가 무언가를 알아낸 것일지도 모르겠네요.', '', 66384),
(295935, 'koKR', '쇠붙이는 마법을 당해낼 수 없습니다.', '', 66384),
(295934, 'koKR', '불길이 밝게 타오를수록, 화상은 진미가 되죠.', '', 66384),
(295933, 'koKR', '황혼의 칼날단은 잘아타스를 섬기지만, 졸개조차 힘을 지니고 있습니다. 그 힘을 빼앗으세요.', '', 66384),
(295932, 'koKR', '가시예언단은 길에서 벗어났습니다. 놈들의 힘을 거두어 우리를 위해 사용합시다.', '', 66384),
(295931, 'koKR', '뒤틀린 자라... 참 잘 어울리는 이름입니다. 오랜 세월을 표류하며 살아남은 그 끈기를 이용해 보죠.', '', 66384),
(295930, 'koKR', '이 죽음의 기사는 쓸모를 다했습니다. 저 불행을 우리 쪽으로 가져옵시다.', '', 66384),
(295929, 'koKR', '이 포식의 군단 개체는 무슨 일이 있어도 철저하게 처단해야 합니다.', '', 66384),
(295928, 'koKR', '도마나르는 잘아타스의 정예병입니다. 그렇기에 더욱 매혹적인 표적이지요...', '', 66384),
(295927, 'koKR', '아, 빛이라. 제 마음에 가장 가까운 힘이지요. 빛에서 벗어난 자들로부터 되찾아 옵시다.', '', 66384),
(295926, 'koKR', '루타니들은 우리 세계의 힘이 스며든 존재들입니다. 이제 그 힘을 배양할 때입니다.', '', 66384),
(295925, 'koKR', '원청순찰대도 타락과 배신에서 벗어날 수는 없습니다.', '', 66384),
(295924, 'koKR', '전 트롤의 힘을 결코 가벼이 보지 않습니다. 그 힘을 활용합시다.', '', 66384),
(295923, 'koKR', '이 괴물은 성질이... 제법 까다롭습니다.', '', 66384),
(295922, 'koKR', '크아레쉬는 우주에서 가장 치명적인 포식자들을 길러낸 곳입니다. 지금 목표도 그중 하나입니다.', '', 66384),
(295921, 'koKR', '공허에 타락한 제 동족의 끈기는 경탄할 만합니다. 그 힘을 이용합시다.', '', 66384),
(295920, 'koKR', '이 자는 체구는 작지만 힘은 대단합니다. 절대 얕보지 마십시오.', '', 66384),
(295919, 'koKR', '이 자는 불꽃처럼 거세게 타오르는군요. 그 불길을 꺼뜨리십시오.', '', 66384),
(295913, 'koKR', '흠, 하하하...', '', 66384),
(295907, 'koKR', '좋습니다. 아스트레가 실버문에서 문제를 일으키지 않도록 지켜 주십시오. 그 친구와 저 자신을 위해서 말입니다. 롬매스만 해도 이미 골칫거리입니다.', '', 66384),
(295905, 'koKR', '오래 걸리진 않을 거예요. 어차피 거긴 절 반기지 않을 테니까요.', '', 66384),
(295902, 'koKR', '균열은 봉인됐습니다. 이제 암연지 성채는 더 이상 실버문을 위협하지 못할 것입니다.', '', 66384),
(295897, 'koKR', '암흑 호드는 로서의 후예들처럼, 아직 2차 대전쟁의 기억 속에 갇혀 있습니다.', '', 66384),
(295896, 'koKR', '', '기묘하고 아름다운 꽃이네요! 지룡들이 당신의 도움을 아주 고마워하는 모양입니다.', 66384),
(295895, 'koKR', '', '지룡이 꽤 많네요! 돌아오세요!', 66384),
(295893, 'koKR', '함께였기에 해낼 수 있었어요. 이제 울부짖는 능선으로 돌아가요.', '', 66384),
(295892, 'koKR', '', '작은 친구, 우리한테 줄 게 있니?', 66384),
(295891, 'koKR', '', '이게 뭐지? 이런 기묘한 모습의 지룡은 처음 봐요!', 66384),
(295879, 'koKR', '', '전 여기서 포식 양상을 관찰하겠습니다. 당신은 지룡들을 도와주세요!', 66384),
(295857, 'koKR', '더럽고... 추잡한... 짐승들...!', '', 66384),
(295854, 'koKR', '그대가 잘아타스에게 가는 길을 찾는다면... 선봉대는 물러날 거요. 게다가 그대의 동족이 얻을 입지는 말할 것도 없소.', '', 66384),
(295843, 'koKR', '실버문이 우리 손에 달려 있습니다. 힘을 모읍시다!', '', 66384),
(295842, 'koKR', '도시 안에서는 내가 보호해 줄 수 있소. 다만, 선봉대는 그대가 태양샘에 접근하는 걸 허락하지 않을 거요. 결과로써 상황을 반전시키시오.', '', 66384),
(295841, 'koKR', '결과? 제겐 도구도, 지원도 없고, 양쪽의 광신자들 모두에게 쫓기고 있습니다...', '', 66384),
(295804, 'koKR', '나는 전사도, 지도자도 아니다. 그런 시절은 지났어.\n\n하지만 내겐 여전히 손이 있고, 시간도 있고, 동족 사이에서 설 자리가 있다. 평화롭게 나눈 한 끼 식사가 전쟁에서 뽑아 든 칼만큼 강력할 수 있지.\n\n그래서 나는 모으고, 요리하고, 내가 줄 수 있는 걸 내놓는다. 그걸로 충분해.', '', 66384),
(295803, 'koKR', '하르마라는 우정으로 세워진 게 아니라 필요 때문에 세워졌다.\n\n하라니르, 루타니, 버섯전사들은... 서로에게 관심이 없었어. 하지만 끝없는 유혈은 땅을 비우는 것 말고는 아무 목적도 없었지.\n\n그래서 우리는 부서지기 쉬운 무언가를 세웠다. 평화가 간신히라도 유지될 수 있는 곳을.', '', 66384),
(295794, 'koKR', '불은 피워 놨는데, 허리가 영 말을 안 들어. 손 좀 빌려주면 고맙게 생각하지.', '', 66384),
(295761, 'koKR', '전 단지 공허폭풍을 좀 더 정밀하게 관측하려 했을 뿐입니다.\n\n들어 보십시오. 지금 제 방식을 의심할 여유는 없습니다. 당신도 느껴지지 않나요? 공허폭풍은 약해지긴커녕 오히려 점점 강해지고 있습니다.\n\n태양샘이 이 방어를 오래 유지하지 못할 겁니다. 전 공허폭풍 내부로 진입할 방법을 찾아야 하고, 그러려면 방금 수집한 자료를 분석할 시간이 필요합니다. 광신도들 손에 죽지 않고 말입니다.\n\n그자들을 설득해 줄 수 있겠습니까?', '', 66384),
(295757, 'koKR', '', '우린 너희 공허 엘프의 도움 \"제안\" 따위에 흔들리지 않는다.', 66384),
(295755, 'koKR', '신중히 행동하시오, 용사여. 우리는 엄브릭도, 선봉대도 모두 필요하오.', '', 66384),
(295741, 'koKR', '대장님을 구했네요... 접질린 발목으로부터 말이죠. 그리고 원정순찰대 초소도 지켰죠... 먼지랑 승냥이들한테서.\n\n이제 진정한 원정순찰대원이 된 걸까요?', '', 66384),
(295738, 'koKR', '아스타레이, 발사린... 다른 순찰대원들 도와주세요.', '', 66384),
(295718, 'koKR', '처음부터 난 답이 없었어. 자크캐쉬 같은 훌륭한 전사를 두고 나 같은 놈팡이를 고를 리가.\n\n<발끝만 쳐다보는 카가라>\n\n난 이번 축제는 거르려고 해. 그래도... 도와줘서 고맙네.', '', 66384),
(295717, 'koKR', '나마지가 왜 날 택했는지 전혀 모르겠어! 그래도 기분은 좋아! 분명 더 나은 선택지가 있었을 텐데.\n\n<스스로를 진정시키는 자크캐쉬>\n\n좋아! 기회가 주어졌으니 최대한 잘 활용해야지!\n\n행운을 빌어 줘!', '', 66384),
(295715, 'koKR', '난 최선을 다했어. 나마지는 똑똑해. 카가라도. 둘이 겹치는 관심사가 많겠지.\n\n나마지가 올바른 선택을 한 거야.\n\n다른 사람한테 물어봐야 하나? 그래도 축제에 가야 할까?\n\n아니면 당분간은 훈련에 집중해야 하려나.', '', 66384),
(295714, 'koKR', '좋습니다. 책임은 당신이 지는 겁니다.', '', 66384),
(295713, 'koKR', '지금이야말로 과감히 나서야 할 때입니다. 엄브릭을 풀어 주십시오. 모든 책임은 제가 집니다.', '', 66384),
(295712, 'koKR', '\'과감한\' 행동을 일삼는다고요? 대마법학자께서 그렇게 말씀하시던가요?', '', 66384),
(295711, 'koKR', '하지만, 엄브릭이...', '', 66384),
(295709, 'koKR', '엄브릭을 구속할 시간적 여유도, 처형할 근거도 없지 않습니까.', '', 66384),
(295708, 'koKR', '나마지가 날 택했다고? 자크캐쉬가 아니라? 둘이 늘 붙어 다녔잖아...\n\n늘 이런 날을 꿈꿨지만, 진짜로 올 줄은 상상도 못 했어!\n\n지금 이게 진짜 현실 맞아? 나 혹시 죽은 거 아냐?\n\n<과호흡이 온 카가라>\n\n이제 어떻게 해야 하지? 무슨 말을 해야 하지?\n\n엄니 예쁘다고 칭찬할까? 안아줘야 하나?\n\n도와줘!', '', 66384),
(295706, 'koKR', '맞습니다. 저도 몇 번이고 그 본색을 봤죠. 엄브릭과 렌도레이는 박해와 불신 속에서도 수도 없이 얼라이언스를 향한 충절을 증명해 왔습니다.', '', 66384),
(295705, 'koKR', '안 됩니다. 이... 엘프는... 이미 본색을 드러냈습니다.', '', 66384),
(295704, 'koKR', '총사령관. 지금 당장 마법학자 엄브릭을 석방하십시오.', '', 66384),
(295701, 'koKR', '전 여러분을 도우려고 공허를 조사하고 있었습니다!', '', 66384),
(295696, 'koKR', '정말 그럴까요?\n\n조만간 공격에 나서지 않으면 결국 공허에 무너질 운명일지도 모릅니다.\n\n음. 일리단이 이런 말을 했었지요. \"때로는 운명의 손을 잡아 끌어야 한다.\"', '', 66384),
(295695, 'koKR', '저도 로르테마르 님의 의견에 동의합니다. 그렇지만 정치적으로 복잡한 사안이기도 하지요.\n\n마법학자 엄브릭은 실버문의 시민이 아닙니다. 엄브릭과 렌도레이는 추방자이기 때문에, 로르테마르 님이 권한을 행사할 수 없습니다.\n\n설령 시민이었어도 마법학자인 이상 대마법학자 롬매스의 관할 아래 있죠. 롬매스는 엄브릭의 공허 마법 사용에 개인적인 배신감을 느낀 듯하더군요.', '', 66384),
(295694, 'koKR', '그 도마나르가 히에론의 주문 집중 장치를 훔쳤나 봅니다. 그걸로 실버문을 찾을 수 있었던 거죠.\n\n지금 바로 행동해야 합니다.', '', 66384),
(295673, 'koKR', '빛의 선봉대가 마법학자 엄브릭이 태양샘에 접근하려는 걸 포착했습니다. 저는 즉결 처형을 막으려고 개입했고요.\n\n로스락시온과 전 특정 마법의 타락성과 그 영향에 대해 잘 압니다. 다만, 그러한 경험에서 얻은 경험은 완전히 다른 것 같네요.', '', 66384),
(295669, 'koKR', '', '좋아, 그럼 누가 더 뜨거운 전율을 느끼는지 보자, 엘프!', 66384),
(295666, 'koKR', '', '참 아마니답군요. 뭐... 솔직히 말하면 저도 비슷한 감정을 느낍니다.', 66384),
(295664, 'koKR', '', '로아께서 내게 힘을 주셨지만, 결국 내 심장을 뛰게 하는 건 전장이다!', 66384),
(295653, 'koKR', '고맙... 다...', '', 66384),
(295648, 'koKR', '이런 거에 지지 마라.', '', 66384),
(295625, 'koKR', '잘아타스 님... 제 실패를 용서하소서.', '', 66384),
(295622, 'koKR', '공허의 군대는 광대하고 무궁하다. 너희는 다가올 미래를 감당하지 못한다!', '', 66384),
(295593, 'koKR', '버섯을 먹으면 쑥쑥 자란다!', '', 66384),
(295592, 'koKR', '', '집으로 돌아가자!', 66384),
(295591, 'koKR', '', '하라니르의 사전에 죽음은 없다!', 66384),
(295590, 'koKR', '...일단 우리 구호부터 생각해 봐야 할 것 같네.', '', 66384),
(295586, 'koKR', '...구미가 당기긴 하는군요.\n\n너무 강렬하게 말이지요.\n\n공허의 하수인이 제시한 길을 신뢰하긴 어렵겠지만, 지금은 무언가 조치를 취해야 할 때입니다.\n\n태양샘이 일단 버티고는 있지만, 지금 이 상황은 교착 상태가 아닙니다. 변화가 없다면 곧 공허폭풍이 방어선을 뚫기 시작할 것입니다.\n\n반격에 나서야 합니다.', '', 66384),
(295585, 'koKR', '얘들아! 어떻게 할까?', '', 66384),
(295584, 'koKR', '이 사안에 한해서는 로르테마르의 권한을 인정하지 않습니다. 그 공허 엘프는 추방자이며, 본질적으로 태양샘과 이곳 병력에 위협이 되는 존재입니다.\n\n엄브릭은 실버문의 시민이 아니며, 공허와의 전쟁에서 우리가 섭정의 지시에 따를 이유도 없습니다.\n\n로르테마르는 조언을 할 수 있을 뿐, 명령을 내릴 권한은 없습니다.', '', 66384),
(295583, 'koKR', '그렇지만 당신은 태양샘이 직접 부른 존재죠. 엄브릭은 그렇지 않습니다. 요컨대 지나치게 오염됐거나, 그 영예를 누릴 자격조차 없다는 뜻이겠지요.', '', 66384),
(295582, 'koKR', '막강한 공허 엘프인 마법학자 엄브릭이 태양샘에 접근하는 걸 허락하는 데 신중을 기하는 건 당연합니다. 몇 년 전 알레리아 윈드러너가 태양샘에 접근했을 때, 단지 근처에 있었을 뿐인데도 마법이 변형되었습니다.\n\n물론 알레리아는 어둠의 나루를 내면에 품고 있으니 그 영향도 있었겠지만, 전 공허에 깊이 물든 존재를 태양샘 가까이 들이는 위험을 감수할 생각은 없습니다.', '', 66384),
(295571, 'koKR', '', '우리 점술가들도 이 문제를 연구하고 있네. 아직 답은 없지만, 그 공허에 물든 엘프 역시 뚜렷한 해법은 없지.\n\n억제 마법 탓에 구원호를 투입할 수도 없고, 순간이동이나 비행 마법도 폭풍을 넘을 수 없다네.\n\n하지만 반드시 돌파구를 찾을 걸세. 믿음을 잃지 않으면 길은 드러나게 되어 있어.', 66384),
(295568, 'koKR', '', '물론 그렇겠지. 하지만 그자가 제대로 된 길을 제시할 수 있을지는 믿기 어렵군. 혹시 자신의 이익을 위한 길은 아닌가?\n\n이젠 공격적으로 나설 때가 맞네. 문제는 이게 바로 공허가 세상을 좀먹는 방식이란 거지. 위험할 때 손을 내밀고는 결국 모든 걸 앗아가 버려.\n\n안수레크 여왕, 아즈샤라 여왕, 연합왕 살라다르... 모두 절박한 순간에 공허의 손을 잡았고, 그 대가를 치렀지.\n\n우린 그런 자들보다 더 나아야 하네.', 66384),
(295564, 'koKR', '', '이미 실버문을 위해 병력을 지나치게 분산시켰네.\n\n로르테마르는 틀에 갇혀서 생각하고 있어. 우린 도시 하나를 지키러 온 게 아닐세. 아제로스 전체를 구하러 온 것이지.', 66384),
(295556, 'koKR', '', '우리 빛의 선봉대는 공허와 맞서는 일에 관해서는 누구보다 잘 안다네. 저들의 병력은 포식을 일삼고, 전염병처럼 퍼지는 종양과 같고, 뭐든 삼켜버린다네.\n\n그게 놈들의 방식이지. 처음에는 친근하게 다가오거나 무슨 거래를 제안해. 그러다 정신을 차리고 보면 또 하나의 세계가 통째로 삼켜지게 되는 걸세.', 66384),
(295534, 'koKR', '움직임 하나하나 다 지켜보겠어.', '', 66384),
(295533, 'koKR', '그래! 북을 울려라. 한심한 트롤들을 더 도살장으로 보내라!', '', 66384),
(295532, 'koKR', '차원문 마법사를 처리한다고 너희가 얻는 건 없다! 네놈들의 초라한 늪지 도시 따윈 우릴 못 막는다!', '', 66384),
(295530, 'koKR', '도움은 돼요. 하지만 싸워야 하죠. 직접 보면 알 거예요.', '', 66384),
(295529, 'koKR', '로르테마르가 절박함에 눈이 멀었군. 물론 실버문과 태양샘을 지켜야 한다는 데는 나도 이견이 없소. 하지만 공허에 손을 뻗는 건...\n\n엄브릭은 단순히 공허를 사용하고 있는 것이 아니오. 우리 종족의 가장 큰 배신자가 다듬은 기법에 의지하고 있소.\n\n공허폭풍에 들어갈 방법을 찾는 데 있어, 빛이나 비전만으로는 어려울 수 있소. 하지만 엄브릭이 하려는 방식보다는 훨씬 신뢰할 수 있을 거요.', '', 66384),
(295527, 'koKR', '너희 필멸자가 깊은 유대를 쌓는 방식이 이렇게 사적인 이야기를 나누는 것임을 안다. 내 궁금증을 풀어 줘서 고맙다.', '', 66384),
(295526, 'koKR', '로르테마르는 그럴 권한이 있다고 생각하겠지만, 엄브릭은 마법학자요. 그러니 판단하고 다스릴 권한은 내게 있소.\n\n무엇보다도 엄브릭과 추종자들은 본인들의 행실로 인해 추방된 자들이오. 공허 마법은 단순한 금기가 아니오. 본질적으로 뿌리부터 악이 깃들어 있는 마법이지.', '', 66384),
(295525, 'koKR', '검이 식을 동안 잠시 쉬자. 자, 네 이야기를 들려다오.', '', 66384),
(295523, 'koKR', '더 시간을 함께 보내니 즐겁군.', '', 66384),
(295522, 'koKR', '로르테마르가 그대를 보냈소?\n\n엄브릭은 한때... 동료였소. 공허에 손대기 전까지는 말이오. 원래 무모한 구석이 있었지.\n\n엄브릭 본인은 그걸 \'과감함\'이라고 포장하겠지만, 마법에 대한 엄브릭의 접근 방식은 우리가 이 세계를 지키기 위해 세운 경계를 전혀 존중하지 않았소.\n\n이젠 너무 멀리 가버렸지.', '', 66384),
(295512, 'koKR', '', '그럼 결정됐네!', 66384),
(295511, 'koKR', '', '카가라? 아니면 자크캐쉬?\n\n카가라는 나한테 멋진 트레샤돈 이빨 목걸이를 줬어. 전사는 아니지만, 똑똑하고 눈치도 빠르지. 얘기 나누기도 좋고, 항상 날 웃게 해.\n\n자크캐쉬는 이 멋진 깃털 머리장식을 줬어. 깜짝 놀랐지. 자크캐쉬는 힘도 세고 정말 훌륭한 전사야. 그런데 다정한 면까지 있다니, 마음이 가더라.\n\n너라면 누구를 고르겠어?', 66384),
(295509, 'koKR', '우스운 말 마라. 필멸자인 너희는 모두 후회한다. 공기 중에서 그 맛이 느껴진다.\n\n많은 목숨을 거두었겠지? 그중에 네가 후회하는 죽음도 있을 터.', '', 66384),
(295503, 'koKR', '흥미로운 대답이로군.\n\n나라고 두려움에서 자유로운 것은 아니다. 더 큰 힘이 나타난다면 우리 공허의 존재들도 두려워한다. 나는 잘아타스를 두려워한다.\n\n너 또한 두렵다.\n\n<입가를 크게 벌려 웃는 데시무스>\n\n더 말해 다오. 알아야겠다. 그렇다면 이번엔 후회다. 네가 후회하는 것은 무엇이냐?', '', 66384),
(295487, 'koKR', '재미있군. 나는 온갖 풍미를 즐긴다. 비통함, 질투, 공포...\n\n<낮게 콧노래를 흥얼거리며 입술을 핥는 데시무스>\n\n하지만 네가 말한 그 물리적인 음식도 맛보고 싶구나.\n\n그다음은 뭐지? 너희 필멸자들이 흔히 나누는 사소한 화제라면... 좋아, 이번엔 이렇게 묻지.\n\n네가 두려워하는 건 무엇이냐?', '', 66384),
(295478, 'koKR', '너희 필멸자의 삶은 참으로 흥미롭고 복잡하구나. 그 내면의 세계가 강렬하고도 맛있는 감정을 만들어낸단 말이지.\n\n너희를 더 깊이 이해하고 싶다.\n\n대화를 해 보자. 너 자신에 대해 말해 다오.\n\n네가 가장 좋아하는 음식은 무엇이냐?', '', 66384),
(295462, 'koKR', '', '그러고 보니, 알레리아 님의 심장에 어둠의 나루가 들어 있다는 소문, 의외로 말이 되네요.', 66384),
(295453, 'koKR', '얘들아! 나 좀 도와줘!', '', 66384),
(295452, 'koKR', '흔적이 남아 있어요. 아직 무언가가 저 밖에 있어요. 가시죠!', '', 66384),
(295451, 'koKR', '', '저기요! 저기 샤오말이 있어요!', 66384),
(295449, 'koKR', '잠깐... 느껴집니다... 실버문입니다. 보십시오! 저 아래에!', '', 66384),
(295448, 'koKR', '이건 도마나르의 소행입니다. 히에론이 놈에게 상처를 입히긴 했지만, 무언가를 빼앗아 간 것 같습니다.', '', 66384),
(295447, 'koKR', '여깁니다!', '', 66384),
(295446, 'koKR', '이 균열들... 마치 벌어진 상처 같군요. 그리고 묘하게 익숙한 기운이 느껴집니다.', '', 66384),
(295445, 'koKR', '', '뭐가 됐든, 이쪽입니다.', 66384),
(295444, 'koKR', '우린 수십 년 전 엘프와 호드와의 싸움에서 많은 이들을 잃었네. 그때는 그래도 번성하는 종족이었지.\n\n지금은 달라. 너무 적어졌어. 이런 손실이 계속되면 아마니는 물론이고 다른 숲 부족들의 시대가 곧 끝나고 말 걸세.\n\n그런 날은 오지 않기를 아킬존께 빌고 있지.', '', 66384),
(295442, 'koKR', '', '정말 용사님 혼자 보낼 줄 아신 건 아니지요?', 66384),
(295427, 'koKR', '자네, 약초와 영혼 물감을 함께 준비해 주게. 고인을 경건한 계곡 너머로 인도할 마지막 의식을 제대로 치르려면 필요하네.', '', 66384),
(295425, 'koKR', '', '날로라크한테 가 있는 사이 조금이라도 멍청한 짓을 하면, 내 손으로 널 처단하겠다.', 66384),
(295424, 'koKR', '', '무슨 용건이지?', 66384),
(295421, 'koKR', '', '이렇게 많이 죽다니... 잔, 도대체 무슨 짓을 한 거야?', 66384),
(295420, 'koKR', '오늘 흘린 피는 강물이 되어 침략자들을 우리 땅에서 쓸어낼 거다!', '', 66384),
(295415, 'koKR', '', '마을에 요즘 많은 일이 있었지. 이번 축제가 분위기를 좀 밝게 만들어 주면 좋겠어!\n\n내가 태어난 뒤로 로아 축제는 한 번도 열리지 않았거든. 장로님들이 설명해 주시긴 했는데, 그래도 긴장돼!', 66384),
(295407, 'koKR', '던러너 대장님이 뭔가에 붙잡혔다면, 우리가 직접 구하러 가야죠.', '', 66384),
(295405, 'koKR', '맞아요! 이상한 마법이 있었고... 잠깐. 던러너 대장님, 무슨 문제라도 있나요?', '', 66384),
(295404, 'koKR', '', '별일 아니야! 그냥 발목을 살짝 접질렸어. 너무 우거져서 그래.', 66384),
(295403, 'koKR', '대장님! 괜찮... 으시네요?', '', 66384),
(295402, 'koKR', '', '그림이 각자에게 전하는 뜻은 다르다네.', 66384),
(295401, 'koKR', '카가라가 나마지를 그렇게 좋아하는 건 아니면 좋겠어. 아니면 난 상대도 안 돼. 카라가는 마을에서 가장 똑똑한 녀석이란 말이야!', '', 66384),
(295378, 'koKR', '의식을 끝내기 전까지는 하르마라를 떠날 수 없다.', '의식을 끝내기 전까지는 하르마라를 떠날 수 없다.', 66384),
(295377, 'koKR', '아버지가 어머니께 직접 말씀하시기를 기다렸지만... 제가 직접 전해야 할 것 같습니다.', '', 66384),
(295376, 'koKR', '', '용사여! 알레리아가 도착하자마자 실종된 장교들을 찾으러 떠났네.', 66384),
(295361, 'koKR', '전부 다 감사합니다, $n 님. 선봉대를 위해, 실버문을 위해... 절 위해 노력해 주셔서.', '', 66384),
(295360, 'koKR', '감사합니다! 재정비 후 다음 공격에 동참하겠습니다.', '', 66384),
(295359, 'koKR', '용사님 아니었으면 죽었을 겁니다!', '', 66384),
(295358, 'koKR', '빛이 우리를 보호하겠지만, 속히 움직여야 합니다!', '', 66384),
(295357, 'koKR', '가능한 한 빨리 치료하십시오. 집결 지점에서 다시 모일 겁니다! 용사님, 저들을 지켜 주십시오!', '', 66384),
(295356, 'koKR', '자크캐쉬는 젊은 전사들 중 가장 뛰어난 친구야. 녀석이 나마지에게 관심이 있다면, 내 계획은 절대 이뤄질 리 없어!', '', 66384),
(295355, 'koKR', '여기서 배운 게 있다면, 포식의 군단은 우리의 신념을 먹잇감으로 삼으려 한다는 사실입니다.', '', 66384),
(295354, 'koKR', '이 불쌍한 병사들은 부대와 흩어졌습니다. 함께 움직입시다.', '', 66384),
(295353, 'koKR', '빛이 전사자들을 품고, 살아 있는 자들을 지켜 악이 우리 세계를 더럽히지 못하게 하소서.', '', 66384),
(295351, 'koKR', '전장에 남은 이들을 구하러 나가야 합니다.', '', 66384),
(295349, 'koKR', '아, 용사님. 잘 오셨습니다. 도움이 필요합니다.', '', 66384),
(295348, 'koKR', '', '잠깐, 세상의 종말을 막기 위한 전쟁이라고요?\n\n정중히 설명만 해줬으면 제가 가진 걸 기꺼이 내줬을 겁니다. 무슨 날강도나 얼라이언스 약탈자처럼 행동할 게 아니라요.\n\n수레 한 대쯤은 드릴 수 있지요. 다만, 본인들이 누구의 도시에서 머물고 있는지 정도는 기억해 줬으면 합니다.', 66384),
(295344, 'koKR', '빛이 자네를 이 전장에 부른 이유를 알 것 같아. 자네는 모두에게 큰 영감을 주고 있네.', '', 66384),
(295338, 'koKR', '공허 대포 때문에 도착한 이후로 줄곧 묶여 있었네. 이제 빚을 갚을 때가 된 것 같지 않나? 자네도 한번 해보겠나?', '', 66384),
(295336, 'koKR', '', '당신! 이야기 들었습니다. 당신이 바로 그 용사라면서요!\n\n공허를 몰아내러 왔다고들 하더군요.\n\n근데 이 병사들이 태양샘에 제 물품이 필요하다며 수레를 그냥 통째로 가져가려 했습니다. 인사도 없이, 대가도 없이요.\n\n전 저 사람들이 누군지도 모릅니다! 이게 얼라이언스가 물건을 강탈하려는 핑계가 아니라는 걸 어떻게 믿을 수 있겠습니까?', 66384),
(295335, 'koKR', '맞소, 엄브릭. 당신의 동족을 구출한 덕분에 공격할 틈이 생겼소.', '', 66384),
(295324, 'koKR', '공허를 다루는 자들을 풀어주십시오. 도시 내부 출입은 허락하겠지만, 태양샘 근처로 더러운 얼룩을 가져오는 건 허락하지 않겠습니다.', '', 66384),
(295323, 'koKR', '난 흑마법사지, 이교도가 아닐세.', '', 66384),
(295318, 'koKR', '', '이미 마법학자에, 기사단에, 무기까지 다 가져갔으면서, 이젠 음식까지 내놓으라고?', 66384),
(295315, 'koKR', '태양샘에 필요한 겁니다. 마나빵만 먹고는 병사들이 못 버팁니다.', '', 66384),
(295308, 'koKR', '', '우리 둘 다 빛을 따르지만, 당신의 믿음은 너무 차갑고 삭막해 낯설기만 합니다.', 66384),
(295307, 'koKR', '', '공허폭풍을 막을 소규모 병력은 남겨 뒀네. 성스러운 빛께서 굽어살피신다면 충분할 터.', 66384),
(295306, 'koKR', '', '잘아타스에게 향할 길이 열리면 곧장 떠나라고 거듭 말해 왔지 않나. 그러니 이제 떠나는 거지.', 66384),
(295304, 'koKR', '제 병사들은 빛 사용자와의 대련에만 지나치게 익숙해져 있습니다. 이젠 다른 무예에도 적응해야 합니다.', '', 66384),
(295303, 'koKR', '잘하셨습니다, 용사님! 선봉대는 용사님의 힘과 신념을 본받도록 노력할 겁니다.', '', 66384),
(295286, 'koKR', '여군주 리아드린을 선봉대 지휘관들에게 보내 즉시 병력을 전개하고, 평화롭게 도시에서 물러나 달라는 뜻을 전하게 했다오.', '', 66384),
(295276, 'koKR', '', '이 야수들을 쓰러뜨리려면 강력한 화력이 필요하겠어.', 66384),
(295258, 'koKR', '', '긴장해라. 지금까지 나온 건 애송이들뿐이니까.', 66384),
(295251, 'koKR', '', '북쪽에서 트롤들의 괴성이 들린 것 같습니다. 좋은 징조는 아닙니다.', 66384),
(295238, 'koKR', '', '태민! 대장을 찾는데... 어, 왜 새끼 곰들을 데리고 왔어?', 66384),
(295237, 'koKR', '전사단, 공격하라!', '', 66384),
(295230, 'koKR', '어린 녀석들을 구한 용사님께 드리는 선물이랍니다... 전설 속 이야기처럼요!', '', 66384),
(295229, 'koKR', '빛나무를 차지하고 싶으면 내 시체를 밟고 가라, 고킨예. 빛나무 무기는...', '', 66384),
(295228, 'koKR', '이 마력은 감당이 안 될 정도예요. 저는 엄브릭 님처럼 강하지 않아서 오래 못 버텨요.', '', 66384),
(295225, 'koKR', '변장을 사용해 물품을 찾으세요.', '', 66384),
(295218, 'koKR', '블러드 엘프들은 우리 땅을 빼앗아 놓고 그 위에 살고 있다.\n\n넌 이해하지 못하지. 빛나무는 원래 우리 것이었다. 우린 그 나무가 꼭 필요해!', '', 66384),
(295208, 'koKR', '놈의 비명은 신경 쓰지 마라. 검이 스스로의 의지로 힘을 끌어내는 게 보이나? 아직 할 일이 남았다, $n. 갉아먹는 유역에서 보자.', '', 66384),
(295207, 'koKR', '보르테시운, 네 원한의 맛이 기대한 만큼 달콤하구나.', '', 66384),
(295206, 'koKR', '새 장난감을 찾았나, 데시무스? 먹잇감을 갖고 장난치는 건 여전하군.', '새 장난감을 찾았나, 데시무스? 먹잇감을 갖고 장난치는 건 여전하군.', 66384),
(295204, 'koKR', '반갑네, 수행사제여.', '', 66384),
(295202, 'koKR', '뭘 망설입니까, $c 친구? 저 흉물들도 피를 흘리는지 직접 확인해 봅시다!', '', 66384),
(295189, 'koKR', '참으로 달콤하구나.', '', 66384),
(295188, 'koKR', '글쎄, 난 옛 군주들과 함께 파멸당하기에는 너무 보잘것없었거든. 너처럼 말이야.', '', 66384),
(295186, 'koKR', '데시무스? 살아 있었나? 다른 군주들과 함께 잘아타스에게 흡수당한 줄 알았는데.', '데시무스? 살아 있었나? 다른 군주들과 함께 잘아타스에게 흡수당한 줄 알았는데.', 66384),
(295185, 'koKR', '착각하지 마라, $n. 녹시안은 잘아타스에게 충성을 바친 적 없다. 질투와 탐욕에 사로잡혀 있었을 뿐이지.', '', 66384),
(295184, 'koKR', '배신자라? 언제부터 충성심이 중요한 덕목이 됐지, 녹시안?', '', 66384),
(295182, 'koKR', '데시무스! 배신자!', '데시무스! 배신자!', 66384),
(295181, 'koKR', '<어깨를 으쓱하는 데시무스>', '', 66384),
(295172, 'koKR', '하! 그럼 우리한테 가치가 있는 걸 내놓아야지.', '', 66384),
(295171, 'koKR', '흥미로운 동료를 데려왔군, 데시무스. 거래를 할 생각은 없나?', '흥미로운 동료를 데려왔군, 데시무스. 거래를 할 생각은 없나?', 66384),
(295079, 'koKR', '심장에 불을! 불길이 점점 더 치솟으리라! 하하하하하!', '', 66384),
(295078, 'koKR', '자네의 불꽃을 마주하게! 불꽃 말이야! 스스로의 불꽃을 마주하지 않으면 마음속에 아무것도 남지 않아!', '', 66384),
(295077, 'koKR', '흠, 아직 쓰러지지 않았으니... 먹을 만한 걸로 봐도 되겠군!', '', 66384),
(295076, 'koKR', '토르톨란들이 피난민에게 식사를 내주었네. 먹어도 괜찮은지 확인해 줄 수 있겠나?', '', 66384),
(295069, 'koKR', '쿨지께 찬미를. 자네가 가져온 줄기와 뿌리가 부상자들에게 큰 힘이 될 걸세.', '', 66384),
(295068, 'koKR', '황혼의 칼날단의 습격으로 아직 회복 중인 이들이 많네. 약을 만들어야 하니, 쿨지의 제단 주변에서 약초를 모아 주게.', '', 66384),
(295067, 'koKR', '불의 자손이 만족하는구먼! 불꽃의 어머니께서 미소 짓네! 오늘은 물고기 비가 내리는 날이야!', '', 66384),
(295066, 'koKR', '불의 자손이 신선한 먹이를 찾고 있네! 헤엄치게! 잠수해! 사냥을 하는 걸세! 잔칫상을 차리고 남을 물고기를 잡아 오게!', '', 66384),
(295061, 'koKR', '', '황혼의 칼날단은 예언자의 휴식처에 숨어 있다. 하쉬우라가 줄아만을 어떻게 지키는지 보여줘라!', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(295060, 'koKR', '', '잘 해냈군, 용사. 덕택에 우리 땅에 남은 황혼의 세력이 줄었다.', 66384),
(295059, 'koKR', '', '우리의 가보와 유물들을 되찾아왔군. 고맙다, 하쉬우라. 깨진엄니와 선조 모두의 이름으로 감사를 표한다.', 66384),
(295058, 'koKR', '바로잡아야 할 일이 있습니다.', '', 66384),
(295057, 'koKR', '', '황혼의 칼날단이 마을을 약탈하면서 귀중한 유물들을 가져갔다. 되찾아다오!', 66384),
(295049, 'koKR', '수많은 이가 죽었습니다. 뭘 위해서였을까요? 차라리 당신도 그 뒤를 따르는 게 나을지도 모르죠.', '', 66384),
(295019, 'koKR', '', '무력을 써야 했다니 안타깝습니다. 모든 문제가 말로 해결할 수 있는 건 아니죠.', 66384),
(295018, 'koKR', '', '이 침입자들은 줄자라의 보호를 받을 자격이 없습니다. 스스로 그 권리를 버렸죠. 한 치도 물러서지 마십시오!', 66384),
(295009, 'koKR', '', '하지만 전 제 동족과 함께 있습니다. 서로를 지켜주는 이들과 함께.', 66384),
(295008, 'koKR', '', '당신이 어떤 존재인지 알고 있습니다. 놓아주려 했지만 실패했어요.', 66384),
(295007, 'koKR', '', '당신은 타락했습니다. 공허의 존재죠.', 66384),
(295006, 'koKR', '', '더 끔찍한 실험도 당해봤습니다.', 66384),
(295000, 'koKR', '그래도 우리는 싸워야 합니다. 우리가 서 있는 한, 그 모든 희생은 헛되지 않을 것입니다. 차 덕분에 이 사실을 다시금 떠올릴 수 있었습니다. 진심으로 감사드립니다.', '', 66384),
(294997, 'koKR', '아마니, 스컬지, 불타는 군단... 전 너무 많은 전우들을 잃고, 땅에 묻었습니다.', '', 66384),
(294996, 'koKR', '유령화? 흥미롭네요. 뭐, 위험하면 얼마나 위험하겠어요?', '', 66384),
(294984, 'koKR', '', '그게 다야? 진짜 싸움꾼들을 좀 끌어내야겠군.', 66384),
(294979, 'koKR', '놈들이 우위를 점하게 둘 수는 없지 않겠습니까?', '', 66384),
(294978, 'koKR', '목표물이 이곳에서 힘을 모으고 있습니다. 근원을 파괴하고, 하찮은 수호자들은 피해 가세요.', '', 66384),
(294977, 'koKR', '사냥감이 상처를 핥으며 물러갈 겁니다. 그때 더 깊이 베어 버리세요.', '', 66384),
(294976, 'koKR', '먹잇감에게 방심하고 당해주는 척하세요. 그리고 실수를 후회하게 만들어 주는 겁니다.', '', 66384),
(294975, 'koKR', '훌륭한 공포로군요.', '', 66384),
(294974, 'koKR', '아직 끝내지 마세요. 사냥을 음미하고, 유물이 놈들의 두려움을 삼키게 하세요.', '', 66384),
(294972, 'koKR', '다들 하늘만 보고 있지만, 나는 남쪽에서 뭐가 올라오고 있는지 알지.\n\n빛이 깃든 식물? 트롤? 태양샘이 위태로운 이 와중에?\n\n스스로의 터전을 지킬 힘조차 없다면, 공허를 받아들이고 그 힘을 거머쥐는 게 맞지 않을까?', '다들 하늘만 보고 있지만, 나는 남쪽에서 뭐가 올라오고 있는지 알지.\n\n빛이 깃든 식물? 트롤? 태양샘이 위태로운 이 와중에?\n\n스스로의 터전을 지킬 힘조차 없다면, 공허를 받아들이고 그 힘을 거머쥐는 게 맞지 않을까?', 66384),
(294971, 'koKR', '\"선봉대\"가 데려온 얼라이언스 성기사는 외국 땅에서 내 가족을 죽음으로 몰아넣은 장본인이다.\n\n저 하늘에 끔찍한 게 있다고 해서, 그런 자를 우리의 도시에 들이는 게 말이 된단 말이냐?', '\"선봉대\"가 데려온 얼라이언스 성기사는 외국 땅에서 내 가족을 죽음으로 몰아넣은 장본인이다.\n\n저 하늘에 끔찍한 게 있다고 해서, 그런 자를 우리의 도시에 들이는 게 말이 된단 말이냐?', 66384),
(294970, 'koKR', '빛의 선봉대가 우리의 터전을 떠돌고 있고, 하늘에는 공허가 도래했다. 우리의 혈기사와 마법학자는 영원노래 숲을 지키기에 턱없이 부족하지.\n\n이게 소중한 모든 것의 종말이 아니라면 무엇이란 말인가?', '빛의 선봉대가 우리의 터전을 떠돌고 있고, 하늘에는 공허가 도래했다. 우리의 혈기사와 마법학자는 영원노래 숲을 지키기에 턱없이 부족하지.\n\n이게 소중한 모든 것의 종말이 아니라면 무엇이란 말인가?', 66384),
(294969, 'koKR', '너. 신도레이 놈들이 입을 모아 찬양하는 \"용사\"가 네놈이로군.\n\n저 하늘을 우러러보고도 우리 눈앞으로 다가온 게 파멸이 아니라고 단언할 수 있겠느냐?', '너. 신도레이 놈들이 입을 모아 찬양하는 \"용사\"가 네놈이로군.\n\n저 하늘을 우러러보고도 우리 눈앞으로 다가온 게 파멸이 아니라고 단언할 수 있겠느냐?', 66384),
(294894, 'koKR', '발리라 님, 황혼의 칼날단에서 빠져나오고 싶어 한다는 이교도들이 있다고 합니다. 그런데 도망치다 붙잡힐까 봐 겁에 질려있다고 하더군요.', '', 66384),
(294889, 'koKR', '네 지혜가 널 살렸구나. 내 축복으로 동료의 회복을 도와라. 나나 나네아 말고는 아무 말도 듣지 말라고 전하도록.', '', 66384),
(294888, 'koKR', '현장을 직접 봐야겠습니다.', '', 66384),
(294887, 'koKR', '테르미나스는 쓰러뜨렸지만, 암연지 성채는 여전히 적의 수중에 있습니다. 아스트레, 거긴 안전하지 않을 거예요.', '', 66384),
(294885, 'koKR', '우리 모두 바로잡아야 할 게 있죠. 암연지에서 만나요, $n 님.', '', 66384),
(294883, 'koKR', '전 제가 텔로그러스로 이끈 이들이 마주한 결과를 받아들였습니다. 제가 살아 있는 한, 동족은 제가 책임일 겁니다.', '', 66384),
(294882, 'koKR', '아, 또 만나 뵙는군요. 아닙니다, 이 자와는 이미 수없이 싸워 왔습니다.', '', 66384),
(294874, 'koKR', '위험한 것도 계약의 일부죠. 그래서 전례 없는 이익을 거둘 수도 있는 거고요.', '', 66384),
(294856, 'koKR', '', '도마나르의 소굴이라니, 편안하다고는 말 못 하겠군요. 하지만 훈련은 계속해야 합니다.', 66384),
(294853, 'koKR', '거짓말을 무시해라! 하늘을 보라! 죽음이 임박했다!', '거짓말을 무시해라! 하늘을 보라! 죽음이 임박했다!', 66384),
(294852, 'koKR', '선봉대가 태양샘을 울부짖게 만들고 있다! 그대들은 느껴지지도 않는가!', '선봉대가 태양샘을 울부짖게 만들고 있다! 그대들은 느껴지지도 않는가!', 66384),
(294851, 'koKR', '선봉대는 우릴 버릴 거다! 놈들은 태양샘밖에 몰라!', '선봉대는 우릴 버릴 거다! 놈들은 태양샘밖에 몰라!', 66384),
(294850, 'koKR', '공허가 도래하리라!', '공허가 도래하리라!', 66384),
(294841, 'koKR', '', '전 이만 가볼게요. 이렇게 가족과 함께하는 건 정말 오래간만이고, 아라토르가 얘기하고 싶어 했거든요.', 66384),
(294840, 'koKR', '', '야수들을 처치했으니, 저 혼자서 진영으로 돌아갈 수 있어요.', 66384),
(294836, 'koKR', '조금 천천히 움직이지 그래.', '', 66384),
(294818, 'koKR', '', '황혼의 칼날단. 가면과 빌린 힘 뒤에 숨는 건 다른 교단하고 다를 바가 없군. ', 66384),
(294782, 'koKR', '더 이상 기다리게 하지 않겠다. 넌 자격을 증명했어.', '', 66384),
(294780, 'koKR', '너무 가깝군!', '', 66384),
(294777, 'koKR', '', '명예를 위해. 영광을 위해. 호드를 위하여!', 66384),
(294776, 'koKR', '', '반갑네. 언젠가 전장에서 함께 싸울 날이 오기를 바라네.', 66384),
(294772, 'koKR', '이제 임무로 돌아가야 할 시간입니다. 곧 또 뵙겠습니다. 나중에 은둔자에서 한잔하는 건 어떠신가요?', '', 66384),
(294693, 'koKR', '', '피와 천둥이여! 자네를 여기서 보게 될 줄은 몰랐네.', 66384),
(294692, 'koKR', '', '용사, 이쪽일세! 안 그래도 자네 얘기를 하고 있었네.', 66384),
(294690, 'koKR', '화톳불이 아직 드러나지 않은 운명의 속삭임과 함께 춤추며 당신을 가까이 끌어당깁니다.', '화톳불이 아직 드러나지 않은 운명의 속삭임과 함께 춤추며 당신을 가까이 끌어당깁니다.', 66384),
(294688, 'koKR', '', '나는 전통을 이해하네만, 자네는 명예로운 일을 했네. 자네의 선조들에 대한 존경의 의미로, 더 이상 의식을 방해하지 않겠네.', 66384),
(294686, 'koKR', '', '이 문서를 잃어버렸으면 섭정은 평생 안고 갈 두통이 생겼을 거야.', 66384),
(294685, 'koKR', '', '솜씨가 대단한데, 용사. 다음에도 함께 일할 날을 기대할게.', 66384),
(294684, 'koKR', '저분이 제가 말씀한 분입니다. 이쪽입니다, 용사님.', '', 66384),
(294683, 'koKR', '제게 베푸신 은혜를 생각하면 감사하단 말로는 부족할 겁니다.\n\n$n 님과 함께하게 되어 기쁩니다. 얼라이언스는 의무와 전통을 존중하지만, 명예와 스스로 길을 개척하려는 의지도 존중합니다. 상황에 따라서는 그럴 수도 있으니까요.\n\n앞으로 다시 만날 수 있으면 좋겠군요.', '', 66384),
(294681, 'koKR', '다른 이들은 울부짖는 능선에 모여 있죠? 거기서 만나요.', '', 66384),
(294680, 'koKR', '', '우리 부족의 입회식이 떠오르네. 그 의식은 내게 목적을 주었지만, 지금의 목적과는 달랐지.', 66384),
(294677, 'koKR', '', '딸깍 소리도 안 나고, 독구름도 안 퍼졌네. 훌륭해. 이제 내용물을 보실까.', 66384),
(294676, 'koKR', '', '자물쇠는 내가 맡을 테니, 함정을 처리해.', 66384),
(294643, 'koKR', '', '제법인데, 용사. 이제 놈들의 발톱이 얼마나 깊이 파고들었는지 확인해 보자.', 66384),
(294642, 'koKR', '', '나는 그림자에 숨어 위에서 지켜볼게. 걱정 마. 상황이 반전될 때는 혼자가 아닐 테니.', 66384),
(294641, 'koKR', '', '이 언덕이라면 우위를 점할 수 있어. 헛되게 날리지 말자고.', 66384),
(294627, 'koKR', '', '생존자가 있군요! 아직 늦지 않았어요!', 66384),
(294618, 'koKR', '동료분들이 제 생존 능력을 믿어주시는 건 감사하지만, 적시에 개입해 주신 점이 더 고맙습니다.\n\n저는 의식에 방해되지 않도록 조용히 있겠습니다.', '', 66384),
(294616, 'koKR', '세계의 뿌리에 대해서는 이름 말고는 알려진 게 거의 없다. 함께 더 알아내 보자.', '', 66384),
(294615, 'koKR', '뿌리가 제자리로 돌아온 걸 알면 뿌리감시관이 기뻐하겠어.', '', 66384),
(294613, 'koKR', '루일라는 최초의 뿌리감시관이자 최초의 뿌리방랑자가 되었다.', '', 66384),
(294612, 'koKR', '서약을 굳히기 위해 뿌리들은 자신들의 일부를 내주었고, 루일라 역시 자신의 일부를 바쳤다. 그렇게 세계의 뿌리가 탄생했다.', '', 66384),
(294611, 'koKR', '뿌릿길은 모든 거목을 연결해 아제로스는 물론, 그 너머로 뻗어 있었다.', '', 66384),
(294610, 'koKR', '뿌리들은 이제 루일라를 동료이자 수호자로 여겼다. 그리고 새로운 수호자에게 뿌릿길의 비밀을 보여주었다.', '', 66384),
(294609, 'koKR', '새로운 힘을 얻은 루일라는 독을 몰아내고, 불타버린 땅을 치유하며, 얽힌 매듭을 풀어냈다.', '', 66384),
(294608, 'koKR', '하지만 뿌리도 맞섰지. 둘의 싸움은 육체가 아닌 정신의 영역에서 이뤄졌다.', '', 66384),
(294607, 'koKR', '루일라는 뿌리를 휘어잡아 뜻대로 굽히며, 세계의 령과 이어졌다.', '', 66384),
(294605, 'koKR', '루일라는 야수의 형상을 빌리는 우리의 힘이 뿌리와 이어져 있다는 걸 알아냈다.', '', 66384),
(294604, 'koKR', '루일라와 추종자들은 고향이 파괴되는 걸 가만히 두고 볼 수 없었다.', '', 66384),
(294603, 'koKR', '사냥꾼 루일라는 시들어가는 뿌리를 가장 먼저 알아챘다. 땅이 불타고 독에 물들고 있었지.', '', 66384),
(294602, 'koKR', '초창기에는 아제로스 지상에서 울려 퍼지던 전쟁에 대해 아는 게 거의 없었다.', '', 66384),
(294587, 'koKR', '이건 입회식에서 강한 인상을 남기겠군.', '', 66384),
(294586, 'koKR', '회고의 소굴에 수많은 입회식이 그려지는 걸 봤다. 하나하나가 저마다의 이야기로 자라났지. 네 이야기는 어떤 그림을 보여줄지 궁금하군.', '', 66384),
(294583, 'koKR', '', '가끔은 모험이 그립기도 합니다. 이곳이 우리의 고향이고, 오르웨냐 님과 함께한 여정은 험난했지만 하란다르에서는 결코 볼 수 없는 것들을 보았습니다.\n\n어쨌거나, 그대는 옳은 일을 하고 있습니다. 전통이 무엇보다 먼저여야 합니다.', 66384),
(294582, 'koKR', '하라티 사이에서 자기 자리를 찾는 건 대단한 일이다. 많은 사람이 내가 오르웨냐를 따라 외부 세계로 나간 걸 주목하지만, 그 사람들이 생각하는 그런 여정은 아니었다.\n\n돌아온 이들 중엔 여정에서 상처를 입은 자들이 많았다. 하지만 사람들은 모험 이야기만 들었지.\n\n오늘의 주역은 너다. 회고의 소굴에서 네 여정의 시작을 새기게 될 것이다.', '', 66384),
(294577, 'koKR', '부족에서 성인식을 치르던 때가 아직도 기억나오. 지금은 아미드랏실의 뿌리감시관으로서 일하고 있지만. 오늘은 그대가 하라티 사이에서 맡게 될 자리를 함께 찾아보도록 합시다.', '', 66384),
(294564, 'koKR', '', '자네가 바로 소문으로만 듣던 그 용사로군.\n\n자네가 태양샘에서 활약한 덕택에 내 동족 중 많은 이가 살아남을 수 있었네. 고맙네.\n\n이제 저 엘프들에게 이 전쟁이 도시만을 위한 싸움이 아님을 납득시키기만 하면 되겠군.', 66384),
(294563, 'koKR', '잠깐! 돌아와!', '', 66384),
(294562, 'koKR', '이건 내 목소리인데. 뭐지... 이게 뭐야?', '', 66384),
(294561, 'koKR', '넌 약해. 그리고 이젠 혼자 남았지.', '', 66384),
(294557, 'koKR', '쓰네요. 강렬하고요. 으... 머리야...', '', 66384),
(294553, 'koKR', '잘하셨습니다, 용사님. 포식의 군단에 큰 타격을 입혔군요. 엄브릭의 도움이 컸습니다.', '', 66384),
(294534, 'koKR', '네가 다시 싸우는 모습을 보고 싶구나.', '', 66384),
(294533, 'koKR', '자, 공결탑 제나스에서 유쾌한 향연을 이어 가도록 하지. 목적지에서 만나자.', '', 66384),
(294532, 'koKR', '왜 내가 그 자리에 없었던 거지? 그 사람은 늘 내 곁에 있었는데...', '', 66384),
(294531, 'koKR', '', '선봉대, 챙길 수 있는 무기는 모조리 거둬서 이동한다!', 66384),
(294530, 'koKR', '', '알겠습니다, 대총독님.', 66384),
(294529, 'koKR', '장군, 태양샘에 주둔 중인 병력을 부탁하네. 나는 섭정과 논의할 안건이 있네.', '', 66384),
(294528, 'koKR', '', '그러니 필요한 채비를 모두 갖추고, 적이 뒤를 치지 못하게 막아야지.', 66384),
(294527, 'koKR', '태양샘을 지켜야 하오.', '', 66384),
(294526, 'koKR', '', '하지만 그것만으로도 충분치 않아. 순전히 우리 병력의 믿음이 있기에 태양샘이 겨우 공허를 막아내고 있는 걸세.', 66384),
(294525, 'koKR', '이미 수많은 혈기사를 차출해 태양샘을 강화하는데 투입했잖소! 쿠엘탈라스는 사실상 무주공산이란 말이오!', '', 66384),
(294521, 'koKR', '서로 이름을 묻거나 가벼운 인사조차 나눌 겨를이 없었습니다.\n\n히에론은 암연지 성채에서 생을 마감했습니다. 그의 희생은 많은 이의 목숨을 구했고, 저와 마엘라도 은혜를 입었습니다. 아라토르가 당신을 보낸 건 히에론을 찾기 위해서였지만, 돌아온 건 고인의 일지뿐이었죠.\n\n히에론을 한마디로 표현한다면, 저는 \"믿음직한 사람\"이라고 하고 싶습니다. 언제나 타인을 먼저 생각했고, 특히 아스트레를 아꼈죠. 두 사람은 서로를 진심으로 사랑했습니다.', '', 66384),
(294516, 'koKR', '바라던 대로 공허에 타격을 입혔지만, 그 대가가 너무도 컸습니다.', '', 66384),
(294512, 'koKR', '계속 나아가야 해요. 히에론도 그러길 원했을 거예요.', '', 66384),
(294511, 'koKR', '', '여기가 놈들 첩보망의 심장부인 게 틀림없어.', 66384),
(294510, 'koKR', '', '로르테마르가 비밀리에 처리할 일이 생긴 것 같아. 태양이 가장 짙은 그림자를 드리운다는 걸 잊지 마.', 66384),
(294508, 'koKR', '제 내면의 그 부분과 마주할 필요가 있었어요. 야영지로 돌아가요, $n 님. 해야 할 일이 남아 있어요.', '', 66384),
(294507, 'koKR', '히에론은 떠났지만, 전 아직 여기 있어요.', '', 66384),
(294503, 'koKR', '', '여신께서 말씀하셨네. 그분의 말씀을 통해 자네의 길은 다른 길이라는 것을 알았지.\n\n자네는 여신의 산과 바다, 숲과 사막, 생명체와 문명을 보게 될 걸세. 그분의 피조물을 경험해야만, 비로소 그분을 찾을 수 있을 테니.', 66384),
(294482, 'koKR', '', '나는 주술사 부족 출신일세. 정령의 목소리에 귀를 기울이는 길 대신 검을 잡았지만, 자네의 전통과 의식을 존중하네.\n\n우리도 옴리고르라는 비슷한 통과 의례를 치르지. 어쩌면 우리 종족은 그리 다르지 않을지도 모르네.\n\n언젠가 다시 만나게 된다면 영광일 것 같네. 자네가 하란다르를 떠나 오그리마에 오게 된다면 말일세.\n\n<고개를 끄덕이고 정중히 인사하는 갈트라>', 66384),
(294481, 'koKR', '전 다른 사람들만큼 영적인 사람은 아니라 이런 의식이 크게 와닿지는 않습니다. 드레나이라면 잘 이해할지도 모르겠네요. 드레나이를 아시지요?\n\n하가르와 오르웨냐가 방해하지 않는 한, 당신의 입회가 끝나면 집으로 돌려보내 주겠다고 약속했습니다.\n\n스톰윈드에서는 많은 음식과 음악, 시끌벅적한 소리가 가득한 축제를 엽니다. 맥주도 많이 마시지요. 당신은 가족과 함께 사냥을 나가거나, 아니면 친구들과 함께...\n\n<말을 멈추더니 멋쩍게 웃는 알톤>\n\n아무것도 아닙니다. 이곳도 정말 멋지긴 합니다. 당신들의 문화에 대한 이야기를 듣고 싶어 할 사람이 제 주변에 최소 4명은 될걸요.', '', 66384),
(294478, 'koKR', '자식들은 무사한데... 무슨 조화를 부린 건지 모르겠네요!', '', 66384),
(294475, 'koKR', '가엾기도 하지... 우리가 너무 늦었네요.', '', 66384),
(294474, 'koKR', '<루일라가 옳았습니다. 뿌리들이 죽어가고 있었습니다.\n\n대지의 다른 뿌리와 생명체들처럼, 지상에서 벌어진 전투로 인해 불타거나 중독된 상태였습니다.\n\n루일라는 아제로스에서 비롯된 이 상처로부터 대지를 돕고자 직접 나서기로 결심했습니다.>', '<루일라가 옳았습니다. 뿌리들이 죽어가고 있었습니다.\n\n대지의 다른 뿌리와 생명체들처럼, 지상에서 벌어진 전투로 인해 불타거나 중독된 상태였습니다.\n\n루일라는 아제로스에서 비롯된 이 상처로부터 대지를 돕고자 직접 나서기로 결심했습니다.>', 66384),
(294469, 'koKR', '사로잡힌 렌도레이가 사슬의 연결고리입니다. 고리를 끊어야 진격을 시작할 수 있습니다.', '', 66384),
(294442, 'koKR', '어둠수호병들은 절박한 상황이에요. 아군과 적을 가리지 않고 마나를 흡수해 섞은 뒤, 그 힘으로 장치를 유지하고 있지요.\n\n다행히도 저 혼합물은 위험한 만큼 불안정합니다.\n\n제가 놈들의 기술자에게서 이 소총을 \"빌렸습니다\". 이걸로 쏘면 마나 용기를 불안정하게 만들 수 있을 거예요.', '어둠수호병들은 절박한 상황이에요. 아군과 적을 가리지 않고 마나를 흡수해 섞은 뒤, 그 힘으로 장치를 유지하고 있지요.\n\n다행히도 저 혼합물은 위험한 만큼 불안정합니다.\n\n제가 놈들의 기술자에게서 이 소총을 \"빌렸습니다\". 이걸로 쏘면 마나 용기를 불안정하게 만들 수 있을 거예요.', 66384),
(294440, 'koKR', '훌륭하다. 이제야 진정으로 기억될 만한 검이 되었구나.', '', 66384),
(294409, 'koKR', '방금 들었나요? 곤경에 처한 생명이 있어요. 원정순찰대로서 반드시 도와야 합니다!', '', 66384),
(294407, 'koKR', '', '다 들은 얘기인데, 우린 언제쯤 철이 들려는지.', 66384),
(294406, 'koKR', '거의 끝났다! 네 빛의 선봉대 친구들이 빛의 파편을 남기고 갔더군. 하나 가져오지 않겠나?', '', 66384),
(294404, 'koKR', '모르타카는 봉인됐지만, 그 존재는 지금도 알른의 균열을 괴롭히고 있다.', '', 66384),
(294393, 'koKR', '', '이 초라한 오두막 말인가? 내가 택한 곳일세. 하르마라 공동체의 중심이자, 위대한 텔드랏실의 뿌리 가까이에 있기 때문이지. 텔드랏실과 그 뿌리는 탄생 때부터 수많은 고통과 상처를 견뎌 왔네. 그럼에도 뿌리는 여전히 강하고, 살아가려는 의지를 품고 있지.\n\n밖을 내다보면, 하란다르로 향하던 우리 종족의 고된 여정이 떠오르네. 많은 축복을 뒤로한 채 떠났고, 그 길에서 수많은 이가 쓰러졌지. 그리고 이어진 광기까지...\n\n그럼에도 우리는 여전히 이곳에 있네. 전통이 굳건하듯, 우리 또한 강인하지.\n\n텔드랏실도 마찬가지네. 시간이 지나면 그 뿌리도, 그리고 이 세상 전체도 치유될 걸세.', 66384),
(294391, 'koKR', '가는 내내 찍찍거렸어요. 웃겨서 참을 수가 없더라고요.', '', 66384),
(294390, 'koKR', '이게 다 제 동물적인 매력 덕택이죠.', '', 66384),
(294389, 'koKR', '', '당신을 거의 한 시간이나 따라다녔어요.', 66384),
(294388, 'koKR', '지도에는 이 동굴이 버려졌다고 나와 있었는데!', '', 66384),
(294387, 'koKR', '정말 웃겼잖아요. 인정하셔야죠. 이야깃거리로는 최고였어요.', '', 66384),
(294386, 'koKR', '', '이번엔 성난 비버만 안 만났으면 좋겠네요.', 66384),
(294385, 'koKR', '분명 폭포가 마음에 들 거예요.', '', 66384),
(294382, 'koKR', '공허란 살육과 혼돈, 그리고 폭력이다. 아름답지. 우리 도마나르 중 상당수가 그 아름다움에 형태와 실체를 부여하고 싶어 하는 것도 당연하다.\n\n이 세계는 공허에 깊이 물들어, 대지 자체에까지 스며들었다. 우리는 그걸 다루는 법을 찾아냈다. 공허의 힘으로 땅을 바꾸고, 세계를 빚어내는 것이다.\n\n허구의 힘이 현실을 지배할 때 전해지는 그 만족감은 이루 말로 표현할 수 없지.', '', 66384),
(294381, 'koKR', '전통은 우리를 하나로 묶고, 단단하게 만들며, 야심을 품고 어려움을 굳건히 헤쳐 나가게 해준다네. 우리 자신과의 균형을 지켜 주고, 위협과 결정, 미래를 어떻게 효율적으로 맞이할지 이끌어 주기도 하지.', '', 66384),
(294331, 'koKR', '구도자들은 침묵 속에 앉아 있었다. 그곳에서도 우리는 여신의 노래를 들었다.', '', 66384),
(294330, 'koKR', '그분은 빛 속에 있지 않았다. 빛이 남기고 간 따스함 그 자체였지.', '', 66384),
(294328, 'koKR', '오래된 방패 조각처럼 보이는군요.', '', 66384),
(294308, 'koKR', '도시에 차고 넘치는 오만한 블러드 엘프요. 세도나 더스크스파이어. 과거 히에론과 연이 있는 사람이에요.\n\n히에론은 우리가 실버문에 오기 직전에 편지를 썼어요. 직접 당사자에게 전하고 싶다고 했죠. 차원문을 넘어 공허폭풍으로 들어가기 직전에도 시도했어요.\n\n이젠 아무 의미 없지만요.', '', 66384),
(294301, 'koKR', '그렇군요. 히에론은 떠난 거였네요.', '', 66384),
(294300, 'koKR', '이 임무는 실수였어요.', '', 66384),
(294299, 'koKR', '이 고생을 하고 뒤처지다니. 다른 이들 소식은 없나요?', '', 66384),
(294298, 'koKR', '진정하세요! 매타조는 제멋대로인 데다, 속도도 빠릅니다!', '', 66384),
(294296, 'koKR', '어떤 씨앗을 뿌리신 건가요? 이런 꽃들은 저도 처음 봐요!', '', 66384),
(294284, 'koKR', '결정화된 공허로 칼날의 날을 강화해라!', '', 66384),
(294283, 'koKR', '저는 리 리의 오빠 스싸이라고 합니다. 직접 맞이해 드리지 못한 게 아쉽네요. 이젠 모두 우리만 기다리고 있는 걸까요?\n\n며칠 전 축제를 준비하려고 우송 마을에 갔는데, 가장 중요한 폭죽이 사라졌더군요! 집에 돌아와 찾아봤지만 아직도 못 찾고 있네요. 시간이 얼마 남지 않았으니 그냥 없는 대로 해야 할지도 모릅니다.\n\n<이마의 땀을 훔치는 스싸이>\n\n리 리의 친구를 만나 정말 반갑습니다. 마지막으로 동생을 본 지 오래된 터라, 풀어야 할 회포가 산더미예요. 물론 대부분은 리 리의 이야기를 듣는 시간이겠지만요. 전 집을 떠나 지금은 아침 바람 마을에서 살고 있습니다. 호숫가에 자리한 정말 아름다운 곳이죠.', '', 66384),
(294273, 'koKR', '공허 화로의 불길로 칼날을 달구어라!', '', 66384),
(294272, 'koKR', '공허 저장소에서 힘을 추출해라. 어둠에 담금질하는 거다!', '', 66384),
(294271, 'koKR', '거수의 뼛가루를 공허로 타오르는 검에 뿌려라. 금속이 단단해질 거다.', '', 66384),
(294270, 'koKR', '아누 벨라 벨로레알론, 말래노레.', '', 66384),
(294269, 'koKR', '잘하셨어요! 벌써 식물들이 싹을 틔우고 있네요. 처음 보는 종들도 있군요!', '', 66384),
(294259, 'koKR', '다음에는 지역민한테 부탁해야겠어!', '', 66384),
(294258, 'koKR', '그 불길 앞에서는 누구도 여신의 노래를 들을 수 없었으니까.', '', 66384),
(294257, 'koKR', '오바요는 메아리 없는 불길이 유일한 희망임을 알고 있었다.', '', 66384),
(294253, 'koKR', '하라니르를 해치워라! 하란다르를 부숴라! 모두 불협화음에 합류하리라!', '', 66384),
(294239, 'koKR', '메아리 없는 불꽃을 다시 지필 방법을 모른다니 안타깝군. 그래도 언젠가는 가능할지도...', '', 66384),
(294236, 'koKR', '오바요를 보고 메아리 없는 불꽃에 대해 배울 수 있다니 부럽구나, $p.', '', 66384),
(294235, 'koKR', '오바요는 그 속에서 고통이 아닌 의무를 보았다. 메아리에 흔들리지 않는 몸으로 균열 속에서 어둠을 사냥했고, 자신처럼 희생을 자처하는 이들을 길러냈다.', '', 66384),
(294234, 'koKR', '그러니 당분간은 네가 놈을 기르도록 해라. 그게 성장시키는 가장 좋은 방법일지도 모르니.', '', 66384),
(294233, 'koKR', '하지만 희생된 건 불길만이 아니었다. 오바요는 더 이상 여신의 목소리를 들을 수 없게 됐다. 유대가 불태워져 사라진 게지.', '', 66384),
(294232, 'koKR', '시간이 지나면 피도피쿠스는 공포 그 자체가 될 거다.', '', 66384),
(294231, 'koKR', '흐음, 기쁘구나. 이런 말을 하게 될 줄 몰랐지만, 잘했다, 필멸자여.', '', 66384),
(294230, 'koKR', '용사님! 막 시작하려던 참이었습니다. 실력이 시험에 들겠지만, 그래도 복구할 수 있어요.', '', 66384),
(294229, 'koKR', '그래서 불길을 3개의 수호물로 나눠 야수를 가두었고, 하란다르 전체를 구해냈지.', '', 66384),
(294228, 'koKR', '오바요는 메아리 없는 불길에 남은 힘만으로는 모르타카를 없앨 수 없다는 걸 알았다.', '', 66384),
(294225, 'koKR', '', '$p 님, 처음 십자군을 떠날 땐 의문과 두려움, 불안으로 가득했어요.\n\n인생에서 가장 힘든 결단이었죠.\n\n그런데 지금까지 배운 모든 게, 확신에 찼던 모든 게 잘못됐다는 걸 깨달았습니다.\n\n엘리스가 같은 길을 걷고 있어서 너무 기뻐요.', 66384),
(294224, 'koKR', '', '$p 님, 전 포세이큰과 인간을 이으려다 목숨을 잃었어요. 저는 목숨을 걸 가치가 있는 대의였다고 생각하고, 지금도 추구하고 있죠.\n\n엘리스를 보내 주셔서 감사합니다. 알론서스 님에게도 감사하고 있고요.\n\n배우려는 열의도 크고, 스스로 저지른 잘못을 바로잡겠다는 의지도 강하더군요.', 66384),
(294223, 'koKR', '현신들은 균열의 불협화음에 고통받았지만, 메아리 없는 불길이 안식을 안겨주었다.', '', 66384),
(294222, 'koKR', '', '자비를 베풀어 주신 덕분에 십자군을 떠날 수 있었습니다.\n\n지난 몇 년 동안 의심이 커지긴 했지만, 항상 옆으로 밀어놓기만 했죠.\n\n칼리아, 마리엘라 님과 대화하면서 세상을 완전히 새로운 관점에서 바라보게 됐습니다, $p 님.\n\n추락하는 느낌인데, 또 어떤 의미로는 완전히 해방된 기분입니다.\n\n저분들의 도움을 받으면 더 좋은 자리를 찾아갈 수 있겠죠.', 66384),
(294221, 'koKR', '하지만 모르타카라는 괴물이 균열에서 현신들을 이끌고 나와, 하란다르 전체를 위협했다.', '', 66384),
(294220, 'koKR', '하라니르는 늘 알른의 균열을 피해 왔다. 여신의 노래가 어긋나 울려 퍼지며 광기를 불러왔고, 그 안의 폭력적인 현신들은 죽음을 몰고 왔다.', '', 66384),
(294219, 'koKR', '', '발밑 조심해요! 다른 둘이 모으는 것들을 싸매려고 어스름잎을 채집하는 중이에요.\n\n샤오말이라면 진작 계획을 다 세웠겠죠. 늘 그랬으니까요. 하지만 지금은 없어요. 그러니 이제 제 몫이에요.\n\n<잠시 말을 멈추는 나옐리>\n\n샤오말을 데려올 거예요. 어떤 일이 있어도요. 그리고 같이 와주셔서 기뻐요... 우린 서로가 필요하거든요.', 66384),
(294218, 'koKR', '', '아! 기척을 못 느꼈는데... 순간 꽃잎날개인 줄 알았네요.\n\n저는 불꽃잎이랑 속삭임꽃을 채집하고 있었어요. 향은 달콤하지만, 잘 태우면 반응 속도를 높여주거든요.\n\n제가 이런 섬세한 일을 잘한다고 샤오말이 항상 칭찬해 줬어요... 돌아오면 좋겠네요. 보고 싶으니까요. 그래서 무섭더라도 돕고 있는 거예요.', 66384),
(294215, 'koKR', '쳇, 그렇게 불쑥 다가오지 마세요! 발광뿌리를 떨어뜨릴 뻔했잖아요.\n\n이 식물들이요? 기운을 조금 북돋아 줘요. 거대한 깃털 야수가 돌아오면 도움이 될 것 같아서요... 물론 무섭다는 건 아니고요. 다만... 누군가는 대비해야 하니까요.\n\n샤오말은 항상 우리를 챙겨줬어요. 그러니 이제는 우리가 샤오말을 챙겨줄 차례예요. 안 그래요?', '', 66384),
(294214, 'koKR', '이제 둘 다 썩 물러가라! 내 앞에 설 자격은 없다.', '', 66384),
(294213, 'koKR', '야수 놈에게 힘이 조금이라도 있었다면 차라리 직접 삼켜 버렸을 텐데!', '', 66384),
(294211, 'koKR', '그딴 보잘것없는 벌레에 내 시간을 낭비하다니, 내가 어리석었지!', '', 66384),
(294209, 'koKR', '뭐라고?', '', 66384),
(294202, 'koKR', '2차 대전쟁은 수십 년 전에 끝났습니다. 우리가 피 흘려 얻은 평화를 무너뜨리게 두지 않겠습니다.', '', 66384),
(294201, 'koKR', '암흑 호드가 국경 정착지를 습격할 준비를 하고 있네. 마지막 방패 파편을 확보하고, 병력을 해산시키게.', '', 66384),
(294192, 'koKR', '', '빛만개가 끈질기니, 우리 또한 그러해야 하네.', 66384),
(294191, 'koKR', '', '정밀 타격? 모두를 부를 걸 그랬군.', 66384),
(294190, 'koKR', '안 돼애애애... 이대로 끝일 거라 생각 마라!', '', 66384),
(294186, 'koKR', '말해 봐라... 놈은 끔찍했느냐? 사나웠느냐? 치명적이었나?', '', 66384),
(294185, 'koKR', '', '이걸 타면 곧장 아래로 내려갈 수 있네. 하지만 빛만개에 오래 노출시킬 순 없어.', 66384),
(294184, 'koKR', '', '여신을 향한 믿음이 증오로 바뀌었구나. 빛만개가 이렇게 만드는 건가?', 66384),
(294183, 'koKR', '', '내가 뿌릿길을 막겠네. 두 번 다시 도망치지 못할 거야.', 66384),
(294182, 'koKR', '빛만개가 하라니르를 올바른 모습으로 되돌릴 수 있다. 하지만 네가 내 앞길을 가로막는군.', '', 66384),
(294181, 'koKR', '', '루이아가 여기 있다고?', 66384),
(294180, 'koKR', '빛만개는 통제할 수 없다. 영원히 억누를 수도 없지.', '', 66384),
(294177, 'koKR', '', '루이아가 여기 숨었단 말이지...', 66384),
(294175, 'koKR', '우리 정원에 침입한 대가를 치러라. 빛만개가 대가를 받아 갈 것이다.', '', 66384),
(294174, 'koKR', '', '심상치 않군. 놈들이 주입을 끝내기 전에 반드시 부숴야 하네.', 66384),
(294173, 'koKR', '안두인 로서가 전사한 뒤, 아버지는 얼라이언스를 규합해 승리를 쟁취했습니다.', '', 66384),
(294172, 'koKR', '제 아버지, 투랄리온도 이 전투에 참전했습니다. 하지만 그 이야기를 들려주신 적은 거의 없습니다.', '', 66384),
(294171, 'koKR', '', '큰 공격은 빛만개를 더 퍼지게 할 뿐이지. 가장 위험한 것들만 골라 솎아내는 게 옳네.', 66384),
(294170, 'koKR', '', '알른가루는 한정돼 있네. 그러니 빛만개가 가장 심한 곳부터 줄여야 하네.', 66384),
(294169, 'koKR', '암흑 호드 역시 이 전투로 깊은 상처를 입었습니다. 여기 남아 한참 전에 진 전쟁을 이어 나가고 있죠.', '', 66384),
(294167, 'koKR', '여기 있었군! 파올, 우릴 왜 이런 황량한 땅으로 데려온 건가?', '', 66384),
(294166, 'koKR', '나는 데시무스를 위해 딱히 일을 하진 않는다. 그저 지켜보고 있을 뿐이지.\n\n우리 도마나르는 끊임없이 힘을 두고 다툰다. 네 눈에는 보이지 않을지라도, 우리는 늘 지위를 놓고 경쟁하고 있다.\n\n데시무스의 성역은 내가 괴수 무리를 키우는 데 필요한 자원을 제공한다. 그 대가로 내 괴물들이 데시무스를 지켜 주는 것이지. 그래서 지금은 동맹일 뿐이다.\n\n하지만 이 관계가 달라질 건 분명하다. 데시무스도 그 사실을 잘 안다.\n\n도마나르보다 더 무서운 건, 수많은 발톱과 송곳니를 거느린 도마나르뿐이다.', '', 66384),
(294164, 'koKR', '새끼들을 맞붙게 하는 건 결국 폭력과 괴물을 낳게 마련이지!\n\n하지만 너희 필멸자들은 다른 방식을 말하더군. 이른바... 애정이라고 하던가. 나도 한 번 시험해 볼까 싶구나.', '', 66384),
(294163, 'koKR', '이제 \"정복\"을 보여다오!', '', 66384),
(294162, 'koKR', '\"흉포함\"을 보여다오!', '', 66384),
(294161, 'koKR', '그게... 이건 제 방패가 아닙니다.', '', 66384),
(294160, 'koKR', '일리 있는 말일세, 젊은이. 훌륭한 방패는 언제나 병사를 지켜 주고, 그 병사는 다른 이를 지키지.', '', 66384),
(294158, 'koKR', '우린 누구나 꺾일 수 있습니다. 하지만 다시 일어나 스스로를 다잡는다면 더 강해질 수도 있죠.', '', 66384),
(294157, 'koKR', '쳇! 끔찍한 생각이로군! 내가 들어 본 것 중 최악일세.', '', 66384),
(294156, 'koKR', '이런 결말은 예상하지 않았지만, 지금 생각하면 꽤 잘 어울리는 헌사일지도 모르겠군.', '', 66384),
(294155, 'koKR', '음... 곰곰이 생각해 봤습니다. 이 방패를 이곳 벽에 걸어 두고 싶습니다. 늘 마음에 새기기 위해서요.', '', 66384),
(294147, 'koKR', '피도피쿠스가 지톡의 시체 위에서 승리의 포효를 내지릅니다.', '', 66384),
(294145, 'koKR', '피도피쿠스는 이제 스스로를 증명할 준비가 됐다. 남쪽에 있는 야수의 소굴에서 우리가 길러낸 야수성을 직접 보아라.', '', 66384),
(294139, 'koKR', '참 대단한 곳입니다, $p 님.\n\n여정 내내 함께해 주셔서 감사합니다.\n\n많은 이를 도왔고, 그 과정에서 저 자신도 치유받았습니다.', '', 66384),
(294132, 'koKR', '피도피쿠스가 작은 물집벌레들을 향해 자신만만하게 포효합니다.', '', 66384),
(294120, 'koKR', '이게 너희 필멸자들이 말하는... 우정이란 건가? 그런 거면 좋겠는데.', '', 66384),
(294119, 'koKR', '이상하게도 네가 점점 더 궁금해지는군. 나 또한 네가 날 알기를 바라고.', '', 66384),
(294118, 'koKR', '우서의 유물을 내게 맡긴 건... 마지막 치유의 기회가 될지도 모르겠소.', '', 66384),
(294117, 'koKR', '그 후로 나는 최선을 다해 빛을 섬겼지만, 내가 겪은 고통의 잔재와 실망은 여전히 날 따라다닌다오.', '', 66384),
(294116, 'koKR', '', '전 그분의 일대기를 듣고 빛의 길을 걷기로 마음먹었어요. 직접 뵌 적은 없지만 소중히 간직할게요, $p 님. 고맙습니다.', 66384),
(294115, 'koKR', '', '아무리 대장이라고 해도 직접 몸을 움직여야 할 때가 있기 마련이죠.', 66384),
(294113, 'koKR', '', '이렇게 하지, 하수인이여. 100년이 지나도 이 계약이 못마땅하다면, 그때 조건을 바꿀 기회를 주마.', 66384),
(294112, 'koKR', '', '$p 님, 마라아드 님은 저희 종족의 영웅이에요. 그분의 빛이 느껴져요. 아직 이 수정에 남아 있군요.', 66384),
(294111, 'koKR', '피도피쿠스가 렌도레이를 향해 사납게 몸짓합니다.', '', 66384),
(294109, 'koKR', '', '$p 님, 잘 지내셨어요? 물론 맡은 일이 산더미시겠죠.\n\n솔직히 저는... 이제 한계까지 온 것 같아요.', 66384),
(294108, 'koKR', '$p, 난 수년간 아서스를 가르쳤다는 이유로 우서를 원망해 왔소. 그런데 정작 우서는 날 용서했지. 낯을 들기 어렵구려.', '', 66384),
(294106, 'koKR', '$p, 태양샘에 거대한 악이 들이닥친 건 이번이 처음이 아니오. 이 몸은 지쳤지만, 그때처럼 견뎌낼 것이오.', '', 66384),
(294105, 'koKR', '', '나도 그 이상은 바라지 않아. 하지만 누가 주인인지 잊지 마. 열등한 형체로 한동안 머무르게 하면 기억이 날지도 모르겠군.', 66384),
(294104, 'koKR', '', '감사해요, $p 님. 검의 마력이 느껴지네요. 잘 사용하겠습니다.', 66384),
(294101, 'koKR', '', '솔직하게 말할게요, $p 님. 태양샘에 있다는 건 정말 큰 영광이지만, 무척 피곤하기도 해요.\n\n혹시 좋은 소식은 없나요? 도움이 더 온다든지?', 66384),
(294098, 'koKR', '건방진 엘프 같으니! 내가 반드시 돌아와 네 최후를 지켜보겠다!', '', 66384),
(294097, 'koKR', '', '네 기백에 찬사를 보내마, 칼고르그. 그래서 내게로 돌아오라고 하는 거야.', 66384),
(294096, 'koKR', '네가 이겼다고 생각하느냐? 나는 영원하다! 나는 공허다! 너희는 하찮은 필멸자일 뿐이다!', '', 66384),
(294092, 'koKR', '규칙은 간단해요. 숨은 사람을 찾으면 협곡 끝에 가서 기다리는 거죠. 간단하지 않나요?\n\n<표정이 날카로워지는 샤오말>\n\n시작할 준비는 되셨나요?', '', 66384),
(294091, 'koKR', '피도가 멈춰 서더니, 뾰족한 뼈 앞에서 움츠러듭니다.', '', 66384),
(294081, 'koKR', '', '거기 있었군, 태민! 다른 녀석들을 먼저 보낼 뻔했잖나!', 66384),
(294080, 'koKR', '일을 마치면 다시 야수들 곁에서 만나자.', '', 66384),
(294071, 'koKR', '', '이제 와서 바보 같은 생각 마, 블록치니우스.', 66384),
(294063, 'koKR', '<당신을 매섭게 노려보는 칼고르그>', '', 66384),
(294058, 'koKR', '그렇지 않기를 바라지만... 어쨌든 우리의 임무는 영원노래 숲을 지키는 것입니다.', '', 66384),
(294057, 'koKR', '하지만 몰락 이후로, 야수들은 긴 세월 동안 아무도 보지 못했습니다. 어쩌면 다른 동족과 죽었을지도 모르죠.', '', 66384),
(294054, 'koKR', '옛 순찰자들은 숲의 수호자였습니다. 숲을 거닐던 수많은 신비한 야수, 전설과 어깨를 나란히 했죠.', '', 66384),
(294053, 'koKR', '저는 그 오래된 이야기들에 끼고 싶었어요. 그래서 이 길을 택한 거랍니다. 한번 보세요.', '', 66384),
(294052, 'koKR', '원정순찰대가 도서관을 갖고 있다고는 생각 못 하셨겠지만, 이들도 신도레이만큼이나 오래된 역사를 가지고 있어요.', '', 66384),
(294043, 'koKR', '야수에게 먹이를 준 뒤, 능선을 함께 돌며... 지배력을 발휘할 수 있게 해라.', '', 66384),
(294042, 'koKR', '재료는 탁자에 올려 두었다. 요리도, 먹이는 것도, 그 후에 돌보는 일까지도 네가 맡아야 한다.', '', 66384),
(294037, 'koKR', '', '이익...! 하늘유리 모으는 게 살짝 늦어질 것 같네요...!', 66384),
(294035, 'koKR', '', '쿠리, 네 정신은 높이 살만해. 자랑스럽구나. 그렇지만 다음부터는 처음 보는 사람에게 랩터 잎사귀 모으는 걸 시키지 말렴. 알았지? 다음 주에는 두 배로 모아야 한다.', 66384),
(294034, 'koKR', '', '우리의 고향은 경이로 가득해요. 모든 게 특이하고 오래됐다고요! 알른샤란도 틀림없이 존재할 거예요. 부르는 방법만 알아내면 돼요!', 66384),
(294033, 'koKR', '', '첫 번째 시도가 실패한 거지, 알른샤란이 실존하지 않는다는 얘기가 아니잖아요! 제가 놓친 게 있는 거라고요.', 66384),
(294032, 'koKR', '', '실망? 그럴 리가요!', 66384),
(294031, 'koKR', '', '너무 실망하지 말려무나, 얘야. 수수께끼와 전설은 원래 까다로운 거란다.', 66384),
(294029, 'koKR', '', '...잠깐, 이게 끝이라고? 마, 말도 안 돼! 이번엔 확실했는데...', 66384),
(294028, 'koKR', '', '보세요! 진짜 효과가 있어요!', 66384),
(294020, 'koKR', '빙글 포자!', '', 66384),
(294019, 'koKR', '야성의 균류! 독성의 회오리! 버섯 용사 중의 용사!', '', 66384),
(294018, 'koKR', '균류와 균사여, 큰 버섯이 온다!', '', 66384),
(294015, 'koKR', '', '오셨군요! 자, 조각을 웅덩이에 던져 넣으세요!', 66384),
(294013, 'koKR', '<피도피쿠스가 낮은 울음소리를 냅니다. 덩치만 작지 않았어도 꽤 위협적으로 느껴졌을 것입니다.>', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(294007, 'koKR', '<작은 거수가 당신을 올려다봅니가. 영양분 가득한 간식을 애타게 바라고 있습니다.>', '', 66384),
(294006, 'koKR', '준비되면 말씀해 주세요!', '', 66384),
(293986, 'koKR', '훌륭합니다! 고요한 안식처로 찾아오세요. 매타조를 준비해 드리겠습니다.', '', 66384),
(293982, 'koKR', '', '제 곁에 있어요. 어둠의 성물함으로 강화해 드릴게요. 이 불복종을 좌시할 수 없어요.', 66384),
(293980, 'koKR', '', '와... 실감이 안 나네요. 제 조모님이세요. 스톰윈드를 벗어나 로데론으로 향하던 피난민을 지키셨죠.', 66384),
(293978, 'koKR', '', '이 진균이 뭐든, 가장 큰 하수인들은 가까이에 두고 있을 거다. 방심하지 마라.', 66384),
(293977, 'koKR', '', '좋은 소식을 가지고 돌아오셨기를 바라요, $p 님. 모두 지쳐가고 있어요.\n\n아까 파올 님의 지팡이로 강화를 받지 않았다면 일찌감치 실패했을지도 몰라요.', 66384),
(293976, 'koKR', '', '불태워라, $c. 퍼지기 전에 불태워야 한다.', 66384),
(293975, 'koKR', '', '조심해라. 불길한 예감이 든다.', 66384),
(293967, 'koKR', '', '빛만개가 버섯전사를 사로잡고 있다고? 루타니만 해도 충분히 골칫거리인데.', 66384),
(293953, 'koKR', '끝난 게 아니다! 아직 안 끝났어!', '', 66384),
(293952, 'koKR', '끝난 건가?', '', 66384),
(293929, 'koKR', '이 땅은 본래의 모습과는 많이 다르지만, 예전보다는 훨씬 나아졌습니다.\n\n조금씩 보살피면 생명은 소생하더군요.', '', 66384),
(293886, 'koKR', '', '주위를 감도는 공허를 느껴보세요, $n 님. 칼고르그가 이 힘을 차지하도록 놔둘 수는 없어요.', 66384),
(293840, 'koKR', '파올, 다 생각이 있는 것이길 바라네.', '', 66384),
(293839, 'koKR', '이 방패를 고쳐서 보여드리면 아버지가 이상으로 삼았던 성기사의 모습을 다시 떠올리실지도 모릅니다.', '', 66384),
(293837, 'koKR', '얼라이언스... 투랄리온... 모든 게 한순간에 변했네.', '', 66384),
(293829, 'koKR', '젊은 친구가 방패 파편을 모두 모았나? 이제 시작할 수 있겠군.', '', 66384),
(293824, 'koKR', '재료는 내가 가마솥까지 가져가겠다. 하지만 요리는 네 몫이다.', '', 66384),
(293820, 'koKR', '궁정의 환심을 사려면 마음이 가는 초대장을 고르시오. 단, 경고하리다. 신도레이는 홀대를 결코 달가워하지 않소.', '', 66384),
(293819, 'koKR', '아, 신도레이 정치가 절정을 이루는 광경이란. 참으로 장관이지 않소?', '', 66384),
(293793, 'koKR', '', '추종자들이 투기장으로 몰려오고 있다!', 66384),
(293792, 'koKR', '', '조심해라. 관중들이 야유만 던질 것 같진 않거든.', 66384),
(293791, 'koKR', '그리고 어떤 짐승들은 여신이 떠나며 남긴 공허를 채우려 탐욕에 잠식됐다.', '', 66384),
(293790, 'koKR', '또 어떤 생명체들은 여신의 노래를 잊고, 뒤따른 침묵만을 들었다.', '', 66384),
(293789, 'koKR', '어떤 생명체들은 그분과 조화를 이루어 노래했지.', '', 66384),
(293788, 'koKR', '생명체들은 그분이 머물던 자리를 기억했다.', '', 66384),
(293787, 'koKR', '', '제 동생은 성가신 방해를 받으면 신경이 곤두서요. 땅과 하늘을 모두 정리해 주세요.', 66384),
(293778, 'koKR', '하! 살데릴이 골목 사람을 초대했다고요? 물건 팔아 돈 좀 챙길 수도 있겠네요. 참석하겠습니다.', '', 66384),
(293777, 'koKR', '난 이런 방식이 몹시 못마땅하오. 그러나 혈기사단이 이 전쟁을 치르려면 자원이 필요하니, 일단 진행하리다.', '', 66384),
(293776, 'koKR', '', '태민을 돕고 계십니까? 그 친구가 좋아할 만한 시구가 몇 구절 들어 있던데요.', 66384),
(293775, 'koKR', '', '초대가 없었더라도 자리에 나갔을 겁니다. 귀족계에서 이런 놀음은 여러 번 해봤거든요. 짐을 챙기죠.', 66384),
(293774, 'koKR', '전부터 되찾으려고 한 거네요! 어떻게든 야전 조리로 해야죠.', '', 66384),
(293773, 'koKR', '', '고맙습니다! 새끼들 훈련시키느라 책 볼 시간이 전혀 없었거든요!', 66384),
(293765, 'koKR', '', '전쟁 채권 모금 행사인가요? 좋아요. 원정순찰대 예산에 귀족 돈 좀 넣는 것도 나쁘지 않겠죠. 잠깐은 어울려 드릴 수 있어요.', 66384),
(293764, 'koKR', '뭘 원하는 거야? 다 죽었다. 더 해치우고 싶으면 나중에 와라.', '', 66384),
(293758, 'koKR', '이 시련을 통과한 외부인은 단 한 명도 없었다. 알른하라의 손길을 받았다는 말이 사실일지도 모르겠군.', '', 66384),
(293757, 'koKR', '이건 아버지의 방패지요? 어쩌다 부서진 겁니까?', '', 66384),
(293748, 'koKR', '살려주셔서 감사합니다! 잠깐... 이것 좀 내려놓고, 도서관에서 뵐게요.', '', 66384),
(293746, 'koKR', '', '비전은 나를 갈망한다!', 66384),
(293745, 'koKR', '던러너 대장님이 마법사를 원정순찰대로 받아주신 건 큰 도전이었죠.\n\n뛰어야 할 일도 생각보다 훨씬 많고, 무거운 것도 들어야 하고, 흙도 많아요!\n\n그래도 절대 낙오하지 않겠습니다!', '', 66384),
(293737, 'koKR', '아, 그리고 죽음의 골목으로 보낸 초청장은 실수가 아니오. 나는 극적인 연출의 영원한 추종자니 말이외다.', '', 66384),
(293736, 'koKR', '본디 신도레이의 정치는 섬세함을 요하오. 아슬아슬한 줄타기는 우리에게 본능과도 같으니 말이지.', '', 66384),
(293733, 'koKR', '좋은 판단이오, 누미아. 나가에게 사용해 보시오. 힘을 빼앗을 수 있을지도.', '', 66384),
(293732, 'koKR', '', '지팡이가 곧바로 비전 마력을 받아들이는군요...', 66384),
(293731, 'koKR', '우리의... 상인들에게도 건배합시다. 신중한... 판단의 대가이자, 영원노래 숲의 수호자들에게! 아누 벨로레 델래나!', '', 66384),
(293730, 'koKR', '원정순찰대에게 건배합시다. 자연의 보호자이자, 영원노래 숲의 수호자들에게! 아누 벨로레 델래나!', '', 66384),
(293729, 'koKR', '혈기사들에게 건배합시다. 빛의 굳건한 신자이자, 영원노래 숲의 수호자들에게! 아누 벨로레 델래나!', '', 66384),
(293728, 'koKR', '마법학자들에게 건배합시다. 비전의 대가이자, 영원노래 숲의 수호자들에게! 아누 벨로레 델래나!', '', 66384),
(293727, 'koKR', '', '배은망덕한 짐승 같으니! 계약을 깨뜨릴 수 있다고 생각해? 쫓아가세요!', 66384),
(293724, 'koKR', '', '칼고르그는 이 세계에 들어왔을 때부터 제 말을 거역하기 시작했어요. 희생시키는 걸 도와주세요. 이젠 쓸모없으니.', 66384),
(293721, 'koKR', '', '새로운 발견 하나하나가 변형물을 제거하고 환경의 균형을 복구하는 데 보탬이 됩니다.', 66384),
(293714, 'koKR', '앗, 조심해라! 부식줄기가 싸우러 왔다!', '', 66384),
(293713, 'koKR', '잊지 마라, 넌 악당이다. 관중을 화나게 해라.', '', 66384),
(293712, 'koKR', '그건 우리가 밝혀내야 할 일이다. 사냥은 긴 여정이 될 때도 있으니.', '', 66384),
(293707, 'koKR', '', '놈들이 보이느냐? 마을에서 첩자들을 몰아내라!', 66384),
(293706, 'koKR', '', '할라지는 사냥의 로아다. 그리고 샤드라는 경쟁자지. 샤드라를 사냥한다면 그 또한 관심을 보일 터.', 66384),
(293690, 'koKR', '이런 완벽한 마법봉을 누가 버리는 걸까요? 마법학자들 기준이 그렇게 까다롭나?', '', 66384),
(293687, 'koKR', '불안정한 비전력... 저희가 찾던 게 틀림없습니다!', '', 66384),
(293680, 'koKR', '내 눈엔 시원하게 부숴 버리기 좋은 기회 같네. 원한다면 나도 함께하지.', '', 66384),
(293679, 'koKR', '산속 오크들이 파편만 쥐고 있던 게 아니더군. 무기도 잔뜩 쌓아 두고 있었어.', '', 66384),
(293669, 'koKR', '싸움꾼에는 두 부류가 있다. 무대 위 영웅, 그리고 몰래 노리는 악당. 영웅은 관중의 환호를 받지. 악당은 야유를 받는다.\n\n영웅이 되고 싶다고? 안 돼, 영웅은 재미없어! 환호가 너무 많으면 싸움이 시시해진다.\n\n이제 넌 악당이다. 나쁘게 굴어라. 관중을 화나게 해라.', '', 66384),
(293665, 'koKR', '', '니자 톤터스크가 웃으며 동의한다는 듯 고개를 끄덕입니다.', 66384),
(293664, 'koKR', '맞는 말이야. 우리의 로아와 함께라면, 단순한 저항에서 끝나지 않을 수 있네!', '', 66384),
(293663, 'koKR', '', '모두 힘을 합쳐 썩은가지에 맞서야 해.', 66384),
(293662, 'koKR', '여긴 다르네. 마른나무껍질은 예전에도 그랬고, 앞으로도 자네의 동맹일 걸세. 우리도 모두를 안전하게 지키기 위해 최선을 다하고 있어. 썩은가지야말로 우리의 진정한 적이네.', '', 66384),
(293661, 'koKR', '', '아니. 난 동부 내륙지에서 왔다. 마른나무껍질이 깨진엄니를 사냥하던 곳에서 말이야. 이곳 마른나무껍질이 옛 방식을 고수하는지, 우리 피난민이 진정으로 안전한 건지 확인할 생각이었어.', 66384),
(293660, 'koKR', '니자. 우리 마을에 무슨 일로 왔는지 궁금한 참이었네. 샤드라 때문인가?', '', 66384),
(293659, 'koKR', '', '나도 가겠다, $n.', 66384),
(293658, 'koKR', '샤드라 님. 마른나무껍질은 다시 당신과 함께하게 되어 영광입니다.', '', 66384),
(293657, 'koKR', '벌써 거미줄을 엮고 있군!. 역시 기대를 저버리지 않아. 줄아만에 온 걸 환영한다, 샤드라.', '', 66384),
(293656, 'koKR', '', '흠. 할 일이 많구나. 부활할 시기를 잘 골랐군.', 66384),
(293655, 'koKR', '알이 형성되었네!', '', 66384),
(293654, 'koKR', '부화를 도와주게. 조심해야 하네!', '', 66384),
(293653, 'koKR', '충직한 마른나무껍질과 깨진엄니에게 돌아와 주십시오!', '', 66384),
(293652, 'koKR', '샤드라여, 당신의 송곳니와 눈, 껍질을 다시 하나로 모았습니다.', '', 66384),
(293651, 'koKR', '저기 중앙에 서서 세 가지 의식 물품에 집중하게.', '', 66384),
(293650, 'koKR', '샤드라는 내가 잘 아는 로아다. 죽음을 맞는 순간까지 동부 내륙지의 마른나무껍질을 보살피며 무기를 강화해 주고, 자손들의 수많은 눈을 통해 지혜를 나눠 주었지. 하지만 안타깝게도... 필멸자들에게 자주 이용당하며 성정이 사나워졌다. 내 신자들을 도와 썩은가지에 맞서는 걸 돕는다면 여기 머무는 걸 기꺼이 환영할 생각이다.\n\n거미 로아는 지금은 작지만 빠르게 자랄 거다. 내가 샤드라를 지켜보겠다. 홀로 고된 세월을 버텨 왔고, 학대도 많이 받았어. 이젠 샤드라의 힘이 올바른 길로 나아가도록 이끌 것이야.', '', 66384),
(293648, 'koKR', '네 사냥은 끝났다.', '', 66384),
(293640, 'koKR', '', '바로 그런 말을 듣고 싶었어. 원정순찰대 초소에 들른 뒤 다시 찾아가겠다.', 66384),
(293637, 'koKR', '원정순찰대의 자랑이 되겠습니다, 대장님!', '', 66384),
(293634, 'koKR', '', '태민, 자네 임무는 더 어려울 거야... 하지만 그 비전 재능은 남쪽 탑에서 매우 유용하게 쓰일 테지.', 66384),
(293618, 'koKR', '', '마이사라 깊은 곳에서 내 껍질을 되찾아라. 함께 썩은가지를 벌하리라.', 66384),
(293617, 'koKR', '', '혐오스러운 썩은가지가 내 자손들과 나의 귀환을 방해하고 있다.', 66384),
(293616, 'koKR', '', '아, 나의 마른나무껍질 아니더냐. 깨진엄니까지 있군. 흥미롭도다.', 66384),
(293615, 'koKR', '', '샤드라여! 제발 이야기를 들어 주십시오.', 66384),
(293614, 'koKR', '', '시작할 준비가 되면 알려주십시오.', 66384),
(293612, 'koKR', '선게이즈 대장님이 보냈습니까? 아, 틀림없이 애가 타고 계실 겁니다.\n\n근데 제가 알아낸 걸 전하면, 대장님 마음이 더 무거워지실 것 같네요.\n\n나가가 여러 곳에서 비전력을 모아 이곳에 쌓아 두고 있습니다... 일부는 힘을 불리는 데 쓰지만, 대부분의 비전력은 바다 너머로 실려 나가고 있습니다.\n\n어디로, 누구에게 가는지는 두고 봐야 알 수 있을 것 같습니다.', '', 66384),
(293611, 'koKR', '저, 저, 제가 큰 잘못을 저질렀어요!\n\n이 어두운 시기에 다 끝장이라고... 나가가 살아남을 길을 쥐고 있을 거라 생각했거든요.\n\n그런데 그 작자들은 힘을 나눌 생각이 전혀 없었어요. 이제야 알겠어요. 왜 절 살려둔 건지는 모르겠지만... 제발, 구해주세요!', '', 66384),
(293610, 'koKR', '', '하지만 눈도 필요하네. 이제 샤드라에게 닿을 수 있기를 바라야지.', 66384),
(293609, 'koKR', '', '로아가 듣고 있네!', 66384),
(293608, 'koKR', '', '아! 절 보셨다면 제 은신 물약 효과가 떨어지고 있는 모양이군요. 이만 가봐야겠어요. 그래도 먼저 찾아주셔서 다행이에요.\n\n녀석들의 비전력을 훔쳐 왔어요. 물론 조사를 위해서죠. 이 정도면 충분할 거예요.', 66384),
(293607, 'koKR', '', '썩은가지 놈들이 아직 샤드라를 소환할 수 있다는 걸 눈치채고 우릴 막으려고 하는 것 같네. 아니면 훔쳐 가려는 걸지도 모르지!', 66384),
(293606, 'koKR', '', '썩은가지가 지금껏 악행을 저질렀다는 점에는 동의한다. 로아와 얘기해 보자.', 66384),
(293605, 'koKR', '', '자쿨 님은... 하라니르 최고의 화가 중 한 분이셨습니다. 워낙 까다로우셔서 제자를 거의 두지 않으셨는데, 제게 재능이 보인다고 하셨어요.\n\n어릴 때부터 함께 지내면서 하루 종일 물감을 섞고 성화를 그리는 법을 배웠죠.\n\n스승님은 떠나셨는데... 아직 배워야 할 게 너무 많아요. 혼자서 어떻게 이어가야 할지 모르겠습니다.', 66384),
(293602, 'koKR', '늦었잖아! 어서 출근 찍어!', '', 66384),
(293577, 'koKR', '다른 사람은 없었습니다. 거의 모든 성기사가 성스러운 빛에 이끌려 태양샘으로 향했으니까요.\n\n다리온은 제게 빚이 있었습니다. 절 죽이고 티리온 님의 시신을 자신의 기사단으로 만들려 했으니 말입니다.\n\n무엇보다 다리온 역시 공허가 아제로스를 지배하는 모습은 절대 보고 싶지 않아 합니다.\n\n그래서 제가 도움을 청했을 때, 칠흑의 기사단이 주저 없이 나서주었습니다.', '', 66384),
(293491, 'koKR', '', '하르쿠아이에서 다시 만나요. 날아다니는 뱀을 불러보자고요!', 66384),
(293446, 'koKR', '구하기 어려운 걸 찾으시나요? 제대로 찾아오셨습니다.', '', 66384),
(293444, 'koKR', '', '약속은 하고 오셨나요? 업무 시간은 내일 저녁부터인데.', 66384),
(293442, 'koKR', '', '<여인이 처음엔 매섭게 훑어보더니, 이내 옅은 미소를 지어 보입니다.>\n\n방어구 멋지네요.\n\n누구 찾으세요? 제가 지금 순찰대원들이 용매 길들이는 걸 돕고 있거든요. 잠깐은 시간 낼 수 있겠네요.', 66384),
(293440, 'koKR', '용건이 있으면 빨리 말하시오. 일정이 촉박하니.', '', 66384),
(293437, 'koKR', '', '썩은가지가 납골당을 습격해 닥치는 대로 훔치고 있네! 내가 설명해 줌세...', 66384),
(293416, 'koKR', '살데릴 경께 빨리 오시라고 말씀드리겠습니다.', '', 66384),
(293408, 'koKR', '', '서두르십시오! 서쪽 전선을 사수해야 합니다!', 66384),
(293407, 'koKR', '', '적이 동쪽에서 몰려옵니다!', 66384),
(293406, 'koKR', '', '북쪽 방어선이 공격받고 있습니다!', 66384),
(293405, 'koKR', '', '남쪽 방어선이 압박받고 있습니다!', 66384),
(293398, 'koKR', '자네들에게 완전히 솔직하지 못했네.', '', 66384),
(293395, 'koKR', '', '이 특이점 고정기로 공허 변형물을 잠시 봉인할 수 있습니다. 고정기가 충전될 동안 지켜야 합니다.', 66384),
(293393, 'koKR', '', '장치를 잃었습니다. 재정비 후 준비하십시오. 곧 다시 시도할 겁니다.', 66384),
(293392, 'koKR', '', '특이점 고정기가 심각하게 손상되었습니다. 더는 버티기 힘듭니다!', 66384),
(293391, 'koKR', '', '적을 몰아내십시오. 특이점 고정기가 공격받고 있습니다!', 66384),
(293390, 'koKR', '', '적이 옵니다. 특이점 고정기를 지키십시오!', 66384),
(293385, 'koKR', '일단... 파수꾼 가동에 집중합시다.', '', 66384),
(293384, 'koKR', '제 어머니이신 알레리아 님이야말로 공허와 싸우는 법을 누구보다 잘 아는 분인데... 몇 주째 뵙지 못했습니다. 부디...', '', 66384),
(293383, 'koKR', '대총독 투랄리온은 뛰어난 전장 지휘관입니다. 다만... 종종 그 외의 모습을 망각하실 때가 있습니다.', '', 66384),
(293382, 'koKR', '조금 전 아버지가 언행은 용서해 주십시오. 사실 저희가 항상 뜻이 맞는 건 아니라서요.', '', 66384),
(293379, 'koKR', '', '이제 더 퍼져 나가 다른 곳을 위협하지 못할 걸세.', 66384),
(293378, 'koKR', '', '사나운 루타니들이 만개하는 격자를 뒤덮었네. 가지를 쳐야겠어.', 66384),
(293339, 'koKR', '', '전부 똑같은 곳으로 도망치고 있군. 어디인지 알아보자.', 66384),
(293336, 'koKR', '아, 당신이 그렇게 금방 죽게 두지는 않을 겁니다.', '', 66384),
(293335, 'koKR', '은밀함은 당신의 강점이 아니군요?', '', 66384),
(293334, 'koKR', '너무 쉽게 붙잡히지 마세요. 저는 이 순간을 오래 즐기고 싶습니다.', '', 66384),
(293325, 'koKR', '샤드라의 숨겨진 눈을 보는 힘을 주겠다.', '', 66384),
(293324, 'koKR', '', '조용히 해.', 66384),
(293322, 'koKR', '빛에 삼켜진 잡초를 없애 주세요.', '', 66384),
(293321, 'koKR', '무슨 뜻인지 아시겠죠, $p 님.', '', 66384),
(293320, 'koKR', '잔혹한 빛의 하수인 같으니. 대가를 받아내야 해요! 몰래 숨어다니며 물고기를 겁주다니!', '', 66384),
(293319, 'koKR', '이번엔 최고로 신선하게 준비했어요!', '', 66384),
(293315, 'koKR', '해충들을 몰아내지 않으면 제 명성이 땅에 떨어지고 말 겁니다!', '', 66384),
(293310, 'koKR', '', '세계수는 크게 손을 보지 않아도 번성해. 하란다르는 세계수의 뿌리들이 자라기에 완벽한 터전이지. 그래도 가뭄이나 기생충을 위시한 여러 위험 요소가 생겨나곤 해.\n\n이건 세계수뿐만 아니라 우리 하라니르를 위한 일이기도 해. 우리 존재의 목적을 되새기고, 고향의 중요성을 잊지 않게 하지. 우리는 목숨을 걸고라도 이곳을 지킬 거야. 이 책무가 우리를 넘어 닿는다는 걸 아니까.', 66384),
(293309, 'koKR', '회수한 무기에서 빛을 끌어내십시오! 저 괴물을 공허로 쫓아내야 합니다!', '', 66384),
(293306, 'koKR', '', '자네는 어둠 속의 봉화일세. 어떤 대가가 따르든 우리는 반드시 승리할 것이야.', 66384),
(293305, 'koKR', '게다가 빛의 축복을 받은 강철 기갑전투복이 용기를 북돋워 주고 있지 않나.', '', 66384),
(293303, 'koKR', '할머니께서 가르쳐 주셨지. 아무리 가망이 없어 보여도 옳은 싸움은 끝까지 하고, 빛을 믿으라고 말일세.', '', 66384),
(293295, 'koKR', '', '생각이 너무 좁군. 잘아타스를 쓰러뜨리려면 선봉대의 모든 힘이 필요해.', 66384),
(293291, 'koKR', '', '당신이 병력을 재배치한 탓에 태양샘에 힘을 불어넣을 인원은 극소수만 남았습니다!', 66384),
(293281, 'koKR', '내가 암흑 호드의 수장을 찾아냈어. 그녀가 마지막 파편을 가지고 있네.', '', 66384),
(293280, 'koKR', '파올 님이 왜 절 이곳에 데려오셨을까요? 성물에 대해 아직 말씀하지 않은 게 있는 게 분명합니다.', '', 66384),
(293279, 'koKR', '저는 2차 대전쟁을 책으로만 배웠습니다. 하지만 여기 계신 분들께는 단순한 역사가 아니죠. 직접 겪었으니까요.', '', 66384),
(293277, 'koKR', '내 사냥용 창은 함부로 건드리지 말게. 교훈을 얻고 싶은 거면 또 모를까. 굼벵이 바위굴에서 얻은 독을 촉에 발라놨거든.', '', 66384),
(293276, 'koKR', '내 전리품을 감상하고 있나? 어리석은 와일드해머 드워프들이 우리 마을을 습격했을 때 얻은 거다. 남부에서 줄아만으로 올 때까지 계속 갖고 있었지!', '', 66384),
(293275, 'koKR', '', '우리가 동부 내륙지에서 도망쳐 나올 때, 나는 준와타의 조제법과 유물 몇 가지를 가져왔네. 하지만 이곳의 재료는 그곳과 극명하게 달라.', 66384),
(293273, 'koKR', '이보게, 내가 그 친구 계략을 망치길 바라나? 평생 투덜대는 소리를 듣게 될 텐데.', '', 66384),
(293272, 'koKR', '이게 파올 님의 세 번째 교훈이군요. 나이도 많은 양반들이 무슨 오지랖을 꾸민 건지.', '', 66384),
(293270, 'koKR', '', '우리는 하란다르에 살 수 있어 축복받았고, 그건 책임이기도 해. 세계수의 뿌리가 이 땅을 휘감고 있으니, 계속 번성하도록 돌봐야 하지.\n\n나는 놀드랏실의 책임 간호사 시에나야. 이 책무를 매우 진지하게 받아들이고 있지.', 66384),
(293267, 'koKR', '', '이건 샤드라알로에 있던 샤드라의 송곳니가 아닌가! 그런데 걱정이군. 썩은가지가 어떻게 손에 넣었을까? 안전하게 감춰져 있어야 하는데.', 66384),
(293266, 'koKR', '', '이 맹독이 토착 개구리들한테서 나왔다고? 이 표본으로 해독제를 만들 수는 있네. 하지만 이 송곳니는...', 66384),
(293265, 'koKR', '', '어디 보자...', 66384),
(293263, 'koKR', '마른나무껍질은 약과 치유 물약 못지않게 독과 맹독을 꼼꼼하게 연구해 왔네.', '', 66384),
(293259, 'koKR', '', '톨바니의 복수다.', 66384),
(293258, 'koKR', '할라지가 보냈나?', '', 66384),
(293257, 'koKR', '혼합사 자만가를 찾아가 보게. 동부 왕국 전역의 독에 대해 해박하니까.', '', 66384),
(293246, 'koKR', '여신께서는 돌아오지 않았다. 하지만 그분의 흔적은 남아, 기억하는 이들을 위해 고요 속에서 꽃피었다.', '', 66384),
(293245, 'koKR', '우린 노래를 매개체 삼아 불렀지만, 여신은 대답하지 않았다. 하지만 그분이 남긴 무언가가 응답했지. 그리고 그걸로 충분했다.', '', 66384),
(293242, 'koKR', '그들이 따른 건 길이 아니라, 감정의 메아리였다.', '', 66384),
(293241, 'koKR', '돌에 여신의 노래가 메아리쳤지만, 이번에는 달랐다. 그 안에서 노래가 일렁이며, 그 선율을 나누고자 갈망했다.', '', 66384),
(293239, 'koKR', '마른나무껍질은 썩은가지와 황혼의 칼날단에 맞서 꿋꿋하게 버티고 있네... 하지만 전력은 이미 지칠 대로 지쳐 있어.', '', 66384),
(293238, 'koKR', '구도자들은 여신의 귀환을 부르짖지 않았다. 그들은 조용히 기억이 머무는 곳에서 듣고 기다렸다.', '', 66384),
(293234, 'koKR', '', '마을에서 길을 따라오는데 숲속에 몸을 순긴 자에게 습격을 당했네. 신종 맹독을 시험한다는 소리를 얼핏 들은 것 같아.\n\n곧이어 다키가 무언가에 맞아 제대로 걷지 못했네. 그래서 최대한 빨리 이곳으로 데려왔지.', 66384),
(293233, 'koKR', '마지막 파편입니다. 누구 것인지 알 것 같습니다.', '', 66384),
(293232, 'koKR', '그분이 이런 걸 짊어지고 다녔다니 의아하네요.', '', 66384),
(293231, 'koKR', '우리가 찾던 파편입니다. 아마 갑옷이나 방패의 일부였던 것 같군요.', '', 66384),
(293219, 'koKR', '', '연못은 남쪽에 있어요. 행운을 빌어요, $c님.', 66384),
(293196, 'koKR', '엘로르타 노 샤드라는 고대의 로아였다. 샤드라는 거미의 여왕이었고, 잔달라에게 죽은 걸로 알고 있었지.\n\n샤드라는 줄아만에서 크게 숭배받은 적이 없었다. 남쪽으로 간 아마니 무리들이 샤드라를 찾아내 섬겼지. 썩은가지가 샤드라를 숭배하는지는 모르겠다. 아마 이 송곳니가 샤드라의 것인지조차 몰랐을 수도 있다.\n\n하나, 만에 하나라도 알고 있었다면... 그건 심각한 문제다. 샤드라의 귀환을 막는 게 목적이거나, 아니면 제 뜻대로 뒤틀려는 심산일 터. 샤드라의 독이 썩은가지 수중에 들어가면 끔찍할 일이 벌어질 거다.\n\n샤드라가 육신은 연약했을지 몰라도, 독만큼은 절대 얕잡아봐선 안 됐거든.', '', 66384),
(293194, 'koKR', '썩은가지가 계속해서 내 스라소니와 마른나무껍질을 공격하고 있다.', '', 66384),
(293192, 'koKR', '상태가 괜찮아진 것 같으면 마을로 돌아가거라.', '', 66384),
(293190, 'koKR', '맹독이 좀 가라앉는 것 같아. 분명 이 자리에 있고 눈으로 볼 수 있는데, 입 밖으로 말이 안 나오더군. 움직일 수도 없었고!', '맹독이 좀 가라앉는 것 같아. 분명 이 자리에 있고 눈으로 볼 수 있는데, 입 밖으로 말이 안 나오더군. 움직일 수도 없었고!', 66384),
(293137, 'koKR', '', '차나가 미소를 짓습니다.', 66384),
(293136, 'koKR', '개구리 맹독은 거미 맹독처럼 강하진 않지만, 그래도 나쁘진 않지...', '', 66384),
(293135, 'koKR', '맹독사술사 락시스가 활기차게 콧노래를 흥얼거립니다.', '', 66384),
(293124, 'koKR', '', '적이 서쪽 방어선을 위협하고 있습니다. 지원이 필요합니다!', 66384),
(293121, 'koKR', '', '적이 북쪽에서 공격해 옵니다, 용사님! 경계를 늦추지 마십시오!', 66384),
(293116, 'koKR', '', '적이 동쪽에 집결하고 있습니다. 그쪽 방어를 강화하십시오!', 66384),
(293107, 'koKR', '', '강 건너 경건한 계곡에서 보세.', 66384),
(293098, 'koKR', '각오 단단히 하십시오, 용사님.', '', 66384),
(293084, 'koKR', '아, $c님. 다가올 전투를 준비 중이십니까?', '', 66384),
(293083, 'koKR', '개조를 서둘러 마치게. 그렇지 않으면 다 같이 숨 막혀 죽을 걸세! 저쪽 공기는 우리 조모님 양고기 스튜보다 더 걸쭉하다고.', '', 66384),
(293075, 'koKR', '물론, 당신이 잡아야 하고요.', '', 66384),
(293070, 'koKR', '', '녀석은 태어난 날부터 누나 말을 무시해 왔다.', 66384),
(293068, 'koKR', '아쉽네요! 요 까다로운 물고기들이 당신에게 정을 붙이고 있나 봅니다.', '', 66384),
(293067, 'koKR', '확실히 훌륭한 물고기군요. 그래도 더 나은 걸 잡을 수 있었을 텐데요.', '', 66384),
(293066, 'koKR', '만약 내 임무로 이곳에서 멀리 떠나야 한다면 어떻게 하겠나?', '', 66384),
(293055, 'koKR', '', '당신의 동생은 명령을 어긴 게 한두 번이 아닙니다. 가족이라는 건 알지만, 그에 따른 책임은 져야 하지 않겠습니까?', 66384),
(293054, 'koKR', '', '줄자라가 깊은 한숨을 내쉽니다.', 66384),
(293036, 'koKR', '쿠르드란이 검은바위 첨탑 입구로 날아갔네. 다음 파편을 찾아낸 모양이야.', '', 66384),
(293035, 'koKR', '암흑 호드가 전리품처럼 내걸고 있어. 그게 뜻하는 건 오직 상실뿐인데 말이야.', '', 66384),
(293032, 'koKR', '', '하하하! 고맙다, 리아드린. 네가 없었으면... 아니, 내 두 하쉬우라가 없었으면 여기까지 오지도 못했을 거다.', 66384),
(293030, 'koKR', '', '태도 말인가? 도끼 들고 가서 협박하는 걸 날로라크가 곱게 받아줄 거라 생각하진 않겠지?', 66384),
(293029, 'koKR', '자네가 우리 삶의 방식이 얼마나 중요한지 알았더라면 시키는 대로 했을 게야. 너무 젊어서 그런 걸까. 너무나도 순진한 게지. \n\n뭐, 상관없네. 전통과 의식이 자네를 진정한 하라니르로 빚어줄 테니.\n\n이제 외부인과 접촉하게 된 만큼, 우리의 전통은 어느 때보다 중요해졌네. 외부인의 사상과 이상은 우리 삶의 방식에 위협이 돼.', '', 66384),
(293027, 'koKR', '', '빛은 $n 자네를 위한 계획을 안배해 두셨네. 나는 알아.', 66384),
(293026, 'koKR', '나는 그 어떤 신도 못지않게 빛을 경배한다네, $n.\n\n그러면서도 무거운 갑옷을 걸치고 전쟁 병기를 끌고 다니지.', '', 66384),
(293023, 'koKR', '자네의 길은 달라. 우리는 옛 방식을 지킬 걸세. 자네의 길은 전통을 잇는 길은 아니지만, 우리의 미래로 이어지는 길 중 하나라네. 잘 지내게. 여신이 자네의 여정을 인도하길.', '', 66384),
(293020, 'koKR', '이거면 되겠죠?', '', 66384),
(293019, 'koKR', '아, 하나 더! 어디 보죠.', '', 66384),
(293017, 'koKR', '안녕하세요! 다시 뵙게 되어 정말 반갑습니다!\n\n원정순찰대 훈련은 만만치 않았어요. 긴 도보 훈련, 조용한 감시, 그리고 대지를 듣는 법을 익히는 시간들까지요. 하지만 모든 게 자연스럽게 느껴져요. 걸음을 옮길수록 진정한 제 자신에 가까워지는 느낌이에요.\n\n이 길을 볼 수 있게 도와주셔서 감사해요.', '', 66384),
(293015, 'koKR', '저는 수십 년 동안 실버문을 위해 일해 왔어요. 원정순찰대원이었고, 마법학자를 보좌했으며, 수많은 수련생의 길잡이였죠.\n\n지금은 수석 교관으로서 누군가의 길을 정해주는 게 아니라, 그들의 영혼이 부르는 길을 찾아갈 수 있도록 인도하는 게 제 임무예요. 각 길은 저마다 다른 걸 요구하고, 저는 모든 길을 조금씩 걸어봤기에 어떤 자질이 필요한지 알 수 있어요.\n\n영웅을 만들어내는 게 아니라, 그들 안에 이미 있는 힘을 스스로 알아보게 돕는 거예요.', '', 66384),
(293013, 'koKR', '', '그야 그렇죠. 하지만 젠체하는 \"고킨예\" 엘프의 격식 있는 인사를 받는 것도 탐탁지 않게 여길 겁니다.', 66384),
(293012, 'koKR', '', '달니르의 방식이 거칠게 느껴질 수 있겠지만, 사실 그럴 만한 이유로 전통을 지키고 있네. 의식을 계속 진행하며 우리 종족의 방식을 따르도록 하게. 이건 오르웨냐가 의식을 치를 때 해준 조언이기도 하네.', 66384),
(293011, 'koKR', '자꾸 한눈을 파는군. 자네의 입회식이 무엇보다 우선이네. 전통이 있었기에 하란다르는 다른 땅이 전쟁에 휘말릴 때에도 번영할 수 있었지.', '', 66384),
(293010, 'koKR', '', '당신의 동기는 선량합니다. 이제 태도만 조금 다듬으면 되지 않을까요.', 66384),
(293009, 'koKR', '', '남은 건 마지막 시련뿐이다. 아니, 정말 그뿐일까? 무엇이 하셰이를 만드는 걸까? 내가 우리 종족을 도울 수 있을까?', 66384),
(292997, 'koKR', '저리 가라, 덩치만 큰 양배추야!', '', 66384),
(292996, 'koKR', '', '나한테 도끼가 없는 걸 다행으로 알아라, 짐승!', 66384),
(292992, 'koKR', '', '하지만 가장 암담했던 순간에 선량한 의도로 빛을 찾았을 때, 빛은 제게 응답했습니다.', 66384),
(292991, 'koKR', '이렇게 찾는 것도 재밌단 말이죠. 구경거리를 주십시오. 학살 말입니다.', '', 66384),
(292990, 'koKR', '사소한 실수 하나로 결착이 났네요. 한심한 저항을 관둔 걸 후회하게 해주십시오.', '', 66384),
(292989, 'koKR', '아주 가까이 왔습니다. 사냥감의 두려움이 느껴지십니까? 전 느껴집니다. 황홀하군요.', '', 66384),
(292987, 'koKR', '제 마법이 사냥감의 은신처를 드러냈습니다. 피로 물들이세요.', '', 66384),
(292986, 'koKR', '아, 쥐새끼가 헐떡이며 멈춰 섰군요. 갈기갈기 찢어 버리세요.', '', 66384),
(292985, 'koKR', '', '저는 빛을 당연한 권리인 양 여겼습니다. 그게 제 실수였죠.', 66384),
(292983, 'koKR', '아, 신입! 오늘은 자네가 큰 걸음을 내딛는 날이네.', '', 66384),
(292964, 'koKR', '', '하지만 진심으로 임한 영적 여정이라면, 성공이든 실패든 그 자체로 의미가 있다고 생각합니다.', 66384),
(292963, 'koKR', '어서 오세요, $n 님. 발걸음에 뚜렷한 목적이 담겨 있네요. 오늘은 무슨 일로 오셨어요?', '', 66384),
(292958, 'koKR', '원정순찰대는 정말 우아합니다. 숲속을 마치 하나 된 듯이 움직이죠.\n\n자연과의 연결, 우리 동족을 지키는 방식은... 정말 대단합니다.\n\n강인함과 섬세함 사이를 절묘하게 오가며 조용히 움직이되, 단 한 번도 흐트러짐이 없다는 점이 늘 감탄스러웠어요.', '', 66384),
(292957, 'koKR', '혈기사들은 용맹하고, 자부심이 강하며, 의무를 절대 저버리지 않습니다.\n\n그들은 어떤 희생을 치르더라도 실버문을 지키기 위해 태양샘의 힘을 이끌어냅니다.\n\n그들의 강인함과 명예는 저에게 큰 영감을 줍니다. 진정한 수호자란 무엇인지 몸소 보여주는 존재들이에요.', '', 66384),
(292956, 'koKR', '마법학자들은 정말 대단합니다. 비전 마법을 자유자재로 다루며, 마법을 마치 숨 쉬듯 다스리죠.\n\n그들이 보여주는 절제와 지성, 거대한 마력을 주저 없이 통제하는 모습은 늘 경외심을 불러일으켜요.\n\n그들이 아는 것의 일부라도 배울 수 있다면, 저는 그걸로도 충분히 행운이라고 생각할 거예요.', '', 66384),
(292955, 'koKR', '', '그... 뭐라 할 말이 없군요. 잘 모르겠습니다.', 66384),
(292951, 'koKR', '', '원정순찰대는 쿠엘탈라스의 눈이자 칼날입니다. 눈에 띄지 않게 움직이고, 신속하게 베며, 위험이 닥치기 전에 우리 동족을 지켜냅니다.\n\n전쟁이 문 앞에 오기를 기다리는 일은 없습니다. 우리는 자연에서 먼저 맞서고, 전쟁이 시작되기도 전에 끝을 냅니다. 뛰어난 실력과 본능, 그리고 필요할 때 홀로 걷겠다는 의지가 필요하죠.\n\n하지만 각오가 있다면, 초록과 금빛이 어우러진 방어구를 입는 것보다 더 큰 자부심은 없을 것입니다.', 66384),
(292942, 'koKR', '혈기사는 실버문의 방패이자 검이오. 우리는 의무와 힘, 명예로 맺어진 존재요.\n\n태양샘의 힘을 휘둘러 종족을 수호하는 선택받은 자들이며, 그 길은 훈련과 희생, 그리고 스스로를 지킬 수 없는 이들을 위해 싸우는 굳건한 의지의 길이오.\n\n이 길을 걷고자 한다면, 내면과 외부의 모든 시련을 맞이할 각오부터 하시오. 혈기사의 충성과 힘은 언제나 시험받는 법이니.', '', 66384),
(292941, 'koKR', '', '당신이 잔알라이의 시련을 치르는 모습을 보며 불안했습니다. 괜찮습니까?', 66384),
(292940, 'koKR', '', '괜찮다. 짐을 덜어낸 것 같지만, 또 다른 무게가 대신 자리 잡은 기분이군.', 66384),
(292938, 'koKR', '마법학자들은 비전 마법의 진정한 학자이자 대가이며, 실버문의 마법적 운명을 이끄는 역할을 맡고 있습니다.\n\n우리는 마법의 흐름을 다듬고, 그 엄청난 힘을 다뤄 우리 동족을 보호하고 지식을 넓혀 나갑니다. 단순히 주문을 사용하는 자들이 아니라, 고대의 비밀을 지키는 자이며, 지성과 절제에 바탕을 둔 길을 걷습니다.\n\n마법학자의 길을 걷는다는 것은 세상을 이루는 힘을 통제하고, 지식을 끝없이 추구하겠다는 다짐입니다.', '', 66384),
(292934, 'koKR', '', '놈들이 선봉대 장교들을 납치하고 있습니다, 용사님. 단순히 굶주려서일까요, 아니면 잘아타스가 정보를 모으는 걸까요?', 66384),
(292922, 'koKR', '', '선봉대 군복 조각... 장교 휘장까지... 역시 예상대로군요.', 66384),
(292921, 'koKR', '', '아라토르가 보냈나요? 마침 일손이 하나 더 필요하긴 했어요.', 66384),
(292908, 'koKR', '용사님, 잠시만요. 아마니 고개에서 있었던 일은 어머니께 말씀드리지 말아 주십시오.', '', 66384),
(292907, 'koKR', '', '동지들을... 실망시키고 말았구나...', 66384),
(292904, 'koKR', '아주 오래전, 아마니 제국은 줄아만을 둘러싼 모든 땅을 지배했네. 훗날 자네들이 동부 내륙지와 아라시 고원이라 부르게 된 곳이지.\n\n그곳에 정착지가 있었네... 하지만 줄진이 죽고 로아와의 소통이 단절되면서,내 어린 형제들은 동부 내륙지와 아라시 고원으로 돌아가 옛 땅을 되찾으려 했지. 예전의 삶으로 돌아가려고 말이야. 우리 모두 마른나무껍질이지만 이제는 서로 극명하게 다른 길을 걷고 있네. 심지어 다른 로아를 섬기고 있지.\n\n얼마 전에는 동부 내륙지의 사촌 중 일부가 쫓겨났네. 일부는 피를 좇아 아라시 고원에서 전쟁만 일삼는 동족에게 합류했고, 평화를 원하는 이들은 이곳 줄아만으로 돌아왔지.', '', 66384),
(292901, 'koKR', '응어리의 구덩이는 싸움 구경하기 가장 좋은 곳이야!', '', 66384),
(292850, 'koKR', '', '저는, 어, 여기서 망볼게요. 먼저 가세요. 하늘유리를 찾으면 크게 외치세요. 바로 따라갈 테니까요!', 66384),
(292834, 'koKR', '선봉대가 신념을 안고 돌격했고, 부상당한 병사들은 이곳으로 이송되고 있습니다.', '', 66384),
(292830, 'koKR', '용사님, 마운틴피스트 지휘관에게 보고하십시오. 기갑전투복 공격에 함께해 주신다면 영광입니다.', '', 66384),
(292824, 'koKR', '', '몇 주 내내 샙터 잎사귀만 모으게 생겼네...', 66384),
(292823, 'koKR', '아, 뿌리감시관님...!', '', 66384),
(292822, 'koKR', '', '너희 둘 다 따라오너라. 너희들이 어질러놓은 건 여행자님이 정리해 주실 거야. 우리 존경심에 관한 이야기를 나눠보자꾸나.', 66384),
(292811, 'koKR', '', '어서 오게, $n.\n\n오늘은 자네에게 매우 뜻깊은 날이네. 우리 사회의 일원으로서 자리를 잡고, 여신의 뜻을 따르며 전통을 지키는 데 힘을 보태게 될 테니까.', 66384),
(292810, 'koKR', '어... 아, 안녕하세요, 뿌리감시관 카마리 님.', '', 66384),
(292809, 'koKR', '', '쿠리, 기다려! 아, 이런. 또 시작이군.', 66384),
(292808, 'koKR', '', '알른샤란은 진짜 있어! 내가 너희 모두한테 증명할 테니 두고 봐!', 66384),
(292807, 'koKR', '', '쿠리가 분노에 차 씩씩거립니다. 쿠리의 눈가에 눈물이 그렁그렁 맺힙니다.', 66384),
(292806, 'koKR', '정신 차려, 쿠리! 알른샤란 같은 건 없어!', '', 66384),
(292805, 'koKR', '', '싫어! 너 같은 건 하늘유리를 갖고 놀면 안 돼. 애초에 아직도 무슨 하늘을 날아다니는 도마뱀이 떨어뜨리는 줄 알잖아!', 66384),
(292804, 'koKR', '', '아, 얘들아! 돌려줘! 하늘조각은 내 거란 말이야!', 66384),
(292793, 'koKR', '비전 능력을 끌어올리는 제 비결이요? 양파랑 바나나즙이에요!', '', 66384),
(292785, 'koKR', '마법학자 엄브릭에게서 소식을 전해 들었소. 공허폭풍으로 향하는 길이 열렸소!', '', 66384),
(292773, 'koKR', '', '여기 있었군. 작은 새 몇 마리쯤은 무섭지 않지? 괜찮다고? 좋아.', 66384),
(292771, 'koKR', '', '용사, 이제 자네의 이야기를 그려낼 시간이네.', 66384),
(292770, 'koKR', '선율? 외부인? 이런 잡된 것들이 용사의 정신을 더럽힌 게로군!', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(292769, 'koKR', '', '나도 들었네.', 66384),
(292768, 'koKR', '', '여신이시여!', 66384),
(292767, 'koKR', '방금 그 선율은 뭐였지?', '', 66384),
(292764, 'koKR', '', '그래도 자네 입회식이 끝날 때까지는 안전할 걸세.', 66384),
(292763, 'koKR', '', '나는 외부인을 찾으러 가겠네.', 66384),
(292759, 'koKR', '꽤 괜찮네요, $n. 제 형제를 도와줘서 고마워요.\n\n다음에는 저도 같이 즐기게 해주세요!', '꽤 괜찮네요, $n. 제 형제를 도와줘서 고마워요.\n\n다음에는 저도 같이 즐기게 해주세요!', 66384),
(292758, 'koKR', '다른 사람이라면 하지 못했을 일을 해냈어. 네게 목숨을 빚졌다.\n\n우리 길이 다시 교차하길 바라지.', '', 66384),
(292757, 'koKR', '너는 엔리안을 도왔다. 무엇보다 균열 문제를 해결하는 데 힘을 보탰지.\n\n감사를 전한다, $n.', '', 66384),
(292754, 'koKR', '균열은 치명적인 교훈을 주지. 이로써 너는 더 현명해졌다.', '', 66384),
(292753, 'koKR', '죄송합니다, 아마라크 님. 제가 제정신이 아니었습니다.', '', 66384),
(292752, 'koKR', '엔리안은 아직 의식 때문에 너무 약해. 좀 더 기다려야 했거늘.\n\n이래선 틀림없이 모르타카에게 죽을 거다.', '', 66384),
(292751, 'koKR', '', '용사, 환영을 따라가게. 마음을 따르게나. 여신을 찾는 걸세.', 66384),
(292750, 'koKR', '', '전통에는 여신의 노래를 따라야 한다고도 정해져 있네, 달니르.', 66384),
(292749, 'koKR', '안 돼! 전통에 따라 우린 하란다르에 머물러야 하네!', '', 66384),
(292748, 'koKR', '', '이방인, 노래, 오늘 이곳에서 있었던 일 모두...', 66384),
(292747, 'koKR', '', '뿌릿길을 열어두게, 오르웨냐.', 66384),
(292745, 'koKR', '뭐지?', '', 66384),
(292743, 'koKR', '그게 너와 알른의 균열의 유대다. 그걸 따라가면 돼.', '', 66384),
(292742, 'koKR', '시작할 준비는 다 됐습니다.', '', 66384),
(292741, 'koKR', '의식 장소를 찾았구나, 엔리안.', '', 66384),
(292738, 'koKR', '파올! 그대와 동료들이 무슨 일로 망치 주둔지에 온 것이오? 설마 세상이 또다시 멸망하려는 것은 아니겠지?', '', 66384),
(292734, 'koKR', '균열 속 작은 틈새들이 커지기 전에 파괴해야 해.', '', 66384),
(292721, 'koKR', '이쪽이 제가 말한 $p입니다.', '', 66384),
(292711, 'koKR', '내 남동생 추아가 실수로 알른의 균열에 들어갔어. 내가 들어가서 구했지만, 정신을 잃고 쓰러졌지.\n\n정신을 차려 보니 추아는 사라졌지만 무사했어. 다행히 술카 중 한 분이 날 구해줬고, 내 스승님이 되어 주셨지.\n\n하지만 난 균열에 너무 오래 머물렀어. 알른하라와의 연결이 강해져서, 균열의 노래가 날 광기로 내몰 거야. 그냥 바깥에 나오는 것만으로는 벗어날 수 없어.\n\n그래서 여신과의 연결을 끊어야만 해.\n\n여신의 노래를 듣지 못하게 되면 어떻게 동족에게, 동생에게 돌아갈 수 있겠어? 그래서 술카의 일원이 되어 균열 속에서 하란다르를 광기로부터 지켜내려고 해.', '', 66384),
(292709, 'koKR', '', '쉿! 둘 다 조용히 하게! 그리고 거기, 이방인. 이리로 오게.', 66384),
(292708, 'koKR', '', '저들은 옳은 일을 했네.', 66384),
(292707, 'koKR', '이번엔 정신을 집중하게!', '', 66384),
(292704, 'koKR', '무슨 용건인가?', '', 66384),
(292688, 'koKR', '엔리안 상태가 좋지 않아 보였어요. 도와줘야 해요.\n\n제발 찾아 주세요, $n 님.', '엔리안 상태가 좋지 않아 보였어요. 도와줘야 해요.\n\n제발 찾아 주세요, $n 님.', 66384),
(292684, 'koKR', '도와줘서 고마워요, $n. 당신이 최고예요!\n\n<속삭이듯 은밀하게 말하는 아이>\n\n엔리안을 만나러 몰래 나가는 건 아무한테도 말하지 말아 주세요.', '도와줘서 고마워요, $n. 당신이 최고예요!\n\n<속삭이듯 은밀하게 말하는 아이>\n\n엔리안을 만나러 몰래 나가는 건 아무한테도 말하지 말아 주세요.', 66384),
(292683, 'koKR', '', '여신이시여, 눈앞에 놓인 신비와 결코 외면할 수 없는 진실을 마주할 용기를 주소서.', 66384),
(292682, 'koKR', '', '이곳에서는 그분의 목소리가 크게 들리네. 너무도... 두려움에 차 있지. 늘 이랬던 걸까?', 66384),
(292681, 'koKR', '', '아크셈이 여신에 대한 추측을 버려야 한다고 한 건 무슨 뜻이었을까? 너무나 끔찍한 진실이라 숨겨야만 하는 걸까?', 66384),
(292679, 'koKR', '', '물과 정수를 준비하세. 준비가 되면 이곳에서 다시 만나세.', 66384),
(292678, 'koKR', '안 그랬으면 전 죽었을 겁니다.', '', 66384),
(292676, 'koKR', '', '내 생명의 은인이야.', 66384),
(292674, 'koKR', '용사! 자네는 곧장 이곳으로 왔어야지. 외부인 일에 끼어들 게 아니라.', '', 66384),
(292670, 'koKR', '여기서 죽는 줄로만 알았습니다. 구해 주셔서 감사합니다!', '', 66384),
(292669, 'koKR', '', '고맙네, 이방인. 목숨을 빚졌군.', 66384),
(292666, 'koKR', '회고의 소굴로 와서 입회를 마무리하게.', '', 66384),
(292663, 'koKR', '자네는 부주의한 모험이 아니라, 전통 의식에 집중해야 하네!', '', 66384),
(292657, 'koKR', '', '달니르는 나를 예전부터 탐탁지 않아 했네. 내가 바깥세상과 접촉하기 전부터 말이야.\n\n그래도 예전에는 속으로만 삭였지. 사실 달니르만 그렇게 생각하는 것도 아니야.\n\n하지만 한 가지는 확실히 말할 수 있네. 다시 과거로 돌아가 외부와의 접촉을 피할 수 있다 해도, 난 아무것도 바꾸지 않을 걸세. 바깥에는 우리가 배울 수 있는 훌륭한 것들이 많으니까.\n\n자, 이제 그만하세나. 이런 얘기를 꺼낼 시기도, 장소도 아니니까.', 66384),
(292656, 'koKR', '', '자네도 의식에 참여하고 있나? 훌륭하네!\n\n내가 의식을 치를 때가 떠오르는군. 마지막에 달니르와 하가르에게 축복을 받았지. 나는 전통에 속박되었지만, 어느 날 부름이 찾아왔네. 몇 번이나 뒤돌아보았으나, 그 부름은 내 깊은 곳에서 울려 퍼지듯 더욱더 강렬해졌지.\n\n나는 신경 쓰지 말고, 오늘을 새로운 여정의 시작으로 기쁘게 맞이하게.', 66384),
(292655, 'koKR', '외부인들은 여기 있어서는 안 돼. 특히 오늘 같은 날은 더더욱.', '', 66384),
(292654, 'koKR', '', '저들은 하란다르가 얼마나 위험한지 모르네. 우리가 찾아야 해.', 66384),
(292646, 'koKR', '', '이건 외부인의 전투 장비로군. 이것조차 없다면 작은 포식자에게도 쉬운 먹잇감이 될 터. 걱정이군.', 66384),
(292645, 'koKR', '', '무엇이 자네를 이곳으로 이끌었나? 자네도 들은 건가...? 흠.', 66384),
(292644, 'koKR', '마음속 깊은 곳에서 희미한 노래가 들려오며 가슴을 짓누르는 감각이 느껴집니다.', '마음속 깊은 곳에서 희미한 노래가 들려오며 가슴을 짓누르는 감각이 느껴집니다.', 66384),
(292643, 'koKR', '', '부름을 따라라. 가슴이 시키는 대로 가.', 66384),
(292642, 'koKR', '뿌리를 돌보는 일은 시간과 헌신이 필요하네. 전통을 건강하게 지탱하는 두 기둥이지.', '', 66384),
(292638, 'koKR', '', '폭풍이 지나간 뒤로 칼고르그가 말을 안 듣고 버릇도 없어졌어요. 원래부터 이런 녀석이었나? 훈련도 안 된 짐승이었던가?\n\n솔직히 더 나은 존재라고 믿었는데 말이죠.', 66384),
(292626, 'koKR', '치유의 제단에서 부서진 지팡이를 찾아라. 더 많은 것을 알게 될 것이다.', '', 66384),
(292622, 'koKR', '', '록타르, 친구여. 고맙네.', 66384),
(292621, 'koKR', '나중에 다시 뵙겠습니다.', '', 66384),
(292620, 'koKR', '', '아, 여정이란. 이제 자네도 고향으로 돌아갈 때가 되었네.', 66384),
(292613, 'koKR', '', '$n, 자네는 여신의 징표를 받았네. 비로소 여정에 나설 때일세.', 66384),
(292611, 'koKR', '', '아니, 굳이 그러고 싶지 않아. 이제 와서 나한테 뭘 증명할 필요는 없지. 뭐, 정말 바보 같은 짓이라도 해보고 싶다면 몰라도.', 66384),
(292608, 'koKR', '', '세이라가 한숨을 내쉽니다.', 66384),
(292607, 'koKR', '', '전 여신께서 부르는 곳이면 갈 겁니다.', 66384),
(292606, 'koKR', '', '오르웨냐, 언젠가는 여기 내려오는 걸 멈춰야 할 거다.', 66384),
(292604, 'koKR', '여신에 대한 네 관념 자체가 뒤바뀔 각오를 해라. 진실을 알게 되면 외면할 수 없게 된다. 여기서부터는 돌아갈 길이 없음이야.', '', 66384),
(292603, 'koKR', '', '정신을 준비하려면 뭘 해야 합니까?', 66384),
(292602, 'koKR', '때가 왔다. 넌 우리의 역사를 향한 헌신과 전장에서의 힘을 증명했다. 이제 요람의 가장 깊은 진실을 배울 준비가 됐어.', '', 66384),
(292597, 'koKR', '', '슬슬 의식이 끝나가고 있네, $n. 무엇을 보았나? 유산석이 어떤 광경을 보여주었지?', 66384),
(292588, 'koKR', '', '나무의 진가는 뿌리에만 있지 않다. 하란다르 너머에 무궁한 세계가 펼쳐져 있지.', 66384),
(292579, 'koKR', '자네는 \"로아 전령\" 아닌가? 그럼 말하게! 쿨지가 우리를 위해 일하게 만들어! 맹세를 잊었는가!', '', 66384),
(292578, 'koKR', '사술군주의 지팡이라고? 하지만 그 지팡이를 쓰는 자라면... 어둠에 물들 수밖에 없...', '', 66384),
(292577, 'koKR', '함부로 떠들지 마라. 나는 네놈 따위 필요 없다. 내 길은 내가 찾아!', '', 66384),
(292576, 'koKR', '시즈타, 어째서 서약파괴자를 쓰지 않은 거야!', '', 66384),
(292575, 'koKR', '안 돼! 날 치료해라, 쓸모없는 로아야. 아마니를 섬기는 게 네 일 아니더냐.', '', 66384),
(292574, 'koKR', '나는 너를 붙잡고 있지 않다. 떠날지 말지는 네 선택이다.', '', 66384),
(292573, 'koKR', '너는 살과 피로 이루어진 존재일 뿐, 영원히 살 자격은 없다. 이건 반드시 알아야 한다.', '', 66384),
(292572, 'koKR', '나는 전쟁군주다. 아버지도 그랬지. 우리는 신성한 전사들이거늘...', '', 66384),
(292570, 'koKR', '그래. 로아를 해치는 사술군주의 지팡이였지. 내가 지팡이를 부쉈을 때... 암흑 마법이 역류한 거야. 누구를 해치려는 생각은 없었는데.', '', 66384),
(292569, 'koKR', '내가 죽을 리 없어. 이건 속임수다. 당신이 틀렸어!', '', 66384),
(292568, 'koKR', '이제 이 지팡이가 무엇을 뜻하는지 알겠느냐, 시즈타?', '', 66384),
(292567, 'koKR', '나라도 할 수 없는 게 있을 때가 있지. 그건 누구나 마찬가지야.', '', 66384),
(292566, 'koKR', '내 약은 무한하지 않다. 삶도 마찬가지다.', '', 66384),
(292565, 'koKR', '나는? 어서 풀어 주게!', '', 66384),
(292562, 'koKR', '나는 여러 맹세의 대상 중에서 선택해야 했네. 그리고 아쿠투의 시간이 온 게지. 그가 진실을 받아들이게 하는 건 내 책임이 아니네.', '', 66384),
(292561, 'koKR', '잘 가게, 아쿠투. 나는 이 지팡이와... 내 죄책감을... 불 속에 던지리라.', '', 66384),
(292557, 'koKR', '시즈타는 떠날 준비만 하면 얼마든지 떠날 수 있다. 다른 이들도 마찬가지다.', '', 66384),
(292554, 'koKR', '', '등을 맞대고 싸우겠습니다. 아제로스를 위하여!', 66384),
(292553, 'koKR', '우린 하나 되어 싸운다! 쿠엘탈라스를 위하여! 아제로스를 위하여!', '', 66384),
(292552, 'koKR', '', '함께하겠네!', 66384),
(292550, 'koKR', '이게 네 진정한 모습인가? 자기 자신의 진실을 찾아라.', '이게 네 진정한 모습인가? 자기 자신의 진실을 찾아라.', 66384),
(292547, 'koKR', '황혼의 칼날단이 영원노래에 얼마나 깊숙이 침투했는지도 의문이군요.', '', 66384),
(292528, 'koKR', '<마음속에서 고요한 노래가 느껴집니다. 말로는 표현하기 어렵지만 깊은 곳에서 부름이 들리는 것 같습니다. 무언가가 당신을 끌어당기며 소통을 원하고 있습니다.>', '', 66384),
(292504, 'koKR', '', '외부인이 이토록... 강렬하다니, 놀랍군. 지팡이를 가져가라. 너는 네 힘을 증명했다.', 66384),
(292503, 'koKR', '', '도전을 받아주지!', 66384),
(292501, 'koKR', '', '아크셈은 네게 배울 자격이 있을지도 모른다고 생각하더군. 지식은 곧 힘이니까. 하지만 그걸 감당할 힘은 있겠나?', 66384),
(292500, 'koKR', '', '오너라. 아크셈이 제자를 제대로 골랐는지 보겠다.', 66384),
(292499, 'koKR', '', '하란다르는 위험한 땅이다. 폭포 하나하나 뒤에 비밀이 숨어 있지. 물론, 살펴볼 배짱이 있어야 하지만 말이다.', 66384),
(292498, 'koKR', '<눈에 띄는 것은 아무것도 없습니다. 허탕만 친 걸지도 모릅니다.>', '<눈에 띄는 것은 아무것도 없습니다. 허탕만 친 걸지도 모릅니다.>', 66384),
(292497, 'koKR', '<부서진 나무 조각들이 보이지만, 특별한 것은 없습니다. 지팡이는 여기 없습니다.>', '<부서진 나무 조각들이 보이지만, 특별한 것은 없습니다. 지팡이는 여기 없습니다.>', 66384),
(292496, 'koKR', '<작은 훔친 물건 몇 개는 있지만, 온전한 물건은 없습니다.>', '<작은 훔친 물건 몇 개는 있지만, 온전한 물건은 없습니다.>', 66384),
(292494, 'koKR', '쿨지는 우리의 요구를 모욕으로 받아들였네, 전쟁군주여. 이미 죽음이 자네를 취했다고 생각...', '', 66384),
(292493, 'koKR', '로아는 내 말대로 할 걸세. 자, 이 사술군주의 지팡이를 받게. 쿨지의 힘을 취해 줄진의 영광을 드높이리라!', '', 66384),
(292485, 'koKR', '저들은 스스로 저주를 만들어 냈다.\n\n생각보다 훨씬 쉬운 일이거든.', '', 66384),
(292481, 'koKR', '다들 마음속 깊은 곳에서는 진실을 알고 있다. 다만 그걸 마주할 수 있는지는 스스로 풀어야 할 과제이니라.', '', 66384),
(292479, 'koKR', '나는 쿨지다. 아킬존이 $n 네 이름을 바람에,실어 보내더구나.\n\n너를 맞이하게 되어 영광이로다.\n\n내 성소의 사정은 네가 짊어질 일이 아니다. 그건 놈들이 스스로 택한 운명이야. 깊은 부정을 안고 있지. 자신들이 어떻게 죽었는지... 그리고 그 죽음을 불러온 배신을 잊은 거다.\n\n정 놈들을 위해 나서고 싶다면, 말리지 않겠다.', '', 66384),
(292476, 'koKR', '얘기 좀 하지.', '', 66384),
(292475, 'koKR', '너는 로아의 친구다.', '', 66384),
(292464, 'koKR', '나는 답을 알아야겠네. 쿨지께 직접 듣고 말 걸세!', '', 66384),
(292456, 'koKR', '', '잠깐! 항복하겠다! 사실 난 한참 전에 믿음을 버렸다. 저런 놈들을 위해 목숨을 내던지고 싶진 않아.', 66384),
(292444, 'koKR', '', '난 잿빛 골짜기 변두리를 순찰하던 중이었네. 그때 눈부신 녹색 섬광이 시야를 가렸고, 정신을 차려보니 이곳이었지.\n\n그 야수와 싸우다 도끼를 잃었네. 자네에게 평생의 빚을 졌어.', 66384),
(292442, 'koKR', '전 엘윈 숲의 큰 나무 근처에서 평소처럼 순찰을 하고 있었습니다. 그때 눈부신 녹색 섬광이 번쩍이더니, 정신을 차려보니 이곳이었습니다.\n\n이곳의 자연은 무자비하고 가혹합니다.', '', 66384),
(292430, 'koKR', '줄자라는 우리를 위한 결정을 내릴 걸세.\n\n하지만 로아는? 흐음. 우리 모두가 교훈을 얻을지도.', '', 66384),
(292424, 'koKR', '아, 이건 아니에요. 다시 해보죠.', '', 66384),
(292421, 'koKR', '훌륭합니다! 가져온 물건을 보여 주십시오!', '', 66384),
(292420, 'koKR', '아라토르, 빛은 따르는 자들에게 힘을 주지만, 그 힘의 도덕과 윤리는 각자의 내면에서 비롯되는 걸세.', '', 66384),
(292417, 'koKR', '', '그대가 바삐 움직이는 동안, 저는 이 근방에 자라는 약초의 잎을 모으고 있었습니다. 루가르가 예전에 보여주었던 식물이었지요.\n\n이 잎으로 만든 연고는 상처 치유를 빠르게 돕는 효능이 있다고 합니다.', 66384),
(292413, 'koKR', '벌써부터 당신의 귀환이 기다려집니다.', '', 66384),
(292412, 'koKR', '칼, 사랑하는 여동생아, 이렇게 도움 되는 여행자님들을 만나다니 좋지 않니?', '', 66384),
(292411, 'koKR', '', '맞는 말이야, 발.', 66384),
(292410, 'koKR', '친구여! 큰 도움을 주셨습니다. 솔라르의 이름에 큰 영광이 될 겁니다.', '', 66384),
(292406, 'koKR', '구해줘서 고맙다. 내 목숨, 아니 최소한 포옹이라도 빚진 셈이지, 하하.\n\n툴아마르는 우리를 고향으로 돌려보낼 방법을 연구해 왔다. 툴아마르가 경계심을 드러낸 걸 용서해라. 우리도 예전에 군단을 배신한 만아리와 손을 잡은 적이 있지만, 그 대가는 늘 따랐다.\n\n<나루 펜던트를 움켜쥐고 숨을 내쉬는 주라스>\n\n우리 또한 버려졌다는 기분이 어떤지 잘 안다.', '', 66384),
(292405, 'koKR', '', '빛벼림 동족들에 대한 이야기는 들었지만, 이렇게 직접 본 건 처음이다. 이런 장소에서 만나다니, 기적이 따로 없군.\n\n나는 툴아마르다. 내 동족 황천사자를 지키고 고향으로 보내는 것이 내 의무지.', 66384),
(292400, 'koKR', '희망의 빛 예배당이 위험에 처했습니다. 세상이 위험하죠. 전투에 집중해야 합니다.', '', 66384),
(292399, 'koKR', '한데 빛을 다룬다는 게 이런 뜻입니까? 끝없는 악과의 싸움?', '', 66384),
(292398, 'koKR', '의심이 이 땅을 지키는 데 방해가 되어선 안 되겠지요.', '', 66384),
(292397, 'koKR', '제가 이곳에 주둔해 스컬지와 싸워야 했다면... 아버지처럼 분노와 노여움에 사로잡혔을 것 같습니다.', '', 66384),
(292396, 'koKR', '칠흑의 기사단에 지원을 요청했지만, 이번 공격을 막아내려면 도움이 필요합니다.', '', 66384),
(292395, 'koKR', '많은 수호자가 태양샘으로 불려 가면서, 스컬지가 예배당 바로 앞까지 밀고 들어왔습니다.', '', 66384),
(292394, 'koKR', '티로서스 님, 사정이 이렇게까지 절박한 줄은 미처 알지 못했습니다. 저희가 뭘 하면 되겠습니까?', '', 66384),
(292392, 'koKR', '', '삶과 죽음의 시련을 두려워하지 마라, $n.\n\n모든 것은 순환하고, 모든 것은 꺼지지 않는 불꽃 속에서 다시 태어난다.', 66384),
(292391, 'koKR', '깨어났네. 깨어났어.\n\n새로운 잔알라이는 암컷이었군! 꼬꼬댁!\n\n좋은 징조일세. 치유의 징조고, 로아의 균형이 되살아난다는 뜻이네.', '', 66384),
(292390, 'koKR', '어둠수호병 지점', '어둠수호병 지점', 66384),
(292389, 'koKR', '', '마도루, 잔알라이시여. 당신의 시련을 통해 저 자신에 대해 많은 걸 배웠습니다. 남은 시련에서도 더 배울 수 있으면 좋겠군요.', 66384),
(292310, 'koKR', '보게! 마지막 시련이네. 정면으로 마주하게. 자기 자신을 마주하게나!', '', 66384),
(292309, 'koKR', '', '아니. 우린 도움을 받고 더 강해졌다. 내 자존심이 동족을 망치게 두진 않겠다.', 66384),
(292308, 'koKR', '', '줄자라가 뼈를 울리는 전투의 함성을 내지릅니다.', 66384),
(292259, 'koKR', '사냥감이 허둥지둥 도망치는 걸 보는 것도 재밌지.', '', 66384),
(292257, 'koKR', '망치 주둔지 주민을 위해 해야 할 일이 많소, $p.\n\n도움이 필요한 이를 돕는 건 안쉬를 기리는 일이기도 하지.', '', 66384),
(292241, 'koKR', '으윽! 아무것도... 느껴지지 않는군. 시즈타가 또 약속을 저버렸어.', '', 66384),
(292240, 'koKR', '쿨지! 당신의 육체 일부를 바쳐 날 치유하고 죽음을 거부하겠소. 치유의 힘을 주시오!', '', 66384),
(292208, 'koKR', '간을 주게. 뭐든 해 보겠네.', '', 66384),
(292206, 'koKR', '아프다... 아파!\n\n이 고통은 끝이 없구나.\n\n제발... 멈춰 주게.', '', 66384),
(292203, 'koKR', '즐기라고.', '', 66384),
(292202, 'koKR', '내 소중한 장난감들이 어디로 도망쳤을까...', '', 66384),
(292196, 'koKR', '', '만아리. 네가 주라스를 우리에게 돌려보냈다는 건, 네가 살게라스의 군단을 버렸다는 뜻이겠지.\n\n좋다. 이런 장소에서 만나다니, 기적이 따로 없군.\n\n나는 툴아마르다. 내 동족 황천사자를 지키고 고향으로 보내는 것이 내 의무지.', 66384),
(292184, 'koKR', '들여보내게. 받아야 할 물건이 있어. 얼른!', '', 66384),
(292180, 'koKR', '줄자라는 늘 믿었던 대로 하셰이가 됐군.', '', 66384),
(292176, 'koKR', '', '할 일... 이... 동족 살해자들을... 공격하는 것!', 66384),
(292175, 'koKR', '기념품이 공허의 영향력에 저항할 만큼 기억을 자극하는 거라면, 아직 희망은 있어요! 시간을 두고 지켜보면 돼요.', '', 66384),
(292174, 'koKR', '', '어둠이 몸을 타고 흘러... 격류가... 그 무엇도 남기지 않고...', 66384),
(292172, 'koKR', '<이 성기사는 이름 없는 공허의 존재에게 무자비하게 제물로 바쳐졌습니다. 생기를 잃은 눈은 하늘을 바라보고만 있습니다.>', '<이 성기사는 이름 없는 공허의 존재에게 무자비하게 제물로 바쳐졌습니다. 생기를 잃은 눈은 하늘을 바라보고만 있습니다.>', 66384),
(292170, 'koKR', '', '길을 여는 것도, 아무도 뒤쫓지 못하게 막는 것도 나만이 할 수 있다.', 66384),
(292169, 'koKR', '', '길을 여는 것도, 아무도 뒤쫓지 못하게 막는 것도 나만이 할 수 있다.', 66384),
(292168, 'koKR', '가슴에 불씨를, 석탄에도 불씨를.\n\n의심을 걷고 영혼을 정화하게!', '', 66384),
(292166, 'koKR', '', '수수께끼에 수수께끼로군요.\n\n그래도... 빛의 방식은 좀 더 직관적인데.', 66384),
(292165, 'koKR', '', '열어야 한다. 그리고 닫아야 해. 나만이 할 수 있다.', 66384),
(292164, 'koKR', '두근거리는 심장 소리가 들리지 않나?', '', 66384),
(292163, 'koKR', '', '가요, 친구! 하늘유리를 모으러 가요!', 66384),
(292160, 'koKR', '붓질 한 획 한 획이 과거의 속삭임이며, 다시 전해지기를 기다리는 기억의 조각이다. 이 고요한 유물들은 세월의 흐름에 묻힌 진실을 품고 있다.\n\n유물들의 메아리가 깨어나면 어떤 이야기가 고개를 들까?\n\n오너라. 네 호기심이 잊힌 진실을 여는 열쇠가 되게 하라.', '', 66384),
(292159, 'koKR', '이곳에 숨겨진 진실은 짊어질 준비가 된 자에게만 드러난다.', '', 66384),
(292158, 'koKR', '이곳의 그림들은 우리 과거의 그림자를 비추고 있다. 희미하지만 사라지지 않은 채로.\n\n언젠가 너도 저 빛에 이야기를 더하게 될 것이다.', '', 66384),
(292157, 'koKR', '주변의 유물들은 잠들어 있지만, 의미를 이해하는 손길을 기다리고 있다.\n\n때가 되면, 너도 유물들의 이야기를 깨우는 자리에 설 수 있을 것이다.', '', 66384),
(292152, 'koKR', '', '<주라스를 바라보며 죄책감과 결의를 동시에 드러내는 툴아마르>', 66384),
(292147, 'koKR', '베란은 제가 안전한 곳으로 데려가죠. 앞에서 합류합시다.', '', 66384),
(292146, 'koKR', '', '키판? 키판 맞아?', 66384),
(292145, 'koKR', '여깁니다, $n 님!', '', 66384),
(292136, 'koKR', '', '와... 루타니치고 참 특이하게 생기셨네요. 꽃이나 장식은 다 어디 갔어요?', 66384),
(292101, 'koKR', '예전엔 그랬지. 하지만 스컬지는 더 이상 위협이 아니니, 물러나라는 제안을 받았네.\n\n정확히 말하자면... 아주 강한 제안이었지.\n\n그 후로 적응이... 쉽진 않더군.', '', 66384),
(292099, 'koKR', '요즘 트랜퀼리엔이 꽤 고요하구먼. 계속 이러면 좋겠어.', '', 66384),
(292098, 'koKR', '느낌이 좋지 않은데.', '느낌이 좋지 않은데.', 66384),
(292097, 'koKR', '우리 마을이 다가오는 폭풍에서 살아남을 수 있을까요?', '우리 마을이 다가오는 폭풍에서 살아남을 수 있을까요?', 66384),
(292096, 'koKR', '기회가 있을 때 이사를 가야 했나...', '기회가 있을 때 이사를 가야 했나...', 66384),
(292095, 'koKR', '이웃이 사라지고 있는데, 총독님은 왜 가만히 있는 거죠?', '이웃이 사라지고 있는데, 총독님은 왜 가만히 있는 거죠?', 66384),
(292080, 'koKR', '베란이 어둠수호병 지점에 있다면 아직 시간이 남아 있을 거예요. 그곳에서 만나요!', '', 66384),
(292072, 'koKR', '', '자쿨 님이 환영의 돌을 남겨놨다니, 아직도 실감이 안 나요. 어떤 기억이 담겨 있을지 정말 궁금하네요.\n\n근데 서둘러야 해요. 곧 루타니가 우리가 여기 있는 걸 눈치챌 거예요.', 66384),
(292066, 'koKR', '', '황혼의 칼날단이 일으킨 혼란으로 인해 혹부리나무족조차 영토에서 밀려나고 있습니다. 아마니가 감당하기엔 너무 벅찹니다.\n\n줄자라가 보여준 강인함이 진심이었기를 바라야겠네요.', 66384),
(292065, 'koKR', '모르둔이 빛나무 병기의 위력에 눌려 도망치고 있다. 지금 이 상황을 이용해야 해.', '', 66384),
(292064, 'koKR', '줄자라 족장을 기다리세.', '', 66384),
(292063, 'koKR', '회의가 더 잘 흘러갔으면 좋았을 텐데.\n\n로아 얘기를 꺼내고... 엘프는 우리 일에서 빠지는 게 좋아.', '', 66384),
(292062, 'koKR', '우린 얼마 남지 않았습니다. 우리 그림자소나무는 행동하기 전 때를 기다립니다.\n\n불꽃의 뜻을 들을 것입니다. 싸워야 할 때가 오면, 싸울 겁니다.', '', 66384),
(292061, 'koKR', '', '아마니는 마른나무껍질에게 너무 많은 걸 기대하는군. 지금 우린 썩은가지에 눌려 있는 상황인데.', 66384),
(292060, 'koKR', '', '나는 깨진엄니의 전사이고, 부족을 대표하는 건 릴라주다.', 66384),
(292059, 'koKR', '', '내가 깨진엄니의 대표다!', 66384),
(292058, 'koKR', '', '지금은 황혼의 칼날단에게 맞서야 합니다.\n\n아마니와 우린 공동의 적이 있습니다. 두 적을 상대하는 건 좋은 판단이 아니에요.', 66384),
(292057, 'koKR', '베란은 살아 있지만... 정신만으로 공허의 영향을 이겨낼 수 있을까요?', '', 66384),
(292055, 'koKR', '', '우리 수레 탄다!', 66384),
(292040, 'koKR', '', '쇠뇌는 그럴듯한 미끼지. 하지만 모르둔의 두개골에 내 도끼가 날아드는 건 못 본 척하긴 어렵겠지.\n\n슬슬 시작하자. 부족도 전투 준비는 끝났다.', 66384),
(292039, 'koKR', '내 빛나무 병기가 얼마나 강력한지 직접 보게 될 거다!', '', 66384),
(292038, 'koKR', '', '줄자라는 모르둔과 직접 싸우겠다고 했습니다. 저도 함께하겠습니다. 이번 공격은 반드시 성공해야 합니다.\n\n쇠뇌를 잘 조준해서 발사하십시오. 반드시 맞혀야 합니다.', 66384),
(292037, 'koKR', '다들 무사하네. 전장에서 멀찍이 떨어진 곳에 숨어 있지.\n\n틈이 보이면 바로 데리고 나가겠네.', '', 66384),
(292035, 'koKR', '베란, 네가... 스산한 노래가... 너와 다른 사람들이 첫걸음이 될 수 있어.', '', 66384),
(292034, 'koKR', '주위를 봐. 이 공허 엘프들은 공허와 공존하는 방법을 터득한 하나의 사회야.', '', 66384),
(292033, 'koKR', '네가 저항할 수 있다는 건, 다른 이들도 가능할 거란 뜻이야. 다른 잃어버린 자매들... 아버지들도...', '', 66384),
(292032, 'koKR', '', '자쿨 님은 제 스승이었지만, 동시에 친구이기도 했습니다. 루타니가 훔쳐 간 걸 그냥 넘길 수는 없습니다!', 66384),
(292031, 'koKR', '', '하지만 어둠은 지금도 우리 안에 도사리고 있어. 오래 머물 수는 없어.', 66384),
(292030, 'koKR', '모르둔의 방패를 몇 번 공격할 화살은 있네.', '', 66384),
(292028, 'koKR', '', '키판... 오빠에 대한 기억... 고향의 기억... 그게 우리를 깨웠어.', 66384),
(292027, 'koKR', '', '안료는 준비됐지만 형태를 유지할 수 있을까? 붓을 들어 도화지에 올려라. 메아리가 일기 전에 물감이 의도한 대로 흐르는지 확인해야 한다.', 66384),
(292024, 'koKR', '', '내 힘을 받아 손끝으로 흐르게 해라! 물감을 불러내고, 메아리의 가마솥으로 돌아가도록 명령을 내리는 거다. 내가 손도장 봉인으로 속박하겠다.', 66384),
(292023, 'koKR', '', '안 돼, 안 돼, 안 된다! 이렇게 흘러서는 안 돼! 물감이 도망치려 해! 밟아! 도망치게 두면 이야기도 함께 사라진다!', 66384),
(292022, 'koKR', '하라니르의 기억이 희미해지자, 사이알요는 기억을 세상에 묶을 방법을 찾았다. 색채만으로는 역사를 담을 수 없었으니, 더 많은 것이 필요했지.', '', 66384),
(292015, 'koKR', '장관이지 않소?', '', 66384),
(292012, 'koKR', '나는 오랜 세월 실버문의 집정관을 섬겼소. 하지만 이곳이 더 마음에 들었지.\n\n결국 이 마을에 정이 붙었지. 조용하고, 이것저것 캐묻는 도시 사람들에게서 멀어질 수도 있고.\n\n공허폭풍이 머리 위에 드리운 상황인데도 실버문은 아무런 조처도 하지 않고 있소. 도저히 납득할 수 없는 일이오.\n\n이 사람들은 좀 더 좋은 대우를 받아 마땅하오.', '', 66384),
(292007, 'koKR', '그게 대답이 되진 않는데. 흠.', '', 66384),
(292003, 'koKR', '', '이건 승리가 아니야. 민간인들이 도망칠 시간을 우리 피로 산 거지.', 66384),
(291996, 'koKR', '', '지배자의 망루에서 만나자, 외행성인. 도마나르가 우리에게 필요한 것을 가지고 있다.', 66384),
(291993, 'koKR', '', '토룬도, 줄잔이 신호를 보낼 때까지 이곳을 사수하라. 혼란이 생기면 생존자들과 함께 빠져나가.', 66384),
(291986, 'koKR', '', '지금은 줄잔을 걱정할 시간이 없다. 날로라크에 집중해야 해. 가자.', 66384),
(291980, 'koKR', '희생이라고? 영웅이라고 해야지. 아탈아만의 빛나무를 되찾다가 참된 아마니로서 전사한 영웅 말이지.', '', 66384),
(291972, 'koKR', '아이들을 안전한 곳으로 데려다주고 나면, 줄잔이 쇠뇌를 준비하는 걸 돕겠네.', '', 66384),
(291970, 'koKR', '부족 최연장자들, 장로들을 지켜야 한다!\n\n우리의 지혜를, 나아가 영광스러운 역사를 지키는 이들이니까!', '', 66384),
(291968, 'koKR', '', '이곳은 오래전 말라크라스가 처단당한 곳입니다. 말라크라스의 용사들은 아마니의 로아를 이용해 얼라이언스와 호드를 공격하려 했죠.\n\n말라크라스를 쓰러뜨린 후 영원노래 숲 습격은 점점 줄어들었고, 어느 시점부터는 완전히 멈췄습니다. 그 이후로 아마니가 무슨 일을 해 왔을지 궁금하군요.', 66384),
(291967, 'koKR', '$n 님! 울부짖는 마루에서 다시 뵙죠.', '', 66384),
(291966, 'koKR', '오래전부터 알고 있긴 하지만, 친한 사이는 아니었습니다. 우리가 영원노래로 돌아왔다는 이야기를 듣고 연락한 겁니다.\n\n안테노리안은 트랜퀼리엔을 지키려는 의지가 강하고, 공허폭풍의 위협에 깊은 우려를 갖고 있습니다. 그래서 저에게 이 연구 환경을 마련해 준 것이겠지요. 제 연구가 실제로 도움이 될 수 있다고 판단한 겁니다.\n\n이 문제를 하루라도 빨리 해결해야 주민들이 안전해진다는 걸, 저도, 그리고 그도 분명히 알고 있을 겁니다. 그 이해해 주는 마음이 고마울 따름입니다.', '', 66384),
(291960, 'koKR', '', '방심을 늦추지 말게, $c.\n\n이 늪지는 멀록이 우글거려.\n\n이미 화물과 톨바니의 목숨을 빼앗아 간 놈들일세.\n\n언제라도 싸울 수 있어야 해.', 66384),
(291958, 'koKR', '카시에아는 제 제자였습니다. 영원노래에 도착한 직후 실종됐죠. 전 카시에아가 우리가 여전히 고립되어 있다는 현실에 실망해서 텔로그러스로 돌아간 줄 알았습니다. \n\n정말 영특하고, 연구에도 열정적인 아이였습니다... 남아 있는 이 기록을 보면 마침내 궤도에 올랐던 모양입니다.\n\n〈고통스러운 표정으로 잠시 말을 잇지 못하는 엄브릭〉\n\n그 순간을 함께하지 못한 게 안타깝습니다.', '', 66384),
(291954, 'koKR', '아마니로서는 과감한 수를 둘 수밖에 없었다. 빛나무는 위험을, 손실을 감수할 가치가 있었거든.\n\n빛나무 창으로 황혼의 칼날단을 찔렀을 때, 뒤틀리는 꼴을 보면 눈앞에 광명이 보이는 듯해. 하!\n\n빛나무는 응당 우리의 것이다. 우리가 그 어떤 엘프보다 잘 사용할 수 있다.', '', 66384),
(291948, 'koKR', '', '아크셈이 널 믿더군. 도둑 무리의 큰 둥지를 뒤져 지팡이의 행방을 알려 줄 단서를 찾아라.', 66384),
(291937, 'koKR', '감히 내게 말을 거느냐? 혀를 잘라버려야 정신을 차리겠군.', '', 66384),
(291936, 'koKR', '', '위험한 곳을 돌아다니는군.', 66384),
(291935, 'koKR', '발을 내딛기 전에 여기가 어딘지 잘 생각해 보는 게 좋을 거다.', '', 66384),
(291921, 'koKR', '지팡이가 영영 사라진다면, 하라니르에게는 엄청난 역사의 손실이 될 거다.', '', 66384),
(291920, 'koKR', '그 뿌리지팡이를 쥔 모든 이가 새로운 생명을 불어넣어 왔다. 거쳐온 모든 이를 담은 살아 있는 기록이라고 할 수 있지.', '', 66384),
(291919, 'koKR', '', '살란드리아, 기다려요!', 66384),
(291918, 'koKR', '', '돈하트에게 남은 시간이 얼마 없을지도 몰라요! 서두르죠!', 66384),
(291917, 'koKR', '세상이 혼돈으로 가득할 때, 가족의 유대가 위안이 될 수 있죠.\n\n전 어둠수호병이 저지른 끔찍한 일들을 용서할 수는 없지만, 여동생 베란의 기억을 기리기로 했습니다.', '', 66384),
(291916, 'koKR', '', '준비됐습니다. 그리고 이 길을 혼자 걸을 필요가 없다는 것도 압니다.', 66384),
(291915, 'koKR', '이 의식을 견뎌내고, 잊어선 안 될 것을 배울 준비가 되었느냐?', '', 66384),
(291914, 'koKR', '너는 하라니르뿐만 아니라 여신의 품 안에 사는 이들을 지켜야 한다. 알른하라의 모든 자손을, 세상의 모든 종족을 말이다.', '', 66384),
(291913, 'koKR', '이 길을 따르고, 여신이 알려 주려는 진실을 알기 위해서는 강해져야 한다. 그리고 강함이란 희생이 아닌 보호에서 나오지.', '', 66384),
(291912, 'koKR', '', '다른 이들이 절 따르는 이유는, 우리가 여신을 찾아 구해낼 수 있다고 믿음을 공유하기 때문입니다. 뭘 하면 됩니까, 아크셈?', 66384),
(291911, 'koKR', '스스로를 바치는 건 고결하다. 하나, 다른 이를 바치는 건 광신에 지나지 않다. 그래도 이 길을 따를 테냐?', '', 66384),
(291910, 'koKR', '', '그, 그건...', 66384),
(291909, 'koKR', '뭐든 바칠 각오가 있단 말이지, 오르웨냐? 너 자신을 바치는 것도 두렵지 않다? 그렇다면 다른 이들을 바치는 건 어떻지?', '', 66384),
(291908, 'koKR', '', '전 여신의 뜻이라면 무엇이든 따를 겁니다. 조금도 두렵지 않아요.', 66384),
(291907, 'koKR', '나는 빛만개에 대해 더 알아야 하오. 그대의 고향으로 가는 위험을 감수하더라도 말이오.', '', 66384),
(291900, 'koKR', '스라소니 로아께서 우리를 이곳으로 인도하고, 지켜주셨네. 그리고 날 전령으로 삼으셨지.', '', 66384),
(291898, 'koKR', '헤. \n\n잔알라이께서 자네를 기다리고 있네, $p. 만날 준비는 됐는가?', '', 66384),
(291897, 'koKR', '주라스가 희망에 찬 눈빛으로 안정되는 차원문을 바라봅니다.', '', 66384),
(291896, 'koKR', '', '하셰이 제단이군요. 아킬존 사원 근처에서 밝힌 제단과 비슷합니다.', 66384),
(291895, 'koKR', '툴아마르의 이론이 옳았다. 제대로 작동하고 있어!', '', 66384),
(291894, 'koKR', '수호자에 대해 잘 아는가? 본래 수호자는 아르거스에서 선각자들의 허영을 채우기 위해 만들어졌다. 하지만 대탈주 이후로는 악마들로부터 쓰러진 동족을 지키는 데 없어서는 안 될 도구가 되었다.\n\n수호자에는 전사한 이들의 영혼이 깃들어 있어, 적과의 싸움을 이어갈 수 있게 한다. 이 수호자는 이미 마지막 전투를 치른 듯하지만, 여전히 수십 명의 드레나이 영혼을 담은 그릇으로 남아 있다.\n\n결코 이상적인 방식은 아니다. 너무 많은 영혼이 한데 모여 있어 괴로움을 겪으니까. 나는 반드시 이들을 고향으로 데려가, 위대한 영묘에 안치할 것이다.', '', 66384),
(291870, 'koKR', '', '내 마음을 털어놓으면, 아킬존이 한 말 때문에 끓어오른 분노와 차가운 수치심을 어떻게 없애야 하는지 또 설교를 늘어놓겠지?', 66384),
(291868, 'koKR', '', '머리가... 복잡해 보입니다, 줄자라. 아킬존이 은총을 베푼 게 기쁘지 않습니까?', 66384),
(291858, 'koKR', '', '분노는 강력한 감정입니다. 제 종족도 한때 분노에 사로잡혔었죠.', 66384),
(291856, 'koKR', '', '전 외숙부님 얘기를 듣는 걸 좋아했어요. 사실일까 궁금하기도 했었지만요.', 66384),
(291855, 'koKR', '아킬존의 사원에 갔던 일을 얼마나 기억하고 있느냐?', '', 66384),
(291854, 'koKR', '나는 너와 줄잔 모두에게 로아를 사랑하는 마음을 심어주려고 애썼다.', '', 66384),
(291853, 'koKR', '', '아킬존,할라지,잔알라이,날로라크에 대한 이야기와.. 그들이 우릴 어떻게 지켜줬는지 기억합니다.', 66384),
(291852, 'koKR', '', '사원까지 올라갔고, 줄잔은 쓰러졌죠. 전 로아의 축복을 받지 못했고... 어머니는 돌아가셨습니다.', 66384),
(291850, 'koKR', '아킬존께서 날 전령으로 삼으며 큰 영광을 베푸셨지.', '', 66384),
(291847, 'koKR', '', '아마니를 상대로 긴 세월 전쟁을 치르면서 그들의 문화에 대해 몇 가지 배운 게 있습니다.\n\n사람들 대부분은 \"아마니 제국\"이 서로 다른 여러 부족으로 이뤄진 국가라는 걸 모릅니다. 사실은 건국 당시 가장 강한 부족의 이름을 가져와서 붙인 것뿐이죠.\n\n모든 부족은 저마다 섬기는 로아가 있습니다. 그리고 독자적인 풍습을 지켜 왔죠. 다만 지금 저들의 \"제국\"은 그 어느 때보다도 심각하게 분열되어 있습니다.\n\n새삼 놀랄 일도 아니긴 하지요. 줄자라가 진정으로 통합할 수 있을지 궁금할 따름입니다.', 66384),
(291844, 'koKR', '<온화한 파히가 아무것도 모른다는 듯 혼란스러운 눈빛으로 당신을 응시합니다.\n\n드레나이 모두가 쓸 피가 부족합니다. 모두에게 묻혀야 하는 건 아닐지도 모릅니다.>', '', 66384),
(291843, 'koKR', '...친구...?', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(291814, 'koKR', '', '잠깐만요, 줄자라! 제정신입니까?', 66384),
(291806, 'koKR', '', '내 은총을 원하는 자는 높은 곳까지 올라야 하지만, 추락을 두려워해서는 아니 된다.', 66384),
(291799, 'koKR', '', '발은 저랑 남매인데, 우스꽝스러운 사람이에요. 나중에 더 나은 소개말을 준비해야겠네요.', 66384),
(291798, 'koKR', '반갑습니다, 모험가 친구! 오늘은 어떻게 꾸며드릴까요?', '', 66384),
(291797, 'koKR', '하라니르와 우리의 역사를 계속 배워라. 네가, 아니 다른 누군가가 이 기억을 가질 자격이 있는지 보고 싶구나.', '', 66384),
(291796, 'koKR', '여신의 기억이 내게 전해졌고, 나는 그 중대함을 아는 자에게만 나눈다.', '', 66384),
(291795, 'koKR', '나는 요람의 목소리를 듣는 자 아크셈이다. 하라니르 대부분은 모르는 지식을 관장하고 있지.', '', 66384),
(291790, 'koKR', '', '아... 심각하군.\n\n나루를... 믿지 마라. 선의는 있다. 없애라는 얘기는 아니야.\n\n그래도... 믿지 마라.', 66384),
(291789, 'koKR', '', '나샤보르. 좋은 땅. 아주... 짜다? 붉은 소금. 보라색 물. 큰 짐승, 많고, 똑똑해. 형제자매 어릴 때, 사냥.\n\n때로 안전하지 않다. 하지만 우린 해낸다. 사죄하는 만아리도 친구로 만들었다. 몇 명뿐이지만. 우리 집을 만든다.', 66384),
(291788, 'koKR', '', '...티에라? 알아. 나루. 그래.\n\n우리에게서 왔다. 우리와 함께였다. 하지만 친구 아니야. 집 떠나라 했다, 뒤로 가라 했다. 그건, 음...\n\n<툴아마르가 설명하고 싶은 개념이 너무 복잡한 듯, 숨을 내쉬며 포기합니다.>\n\n너도 알지?', 66384),
(291787, 'koKR', '', '쳇.\n\n<손을 내젓는 툴아마르>\n\n빛의 일. 그들 싸움. 우리 돕지 않아. 나도 똑같이 한다.', 66384),
(291786, 'koKR', '', '여기 있어라. 형제자매를 도와라. 너 돕는다. 너도 돕는다.\n\n<드물게 미소를 지어 보이는 툴아마르>\n\n그러고 나서, 집으로 돌아가라.', 66384),
(291785, 'koKR', '', '나는 황천사자다. 내가 있어야 할 곳은 우리 종족의 곁이고, 우리가 가장 안전하게 지낼 수 있는 고향이야.\n\n그럼에도 벨렌을 마주하고 싶군. 우리가 아직도 굳건히 서 있다는 걸 보여 주고 싶거든. 내가 끝없는 어둠 너머에서 발견한 것들을 나눠 도움이 되고 싶다. 수천 년 동안 떨어져 있었던 다른 비전술사들과 황천술사들이 얼마나 발전했는지도 보고 싶고.\n\n내 동족을 지키는 데 도움이 된다면, 할 수 있다. 오래는 못 버티겠지만... 그래도 할 수 있지.', 66384),
(291784, 'koKR', '', '흠. 그녀가 어떤 죗값을 치러야 했다 해도, 저런 방식은 아니었지. 나루도 자기들 방식대로 돕고는 있어. 그건 나도 잘 안다.\n\n하지만 말이야. 예전에도 내 본능이 아키몬드와 킬제덴을 거부하라고 했고, 동료들은 그 결정을 도저히 이해하지 못했지. 지금 나루에 대해서도 똑같은 예감을 느낀다. 우리가 그들이 원하는 그릇이 아니면, 어떻게든 우릴 고쳐놓으려 들 거라는 거야.\n\n난 그저 내 동족과 함께 평온하게 살고 싶을 뿐이다. 하지만 살아남기 위해 힘을 써야 한다면, 그 힘은 내 것이어야 해.', 66384),
(291782, 'koKR', '', '나샤보르. 칼날의 정착지. 자연이 아름다운 세계야. 붉은 소금 평원이 펼쳐지다가 시원한 보랏빛 호수로 이어지지. 우리 강은 거대하고 튼튼한 수련 잎으로 가득하고, 평화로운 때면 드레나이가 그 위에서 낮잠 자며 강물에 흘러가는 광경을 흔히 볼 수 있어. 우리는 어려서부터 싸움을 배운다. 아르거스 시절보다 훨씬 일찍 말이지. 그 세계의 덩치 크고 지능 높은 야수들한테 살아남으려면 무력과 비전 마법을 다 익혀야 해.\n\n우린 분쟁과 재건을 반복해 왔고, 소수지만 우리 곁에서 사는 군단 탈주자들과 뜻밖의 동맹을 이루기도 했어. 그리고 우리를 끝없는 도주로 몰아넣었던 힘들... 지옥 마력도, 공허도, 빛까지 대부분 거부해 왔다.\n\n우리 세이야드는 제드힌에 천부적인 재능이 있어. 지켜보는 것만으로도 즐겁지.', 66384),
(291781, 'koKR', '제가 베란을 찾아보겠습니다.', '', 66384),
(291777, 'koKR', '너한테는 아무 의미 없겠지. 우리에겐 고향의 상징이다.', '너한테는 아무 의미 없겠지. 우리에겐 고향의 상징이다.', 66384),
(291776, 'koKR', '그 여자한테 받은 이 물건, 무슨 의미가 있지?', '', 66384),
(291775, 'koKR', '그분의 목소리가 들려...\n\n순찰 구역을 바꿔야 할 때가 온 걸지도 모르겠군.', '그분의 목소리가 들려...\n\n순찰 구역을 바꿔야 할 때가 온 걸지도 모르겠군.', 66384),
(291774, 'koKR', '알른의 균열은 가장 타락한 꿈과 끔찍한 악몽에서 비롯된 위험한 땅이다. 그래서 우리가 지키고 있는 거다. 우리 무리를 지켜야 하니까.', '알른의 균열은 가장 타락한 꿈과 끔찍한 악몽에서 비롯된 위험한 땅이다. 그래서 우리가 지키고 있는 거다. 우리 무리를 지켜야 하니까.', 66384),
(291773, 'koKR', '가장자리엔 가까이 가지 마라. 떨어지면 죽는다. 하라니르는 특히 순식간에.', '가장자리엔 가까이 가지 마라. 떨어지면 죽는다. 하라니르는 특히 순식간에.', 66384),
(291771, 'koKR', '할라지께서 자네가 온다고 하더군. 잘 왔네, 하쉬우라!', '', 66384),
(291765, 'koKR', '', '그 말은 안개가 너희를 썩은가지로부터 지켜줬단 얘기인가? 길을 잃고 헤맨 게 아니라?', 66384),
(291763, 'koKR', '', '...그래, 안다. 그 여자는 더 위대한 운명을 약속하며 우리 세계로 건너와, 우리를 데려가고 싶어 했지.\n\n내 종족 사이에서는 제안을 받아들여야 하느냐를 두고 의견이 갈렸고, 나는 반대했지만 내 어린 동생은 그자의 존재를 통해 위안을 찾았다. 우리가 도마나르에게 납치되던 순간에도 그 여자는 그 자리에 있었다.\n\n주라스는, 단지 본성이 선하다는 이유로 차원선과 마음을 달래는 영혼의 선율을 베풀어줄 존재가 있다고 믿지 않는 나를 음모론자 취급했지.\n\n그런데 너는 어떻게 그자를 아는 거지?', 66384),
(291762, 'koKR', '', '그런 것 같군. 저 멀리에서 놈들의 번쩍이는 전쟁 무기들을 봤다.\n\n<툴아마르가 가볍게 손을 내젓습니다.>\n\n비전은 언제나 믿음직한 벗이었지만, 빛은 나를 제대로 돕지 못했다. 되갚게 되어 기쁘군.', 66384),
(291760, 'koKR', '도마나르는 차원 곳곳에서 필멸의 도전자들을 낚아채 투기장에 던진다. 여기 서 있는 우리처럼 스스로 선 자들은, 우리가 보여줄 폭력 때문에 그저 존재가 허락되고 있을 뿐이다.\n\n투기장에 들어갈 거라면, 네 의지로 해라. 우리가 부서지지 않는다는 걸 놈들에게 보여줘라.', '', 66384),
(291759, 'koKR', '', '말인즉슨 다 왔다는 뜻이지. 누가 우릴 지켜보는 느낌이 안 드나?', 66384),
(291754, 'koKR', '', '건투를 빌지. 뭐, 날로라크께서 네 얼굴을 물어뜯어도 난 두 발 뻗고 잘 수 있을 것 같군.', 66384),
(291751, 'koKR', '', '좋다. 잠든 전쟁의 로아와 교감하고 싶다면, 그분의 불가에 앉아야 한다. 문제는 앉았던 자들이 돌아오지 못했다는 거다.', 66384),
(291749, 'koKR', '', '내 목숨을 걸고 맹세한다, 릴라주. 날로라크에게 축복을 받아 줄아만의 위협을 전부 몰아내겠다.', 66384),
(291740, 'koKR', '아마니 지원군? 상관없다. 더 많은 혼란과 죽음이 잘아타스 님을 기쁘게 할 테니!', '', 66384),
(291736, 'koKR', '우린 아킬존의 바람을 타고 날게 될 걸세. 옛날처럼 말이지.', '', 66384),
(291713, 'koKR', '용사여, 그대는 쿠엘탈라스를 위협하는 수많은 적을 밝혀냈소. 이제 다음 수를 논의해야 하오.', '', 66384),
(291711, 'koKR', '지금까지의 노력에 감사하오. 그대는 지긋지긋한 빛만개를 막아내고, 이교도 집단의 실체를 밝혀내고, 아마니의 침공으로부터 우리 동족을 지켜냈소.\n\n그러나 사안마다 처리할 일들이 남아 있소. 더 나은 미래를 이루려면 아직도 알아야 할 게 많다오. 다음을 함께 고민해 봅시다.', '', 66384),
(291710, 'koKR', '', '전 섭정의 명에 따라 이곳을 지키겠습니다. 이 승리가 아마니의 또 다른 공격을 막는 데 보탬이 되기를 바랄 뿐입니다.\n\n그보단 아라토르가... 걱정됩니다.\n\n아라토르의 말이 사실이라면, 아마니가 정말 황혼의 칼날단과 싸우고 있다면 우리도 전략을 재고할 이유로 충분합니다. 줄아만 편을 들겠다는 건 아니지만, 그래도 공동의 적을 둔 상대랑 싸우면 안 된다는 건 압니다.\n\n아라토르를 찾아주십시오, $p 님. 그 아이의 감은 믿을 만합니다.', 66384),
(291709, 'koKR', '처음 오르웨냐 님과 함께 하란다르를 떠났을 때, 나는 그 결단이 얼마나 소중한지 깨달았소.\n\n이제 그분이 홀로 흔들리게 두지 않을 것이오.\n\n알른의 균열은 실로 위험천만한 곳이지만... 반드시 도울 방법을 찾을 거요.', '', 66384),
(291708, 'koKR', '지금이야 잠잠하지만... 황혼의 칼날단이 이 지역의 지도를 갖고 있었다면 오래가진 못할 겁니다.', '', 66384),
(291707, 'koKR', '저는 일리다리에 보고하겠습니다. 오늘 수고 많으셨습니다.', '', 66384),
(291706, 'koKR', '서둘러요! 골목으로 돌아가죠. 부정한 빗물을 찾아 자엔의 행방을 추적하고, 지옥 마력 거래를 종식시켜야 합니다.', '', 66384),
(291702, 'koKR', '예감이 좋지 않습니다, $p 님.', '', 66384),
(291701, 'koKR', '떠나십시오. 다른 일 찾고.', '', 66384),
(291700, 'koKR', '', '모, 몰라요. 전 그냥 화물만 옮겨요. 진짜예요!', 66384),
(291699, 'koKR', '자엔은 어디 있습니까?', '', 66384),
(291693, 'koKR', '제가 그렇게 멍청해 보입니까? 자엔이 제 목을 치려고 들 겁니다!', '', 66384),
(291689, 'koKR', '부두주임을 찾았습니다. 가서 얘기해 보세요. 전 일이 틀어질 경우를 대비해 여기 숨어 있겠습니다.', '', 66384),
(291671, 'koKR', '', '날로라크를 찾을 준비는 됐나? 더 이상 지체할 시간 없다.', 66384),
(291657, 'koKR', '', '널 기억한다. 아마니자르에 있던 고킨예 말이다.\n\n킨두루가 너랑 리아드린을 하쉬우라로 삼았다는 게 사실이냐? 흠.\n\n네가 줄자라가 하셰이의 길을 걷는 걸 도왔고, 로아들이 돌아왔다는 얘기도 들었다.\n\n하지만 날로라크의 소굴에선 아직 아무 소리도 들리지 않더군.\n\n<허리에 손을 얹는 릴라주>\n\n역시. 우리한테는 가장 마지막에 온 거지? 우리도 도움이 필요했단 말이다!', 66384),
(291645, 'koKR', '항구로 가서 자엔의 화물을 받으러 왔다고 하세요. 놈들의 공급로를 흔들고, 그걸 증거로 삼는 겁니다. 항구에서 뵙죠.', '', 66384),
(291644, 'koKR', '안 돼! 여기서는 안 돼! 아직은!', '', 66384),
(291642, 'koKR', '아마니는 과거에 이룩했던 위대한 문명의 폐허에서 살아가고 있다, 고킨예.\n\n지금은 산에 틀어박혀 살지만, 옛날 우리 제국은 모든 국경이 바다에 닿을 정도로 광활했다.\n\n그리고 다시 찾을 수 있다. 용기를 내어 손을 뻗고, 가져오면 돼.', '', 66384),
(291636, 'koKR', '', '난 내 모든 동족이 도마나르에게서 해방됐다고 확신할 때까지 이 세계에 남아 있을 거다. 그 일에 협조해 주길 바란다. 나도 너를 도울 테니.\n\n그리고 내가 더 이상 필요 없어지면, 고향으로 돌아갈 길을 찾겠다.', 66384),
(291631, 'koKR', '벤비스, 멍청한 놈! 역시 네놈은 주인님의 은총을 받을 자격이 없다!', '', 66384),
(291630, 'koKR', '너희 도시는 가망이 없다. 어째서 잘아타스 님의 은총을 거부하느냐?', '', 66384),
(291629, 'koKR', '절망 속에서 울부짖어라! 너희 도시가 불타는 소리가 잘아타스에게 들릴 때까지!', '', 66384),
(291622, 'koKR', '', '아마니가 정말 많아. 모든 부족이 모였군.\n\n이렇게 다 함께 모인 건 정말 오랜만이지.\n\n하쉬우라, 이건 휴식이 아니라 축제처럼 보이는데. 뭐, 모르둔을 쓰러뜨렸으니 축제를 여는 것도 어울리긴 하다만.\n\n<줄자라가 장난스러운 웃음을 지어 보입니다.>\n\n자, 아마니답게 신나게 놀 준비는 됐나?', 66384),
(291616, 'koKR', '안에서 꽤 오래 머무르시던데요. 단서를 찾으셨습니까?', '', 66384),
(291597, 'koKR', '', '기다릴 동안 가공하지 않은 지옥 마력을 맛봐도 좋아. 품질 확인 차원에서 말이야.', 66384),
(291596, 'koKR', '', '걱정 마. 곧 더 많은 지룡들이 주입을 마칠 테니. 네가 구매할 몫도 따로 챙겨 놓을게.', 66384),
(291595, 'koKR', '', '안타깝게도 공허가 가까이 다가오면서 공급이 수요를 따라가지 못하는 상황이야.', 66384),
(291594, 'koKR', '', '공통된 목표나 성향을 지닌 자들이 자유롭게 어울릴 수 있는 안식처지.\n\n그리고... 원하는 게 있다면 뭐든 마음껏 즐길 수 있는 곳이기도 하고.\n\n들킬 걱정은 마. 자엔이 우리 뒤를 봐주고 있거든.', 66384),
(291591, 'koKR', '', '아, 처음 보는 얼굴이네. 신도레이 사이에 우리 입소문이 퍼지는 것 같아서 다행이야.\n\n이 소굴에는 무슨 일로 오셨을까?', 66384),
(291590, 'koKR', '', '아, 강한 기운이 느껴지더라니. 너였군.\n\n바로 모시지 못해서 미안하게 됐어, 나리. 이 소굴에는 무슨 일로 오셨을까?', 66384),
(291589, 'koKR', '', '키스티아가 자리를 뜨면서 경멸 섞인 시선으로 당신을 흘겨봅니다.', 66384),
(291588, 'koKR', '', '좋아. 가루가 준비되면 바로 가져와. 기다리게 하지 마.', 66384),
(291585, 'koKR', '', '화물이 하나 더 남긴 했는데, 거의 끝나 간.', 66384),
(291584, 'koKR', '', '지금 요구가 빡빡해. 유물들 얼마나 빨리 분해할 수 있지?', 66384),
(291583, 'koKR', '', '이제 모르둔을 공격해야 한다. 가자.', 66384),
(291573, 'koKR', '완전히 가망이 없는 건 아니야. 다만 당장 균열에서 끌어내야 한다.', '', 66384),
(291572, 'koKR', '알른가루의 힘은 여신 본인의 것이다. 그게 오르웨냐 네 뜻에 도움이 된다면, 함께 모아 주지.', '', 66384),
(291571, 'koKR', '너! 네가 빼앗아 갔지. 그분을 훔쳐 갔잖아! 전부 숨통을 끊어 주마!', '', 66384),
(291568, 'koKR', '북이 울릴 때 다들 어디 있었지? 아탈아만을 뜬눈으로 넘겨줬잖아!', '', 66384),
(291566, 'koKR', '감히 아마니가 다시 신도레이를 위협하다니!', '', 66384),
(291512, 'koKR', '', '아마니자르에서 본인 안전이 걱정된다면 무기를 집어넣고, 내 곁에서 떨어지지 마라.', 66384),
(291506, 'koKR', '', '$n 님, 할 얘기가 많습니다.\n\n일단 마을로 이동하시죠.', 66384),
(291492, 'koKR', '', '로아의 축복과 함께라면, 줄아만에서 황혼의 칼날단을 몰아낼 수 있다. 아마니를 위하여!', 66384),
(291485, 'koKR', '줄자라! 줄잔이 기다리지 않겠다고 하더니, 전사들을 데리고 나갔다! 이대로 가면 몰살당할지도 몰라!', '', 66384),
(291483, 'koKR', '', '아탈아만의 복수다! 저 침략자들에게 여기가 누구 땅인지 똑똑히 알려줘라!', 66384),
(291449, 'koKR', '', '추적 훈련, 아니면 사격 연습? 어떤 일로 오셨나요?', 66384),
(291448, 'koKR', '혈기사의 길은 균형이오. 그대는 어떤 길을 열려 하오?', '', 66384),
(291447, 'koKR', '마법을 추구하는 길은 발견과 신중함이 공존하는 여정입니다. 무엇을 배우고 싶으신가요?', '', 66384),
(291446, 'koKR', '와, 모두 정말 대단했어요.\n\n원정순찰대는 용감했어요. 자연과 조화를 이루며 우리를 지키는 솜씨가 놀라웠어요.\n\n혈기사는 강인하고 두려움을 몰랐어요. 자랑스럽게 전선을 지키며 흔들림 없는 책임감을 보여줬고요.\n\n그리고 마법학자들은... 정말 놀라웠어요. 끝이 없어 보이는 지식과 비전 마법으로 세상을 빚어내는 모습이 인상적이었어요.\n\n용사님은 그들을 가까이서 지켜봤잖아요. 제가 어떤 길을 따라야 할까요? 당신 눈에는 제가 어느 길에 어울려 보이나요?', '', 66384),
(291371, 'koKR', '진정하세요. 고삐만 붙들 게 아니라 박자를 타야 해요.', '', 66384),
(291363, 'koKR', '', '고마워요, $n 님. 덕분에 깃털 달린 친구들뿐만이 아니라 많은 사람과 우정을 나눌 수 있었어요.', 66384),
(291361, 'koKR', '황혼의 칼날단과 한패였군요. 아라토르, 당신 말이 맞았습니다. 속히 트랜퀼리엔으로 돌아갑시다!', '', 66384),
(291360, 'koKR', '', '그리고 이번에는 시체를 더 알맞은 곳에 옮겨놓도록.', 66384),
(291359, 'koKR', '', '작은 새들. 공허와 빛. 쓸데없이 질문이 너무 많아. 전부 해치워라.', 66384),
(291312, 'koKR', '시엘이 당신 손에 인장 반지를 슬쩍 쥐여줍니다.', '', 66384),
(291311, 'koKR', '질문은 그렇게 큰 소리로 하는 게 아닙니다만.', '', 66384),
(291310, 'koKR', '데노린이 당신 손에 인장 반지를 슬쩍 쥐여줍니다.', '', 66384),
(291309, 'koKR', '안타깝게도 모두 팔렸습니다. 대신 다른 생물들이 있는데 말이죠.', '', 66384),
(291308, 'koKR', '', '렌데일 양이 당신 손에 인장 반지를 슬쩍 쥐여줍니다.', 66384),
(291307, 'koKR', '', '뭘 말씀하시는 건지 모르겠네요. 저희는 그런 종류의 마법에는 손대지 않습니다.', 66384),
(291306, 'koKR', '알른가루의 광채를 통해 사이알요는 살아 있는 그림의 비밀을 풀어냈다. 그리고 힘과 위험이 얽힌 유산을 주르아샤르에게 맡긴 거다.', '', 66384),
(291305, 'koKR', '사이알요는 안료가 남긴 흔적에서 답을 찾으려 했다. 아직 드러나지 않은 계시를 엮어내려 애썼지.', '', 66384),
(291304, 'koKR', '그건 평범한 안료가 아니었다. 안에 깃든 알른가루가 들끓기 시작했지! 길들지 않은 색들이 날뛰며 메아리의 가마솥이 요동쳤다.', '', 66384),
(291303, 'koKR', '사이알요는 도가니를 사용해 만든 물감으로 자신의 영혼을 그림에 새겼고, 자신의 기억조차 넘어서는 것들을 끌어냈다.', '', 66384),
(291302, 'koKR', '메아리의 가마솥은 원래 주르아샤르 사이알요의 것이었다. 사이알요는 평범한 화가가 아니었다. 잊힌 것과 세상을 이어주는 다리였지.', '', 66384),
(291301, 'koKR', '불길이 솟구친다. 시련에 맞서게. 자네 영혼을 깨끗이 정화하게나!', '', 66384),
(291299, 'koKR', '이제 석탄이 타오를 준비가 되었네. 태워서 정화하게. 제단이 길을 보여줄 걸세.', '', 66384),
(291298, 'koKR', '그래! 불꽃이 돌아왔구먼. 잔알라이의 불이 다시 환하게 타오른다! 불의 주인이시여, 날아가게! 훨훨 날아가게나!', '', 66384),
(291297, 'koKR', '자네 안에서 불이 보이는군. 더 많은 석탄을 찾고, 더 많은 불을 피워 살아 있는 불길을 되살리게!', '', 66384),
(291296, 'koKR', '설마... 불꽃인가? 우리가 찾던 그 불인가?', '', 66384),
(291295, 'koKR', '물론입니다! 위상은 각 용군단의 지도자라고 보시면 됩니다.\n\n검은용군단, 붉은용군단, 녹색용군단, 청동용군단, 그리고 푸른용군단이 있지요. 제 용군단은 비전 마법의 보존에 헌신하고 있습니다.', '', 66384),
(291291, 'koKR', '살아 있는 불꽃은 사라졌지만, 그래도 많은 이의 마음속에 새겨졌지. 스스로를 정화하면 불꽃이 다시 일어날 걸세!', '', 66384),
(291290, 'koKR', '그동안 전 거리들을 지켜보고 있겠습니다.', '', 66384),
(291288, 'koKR', '줄자라에게 병력을 내줄 순 없지만, 하셰이의 여정을 도울 방법은 찾아보겠다.', '', 66384),
(291286, 'koKR', '마른나무껍질은 잔알라이에 대해 아는 게 별로 없네만, 잔알라이의 괴짜 로아 전령은 아직 동쪽 사원에 살고 있네.', '', 66384),
(291283, 'koKR', '하셰이의 길? 어릴 적 할머니께서 모닥불가에 앉아 하셰이에 대한 이야기를 들려주시곤 했지.', '', 66384),
(291282, 'koKR', '줄잔이 화난 듯 쿨라마라를 쏘아봅니다.', '', 66384),
(291237, 'koKR', '', '또 너인가? 그 엘프도 같이 왔네.\n\n<비웃듯 당신을 훑어보는 쿨라마라>\n\n줄자라가 너희 내장을 꺼내 두르고 다니지 않는 걸 보니 우리가 정말 위험하긴 한 모양이야.\n\n난 마른나무껍질 군대의 대표로서 썩은가지 놈들 감시 중이다.\n\n<저 멀리 늪지대에 임시로 세워진 썩은가지의 판잣집을 가리키는 쿨라마라>', 66384),
(291236, 'koKR', '', '전사들이 계속 실종되고 있는 이 와중에, 그대는 로아 유령 쫓아가겠단 말인가?', 66384),
(291227, 'koKR', '', '결국 죽은 사람인 건 똑같잖아, 잔!', 66384),
(291225, 'koKR', '', '빛나무를 이교도로부터 되찾는다고 얼마나 많은 전사를 희생시킨 거냐, 잔?', 66384),
(291224, 'koKR', '', '하! 할라지라고? 귀는 어디에다 두고 다니나, $r? 로아는 떠났다고 말하지 않았나?\n\n설령 남아 있다 해도 지금은 할라지의 사원까지 갈 수도 없다. 썩은가지랑 황혼의 칼날단이 손잡고 우릴 없애려 들고 있거든.\n\n두 전장에서 싸우고 있고, 썩은가지 놈들은 밤마다 마을을 공격하고 있다.\n\n게다가 안개까지 있지. 썩은가지와 황혼의 칼날단이 안개로 할라잘로어와 사원 주변을 완전히 가려버렸어.\n\n수많은 전사가 들어갔지만, 돌아온 이는 단 한 명도 없다.', 66384),
(291223, 'koKR', '누나, 드디어 돌아왔군! 누나가 로아 앞에서 고개를 조아릴 때, 난 진짜 힘을 손에 넣었지!', '', 66384),
(291220, 'koKR', '', '루타니는 겉보기엔 사람 같지만, 전부 식물로 이루어진 종족이네. 내 고향의 토착 종족이지. 내가 알기로 지상에 올라온 적은 없었는데, 이번이 처음일세.\n\n한데 이 루타니들은 내가 알던 이들과는 어딘가 달라. 변했어. 변형됐다고 해야 하나. 걱정되는군.', 66384),
(291199, 'koKR', '제 마법은 오래가지 않지만, 지옥 마력을 추적하는 데 도움이 될 겁니다. 금방 다시 합류하겠습니다.', '', 66384),
(291198, 'koKR', '당신의 시야로 지옥 마력을 추적하세요, $ct님. 금방 다시 합류하겠습니다.', '', 66384),
(291197, 'koKR', '당신이라면... 친숙할 테니 잘 알겠죠, 악마여. 금방 다시 합류하겠습니다.', '', 66384),
(291193, 'koKR', '하지만 아무도 확실히 알지 못해. 부디 엔리안을 도와다오.', '', 66384),
(291189, 'koKR', '모르타카는 균열의 광기에 처음 굴복한 하라티의 그림자라고 전해지지.', '', 66384),
(291184, 'koKR', '고킨예! 어서 불을 끄는 걸 도와다오!', '', 66384),
(291179, 'koKR', '', '계속 밀려오는군! 알른하라시여, 우리의 목소리를 듣고... 힘을 내려주소서!', 66384),
(291172, 'koKR', '', '이건 하셰이의 지팡이일세. 로아의 힘을 다루며 종족을 하나로 모으는 자가 사용했지.\n\n로아가 다시 우리에게 말을 건네게 된다면 이 지팡이가 필요할 걸세.\n\n진정한 하셰이를 우리가 마지막으로 본 게... 참 오래됐지.\n\n하나 늙은이라도 희망은 품게 마련이니까.', 66384),
(291166, 'koKR', '', '우리에겐 두 거룩한 로아가 있지! 사냥의 로아 할라지, 승리의 로아 아킬존이네!\n\n아킬존은 매서운 눈을 가졌지. 할라지는 그림자에 숨어 있네. 하지만 숨은 걸 드러낼 수 있는 로아지!\n\n난 지금... 아니, 예전엔 아킬존, 승리의 로아를 대변했다네!\n\n아, 로아의 목소릴 다시 듣고 싶군. 이 성지가 황혼의 칼날단에게 파괴되기 전에 말이야.\n\n하지만 지금 로아는 침묵하고 있네... 우릴 듣고 있을지, 아닐지. 아니면 우릴 향해 크게 말하고 있는데, 우리가 저지른 일 때문에 듣지 못하는 걸지도 모르지.\n\n하셰이가 있었다면... 어쩌면...', 66384),
(291161, 'koKR', '하지만 전쟁은 성기사들이 할 일을 바꿔 놓았다오.', '', 66384),
(291155, 'koKR', '그래야지. 우린 무슨 일이 있어도 영원한 형제니까.', '그래야지. 우린 무슨 일이 있어도 영원한 형제니까.', 66384),
(291154, 'koKR', '그렇지. 임무 때문에 바쁘긴 하겠지만, 방문 못 할 정도로 쉴 틈이 없진 않을 거야.', '', 66384),
(291153, 'koKR', '몰래 빠져나가는 건 아무도 못 막아. 봤지?', '몰래 빠져나가는 건 아무도 못 막아. 봤지?', 66384),
(291152, 'koKR', '쫓아낸 게 아니야, 이 바보야. 보고 싶었어.', '쫓아낸 게 아니야, 이 바보야. 보고 싶었어.', 66384),
(291151, 'koKR', '아마라크와 $p 덕분에 나아졌지만, 이제 나도 술카의 일원이야. 균열에 남아야 해. 일종의 자가 추방이지.', '', 66384),
(291150, 'koKR', '미안하다. 균열이 날 광기에 빠뜨려서 위험한 상태였어.', '', 66384),
(291149, 'koKR', '도망가면 어떡해. 죽은 줄 알았잖아!', '도망가면 어떡해. 죽은 줄 알았잖아!', 66384),
(291148, 'koKR', '뭐 하는 거야? 여기에 있으면 안 돼!', '', 66384),
(291144, 'koKR', '알겠네, 파올. 다른 이들을 모아 자네가 올 때까지 기다리겠네.', '', 66384),
(291143, 'koKR', '추아? 추아!', '', 66384),
(291142, 'koKR', '엔리안!', '엔리안!', 66384),
(291133, 'koKR', '', '[드레나이] 다이오니스 아카, 작은 형제여.', 66384),
(291132, 'koKR', '', '드레나이. 추방된 자.\n\n내 첫 번째 추방은 우리의 대대적인 도주가 시작되던 날이었다. 벨렌의 말이 내 마음을 일깨웠다. 제네다르에 발을 디딘 우리 모두 아르거스에서 함께 추방당한 셈이 되었지. 나는 그 선택이 옳기를 기도했다.\n\n두 번째 추방은 군단이 우리의 세계를 습격한 날이었다. 나는 주라스와 함께 지하에서 부서진 동력 핵을 대체할 광물을 찾고 있었다. 주라스는 어머니에게 애원해 함선을 나와 누나를 도우려 했지. 그런데 그 순간, 따잉 지옥절단기들의 발걸음에 흔들렸다. 우리가 지상으로 돌아왔을 땐, 지옥불 대포가 제네다르를 하늘로 내몰고 있었다. 떠나야만 했던 거지. 선택의 여지가 없었다. 그건 안다.\n\n그리고 지금... 다시 이렇게 됐군.\n\n잠시 혼자만의 시간이 필요하다. 나중에 널 찾겠다. 안전한 곳에서, 오래도록 이야기를 나눌 수 있는 곳에서 말이다.', 66384),
(291131, 'koKR', '', '우리의 동족이 기다려 온 기회를 주고 있군. 이제 도마나르에게 싸움을 걸 차례다.', 66384),
(291130, 'koKR', '', '지배자의 망루에서 만나자, 외행성인. 도마나르가 우리에게 필요한 것을 가지고 있다.', 66384),
(291129, 'koKR', '고의였다면 태양왕관이 무너지자마자 공격했을 겁니다. 분명 다른 이유가 있다고 생각합니다.', '', 66384),
(291128, 'koKR', '다 잃은 건 아닙니다, 엄브릭. 놈들이 전부를 훔쳐 간 건 아닐 테죠.', '', 66384),
(291127, 'koKR', '제가 실버문을 돕고 싶어도, 지금은 드릴 것이 많지 않습니다.', '', 66384),
(291126, 'koKR', '', '원정순찰대는 소요를 조사하러 떠났습니다. 태양왕관에는 방어 병력이 남아 있지 않았습니다.', 66384),
(291125, 'koKR', '내가 직접 조사하리다. 나중에 함께 경과를 대조해 봅시다.', '', 66384),
(291124, 'koKR', '마을의 안전을 진지하게 지켜 주는 세 사람에게는 아무리 감사를 표해도 모자라겠군.', '', 66384),
(291121, 'koKR', '<이 일기의 마지막 장에는 어제 날짜가 적혀 있습니다.>\n\n떠나려 한다는 걸 들켰다. 어떻게 알았는지는 모르겠지만.\n\n도망쳐야 한다. 도와줄 사람은 없다. 달콤한 거짓말을 믿은 내 잘못이야... 너무 무서웠어. 진작 눈치채야 했는데.\n\n내 연구를 넘길 수는 없다. 놈들에게 더 이상 무기를 쥐여줄 순 없어.\n\n제발 날 용서해 줘.', '<이 일기의 마지막 장에는 어제 날짜가 적혀 있습니다.>\n\n떠나려 한다는 걸 들켰다. 어떻게 알았는지는 모르겠지만.\n\n도망쳐야 한다. 도와줄 사람은 없다. 달콤한 거짓말을 믿은 내 잘못이야... 너무 무서웠어. 진작 눈치채야 했는데.\n\n내 연구를 넘길 수는 없다. 놈들에게 더 이상 무기를 쥐여줄 순 없어.\n\n제발 날 용서해 줘.', 66384),
(291120, 'koKR', '줄잔이 답답한 듯 신음을 흘립니다.', '', 66384),
(291117, 'koKR', '이미 짐에 넣은 거 아니에요?', '', 66384),
(291116, 'koKR', '내 지팡이! 자네 눈에 거룩한 아킬존께서 강림하셨나 보구먼.', '', 66384),
(291115, 'koKR', '잠깐만 기다리거라, 잔아.', '', 66384),
(291114, 'koKR', '외숙부님. 지금 공격받고 있단 말입니다! 꼭 필요한 것만 챙기십시오!', '', 66384),
(291112, 'koKR', '우리 땅이라고? 여긴 원래 전부 \"우리 땅\"이었다. 이 땅 위의 모든 것도!', '', 66384),
(291111, 'koKR', '', '더 이상 피 흘리지 맙시다. 습격을 멈추고, 빛나무를 넘기고, 당신들 땅으로 돌아가십시오.', 66384),
(291101, 'koKR', '작은 하라니르여, 돌아올 때 내 반드시 널 내 것으로 만들겠다.', '', 66384),
(291100, 'koKR', '다 끝났군. 바깥에서 만나자.', '', 66384),
(291095, 'koKR', '', '드레나이. 하나의 단어다. 알고 있나? 그 의미는... 추방이다.\n\n<숨을 내쉬며 시선을 돌리는 툴아마르>\n\n혼자 있고 싶다. 시간이 필요해.\n\n나중에 다시 보자. 널 찾겠다. 안전한 곳에서.', 66384),
(291090, 'koKR', '오너라. 네 정수도 내 것으로 삼겠다.', '', 66384),
(291089, 'koKR', '난 널 해치우고 술카가 될 거다.', '', 66384),
(291087, 'koKR', '', '[드레나이] 다이오니스 아카, 돌로스.', 66384),
(291083, 'koKR', '', '낭비할 시간 없어요!', 66384),
(291082, 'koKR', '', '가서 뵙겠습니다, $p 님.', 66384),
(291071, 'koKR', '고향...', '', 66384),
(291068, 'koKR', '', '잔잔한 바닷바람의 향기가 동굴을 가득 메우는군.', 66384),
(291064, 'koKR', '제 여동생 베란은 공허에 사로잡혔을지 몰라도, 기억은 되찾을 수 있을지도 모르죠.', '', 66384),
(291062, 'koKR', '어둠수호병 탐지 결과가 저쪽에서 나오고 있어요.', '', 66384),
(291061, 'koKR', '알론서스가 말해줬소. 은빛 성기사단은 본래 이런 봉사에 힘쓰도록 세워진 거라고.', '', 66384),
(291060, 'koKR', '이게 은빛 성기사단이 관여할 만한 일은 아니지 않습니까?', '', 66384),
(291058, 'koKR', '하지만, 무고한 이가 고통받도록 내버려두는 것... 그것이야말로 최악의 악이오.', '', 66384),
(291056, 'koKR', '죄송합니다, 선생님. 여긴 일꾼 외 출입 금지입니다. 일정이 무척 촉박해서요.\n\n찾으시는 거라도 있습니까?', '', 66384),
(291052, 'koKR', '', '기사단은 영원노래 숲을 지킨다. 용사님, 우리끼리 추적하죠.', 66384),
(291051, 'koKR', '', '국경? 하. 줄아만에서 황혼의 칼날단한테 죽고 싶다면 말리진 않겠다. 하지만 군대는 들여보낼 수 없다.', 66384),
(291049, 'koKR', '', '따라와라, 형제자매들이여. 조용히 움직여라.', 66384),
(291048, 'koKR', '', '<두 번 추방당한 툴아마르가 감사하다는 듯 고개를 끄덕이더니, 동족을 이끌고 안전한 곳으로 향합니다.>', 66384),
(291037, 'koKR', '', '그나마 보낼 수 있었던 원정순찰대 대부분은 이곳 서쪽, 태양왕관 나무에서 방어선을 구축하고 있다네.\n\n할두런은 우리 몇 명을 이 뿌릿길로 이끌었지. 이 길을 통해 지원군을 확보할 수 있다고 했네. 솔직히 말하면... 최소한 $c 하나랑, 그리고... 저 여자가 전부일 줄은 몰랐지.\n\n<발리아가 오르웨냐를 뚫어지게 바라봅니다.>', 66384),
(291028, 'koKR', '', '여깁니다, 용사님! 상황이 점점... 심각해지고 있습니다.', 66384),
(291009, 'koKR', '여기서 뭐 하는 거지, 고킨예?\n\n로아한테 가서나 아양이나 떨어야 하는 거 아닌가?', '', 66384),
(291006, 'koKR', '엔리안, 안 돼. 너는 너무 약해!', '', 66384),
(291005, 'koKR', '이제 뭘 해야 할지 알아. 모르타카를 해치워야 해.', '', 66384),
(290993, 'koKR', '', '적이 특이점 고정기를 공격하지 못하게 하십시오!', 66384),
(290989, 'koKR', '당장 알아보겠소. 아무튼 그대가 여기 있어서 다행이오. 사실 도움이 필요한 일이 있다오.', '', 66384),
(290988, 'koKR', '정말이오? 별 이상한 일이 다 있군.', '', 66384),
(290987, 'koKR', '이교도? 몹시 무거운 고발이구려.', '', 66384),
(290986, 'koKR', '어떤 의미로는 그렇소. 다만, 어떤 이는 거대한 망치로 사악한 자를 내리치는 데 만족하오.', '', 66384),
(290985, 'koKR', '태양길잡이가 된다는 건 이런 겁니까?', '', 66384),
(290981, 'koKR', '우리의 평온에서 바람직하지 못한 일이 일어나고 있다니 생각하니 마음이 아프군.', '', 66384),
(290980, 'koKR', '자, 용사님. 말하십시오.', '', 66384),
(290979, 'koKR', '마법학자 엄브릭! 연구는 잘 되어가고 있소?', '', 66384),
(290975, 'koKR', '용사, 빛의 성소로 돌아가시오. 이 싸움은 아직 끝나지 않았소.', '', 66384),
(290953, 'koKR', '', '<툴아마르가 당신이 다가오자 눈을 뜨고 고개를 끄덕여 인사합니다.\n\n그리고는 당신 너머로 지나가는 공허 존재를 향해 냉소를 지어 보입니다.>', 66384),
(290950, 'koKR', '', '아, 생각도 못 한 손님이 오셨네. 그래도 불청객은 아니긴 해.\n\n이 소굴에는 무슨 용건으로 행차하셨을까?', 66384),
(290949, 'koKR', '주라스가 울음을 터뜨립니다. 툴아마르는 고개를 돌려 눈가를 훔칩니다.', '', 66384),
(290948, 'koKR', '', '도마나르가 너를 따라가게 둘 수는 없다. 다른 길은 없다, 형제여.', 66384),
(290947, 'koKR', '뭐라고? 안 간다니?!', '', 66384),
(290946, 'koKR', '', '물론이지. 성물회는 도움이 필요한 곳이라면 힘을 보태거든. 관심 있으면 말해.', 66384),
(290945, 'koKR', '아마니 고개가 우선이오. 다시는 쿠엘탈라스를 침공하게 두지 않겠소.', '', 66384),
(290944, 'koKR', '돌아가려는 건가? 제발 조심해라, 툴아마르.', '', 66384),
(290942, 'koKR', '조사하고 싶다면 해도 좋다, 아라토르. 대신 최대한 빨리 고개로 와야 한다.', '', 66384),
(290941, 'koKR', '', '공허의 존재에게 가야 한다. 그곳에서 보자.', 66384),
(290939, 'koKR', '', '툴아마르가 당신을 바라보며 위쪽을 가리킵니다.', 66384),
(290938, 'koKR', '', '도마나르가 쓸 만한 물건을 가지고 있다. 찾아야 한다. 피 갖고 이방인을 탓하지 마라, 형제자매들이여.', 66384),
(290937, 'koKR', '', '태양샘에서 터져 나온 마력은... 지금껏 봐온 어떤 마법보다도 강력했습니다. 참고로 전 마법을 수련한 기간이 결코 짧지 않아요. 저 군대가 우릴 지켜주러 온 거라는데, 마력 쇄도를 일으킨 것도 저들이라고 들었습니다! 뭘 제대로 알고 건드리기나 하는 걸까요?', 66384),
(290935, 'koKR', '', '이런저런 일이 다 터지고, 하늘에는 말도 안 되는 어둠의 소용돌이까지 생긴 탓에 손님들이 줄줄이 떠나고 있어요. 저도 이곳을 관리하는 사람이 아니었다면 여기 남아 있었을지 모르겠네요. 방을 원하신다면 드리겠습니다.', 66384),
(290934, 'koKR', '로르테마르! 주변 일대를 확보했지만, 놈들이 아마니 고개로 진격하고 있소.', '', 66384),
(290932, 'koKR', '도움을 줘서 고맙소. 로르테마르에게 태양왕관에서 있었던 일을 들었소.\n\n태양왕관은 내가 맡고 있었는데, 나무가 쓰러지는 소리를 듣고 그 원인을 조사하러 떠났었다오. 빛만개의 소행일지도 모른다 생각했소. 설마 아마니가 그렇게 대담하게 침범할 줄은 상상도 못 했지.\n\n빛만개는 내가 해결하리다. 로르테마르는 아마니를 상대하면 되겠지... 제발 이번엔 다른 눈까지 내주지 않기를 바랄 뿐이오.\n\n<윙크를 보내는 할두런>', '', 66384),
(290931, 'koKR', '태양샘의 급격한 쇄도로 용매들이 예민해졌소. 위험을 바로 감지하는 생물이거든. 용매들이 이렇게 불안에 떠는 광경은 처음 본다오. 동물들도 이런데, 영원노래 숲은 어떨지 모르겠군.', '', 66384),
(290929, 'koKR', '', '마지막으로 쿠엘다나스에 어둠이 닥쳤을 때가 언제였냐면, 아서스가 스컬지 군대를 이끌고 왕국에 쳐들어왔을 무렵이었습니다. 이젠 다른 군대가 도시를 거닐고 있죠. 우리를 지켜주러 왔다면서 말입니다... 근데, 정말 그럴까요?', 66384),
(290927, 'koKR', '', '두 번 추방당한 툴아마르가 눈앞에 형성되는 희미한 차원문을 자세히 살핍니다.', 66384),
(290926, 'koKR', '', '불평은. 자, 효과가 있지 않나.', 66384),
(290925, 'koKR', '다음에는 경고라도 해라!', '', 66384),
(290924, 'koKR', '', '이쪽이다, 주라스.', 66384),
(290923, 'koKR', '주라스가 자신에게 피를 묻히는 툴아마르를 심드렁한 시선으로 바라봅니다.', '', 66384),
(290921, 'koKR', '<쓰러진 빛만개 나무를 깔끔하게 가공한 목재 더미입니다.>', '', 66384),
(290916, 'koKR', '<사내가 말없이 당신을 위아래로 훑어봅니다.\n\n방에 있는 다른 이들의 낮은 웃음소리가 들려옵니다.>', '', 66384),
(290915, 'koKR', '아, 동물원에 오신 것을 환영합니다. 쿠엘탈라스를 넘어 다양한 지역에서 온 생물을 보유하고 있습니다.\n\n구매에 특별 허가가 필요한 종이라도 걱정하지 마세요. 약간의 수수료만 지불하시면 그 불편함은 저희가 기꺼이 처리해 드리겠습니다.', '', 66384),
(290906, 'koKR', '', '예약은 하고 오셨나요? 요즘 일정 잡기도 쉽지 않아요. 미래를 위해 돈을 넉넉하게 쓸 생각이 있는 시민들은 널리고 널렸으니까요. 다들 줄 서기 바쁘죠.', 66384),
(290905, 'koKR', '<이 아마니는 빛만개 생명체에게 참혹한 최후를 맞이했습니다.>', '<이 아마니는 빛만개 생명체에게 참혹한 최후를 맞이했습니다.>', 66384),
(290892, 'koKR', '', '루이아가 물러나고 알른가루를 손에 넣었으니, 이제 광란을 잠재울 수 있네.', 66384),
(290889, 'koKR', '', '그 자루... 씨앗이 들어 있습니까?', 66384),
(290888, 'koKR', '', '루가르가 쓰러지기 전에 몇 놈은 쓰러뜨린 모양입니다.', 66384),
(290883, 'koKR', '빛의 선봉대를 위한 숙소와 물자가 필요하오.', '', 66384),
(290882, 'koKR', '$p, 너만 준비됐으면 나도 의식을 시작할 수 있어.', '', 66384),
(290881, 'koKR', '먼저 수호물을 배치해라. 벌써 현신들이 몰려드는 게 느껴지는군.', '', 66384),
(290879, 'koKR', '', '진균의 틈 웅덩이는 본디 아름다운 곳이었습니다. 균형이 어그러지면 이렇게 되는 겁니다. 버섯전사들이 지나치게 자라서 웅덩이를 오염시켰어요.', 66384),
(290878, 'koKR', '', '루가르는 목숨을 바쳐 싸웠지만, 전투를 승리로 이끌기엔 역부족이었습니다. 강인한 전사라고 해도 수적으로 밀리면 누구라도 당할 수 있지요.\n\n루가르의 죽음과 루타니가 나르던 씨앗이 도난당한 것도 모두 버섯전사의 소행으로 보입니다.\n\n이 길을 따라 더 올라가면 진균의 틈이 나옵니다. 가까이 다가가야 하니, 준비되면 말씀하십시오.', 66384),
(290876, 'koKR', '침입자인가?! 경비대! 장로님들을 지켜라!', '', 66384),
(290875, 'koKR', '', '진정하게, 오르웨냐. 루이아는 심판을 받게 될 걸세. 자, 태양왕관 나무로 물러가세.', 66384),
(290874, 'koKR', '', '루이아가 뿌리를 따라 달아나는 게 느껴지네. 우리도 얼른...', 66384),
(290872, 'koKR', '', '적을 저지했고, 특이점 고정기도 가동됐습니다!', 66384),
(290871, 'koKR', '', '서두르세요, 용사님. 적이 오기 전에 특이점 고정기 주변에 방어 시설을 설치해야 합니다!', 66384),
(290870, 'koKR', '', '꽃의 양분이 되어라!', 66384),
(290868, 'koKR', '저 괴물은 분명 빛만개에서 나온 겁니다! 마법학자에게 알려야 합니다.', '', 66384),
(290867, 'koKR', '바로 저기가 의식 장소야!', '', 66384),
(290866, 'koKR', '그게... 잘 모르겠어. 다시 돌아가야 하는 것 같아.', '', 66384),
(290865, 'koKR', '윽... 의식 장소가 가까워졌어.', '', 66384),
(290864, 'koKR', '조심해. 여기에는 우리를 갈기갈기 찢어버릴 존재들이 있거든.', '', 66384),
(290863, 'koKR', '내 일부가 뜯겨 나가는 것 같은 고통이야.', '', 66384),
(290861, 'koKR', '우리를 균열 속으로 이끌고 있어. 따라가야 해.', '', 66384),
(290858, 'koKR', '뭔가 가까이에서 느껴져... 날 끌어당기고 있어.', '', 66384),
(290857, 'koKR', '', '적이 남쪽에서 접근합니다! 특이점 고정기에 도달하지 못하게 막으십시오!', 66384),
(290855, 'koKR', '...그리고 이 참사에 가까운 사태에 대해서도 사과를 드려야겠군요.', '', 66384),
(290854, 'koKR', '됐습니다! 공허폭풍으로 통하는 길이 열렸습니다. 로르테마르에게 알려야 합니다.', '', 66384),
(290853, 'koKR', '저게...  무슨 괴물이지? 용사님, 제가 주문에 집중해 이 혼돈을 끝낼 테니, 잠시 놈을 상대해 주십시오!', '', 66384),
(290852, 'koKR', '용사님, 이제 알겠습니다! 초점을 공허폭풍에 맞춰 조율해야 합니다.', '', 66384),
(290851, 'koKR', '큰 문제가 생겼는데... 가십시오. 방법을 찾는 대로 따라가겠습니다.', '', 66384),
(290850, 'koKR', '초점을 둘러싼 수호물을 해제하는 데 힘을 보태 주십시오!', '', 66384),
(290849, 'koKR', '제압하십시오! 보호막을 처리하겠습니다.', '', 66384),
(290848, 'koKR', '거짓말! 누구에게도 초점을 내주지 않겠다!', '', 66384),
(290847, 'koKR', '세라넬! 무기를 거두십시오! 로르테마르 본인의 허가도 받았습니다!', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(290844, 'koKR', '단순무식하긴 해도 효과적이군요. 초점은 저 앞에 있을 겁니다.', '', 66384),
(290843, 'koKR', '제가... 구금된 것 같네요. 앞에 있는 피조물이 롬매스의 주문을 강화하고 있습니다. 파괴하십시오.', '', 66384),
(290842, 'koKR', '이 이상은 못 간다, 엄브릭. 이 새로운 방어 시설은 특별히 널 염두에 두고 만들었지.', '', 66384),
(290841, 'koKR', '롬매스가 절 막으려고 이렇게까지 할 줄이야...', '', 66384),
(290840, 'koKR', '즐거운... 하루... 보내십시오...', '즐거운... 하루... 보내십시오...', 66384),
(290838, 'koKR', '승인되지 않은 출입 감지.', '승인되지 않은 출입 감지.', 66384),
(290837, 'koKR', '이 도서관을 얼마나 그리워했는지. 뭐, 오래 머물 여유는 없지만요.', '', 66384),
(290835, 'koKR', '참, 사서들을 조심하세요. 이 전당에서 지식은... 주먹처럼 매울 때가 있거든요.', '', 66384),
(290834, 'koKR', '챙길 물건들이 있습니다. 출구에서 합류하겠습니다.', '', 66384),
(290833, 'koKR', '역시 제게 전언을 남겼군요. 아쉽게 됐지만, 경비병들을 제압해야 합니다.', '', 66384),
(290832, 'koKR', '똑똑히 경고했을 텐데, 엄브릭! 너는 영원히 출입 금지다! 더 버티지 말고 떠나라. 그렇지 않으면...', '', 66384),
(290831, 'koKR', '승인되지 않은 출입 감지. 기다려 주십시오.', '승인되지 않은 출입 감지. 기다려 주십시오.', 66384),
(290830, 'koKR', '정원에 공허폭풍에 들어가는 데 필요한... 황혼의 초점이 있습니다.', '', 66384),
(290801, 'koKR', '알겠습니다... 단, 이번 교훈도 다른 것들과 비슷하다면...', '', 66384),
(290800, 'koKR', '아라토르, 내가 전에 다른 길을 찾아야 한다고 했지. 이제 정말 시작할 때일세.', '', 66384),
(290693, 'koKR', '', '이건 또 무슨 화물이야?', 66384),
(290676, 'koKR', '', '알른하라의 뿌리시여, 악취가 진동하는군요. 딱 버섯전사들이 좋아할 만한 곳입니다.', 66384),
(290671, 'koKR', '돈을 넉넉하게 가져온 구매자 행세를 해보세요. 지옥 마력 상인을 만날 수 있을 겁니다.', '', 66384),
(290660, 'koKR', '안테노리안 군주가 모두에게 피난처를 마련해 준 것 같습니다.', '', 66384),
(290646, 'koKR', '', '새로 온 사람에, 물자에... 다들 무슨 재난이라도 대비하는 것 같아.', 66384),
(290645, 'koKR', '', '걱정 마세요. 안테노리안 님이 우리 모두를 지켜주실 테니.', 66384),
(290644, 'koKR', '빛은 반드시 승리합니다. 그런 믿음을 가져야 하고요.', '', 66384),
(290643, 'koKR', '', '하늘을 보세요! 빛은 우리 모두를 버렸습니다.', 66384),
(290637, 'koKR', '', '발밑을 조심하세요... 작은 아이들이 돌아다니고 있거든요! \n\n여기엔 무슨 일로 오셨나요?', 66384),
(290636, 'koKR', '$n, 보세요. 어떤 엘프들이 절 보곤 부리나케 도망치더군요. 근데 뭔가를 두고 갔습니다.', '', 66384),
(290629, 'koKR', '', '트랜퀼리엔 주민들이 공포에 떨며 도움을 호소하고 있어요.\n\n주민들이 걸어온 길은 너무나 아득하고, 태양의 빛은 이미 등을 돌린 것만 같죠...', 66384),
(290626, 'koKR', '그래서 다들 그 얘기 하잖아. 무기를 최대한 장만해야 해.', '그래서 다들 그 얘기 하잖아. 무기를 최대한 장만해야 해.', 66384),
(290625, 'koKR', '공허는 기다려주지 않아. 학술원에서 배우기엔 너무 느려.', '공허는 기다려주지 않아. 학술원에서 배우기엔 너무 느려.', 66384),
(290624, 'koKR', '2년을 더 버텨야 졸업이라고? 당장 2달 뒤면 실버문이 사라질지도 모르는 마당에!', '2년을 더 버텨야 졸업이라고? 당장 2달 뒤면 실버문이 사라질지도 모르는 마당에!', 66384),
(290623, 'koKR', '전혀 아깝지 않은 지출이지. 우리 종족을 멸종에서 한 번 구해줬으니까. 한 번 더 구해줄 거야.', '전혀 아깝지 않은 지출이지. 우리 종족을 멸종에서 한 번 구해줬으니까. 한 번 더 구해줄 거야.', 66384),
(290622, 'koKR', '네 연줄이 쓸모 있었어. 하인이 골목에서 보급품을 구해 오더군. 일탈치곤 값이 많이 나갔지만, 꼭 필요했으니.', '네 연줄이 쓸모 있었어. 하인이 골목에서 보급품을 구해 오더군. 일탈치곤 값이 많이 나갔지만, 꼭 필요했으니.', 66384),
(290621, 'koKR', '근데 그것도 다 돈이잖아. 지옥 마법이 어디 한두 푼인가. 자엔하고 협상해 보는 건 어때? 거래를 하는 거지.', '근데 그것도 다 돈이잖아. 지옥 마법이 어디 한두 푼인가. 자엔하고 협상해 보는 건 어때? 거래를 하는 거지.', 66384),
(290620, 'koKR', '공허가 스컬지 때처럼 도시를 공격해 온다면 아무도 골목을 지켜주지 않을 거야. 우리도 무장해야 해.', '공허가 스컬지 때처럼 도시를 공격해 온다면 아무도 골목을 지켜주지 않을 거야. 우리도 무장해야 해.', 66384),
(290619, 'koKR', '원정순찰대의 부재가 살인범에게 너무나 편리한 환경이 되고 있군요.', '', 66384),
(290602, 'koKR', '', '루가르는 전사이자 이름 높은 사냥꾼이었고, 스승이었습니다. 제가 아는 모든 건 루가르에게 배웠다고 해도 과언이 아니죠. 우리 중에서 누구보다 뛰어난 이였지만, 세월 앞에는 장사가 없더군요.\n\n요즘은 정원에 몰두하며... 루타니들과 새로운 품종의 틸라탁을 연구하고 있었습니다. 매우 천천히 자라는 뿌리채소인데, 맛이 뛰어났죠.\n\n수확량을 늘리면서도 생장 주기를 단축할 수 있다고 호언장담했는데... 이젠 결과를 알 길이 없겠군요.', 66384),
(290600, 'koKR', '', '루가르가 쓰러졌다니 믿기지 않습니다. 함께 사냥을 함께 나설 참이었는데.\n\n<네이레이아가 말없이 고개를 숙입니다. 잠시 후, 네이레이아가 지친 한숨을 내쉬며 몸을 곧게 폅니다.>\n\n루가르와 함께했던 루타니 중 일부는 아직 살아 있을지도 모릅니다. 여기에 쓰러져 있는 녀석 말고도요. 그냥 내버려두면 안 돼요. 이곳 버섯전사들은 행동 방식이 너무 이질적입니다.', 66384),
(290598, 'koKR', '따라와라.', '', 66384),
(290593, 'koKR', '<온몸이 상처로 뒤덮인 버섯전사가 끝내 쓰러집니다. 공기엔 썩은 냄새와 곰팡내가 짙게 배어듭니다.>', '', 66384),
(290592, 'koKR', '전령이 사냥에서 돌아온 뒤로 이상하게 행동하더군요...', '전령이 사냥에서 돌아온 뒤로 이상하게 행동하더군요...', 66384),
(290589, 'koKR', '그럴 리가요.', '그럴 리가요.', 66384),
(290588, 'koKR', '항상 저랬습니까?', '항상 저랬습니까?', 66384),
(290586, 'koKR', '', '안 됩니다! 여기서 무슨 일이 있었는지 알아내야 합니다.', 66384),
(290585, 'koKR', '', '서두르십시오, $n 님.', 66384),
(290582, 'koKR', '', '빛이... 뜨거워...', 66384),
(290572, 'koKR', '', '킨두루... 당신 말이 맞기를 바라죠. 아마니를 위하여!', 66384),
(290560, 'koKR', '', '너무 급히 가버리긴!', 66384),
(290559, 'koKR', '이 씨앗을 실버문으로 가져가겠소. 마법학자들이 무언가 실마리를 얻을 수 있겠지.', '', 66384),
(290558, 'koKR', '$p 님, 전 평생 빛을 충직하게 섬기며 살아왔고, 그 과정에서 한쪽 눈도 잃었습니다.\n\n저보다 강한 성기사가 없다고는 말 못 하겠지만, 많지는 않을 겁니다.\n\n문제는 몇몇 수호병과 종자를 제외하면 대부분이 실버문으로 차출되어 공허에 맞서고 있습니다.\n\n혹시 제가 빛을 저버리는 행동을 한 건 아닐까 하는 의문이 들지만, 이유를 알 수 없더군요.', '', 66384),
(290557, 'koKR', '', '조심하세요. 저도 저렇게 시작했다가 결국에는 키우게 됐거든요.', 66384),
(290556, 'koKR', '간식을 달라는 건지, 컵케이크를 동생쯤으로 아는 건지 모르겠네요.', '', 66384),
(290553, 'koKR', '제가 태양샘으로 부름을 받지 못한 것도 장점은 있더군요. 희망의 빛 예배당 방어를 지휘할 수 있었으니까요.', '', 66384),
(290552, 'koKR', '', '그건 지금 상관없어. 자네 도움을 받아야 해.', 66384),
(290551, 'koKR', '아이 둘이 아직 밖에 있다!', '', 66384),
(290548, 'koKR', '하란다르에 외부인을 들이는 건 금기다! 오르웨냐는 지상에 올라가 너희 세계에 우리의 존재를 알림으로써 율법을 어겼다. 그런데 이제 이런 일까지?\n\n오르웨냐를 친구로 둔 걸 다행으로 알아라. 아니면 뿌리로 속박해 샙터들한테 던져줬을 테니까.', '', 66384),
(290545, 'koKR', '<원정순찰대의 정찰 보고서입니다. 데솔름 폐허에서 감지된 수상한 움직임, 정체불명의 공허 생명체 출현, 실종자 발생 등 우려스러운 사건들이 연이어 기록되어 있습니다.\n\n하지만 수많은 보고에도 불구하고 실질적인 대응은 거의 이뤄지지 않은 듯합니다.>', '<원정순찰대의 정찰 보고서입니다. 데솔름 폐허에서 감지된 수상한 움직임, 정체불명의 공허 생명체 출현, 실종자 발생 등 우려스러운 사건들이 연이어 기록되어 있습니다.\n\n하지만 수많은 보고에도 불구하고 실질적인 대응은 거의 이뤄지지 않은 듯합니다.>', 66384),
(290544, 'koKR', '<전날 밤 예정되어 있던 순찰 일정이 모두 지워져 있습니다. 경비대장의 쪽지가 남겨져 있습니다.>\n\n오늘 밤은 나 혼자 경계 보초를 서겠다. 총독의 명령이니 편히 쉬도록.\n\nL.', '<전날 밤 예정되어 있던 순찰 일정이 모두 지워져 있습니다. 경비대장의 쪽지가 남겨져 있습니다.>\n\n오늘 밤은 나 혼자 경계 보초를 서겠다. 총독의 명령이니 편히 쉬도록.\n\nL.', 66384),
(290542, 'koKR', '<이 책에는 엘프의 전통적인 설교와는 완전히 다른 기이한 설교가 실려 있습니다.\n\n빛이 드리우는 그림자의 중요성을 강조하고 있으며, 다가오는 일식을 달래야 한다는 경고도 보입니다.>', '<이 책에는 엘프의 전통적인 설교와는 완전히 다른 기이한 설교가 실려 있습니다.\n\n빛이 드리우는 그림자의 중요성을 강조하고 있으며, 다가오는 일식을 달래야 한다는 경고도 보입니다.>', 66384),
(290541, 'koKR', '트랜퀼리엔에 오신 것을 환영합니다!\n\n가장 어두운 시기 속에서도 트랜퀼리엔은 살아남았습니다. 안심하고 편히 쉬셔도 됩니다. 힘겨운 날들은 지나갔습니다.\n\n곧 새로운 변화가 찾아옵니다. 모든 것이 괜찮아질 것입니다.\n\n당신이 이곳에 온 것도 이유가 있을지 모릅니다. 당장 모를 수 있지만 말이죠.', '트랜퀼리엔에 오신 것을 환영합니다!\n\n이 작은 마을도 적잖은 시련을 겪었습니다.\n\n힘겨웠던 날들은 지나갔고, 곧 새로운 변화가 찾아올 것입니다.\n\n당신이 이곳에 온 데는 분명한 이유가 있습니다. 아직 모르시더라도 말이죠.', 66384),
(290540, 'koKR', '<신입 주민 환영 꾸러미에 가끔 경비대장이 넣어주는 쪽지로 보입니다.>\n\n앞날이 불확실하게 느껴질지라도, 진실은 바로 눈앞에 있습니다.\n\n트랜퀼리엔 남쪽으로 와 동참하십시오. 미행이 붙지 않도록 주의하시길.', '<신입 주민 환영 꾸러미에 가끔 경비대장이 넣어주는 쪽지로 보입니다.>\n\n앞날이 불확실하게 느껴질지라도, 진실은 바로 눈앞에 있습니다.\n\n트랜퀼리엔 남쪽으로 와 동참하십시오. 미행이 붙지 않도록 주의하시길.', 66384),
(290539, 'koKR', '', '알른가루를 전사들에게 나눠주게. 빛만개에 맞서 싸울 힘을 얻을 걸세.', 66384),
(290536, 'koKR', '어쩌면 빛만개가 선봉대에 실제로 도움이 될지도 모릅니다. 최소한 확인은 해봐야 합니다.', '', 66384),
(290535, 'koKR', '', '제발 내려와!', 66384),
(290534, 'koKR', '이곳 태양샘에서 승리하는 데 많은 것이 걸려 있습니다, $p 님.\n\n무거운 짐이긴 하지만, 거부하는 것보다는 덜하겠죠.\n\n부담을 함께 나눠 들어주셔서 감사합니다.', '', 66384),
(290531, 'koKR', '영원노래 숲에 빛만개가 퍼지고 있소. 지금 행동하지 않으면 늦을 것이오. 상황이 절박하오, 오르웨냐.', '', 66384),
(290522, 'koKR', '', '킨두루 외숙부가 공물을 바치라고 했지. 적의 머리카락이면 충분할 거다.', 66384),
(290521, 'koKR', '늦기 전에 줄잔을 찾아야 합니다.', '', 66384),
(290520, 'koKR', '멈추십시오! 피를 흘릴 필요는 없잖습니까!', '', 66384),
(290518, 'koKR', '', '그래도 독수리들이 돌아온 건 좋은 징조 같습니다.', 66384),
(290513, 'koKR', '', '술카의 의식을 치를 준비가 됐네. 알른의 균열에 들어가도 우릴 지켜줄 걸세... 잠깐은 말이지.', 66384),
(290511, 'koKR', '로르테마르 님, 근처에서 은신처의 흔적을 발견했습니다...', '', 66384),
(290498, 'koKR', '감각을 활용해 지옥 마력을 추적하세요, $c님. 금방 다시 합류하겠습니다.', '', 66384),
(290488, 'koKR', '흔적이 희미하군요... 그래도 아직 남아 있습니다.', '', 66384),
(290487, 'koKR', '그러니까...\n\n솔직히 말하자면, 균열에서 튀어나오는 수액괴물을 으깨고, 그 영향에 삼켜지면 서로 도와주고 있어.\n\n그게 우리가 할 수 있는 전부야.', '그러니까...\n\n솔직히 말하자면, 균열에서 튀어나오는 수액괴물을 으깨고, 그 영향에 삼켜지면 서로 도와주고 있어.\n\n그게 우리가 할 수 있는 전부야.', 66384),
(290485, 'koKR', '알른의 균열은 하라니르에게 위험한 장소다. 여신의 목소리가 너무 강하게 울리는 탓에, 부름에 휘말려 길을 잃고 말지. 심지어 균열에서 탈출한 생명체들조차 우리에게 해가 되는 수액을 흘린다.\n\n누군가는 균열의 영향이 하란다르 전역으로 퍼지는 걸 막아야 해. 그래서 우리가 여기 있는 거다.', '알른의 균열은 하라니르에게 위험한 장소다. 여신의 목소리가 너무 강하게 울리는 탓에, 부름에 휘말려 길을 잃고 말지. 심지어 균열에서 탈출한 생명체들조차 우리에게 해가 되는 수액을 흘린다.\n\n누군가는 균열의 영향이 하란다르 전역으로 퍼지는 걸 막아야 해. 그래서 우리가 여기 있는 거다.', 66384),
(290449, 'koKR', '<데시무스와 로스락시온을 억제하는 데 아라토르의 온 정신이 쏠려 있습니다. 이를 악물며 힘을 쥐어짜 내는 듯합니다.>', '', 66384),
(290443, 'koKR', '', '이곳의 공허는 삼켜질 정도로 짙습니다. 저는 이 힘을 받아들이고 기꺼이 시험을 맞이할 거예요. 이 차가운 혼돈의 돌풍은 오히려 기쁨을 안겨 준다고나 할까요.\n\n우리 흑마법사는 다른 이들이 위험하다 말하는 경계를 넘어섰고, 또다시 그리할 겁니다.\n\n이 순간, 저는 제 의지로 서 있습니다.', 66384),
(290440, 'koKR', '안개 수호물이 사라졌습니다! 줄잔을 찾읍시다.', '', 66384),
(290439, 'koKR', '<꽃병 안에는 피정맥 덩어리가 재에 스며들고 있습니다.>', '', 66384),
(290437, 'koKR', '<꽃병 밑바닥에 재가 쌓여 있습니다.>', '', 66384),
(290436, 'koKR', '<꽃병 안에는 해골갑각 송곳니가 재 표면 위에 놓여 있습니다.>', '', 66384),
(290434, 'koKR', '<꽃병 밑바닥에 재가 쌓여 있습니다.>', '', 66384),
(290425, 'koKR', '', '이 반쯤 썩어 문드러진 곳에서 이렇게 많은 보급품이 오가는 광경을 보긴 처음이야.\n\n총독은 나보고 이걸 다 어떻게 관리하라는 거지?', 66384),
(290424, 'koKR', '보통 있는 일은 아니지만, 외부의 도움을 받는 게 금지된 건 아니야. 가자, $c|1이여;여;.', '', 66384),
(290423, 'koKR', '', '무기는 눈앞에 잘 보이게 두고 있어라.', 66384),
(290422, 'koKR', '너무 약하구나. 너무 하찮군...', '', 66384),
(290418, 'koKR', '가서 만나지.', '', 66384),
(290417, 'koKR', '군주 안테노리안은 동족의 안전을 무엇보다 소중히 여깁니다. 반드시 알려야 합니다.', '', 66384),
(290414, 'koKR', '스승님이 북쪽 절벽 끝, 균열이 내려다보는 곳에서 만나자고 하셨어.', '', 66384),
(290413, 'koKR', '다른 이들과 상의한 후에 고려해 보겠소.', '', 66384),
(290412, 'koKR', '', '<당신이 다가오자 마법사가 킁킁거리더니, 눈을 가늘게 뜨고 노려봅니다. 잠시 머뭇거리던 끝에 마지못해 유창한 에레다르어로 말합니다.>\n\n너에게 지옥의 악취가 난다. 굳이 서로 으르렁댈 일은 만들지 않겠지만, 날 만아리로 착각하지 마라. 우리는 드레나이, 추방자이자 생존자다.\n\n나는 툴아마르다. 내 동족, 황천사자를 지키고 고향으로 데려가는 것이 내 의무다.', 66384),
(290411, 'koKR', '', '잃은 것이 너무 많네. 처음엔 위대한 나무, 그리고 이번엔 쿠자트와 상인들이 감염시킨 이들까지...\n\n그래도 오르웨냐가 돌아온 건 다행이야. 곧 여신이 또다시 부를 테지만.', 66384),
(290410, 'koKR', '', '빛만개에 오염된 이들을 치유할 방법을 찾아야 하네. 너무 많은 희생을 치렀어.', 66384),
(290405, 'koKR', '', '나는 만개하는 정원에서 움텄지만, 알른의 균열에서 씨앗을 모으고 있다.\n\n하르알노어는 우리 정원이나 균열 근처에 있지 않다.', 66384),
(290374, 'koKR', '', '<당신은 툴아마르 주변 공기에서 익숙한 비전의 진동을 느낍니다. 상대 역시 당신처럼 비전 언어학을 통해 동료의 언어를 이해할 수 있는 듯합니다. 툴아마르가 당신의 능력을 알아보고 미소 짓습니다.>\n\n마법사 동지로군. 잘됐다. 이러면 일이 더 쉬워지지.\n\n나는 툴아마르다. 내 동족, 황천사자를 지키고 고향으로 데려가는 것이 내 의무다.', 66384),
(290373, 'koKR', '우리 언데드와 빛의 관계는 복잡하기 그지없지. 특히 나는 그 누구보다도 더 그렇네.\n\n빛은 내 몸을 불사르지만, 나는 그 고통을 견디는 법을 터득했고 계속해서 사제로서의 길을 걷고 있네. 긴 세월 대주교로 살아왔기에 나는 다른 이들보다 빛에 더 강하게 공명한다네.\n\n태양샘도 예외는 아니지. 이곳에 있으면 항상 살을 태우는 듯한 격통이 따라붙지만, 그래도 버틸 수 있는 수준일세.\n\n다만 안으로 들어간다면... 불길에 달려드는 나방처럼 완전히 타버리고 말 걸세.', '', 66384),
(290370, 'koKR', '태양샘에 이렇게 가까이 오긴 정말 오래간만이군...', '', 66384),
(290369, 'koKR', '크로나, 이방인이여. 미안하지만 쉴 시간이 없다. 쓰러진 내 동족을 지키려면 서둘러야 한다.', '', 66384),
(290368, 'koKR', '그거 하나만 이유는 아닙니다, 물론 그것만으로도 충분한 이유이긴 하지만.\n\n저는 늘 영웅이 되고자 애써 왔습니다. 실제로 구원자 아라토르라는 명칭으로 불리기도 했죠.\n\n검을 들고 돌격하고, 빛의 힘으로 싸우고...\n\n한데 그 빛이라는 게 제가 생각한 만큼 명료하거나 단순한 게 아님을 느끼고 있습니다.\n\n이렇게 고민하는 와중에도 공허는 스멀스멀 다가오고 있고요.\n\n그래서 중심을 찾을 때까지는 파올 님의 인도를 따라야 할 것 같습니다.\n\n적어도 땅을 다시 밟게 될 때까지는 말이죠.', '', 66384),
(290366, 'koKR', '$p 님.\n\n죄송하지만 실례하겠습니다. 지금 얘기할 기분이 아닌지라.', '', 66384),
(290365, 'koKR', '$p, 도우러 와줘서 고맙네. 빛의 선봉대가 의식을 유지하며 잘아타스를 막고는 있네만, 이들은 나만큼 오래 버티진 못하네.\n\n자네가 도와준다면 필요한 만큼 버틸 수 있을 걸세.', '', 66384),
(290364, 'koKR', '', '$p 님! 용사님이 절 붉은십자군에서 구해주시고, 빛을 따를 두 번째 기회를 주신 날을 매일 떠올려요.\n\n지금 이렇게 그 길을 계속 걷는 것도 용사님 덕분이죠. 다시 한 번 감사해요.', 66384),
(290363, 'koKR', '', '$p 님, 저는 잘 이해되지 않아요. 무엇이 잘아타스를 이런 길로 이끈 걸까요. 잘아타스의 과거는 공허만큼이나 어두웠겠죠.\n\n그런데 그보다 더 신경 쓰이는 건 잘아타스로 인해 고통받는 사람들입니다. 그자의 계략에 목숨을 잃은 모두 말이에요. 그렇기에 아무리 지쳐 있더라도 태양샘을 통해 잘아타스를 막아야 합니다.', 66384),
(290362, 'koKR', '', '$p 님, 솔직하게 말씀 드리자면... 아버지를 따라 죽음의 영역까지 갔을 때 이 인생에서 더 볼 건 남아 있지도 않다고 생각했어요.\n\n그런데 지금은 그 이상으로 낯설고 헤아릴 수 없는 적과 싸우고 있네요. 무섭지만, 기꺼이 한 사람 몫을 다하겠습니다.', 66384),
(290361, 'koKR', '카시에아의 기록을 살펴봐야 합니다. 헛된 죽음으로 만들 순 없으니까요.', '', 66384),
(290360, 'koKR', '', '아웃랜드에서 이곳에 온 이후로, 태양샘은 제게 빛의 봉화이자 블러드 엘프로서의 의미를 되새기게 해주는 매개체였어요.\n\n이 일에 조금이라도 힘을 보탤 수 있다니 영광이에요, $p 님.', 66384),
(290359, 'koKR', '이 기록은... 카시에아? 안 돼!', '', 66384),
(290358, 'koKR', '애도를 표하오, 마법학자여. 시신은 사람을 시켜 수습하도록 하겠소.', '', 66384),
(290357, 'koKR', '나는 많은 것을 봤소, $p. 초창기 성기사단부터 아서스가 빛을 벗어나 타락하던 날까지...\n\n군단이 패하고 티르 님이 돌아오셨을 때는 밝은 앞날이 펼쳐질 줄 알았다오. 한데 공허가 이 세계를 암흑의 벼랑 끝으로 몰아넣고 있구려.\n\n계속 나아갈 힘을 찾을 수 있도록 도와줘서 고맙소.', '', 66384),
(290355, 'koKR', '', '$p 님. 그 지팡이는 알론서스 님의 것이죠? 제가 붉은십자군에서 나왔을 때, 그분이 절 비밀결사에 받아주셨어요.\n\n알론서스 님이 당신을 믿는다면, 저도 믿을 수 있을 것 같아요.', 66384),
(290354, 'koKR', '', '아라시 제국에는 태양샘 같은 게 없었던 것 같아요, $p 님.\n\n이건 반드시 지켜야 해요. 도와주셔서 감사합니다.', 66384),
(290353, 'koKR', '', '우리 아마니는 공허의 침공에 익숙하다. 과거 우리가 버텨낸 건 로아에 대한 신념 덕분이지.\n\n오늘은 내 로아와 티르의 가르침을 향한 믿음이 내 손을 이끌 것이다. 그 힘만으로 충분하길 기도할 뿐.', 66384),
(290352, 'koKR', '안쉬께서도 공허에 맞서기를 바라실 것이오. 본인이라면 그리 할 테니까.\n\n그리고 그대의 도움이 있었기에, 나도 이렇게 그 뜻을 따를 수 있소.', '', 66384),
(290351, 'koKR', '', '오랜 세월 동안, 저는 공허가 수많은 병사들의 목숨을 앗아가는 모습을 지켜봐 왔습니다...\n\n모든 걸 집어삼키고, 끝이 없다는 점에서 군단과도 닮았지요. 어쩌면 그보다 더할지도 모릅니다.\n\n$p 님, 저는 이 싸움이 몇천 년씩 이어지지 않기를 간절히 기도하고 있습니다.', 66384),
(290333, 'koKR', '실버문으로 돌아가야 합니다. 이 사실을 알릴 필요가 있습니다.', '', 66384),
(290329, 'koKR', '', '루타니가... 성장에 집착하고 있어. 자네가 말한 그 빛이 원인일지도 모르겠군.', 66384),
(290321, 'koKR', '도와줘서 고맙다, $p. 독을 채취하는 건 내가 하지... 기절만 하지 않으면 말이야.', '', 66384),
(290303, 'koKR', '추아, 다시 밖에 나갈 생각은 꿈도 꾸지 마.', '추아, 다시 밖에 나갈 생각은 꿈도 꾸지 마.', 66384),
(290299, 'koKR', '', '공허첨탑은 무너질 거다, 에테리얼 놈들!', 66384),
(290298, 'koKR', '우리는 빛을 향해 다른 길을 걸어왔으나, 같은 뜻으로 이 자리에 모였네. 아제로스를 지키기 위해서!', '', 66384),
(290297, 'koKR', '긴 여정 때문에 몸이 좀 시들었어.\n\n그래도 생명체의 꽃잎을 감상하니 다시 생기가 도는 것 같다.', '', 66384),
(290296, 'koKR', '', '공허에 노예가 되는 자도 있지만, 전 힘으로 삼습니다!', 66384),
(290295, 'koKR', '태양샘이 무너지면, 포식의 군단을 막을 도리가 없네!', '', 66384),
(290294, 'koKR', '지친 건 알고 있네. 견디기 어렵겠지만, 그래도 해야 하네!', '', 66384),
(290291, 'koKR', '$p 님, 제발 형제를 찾아 주세요. 집으로 돌아오라고 전해 주세요.', '$p 님, 제발 형제를 찾아 주세요. 집으로 돌아오라고 전해 주세요.', 66384),
(290288, 'koKR', '어둠과 습기, 부패가 널 덮친다!', '', 66384),
(290287, 'koKR', '우호적인 루타니라니, 신기하군.', '', 66384),
(290286, 'koKR', '좋은 연회네요. 살데릴은 여전히 이런 자리를 곧잘 여는군요.\n\n게다가 평소에 죽음의 골목에 절대 안 올 귀족들을 손님으로 만들 기회이기도 하고요.', '', 66384),
(290285, 'koKR', '', '좀 답답하네요. 그래도 무도회장보단 낫지만요.', 66384),
(290283, 'koKR', '이런 부질없는 시간 낭비는 진심으로 혐오스럽지만, 우리가 이 전쟁에서 승리하려면 혈기사단이 반드시 자금을 확보해야 하오.', '', 66384),
(290281, 'koKR', '나는 미카라고 한다. 이곳 하르마라에 있는 루타니를 관리하고 있지.', '', 66384),
(290280, 'koKR', '이방인의 뿌리가 깊이 뻗기를.', '', 66384),
(290271, 'koKR', '', '살데릴 경께 높은 평가를 받으신다고 들었습니다. 여기서는 그분의 호의가 중요하게 통하지요.\n\n그분의 은총을 마법학자들에게도 조금 나눠 주실 수 있다면, 서로에게 이로운 합의를 이끌어낼 수 있을 것이라 믿습니다.', 66384),
(290185, 'koKR', '시스템... 오류.', '', 66384),
(290183, 'koKR', '지령... 대부께서는 모든 출입을 금하셨습니다.', '', 66384),
(290178, 'koKR', '', '내가 이 시련을 겪은 건 아주 오래전, 아직 젊었을 때였지. 우리 하라니르는 누구나 일정한 나이와 능력에 이르면 반드시 거치는 관문이라네.\n\n성인으로서의 시작을 의미하고, 부족 내에서 자신의 길을 정립하는 전환점이기도 하지.', 66384),
(290177, 'koKR', '', '다치지 않고 시련을 마쳤다니 기쁘네, $n. 물론 그럴 줄 알고 있었어.\n\n자넨 유능하고 신뢰할 수 있는 사람이니까. 그래서 우리 역사를 자네에게 보여줄 가치가 있다고 판단했네.', 66384),
(290175, 'koKR', '어려움은 있었지만, 이겨내지 못할 정도는 아니었소. 그대 또한 무사히 도착해서 다행이구려.\n\n나는 하라니르가 마음에 들었소. 자연과 밀접하게 닿아 있으며, 우리 순찰대처럼 수호하지.\n\n흥미로운 종족이고, 그림을 통해 역사를 전하는 방식은 실로 독특하오. 내가 본 적 없는 전통이라오.\n\n하가르 말로는 하라니르 주위에 저들의 이야기를 전하는 그림이 더 있다더군. 나도 찾아보며 이 종족의 과거를 더 느껴보고 싶소.', '', 66384),
(290174, 'koKR', '하라니르의 역사는 실로 흥미롭소. 아제로스의 노래, 알른하라의 목소리를 가장 먼저 들은 존재였을지도 모르겠소.', '', 66384),
(290102, 'koKR', '저 무기... 빛나무... 영원노래를 정복하려는 게 아니었군요. 황혼의 칼날단으로부터 자신들을 지키기 위해서였지.', '', 66384),
(290101, 'koKR', '누군가에게 영감을 주라니. 파올 님은 예전부터 기발한 분이셨죠.', '', 66384),
(290092, 'koKR', '파올 님이 보내셨다고요? 훌륭한 분이시지요.\n\n파올 님이 제가 있는 성기사단을 창설한 분이신 건 알고 계셨나요? 제... 은빛 성기사단은 그분의 유산입니다.\n\n알겠습니다, $p 님. 전 명령받는 곳으로 갑니다. 그게 제가 선택한 삶이니까요.', '', 66384),
(290090, 'koKR', '아. 안녕하십니까, $p 님.\n\n그냥... 분수를 감상하고 있었습니다. 바람 좀 쐬고 싶어서요.\n\n혹시 누가 절 찾던가요? 그래서 오신 겁니까?', '', 66384),
(290085, 'koKR', '', '그... 생각해 보겠다. 하지만 이해해라. 이 사람들은, 내 동족은 이미 집을 가지고 있다. 가족이 있고, 사랑하는 이들이 있으며, 그 모두를 빼앗기고 말았다.\n\n그런데 같은 일을 하라니? 지금 가진 모든 걸 버리고 우리와 함께하라니? 새로운 세계가, 이미 알고 사랑하는 세상보다 더 안전할 거라고 무작정 믿으라니?\n\n이 이야기는 나중에 더 나누자. 지금은 서서 이야기할 만큼 한가하지 않다. 위험이 코앞에 있으니.', 66384),
(290078, 'koKR', '', '블록치니우스를 보세요. 정말 규율이 잘 잡힌 친구예요. 속박도 없이 잘 따르잖아요. 다크글렌이 얼마나 운이 좋은지 깨달았으면 좋겠네요.\n\n<자신의 공허방랑자를 흘겨보며 입꼬리를 비트는 루시아>\n\n폭풍 때문에 버릇이 나빠졌어, 칼고르그. 넌 저 친구에 비하면 들개나 마찬가지야.', 66384),
(290075, 'koKR', '', '먼지로 돌아가라.', 66384),
(290072, 'koKR', '<주라스가 눈을 크게 뜨며 당신을 바라봅니다. 이해하지 못한 듯 보입니다.>\n\n어? 어어? 아니, 아니다! 친구여! 옛말 모른다! 무섭다!', '', 66384),
(290071, 'koKR', '구해줘서 고맙다. 내 목숨, 아니 최소한 포옹이라도 빚진 셈이지, 하하.\n\n툴아마르는 우리를 고향으로 돌려보낼 방법을 연구해 왔다. 툴아마르가 경계심을 드러낸 걸 용서해라. 아직 빛과 그 은총을 지닌 자들에게 쌓인... 앙금이 남아 있거든. 툴아마르와 달리 나는 아직 신앙을 지키고 있다.\n\n<나루 펜던트를 움켜쥐고 숨을 내쉬는 주라스>\n\n다만 나 또한 잊힌 듯한 기분이 드는 건 부정 못 하겠군.', '', 66384),
(290070, 'koKR', '<활짝 웃으며 엄지를 치켜세우는 주라스>\n\n고맙다. 정말 고맙다! 힘껏 안아준다!', '', 66384),
(290065, 'koKR', '', '잊을 수 있겠는가! 크로쿨, 살게레이 변절자, 상상조차 못 할 출신도 있지! 우리는 하나같이 살아남은 자들이다. 그들 또한 드레나이이며, 나는 내 동족을 자랑스럽게 여긴다!\n\n우리는 냉혹하고 무심한 끝없는 어둠 너머에서 수천 년을 홀로 버텼다. 동족에게도, 빛에게도 버려진 채! 에테리얼 납치범들에게서, 기생하는 돌연변이들에게서, 지금 이 순간에도 우릴 괴롭히는 공허의 괴물들에게서 서로를 지켜냈다.\n\n그 모든 걸 딛고 소중한 보금자리를 일궈냈지. 그곳으로 돌아가야 한다.', 66384),
(290063, 'koKR', '', '나는 에레다르다. 그러나 그 이전에, 드레나이다. 내 동족을 우주 저편까지 쫓아다닌 악마들을 경멸한다. 폭군, 만아리. 그러나 지금 우리를 위협하는 괴물들은 그자들이 아니다.\n\n내 동족에게 네 도움이 필요하다, $c|1이여;여;. 부탁한다.', 66384),
(290061, 'koKR', '', '<드레나이가 분리된 이후 겪은 역사를 주의 깊게 듣는 툴아마르>\n\n아르거스에서의 승전 소식은 들었다. 최근 들어 지옥에 물든 채 속죄를 구하는 동족들을 그 어느 때보다 많이 마주쳤다. 우리가 그 자리에 함께하지 못한 것이 안타깝군.\n\n아직 나눌 이야기가 많다. 시간이 있으면 좋았을 것을. 하지만 지금은 이곳이 위험하다. 내 동족은 고향으로 돌아가야 한다.', 66384),
(290059, 'koKR', '', '이런 장소에서 만나다니, 기적이 따로 없군.\n\n나는 툴아마르다. 내 동족 황천사자를 지키고 고향으로 보내는 것이 내 의무지.', 66384),
(290058, 'koKR', '', '수천 년 동안 제네다르에 남은 동족과 떨어져 지내다 보니 우리 사이에도 틈이 생겼다. 설명해 주마.\n\n우리 중 많은 이가 살게라스의 군단을 피해 예언자 벨렌을 따라 떠났다. 우리가 피난처를 찾아 떠돌던 수많은 세계를 알지도 모르겠군. 어쩌면 네가 직접 발을 디뎠을지도 모르지. 눈과 얼음의 세계, 안개와 숲의 세계, 끝없는 바다의 세계. 그러나 오래 머물 수 있는 곳은 없었다.\n\n군단은 언제나처럼 우리를 쫓아왔고, 나는 제때 차원선에 오르지 못한 이들과 함께 남겨졌다. 제네다르가 하늘로 떠올라 반짝이는 점이 될 때까지 바라보다, 결국 사라지는 걸 지켜봐야 했다.\n\n그 이후 우리는 끝없는 어둠 너머에서 살아남아야 했다. 쓸쓸하게 말이지.', 66384),
(290057, 'koKR', '', '<툴아마르가 마법을 시연합니다. 당신과 비전 능력을 교감하며 자연스럽게 대화가 이어집니다.>\n\n나는 에레다스의 빛나는 전당에서 수련했다. 이건 우리 종족에게도 드문 기법이지. 네가 어디서 왔든, 네 마법을 결코 가볍게 여겨선 안 된다는 걸 알겠다.', 66384),
(290055, 'koKR', '내가 데려온 자를 봐라. 오래전에 잃어버린 동족이다! 내 생명의 은인이지.', '', 66384),
(290051, 'koKR', '용사님, 기다리십시오! 매복입니다!', '', 66384),
(290050, 'koKR', '로아들은 언제나 위기의 순간에 우리에게 귀를 기울였단다. 지금도 올바른 목소리, 하셰이의 길을 걷는 자라면 들어줄 거야!', '', 66384),
(290047, 'koKR', '줄자라가 아이였고, 아이의 할아버지가 족장이던 시절만 해도 로아는 아마니 문화의 중심이었네. 아마니가 출발한 이래로 그래 왔지.\n\n모든 아마니 족장은 로아 앞에 나섰고, 그중 일부만이 로아의 축복을 받아 하셰이가 되었어. 하셰이는 단순한 족장이 아니라, 로아의 목소리요 공동체의 기둥이자 두려움 없는 전사였네.\n\n이게 줄자라가 걸어야 할 여로일세. 로아의 뜻이 따르기를! 이 길만이 우릴 구할 수 있네.\n\n자네... 혹시 줄자라를 도와주면 안 될까? 아마니는 아니지만, 강하잖아. 아킬존이 자네에게 여러 번 승리의 축복을 내린 게 느껴지네. 자네보다 더 나은 하쉬우라 후보는 없어.', '', 66384),
(290034, 'koKR', '그대의 병력은 이쪽에 필요하다, 쿨라마라.', '', 66384),
(290023, 'koKR', '', '에테리얼 만난다. 친구. 봤다... 만트라스... 에...\n\n<툴아마르가 둥근 구체를 그리듯 손짓하며 손끝에서 작은 비전 불꽃을 흩뿌립니다.>\n\n너 같은 자가 우리를 도와줬다. 그리고 떠났다.\n\n알았나?', 66384),
(290021, 'koKR', '<주라스가 당신을 가리키자, 툴아마르가 당신을 신중하게 바라봅니다. 다른 피난민들은 놀라움에 속삭입니다.>', '', 66384),
(290020, 'koKR', '내가 데려온 자를 봐라. 이 이방인은 영웅이다! 이 사람이 날 구했다.', '', 66384),
(290017, 'koKR', '<감사하다는 듯 허리를 숙이고 북서쪽 지평선을 가리키는 주라스>', '', 66384),
(290012, 'koKR', '나는 메아리의 소굴의 주르아샤르 카사메다. 네 시련을 인도할 자다.', '', 66384),
(290010, 'koKR', '', '자네가 여신의 인정을 받는다면, 외부의 존재 또한 그분의 부름을 받을 수 있다는 걸 증명하는 셈이네. 자네가 돕기 위해 왔다는 것도... 우리도 자네들의 도움이 필요하다는 것도 다들 이해하게 될 걸세.\n\n우리 종족은 더 이상 뿌리 아래에만 숨어 있을 수 없네. 나무가 병들면 뿌리도 무사할 수 없어. 이제는 지상을 외면할 수 없단 얘기지.', 66384),
(289995, 'koKR', '', '어서 가세요, $n 님! 시간이 없어요! 저도 금방... 따라갈... 윽...!\n\n<기력이 다한 듯 그대로 주저앉는 알레리아>', 66384),
(289994, 'koKR', '활시위를 마지막으로 끊었던 게 언제인지도 기억이 나지 않습니다. 이보다 덜한 일이어도 원정순찰대 신병들에게 전력 질주를 시키곤 했죠.\n\n<왼팔을 어루만지며 인상을 찡그리는 사이데라스>\n\n공허 때문입니다. 공기 중의 마력이 우리 모두를 조이고 있어요. 너무 팽팽합니다.', '', 66384),
(289993, 'koKR', '이 동굴 그림들은 실로 거대하군. 정말 하라니르 종족의 기억이 담겨 있는 거요?', '', 66384),
(289991, 'koKR', '', '나는 텔드랏실의 뿌리감시관이었네. 위대한 세계수가 파괴되며 내 임무도 함께 끝났지.\n\n우린 하라니르로서 오랜 세월 세상과 단절된 채 살아왔지만, 더는 그렇게 지낼 수 없네.\n\n뿌리는 나무의 일부일 뿐이야. 진정한 감시관이라면 뿌리뿐만 아니라 나무 전체를 지키고 돌볼 줄 알아야 하지.\n\n텔드랏실이 파괴되는 걸 막을 방법이 없었는지 난 지금도 스스로에게 묻곤 하네. 자네의 이야기를 들을 마음이 생긴 것도 세계수를 파괴한 불길에서 피어났다고 할 수 있지.', 66384),
(289990, 'koKR', '전 어릴 적부터 부모님에 대한 이야기를 들으며 자랐습니다. 그만큼 기대도 컸지요.\n\n이제 어머니의 곁에서 직접 행동하는 모습을 보고, 배운 걸 실전에 응용하고 있으니... 이곳이 아무리 위험하더라도, 함께 있다는 사실이 참 뿌듯하게 느껴집니다.', '', 66384),
(289989, 'koKR', '', '나는 하가르라네. 장로이자 전직 뿌리감시관이지. 자네가 이번 시련에서 어떤 성과를 내는지 지켜보고, 성공 여부를 보고하러 왔네.', 66384),
(289988, 'koKR', '', '정녕 여신의 노래를 들었다면, 시련을 무난히 극볼할 수 있을 게야. 어쩌면 오르웨냐처럼 여신께서 자네를 부르신 걸지도 모르지.', 66384),
(289987, 'koKR', '', '메아리의 소굴은 우리 종족의 기억과 역사가 깃든 곳이라네. 시련을 견뎌낸다면, 많은 것을 얻게 될 걸세.', 66384),
(289984, 'koKR', '오르웨냐가 먼저 장로들과 이야기를 나누고 있소. 준비되는 대로 알려 주시오, $n.', '', 66384),
(289980, 'koKR', '의회가 소집되었소. 오르웨냐가 저지른 죄를 심판하려 하고 있지. 준비되면 함께 가도록 합시다.', '', 66384),
(289946, 'koKR', '끔찍하군요. 산들바람 마을도 이 정도는 아니었습니다.', '', 66384),
(289944, 'koKR', '', '태양샘의 광휘를 잠재우겠다!', 66384),
(289940, 'koKR', '빛이 잠시 쉴 틈을 내려주셨군! 그래도 몰아붙여야 하네!', '', 66384),
(289936, 'koKR', '', '빛 근처에 머무르십시오. 그러지 않으면 공허가 당신을 집어삼킬 겁니다.', 66384),
(289935, 'koKR', '', '보호 수단 없이 공허의 심연을 헤매는 건 매우 위험합니다.', 66384),
(289934, 'koKR', '', '빛이 당신을 다시 우리 곁으로 데려왔습니다. 너무 공허 깊숙이 들어가지 않도록 조심하세요.', 66384),
(289933, 'koKR', '', '너희의 소중한 유물은 이제 잘아타스 님의 것이다!', 66384),
(289932, 'koKR', '정 가야겠다면 술카의 힘을 빌려야 할 거다. 술카를 향한 감정이 어떻든 이 사실은 변하지 않아.', '', 66384),
(289922, 'koKR', '실버문에 알려야 합니다.', '', 66384),
(289919, 'koKR', '루이아는 샬라드라실의 뿌리감시관이다.\n\n내가 아미드랏실의 뿌리감시관이 된 이후로, 나의 스승이 되어 가르침을 주고 있지.', '', 66384),
(289916, 'koKR', '뿌리감시관은 세계수의 뿌리를 돌보고 가꾸는 일을 맡은 자다. 나는 아미드랏실의 뿌리감시관이고, 그렇다 보니 아직 이 책무에는 익숙하지 않아.\n\n우리는 뿌리를 보살피고 건강을 지키며, 위대한 뿌리에 해악을 끼치려는 존재와 해충들을 막아낸다.', '', 66384),
(289912, 'koKR', '아이들을 찾아줘서 고맙다. 하지만 그것만으로 우리 땅을 마음대로 드나들 수 있는 권한이 주어지는 건 아니다.\n\n우리 하라니르의 방식은 저 너머의 세계와 접촉하지 않는 것이다. 오르웨냐는 외부인에게 하라니르의 존재는 물론, 하란다르까지 노출했지.\n\n오르웨냐는 죄에 대한 대가를 치러야 한다. 너 또한 마찬가지고.', '', 66384),
(289911, 'koKR', '', '나도 오르웨냐 님을 돕고 싶지만, 가야 할 곳을 가고 싶어 하진 않으실 거야.', 66384),
(289910, 'koKR', '이렇게 구속된 게 대체 얼마 만인지 모르겠군. 게다가 이토록 독특한 방식이라니! 이 물질은 뭐라 불러야 할까? 빛접목?\n\n<데시무스가 웃으려 입을 벌리다 멈추더니, 당신을 뿔에서 발끝까지 유심히 바라봅니다.>\n\n곰곰이 생각해 보니 너희 빛벼림과도 일맥상통하는 면이 있군. 네 등을 한번 자세히 살펴보고 싶은걸. 이번에는 나한테 심문 기회를 주는 게 어때?', '', 66384),
(289901, 'koKR', '', '하란다르는 저 아래 뿌리 너머에 있네. 위로 소용돌이치는 뿌리는 여신 알른하라와 관련된 가장 신성한 장소, 요람일세.\n\n그 아래에 있는 곳이 바로 물감을 만드는 이들의 마을 하라시르지. 여기서 잠시 멈추세. 오랜만에 고향의 풍경을 눈과 가슴으로 담고 싶구먼.', 66384),
(289900, 'koKR', '저들이 왜 그토록 지키려 드는지 알겠소... 손때 묻지 않은 아름다움의 극치로군.', '', 66384),
(289896, 'koKR', '고맙다, $n. 네가 없었다면 살아남지 못했을 거야.', '', 66384),
(289895, 'koKR', '저 괴물... 악몽 그 자체야. 아마라크 님 말씀으로는 아주 오래된 존재고, 그동안 목숨을 빼앗은 모든 술카의 정수를 품고 있대.\n\n우리가 이길 수 있을까?', '', 66384),
(289887, 'koKR', '어떻게 되든, 친절을 베풀어 줘서 고맙다, $n. 최악의 일이 닥친다면 추아에게 알려 줘.', '', 66384),
(289886, 'koKR', '지금이 결정적인 순간이다. 엔리안이 의식을 버텨내 살아남든지, 아니면 영원히 사라지든지.', '', 66384),
(289884, 'koKR', '윈드러너가 어둠의 나루를 품고 있었다니, 그건 또 몰랐네. 단순한 유흥으로 끝날 일이 아닌데...', '', 66384),
(289880, 'koKR', '', '이제 선장에게 영원한 휴가를 선사하죠...', 66384),
(289876, 'koKR', '지금은 엔리안에게 아주 위험한 시기다. 의식에 실패해 알른하라와의 연결을 끊지 못하면, 균열의 광기에 삼켜지고 말 테지.\n\n네가 함께한다니 다행이구나. 술카의 방식은 아니긴 하지만. 우린 길은 보여주되, 직접 간섭하지는 않아.', '', 66384),
(289873, 'koKR', '보이나? 놈들이 빛나무를 불태우는 건 그 힘을 두려워하기 때문이다.', '', 66384),
(289871, 'koKR', '너, 그리고 너. 남은 쇠뇌 화살을 제단으로 가져가라.', '', 66384),
(289865, 'koKR', '', '제 고양이를 구해 주세요, 성기사님!', 66384),
(289858, 'koKR', '여신과의 연결을 끊는 의식을 반드시 끝내야 해. 그렇지 않으면 뒤틀린 노래 때문에 내가 정신을 잃고 죽거나, 아니면 더 끔찍한 일을 겪게 될 거야.', '', 66384),
(289848, 'koKR', '', '마법석이... 성장물은 막았지만, 저것들은... 도저히 막을 수 없었습니다!', 66384),
(289846, 'koKR', '', '하라니르가 외부 세계와 접촉하는 건 우리 방식에 어긋나는 일이네. 따뜻한 환영은 기대하지 않아. 하지만 빛만개의 위협은 지상에서 비롯된 것이 아닐세.\n\n이젠 우리 종족도 이 싸움에 나설 때일세. 사람들을 설득하는 길은 험난하겠지. 기회를 주기 전에 살려두기나 할지 의문이긴 하네만.', 66384),
(289845, 'koKR', '', '고향에 돌아와 하란다르의 뿌리를 만지니 마음이 참 편안하네. 너무 오래 떠나 있었어.', 66384),
(289843, 'koKR', '대마법학자 롬매스의 요청에 따라 그대와 오르웨냐가 있는 하란다르에 왔소. 나는 원정순찰대 출신으로 빛만개를 추적할 수 있다오.\n\n오르웨냐는 이 오염이 자신의 고향에서 시작되었을지도 모른다고 의심하고 있소. 그대와 함께 근원을 찾아보려고 하오.', '', 66384),
(289841, 'koKR', '나는 실버문의 순찰대 사령관, 할두런 브라이트윙이오. 아제로스는 물론, 그 너머까지 아우르는 최고의 순찰자 집단인 원정순찰대의 지도자라오.', '', 66384),
(289840, 'koKR', '하라니르의 고향을 직접 볼 기회는 누구에게도 허락된 적이 없었소. 저들은 세상과의 연결을 철저히 끊고 있었고, 세계수의 뿌리를 통해서조차 하란다르의 소문 하나 들리지 않았소.', '', 66384),
(289836, 'koKR', '<인상을 구기는 아라토르>\n\n지금은 안 됩니다, $n 님. 이제 막 어머니를 다시 만났는데요.\n\n말할 겁니다. 반드시요. 다만, 조금 더 마음이 가라앉고, 안전한 곳에서 말하고 싶습니다.\n\n어머니가 아버지에게 분노하는 모습을 보고 싶진 않아요.\n\n그러니 제발... $n 님, 그 일은 당신만 알고 계세요. 어머니께는 때가 됐을 때 제가 직접 말씀드리겠습니다.\n\n지금은... 전쟁이 먼저입니다.', '', 66384),
(289834, 'koKR', '살아 계셨어요! 이곳에 계셨었군요!\n\n마음 깊은 곳에서는 줄곧 믿고 있었습니다. 어딘가에서 멀쩡히 살아, 사냥하고 있다고... 언제나 그랬던 것처럼.\n\n<슬픔이 섞인 미소를 짓는 아라토르>\n\n이번엔 함께할 겁니다. 이번에는, 함께 싸울 겁니다.', '', 66384),
(289832, 'koKR', '<얼굴을 찡그리는 아라토르>\n\n정신을 짓누르는 압박감이 느껴집니다. 가슴 깊이 스며드는, 겪어보지 못한 두려움도요...', '', 66384),
(289815, 'koKR', '앞에 적이 있습니다! 긴장하십시오!', '', 66384),
(289804, 'koKR', '<이 수호병의 시체는 부리와 발톱에 훼손된 흔적이 가득합니다. 상처를 자세히 살펴보자 식물에서 자라난 듯한 촉수가 솟아납니다.>', '<이 수호병의 시체는 부리와 발톱에 훼손된 흔적이 가득합니다. 상처를 자세히 살펴보자 식물에서 자라난 듯한 촉수가 솟아납니다.>', 66384),
(289780, 'koKR', '일이 산더미라서 네 도움이 필요해.\n\n알른의 균열에 너무 오래 머물렀더니, 이제 여신의 뒤틀린 노래가 사방에 울려 퍼지고 있어.\n\n<기침하는 젊은 하라니르>\n\n그게 날 천천히 죽음으로 내몰면서, 미치게 해. 뭐가 먼저 올지는 모르겠네.', '', 66384),
(289779, 'koKR', '괴물이 나타났습니다! 빛만개에서 나타났어요!', '괴물이 나타났습니다! 빛만개에서 나타났어요!', 66384),
(289778, 'koKR', '', '약한 자들이 저지른 죄악이 그림자처럼 드리워져 있군요...', 66384),
(289775, 'koKR', '한 걸음도 허락하지 않겠다!', '한 걸음도 허락하지 않겠다!', 66384),
(289765, 'koKR', '알른하라의 뿌리시여! 넌 누구지?', '', 66384),
(289759, 'koKR', '도대체 어디서 온 거냐? 내 평생 이런 건 처음 본다!', '', 66384),
(289757, 'koKR', '', '흔적을 따라가게. 우리가 찾는 답으로 이어질 걸세.', 66384),
(289743, 'koKR', '', '이방인이 여기 어떻게 오신 거죠? 외부인은 하란다르에 들어오면 안 돼요!', 66384),
(289735, 'koKR', '', '누구... 당신 뭐예요? 가까이 오지 말아요. 경고했어!', 66384),
(289729, 'koKR', '여긴... 마치 시간을 거슬러 과거로 온 것 같군.', '', 66384),
(289725, 'koKR', '형제를 찾아야 해요. 아직 살아 있을 거라고 믿어요!', '형제를 찾아야 해요. 아직 살아 있을 거라고 믿어요!', 66384),
(289718, 'koKR', '', '이봐요! 여기예요!', 66384),
(289710, 'koKR', '지금 당장 떠나지 않으면 선조들 앞에 맹세코, 강제로 어깨에 짊어지고 나갈 겁니다.', '', 66384),
(289708, 'koKR', '하하! 네가 어릴 때 내가 늘 해주던 말이었지!', '', 66384),
(289705, 'koKR', '', '대총독님의 부인인가요? 아니, 애인이라고 해야 하나. 키가 더 클 줄 알았는데. 그분이 심장에 어둠의 나루를 품고 있다는 게 사실입니까?', 66384),
(289704, 'koKR', '', '당신은 선봉대가 아니군요. 그래도 구해주신 데 불만은 없어요. 근데 방금 같이 있던 여성분은 누군가요?', 66384),
(289703, 'koKR', '', '이런, 또 다른 차원문이라니!', 66384),
(289700, 'koKR', '', '제 공허방랑자가 공허폭풍에 대해 속삭여 주더군요. 광기와 폭력으로 소용돌이치는 그곳...\n\n 역시 이 힘에 맞설 수 있음을 증명하고 싶습니다.', 66384),
(289698, 'koKR', '아라토르, 무시하고 알레리아를 살피십시오. 지금 이 임무의 책임자는 접니다.', '', 66384),
(289694, 'koKR', '', '공격이 한풀 꺾였군. 잘했네!', 66384),
(289693, 'koKR', '빛에서... 벗어날 순 없다.', '', 66384),
(289691, 'koKR', '빛이 너희를 거두리라!', '', 66384),
(289689, 'koKR', '', '빛은 번성한다...', 66384),
(289686, 'koKR', '', '빛이 만물을 삼키리라!', 66384),
(289683, 'koKR', '나는... 땅의 양분이 된다.', '', 66384),
(289680, 'koKR', '빛이... 너무 과해!', '', 66384),
(289666, 'koKR', '', '상인들이 거짓말을 했거나, 자신들이 빛만개에 감염된 줄도 몰랐던 게 분명하네. 이젠 마을로 가 빛만개를 퍼뜨리고 있지.\n\n더 번지기 전에 이 확산을 막아야 하네!', 66384),
(289655, 'koKR', '이동하겠습니다! 빛의 축복이 있기를!', '', 66384),
(289653, 'koKR', '', '시련을 무사히 마쳤다니 다행이네, $n. 우리 종족은 매우 폐쇄적인 편이지. 자네에게 우리 역사를 나눌 수 있어 다행일세, 친구여.', 66384),
(289594, 'koKR', '', '날이 참 좋지 않나요?', 66384),
(289593, 'koKR', '가장 가까운 빛만개도 마을과 한참 떨어져 있었는데, 어쩌다 이렇게 퍼진 걸까요?', '', 66384),
(289592, 'koKR', '아직 안 봤으면 아라토르에게 가보십시오. 저쪽 진지에서 부상자들을 돌보고 있습니다.', '', 66384),
(289591, 'koKR', '태양샘의 힘이 강해진 것과 관련이 있을지도 모르죠. 아마 제 생각이 맞을 겁니다. 선봉대를 돕는 데 활용할 수 있을지도요.', '', 66384),
(289590, 'koKR', '빛만개는 수년 전, 태양샘이 회복될 때 처음 모습을 드러냈습니다. 하지만 이렇게 문명 가까이 자라난 적은 없었습니다.', '', 66384),
(289581, 'koKR', '무슨 일이 있었던 겁니까?', '', 66384),
(289580, 'koKR', '', '매타조들이... 날뛰고 있어요...', 66384),
(289579, 'koKR', '공허폭풍 내부에서는 평범한 탐지가 통하지 않더군요. 그래서 적을 감지할 수 있게 특별히 조율한 단상을 만들었습니다.', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(289576, 'koKR', '사방에서 공격이 들어오고 있습니다! 전황을 분석해야 합니다. 엄브릭! 용사님이 도울 거요.', '', 66384),
(289567, 'koKR', '자, 됐다. 이제 놓치지 말렴!', '', 66384),
(289566, 'koKR', '나루가 쓰러지다니! 이 모든 힘이... 잘아타스에게 가고... 나는 아무것도 얻지 못했다고?!', '', 66384),
(289565, 'koKR', '', '감염된 루타니가 빛만개를 퍼뜨리고 있네! 에온카는 어디 있나?', 66384),
(289556, 'koKR', '', '임무를 완수하고 공허 첨탑으로 돌아가세요, 살하다르. 약속한 힘을 드리죠.', 66384),
(289552, 'koKR', '이 정도는 아무것도 아니죠.', '', 66384),
(289551, 'koKR', '놈들이 오래 말썽을 피우진 못할 겁니다.', '', 66384),
(289550, 'koKR', '', '감사합니다! 매타조들이 너무 무서웠어요!', 66384),
(289549, 'koKR', '', '용사님, 선봉대 지휘관들과 상의해 주시겠습니까? 전 장군에게 태양샘을 반드시 지켜야 하는 이유를 설명해야 합니다.', 66384),
(289547, 'koKR', '', '함께해 주실 거죠, $n 님? 용사님이 힘을 보태주신다면 언제든 환영입니다.', 66384),
(289414, 'koKR', '우리 가엾은 고양이를 구해 주셔서 감사합니다!', '', 66384),
(289409, 'koKR', '빛이 상처를 달래 주기를, 작은 친구여.', '', 66384),
(289404, 'koKR', '어르신, 로아는 수십 년 전부터 우리를 외면했습니다. 오히려 없는 편이 나아요.', '', 66384),
(289403, 'koKR', '', '다들 공포에 정신이 나갔어!', 66384),
(289402, 'koKR', '<얼굴을 찌푸리는 로스락시온>\n\n모든 오크가 피에 굶주린 광전사입니까? 모든 판다렌이 술에 취한 수도사이고, 모든 엘프가 거만한 귀족입니까?\n\n자기 자신을 결정짓는 것은 태생이 아니라 선택입니다. 필멸자들이 그러하듯, 나스레짐도 다르지 않습니다.\n\n저는 과거를 버렸습니다. 거짓말도, 변신도, 배신도 하지 않습니다. 그건 빛의 방식이 아닙니다.\n\n빛은 제 과거를 씻어냈고, 빛의 선봉대의 병사로 다시 태어났습니다.', '', 66384),
(289399, 'koKR', '', '그 벌레는... 아무튼, 감사합니다.', 66384),
(289398, 'koKR', '', '황혼이... 부른다...', 66384),
(289397, 'koKR', '당장 보호막을 무너뜨려야 합니다!', '', 66384),
(289393, 'koKR', '렌도레이가 추방당했던 무렵에 알레리아 윈드러너 님이 실버문으로 돌아오셨습니다. 그분은 여러 세계를 떠돌며 수많은 악마와 싸워왔고, 태양샘의 따스함을 다시 느끼고자 했지요.\n\n그러나 여정 중 그분은 어둠에 물든 나루, 르우라의 정수를 흡수하게 되었고, 그 영향으로 지금의 렌도레이처럼 변화하였습니다. 공허의 존재가 된 것입니다.\n\n빛과 공허는 떼려야 뗄 수 없는 관계입니다.\n\n알레리아 님이 태양샘에 다가갔을 때, 태양샘의 빛이 그분의 공허와 격렬히 충돌했고, 어둠의 존재들이 쏟아져 나왔습니다. 당시 위대한 영웅들이 자리에 없었다면, 태양샘은 공허에 잠식되었을지도 모릅니다.\n\n그렇기에 우리를 영원히 추방하고자 하는 이들이 많습니다. 그래서 어느 때보다 신중하게 처신해야 하고요.', '', 66384),
(289391, 'koKR', '자, 이 전언을 잘아타스에게 전해라!', '', 66384),
(289388, 'koKR', '', '나는 아직 빛만개를 보지 못했다. 그래도 늘 그렇듯, 균열이 우리를 지켜줄 것이다.', 66384),
(289381, 'koKR', '나는 키엠, 하르알노어 작물의 일원이다.', '', 66384),
(289379, 'koKR', '공허첨탑은 견고하지만, 세상에 무적의 요새 같은 건 없습니다.\n\n이곳도 예외는 아닙니다.', '', 66384),
(289377, 'koKR', '', '오늘 하루의 시작은 별로였지만, 마무리는 정말 마음에 들어요. 정말 고마워요!', 66384),
(289375, 'koKR', '호들갑 떨지 말게. 살았잖나?', '', 66384),
(289374, 'koKR', '저 죽을 뻔했어요, 영감님.', '', 66384),
(289372, 'koKR', '모든 루타니는 빛 속에서 번성한다. 어둠 속에서 번성하는 건 포자 친족뿐이야.', '', 66384),
(289371, 'koKR', '', '혼쭐을 내주자고요!', 66384),
(289369, 'koKR', '', '저놈이 절 여기로 끌고 온 덩치 녀석이에요.', 66384),
(289347, 'koKR', '왜 이방인이 귀찮게 구는 거지?', '', 66384),
(289330, 'koKR', '그럴지도. 근데 그럼 재미 없잖아. 투덜대지 말게.', '', 66384),
(289329, 'koKR', '이것 좀 풀어주면 훨씬 쉬울 텐데요.', '', 66384),
(289328, 'koKR', '저... 돌아가서 감사 인사를 드려야겠어요. 너무 많은 걸 잘못 생각했네요.', '', 66384),
(289327, 'koKR', '오늘 당신은 쓰러지지 않을 겁니다!', '', 66384),
(289326, 'koKR', '빛이 당신을 보호할 것입니다!', '', 66384),
(289319, 'koKR', '', '오, 빛이시여, 정말 용사님이군요! 이건... 정말... 놀랍네요!', 66384),
(289318, 'koKR', '', '용사님, 오셨군요. 장교도 구하셨네요.', 66384),
(289317, 'koKR', '그래도 이건 바로잡아야 해요. 황혼의 칼날단은 제 여동생의 죽음에 대한 대가를 치를 거예요!', '', 66384),
(289315, 'koKR', '<검을 하얗게 단단히 움켜쥐는 마엘라> \n\n이곳에서는 더 이상 동료를 잃지 않을 겁니다.', '<검을 하얗게 단단히 움켜쥐는 마엘라> \n\n이곳에서는 더 이상 동료를 잃지 않을 겁니다.', 66384),
(289314, 'koKR', '<당신을 보고 능청스럽게 웃다 옆구리를 붙잡고 인상을 찡그리는 사이데라스>\n\n또다시 윈드러너 밑에서 싸우게 될 줄은 몰랐습니다. 지난번과 비슷한 전개인 것 같군요.', '', 66384),
(289313, 'koKR', '<로스락시온을 쏘아보는 여군주 다크글렌> \n\n저 자식, 알레리아 님이 계신 걸 다행으로 알아야 합니다. 일이 끝나면 히에론이 그렇게 된 대가를 치르게 할 거예요.', '<로스락시온을 쏘아보는 여군주 다크글렌> \n\n저 자식, 알레리아 님이 계신 걸 다행으로 알아야 합니다. 일이 끝나면 히에론이 그렇게 된 대가를 치르게 할 거예요.', 66384),
(289312, 'koKR', '둘 다 멀쩡하구먼?\n\n<천천히 고개를 끄덕이는 아자이>\n\n아주 훌륭하네, $n. 저 아이도 인생의 두 번째 교훈을 배웠겠지. 안 죽은 걸 보니 말이야.', '', 66384),
(289309, 'koKR', '잠깐! 거기 서! 이 무모한 녀석!', '', 66384),
(289307, 'koKR', '<사이데라스의 가슴에 난 찢긴 상처를 붕대로 단단히 누르는 아라토르>\n\n1분만 늦었어도 이미 숨이 끊어졌을 겁니다.', '', 66384),
(289306, 'koKR', '흠. 이방인이 이렇게 빨리 우리 수공예를 익히다니, 놀랍구먼.\n\n자네 덕분이 아니라, 내가 가르치는 솜씨가 좋은 덕이겠지.\n\n<미소를 보일 뻔하며, 고개를 살짝 끄덕여 당신을 칭찬하는 아자이>', '', 66384),
(289305, 'koKR', '불편할 정도로 식욕이 넘치는 도마나르지. 오해는 마라. 세베룸의 굶주림은 정당하다. 다만, 모름지기 참된 미식가는 한 입 한 입을 음미할 줄 알아야 해. 세베룸은 그냥 끝없는 구덩이다. 솔직히 테르미나스가 놈을 곁에 두는 건 토렌티아를 골려먹기 위한 게 아닐까 싶을 정도야. 토렌티아는 세베룸 같은 얼간이가 자기 위에 있는 걸 참지 못하거든.', '', 66384),
(289303, 'koKR', '토렌티아 말인가. 도마나르라고 부르기도 민망한 존재지. 놈도 한때 포식의 견장을 노린 적이 있었다는 걸 아나? 테르미나스는 그 시도가 어찌나 우스웠는지, 살려두고 부하로 삼아버렸지. 그렇게 토렌티아는 이제 자신이 감당하지 못하는 물건을 영원히 지켜야 하는 처지가 됐다. 놈의 영지를 둘러봐라. 피에 굶주린 야수와 비실거리는 공허괴물만 가득하지. 언제 무너져도 이상하지 않다. 그런데도, 삶에 매달리는 필멸자처럼 그 자리를 놓지 않으려 애쓰고 있지.', '', 66384),
(289300, 'koKR', '이 냄새가 느껴지나? 바로 암연지 성채 특유의 향취다. 다소 투박하긴 하지만, 폭력적인 매력이 있지.', '', 66384),
(289299, 'koKR', '직접... 보진 못했어요.\n\n들어봐요, 공격을 당했어요. 줄아만 쪽에서 왔죠.\n\n그럼 누가 했겠어요? 아마니 말고?\n\n그렇죠?\n\n<시선을 피하는 켈러>', '', 66384),
(289295, 'koKR', '레이니아는 죽었어요.\n\n<결박된 채로 주먹을 움켜 쥐는 켈러>\n\n꼭 밤의 유령 같았어요...\n\n아마니였을 거예요. 틀림없어요.\n\n그냥 닥치는 대로 공격했어요. 그렇다면 우리도 똑같이 하면 되잖아요? 아무 아마니나 상관없잖아요.\n\n왜 안 되죠?', '', 66384),
(289293, 'koKR', '시체가 이렇게나 많이... 황혼의 칼날단이 한 짓인가요?', '', 66384),
(289290, 'koKR', '', '저기요? 누구 없어요? 구해주세요!', 66384),
(289289, 'koKR', '', '서두르세요, 용사님! 제가 균열을 열어둘 테니 안에 들어가 구해 주세요.', 66384),
(289287, 'koKR', '우린 빛나무를 가공할 때, 천산갑 기름과 용매 둥지의 재를 섞은 기름을 발라서 밀봉하네. 이게 바로 빛나무를 제대로 다루는 비결이지.\n\n이 처리를 하지 않으면, 무기가 금세 타버리거나 빛을 잃게 돼. 빛이 바랜 빛나무 무기는 황혼의 칼날단을 상대하는 데 있어 그냥 평범한 칼이나 다름없지.', '', 66384),
(289286, 'koKR', '시련은 아직 끝나지 않았다. 저 앞에서 하가르가 기다린다. 알른하라가 함께하기를 빌지.', '', 66384),
(289285, 'koKR', '허. 로아의 마법으로 빛을 보존하다니... 꽤 영리하네요.', '', 66384),
(289283, 'koKR', '', '지난번 만남 이후, 여신의 목소리를 따라 먼 길을 여행했네. 지상에는 배울 게 참 많더군.\n\n왜 이곳으로 이끌렸는지는 아직 알 수 없지만... 다시 만나 반갑네, $p.', 66384),
(289281, 'koKR', '', '난 하라니르의 오르웨냐라고 하네. 우리 종족이 고향을 벗어나는 일은 드물지. 하지만 세계의 노래가 나를 이끌고 있어. 여신의 뜻이라면 어디든 따를 걸세.', 66384),
(289275, 'koKR', '참 야단법석이네. 빛의 무리는 전부 조화와 평온만을 추구한다고 믿었던 내가 어리석었던 걸까? 뭐, 이쪽이 훨씬 흥미롭긴 해.', '', 66384),
(289273, 'koKR', '공허의 굶주림이 우리 세계에만 닿기를 바란 것이 어리석은 희망이었을까요?\n\n주위를 보십시오. 태양샘에서 온 성기사들, 실버문의 수호자들. 그뿐만이 아닙니다. 처음 보는 이계의 전사들도 있습니다.\n\n공허처럼 탐욕스럽고 무차별적인 적을 우리는 어떻게 이겨낼 수 있을까요?', '', 66384),
(289272, 'koKR', '말로 표현할 수 없는 죄악의 온상이군요.', '', 66384),
(289271, 'koKR', '', '$p 님, 무기는 늘 가까이 두세요. 이곳은 폭력이 곧 대화 수단인 세계예요. 우리도 같은 언어로 답할 준비가 되어 있어야 해요.', 66384),
(289270, 'koKR', '진심에서 우러나온 호기심인가, 아니면 미묘한 의심이 섞인 건가? 이거 가슴 아픈걸. 난 상처에서 흘러나오는 피처럼 진실만을 알려줬는데 말이지.\n\n포식의 견장은 많은 이가 탐내지만, 자격 있는 자만이 가질 수 있다. 잘아타스는 우주의 서열 높은 곳에 오르는 자에게만 견장을 내린다. 그리고 그 계단 하나하나에는 사냥당한 자들의 뼈가 박혀 있지.\n\n문제는 골치 아픈 선물이란 거야. 힘은 힘을 끌어당기기 마련이지. 견장을 지닌 자는 항상 경계해야 하고, 언제나 목덜미에 송곳니가 박힐 순간을 대비해야 해. 어쩌면 잘아타스는 그걸 즐기는 걸지도 몰라. 자신의 하수인들이 항상 긴장하고, 초조함 속에서 살도록 말이야.', '', 66384),
(289268, 'koKR', '잘아타스의 숙주가 자리한 중심부를 고작 저 정도 병력으로 쳐들어오다니. 오만하다고 해야 할지, 처절하다고 해야 할지.', '', 66384),
(289267, 'koKR', '겉으로 드러나는 평온한 모습에 속지 마십시오. 이 영지 역시 이곳의 다른 장소들처럼 사악합니다.', '', 66384),
(289266, 'koKR', '주변을 둘러보십시오. 첨탑이며 건물이며, 전부 지어진 것이 아니라 형태를 부여받은 것입니다. 흙과 바위를 공허의 마법으로 빚어낸 것이지요.\n\n도마나르가 공허를 다루는 솜씨는 실로 놀랍습니다. 우리가 저들에게서 배울 수 있는 것을 생각해 보십시오.', '', 66384),
(289260, 'koKR', '순수한 비전 마력... 이 정도면 충분하겠군.', '', 66384),
(289259, 'koKR', '<삑삑이가 둥그레진 눈으로 당신을 올려다보더니, 어딘가 당혹감이 섞인 듯한 울음소리를 냅니다.>', '<삑삑이가 둥그레진 눈으로 당신을 올려다보더니, 어딘가 당혹감이 섞인 듯한 울음소리를 냅니다.>', 66384),
(289255, 'koKR', '', '마법학자 던블레이즈가 미소를 지으며 포도주를 홀짝거립니다.', 66384),
(289253, 'koKR', '네 머리통도 가져가면 돈 줄 사람 있어. 명심해.', '', 66384),
(289251, 'koKR', '', '돈 받고 사람 목숨을 빼앗는 자에게 설교를 들으니 참 우습네요.', 66384),
(289250, 'koKR', '골목을 지킨 건 나야. 네놈들이 골목은 실버문의 일부도 아닌 양 모르는 체하고 있을 때 말이지.', '', 66384),
(289248, 'koKR', '', '물론입니다. 눈엣가시였던 아라디스가 사라졌고, 골목이 연루되면서 일 처리 비용도 아꼈거든요.', 66384),
(289247, 'koKR', '이 길은 반드시 지켜야 합니다. 그 피조물이 있어야 억제가 되죠.', '', 66384),
(289245, 'koKR', '', '농담이 아니라, 정말 저걸 그냥 두고만 볼 건가요?\n\n저것 좀 보세요! 깃털은 다 곤두섰고, 겁에 질렸잖아요! 지난번에도 겨우 달래는 데 몇 시간이 걸렸다고요.', 66384),
(289244, 'koKR', '우린 이 싸움에서 이기는 편에 서겠다!', '', 66384),
(289242, 'koKR', '', '빛이시여... 저리 떨어져라, 괴물!', 66384),
(289241, 'koKR', '', '피에 온기가 남아 있는데... 잠깐만요, 용사님. 소리 들으셨나요?', 66384),
(289238, 'koKR', '왜, 우리 도마나르는 네 빛벼림 친구가 간단히 정리한 것처럼 악과 어둠의 결정체일 뿐이야!\n\n확실히 우리가 바라는 건 오직 하나다. 너희 필멸자의 마음에서 우러나오는 고통을 한 방울도 빠짐없이 맛보는 거지.\n\n고상한 구조물을 세우고, 화려한 정원을 가꾸고, 머나먼 세계에서 들은 이야기들을 나누는 삶? 그런 건 우리한테 어울리지 않아.\n\n<몸을 앞으로 기울이며 당신의 무기를 탐스럽게 바라보는 데시무스>\n\n정교한 공예품은 말할 것도 없고 말이야.\n\n아니지, 아니고말고. 우린 그저 잘아타스의 포식의 군단을 이끌고, 잘아타스의 이름으로 용사들을 학살하길 원할 뿐이다.\n\n<당신을 훑어보며 배고픈 미소를 짓는 데시무스>\n\n맛있는 식사를 마다할 이유가 있을까?', '', 66384),
(289235, 'koKR', '빛의 선봉대는 이미 과도한 부담을 지고 있습니다. 병사 하나조차 돌릴 여유가 없습니다.\n\n투랄리온은 군을 지휘해야 하니 남아야 합니다. 다행히 전 위험한 소수 정예 임무를 수없이 이끌어 본 경험이 있지요.\n\n우리는 실패하지 않을 겁니다.', '', 66384),
(289234, 'koKR', '', '마법학자 던블레이즈가 미소를 짓습니다.', 66384),
(289233, 'koKR', '로르테마르 님의 부름을 받고 이 공허폭풍 강습 임무에 합류하게 되어 더없이 기뻤습니다. 빛의 선봉대를 위협하는 어둠의 중심지, 바로 그 한가운데를 향하는 작전이니까요.\n\n우리는 적의 심장을 꿰뚫고, 아군의 부담을 덜어줄 겁니다.\n\n그리고...\n\n<시선을 피하는 아라토르>\n\n사실 어머니에 대한 소식이 한참 전부터 끊겼습니다. 왠지... 잘은 모르겠지만, 어머니를 찾을 수 있는 곳이 있다면 바로 저 안일 겁니다. 잘아타스에게 먼저 싸움을 거셨을 테니까요.', '', 66384),
(289213, 'koKR', '기쁘다고? 이 일 때문에 내 친구 한 명이 죽었어.', '', 66384),
(289212, 'koKR', '', '이 작은 소동이 원만히 해결되어 기쁠 따름입니다.', 66384),
(289211, 'koKR', '', '아라디스에게는 참으로 유감스러운 결말이군요.', 66384),
(289209, 'koKR', '', '이 시체는 반쯤 먹혔고, 청소부들이 헤집어놨군요.', 66384),
(289197, 'koKR', '', '선봉대원의 유해예요. 침상에서 끌려 나와 이 협곡에서 잡아먹힌 모양입니다.', 66384),
(289190, 'koKR', '', '칼날굴에서 만나요.', 66384),
(289183, 'koKR', '요람에 온 걸 환영한다.', '', 66384),
(289179, 'koKR', '꼬마는 우릴 원수로 알고 있더군.\n\n그 녀석 여동생이 정말 아마니에게 죽임을 당했는지 나는 모른다네. 설령 그랬다 해도, 이곳에 있는 누구도 그 일에 책임은 없네.\n\n지금은 그걸 받아들이지 못하더라도, 시간이 지나면 이해할 수도 있겠지. 그런 기회를 주는 데 우리 쪽에서 잃을 건 별로 없지 않겠나. 슬픔에 있는 빠진 사람이니 말이야.', '', 66384),
(289178, 'koKR', '$n, 날을 붙이게. 어린 친구, 자네는 그걸 단단히 잡고 있게.', '', 66384),
(289176, 'koKR', '이제 사포질하게. 투덜대지 말고. $n 방해하지 마.', '', 66384),
(289171, 'koKR', '뭐요? 전 아직도 묶여 있다고요! 이래서야 어떻게 도와요?', '', 66384),
(289163, 'koKR', '무분별한 $r 같으니! 정신 나갔습니까?! 저건 괴물입니다! 그런데도 빛의 심판을 피하도록 도왔다고요?\n\n이번 임무가 끝나면 따로 얘기 좀 합시다.', '', 66384),
(289162, 'koKR', '경비병들 들이닥치기 전에 골목으로 돌아가. $n, 현상금 챙기러 가자.', '', 66384),
(289160, 'koKR', '제이스, 굳이 안 그래도...', '제이스, 굳이 안 그래도...', 66384),
(289159, 'koKR', '그놈 목에 현상금 붙어 있었지, 참. 내 몫은 다 같이 나눠 가지자.', '', 66384),
(289158, 'koKR', '그래. 죽었어. 이제 아무도 납치 못 할 거야.', '', 66384),
(289157, 'koKR', '마법학자는 죽었어?', '마법학자는 죽었어?', 66384),
(289153, 'koKR', '다른 녀석들 상태 좀 봐야겠어. 그놈 시체에서 챙길 거 챙기고 나서 위층에서 보자.', '', 66384),
(289152, 'koKR', '에이, 내가 숨통을 끊어야 했는데... 뭐, 죽었으니 됐어.', '', 66384),
(289147, 'koKR', '<아라토르가 거칠게 숨을 몰아쉬며 공기를 들이마십니다. 얼굴은 땀으로 흠뻑 젖어 있습니다.>\n\n통할 거란 확신은 없었는데... 고맙습니다, $n 님.', '', 66384),
(289145, 'koKR', '적을 막아야 합니다! 전장에 흩어진 신성 마력을 모아 주십시오. 그 힘을 이용하면 적의 진열을 무너뜨릴 수 있을 겁니다! 서둘러 주십시오!', '', 66384),
(289144, 'koKR', '한 번 더 배를 갈라 주마, 개자식아!', '', 66384),
(289142, 'koKR', '또 만나게 됐군요, $n. 이번엔 당신이 풀어준 자들을 대신할 쥐를 새로 데려오셨네요. 배려심도 좋아.', '', 66384),
(289133, 'koKR', '너무... 배고파...', '너무... 배고파...', 66384),
(289132, 'koKR', '제자로 삼아 주겠다고 했어...', '제자로 삼아 주겠다고 했어...', 66384),
(289130, 'koKR', '이제... 걸을 수 있을 것 같아.', '이제... 걸을 수 있을 것 같아.', 66384),
(289129, 'koKR', '골목 인생에서... 구해주겠다고 했는데...', '골목 인생에서... 구해주겠다고 했는데...', 66384),
(289126, 'koKR', '정말 죽는 줄 알았어...', '정말 죽는 줄 알았어...', 66384),
(289123, 'koKR', '젠장! 수정에서 사람들 빼내! 이게... 사르비, 일어나!', '', 66384),
(289122, 'koKR', '이게 뭔...', '', 66384),
(289121, 'koKR', '서둘러! 낭비할 시간 없다!', '', 66384),
(289119, 'koKR', '너한테 지팡이를 준 걸 후회하게 만들어 주자.', '', 66384),
(289118, 'koKR', '아라디스는 아직 안 보여. 근데 이 수호물 너머로 무슨 소리가 들리는군. 경계를 늦추지 마.', '', 66384),
(289116, 'koKR', '다 말해 주지. 따라와라, $n. 치워야 할 놈이 생겼으니.', '', 66384),
(289115, 'koKR', '내일 아라디스에 대한 \"흥미로운\" 소식이 날아들면 매우 재밌을 것 같네요.', '', 66384),
(289114, 'koKR', '지옥 마력은 강력하면서도 위험한 도구입니다. 신도레이는 그 점을 아주 잘 이해하고 있죠.', '', 66384),
(289113, 'koKR', '제단에 수호물 파괴기를 올려놓으세요. 물품들에서 마력을 추출해 다시 조율하겠습니다.', '', 66384),
(289112, 'koKR', '흑마법사를 해치우는 게 더 중요해. 놈의 마법 수호물을 파괴하려면 수호물 파괴기를 조율해야 한다.', '', 66384),
(289111, 'koKR', '멀쩡하게 작동하는 수호물 파괴기라. 값이 꽤 나가는 물건이죠.', '', 66384),
(289110, 'koKR', '', '조심하세요, 용사님. 이 괴물들은 어디서든 나타날 수 있어요.', 66384),
(289108, 'koKR', '이쪽이다. 전이랑 똑같이 해. 네가 시간 끌 동안 내가 들어간다.', '', 66384),
(289107, 'koKR', '마지막 목표다. 이번엔 보는 눈이 많네. 그래도 피해갈 수 있어. 일꾼들 좀 붙잡아놔.', '', 66384),
(289106, 'koKR', '여기부터 시작한다. 저 일꾼 주의 좀 돌려. 내가 몰래 숨어 들어갈 테니까.', '', 66384),
(289101, 'koKR', '', '이 땅에 흐르는 공허 마력은 무한한 힘을 약속하죠. 하지만 어떤 대가가 뒤따를까요?', 66384),
(289100, 'koKR', '', '우리가 알아낸 내용을 엄브릭 님에게 보고했어요. 이곳이 모두에게 위험하다는 데 동의하셨고요.\n\n다만, 공허폭풍이 우리 동족에게 주는 위험을 감내하긴 해야겠죠.\n\n아제로스의 운명이 걸려 있으니.', 66384),
(289086, 'koKR', '하! 아무리 해치워도 경보가 울리지 않는군. 놈들은 이 혼돈이 익숙한 모양입니다. ', '', 66384),
(289085, 'koKR', '이곳은 가장 작은 벌레까지, 모든 생명체가 공허에 잠식된 것 같습니다. 경계하십시오. ', '', 66384),
(289076, 'koKR', '그리고 어둠도 빛이 될 수 있죠. 알겠습니다, 어머니. 놈들의 물건으로 도마나르를 생포할 수 있겠군요. ', '', 66384),
(289075, 'koKR', '', '빛과 어둠은 같은 동전의 양면 같은 거야. 충분히 밀어붙이면 빛도 어둠이 될 수 있지.', 66384),
(289071, 'koKR', '', '같잖은 샘에 빌어 봐라. 그래도 잘아타스 님을 피할 순 없다!', 66384),
(289070, 'koKR', '우리가 털 가게들은 실버문 상류층을 상대로 장사하는 곳이야. 좋은 물건을 취급하겠지. 그런 놈들이 손해 좀 본다고 해서 내 알 바는 아니야.', '', 66384),
(289068, 'koKR', '제이스가 서류를 노려보다가 땅에 침을 뱉습니다.', '', 66384),
(289066, 'koKR', '이름까진 몰라도 그 흑마법사 개자식은 알아. 몇 달째 사람을 납치하고 있거든. 돌아온 사람은 아무도 없어.', '', 66384),
(289064, 'koKR', '특별한 관심을 보일 거라고? 근거를 대봐.', '', 66384),
(289062, 'koKR', '', '아라토르, 용사님! 의식을 치를 동안 보호해 주십시오!', 66384),
(289061, 'koKR', '맡겨 주십시오! 저희가 방을 정리하겠습니다!', '', 66384),
(289060, 'koKR', '', '당신이 마지막으로 도착한 선봉대입니다.', 66384),
(289059, 'koKR', '얘기하고 싶으면 선술집에서 하지. 더 이상 사고 치지 말고.', '', 66384),
(289058, 'koKR', '그만해. 날 찾는다고? 자, 여기 있다.', '', 66384),
(289043, 'koKR', '제기랄! 선봉대! 후퇴하라!', '', 66384),
(289041, 'koKR', '', '투랄리온 님! 늦기 전에 태양샘으로 다시 집결해야 합니다!', 66384),
(289038, 'koKR', '서두르게, 용사! 저 거수를 상대하려면 자네의 도움이 필요하네!', '', 66384),
(289037, 'koKR', '엘프를 살려둔 걸 보면 아자이는 확실히 명예를 알아.\n\n라카니는 그걸 이해 못 하지. 언제나 분노에 눈이 멀어 있고, 과거의 고통에 사로잡혀 있으니까.\n\n그 엘프와 다를 바 없지.\n\n하지만 이번 일은 그 녀석에게 배울 기회가 될 수도 있어. 변할 수 있는 기회지.\n\n그리고 우리에게도 마찬가지야.', '', 66384),
(289036, 'koKR', '', '아자이가 블러드 엘프 놈을 해치워야 했어.\n\n낯선 자는 여기서 환영받지 못하네. 특히 문제를 일으키려고 오는 자라면 더더욱.', 66384),
(289035, 'koKR', '', '이 사본을 가져가세요. 이 문제를 해결해 주면 돈을 낼 용의가 있다고도 전해 주시고요.', 66384),
(289034, 'koKR', '', '제이스는 예전에... 제 일을 몇 번 해 준 적 있습니다. 아라디스에게 특별한 관심을 보일 수도 있다는 것도 알고 있죠.', 66384),
(289033, 'koKR', '다들 답답한 건 마찬가지지. 하지만 황혼의 칼날단이 목덜미까지 들이닥친 상황이라네.\n\n놈들이 점점 가까이 밀고 들어와서, 이제는 밖에 발도 못 들여놓을 판이야. 제대로 된 작업은 꿈도 못 꾸지.\n\n일단은 여기 있는 자원으로 버틸 수밖에 없겠군.', '', 66384),
(289032, 'koKR', '', '자네도 나만큼 심심한가 보군, 응?\n\n우린 아자이가 무기들을 마을로 옮기라고 할 때까지 여기에 발이 묶였지.\n\n저번 수송대가 돌아오지 않은 뒤로 아자이가 우리를 지키려고 이러는 거긴 한데, 난 차라리 황혼의 칼날단한테 덤벼서라도 가만히 서 있는 것보단 낫다고 생각하네. 우리 동족한테 이 무기가 필요하니까 말이야.', 66384),
(289030, 'koKR', '어머니...', '', 66384),
(289029, 'koKR', '', '들고 있는 문서를 보니 아라디스가 시켰나 보죠. 이리 오세요. 그럼 경비를 부르지 않겠습니다.', 66384),
(289028, 'koKR', '', '아, 오셨군요. 남의 수호물을 뻔뻔하게 대놓고 해제하고 다니던 도둑 나리 아닙니까.', 66384),
(289026, 'koKR', '빛을 위하여!', '', 66384),
(289025, 'koKR', '빛의 선봉대! 나를 따르라! 저 침략자들을 다시 공허로 몰아내자!', '', 66384),
(289022, 'koKR', '중요한 건 문서를 회수하는 겁니다. 실패하지 마세요.', '', 66384),
(289021, 'koKR', '아, 보호가 약해지는군요. 원래는 마법으로 건드리려고 하면 방해를 받았는데, 이젠 아니네요.', '', 66384),
(289020, 'koKR', '', '용사님이 유물을 회수해 주셔서 정말 다행입니다!', 66384),
(289018, 'koKR', '', '에테리얼들이 우리의 성물을 약탈하게 두어서는 안 됩니다!', 66384),
(289017, 'koKR', '그 점은 의견이 맞는군. 아라토르, 전선을 지켜라. 용사님, 저 무기를 확보하십시오!', '', 66384),
(289016, 'koKR', '훌륭합니다. 이 도관을 따라가면 다음 연결고리가 나올 겁니다. 실패하지 마시길.', '', 66384),
(289015, 'koKR', '수호물 파괴기는 이 도관을 보호하는 비전 마법에 맞춰 조율되어 있습니다. 파괴기를 사용하면 보호막이 사라질 거예요.', '', 66384),
(289014, 'koKR', '그럼 그게 첫 목표입니다. 폭풍과 적을 약화시켜야 합니다! 이동합시다!', '', 66384),
(289013, 'koKR', '', '도마나르라는 강력한 존재들이 잘아타스의 이름으로 군단을 지휘하고 있어. 그중 한 명이 근처의 공결탑을 감시하고 있지만, 아직 가까이 가지 못했어.', 66384),
(289012, 'koKR', '', '좋아. 어차피 그게 없으면 죽을 테니까. 이제 잘 들어.', 66384),
(289009, 'koKR', '아라토르! 대형을 이탈했더군.', '', 66384),
(289008, 'koKR', '여전히 형편없지만, 아무튼 수호물 파괴기는 충전됐네요. 이리 오시죠.', '', 66384),
(289007, 'koKR', '으, 자세가 엉망이군요. 흡수하는 동안에는 움직이지 마세요. 에테르 흐름이 뒤틀릴 수도 있습니다.', '', 66384),
(289006, 'koKR', '던블레이즈는 그걸 막으려고 절 협박할 거짓 증거를 만들어 냈습니다. 이게 얼마나 큰 불의인지는 아시겠죠.', '', 66384),
(289005, 'koKR', '그 여자는 신도레이가 당면한 새로운 위협에 적응하지 못하고 있습니다. 그래서 제가 대신하러 나선 겁니다.', '', 66384),
(289004, 'koKR', '말씀드린 대로 수호물장이들은 마법학자 던블레이즈가 이끌고 있습니다. 전쟁 이후 공석이 된 자리를 이어받았지만, 계속 무능함을 드러내고 있죠.', '', 66384),
(289003, 'koKR', '수호물 파괴기를 가져가 제 서재에 있는 저장소에서 충전하세요. 당신이라면 무난히 해낼 수 있으리라 믿습니다.', '', 66384),
(289002, 'koKR', '', '제 이성은 걱정 마세요, 용사님. 저나 제 하수인이나 이런 광기에는 익숙하니. ', 66384),
(289000, 'koKR', '', '꼭 사르비가 보냈다고 해야 해. 그래야 나한테도 몫이 떨어져.', 66384),
(288995, 'koKR', '병력을 뺄 여유가 없습니다! 에테리얼 대포의 압박이 강합니다.', '', 66384),
(288987, 'koKR', '그 존재는 강대한 힘을 지녔음에도, 고통에 휩싸여 있었습니다. 저도 분노에 삼켜졌을 때 고통에 휘둘려 폭발했지요. 공허도 빛과 같은 걸까요?', '', 66384),
(288982, 'koKR', '아버지는 군단을 무찌르는 데 혈안이 되어 있지만, 단순한 돌격만으로는 부족합니다. 수정탑을 먼저 파괴해야 합니다.', '', 66384),
(288981, 'koKR', '빛의 선봉대, 대열을 이뤄라! 이 관문을 사수한다!', '', 66384),
(288979, 'koKR', '탈것에 오르십시오, 용사님. 선봉대가 공격하기 전에 관문에 도착해야 합니다!', '', 66384),
(288977, 'koKR', '', '젠장, 이미 안으로 뚫고 들어갔네요.', 66384),
(288976, 'koKR', '', '나쁘지 않군. 하지만 이제 끝낼 때다.', 66384),
(288975, 'koKR', '작은 고깃덩이야. 어쩌다 여기까지 흘러 들어왔느냐?', '', 66384),
(288964, 'koKR', '투랄리온은 모든 것을 잃고 얻는 승리는 아무 소용 없다는 사실을 망각했소.', '', 66384),
(288958, 'koKR', '모두 구하셨군요! 정말 다행입니다!', '', 66384),
(288957, 'koKR', '놈들이 배를 가라앉혔습니다! 생존자에게 밧줄을 던지십시오!', '', 66384),
(288956, 'koKR', '하늘을 정리하고 생존자들을 구하십시오!', '', 66384),
(288955, 'koKR', '배들을 지키지 못하면 동족을 죽음으로 몰아넣은 것과 다름없게 되오!', '', 66384),
(288954, 'koKR', '<어깨 너머로 당신을 돌아보며 작게 미소 짓는 히에론>\n\n죄송합니다. 이 일이 끝나면 실버문에서 차 한잔 대접하며 사과드리지요.', '', 66384),
(288953, 'koKR', '아라토르, 용사! 피난선이 공격받고 있소!', '', 66384),
(288951, 'koKR', '빛이 당신의 길을 인도하기를.', '', 66384),
(288950, 'koKR', '빛이 당신을 치유합니다.', '', 66384),
(288949, 'koKR', '성스러운 빛이 고통을 덜어줄 겁니다.', '', 66384),
(288948, 'koKR', '성스러운 빛으로, 고통은 사라지리라.', '', 66384),
(288947, 'koKR', '', '저기, 탑의 기슭을 보세요. 저자가 지휘관입니다.', 66384),
(288946, 'koKR', '됐습니다. 길이 열렸어요.', '', 66384),
(288936, 'koKR', '서두르시죠, 용사님. 생존자들에게 길을 열어 줘야 합니다!', '', 66384),
(288931, 'koKR', '안 되오! 내 동족을 무방비로 두고 떠날 수 없소!', '', 66384),
(288930, 'koKR', '지금이 반격할 기회요. 반드시 쳐야 하오!', '', 66384),
(288929, 'koKR', '선봉대원들을 찾아야 합니다. 대총독님을 실망시킬 순 없지요.', '', 66384),
(288928, 'koKR', '용사님! 이쪽입니다!', '', 66384),
(288926, 'koKR', '대총독께서 우리를 영광과 죽음으로 이끄신다!', '', 66384),
(288925, 'koKR', '불결한 공허의 피조물들아! 최후를 맞이해라!', '', 66384),
(288924, 'koKR', '내면의 불꽃을 찬란하게 불태우게, 형제들이여! 부름에 따라 공허에 맞서야 하네!', '', 66384),
(288923, 'koKR', '잘아타스! 내가 저 사악한 비수를 파괴할 길만 찾았더라면!', '', 66384),
(288922, 'koKR', '', '누군가는 태양샘을 지켜야 합니다! 태양샘이 무너지면 모든 게 끝장입니다!', 66384),
(288921, 'koKR', '용사님, 아라토르를 찾으십시오! 전 선봉대를 모아 공격을 준비하겠습니다!', '', 66384),
(288920, 'koKR', '아군 병력이 흩어졌습니다. 포식의 군단이 밀어닥치고 있습니다!', '', 66384),
(288918, 'koKR', '', '지원이 도착했다고 해도 포식의 군단을 상대로 오래 버티기는 어렵습니다. 서둘러야 합니다, 용사님.', 66384),
(288917, 'koKR', '제 빛의 보호 안에서 치유받으십시오! 지켜드리겠습니다!', '', 66384),
(288912, 'koKR', '', '즐겁나, 테르미나스? 어디 한번 내려와 봐.', 66384),
(288910, 'koKR', '', '전 용사님이 싸우는 걸 봤어요. 더 잘하실 수 있잖아요.', 66384),
(288905, 'koKR', '', '받으세요. 히에론은 너무 겸손해서 탈이라니까요. 제가 그렇게 말했다고 일러도 됩니다.', 66384),
(288901, 'koKR', '', '털고 일어나세요, 렌도레이. 아직 쓰러지지 않았잖아요.', 66384),
(288899, 'koKR', '거, 거기 누구야? 가까이 오지 마!', '거, 거기 누구야? 가까이 오지 마!', 66384),
(288898, 'koKR', '알겠습니다. 저도 좀 앉아서 쉬어야겠군요.', '알겠습니다. 저도 좀 앉아서 쉬어야겠군요.', 66384),
(288754, 'koKR', '', '뜸 들이지 말고 말씀하세요. 마법학자 아라디스는 어떻게 됐나요?', 66384),
(288738, 'koKR', '', '한 입만 더... 식욕이 대단하네요! 좋은 징조예요.', 66384),
(288685, 'koKR', '이 기회를 온전히 받아들여야 합니다, 켈리아.', '', 66384),
(288684, 'koKR', '언제 연구에서 조심만으로 발전을 이룬 적 있었습니까!', '', 66384),
(288683, 'koKR', '물은 새로 갈았고 건초도 다 쌓았어요. 평소랑 다름없네요.', '', 66384),
(288682, 'koKR', '', '공허폭풍이 우리 안의 무언가를 흔들고 있어요, 마트리안. 조심해야 해요.', 66384),
(288672, 'koKR', '', '서두르세요. 테르미나스가 요새로 돌아오기 전에 견장을 확보해야 합니다.', 66384),
(288671, 'koKR', '내 애완동물의 시야를 빌려라. 폭풍을 약화시킬 방법을 알려주지.', '', 66384),
(288655, 'koKR', '빛은 공허에 맞서는 최고의 무기입니다. 기억하십시오. 그렇지 않으면 타락하고 말 것입니다. ', '', 66384),
(288654, 'koKR', '젊은 아라토르는 이미 자신의 가치를 충분히 증명했소. 함께라면 어둠 속에서도 빛이 균형을 이룰 수 있을 거요. ', '', 66384),
(288649, 'koKR', '', '잘아타스와 포식의 군단이 쿠엘다나스 섬의 태양샘을 공격했습니다. 빛이 $p 님을 불러 돕게 한 것이고요.', 66384),
(288626, 'koKR', '', '$n 님! 마트리안이 더 큰 재앙을 일으키기 전에 막아 주세요.', 66384),
(288621, 'koKR', '진보의 그릇이 되는 건 최고의 학문적 영예입니다. 지금 멈출 수는 없습니다.', '', 66384),
(288413, 'koKR', '먹거나... 먹히거나...', '', 66384),
(288412, 'koKR', '허기에는. 끝이. 없다.', '', 66384),
(288410, 'koKR', '안 돼! 목숨으로 갚아라!', '', 66384),
(288409, 'koKR', '마침내... 안식이...', '', 66384),
(288408, 'koKR', '필멸자! 네 영혼으로 소생하리라!', '', 66384),
(288401, 'koKR', '고마워, 오르웨냐. 진심으로 영광이야. 이렇게 날, 아니 우리를 받아줘서 고마워.', '', 66384),
(288400, 'koKR', '', '자네의 징표는 수 세대 전부터 이곳을 지나간 이들이 남긴 징표 옆에 새겨졌네. 자네도 이제 하란다르의 일원일세.', 66384),
(288398, 'koKR', '$c님이 부주의하게 동료를 잃어버리게 되더라도, 저한테 그 친구를 찾을 수 있는 능력이 있어요. 야수 보관도 도와드릴 수 있고요.', '', 66384),
(288397, 'koKR', '만약 $c님이 부주의하게 동료를 잃어버리는 일이 생기면, 제가 그 친구를 찾아드릴 수 있습니다.', '', 66384),
(288396, 'koKR', '쿠엘탈라스는 드넓지만, 제 매는 하늘길을 잘 알죠. 어디로 모셔드릴까요?', '', 66384),
(288394, 'koKR', '', '모든 여행자가 이런 안락함을 누릴 자격이 있는 건 아니지만, 당신은... 그럭저럭 괜찮아 보여요. 운이 좋은 줄 아세요.', 66384),
(288393, 'koKR', '', '모든 여행자가 이런 안락함을 누릴 자격이 있는 건 아니지만, 당신은 있어 보여요. 필요하다면 머무세요.', 66384),
(288387, 'koKR', '하, 좋지! 나중에 더 알아보자고. 이번엔 또 어딜 구경시켜 줄 거야?', '', 66384),
(288386, 'koKR', '', '우린 수 세대에 걸쳐 버섯에 가장 잘 어울리는 향신료와 약초의 황금 비율을 찾아냈다네. 근데 방심 말게나. 맛이 슬며시 몰려오거든.', 66384),
(288385, 'koKR', '허, 이건 뭐가 들어간 거야? 맵긴 한데, 딱 적당하네.', '', 66384),
(288384, 'koKR', '원래 다이너마이트를 좋아하는 녀석도 있고, 부식성 물질을 좋아하는 녀석도 있는 거지. 고전적이지만 물리적인 충격을 좋아하는 놈도 있고.', '', 66384),
(288383, 'koKR', '', '이건 날 위해 처음으로 만들어진 무기들일세. 여러 종류를 써봤지만, 이 발톱이 제일 잘 맞았어.', 66384),
(288362, 'koKR', '아마시가 그러더군. 독을 쓰는 마른나무껍질 요리법이 아직 훨씬 많이 남아 있다나. 사냥할 거리가 생겼다고 무척 들떠 있지. 내가 뭔가 새로운 걸 시도하면 늘 그렇게 열을 올린다네!\n\n<활짝 웃어 보이는 구슈>\n\n내 세계 요리책 집필은 이제 제대로 시작된 거지!', '', 66384),
(288361, 'koKR', '잔달라 요리는 많이 맛보았지만, 아직 아마니 요리는 접해 보지 못했네.', '', 66384),
(288360, 'koKR', '하! 그 양반 조리법을 버텨냈다면 뭐든 버텨내겠지. 내가 한번 들러서 표본을 받아볼까, 늙은 탐구자?', '하! 그 양반 조리법을 버텨냈다면 뭐든 버텨내겠지. 내가 한번 들러서 표본을 받아볼까, 늙은 탐구자?', 66384),
(288359, 'koKR', '딸에게 주는 건 어떻겠나, 아마시? 온 마을 사람들에게 새로운 요리를 먹이고 있던데.', '', 66384),
(288358, 'koKR', '우리가 만드는 물건은 긴 세월을 버티게 되어 있네. 우린 같은 걸 귀하게 여기는 걸지도 모르겠구먼.', '우리가 만드는 물건은 긴 세월을 버티게 되어 있네. 우린 같은 걸 귀하게 여기는 걸지도 모르겠구먼.', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(288357, 'koKR', '허. 이 항아리... 세월에 비해 놀라울 만큼 상태가 좋지 않은가. 우리처럼 말이야!', '', 66384),
(288356, 'koKR', '그리고 이제 나한테 준다고? 대체 무슨 꿍꿍이인가, 토르톨란? 정말 여기 온 이유가 뭐지?', '그리고 이제 나한테 준다고? 대체 무슨 꿍꿍이인가, 토르톨란? 정말 여기 온 이유가 뭐지?', 66384),
(288355, 'koKR', '낡은 항아리라고? 자네는 나한테 여기로 오라고 편지를 몇십 통씩이나 보냈는데, 찾은 게 고작 낡은 항아리인가?', '낡은 항아리라고? 자네는 나한테 여기로 오라고 편지를 몇십 통씩이나 보냈는데, 찾은 게 고작 낡은 항아리인가?', 66384),
(288353, 'koKR', '장로 렌젠, 모래톱에서 오래된 마른나무껍질 냄비를 찾았네. 이렇게 온 건 반환하기 위해서일세.', '', 66384),
(288352, 'koKR', '나루가 잘아타스의 병력에게 사로잡히다니... 우리가 나서야 합니다, $n 님.', '', 66384),
(288344, 'koKR', '', '이 토르톨란은 죽질 않는구먼.\n\n<아마시가 좌절한 듯한 표정을 짓더니, 이내 위협적인 미소를 그립니다.>\n\n내가 저런 위장을 가졌으면 얼마나 치명적인 요리를 시도해 볼 수 있을까!\n\n내 언젠가는 꼭 한계를 알아내, 같은 조건에서 함께 식사를 즐길 수 있게 하겠네!', 66384),
(288338, 'koKR', '', '그리고 자네가 그 효과를 온전히 느껴볼 수 있게 조리법을 하나 만들어주지.', 66384),
(288337, 'koKR', '놀랍군! 요리책에 반드시 기록해야겠네.', '', 66384),
(288336, 'koKR', '', '흥미롭군... 자네에겐 거의 효과가 없구먼. 그 정도 양이면 트롤은 한 이틀 마비됐을 텐데.', 66384),
(288335, 'koKR', '으윽! 팔다리가 저릿저릿하구먼! 아마시, 이게 자네가 말한 마비인가?', '', 66384),
(288334, 'koKR', '구슈가 농포 멧돼지 고기를 한입 물어뜯습니다.', '', 66384),
(288333, 'koKR', '자, 이제 먹어 보세!', '', 66384),
(288332, 'koKR', '', '좋아 보이는구먼. 충분히 익혔네.', 66384),
(288331, 'koKR', '아, 톡 쏘는 냄새가 나는군!', '', 66384),
(288330, 'koKR', '', '이제 모든 재료를 꼬챙이에 꿰게. 한동안 익혀야 두 독이 하나로 합쳐진다네.', 66384),
(288329, 'koKR', '', '손질할 멧돼지를 가져왔네. 농포 멧돼지 반죽을 발라 향신료로 사용할 걸세.', 66384),
(288328, 'koKR', '', '이제 기포가죽 물풀을 으깨게. 잎 끝만 쓰게나. 독이 가장 많이 모이는 데가 그쪽일세.', 66384),
(288327, 'koKR', '', '장어 위장부터 시작하게. 꼭 짜내서 체액을 다 빼내야 하네.', 66384),
(288321, 'koKR', '이 재료들은 마력이 가득해. 가자. 목표가 하나 더 남았어.', '', 66384),
(288318, 'koKR', '안녕하세요, $c 님. 특별히 찾는 물건이라도 있으신가요?', '', 66384),
(288306, 'koKR', '이 검에 마력이 좀 남아 있어. 골목으로 돌아가지.', '', 66384),
(288302, 'koKR', '', '빛을 향해 기도드렸고, 당신이 응답한 겁니다. 진정 광휘가 당신을 이끈 셈이지요.', 66384),
(288300, 'koKR', '', '싸움과 관련된 이야기는 하나도 없는가?', 66384),
(288299, 'koKR', '마음에 드는 이야기네요!', '', 66384),
(288298, 'koKR', '그게 바로 타우렌이 가장 멋진 바구니를 엮는 방법일세.', '', 66384),
(288293, 'koKR', '반갑습니다. 채광에 대한 지도가 필요하십니까?', '', 66384),
(288281, 'koKR', '빛이 우리와 함께합니다. 반드시 잘아타스를 막아내겠습니다!', '', 66384),
(288276, 'koKR', '', '우린 도움을 간절하게 기도했고, 태양샘은 응답했습니다. 이제 그 도움을 받을 자격이 있음을 증명해야 합니다.', 66384),
(288231, 'koKR', '적의 잔해를 움켜쥔 채, 웨이난은 동료들을 마법의 가루가 가득한 동굴로 이끌었다. 그곳에서 잔해를 엮어 부적으로 만들었고, 양손과 마음속에서 균형을 이루었다.', '', 66384),
(288223, 'koKR', '새겨두지 않은 교훈은 금방 잊히는 법. 그래서 웨이난은 쓰러뜨린 적의 잔해를 모아, 기억의 부적을 만들었다.', '', 66384),
(288222, 'koKR', '야수는 쓰러져 있었고, 곁에는 웨이난의 전우들이 죽어 있었다. 짐승의 발톱 때문이었는지, 웨이난이 저지른 일인지는 알 수 없었다. 분노가 감각을 마비시켰으나, 고향의 냄새가 웨이난을 심연에서 끌어냈다.', '', 66384),
(288221, 'koKR', '웨이난은 동족이 맞닥뜨린 전환점을 보았다. 사냥감이 사냥꾼이 되었지. 웨이난은 진실이 숨어 있는 고요한 동굴로 발걸음을 옮겼다.', '', 66384),
(288220, 'koKR', '이빨과 발톱이 덩굴과 가시에 맞서 부딪쳤고... 그 광란 속에서 하라니르는 광기의 낭떠러지에 매달렸다.', '', 66384),
(288219, 'koKR', '하라니르가 처음 이 땅을 걸었을 때, 하라니르를 맞이한 건 환대가 아니라 송곳니와 분노뿐이었다. 보이지 않는 의도로 덮쳐온 생명체들 때문이었지.', '', 66384),
(288215, 'koKR', '', '그냥 처리하자. 끝내버리게, 아자이.', 66384),
(288213, 'koKR', '가능한 한 많은 주민을 안전한 실버문으로 인도해야 하오. $p, 그대의 도움이 필요하오.', '', 66384),
(288210, 'koKR', '<루마가 온갖 잡동사니와 보물 더미 옆에 서 있습니다. 당신에게 보여주고 싶어 했던 게 바로 이것인 듯합니다.\n\n루마가 헉헉거리며 환하게 이를 드러내 웃습니다. 눈썹이 해가 뜬 듯 활짝 올라가 있습니다.\n\n당신을 바라보는 표정에서는 스스로가 무척 자랑스럽다는 기색이 역력합니다. 무엇이라도 말해주길 기대하는 듯합니다.>', '<루마가 온갖 잡동사니와 보물 더미 옆에 서 있습니다. 당신에게 보여주고 싶어 했던 게 바로 이것인 듯합니다.\n\n루마가 헉헉거리며 환하게 이를 드러내 웃습니다. 눈썹이 해가 뜬 듯 활짝 올라가 있습니다.\n\n당신을 바라보는 표정에서는 스스로가 무척 자랑스럽다는 기색이 역력합니다. 무엇이라도 말해주길 기대하는 듯합니다.>', 66384),
(288203, 'koKR', '마법 목걸이 하나 찾았어. 슬슬 빠져나가자.', '', 66384),
(288199, 'koKR', '이 장치로 비교적 안전하게 전황을 파악할 수 있을 겁니다.', '', 66384),
(288197, 'koKR', '', '마트리안은 이론을 그냥 넘어가는 법이 없었죠.', 66384),
(288196, 'koKR', '다시 만나서 반갑습니다, 용사님.', '', 66384),
(288194, 'koKR', '좋았어! 단추 누른다! 뒤로 물러서!', '', 66384),
(288193, 'koKR', '단추를 눌러요!', '단추를 눌러요!', 66384),
(288192, 'koKR', '해 봐요!', '해 봐요!', 66384),
(288189, 'koKR', '이게 아닌 것 같습니다. 다시 해보죠.', '', 66384),
(288187, 'koKR', '방금 그 괴물을 쓰러뜨릴 땐 안 보이던데요? 땅이나 뒤지고 있었습니까?', '', 66384),
(288186, 'koKR', '덩치 큰 고양이 한 마리에 도망치는 마법학자가 어디 있습니까? 당신 같은 낙제생이나 그렇겠죠...', '', 66384),
(288184, 'koKR', '레나 님은 군대를 이끌고 불타는 군단과 맞섰습니다. 그런데 왜 이런 게 성물로 선택된 걸까요?', '', 66384),
(288183, 'koKR', '마라 님의 영웅적인 행적은 은빛 성기사단의 창설에 영감을 주었습니다. 그런데 그분의 성물은 피난민의 기도가 담긴 책이군요.', '', 66384),
(288182, 'koKR', '마라아드 님은 전장에서의 맹활약으로 유명했습니다. 그런데 성물은 명상용 수정이라니.', '', 66384),
(288181, 'koKR', '크롬 님은 로데론의 백성을 지켜냈습니다. 한데, 그분의 성물은 무기가 아닌 대장장이 망치군요.', '', 66384),
(288180, 'koKR', '우서 님은 은빛 성기사단 최초이자 가장 위대한 성기사였습니다. 그분의 망치가 아니라 치료 도구가 남아 있다니 놀랍군요.', '', 66384),
(288172, 'koKR', '로스락시온, 날 모욕할 생각이면 최소한의 성의는 챙기지 그래.', '', 66384),
(288135, 'koKR', '방어구나 무기를 강화하고 싶으신가요? 저희 장인들이 도와드릴 수 있습니다.', '', 66384),
(288134, 'koKR', '저는 힘보다는 머리를 쓰는 쪽이라서요. 행운을 빕니다.', '', 66384),
(288133, 'koKR', '이번만큼은 저도 멜레도어의 말에 동의합니다. 죄송하지만, 저는 어느 쪽도 돕지 않겠습니다.', '', 66384),
(288131, 'koKR', '정말 최악의 하루네요...', '', 66384),
(288130, 'koKR', '이런 말도 안 되는...', '', 66384),
(288127, 'koKR', '', '옛 산악 야수의 후예는 극소수밖에 남지 않았네. 그래서 존중하는 게지. 하란다르에 온 걸 환영하네, 몬테. 내 동족을 보러 가세나.', 66384),
(288126, 'koKR', '설마 저 가시 곰 같은 녀석들이 더 있는 건 아니겠지?', '', 66384),
(288125, 'koKR', '빨리 오르웨냐 불러와! 난 여기 있어도 괜찮아. 이 동물, 은근히 괜찮아. 털은 가시 같고... 곰처럼 생기긴 했지만.', '', 66384),
(288124, 'koKR', '어후! 이제 숨통 좀 트이네. 도와줘서 고마워.', '', 66384),
(288104, 'koKR', '언더마인에서 신세를 졌으니, 이번엔 내가 오르웨냐 고향에 한번 들러볼까 했거든.\n\n근데 정문을 넘기 전부터 막혔다고 해야 하나. 이런 일쯤은 익숙할 법도 한데, 아니더라. 몸 좀 비틀면 저 야수가 으르렁거리기 시작해.\n\n그러니까 얌전히 여기 붙어 있으면서 오르웨냐가 어떤 좋은 생각을 가져올지 두고 보려고.', '', 66384),
(288101, 'koKR', '이봐, 친구! 그냥 대롱대롱 매달려 있으면서 반가운 얼굴 안 보이나 기다리고 있었지.\n\n<가즈로가 다소 과장된 미소를 지어 보입니다. 뭔가 불편해 보입니다.>', '', 66384),
(288100, 'koKR', '', '가즈로가 내 고향을 보러 왔다고? 진작 문제에 휘말릴 줄 알았는데, 생각보다 훨씬 멀리 왔구먼.', 66384),
(288097, 'koKR', '', '그래, 무슨 일이 있었나?', 66384),
(288075, 'koKR', '정확히 말하자면 아니오. 다만, 이곳에서 가장 많은 시간을 보낸 자일 수는 있겠지.\n\n아르칸티나는 내가 오기 전, 어느 키린 토 마법사가 만든 곳이오.\n\n그러나 나와 로서의 후예들은 강행군의 연속이었던 드레노어 원정 당시 안전한 이곳에서 휴식을 취하곤 했다오.\n\n세월이 흐르며 점점 더 많은 사람이 스스로 찾아오거나 초대를 받아 왔고, 이제는 오랜 동지들과 역전의 용사들이 모이는 마법 피난처가 되었소.', '', 66384),
(288073, 'koKR', '아. 반갑소, $p. 아르칸티나를 감상한 소감은 어떻소?', '', 66384),
(288072, 'koKR', '솔직히, 아라토르 자네에게 이곳을 보여 주고 싶다는 생각을 오래전부터 해왔네. 드디어 기회가 와서 기쁘군.', '', 66384),
(288054, 'koKR', '황혼의 칼날단이라니. 설마 영원노래 숲에도 숨어들 줄은 몰랐습니다. 좌시하지 않겠습니다.\n\n저지른 만행에 대한 대가를 치르게 하겠습니다.', '', 66384),
(288053, 'koKR', '눈먼 얼간이들 같으니...', '', 66384),
(288052, 'koKR', '실버문이 우릴 도와준 적이라도 있나? 없다!', '', 66384),
(288051, 'koKR', '', '내가... 옳았던... 건가...?', 66384),
(288050, 'koKR', '', '공허가 우리를 구원하리라!', 66384),
(288014, 'koKR', '토르톨란들은 장황하게 이야기를 늘어놓더군. 차라리 결투를 했으면 좋겠어.', '토르톨란들은 장황하게 이야기를 늘어놓더군. 차라리 결투를 했으면 좋겠어.', 66384),
(288013, 'koKR', '어떻게 말만으로 이야기를 전할 수 있겠어? 행동으로 보여줘야지!', '어떻게 말만으로 이야기를 전할 수 있겠어? 행동으로 보여줘야지!', 66384),
(288012, 'koKR', '여관주인의 술은 마셔 봤냐? 엄니에 감각이 안 느껴져.', '여관주인의 술은 마셔 봤냐? 엄니에 감각이 안 느껴져.', 66384),
(288011, 'koKR', '바쁜 거 안 보이나, $c 친구?', '바쁜 거 안 보이나, $c 친구?', 66384),
(288010, 'koKR', '토르톨란은 처음 봐. 왜 우리를 알고 싶어 하지?', '토르톨란은 처음 봐. 왜 우리를 알고 싶어 하지?', 66384),
(288009, 'koKR', '크리캐쉬가 이야기를 해 달라더군. 그런데 끝까지 말도 못 하게 했어. 내가 검을 놈의 목에 대고 있었는데도!', '크리캐쉬가 이야기를 해 달라더군. 그런데 끝까지 말도 못 하게 했어. 내가 검을 놈의 목에 대고 있었는데도!', 66384),
(288007, 'koKR', '이야기를 듣고 싶으면 싸울 준비부터 해라. 우린 대충 하는 법이 없으니까.', '이야기를 듣고 싶으면 싸울 준비부터 해라. 우린 대충 하는 법이 없으니까.', 66384),
(288006, 'koKR', '필요한 거라도?', '필요한 거라도?', 66384),
(287985, 'koKR', '', '쓴맛을 견딜 수 있긴 해야 하네만, 물속에서 자라는 심연풀을 먹으면 숨을 오래 참는 데 도움이 된다네.', 66384),
(287981, 'koKR', '스테기가 안전한 곳으로 도망칩니다.', '스테기가 안전한 곳으로 도망칩니다.', 66384),
(287980, 'koKR', '스테기는 온몸이 파래요. 구슈처럼요! 그런데 아주 작아요. 배불리 먹어야 하니, 먹이를 찾아주세요!', '', 66384),
(287954, 'koKR', '', '너도 훌륭히 잘 싸우고 있다. 너무 서두르지만 마.', 66384),
(287953, 'koKR', '어머니의 전설에는 거짓 하나 없었군요.', '', 66384),
(287939, 'koKR', '', '우린 아무것도 해결하지 못했네. 이 루타니들은 변해버렸어. 하란다르로 돌아가 조사해야 하네.', 66384),
(287936, 'koKR', '용사님, 엄브릭을 찾으십시오. 전 이곳을 지키겠습니다.', '', 66384),
(287916, 'koKR', '따라오세요!', '', 66384),
(287915, 'koKR', '서둘러요! 얼른 똥개를 쫓아가세요!', '', 66384),
(287914, 'koKR', '...일지가요?!', '', 66384),
(287913, 'koKR', '저건...', '', 66384),
(287912, 'koKR', '이렇게 허상만 좇지 말고, 단서 하나라도 제대로 있었으면 좋겠군요...', '', 66384),
(287911, 'koKR', '대단하네요. 어쩌면 일지가 다리를 달고 걸어 나갔을지도 모르죠!', '', 66384),
(287902, 'koKR', '아버지가 활약하기 시작했던 시절을 직접 보면서 많은 생각이 들었습니다, $p 님.\n\n저는 예전의 아버지를 닮은 성기사가 되고 싶습니다. 그 이후가 아니라요.\n\n도와주시겠습니까?', '', 66384),
(287890, 'koKR', '이 초창기의 아버지는 제가 아는 사람과는 완전히 다르게 묘사되어 있습니다, $p 님.', '', 66384),
(287883, 'koKR', '', '다른 부족들이 왜 북소리에 응하지 않은 거지?', 66384),
(287874, 'koKR', '나, 나는 수련 중인 탐구자일세! 첫 두루마리를 얻기 위해 커다란 요리책을 만들고 있지.', '', 66384),
(287873, 'koKR', '', '우리... 요리 말인가? 왜 묻는 게지?', 66384),
(287872, 'koKR', '훌륭하네. 이제 서로 알게 되었으니, 탐구자 구슈가 자네들 요리에 대해 물어볼 걸세.', '', 66384),
(287871, 'koKR', '', '아버지가 머물러도 된다고 하시면, 여기서 야영할 수 있게 해주겠네. 내 감독을 받게 될 걸세.', 66384),
(287868, 'koKR', '그럴 리 없네, 젊은이. 차분하게 기다리겠네.', '', 66384),
(287867, 'koKR', '', '$p 님이 와주셔서 정말 다행이에요. 아이를 안전한 곳으로 데려가야 해요!', 66384),
(287866, 'koKR', '', '꼼짝 마라!', 66384),
(287865, 'koKR', '마른나무껍질 장로 렌젠을 찾아가 보게. 분명 오해가 있을 걸세.', '', 66384),
(287864, 'koKR', '', '편지라니? 장로들은 큰 등딱지를 짊어진 침입자들을 들여보낸다고 말한 적 없네. 어서 떠나게!', 66384),
(287863, 'koKR', '당황하지 말게, 친구들. 이곳 유물 연구를 허락하는 자네들 장로의 서한이 있네.', '', 66384),
(287858, 'koKR', '장로 레센이 웃음을 터뜨립니다.', '장로 레센이 웃음을 터뜨립니다.', 66384),
(287857, 'koKR', '', '건방진 것! 다른 놈들처럼 피를 쏟게 만들어 주마.', 66384),
(287854, 'koKR', '필멸자 구세주가 이곳에? 그럼 희망이 없는 건 아니군.', '필멸자 구세주가 이곳에? 그럼 희망이 없는 건 아니군.', 66384),
(287852, 'koKR', '토르톨란은 당분간 머물러도 되네. 나만큼 고집 센 자는 드물지!', '토르톨란은 당분간 머물러도 되네. 나만큼 고집 센 자는 드물지!', 66384),
(287851, 'koKR', '이런 걸 원했단 말이야, 살라다르?', '이런 걸 원했단 말이야, 살라다르?', 66384),
(287848, 'koKR', '공허는 동족마저 포식하지. 우리에겐 남은 게 없어.', '공허는 동족마저 포식하지. 우리에겐 남은 게 없어.', 66384),
(287847, 'koKR', '토르톨란의 말이 진심이었다고? 정말 얼굴을 내밀었단 말인가?\n\n<호탕하게 웃는 장로 렌젠>\n\n편지를 그렇게도 보냈으니! 정작 난 무시로 일관했지만. 그러다 결국 친구에게 허락만 기다리지 말고 하고 싶은 걸 하라고 했네. 기다리겠다고 하더니!\n\n어찌 거절하겠나? 그래서 \"허락 편지\"를 보냈네. 몇 년 동안 한 번도 주지 않았던 건데!\n\n결정을 존중하겠네. 자고로 탐구자는 스스로 원하는 길을 갈 자유가 있지. 어차피 마른나무껍질이 토르톨란 손님들을 지켜볼 게야. 이 땅을 찾은 방문객한테는 다 그렇게 하고 있으니.', '토르톨란의 말이 진심이었다고? 정말 얼굴을 내밀었단 말인가?\n\n<호탕하게 웃는 장로 렌젠>\n\n편지를 그렇게도 보냈으니! 정작 난 무시로 일관했지만. 그러다 결국 친구에게 허락만 기다리지 말고 하고 싶은 걸 하라고 했네. 기다리겠다고 하더니!\n\n어찌 거절하겠나? 그래서 \"허락 편지\"를 보냈네. 몇 년 동안 한 번도 주지 않았던 건데!\n\n결정을 존중하겠네. 자고로 탐구자는 스스로 원하는 길을 갈 자유가 있지. 어차피 마른나무껍질이 토르톨란 손님들을 지켜볼 게야. 이 땅을 찾은 방문객한테는 다 그렇게 하고 있으니.', 66384),
(287845, 'koKR', '도울 일이라도 있나, $c 친구?', '도울 일이라도 있나, $c 친구?', 66384),
(287833, 'koKR', '고킨예를, 저 침략자들을 아탈아만에서 싸우게 하겠다고?', '', 66384),
(287831, 'koKR', '', '우린 도시를 지킬 전사가 필요해. 도와줄 이들이 어디 또 있단 말이냐, 잔?', 66384),
(287826, 'koKR', '', '난 성물회와 함께 적진 깊은 곳으로 들어갈 거야. 필요한 거라도 있어?', 66384),
(287808, 'koKR', '맛있군. 이제 견장을 손에 넣기까지 절반 왔다.', '', 66384),
(287807, 'koKR', '집어삼켜라. 토렌티아의 권위를 네 것으로 삼아라.', '', 66384),
(287701, 'koKR', '', '줄아만으로 통행을 허락해 주십시오! 황혼의 무리가 국경 가까이 집결하고 있는데, 손 놓고 있을 수는 없습니다!', 66384),
(287693, 'koKR', '', '빛만개는 살상을 일삼고, 또다시 자라난다네. 이런 흉악한 악순환은 반드시 끊어내야 해.', 66384),
(287692, 'koKR', '', '지켜줄 인원이 없으면 마법석조차 빛만개의 쇄도는 막지 못하는 것 같구먼.', 66384),
(287691, 'koKR', '', '이 식물들의 성장은 강제로 이루어진 걸세. 무엇 때문인지는 아직 알 수 없지만 말이야.', 66384),
(287605, 'koKR', '', '차나가 머뭇거립니다.', 66384),
(287604, 'koKR', '', '그래. 나도 가지.', 66384),
(287603, 'koKR', '게다가 네 조카의 첫 사냥이기도 하지.', '', 66384),
(287602, 'koKR', '가족 사냥이잖아. 너도 가족이고.', '', 66384),
(287601, 'koKR', '', '내가 가도 환영받을까?', 66384),
(287600, 'koKR', '다음 달에 사냥을 주관할 생각이네. 혹시 함께할 수 있겠나?', '', 66384),
(287599, 'koKR', '', '도움을 청할 기회를 주지 못해 미안해.', 66384),
(287598, 'koKR', '어머니 곁에 두고 떠나서 미안해.', '', 66384),
(287597, 'koKR', '', '이제 살아 있을 때 말하지 못한 후회들을 고백해야 해.', 66384),
(287596, 'koKR', '', '애초에 내 말을 믿지도 않았어.', 66384),
(287595, 'koKR', '사람들한테 한 번도 말하지 않았지?', '', 66384),
(287594, 'koKR', '', '부족은 아직도 그분을 사랑하니까.', 66384),
(287593, 'koKR', '우리가 왜 어머니를 기려야 해?', '', 66384),
(287592, 'koKR', '', '위로를 빙자한 거짓말뿐.', 66384),
(287591, 'koKR', '어머니가... 마지막으로 남기신 말은 있었어?', '', 66384),
(287590, 'koKR', '', '병에 걸리셨지. 끝이 올 거라는 건 알고 있었어. 문제는 언제냐 하는 것뿐이었고.', 66384),
(287589, 'koKR', '그분은 어떻게 가셨어?', '', 66384),
(287588, 'koKR', '', '아니. 어머니가 더 이상 네게 손을 뻗을 수 없게 됐으니까.', 66384),
(287587, 'koKR', '더 이상 내 잘못을 대신 떠안지 않아도 돼서?', '', 66384),
(287586, 'koKR', '', '아니. 더 나빠졌어. 근데 솔직히... 네가 우리 곁을 떠났을 때 난 오히려 기뻤어.', 66384),
(287585, 'koKR', '내가 떠난 뒤에, 어머니는 좀 나아졌나?', '', 66384),
(287584, 'koKR', '좋아. 사실 꽤 괜찮은 생활을 하고 있어.', '', 66384),
(287583, 'koKR', '', '숲속에서의 삶은 어때?', 66384),
(287582, 'koKR', '', '그래도 난 널 구하다 얻은 상처 하나하나를 자랑으로 여기고 있어.', 66384),
(287581, 'koKR', '', '아니.', 66384),
(287580, 'koKR', '내 잘못 때문에 네가 벌받을 때, 내가 얼마나 죄책감을 느꼈는지 생각해 본 적 있어?', '', 66384),
(287579, 'koKR', '', '너는 내 동생이잖아. 널 지키는 게 내 의무였어.', 66384),
(287578, 'koKR', '너도 마찬가지였고.', '', 66384),
(287577, 'koKR', '변하지 않는 것들도 있으니까...', '', 66384),
(287576, 'koKR', '', '이즈켄, 포자 딸 때 멧돼지를 자극하지 않게 조심해.', 66384),
(287533, 'koKR', '아윽. 하. 하하하.', '', 66384),
(287532, 'koKR', '오호. 이건 꽤 흥미롭군.', '', 66384),
(287531, 'koKR', '그만해라, 그만. 그런 모습을 보고도 어찌 널 거절하겠나?', '', 66384),
(287530, 'koKR', '이 땅에서는 자비로 살아남지 못해. 그래도 네 선의는 받아들이지.', '', 66384),
(287529, 'koKR', '그래, 어디 한번 해보자.', '', 66384),
(287511, 'koKR', '도와주려고? 아니면 우리가 서로 죽고 죽이지 않게 말리려고?', '', 66384),
(287510, 'koKR', '', '네가 올 줄은 몰랐어. 녀석들이 의식을 돕겠다고 왔거든.', 66384),
(287509, 'koKR', '어머니가 돌아가셨다고 들었어. 이 $rl|1은;는; 누구지?', '', 66384),
(287508, 'koKR', '', '동생아, 너냐?', 66384),
(287491, 'koKR', '바다가 우리 흔적을 지워 줄 거다.', '바다가 우리 흔적을 지워 줄 거다.', 66384),
(287490, 'koKR', '그래, 심연 속으로 보내라.', '그래, 심연 속으로 보내라.', 66384),
(287489, 'koKR', '당장 바다에 던져라. 들키는 위험을 감수할 수 없다.', '당장 바다에 던져라. 들키는 위험을 감수할 수 없다.', 66384),
(287472, 'koKR', '맞아. 질질 끌면 서로 손해지.', '맞아. 질질 끌면 서로 손해지.', 66384),
(287464, 'koKR', '누가 캐묻기 시작하면 화물이 바로 사라지는 것도 참 웃기지.', '누가 캐묻기 시작하면 화물이 바로 사라지는 것도 참 웃기지.', 66384),
(287462, 'koKR', '음. 우리가 뒷담의 대상이 되는 건 좀 별로거든.', '음. 우리가 뒷담의 대상이 되는 건 좀 별로거든.', 66384),
(287446, 'koKR', '이곳의 오크와 오우거들은 오래전부터 골칫거리였다네, $p.', '', 66384),
(287438, 'koKR', '뭘 가져왔지?', '', 66384),
(287422, 'koKR', '', '흠. 태양샘이 저 휘몰아치는 회오리를 향해 폭발했을 때인가? ...죄송합니다. 제가 지금 좀 감정이 벅찬 상태라.', 66384),
(287411, 'koKR', '이 수수께끼야말로 우리가 빠져나갈 열쇠일 겁니다.', '', 66384),
(287408, 'koKR', '하라티가 도착하기 전까지만 해도, 우리는 피해를 줄이는 데 만족할 수밖에 없었소. 숲은 결국 파괴됐을 테지.\n\n하지만 이제 하라니르가 본격적으로 모습을 드러냈고, 알른의 마법까지 더해졌으니... 광란을 몰아낼 가능성이 생겼소.', '', 66384),
(287406, 'koKR', '', '의회는 우리의 요청을 거부했네. 하라티는 빛만개에 맞설 뜻이 없어.\n\n하지만 난 아니야. 알른가루가 있는 한 조금이라도 그 영향력을 막아 보겠네.', 66384),
(287405, 'koKR', '아주 화려한 난장판을 만들어 놨군.', '', 66384),
(287402, 'koKR', '뭘 쳐다봐?', '뭘 쳐다봐?', 66384),
(287380, 'koKR', '', '용사. 로르테마르가 보냈어. 쥐를 쫓는 데 도움이 필요하다며?', 66384),
(287371, 'koKR', '공허 표본이군요! 다른 것들도 있는지 확인해 보십시오.', '', 66384),
(287367, 'koKR', '안테노리안 총독이 먼저 접촉해 왔고, 공허폭풍을 연구할 공간을 제공해 주겠다고 했습니다.\n\n그래도 심각성을 이해하는 사람이 조금이라도 있어서 다행이지요. 이 위기는 모두에게 위협이 됩니다.', '', 66384),
(287333, 'koKR', '용사, 청소와 운반을 도와주시오. 아라토르에게는 달리 일손이 더 필요한 일을 맡기겠소.', '', 66384),
(287332, 'koKR', '이만 실례하겠네. 아이트리그를 찾아야 하거든. 준비할 일이 좀 있어.', '', 66384),
(287330, 'koKR', '', '이제 충분히 봤어요, 마트리안. 이런 방식은 도를 넘어섰어요.', 66384),
(287329, 'koKR', '', '이 해안을 더럽힌 무리가 누군지 알아보고, 다 끝나면 여기로 돌아오세요.', 66384),
(287294, 'koKR', '', '더 많은 렌도레이가 같은 운명을 맞기 전에, 엄브릭 님에게 알리러 가야 해요. 쇼렐러란.', 66384),
(287293, 'koKR', '', '이 연구로 최악의 상황에 대비할 수 있어야 했는데... 도와줘서 고마워요, $n 님.', 66384),
(287292, 'koKR', '', '이 사실을 장로들에게 알려야 하네. 바람과 함께 가게나!', 66384),
(287291, 'koKR', '', '이 광경을 보니 마음이 아프군. 아름답던 고향이, 사라지다니...', 66384),
(287290, 'koKR', '', '광기가 뿌리를 집어삼켰네. 여기서 막아야 하네.', 66384),
(287279, 'koKR', '여신은 요람을 떠났지만, 영향력은 여전히 남아 있네. 알른의 균열은 하라니르가 들어가기엔 너무 위험한 곳이야.\n\n나는 여신을 섬기고자 여신과의 유대를 끊었네. 내 조언을 귀담아듣는 게 좋을 걸세. 저 아래 균열에서 빠른 최후를 맞고 싶은 게 아니라면 말이지.', '', 66384),
(287263, 'koKR', '그럼 파괴하면 되겠군. 폭탄은 에테리얼에게서 조달하면 돼.', '', 66384),
(287257, 'koKR', '제가 어리석었어요. 당신들도 우리처럼 똑같은 사람들이었어요. 그날 밤 공격한 건 황혼의 칼날단이었어요!', '', 66384),
(287244, 'koKR', '바로 눈앞이었습니다. 카시에아가... 남긴 기록에 따르면 공허폭풍에서 무언가를 끌어오려 했습니다. 저는 그 경로를 거꾸로 되돌려 우리 쪽에서 들어갈 수 있지 않을까 했지만, 책장이 완전하지 않았습니다. 빠진 게 너무 많아요.\n\n그 누락된 책장들... 누가 훔쳐 갔는지 짐작은 갑니다.', '', 66384),
(287238, 'koKR', '우리가 최상위 포식자다. 우리가 곧 공허다!', '', 66384),
(287230, 'koKR', '피...\n\n공허...\n\n최상위 포식자...\n\n모든 게 어떻게 맞물리는지 알겠습니다. 이제 우리의 목적을 알겠어요.', '', 66384),
(287227, 'koKR', '바람이 힘을 약속하며 속삭이는군요.\n\n저는 이런 제안을 거절해 본 적 없습니다.', '', 66384),
(287179, 'koKR', '증원은 저희가 막겠습니다. 발리라 님과 함께 가십시오!', '', 66384),
(287177, 'koKR', '용사님을 믿겠습니다. 안테노리안을 찾아 필요한 정보를 확보하고, 놈을 쓰러뜨려 주십시오.', '', 66384),
(287172, 'koKR', '카시에아의 연구가 실버문을 돕는 첫걸음이 될 겁니다. 안테노리안이 뜯어간 책장이 바로 그 실마리입니다. 제 목숨을 걸고 단언합니다.', '', 66384),
(287171, 'koKR', '화염의 날개가 다시 날아올랐네!\n\n잔알라이가 하늘을 가르며, 수년 만에 처음으로 우리의 가슴에 온기를 불어넣었네. 그 불씨가 아마니의 무기와 함께 어둠에 삼켜진 적의 심장을 꿰뚫으리!', '', 66384),
(287170, 'koKR', '다시 만나 뵙게 되어 반갑습니다, $p 님.\n\n스라소니 로아, 할라지께서 장로들께 용사님의 이야기를 전하셨습니다. 제국의 유산을 위해 다시 창을 들 기회를 얻게 되어 감사할 따름입니다.', '', 66384),
(287169, 'koKR', '', '나는 펠나. 톤터스크의 칭호를 짊어진 자이자, 깨진엄니 부족의 전사다.\n\n지난 세월 무슨 일이 있었든 간에, 우리 마음의 고향이 줄아만이란 사실은 변하지 않는다.\n\n우리의 고향을 위해 싸우러 왔다!', 66384),
(287165, 'koKR', '이 둥지... 빛만개 성장물에 뒤덮여 숨을 쉬지 못하고 있습니다. 정리해 줍시다.', '', 66384),
(287164, 'koKR', '윽! 모습도, 냄새도... 지역 동물들이 영역 표시를 한 것 같습니다. 그만큼 불안하다는 증거겠지요.', '', 66384),
(287163, 'koKR', '덤불이 짓밟혔군요. 가엾은 야생동물들이 두려움에 떨고 있겠습니다.', '', 66384),
(287076, 'koKR', '아니. 나는 그렇게 행동하는 루타니를 본 적 없다.', '', 66384),
(287049, 'koKR', '그렇게 부적이 만들어졌다. 경고였고, 다짐이었지. 본능만으로는 안 된다는 걸 잊지 않기 위해서였다.', '', 66384),
(287038, 'koKR', '', '영원노래 숲의 빛이 하란다르에 그런 재앙을 불러올 줄이야.', 66384),
(287033, 'koKR', '안 돼! 거의 다 됐는데...!', '', 66384),
(287028, 'koKR', '용사님! 공허의 조각을 중앙 차원문으로 가져가십시오. 제 예상이 맞다면 경로가 뒤집히면서 공허폭풍으로 통하는 길이 열릴 겁니다.', '', 66384),
(287027, 'koKR', '이 오래된 피조물을 손봐서 이교도들을 쓰러뜨립시다.', '', 66384),
(287026, 'koKR', '마지막으로 카시에아의 기록을 해독해 보겠습니다. 공허폭풍의 실마리를 풀 열쇠가 될지도 모릅니다.', '', 66384),
(287024, 'koKR', '도망치는 거냐? 겁쟁이. 승리가 목전이었는데!', '', 66384),
(287005, 'koKR', '이 벽에는 우리 종족의 기억과 경험, 지혜가 깃들어 있다.\n\n준비가 되면 벽화를 만져라.', '', 66384),
(287004, 'koKR', '그림에 손을 대라. 그림에 깃든 알른가루가 우리의 진실을 드러낼 거다.', '', 66384),
(287003, 'koKR', '', '알른하라가 인도하기를. 행운을 비네.', 66384),
(286998, 'koKR', '이 영원노래 숲 지도에 황혼의 칼날단의 목표가 표시되어 있습니다. 윈드러너 마을까지 노리고 있더군요!', '', 66384),
(286970, 'koKR', '', '장로들이 결론을 내렸네. 과거를 되새기면서 자네의 행동이 얼마나 어리석었는지 깨달으라고 하더군.', 66384),
(286969, 'koKR', '누가 진짜 적인지 깨닫게 해줘서 고마워요. 그리고 행동하기 전에 생각해야 한다는 것도요.', '', 66384),
(286961, 'koKR', '당장 소굴로 가라! 의회가 처분을 결정할 거다.', '', 66384),
(286957, 'koKR', '놀랍군. 용사, 와서 보시오.', '', 66384),
(286956, 'koKR', '실로 놀랍군. 뿌릿길의 끝에 완전한 세계가 있다니. 하란다르가 영겁의 세월 동안 모습을 감춰왔다는 사실 자체가 경이롭소.\n\n지금은 빛만개에 집중해야 하지만, 하라니르와 이 땅에 대해 더 알아가고 싶다는 마음이 드는 것도 부정할 수 없구려.', '', 66384),
(286955, 'koKR', '오르웨냐는 지나치게 성급하고 무모하오. 하지만 이젠 하란다르 밖의 세상을 겪어 봤으니 그 점을 인정할 테지.\n\n안타깝게도 장로들이 지나치게 신중하게 나올 수도 있지만.', '', 66384),
(286895, 'koKR', '호드는 이미 오래전에 어두운 과거를 벗어났네. 모두가 함께했다면 얼마나 좋았겠나.', '', 66384),
(286884, 'koKR', '', '따라와라, 엘프. 가까이 가서 주의를 끌자.', 66384),
(286883, 'koKR', '이리 와라! 내가 화살을 장전할 테니, 어서 발사해.', '', 66384),
(286878, 'koKR', '여관에 모이세요. 거긴 안전해요!', '', 66384),
(286838, 'koKR', '', '용사님, 잘아타스와 포식의 군단이 태양샘을 포위했습니다. 당신은 빛의 선택을 받아 이곳을 지키러 오게 된 겁니다.', 66384),
(286837, 'koKR', '쳇. 암흑 호드라니. 4차 대전쟁 때 평화를 맺었는데, 저것들은 아직도 2차 대전쟁의 망령을 붙잡고 있어. 시대에 맞춰 살아야지!', '', 66384),
(286836, 'koKR', '가세, 쿠르드란. 다른 암흑 호드 진지를 정찰하세.', '', 66384),
(286828, 'koKR', '오르웨냐 님은 본인 생각 이상으로 더 많은 이들에게 신뢰받고 있다. 난 그분이 어딜 가든 따를 거야.', '오르웨냐 님은 본인 생각 이상으로 더 많은 이들에게 신뢰받고 있다. 난 그분이 어딜 가든 따를 거야.', 66384),
(286827, 'koKR', '난 싸울 준비가 됐다! 사랑하는 하란다르를 더럽히게 두지 않겠어.', '난 싸울 준비가 됐다! 사랑하는 하란다르를 더럽히게 두지 않겠어.', 66384),
(286826, 'koKR', '모두 생태계를 위해 각자의 몫을 해야 해.', '모두 생태계를 위해 각자의 몫을 해야 해.', 66384),
(286825, 'koKR', '이 괴이한 빛만개는 어쩌다 이렇게 우리 땅에 퍼진 거지? 하란다르에 있으면 늘 안전할 줄 알았는데.', '이 괴이한 빛만개는 어쩌다 이렇게 우리 땅에 퍼진 거지? 하란다르에 있으면 늘 안전할 줄 알았는데.', 66384),
(286824, 'koKR', '가엾은 루타니들처럼 고향에서 쫓겨나면 정말 끔찍할 거야. 저들을 돕고 싶군.', '가엾은 루타니들처럼 고향에서 쫓겨나면 정말 끔찍할 거야. 저들을 돕고 싶군.', 66384),
(286813, 'koKR', '자리를 비켜주든가, 아니면 도끼를 들고 일손이라도 보태게나.', '', 66384),
(286811, 'koKR', '그 아이는 시련을 통해 단련될 걸세. 필요한 과정이야.\n\n다만, 그 과정에서 진짜 죽어버리진 않게 자네가 좀 챙겨주게. 참 어리석은 녀석이라니까...', '', 66384),
(286809, 'koKR', '전 복수를 하러 왔어요.\n\n그런데 여기서, 내가 몰랐던 답을 찾았네요.\n\n고마워요, $n 님. 당신이 아니었다면 내 어리석음 때문에 죽었을지도 몰라요.', '', 66384),
(286808, 'koKR', '<피투성이에 온몸이 멍든 채, 희미하게 신음하며 간신히 의식을 붙잡고 있는 켈러>', '', 66384),
(286807, 'koKR', '절... 절 구하러 온 건가요? 그 늙은 목각가가 보냈나 보군요...', '', 66384),
(286804, 'koKR', '', '나는 깨어났다. 더 이상 변하지 않는다.', 66384),
(286750, 'koKR', '금고에는 뭐가 들어 있었습니까?', '', 66384),
(286749, 'koKR', '구할 수 있는 자들은 구했지만, 제 연구 자료가...', '', 66384),
(286748, 'koKR', '여태껏 안테노리안이 두 발 앞서 움직이고 있었습니다. 제 연구실로 돌아갑시다.', '', 66384),
(286745, 'koKR', '', '이렇게나 쉽게 속다니!', 66384),
(286743, 'koKR', '무사하셨군요! 엄브릭을 보셨습니까?', '', 66384),
(286740, 'koKR', '주민들을 돌보십시오. 전 안테노리안을 찾아내... 반드시 대가를 치르게 하겠습니다.', '', 66384),
(286739, 'koKR', '이교도들이 마을을 점령하게 두면 안 됩니다!', '', 66384),
(286725, 'koKR', '이 빛만개에 많은 동족을 잃었다. 저들이 희망을 전하러 온 거라면 들을 용의가 있다.', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(286708, 'koKR', '', '왔구먼. 불행히도 우려가 사실로 드러났네.', 66384),
(286702, 'koKR', '', '하르마라에 온 걸 환영하네. 나도 한때는 텔드랏실의 뿌리감시관으로 이곳에서 살았지만, 그 시절은 지나갔지.', 66384),
(286700, 'koKR', '', '알른가루일세. 어쩌면 그게 에온카를 빛만개로부터 지켜준 걸지도 모르겠군.', 66384),
(286699, 'koKR', '이 씨앗... 무언가로 뒤덮여 있는데...', '', 66384),
(286698, 'koKR', '', '우리는 이곳에 남아 하가르와 다른 이들을 보호하겠네.', 66384),
(286695, 'koKR', '', '썩은 성장물을 많이 솎아 냈군. 하르알노어에서 온 잡초들이 땅의 먹이가 되고 있다.\n\n전투가 끝난 거면 좋겠군.', 66384),
(286693, 'koKR', '여신이시여...', '', 66384),
(286681, 'koKR', '줄잔은 제 검 아래 쓰러질 것입니다!', '', 66384),
(286677, 'koKR', '', '빛만개는 태양샘이 다시 불타오른 뒤 얼마 지나지 않아 나타났습니다. 처음엔 여기저기 특이한 식물이 조금씩 자라나는 정도였기에 별다른 걱정거리는 아니라고 여겼죠. 태양샘을 통해 우리에게 스며든 성스러운 빛이 숲의 식물에도 깃든 듯 보였고, 실로 흥미로웠습니다.\n\n우리는 예로부터 숲을 뜻대로 다듬고 조형해 왔지만, 빛만개는 그렇지가 않습니다. 훨씬 거칠고, 고집스럽고, 마치 의지를 가진 생명체처럼 말을 듣지 않습니다... 물론 우스운 생각이긴 하지만요. 고작 식물일 뿐인데 생각이 있을 리 없잖아요.', 66384),
(286666, 'koKR', '', '산들바람 마을에 오신 걸 환영합니다.', 66384),
(286656, 'koKR', '내가 하르알노어에 도착한 건 당신보다 조금 앞선 시점이었소. 확실히 심각한 문제가 있군. 주변의 고통을 덜어내려면 다들 할 일이 많겠소.\n\n어쩌다 이렇게 된 건지.', '', 66384),
(286645, 'koKR', '', '툴아마르.\n\n<툴아마르가 자기 자신을 가리킵니다.>\n\n내가 한 일이다. 형제자매들은 무사하다. 집으로 돌아가라.', 66384),
(286641, 'koKR', '알른가루를 집어들어라, $p. 서둘러라.', '', 66384),
(286640, 'koKR', '안 돼... 분노에... 삼켜졌었어. 다시는... 그렇게 되지 않을 거야.', '안 돼... 분노에... 삼켜졌었어. 다시는... 그렇게 되지 않을 거야.', 66384),
(286632, 'koKR', '빛을 깃들게 하고, 용매의 재 기름을 써서 보존하게.', '', 66384),
(286612, 'koKR', '', '나는 수많은 만개를 지켜봐 왔다. 만개는 좋은 것이지. 안 그런가?', 66384),
(286595, 'koKR', '', '의식을 시작하면 잘아타스가 이 입구로 병력을 보낼 겁니다.\n\n의식이 끝날 때까지 적을 막아 주셔야 합니다.', 66384),
(286594, 'koKR', '저 공허 마법 망토들... 전에 본 적 있어요!', '', 66384),
(286593, 'koKR', '', '우리는 아마니를 버린 게 아니다. 아마니가 우리를 배신했지.\n\n사술군주 말라크라스가 전쟁군주 줄진에게 어떤 수를 써서라도 강력한 전사를 만들자고 설득했거든.\n\n우리의 힘을 흡수해 네 명의 아마니 화신에게 주입하는 불경한 방법을 찾아낸 것이야. 고킨예는 너처럼 둘을 막아섰다. 화신들과 말라크라스, 줄진을 모두 응징했지.\n\n그 후 난 사원을 버렸다. 할라지는 안개 속으로 숨어 들어가 치유에 전념했고, 잔알라이가 가장 큰 고통을 받았지. 말라크라스에게 불꽃이 꺼뜨려지고 흡수까지 당했으니까. 날로라크는 분노 그 자체가 되는 바람에, 산속에서 깊은 동면에 들어가서야 겨우 진정할 수 있었다.\n\n줄자라가 하셰이가 되어 황혼의 칼날단을 파괴하고 싶다고 했나? 그렇다면 우리 모두의 축복이 필요할 것이니라.\n\n로아와 아마니 사이의 유대를 다시 회복해야 한다.', 66384),
(286591, 'koKR', '', '아마니는 내 자식이나 다름없다. 하지만 자식이란 가끔 그릇된 길로 빠지기도 하지.', 66384),
(286576, 'koKR', '세계수의 뿌리 한가운데에 한 세상이 숨어 있을 줄 누가 알았겠소. 실로 경이롭군.', '', 66384),
(286565, 'koKR', '', '이런! 공허에 삼켜졌어요!', 66384),
(286561, 'koKR', '', '이 야수를 쫓는 데 너무 많은 시간을 허비했어요, 마트리안. 돌아가 보고해야 해요.', 66384),
(286527, 'koKR', '어둠이... 너희를 데려가리라...', '', 66384),
(286526, 'koKR', '훌륭합니다. 잠깐, 저기 반짝이는 건 뭐죠?', '', 66384),
(286525, 'koKR', '제 공허폭풍 연구 자료를... 황혼의 칼날단이 모조리 훔쳐 갔습니다!', '', 66384),
(286517, 'koKR', '꽤 긴 여정이었구먼, $p. 한 번 더 나설 준비는 됐는가?', '', 66384),
(286516, 'koKR', '고맙습니다, 데즈코 님. 여기서 하시는 일을 진심으로 존경합니다. 꼭 다시 오겠습니다.', '', 66384),
(286515, 'koKR', '이제 아라토르와 용사를 데려가야겠네. 마지막 성물을 찾을 준비가 끝났으니 말이네.', '', 66384),
(286499, 'koKR', '틀렸습니다, 켈리아. 우리는 속삭임을 이해합니다. 약속을 이해하죠.', '', 66384),
(286490, 'koKR', '들판에 있던 고철을 치웠소. 이 버려진 것들로 쓸모 있는 물건을 만들 것이오.', '', 66384),
(286487, 'koKR', '', '머리가 좀 큰 이후로는 사원에 가지도 않았다. 새랑 가시덤불밖에 없었거든.', 66384),
(286478, 'koKR', '', '내 영혼에 숨은 부끄러움이 있다면, 당당히 마주하겠다.', 66384),
(286462, 'koKR', '그래. 해 지기 전에 서둘러 부두로 돌아가야 해.', '그래. 해 지기 전에 서둘러 부두로 돌아가야 해.', 66384),
(286461, 'koKR', '놈들 장부는 멀쩡한데, 하는 짓은 선창 썩은물보다 더 구려.', '놈들 장부는 멀쩡한데, 하는 짓은 선창 썩은물보다 더 구려.', 66384),
(286459, 'koKR', '그 자식들하고 엮이지 마. 입이 로르테마르 지갑보다 더 헐렁하거든.', '그 자식들하고 엮이지 마. 입이 로르테마르 지갑보다 더 헐렁하거든.', 66384),
(286448, 'koKR', '용사님! 탈것을 타고 태양샘으로 퇴각하십시오!', '', 66384),
(286435, 'koKR', '족쇄는 그대로 두게. 발버둥 치라지.', '', 66384),
(286434, 'koKR', '서두르지 말고 집중하게. 완성도는 아주 작은 차이에 달려 있네.', '', 66384),
(286433, 'koKR', '라카니는 엘프의 피를 원했지.\n\n자네가 오기 전에 꼬마가 꽤 소란을 피우긴 했네. 하지만 사실 우리한텐 위협이 되진 않아. 그냥 농부의 아들일 뿐. 우리처럼 민간인이네.\n\n그래도 결박당한 채 자네를 따라가지 못하고 적에게 당한다면, 어쩔 수 없는 일이겠지.', '', 66384),
(286412, 'koKR', '', '들여보내라. 저 용사는 우리 적의 피를 뒤집어쓰고 있다.', 66384),
(286404, 'koKR', '멈추지 마라! 어둠에 굴복하지 마라!', '', 66384),
(286397, 'koKR', '', '나약하긴! 혼자 서는 게 두려워서 남의 손을 빌리려고 해?', 66384),
(286388, 'koKR', '', '진격하라! 어둠을 몰아내라!', 66384),
(286387, 'koKR', '그 반대일세. 우린 지금 놀라운 일을 해내고 있는 이를 만나러 가는 길이라네. 내가 이루지 못한 일을 행하고 있는 사람 말일세.', '', 66384),
(286386, 'koKR', '망치 주둔지? 혹시 붉은 여명회와 관련된 일입니까?', '', 66384),
(286374, 'koKR', '', '어서 오게. 마지막 시련이 저 아래에서 기다리고 있네.\n\n견뎌낸다면 자네는 내 동족에게 받아들여질 걸세. 시작할 준비가 되면 구렁으로 들어가게.', 66384),
(286368, 'koKR', '', '알른가루가 있기에 가능한 일이네. 우리가 그토록 신성하게 여기는 이유 중 하나지.', 66384),
(286367, 'koKR', '이 그림들... 이런 마법은 태어나서 처음 보는군.', '', 66384),
(286366, 'koKR', '다 예방할 수 있는 일이었습니다! 어서 갑시다.', '', 66384),
(286361, 'koKR', '우리의 갈망에 세계 깊은 곳에서 울려 퍼지는 노래가 응답했다.', '', 66384),
(286360, 'koKR', '좀 더 알아봐야 합니다.', '', 66384),
(286359, 'koKR', '잠시만, 이 말뚝이 고집을 부려서.', '', 66384),
(286356, 'koKR', '망치 주둔지를 도와줘서 고맙소, $p.', '', 66384),
(286355, 'koKR', '', '줄잔... 안 돼...', 66384),
(286354, 'koKR', '', '먼저 피를 흘리게 한 건 너희다. 이제 죽어라!', 66384),
(286353, 'koKR', '실버문으로 돌아가는 차원문을 열어 주겠네, $p. 카드가에게 빌린 마법서가 있거든.', '', 66384),
(286337, 'koKR', '끝이 없군요, 그렇지 않습니까? 또 다른 자가 증오의 교리를 이어갈 뿐이니.', '', 66384),
(286336, 'koKR', '이 검은 십자군의 증오가 태어나기 훨씬 전부터 존재했습니다. 어쩌면 진정한 의인에게 다시 맡기는 게 나을지도 모르겠군요.', '', 66384),
(286335, 'koKR', '이 수습생들은 영원히 증오로 빛을 불러내려는 걸까요?', '', 66384),
(286333, 'koKR', '빛은... 우리 십자군의... 새로운 지도자를... 선택할 것이다...', '', 66384),
(286331, 'koKR', '이교도들이 감히 교감을 방해해?', '', 66384),
(286330, 'koKR', '가십시오! 항복하려면 무기를 내놓고, 이 저주받은 곳을 떠나 다시는 돌아오지 마십시오!', '', 66384),
(286329, 'koKR', '', '침입자들... 그래, 성전의 때가 왔는가.', 66384),
(286328, 'koKR', '그렇다면 빛의 독선은... 누가 가르친단 말이냐?', '', 66384),
(286327, 'koKR', '불신자를 응징하는 법을 몸소 가르쳐 주지!', '', 66384),
(286326, 'koKR', '', '일은 이미 벌어졌고, 앞으로도 일어날 거다. 난 그 사실을 말하는 거다.', 66384),
(286324, 'koKR', '', '우리의 뿌리는 샬라드라실 근처에서 가장 평안히 쉴 수 있다. 내 숲은 돌아갈 거다.', 66384),
(286323, 'koKR', '', '우리 보금자리가 빛나고 있다. 루타니에게 위험하지. 빛이 잠잠해지면 돌아갈 거다.', 66384),
(286322, 'koKR', '', '나는 루타니의 원로다. 우리 숲을 대표해 말한다.', 66384),
(286311, 'koKR', '태양샘은 빛의 매개체일세! 나루 므우루의 희생으로 성스러워졌지!', '', 66384),
(286310, 'koKR', '', '여신의 목소리가 들리네만, 이제는 속삭임에 불과하네. 술카는 이 공허함을 어떻게 견디는 걸까?', 66384),
(286308, 'koKR', '', '공허폭풍이 나타난 뒤로 남쪽에 파견된 정찰병 3명이 또 연락 두절됐습니다!', 66384),
(286307, 'koKR', '', '누구... 무슨 일로 오셨습니까?', 66384),
(286305, 'koKR', '신병인가? 훌륭하군!', '', 66384),
(286303, 'koKR', '', '트랜퀼리엔에 이렇게 긴장감이 감도는 건 몇 년 만에 처음 봅니다.', 66384),
(286302, 'koKR', '', '빛나무든 뭐든 상관없어. 동족을 구해야 해, 잔. 엘프를 데려가서 생존자를 찾아.', 66384),
(286300, 'koKR', '좋다. $C|1이여;여;, 무기를 가져가라. 만나는 아마니를 전부 무장시켜라.', '', 66384),
(286288, 'koKR', '몰아치는 공허폭풍의 심연 아래 무력하게 짓눌리는 기분, 저희는 잘 알고 있습니다.\n\n이 서신을 읽는 지금, 당신의 각성이 시작된 것입니다.\n\n남쪽으로 향하십시오, 지친 순례자여. 트랜퀼리엔은 여정 중 잠시 쉬어가는 곳일 뿐입니다.\n\n경애하는 지도자께서 길을 보여주실 것입니다.', '몰아치는 공허폭풍의 심연 아래 무력하게 짓눌리는 기분, 저희는 잘 알고 있습니다.\n\n이 서신을 읽는 지금, 당신의 각성이 시작된 것입니다.\n\n남쪽으로 향하십시오, 지친 순례자여. 트랜퀼리엔은 여정 중 잠시 쉬어가는 곳일 뿐입니다.\n\n경애하는 지도자께서 길을 보여주실 것입니다.', 66384),
(286287, 'koKR', '폭풍이 다가오는데 실버문은 수수방관하고 있습니다. 이젠 우리가 직접 나서야 할 때입니다.\n\n트랜퀼리엔에는 당신의 자리가 마련되어 있습니다. 함께라면 안전할 수 있습니다. 힘을 모으면 우리 스스로를 지킬 수 있습니다.\n\n관심이 있으시다면 안테노리안 총독 관저로 문의하십시오.\n\n누구든 환영합니다. 특히 군 경험이 있으신 분을 우대합니다.', '폭풍이 다가오는데 실버문은 수수방관하고 있습니다. 이젠 우리가 직접 나서야 할 때입니다.\n\n트랜퀼리엔에는 당신의 자리가 마련되어 있습니다. 함께라면 안전할 수 있습니다. 힘을 모으면 우리 스스로를 지킬 수 있습니다.\n\n관심이 있으시다면 안테노리안 총독 관저로 문의하십시오.\n\n누구든 환영합니다. 특히 군 경험이 있으신 분을 우대합니다.', 66384),
(286286, 'koKR', '<마을 지도와 함께 주요 위치들이 표시된 환영 책자입니다. 총독 관저, 경비초소, 엄브릭의 실험실 등이 안내되어 있습니다.>\n\n트랜퀼리엔에 오신 것을 환영합니다!\n\n평화를 찾으러 오셨나요? 안전과 진실을 원하시나요? 이 모든 것, 나아가 그 이상을 약속드립니다.\n\n잊지 마십시오. 총독께서는 여러분의 목소리에 귀 기울이고 계십니다. 우리 모두를 주의 깊게 지켜보고 계시니까요!', '<마을 지도와 함께 주요 위치들이 표시된 환영 책자입니다. 총독 관저, 경비초소, 엄브릭의 실험실 등이 안내되어 있습니다.>\n\n트랜퀼리엔에 오신 것을 환영합니다!\n\n평화를 찾으러 오셨나요? 안전과 진실을 원하시나요? 이 모든 것, 나아가 그 이상을 약속드립니다.\n\n잊지 마십시오. 총독께서는 여러분의 목소리에 귀 기울이고 계십니다. 우리 모두를 주의 깊게 지켜보고 계시니까요!', 66384),
(286262, 'koKR', '트롤들이 뭐라 하든 상관없어요.\n\n놈들은 나무꾼이 아니라 괴물이에요.\n\n밤을 틈타 몰래 와서 여동생의 목숨을 빼앗고, 농장을 불태웠죠!\n\n그래요, 교훈을 주고 싶겠죠. 하지만 맨몸에 묶인 사람더러 전장에 나가서 뭘 배우란 건가요?\n\n결국 날 죽이려는 거잖아요.', '', 66384),
(286261, 'koKR', '늦기 전에 이거 좀 풀어주세요.', '', 66384),
(286257, 'koKR', '토룬도가 보낸 건가? 빛나무 무기 배송이 왜 늦는지 알아보라고? 그렇다면 잘 찾아왔네.\n\n황혼의 칼날단이 우리 야영지를 알아냈고, 아마니에게 강력한 빛나무 무기를 공급한다는 것도 눈치챘지. 그래서 요즘은 수시로 들이닥쳐서 일만 방해하고 있어.\n\n그 와중에 어떤 엘프 아이가 야영지에 들이닥쳐서는 여동생 얘기를 하며 고래고래 소리를 지르지 뭔가. 지금 황혼의 칼날단 상대하기도 바쁜데, 화난 엘프 농부가 잃어버린 자식까지 돌볼 시간은 없네!\n\n나이도 어리고, 뭐든 다 안다고 착각해. 하지만 나라고 다 모르는 건 아니거든...\n\n자네가 이 두 가지 문제를 한꺼번에 해결해 줄 수 있을지도 모르겠군.', '', 66384),
(286255, 'koKR', '우리 종족도 저런 기술을 배워 쓸 수 있다면 좋을 텐데요.\n\n그런 지식이 있다면 공허의 위협으로부터 가족을 지킬 수 있을 거예요.... 남은 가족이라도요.', '', 66384),
(286231, 'koKR', '미안해요. 이제 알겠어요. 경솔하게 단정 지어선 안 됐어요.', '', 66384),
(286230, 'koKR', '고맙단 말은 됐네, 어린 친구. 이제 농장으로 돌아가. 줄아만은 엘프 소년이 있을 곳이 못 돼.', '', 66384),
(286226, 'koKR', '당신들 동족이 우리 농장을 습격해서 여동생을 죽였어. 그 정도면 이유는 충분하지.', '', 66384),
(286224, 'koKR', '빛나무 조각 하나에 이렇게 큰 힘이 있다니, 트롤들을 너무 얕봤던 것 같네요.', '', 66384),
(286223, 'koKR', '황혼의 칼날단이 여기에 있을 줄은 몰랐어요... 이렇게 많을 줄이야.', '', 66384),
(286222, 'koKR', '가게. 정찰대장을 제거해. 녀석이 아이를 해치기 전에.', '', 66384),
(286221, 'koKR', '어린 친구, $n|1을;를; 도와주게. 나무를 베야 해.', '', 66384),
(286216, 'koKR', '우린 빛나무를 가공하고 있네. 지금 어떤 위협이 도사리는지 전혀 모르고 있구먼, 어린 친구.', '', 66384),
(286193, 'koKR', '빛나무가 놈들의 실체를 드러내고, 기절까지 시켰다고요?', '', 66384),
(286191, 'koKR', '저 아이에게 진짜 적이 누군지 보여주게.', '', 66384),
(286168, 'koKR', '이곳은 나의 안식처요. 필요한 것이 있다면 언제든 말씀하시오.', '', 66384),
(286135, 'koKR', '', '토룬도, 보고를 듣고 싶군. 병사들의 전투 준비는 언제쯤 끝나지?', 66384),
(286134, 'koKR', '두 번째 가르침일세. 빛은 믿음과 신념을 통해 흘러드는 것이네. 비록 그 신념이 잘못되었을지라도 말이야.', '', 66384),
(286133, 'koKR', '여긴 겉모습만 보면 영락없이 성스러운 빛의 교회지만, 사악한 목적에 사용되고 말았지요.', '', 66384),
(286129, 'koKR', '여긴 진정으로 성스러운 빛을 추종하던 장소였네.\n\n사이단과 알렉산드로스가 이끌던 십자군은 로데론에서 많은 선행을 실천했네.\n\n하지만 시간이 흐르며 잘못된 지도자의 인도를 받았고, 타인을 미워하도록 길들였지. 바로 그 증오심이 수십 년간 십자군의 행동을 이끌어 왔네.', '', 66384),
(286125, 'koKR', '아, 그렇죠, 멜레도어. 당신의 잘난 마법이 멀쩡한 일지를 망쳐놨지만, 적어도 재앙을 다루는 데는 도가 텄다고 할 수 있겠네요.', '', 66384),
(286123, 'koKR', '그나마 다행이네요, 바르디스. 이번만큼은 당신의 엉성한 방식이 이 혼란스러운 상황과 잘 맞잖아요.', '', 66384),
(286119, 'koKR', '왔구먼, 용사. 들어가 아라토르와 합류하세. 저 광신도들에게 내 설교는 먹히질 않는군.', '', 66384),
(286118, 'koKR', '교회를 점령당했을 때 많은 성물을 빼앗겼지. 차라리 잘아타스를 막는 데 쓰는 게 훨씬 나을 걸세.', '', 66384),
(286104, 'koKR', '', '오르웨냐가 고개를 젓습니다.', 66384),
(286099, 'koKR', '', '그럼 썩은가지 놈들이 한밤중에 우릴 납치하지 못하게 막아야지!', 66384),
(286081, 'koKR', '그리고 숲이 당신에게 가장 빠른 길을 보여주길 바랍니다. 우리 마법사는 그런 도움을 줄 생각이 없을 테니까요.', '', 66384),
(286077, 'koKR', '장로들께서 네가 시련을 치르는 걸 허락하셨다. 알른하라가 정말 너를 부른 것인지 이제 알 수 있겠지.\n\n우리 종족과 문화, 역사를 배울 수 있는 기회는 아주 드물다.\n\n준비되면 말해라.', '', 66384),
(286071, 'koKR', '행운을 빕니다. 우리가 먼저 수색하겠습니다. 바르디스를 데리고 가는 건 시간 낭비겠지만요.', '', 66384),
(286065, 'koKR', '잘아타스는 빛의 선봉대와 신도레이의 결의를 얕봤습니다. 오늘 우리는 무너지지 않습니다. 오히려 공허에 결정타를 날릴 겁니다!', '', 66384),
(286053, 'koKR', '<아라토르가 멈춰 서며 당신에게도 멈추라는 손짓을 합니다.>\n\n잠깐. 누가 옵니다.', '', 66384),
(286050, 'koKR', '고맙습니다. 스컬지의 기세가 꺾였군요. 태양샘을 지키는 데 필요한 유물은 얼마든지 가져가십시오.', '', 66384),
(286049, 'koKR', '전 은빛 성기사단에 들어온 이래로 줄곧 그렇게 해 오고 있습니다.', '', 66384),
(286048, 'koKR', '내 첫 가르침은 이걸세. 과거 존경받던 영웅들을 보고 배워라. 영웅들의 빛을 북돋운 것이 무엇인지 알아보게.', '', 66384),
(286037, 'koKR', '성기사 문제를 잊기에 이보다 나은 곳도 없겠군요.', '', 66384),
(286035, 'koKR', '희망의 빛 예배당으로 가서 유물을 모으고 선봉대를 독려하게.', '', 66384),
(286029, 'koKR', '흐으음. 파수병들은 스스로 믿음과 힘을 다 쏟아내 버렸네. 우리가 북돋워 줘야 해.', '', 66384),
(286028, 'koKR', '그게 해결책입니까? 지팡이로 번개를 쏘는 게?', '', 66384),
(286018, 'koKR', '', '섭정님... 아마니가 영원노래 숲에 침입했습니다. 순찰대 사령관은 요격을 위해 출정했습니다.', 66384),
(286006, 'koKR', '아, 잘됐군! 둘 다 왔어. 지금 신앙의 위기가 닥쳤네. 우리가 바로 잡아야 하네!', '', 66384),
(286005, 'koKR', '참 괴로움 많은 아이로다. 아버지가 가슴에 깊은 상처를 남기면 그렇게 될 수밖에 없지. 걱정 말게, 내게 방도가 있으니.', '', 66384),
(286003, 'koKR', '사라넬 님, 공허가 돌파했습니다! 너무, 너무 늦었습니다...', '', 66384),
(285998, 'koKR', '', '언젠가 제 힘이 소중한 이들을 해칠까 두려웠습니다. 하지만 그건 늘 순간적으로 약해졌을 때, 내면의 어두운 나루가 빈틈을 헤집고 빠져나오려는 것이었죠.\n\n오랜 동료에게 떠밀려 그 힘을 쓰게 될 줄은 상상도 못 했습니다.', 66384),
(285997, 'koKR', '로스락시온!', '', 66384),
(285994, 'koKR', '이 수수께끼의 진실은 분명 이 안에 숨어 있습니다. 이제 찾기만 하면 됩니다.', '', 66384),
(285983, 'koKR', '굴복해라, 지상인들아! 너희의 빛이 다시 너희를 덮칠 것이다!', '', 66384),
(285979, 'koKR', '쉬어라, 살덩이야. 안식을 찾아라.', '', 66384),
(285977, 'koKR', '이곳은 공허의 기운이... 예리하게 다듬어져 있습니다. 데시무스의 소행일까요?', '', 66384),
(285959, 'koKR', '저는 걱정하지 않으셔도 됩니다. 하지만 티에라의 고통이... 깊이 전해졌습니다. 용사님도 그랬을 거라 믿습니다.\n\n이 길을 걷는 데 대가가 따른다는 건 알고 있었습니다. 하지만 지금처럼 실감한 건 이번이 처음입니다.', '', 66384),
(285955, 'koKR', '$n 님. 다른 사람들을 확인해야 합니다.', '', 66384),
(285937, 'koKR', '', '할두런, 용사. 이쪽일세.', 66384),
(285936, 'koKR', '우리가 지금 거대한 세계수의 뿌리 아래에 있다니. 숨이 멎을 듯한 절경이구려. 이렇게 넓은 세계가 있다는 걸 미처 몰랐소.\n\n이건 아제로스의 그 누구에게도 주어진 적 없는 소중한 기회요.\n\n그대만 준비되면, 나는 언제든 나아갈 준비가 되어 있소.', '', 66384),
(285929, 'koKR', '놈들의 벌목이 태양왕관의 파멸을 불러온 원인이었소! 아마니가 반드시 대가를 치르게 할 거요!', '', 66384),
(285928, 'koKR', '', '지금으로선 할 수 있는 만큼 했습니다.\n\n슬픔에 잠겨 있을 여유는 없습니다... 이제 막 시작일 뿐입니까요.', 66384),
(285927, 'koKR', '충돌이 빛만개의 폭주를 일으킨 거였군... 고맙소. 이제 편히 쉬고, 이 일은 우리에게 맡기시오.', '', 66384),
(285923, 'koKR', '아, 그렇지. 줄자라 님이 어떤 $c|1을;를; 회의에 동석시키고 싶다고 하더니! 그게 자네였구먼. 날 탈출시켜 준 바로 그 $c 말이야.\n\n잘됐네. 아마니에겐 아군이 더 필요하네. 자네도, 여기 모인 부족 지도자들도.\n\n리아드린이 함께 있는 건... 마음에 들지 않지만, 내가 줄자라 님의 결정에 이의를 제기하는 건 맞지 않아.', '', 66384),
(285922, 'koKR', '', '우리 깨진엄니는 황혼의 칼날단에게 장로와 마을을 잃었다. 아버지와 조부님도 세상을 떠나셨지.\n\n지금은 내가 깨진엄니를 이끌고 있다.', 66384),
(285909, 'koKR', '', '난 우리가 옳은 길을 가고 있다고 믿네. 어떤 위험이 따르더라도 이 길의 끝을 반드시 볼 걸세.', 66384),
(285908, 'koKR', '', '아무리 좋은 약도 양을 잘못 맞추면 독이 됩니다.', 66384),
(285907, 'koKR', '마법학자의 실험 때문이라지만, 그 영향만으로 저게 생겼다고는 생각하지 않아요.', '', 66384),
(285906, 'koKR', '', '저는 그 괴물이 빛을 이런 상태로 밀어 넣은 장본인이라고 생각합니다.', 66384),
(285905, 'koKR', '저건 대체 무슨 괴물이죠? 빛이 정말 그런 괴물을 만들어낼 수 있는 건가요?', '', 66384),
(285900, 'koKR', '', '도와주러 오셨습니까?', 66384),
(285896, 'koKR', '하가르는 뿌리감시관이 아니지만, 지혜만큼은 누구보다 깊지. 그런 사람이 오르웨냐를 잘못 이끌 리는 없다고 믿는다.', '', 66384),
(285889, 'koKR', '', '존경받는 뿌리감시관이 더 많은 걸 알려줄 수 있을 거다.', 66384),
(285885, 'koKR', '전통이란 건 다 이유가 있기에 존재한다. 우리를, 나아가 이 땅을 지켜주지. 젊은이들이 의심을 품어선 안 돼.', '', 66384),
(285882, 'koKR', '이 세상의 경계에는 공결탑이 있다. 그게 폭풍을 끊임없이 휘몰아치게 하지.', '', 66384),
(285825, 'koKR', '데시무스의 얼굴에 미소가 천천히 번집니다.', '', 66384),
(285824, 'koKR', '그럼 폭풍을 없앨 방법을 말해라, 공허의 피조물아.', '', 66384),
(285822, 'koKR', '참, 이렇게 무례한 손님은 얼마 만인지... 언제였더라. 말을 아끼는 게 좋겠군.\n\n내가 졌다는 걸 인정하지. 이제 문명인답게 얘기해 보자고.', '', 66384),
(285818, 'koKR', '아, 그렇죠. 그 \"훌륭한\" 두뇌로 일지를 잃어버렸지! 정말이지 한심하기 짝이 없습니다!', '', 66384),
(285817, 'koKR', '당신 \"눈썰미\"가 그렇게 대단하다면, 지금쯤 일지는 벌써 찾았겠지요?', '', 66384),
(285816, 'koKR', '젊은것들 철면피는 볼 때마다 감탄이 나오는군.', '', 66384),
(285813, 'koKR', '', '장로들은 알른가루를 내어주지 않을 걸세. 다른 길을 찾아야 하네.', 66384),
(285811, 'koKR', '붉은십자군? 많고 많은 사람 중에, 당신이 빛을 전파하고 싶다고요?', '', 66384),
(285808, 'koKR', '$p! 우린 태양샘을 구할 걸세. 더 중요한 건, 그 상처 입은 젊은이도 바로잡을 거라네.', '', 66384),
(285793, 'koKR', '', '하라티가 곁에 있고, 알른의 은총이 우리 마음속에 깃들었으니 이 광란을 몰아낼 수 있을 걸세.\n\n그렇지만 해야 할 일은 그것뿐만이 아닐세. 루이아가 기다리고 있어. 만행에 대한 대가는 반드시 받아내야 하네.', 66384),
(285786, 'koKR', '', '아, 그렇군요. 혹시... 찾아온 손님들 때문에 떠들썩한 분위기에서 잠시 벗어나고 싶으시다면, 도시 곳곳에 걸린 붉은 깃발을 찾아보세요. 그 구역만큼은 얼라이언스가 출입하지 못하게 하거든요.', 66384),
(285785, 'koKR', '', '발라 다쉬, 말래노레.\n\n왕궁 교역소는 이 혼란스러운 시기에도 일상을 유지할 수 있도록 돕는 공간입니다. 시장에 있는 시설 대부분이 이곳에서도 운영되고 있지요. 제약을 받는 분들을 위한 배려랄까요.', 66384),
(285784, 'koKR', '', '내가 부름을 받은 건 이유가 있을 걸세.', 66384),
(285779, 'koKR', '이 뒤로는 호드 구성원만 출입할 수 있습니다. 붉은색 깃발이나 나무가 있는 곳은 주의하십시오. 무시하면 대가가 따를 겁니다.', '', 66384),
(285778, 'koKR', '얼라이언스는 이 문 너머로 못 갑니다. 당신도 여기까지입니다, \"영웅\"님.', '', 66384),
(285777, 'koKR', '죄송합니다, 지금은 한가롭게 대화 나눌 시간이 없습니다.\n\n얼라이언스에게 시장 입장을 허락하긴 했지만, 그렇다고 우리가 경계를 늦출 이유가 되진 않습니다. 분명 선을 넘으려 들 겁니다.', '', 66384),
(285761, 'koKR', '', '줄잔이 이럴 줄 알아야 했는데...\n\n스라소니가 무늬를 바꾸지 않듯, 뱀도 비늘을 바꾸진 않지...\n\n그래도 내 동생이니까, 깨닫는 바가 있을 거라고 생각했건만...\n\n한 번만 내 얘기를 들었더라면!\n\n로아의 도움을 받기도 전에 줄잔이 모두를 죽음으로 내몰면 하셰이의 길을 걷는다 한들 무슨 의미가 있단 말이냐?!', 66384),
(285760, 'koKR', '', '날로라크의 짐과 책무를 모두 받았으니, 동족을 모아 모르둔을 끝장낼 수 있겠군!', 66384),
(285754, 'koKR', '나는 티템이다. 하르알노어에서 거래하러 왔지.', '', 66384),
(285753, 'koKR', '', '동생분이 명령을 따를 거란 확신이 있나요?', 66384),
(285751, 'koKR', '<마법학자 멜레도어와 순찰자 바르디스가 식사 중입니다.\n\n사라진 일지가 이젠 보이지 않습니다. 바로 이 시점에 사라진 듯합니다.>', '<마법학자 멜레도어와 순찰자 바르디스가 식사 중입니다.\n\n사라진 일지가 이젠 보이지 않습니다. 바로 이 시점에 사라진 듯합니다.>', 66384),
(285750, 'koKR', '<마법학자 멜레도어와 순찰자 바르디스가 잡담을 나누며 움직이고 있습니다.\n\n사라진 일지가 바로 앞에 있습니다. 아무래도 일지가 사라진 건 다른 시점으로 보입니다.>', '<마법학자 멜레도어와 순찰자 바르디스가 잡담을 나누며 움직이고 있습니다.\n\n사라진 일지가 바로 앞에 있습니다. 아무래도 일지가 사라진 건 다른 시점으로 보입니다.>', 66384),
(285748, 'koKR', '<마법학자 멜레도어와 순찰자 바르디스가 대련 중인 것 같습니다.\n\n사라진 일지가 바로 앞에 있습니다. 아무래도 일지가 사라진 건 다른 시점으로 보입니다.>', '<마법학자 멜레도어와 순찰자 바르디스가 대련 중인 것 같습니다.\n\n사라진 일지가 바로 앞에 있습니다. 아무래도 일지가 사라진 건 다른 시점으로 보입니다.>', 66384),
(285736, 'koKR', '리잠이다. 하르알노어에서 거래하러 왔다.', '', 66384),
(285733, 'koKR', '실버문, 아니 아제로스 전체의 운명이 이 임무의 성패에 달려 있소. 아누 벨로레 델래나.', '', 66384),
(285717, 'koKR', '이 꽃이 뿌리내린다면, 하르마라는 파괴될 거요!', '', 66384),
(285706, 'koKR', '공허의 세력은 빛의 힘을 얕봤습니다.', '', 66384),
(285703, 'koKR', '', '우리 둘 다 아마니다, 동생아. 서로에게 조금만 더 관대해지자.', 66384),
(285702, 'koKR', '또 뭘 꼬집으러 온 거야, 누나? 내가 누나보다 더 아마니다워질까 봐 겁나?', '', 66384),
(285701, 'koKR', '이게 살육의 맛인가!', '', 66384),
(285699, 'koKR', '', '아뇨! 전 할아버지처럼 실수하지 않을 겁니다. 그깟 \"가문의 긍지\"가 무너지는 한이 있어도!', 66384),
(285698, 'koKR', '멍청한 계집! 엘프랑 어울려? 네가 우리 가문을 욕보이는구나!', '', 66384),
(285694, 'koKR', '속삭임들이 제 감각을 질식시킵니다.', '속삭임들이 제 감각을 질식시킵니다.', 66384),
(285692, 'koKR', '이 빛만개는 제 예상과 사뭇 다르군요.', '', 66384),
(285689, 'koKR', '따분한 동료애 따윈 집어치워라. 데시무스처럼 너도 곧 주제를 알게 해주마.', '', 66384),
(285688, 'koKR', '', '루타니 대부분은 영역 의식이 매우 강해. 여긴 저들과 평화롭게 교류할 수 있는 몇 안 되는 곳이지.', 66384),
(285685, 'koKR', '', '제단에서 보자. 석탄은 내가 가져가지. 내 영혼은 어떤 시련도 맞설 준비가 되어 있다.', 66384),
(285680, 'koKR', '', '조심해라, 로아 전령!', 66384),
(285678, 'koKR', '', '헛소리를 늘어놓긴 해도, 로아와 깊이 이어진 건 분명해. 석탄을 챙겨라, 용사. 의식을 시작할 수 있을지도.', 66384),
(285672, 'koKR', '', '외숙부님, 수년간 로아와 대화도 못하셨잖아요? 왜 말을 해줄거라고 생각하시죠?', 66384),
(285671, 'koKR', '넌 로아가 있던 세상을 모르잖느냐. 로아는 우리의 힘이었고, 희망이었단다.', '', 66384),
(285667, 'koKR', '', '모르둔과 황혼의 칼날단을 뒤쫓아 말살하는 걸 도와주실 겁니까, 사냥의 지배자시여?', 66384),
(285665, 'koKR', '놈들은 내 사냥감이다, 어린 아마니여. 그림자가 늘 너를 지켜주기를.', '', 66384),
(285664, 'koKR', '', '몸을 가눌 수 있게 되는 대로 내려오게. 다들 기다리고 있으니.', 66384),
(285662, 'koKR', '', '이곳 하라마라에서는 루타니와 버섯전사가 평화롭게 공존하는 드문 광경을 볼 수 있네.', 66384),
(285661, 'koKR', '', '계속 나아가자. 하셰이 제단들이 우리를 할라지의 사원으로 이끌 거다.', 66384),
(285660, 'koKR', '', '이제 어떻게 하죠? 이 안개는... 도저히 뚫을 수가 없는데.', 66384),
(285659, 'koKR', '', '아, 정신이 드는가? 하르마라에 온 걸 환영하네.', 66384),
(285656, 'koKR', '빛은 우리와 함께합니다. 희망은 있습니다.', '', 66384),
(285630, 'koKR', '벌써 상태가 좋아졌네요. 다 고쳐졌나 봐요!', '', 66384),
(285627, 'koKR', '오래된 형상변환기가 운반 중 손상됐습니다. 고칠 수 있는지 봐주세요.', '', 66384),
(285603, 'koKR', '', '5명! 저 아래 남쪽에서 무슨 이상한 일이 벌어지고 있는데, 순찰대 인원이 부족합니다.', 66384),
(285599, 'koKR', '아라토르, 대피는 로르테마르에게 맡겨라. 넌 여기서 선봉대와 함께해야 한다!', '', 66384),
(285597, 'koKR', '제가 수소문해서 단서를 찾아보겠습니다.', '', 66384),
(285589, 'koKR', '', '납골당에서 보니, 썩은가지 놈들도 안개에 눈이 멀어 있더군. 흠.', 66384),
(285585, 'koKR', '', '우리가 네 전사들을 되찾고, 할라지 사원으로 가는 길도 찾아내겠다.', 66384),
(285584, 'koKR', '', '안개를 조심해라, 줄자라. 자연스러운 안개가 아니야. 썩은가지 놈들이 사악한 만행을 은폐하려고 수작을 부린 것 같다.', 66384),
(285580, 'koKR', '', '쏜살이도 왜 여기 왔는지 잘 모르겠어. 근데 양초가 나 지켜줘.\n\n$p도 안전 양초 필요해?', 66384),
(285574, 'koKR', '', '이제 할라지의 축복을 받거라. 할라지는 숨었지만, 그자의 전령이 널 인도할 것이다.', 66384),
(285573, 'koKR', '', '마른나무껍질의 로아 전령은 모두 죽었습니다. 쿨라마라라면 도와줄지도 모르겠군요.', 66384),
(285551, 'koKR', '', '표본을 원정순찰대에게 가져가겠습니다. 거기서 연구에 활용할 수 있을지도 모르겠습니다.', 66384),
(285550, 'koKR', '', '이 꽃... 빛으로 가득 차 있습니다. 빛만개 외에는 이런 걸 본 적이 없습니다. 손을 뻗으면 눈이 부실 정도입니다.', 66384),
(285546, 'koKR', '가세요. 누가 돌아올지 여기서 지켜볼게요.', '', 66384),
(285545, 'koKR', '해리스가 한숨을 내쉽니다.', '', 66384),
(285544, 'koKR', '세디나...!', '', 66384),
(285543, 'koKR', '', '따라오십시오! 도움이 필요한 사람이 있을 수 있는데, 기다려서는 구할 수 없습니다!', 66384),
(285528, 'koKR', '', '시련이라... 어릴 때 킨두루 외숙부가 여기 데려왔었지... 아직도 기억나.', 66384),
(285517, 'koKR', '', '네 아버지에 대해서 말인데. 그이가... 잠깐. 방금 소리 들었어?', 66384),
(285514, 'koKR', '우린 뿌리를 헤치고 싸워 나간 끝에 하란다르에 다다랐다. 다만, 이건 훨씬 더 깊고 위험한 이야기지.', '', 66384),
(285510, 'koKR', '이 일의 중대함을 이해하는 건 저 하나뿐인 것 같지만 말이지요.', '', 66384),
(285509, 'koKR', '', '적은 이미 저 앞에 차고 넘치지 않아? 난 아군으로 삼을 수 있으면 누구든 받아들일 거야.', 66384),
(285508, 'koKR', '곧 필요한 준비물이 모입니다. 이 악한의 굶주림이 우리에게 향하기 전에 처치해야 합니다.', '', 66384),
(285507, 'koKR', '', '마트리안, 그건 분석을 위한 거예요!', 66384),
(285505, 'koKR', '', '준비되셨나요? 목적지는 가까워졌지만, 불안감은 어느 때보다 크게 와닿네요.', 66384),
(285504, 'koKR', '', '이곳은 자체적인 법칙이 있어요. 공허는 그 틈을 파고들 수 있고, 우리도 그렇게 해야 해요.', 66384),
(285503, 'koKR', '다른 방법은... 없었던 걸까...?', '다른 방법은... 없었던 걸까...?', 66384),
(285502, 'koKR', '공허가... 우리를 해체한다...', '공허가... 우리를 해체한다...', 66384),
(285501, 'koKR', '', '연합왕 살라다르는 어둠수호병을 이끄는 자예요. 공허를 무분별하게 다루는 에테리얼들이죠. 살라다르는 디멘시우스의 가장 열렬한 추종자 중 하나였습니다. \n\n마나괴철로 종극점에서 쓰러뜨렸을 때, 잘아타스가 어딘가 멀리 떨어진 영역으로 빼돌렸죠. 살라다르나 수하 에테리얼들이나 한동안 잠적해 있었지만, 얼마 안 가 자발적으로 잘아타스에게 합류했습니다.\n\n과거의 살라다르는 정복자를 자칭했지만, 지금은 잘아타스의 하찮은 꼭두각시에 불과합니다.', 66384),
(285500, 'koKR', '', '용매에게 이렇게 큰 힘을 주입하는 건 처음이지만, 아무튼 괜찮을 겁니다.', 66384),
(285499, 'koKR', '', '얼른 타세요. 준비됐어요!', 66384),
(285498, 'koKR', '그대의 도움으로 많은 사람이 살아 실버문이 살아남는 걸 지켜볼 수 있을 거요!', '', 66384),
(285481, 'koKR', '데시무스가... 이상할 정도로 협조적입니다. 속을 알 수 없는 자와 함께 움직이는 건 영 달갑지 않군요.', '', 66384),
(285480, 'koKR', '', '<잠시 멍한 듯하다가 당신을 바라보는 알레리아>\n\n함께해 주셔서 감사해요. 잘아타스의 계획을 반드시 저지해야 합니다.', 66384),
(285478, 'koKR', '', '알른가루일세. 여신의 의지가 형태를 얻은 결과물이지. 우리의 마법을 강화하고, 세계 사이를 오갈 수 있게 해준다네.', 66384),
(285477, 'koKR', '살갗이 간질거리는군. 이게 도대체 뭐지?', '', 66384),
(285476, 'koKR', '이곳은 하늘마저도 이빨로 가득한 것 같습니다.', '이곳은 하늘마저도 이빨로 가득한 것 같습니다.', 66384),
(285475, 'koKR', '조심하세요, 용사님. 야수가 굶주린 모양입니다.', '조심하세요, 용사님. 야수가 굶주린 모양입니다.', 66384),
(285470, 'koKR', '', '바로 이곳이 하란다르일세.', 66384),
(285464, 'koKR', '', '분명히 경고하겠네. 내 동족은 외부인을 반기지 않네. 어쩌면 나조차도 환영받지 못할 수 있어.', 66384),
(285459, 'koKR', '우리 동료가 죽었다고요? 어떻게 이런 일이?', '', 66384),
(285454, 'koKR', '기록? 내용이 꽤 뜯겨 나갔군요... 이상합니다. 엄브릭에게 가보죠. 꼭 알리는 게 좋겠습니다.', '', 66384),
(285450, 'koKR', '', '...거짓말은 안 하겠다. 우린 도움이 필요해. 너희를 믿는 건 아니지만, 황혼의 칼날단을 해치우고 싶다면야 손잡을 수 있지.', 66384),
(285449, 'koKR', '놈들은 잊어버려, 누님. 우린 빛나무가 있어. 아마니에게 다른 부족은 필요 없어.', '', 66384),
(285432, 'koKR', '', '난 모르는 사람의 질문에 대답할 만큼 한가하지 않다.\n\n무슨 용건이지?', 66384),
(285428, 'koKR', '그만!', '', 66384),
(285426, 'koKR', '', '혹부리나무족이 제단을 거의 파괴했습니다. 이곳에 둥지를 튼 독수리들의 보금자리도 위험합니다.', 66384),
(285425, 'koKR', '빛이... 로스락시온의 분노로 타오릅니다... 꼭 아버지의 것처럼...', '', 66384),
(285424, 'koKR', '', '그럼 놈들을 해치워야겠군.', 66384),
(285423, 'koKR', '용사님, 빛의 힘을 빌려주십시오. 제가 억제해 보겠습니다!', '', 66384),
(285422, 'koKR', '', '혹부리나무족은 원래 북쪽 숲의 동굴에 사는 거인들이다. 그대로 머물렀으면 좋았을 텐데.\n\n지금은 우리 앞길을 막고 있다. 시간이 없어. 내쫓는 수밖에.', 66384),
(285421, 'koKR', '', '아라토르! 어서 막아!', 66384),
(285420, 'koKR', '사원으로 가는 길에 제단의 불을 밝혀 주게. 그리고 아킬존께 바칠 공물도 잊지 말게나!', '', 66384),
(285418, 'koKR', '', '사원이 혹부리나무족에게 점령당했다. 놈들을 처치하며 전진해야 해. 가자, \"하쉬우라\".', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(285409, 'koKR', '나는 세상을 참 많이 돌아다녔다오. 아니, 여러 세계를 많이 돌아다녔다 해야겠지.\n\n하지만 이 척박한 바위투성이 황무지에서 우리가 해낸 일은 내 일생에서 가장 자랑스러운 일이오. 생명의 순환은 중요하다지만, 이렇게 살생이 아닌 살리는 쪽에 서 본 건 처음이오. 참으로 뿌듯하구려.\n\n당신은 어떻소? 감상을 듣고 싶소만.', '', 66384),
(285408, 'koKR', '', '그리고 그게 우리 연구에 어떻게 도움이 된다는 거죠?', 66384),
(285407, 'koKR', '놀라운 결과로군요...', '', 66384),
(285377, 'koKR', '', '알른가루라... 장로들이 쉽게 내어줄 리 없네. 그래도 시도는 해봐야지.', 66384),
(285370, 'koKR', '내가 도망칠까 봐 걱정되나? 천만에. 이 흐름이라면 오히려 날 떼어낼 수 없을걸.', '', 66384),
(285369, 'koKR', '', '<겉보기에는 나무에서 솟아난 괴상한 꽃처럼 보입니다. 하지만 가까이 다가가서 보면 꽃이 자라나는 시체를 완전히 집어삼킨 상태라는 게 드러납니다. 나무 자체도 시체 주변이 아니라, 몸에서 자라난 것처럼 보입니다.>', 66384),
(285367, 'koKR', '<정면만 응시하는 로스락시온>', '', 66384),
(285366, 'koKR', '이 익숙한 냉기. 절 부르고 있어요...', '', 66384),
(285360, 'koKR', '', '내가 가진... 전부였는데...', 66384),
(285357, 'koKR', '죄송하지만, 제가 곁에 있어 줘야 할 것 같습니다. 제 보고서보단 마엘라의 것이 훨씬 자세하니 확인해 보세요.', '', 66384),
(285354, 'koKR', '<아스트레를 걱정한 나머지 당신이 다가온 것도 눈치채지 못하는 히에론>', '', 66384),
(285353, 'koKR', '', '$n 님. 윈드러너 여군주님과 무사히 돌아오셔서 다행입니다.\n\n저희는 공허폭풍 속에서도 살아남고 저항할 수 있는 특별한 종족입니다. 하지만, 그 힘의 유혹에 가장 쉽게 빠질 수 있는 존재이기도 하지요.', 66384),
(285351, 'koKR', '아무렴, 천천히 하시오! 강 건너에서 굶주린 나무 생명체들이 우리를 잡아먹으려 몰려오고 있는 것도 아니니 말이오.', '', 66384),
(285345, 'koKR', '', '고맙네, $n. 자네 덕분에 내 동족이 세상으로 돌아올 수 있었네. 여신께서도 기뻐하실 걸세.', 66384),
(285344, 'koKR', '오늘 그대의 노력이 영원노래 숲을 구했소, 오르웨냐. 하라니르가 원한다면 언제든 실버문에서 자리를 얻을 수 있을 것이오.', '', 66384),
(285342, 'koKR', '그대의 동족이 우리 고향을 구했소, 오르웨냐. 그대들 스스로 큰 희생을 치르면서 말이오. 이 헌신은 반드시 기려질 것이오.', '', 66384),
(285341, 'koKR', '함께 실버문으로 갑시다.', '', 66384),
(285335, 'koKR', '건방진 놈. 네 만행은 여기서 끝난다.', '', 66384),
(285334, 'koKR', '', '루이아! 알른하라의 의지가 네게 맞선다! 이 광란을 멈춰라!', 66384),
(285333, 'koKR', '', '두려워하지 말게. 루이아는 강하지만 혼자일세. 오늘 여기서 끝내자고.', 66384),
(285332, 'koKR', '하라니르 뿌리감시관과 싸우는 건 처음이오. 알아야 할 사항은 없소?', '', 66384),
(285323, 'koKR', '', '알른하라의 축복이 우리를 북돋우고 있네. 오늘은 여신의 모든 피조물을 위해 싸우는 날일세!', 66384),
(285322, 'koKR', '의식을 멈추시오! 전투 태세로! 오늘 영원노래 숲이 불타게 두지 마시오!', '', 66384),
(285321, 'koKR', '', '지원이 왔다네, 작은 새싹이여. ', 66384),
(285320, 'koKR', '', '하가르 장로?', 66384),
(285318, 'koKR', '한심한 오르웨냐. 너 혼자서는 빛만개를 막을 수 없다.', '', 66384),
(285316, 'koKR', '', '집요한 놈들! 알른하라시여, 힘을 주소서!', 66384),
(285312, 'koKR', '이건 간단한 주문 따위가 아니오! 계속 쏘고 죽지나 마시오!', '', 66384),
(285311, 'koKR', '서두르시오, 롬매스!', '', 66384),
(285308, 'koKR', '순진한 오르웨냐. 이 광란은 이제 우리의 신성한 터전을 갉아먹지 못할 것이다. 내가 저 꽃을 창조자에게 되돌려 주었다!', '', 66384),
(285307, 'koKR', '', '뿌리감시관 루이아? 이게 무슨 터무니없는 짓이지?', 66384),
(285304, 'koKR', '빛만개가 강에 도달했소. 태양의 빛이 우리를 지켜 주기를. 시간이 없소.', '', 66384),
(285302, 'koKR', '', '마법석을 터뜨리면 자네들 숲 전체가 잿더미가 되고 말 걸세.', 66384),
(285301, 'koKR', '영원노래 숲은 살아남을 것이오. 재에서 다시 피어오르더라도.', '', 66384),
(285300, 'koKR', '', '내가 더 도울 수 있으면 좋았을 텐데...', 66384),
(285299, 'koKR', '할두런, 정말이오? 룬석을 과부하시키면 전부 타버릴 것이오.', '', 66384),
(285296, 'koKR', '이대로는 진전이 없구려. 롬매스에게 전언을 보내시오. 마법학자들을 태양왕관 나무로 급파하라고 해야겠군.', '', 66384),
(285295, 'koKR', '무엇이든 해야겠지.', '', 66384),
(285294, 'koKR', '', '모아 온 알른가루는 이미 다 써 버렸네. 자네 생각은 어떤가, 할두런?', 66384),
(285291, 'koKR', '가능한 한 많이 데려왔소.', '', 66384),
(285290, 'koKR', '', '알른가루가 없으면 참혹한 결과를 맞을 걸세. 마음을 굳게 다지게.', 66384),
(285277, 'koKR', '하라니르와 저들의 마법 없이는 빛만개에 맞설 방도가 거의 없소.', '', 66384),
(285232, 'koKR', '', '이건 아니야. 전부 잘못됐어.', 66384),
(285231, 'koKR', '빛만개가 선봉대에 힘을 줄 거라 생각했는데... 오히려 빛만개가 원인일 수도 있다는 겁니까?', '', 66384),
(285225, 'koKR', '', '루타니일세. 내 고향의 생명체들이지. 이곳에 있어서는 안 될 존재들이네.', 66384),
(285224, 'koKR', '근처에 룬석이 있으니 서두르시죠. 안전한 곳으로 가서 살펴봅시다.', '', 66384),
(285222, 'koKR', '흩어져서 넓은 영역을 살펴보는 게 좋겠습니다. 전 나중에 두 분과 합류하겠습니다.', '', 66384),
(285221, 'koKR', '', '용사, 저 생명체들이 어쩌다 갑자기 번성했는지 밝혀내야 하네.', 66384),
(285220, 'koKR', '', '저들은 이곳을 자기 영역이라고 주장했네. 지금 우리가 침범한 셈이야.', 66384),
(285219, 'koKR', '이 생명체들은 빛의 축복을 받은 것 같지만... 너무 사납습니다.', '', 66384),
(285217, 'koKR', '', '저 생명체들... 고향을 떠올리게 하는구먼. 하지만 이 지상에 올라와 살고 있다니, 말도 안 되는 일이야.', 66384),
(285216, 'koKR', '자연에 친숙한 분이라고 어머니께 들었습니다. 이 상황을 어떻게 보십니까?', '', 66384),
(285212, 'koKR', '', '자네가 말하는 이 빛만개는 틀림없이 통제를 벗어나 있네. 무엇이 균형을 깨뜨린 건지 알아내야 해.', 66384),
(285211, 'koKR', '', '마법학자, 자네는 언제 처음 이 빛만개의 혼란을 봤는가?', 66384),
(285203, 'koKR', '오르웨냐 님 맞습니까? 제 어머니이신 알레리아 님께 이야기를 들었습니다.', '', 66384),
(285202, 'koKR', '전할 소식이 있으면 이 비전 투영기를 사용하시오.', '', 66384),
(285201, 'koKR', '아라토르, 태양샘에 네가 필요할지도 모른다.', '', 66384),
(285179, 'koKR', '너 같은 건 필요 없다!', '', 66384),
(285178, 'koKR', '그건 당신이 결정할 일이 아닙니다!', '', 66384),
(285156, 'koKR', '', '효과가 있군! 드디어 반격할 길을 찾았네.', 66384),
(285154, 'koKR', '', '알른하라의 은총으로, 알른가루가 루타니를 지켜 줄 걸세. 에온카처럼 말이야.', 66384),
(285153, 'koKR', '하늘에서 내려온 그건 며칠 만에 샬라드라실 전역을 집어삼켜 버렸소.', '', 66384),
(285149, 'koKR', '', '고맙다, 아마라크. 네게 진 빚은 말로 다 못 갚을 거야.', 66384),
(285145, 'koKR', '이게 있으면 현신을 상대로 우위를 점할 수 있다.', '', 66384),
(285143, 'koKR', '현신들은 심각한 위협이지만... 동시에 가장 풍부한 알른가루의 원천이기도 하다.', '', 66384),
(285142, 'koKR', '균열의 가장 어두운 심연에서 알른가루가 뭉쳐서, 거수의 형태로 나타난다.', '', 66384),
(285140, 'koKR', '사라졌어. 빼앗겼다고! 그분은 어디로 간 거지?', '', 66384),
(285139, 'koKR', '', '온히아? 제발!', 66384),
(285138, 'koKR', '', '안 돼! 여신이시여! 그분이... 여신님이... 아마라크? $n?', 66384),
(285137, 'koKR', '이성이 돌아왔군. 잘했다. 안타깝게도 네 친구는 그러지 못했다.', '', 66384),
(285136, 'koKR', '이런. 정신을 집중해라, 오르웨냐! 내 목소리를 들어!', '', 66384),
(285133, 'koKR', '', '나는 소리의 구름을 떠돌고 있네, 친구여. 그분이 날 위로해 주고, 환영해 주고 있어. 나는...', 66384),
(285132, 'koKR', '', '여기 없군. 수호물이... 용사, 알른가루가 더 필요하네. 서둘러 주게.', 66384),
(285131, 'koKR', '', '이 의식은 술카의 희생을 흉내낼 뿐이네. 영구적이지도 않고, 완전하지도 않지. 서둘러 아마라크를 찾아야 하네.', 66384),
(285129, 'koKR', '', '그분의 목소리가 사라졌네. 이렇게 외롭긴 처음이야. 이게 아마라크의 삶이란 말인가?', 66384),
(285122, 'koKR', '정 그렇게 하겠다면, 알른가루로 네 정신과 영혼을 지켜야 한다.', '', 66384),
(285118, 'koKR', '오랜 세월이 흘러 돌아와서는 균열에 들어가려 하다니. 전혀 변하지 않았군, 오르웨냐.', '', 66384),
(285115, 'koKR', '여신께서 요람으로부터 뜯겨 나올 때 잔혹한 상처가 생겼고, 아직도 낫지 않고 있다.', '', 66384),
(285114, 'koKR', '그분의 괴로운 절규에서 형태를 갖지 못한 공포가 태어났고, 발을 들이는 이들을 광기로 몰아넣었다.', '', 66384),
(285112, 'koKR', '알른가루를 모으는 데 어떤 대가가 따르는지 누구보다 잘 아는 사람이. 허비하고 싶으면 직접 균열로 들어가 구하라고 전해라.', '', 66384),
(285110, 'koKR', '외부인들을 위해 알른가루를 내어달라? 웃기는군!', '', 66384),
(285109, 'koKR', '', '소굴에서 수소문하게. 얻을 수 있는 단서는 뭐든 모으는 게 좋네.', 66384),
(285104, 'koKR', '나머지는 실버문으로 돌아가겠소. 논의해야 할 사안이... 많으니.', '', 66384),
(285103, 'koKR', '리아드린 여군주, 길목을 확보하시오. 좋든 싫든 우리는 입장을 정했소. 고수해야 하오.', '', 66384),
(285102, 'koKR', '용사여! 줄잔을 궁지에 몰아넣었소. 이제 이 침공을 끝냅시다!', '', 66384),
(285101, 'koKR', '가증스러운 아마니 같으니! 성스러운 빛에 맹세코 저 괴물들을 정화하고 말리라!', '', 66384),
(285098, 'koKR', '이 참상은... 광기 그 자체군요. 아버지는 어디 계십니까? 지금이라도 진실을 아셔야 합니다!', '', 66384),
(285097, 'koKR', '황혼의 칼날단입니다! 진짜 위협은 그자들입니다!', '', 66384),
(285093, 'koKR', '', '이미 늦었습니다, 아라토르. 그래도 도움이 필요한 이들은 치유할 수 있습니다.', 66384),
(285092, 'koKR', '우리가 막아야 합니다!', '', 66384),
(285086, 'koKR', '싸울 생각이 없으면 비켜라!', '', 66384),
(285083, 'koKR', '빨리 아마니 고개로 가서 사건의 진상을 알려야 합니다!', '', 66384),
(285080, 'koKR', '하! 잘하셨습니다!', '', 66384),
(285079, 'koKR', '또 다른 마법이 길을 막고 있습니다. 저 벽돌바닥이 열쇠일지도 모릅니다.', '', 66384),
(285073, 'koKR', '아마니가 불청객을 막으려 했던 모양입니다. 다행히 이 수호물은 오래됐군요.', '', 66384),
(285072, 'koKR', '이 정도로 삼엄한 곳이라면 조심하는 게 좋겠습니다. 절 따라오되, 조용히 움직이십시오.', '', 66384),
(285071, 'koKR', '여깁니다. 룬이 새겨져 있고, 강력한 수호물로 보호받는 것 같군요.', '', 66384),
(285043, 'koKR', '고맙소, 리아드린. 할두런이 이 상황을 설명해 줄 수 있으면 좋겠군.', '', 66384),
(285042, 'koKR', '', '전 이곳에서 생존자들 일을 마무리하겠습니다.', 66384),
(285041, 'koKR', '', '북쪽에서 굉음이 들렸어요. 그리고... 빛만개가 온 사방에 퍼졌죠!', 66384),
(285040, 'koKR', '누가 나무를 쓰러뜨린 것 같은 소리가 났어요. 원정순찰대에서 조사를 나갔죠.', '', 66384),
(285039, 'koKR', '', '분명 빛만개가 강 건너편에만 머물렀는데, 언제 여기까지 퍼졌지?', 66384),
(285038, 'koKR', '', '마치 자연 그 자체가 이곳을 집어삼킨 것 같습니다.', 66384),
(285037, 'koKR', '', '빛이시여...', 66384),
(284695, 'koKR', '', '지금도... 친구는 맞아. 로스락시온이 공허를 불신하는 건 틀린 게 아니야. 다만 날 믿어줬으면 하는 거지.', 66384),
(284694, 'koKR', '로스락시온과 친한 줄 알았는데요.', '', 66384),
(284693, 'koKR', '무기를 가까이 두십시오. 공허가 내미는 건 어떤 것도 믿지 마십시오.', '', 66384),
(284689, 'koKR', '', '안테노리안 님은 부재 중이십니다. 대신 저한테 말씀하세요.', 66384),
(284688, 'koKR', '뭔가 이상합니다. 아까 그 사람이 만지던 금고를 확인해 보죠.', '', 66384),
(284686, 'koKR', '', '안테노리안 군주님은 무척 바쁘신 분입니다. 그분이 아니면 쿠엘탈라스가 무너지는 가운데 트랜퀼리엔을 안전하게 지킬 사람이 어디 또 있겠습니까?\n\n대신 제가 도울 일은 없을까요?', 66384),
(284685, 'koKR', '어젯밤에 어떤 공허 엘프 여성이 헐레벌떡 뛰쳐나갔어요. 뭐에 쫓기듯이.', '', 66384),
(284684, 'koKR', '저 목소리는 카시에아 같군요. 무언가 남긴 게 있을지도 모릅니다. 한번 가보죠.', '', 66384),
(284681, 'koKR', '트랜퀼리엔에서 원하는 모든 걸 찾으실 수 있길 바랍니다, 여행자님.', '', 66384),
(284664, 'koKR', '', '세계의 노래가 이곳으로 가라고 했네. 내가 아는 건 그게 전부일세.', 66384),
(284658, 'koKR', '', '나는 세계의 노래를 듣고, 응답한다네.', 66384),
(284646, 'koKR', '제 연구실로 가져가도록 하죠.', '', 66384),
(284645, 'koKR', '마지막 표본이군요. 한데 이 모든 게 무슨 의미였을까요?', '', 66384),
(284644, 'koKR', '효과가 있군요! 저 크기를 보십시오!', '', 66384),
(284642, 'koKR', '카시에아... 대체 무슨 일을 하고 있었던 거야?', '', 66384),
(284632, 'koKR', '마지막 장소도 확인해 봅시다.', '', 66384),
(284631, 'koKR', '설마 공허폭풍에서 직접 소환하고 있었던 건가? 왜 그런 짓을?', '', 66384),
(284630, 'koKR', '괴물이 더 몰려옵니다!', '', 66384),
(284628, 'koKR', '여긴 공허폭풍에 더 노출된 터라, 위험할 수 있습니다.', '', 66384),
(284358, 'koKR', '우리 종족을 위해 힘써줘서 고맙다.', '우리 종족을 위해 힘써줘서 고맙다.', 66384),
(284357, 'koKR', '환영한다, 이방인. 여기서 편히 쉬도록.', '환영한다, 이방인. 여기서 편히 쉬도록.', 66384),
(284347, 'koKR', '공허 마력 표본이군요. 좋습니다. 채취하고, 다른 장소도 살펴봅시다.', '', 66384),
(284346, 'koKR', '균열이다!', '', 66384),
(284345, 'koKR', '카시에아의 기록은... 소환과 관련된 것 같습니다. 어디 보자.', '', 66384),
(284343, 'koKR', '그럼 함께 싸워요. 어머니를 두고 가지 않을 겁니다.', '', 66384),
(284342, 'koKR', '', '투랄리온이 여기 있었으면 좋았을 텐데. 로스락시온도 남편 말은 들었을 거야.', 66384),
(284341, 'koKR', '로스락시온의 눈빛에서 아버지의 눈빛이 보입니다.', '', 66384),
(284340, 'koKR', '', '인사치레나 할 만큼 한가한 곳이 아니야. 빨리 움직여야 해! ', 66384),
(284339, 'koKR', '흥분하지 마라, 짐승아. 알레리아는 속았을지 몰라도, 난 네 실체를 꿰뚫고 있다.', '', 66384),
(284338, 'koKR', '느껴지느냐? 견장이 가까이에 있다.', '', 66384),
(284335, 'koKR', '죽었어! 그리고 쿠자트만 정신 나간 게 아니야!', '', 66384),
(284334, 'koKR', '', '잘아타스는 검은 심장과 이 땅 그 자체의 힘을 이용해 공허첨탑을 세웠어요.\n\n이 몰아치는 마력이 모두 잘아타스의 공허폭풍이란 얘기죠. 그리고 태양샘을 향하고 있다는 걸 알아내기까지 그리 긴 시간이 걸리지 않았습니다.\n\n물론 저도 실버문을 도우러 가고 싶었습니다. 하지만 전 거기서 환영받지 못하는 몸이고... 여기 있는 편이 더 도움이 될 거예요.', 66384),
(284332, 'koKR', '', '전 처음 검은 심장의 존재를 알게 된 이후로 줄곧 잘아타스를 추적해 왔어요. 그자가 카즈 알가르를 떠난 뒤엔 크아레쉬로 따라갔죠. 그런데 거기서 잘아타스는 디멘시우스의 귀환을 막고 있었어요.\n\n아제로스의 영웅들이 실버문 방어를 위해 물러난 뒤에도, 저는 계속 뒤를 쫓았습니다. 절대 포기하지 않을 거예요.\n\n잘아타스는 어둠수호병 에테리얼들을 다시 거두었고, 이 낯선 장소로 통하는 길을 열었어요. 저도 빈틈을 노려 들어왔죠.\n\n이 폭풍 속에선 돌아갈 길이 없었어요. 뭐, 그럴 필요도 없었지만요. 제 표적은 여기 있으니.', 66384),
(284328, 'koKR', '저는 수많은 면모로 이루어진 존재입니다, 필멸자여. 나스레짐이자, 악마이며, 죽음 그 자체이지요. 무엇보다 빛벼림입니다.\n\n제 동족 나스레짐, 일명 공포의 군주는 변신과 기만... 쉽게 바뀌는 충성심으로 유명합니다.\n\n한때 저도 불타는 군단에서 동족들과 함께 싸웠습니다. 진정한 죽음의 군주께 복종하며 명령을 수행하고, 보고를 보내며 살아갔지요. 우리는 공허의 파멸만을 추구했습니다. 수많은 세계를 희생시키면서 말입니다.\n\n하지만 드레나이를 만났고, 그들의 빛을 보았습니다. 공허를 이겨내는 진정한 길은 그 반대편을 포용하는 것이라는 걸 알게 되었지요. 빛과 하나가 되는 것 말입니다.\n\n다른 나스레짐들은 이해하지 못했습니다. 그래서 저는 떠났습니다. 빛만이 제 길입니다.', '', 66384),
(284324, 'koKR', '나는 에온카. 만개하는 정원에서 자라났다. 알른의 균열의 씨앗을 거래하려고 왔지.', '', 66384),
(284323, 'koKR', '반갑다. 네 뿌리가 깊이 뻗기를. 혹시 거래할 씨앗을 가지고 왔나?', '', 66384),
(284321, 'koKR', '빛만개 아니다. 이방인 거래할 거 아니면 떠나라.', '', 66384),
(284320, 'koKR', '이방인, 나랑 거래하러 왔어?', '', 66384),
(284315, 'koKR', '이 몸에게 물건 있어. 이방인 교환할 거 없어?', '', 66384),
(284303, 'koKR', '강도만 벌써 3번째야!', '', 66384),
(284301, 'koKR', '마을 주민 모두가 하늘을 보고 걱정하고 있네.', '', 66384),
(284298, 'koKR', '수상하다니요? 우리 모두의 머리 위에 떠 있는 거대한 공허의 폭풍처럼 말이지요? 글쎄요. 잘 모르겠군요.', '', 66384),
(284296, 'koKR', '무슨 일입니까? 제가 요즘 좀 많이 바쁩니다.', '', 66384),
(284291, 'koKR', '우린 이런 화물을 자주 가로챕니다. 안에 뭐가 들었을지는 알 수 없지요. 또 부탁을 드릴 일이 생길지도 모르겠군요.', '', 66384),
(284290, 'koKR', '마도공학자들이 일전에 가로챈 차원 간 화물의 보안 체계를 해석하는 데 애를 먹고 있습니다. 당신이라면 열 수 있을지도 모르겠군요.', '', 66384),
(284289, 'koKR', '저는 끝없는 어둠을 누비며 수백, 아니 수천 개의 세계를 보았습니다.\n\n우린 군단과 싸웠습니다. 전쟁과 어둠에 삼켜진 세계들이었죠.\n\n하지만 이런 곳은 처음입니다. 입안에 남는 이 추악한 맛, 살을 에는 냉기...\n\n아주 깊은 어둠이 이곳에 있습니다. 잘아타스 말이죠.', '', 66384),
(284286, 'koKR', '', '같이 가자. 숲 부족의 지도자들이 모여 전쟁 계획을 논의하고 있다.', 66384),
(284285, 'koKR', '렌도레이를 실버문, 심지어 태양샘 가까이에 들이는 내 결정을 두고 많은 사람이 이의를 제기할 거요. 나 또한 다르칸 드라시르의 길을 따른 이들을 향한 분노와 두려움을 누구보다 잘 이해하오.\n\n다르칸은 내 친우였소. 그때의 배신감은 지금도 가슴 깊이 비수처럼 박혀 있지.\n\n하지만 애초에 렌도레이의 추방에 의문을 표한 이들도 많았소. 그 엘프들에겐 가족도 있고, 친구도 있소. 모두가 그들을 잃었다고 생각하지는 않았다오.\n\n지금 우리에게 가장 필요한 건 분열이 아니라 단결이오.', '', 66384),
(284279, 'koKR', '나는 물건 팔 때 상대 출신 같은 거 안 봐.', '', 66384),
(284270, 'koKR', '이방인은 들이지 않지만, 이번에는 예외로 해야겠군.', '', 66384),
(284260, 'koKR', '저를 비롯한 많은 렌도레이가 마법학자의 정원에서 마법을 공부했습니다. 우리의 고향이었죠. 롬매스는 제 동기였습니다.\n\n전 적을 제대로 이해해야 진정으로 맞설 수 있다고 믿었습니다. 그래서 저는 공허를 탐구하는 연구진을 이끌었지요. 그 과정에서 실버문을 리치 왕에게 넘긴 장본인, 다르칸 드라시르의 기록을 발견했습니다. 그가 저지른 배신으로 인해 3차 대전쟁 당시 많은 소중한 것들이 파괴되었습니다. 그자의 공허 연구는 그러한 비극을 일으킨 원인이기도 했지요.\n\n그러니 지옥 마법처럼 위험한 힘을 오랜 세월 사용해 온 블러드 엘프조차 우리의 연구를 꺼리게 된 것도 이해하실 수 있을 겁니다. 우리는 멈추기를 거부했고, 끝내 추방당했습니다.\n\n저는 제 선택을 후회하지 않습니다. 다만 그로 인해 동족이 겪은 고통은 안타깝게 생각합니다.', '', 66384),
(284258, 'koKR', '', '공허와 빛이 꼭 대립할 필요는 없습니다. 저는 제 신념으로 공허의 악영향을 막아내고 있습니다.\n\n그리고 이 신념은 폭풍 너머에 있는 위험으로부터도 절 지켜줄 것입니다. 장담하죠.', 66384),
(284257, 'koKR', '<조용히 동료들의 장비를 점검하다가 당신을 올려다보는 히에론>\n\n아, $n 님. 우리의 비장의 무기 아닙니까. 용사님이 함께라면 이번 임무도 그리 절망적이지만은 않을 것 같습니다. 사실 실버문 여론은 오히려 이 작전을 반길지도 모르겠네요. 요즘 공허는 폭풍이든 엘프든 어느 쪽도 인기 없으니까요.\n\n그래도 언젠가는 바뀌었으면 합니다. 우리를 바라봐줬으면 해요. 그러니 그럴 이유를 확실히 보여줍시다.', '', 66384),
(284256, 'koKR', '얼마 전까지만 해도 이곳을 집처럼 여겼습니다. 모두가 저에게 기대를 걸었고, 저도 부응하고 싶었습니다. 인정받고, 필요한 존재였지요... 제 재능이 처음 계획한 인생과 어긋나기 전까진 말입니다. 제가 진짜 어떤 사람인지 말하기 전까진요.\n\n<쓴웃음을 머금고 하늘을 올려다보는 아스트레>\n\n저는 저들을 구하러 온 게 아닙니다. 우리가 어떤 존재인지 보여주기 위해 왔습니다. 틀렸다는 걸 자각하게 해주려고요.', '', 66384),
(284255, 'koKR', '지난번 실버문이 전쟁에 휘말렸을 때, 저는 원정순찰대 소속 부관이었습니다. 부대와 함께 성벽 위에 나란히 서 있던 기억이 납니다. 그때 급보가 날아들었죠. 순찰대 사령관이 전사했다고. 아무도 믿지 않았습니다. 언데드가 숲을 뚫고 튀어나오기 전까지는...\n\n<고개를 젓는 사이데라스>\n\n지금도 똑같은 기분입니다. 변하지 않는 것도 있나 봅니다. 안 그런가요, $p 님?', '', 66384),
(284254, 'koKR', '', '저는 주문파괴자였습니다. 마법학자의 정원이 제 터전이었죠.\n\n동족을 돕기 위해 공허를 연구했지만, 공허와 하나가 되길 원한 적은 없습니다. 고향을 떠나고 싶지도 않았습니다.\n\n롬매스가 제 말을 들어줬냐고요? 마법학자들이 이해해 줬냐고요? 그럴 리가요.\n\n<얼굴을 구기는 마엘라>', 66384),
(284252, 'koKR', '데시무스가 손가락 끝을 튕기며 당신을 부르는 시늉을 합니다.', '', 66384),
(284248, 'koKR', '특히 너. 지난번의 일을 내가 잊었다고 생각하지 마라.', '', 66384),
(284216, 'koKR', '빛만개는 느닷없이 퍼졌소. 상인들을 심문한 게 자극이 됐나? 위협을 느끼기라도 해서? 감정을 느낄 수나 있는 건지...\n\n의문이 많긴 하지만, 점차 진실에 다가서는 기분이오.', '', 66384),
(284178, 'koKR', '', '쿠자트는 평소에는 차분하지만, 한번 흥분하면 무척 위험해지네. 조심하게.', 66384),
(284160, 'koKR', '나머지는 생태지구 작업자들이 처리하겠습니다. 보호막이 민감해서 말이죠. 나중에 또 들러주세요. 도움이 필요할 수도 있으니.', '', 66384),
(284159, 'koKR', '마침 잘 오셨습니다! 공허 포자가 또 보호막을 뚫고 들어왔습니다. 생태를 오염시키기 전에 치워야 합니다.', '', 66384),
(284116, 'koKR', '제 고향이 파괴됐는데, 싸워보지 않고 당해줄 생각은 추호도 없습니다!', '', 66384),
(284092, 'koKR', '여기 있으면 안 돼요. 실버문으로 가야 한다고요!', '여기 있으면 안 돼요. 실버문으로 가야 한다고요!', 66384),
(284078, 'koKR', '', '여기서 벗어나곤 싶은데, 사방을 포위당했습니다.\n\n저 아래에 있는 게 뭔지 알고 싶지도 않지만, 빠져나가려면 다른 길이 없습니다!', 66384),
(284072, 'koKR', '밖에 있던 그 거대한 야수 말이오? 온순해 보였는데... 추악한 수작질의 악취가 나는군.', '', 66384),
(284071, 'koKR', '쿠자트가 광란에 빠졌어!', '', 66384),
(284068, 'koKR', '필요한 건 다 있다. 친구를 애도하는 건 도시를 구한 다음에 해.', '', 66384),
(284066, 'koKR', '', '준비되셨나요?', 66384),
(284038, 'koKR', '뭐가 어떻게 된 거죠? 끔찍해!', '뭐가 어떻게 된 거죠? 끔찍해!', 66384),
(284037, 'koKR', '도와주세요! 여기서 빠져나가야 해요!', '도와주세요! 여기서 빠져나가야 해요!', 66384),
(284034, 'koKR', '실버문으로 떠나는 배가 있어요. 여기엔 못 있겠습니다. 배로 가야 해요!', '실버문으로 떠나는 배가 있어요. 여기엔 못 있겠습니다. 배로 가야 해요!', 66384),
(283974, 'koKR', '온 사방에 악몽이 깔렸습니다! 못 갈 것 같아요!', '온 사방에 악몽이 깔렸습니다! 못 갈 것 같아요!', 66384),
(283970, 'koKR', '', '제 고향은... 어떻게 됐습니까?', 66384),
(283963, 'koKR', '제가 앞장서겠습니다. 따라오십시오.', '', 66384),
(283956, 'koKR', '나가! 다시는 이 도시에서 일 못 하게 만들어 주지!', '', 66384),
(283954, 'koKR', '잠시만요. 여기 시신이 있습니다. 뭔가를 쥐고 있군요.', '', 66384),
(283921, 'koKR', '배고파! 너무... 배고파...', '', 66384),
(283920, 'koKR', '만찬이 늘었구나!', '', 66384),
(283916, 'koKR', '공결탑에 나루를 던지고 싶다면야, 말리진 않겠다.', '', 66384),
(283857, 'koKR', '전선이 아닌 곳에서도 더 큰 도움이 될 수 있습니다. 희생자를 줄일 수도 있고요. 저는 공허의 방식을 잘 압니다. 그리고 당신은 전설이죠.', '', 66384),
(283852, 'koKR', '실버문에 어서 오시오.', '', 66384),
(283851, 'koKR', '<경멸에 찬 눈빛으로 당신을 응시하는 롬매스>', '', 66384),
(283845, 'koKR', '실버문을 대신해 지원에 감사를 표하오.', '', 66384),
(283832, 'koKR', '이곳에 빛이 닿은 적이 한 번이라도 있었을까요?\n\n너무나도 부정한 어둠이 만연하고 있군요. 이 땅의 생명체들은 그 어둠을 즐기고 있고 말이지요. 공허의 영향을 받는 동료들 역시 그 유혹에 휘둘리지 않도록 경계해야 합니다.', '', 66384),
(283796, 'koKR', '선봉대에 합류하십시오, 페어린! 전 모두를 태양샘으로 데려가겠습니다.', '', 66384),
(283795, 'koKR', '부상자를 수송해야 합니다!', '', 66384),
(283794, 'koKR', '', '고마워요, 안두인. 신성한 불꽃이 우리 모두를 지켜주시길.', 66384),
(283793, 'koKR', '', '성스러운 빛이 선조의 땅을 지키는 방패가 될 거예요!', 66384),
(283775, 'koKR', '로스락시온도 같은 마음이었을 겁니다.', '', 66384),
(283774, 'koKR', '', '로르테마르에게 제 보고서를 전해주세요. 해야 할... 일을 했다고요.', 66384),
(283771, 'koKR', '빛에 홀린 머저리 놈을 막아라. 그럼 내가 합류해서 견장으로 폭풍을 약화시키겠다.', '', 66384),
(283766, 'koKR', '네가 얼마나 오래 기다리게 했는지 모르겠지, 작은 하쉬우라. 내 친우들이 스스로 증명하고 돌아오기를 바랐건만.\n\n줄진과 말라크라스가 날 배신한 뒤로, 난 이곳으로 돌아와 지켜보고, 기다리고, 상처를 치유하며, 하셰이가 오길 소망했다.\n\n그러다 내 친우들이 공격당했고, 내 자손들마저 다쳤다.\n\n희망의 끈을 놓은 상태였지.', '', 66384),
(283755, 'koKR', '', '그 늙은 얼간이를 찾아주세요. 영웅 놀이를 한 죗값으로 잔소리를 퍼부어 주고 싶네요.', 66384),
(283754, 'koKR', '', '히에론, 여군주 다크글렌 님과 떨어졌습니다. 반드시 찾아야 합니다.', 66384),
(283753, 'koKR', '좋습니다. 아스트레에게 미안하다고 전해 주세요. 오늘은 차를 함께할 수 없을 것 같군요.', '', 66384),
(283752, 'koKR', '', '아니, 이것만큼은 빼앗기지 않겠다!', 66384),
(283751, 'koKR', '', '네놈을 야수들 먹이로 던져 주마.', 66384),
(283749, 'koKR', '토렌티아의 장난감을 부수고 먹이사슬 꼭대기로 올라가라. 놈은 분명 도전으로 받아들일 거다.', '', 66384),
(283748, 'koKR', '들어가셨군요. 상품을 찾으세요.', '', 66384),
(283739, 'koKR', '', '많은 이가 나루를 빛의 현신으로 생각하지만, 저는 그렇게 단순한 존재가 아니라는 걸 직접 확인했습니다.\n\n저는 이 마법 능력을 타고나지 않았습니다. 어둠에 물든 나루, 르우라에게서 진정한 힘을 얻었고 이젠 제 안에서 머무르고 있죠. 즉, 르우라가 제 공허의 힘의 근원입니다.\n\n르우라를 다스리고 마력을 다룰 수 있게 되기까지 오랜 시간과 고된 여정이 뒤따랐어요. 하지만 그 덕분에 소중한 사람들을 지킬 수 있는 힘을 얻었죠.\n\n나루를 아군으로 포섭하면 잘아타스를 상대로 전세를 뒤집을 수 있다는 로스락시온의 생각도 옳습니다.', 66384),
(283738, 'koKR', '', '오랜만에 아들과 함께할 수 있어서 기쁘긴 해요. 하지만 이 감정이...\n\n<알레리아가 갑자기 고개를 돌리며 얼굴을 찡그립니다. 그리고는 한숨과 함께 떨쳐냅니다.>\n\n지금은 감상에 젖을 틈이 없습니다. 모두가 임무에 집중해야 해요.', 66384),
(283735, 'koKR', '', '<두 눈을 바쁘게 움직이는 알레리아>\n\n하늘을 주시하세요! 이곳엔 안전한 곳이 없어요.\n\n이상한 기척이 느껴져서 잘아타스의 병력인 줄 알고 긴장했는데, 용사님이셨군요... 그리고 아라토르도 있고요.\n\n얼마 전, 저는 잘아타스와 에테리얼들이 이 낯선 장소로 향하는 걸 봤습니다. 계속 뒤를 밟았죠. 하지만...\n\n<알레리아가 말끝을 흐리자, 보라색으로 빛나는 광채가 알레리라를 휘감습니다.>\n\n이곳의 공허는 너무 강력해요. 정신이... 아득해질 만큼. 황홀하죠.\n\n그래도 용사님이 오셨고, 아라토르도 와서 다행입니다. 신중해야 해요.', 66384),
(283721, 'koKR', '아니! 지금은 역습에 집중해야 하오!', '', 66384),
(283713, 'koKR', '그 여정은 길고도 험난했다. 수많은 시련이 길을 가로막았어.', '', 66384),
(283712, 'koKR', '모두가 여신의 부름을 따른 건 아니었지만, 하라티는 그 노래를 좇았다.', '', 66384),
(283695, 'koKR', '공허가... 너무 강합니다!', '', 66384),
(283691, 'koKR', '여기가 차원문을 열기엔 가장 안정적인 곳이지만, 데시무스의 야수가 길을 막고 있습니다.', '', 66384),
(283686, 'koKR', '내 지팡이가 필요하다. 전투 중에 버리고 도망쳤다간 아킬존께서 날 용서하지 않으실 거다!', '', 66384),
(283685, 'koKR', '길을 열어줘서 고맙네, 이방인.', '', 66384),
(283684, 'koKR', '', '줄잔이 빛나무를 좀 더 가져왔으면 좋았을 텐데. 자투리로만 일하려니 피곤하단 말이지.', 66384),
(283682, 'koKR', '흠. 아킬존의 냉철한 눈썰미를 빌릴까, 아니면 할라지의 귀를 빌려서 숨어 있는 걸 밝혀낼까?\n\n둘 다 쓰면 되겠지? 그래, 좋아. 둘 다 쓰자.', '', 66384),
(283676, 'koKR', '<토룬도는 당신을 의심스러운 눈초리로 바라보며, 무언가를 숨기듯 몸을 뒤로 움찔합니다.>\n\n자네는 누구지?\n\n이제 아탈아만을 떠날 시간인가?', '', 66384),
(283675, 'koKR', '', '<도루 장로는 버려진 마차에서 빛나무 무기를 수거하느라 정신이 없는 듯합니다.>\n\n전쟁 북소리가 들리긴 했네만, 이 무기들을 두고 갈 순 없지.', 66384),
(283664, 'koKR', '', '용사님과 전 흩어져서 수색하겠습니다. 제가...', 66384),
(283662, 'koKR', '', '아니. 줄아만을 홀로 돌아다니는 엘프는 등에 칼을 맞게 되어 있다. 그대는 나랑 같이 간다. 잔, 너는 친구 쪽을 맡도록.', 66384),
(283656, 'koKR', '', '황혼의 칼날단이 혹부리나무족을 우리 영토로 밀어 넣었다. 사원으로 가려면 놈들을 뚫고 지나가야 해.', 66384),
(283632, 'koKR', '고요한 날들이 이어지면 마음은 허전했다. 우리는 더 큰 목적을 갈망했지.', '', 66384),
(283630, 'koKR', '', '우린 지쳤다. 만신창이야. 모르둔과의 싸움에서는 이겼지만, 우리도 멍들고 피투성이가 됐지. 다음 전투에서는 어떻게 이기란 말이야?', 66384),
(283628, 'koKR', '전쟁터는 심약한 자가 있을 곳이 아닙니다.', '', 66384),
(283627, 'koKR', '용사님, 히에론은 어딨죠? 설마...?', '', 66384),
(283620, 'koKR', '사납디사나운 포식자들과 맞서 싸우고, 비로소 길들이기까지 했지.', '', 66384),
(283619, 'koKR', '우린 숲에서 가장 뛰어난 사냥꾼이 됐다.', '', 66384),
(283615, 'koKR', '민간인 대피가 최우선이오!', '', 66384),
(283614, 'koKR', '', '우리는 기적을 바라며 기도했고, 빛의 선봉대가 응답했습니다. 하지만 전투는 여전히 계속되고 있습니다.', 66384),
(283604, 'koKR', '아무도 우릴 주목하지 않았지. 땅을 흔들던 거인도... 대지를 누비는 거대한 야수들도.', '', 66384),
(283603, 'koKR', '아득히 먼 옛날, 우리 종족은 거대한 산의 숲을 헤매며 걸었다.', '', 66384),
(283589, 'koKR', '쪽지 읽었어? 또 다른... 일이 생긴 모양이야.', '쪽지 읽었어? 또 다른... 일이 생긴 모양이야.', 66384),
(283574, 'koKR', '저 언더핀이란 놈, 엄청나게 강하군요. 조심하십시오, 브란!', '', 66384),
(283573, 'koKR', '그래요? 그럼 한 2주 정도 쉬는 게 어때요? 영원히 은퇴하든지.', '', 66384),
(283549, 'koKR', '다른 이들에게 시간을 벌어주고 싶었습니다.\n\n<거칠게 숨을 몰아쉬는 히에론>\n\n막판에 몇 마리만 나타나지 않았어도 해낼 수 있었을 텐데. 다들 무사히 빠져나갔나요?', '', 66384),
(283540, 'koKR', '온다는 얘기는 들었다, 용사. 바로 시작하지.', '', 66384),
(283531, 'koKR', '', '히에론이 주의를 끌어주지 않았다면 울트라돈이 절 붙잡았을지도 몰라요.\n\n히에론이 펼쳐 보인 공허는 마치 일식처럼 느껴졌습니다.', 66384),
(283529, 'koKR', '', '정문을 지나자마자 울트다론이 저희의 냄새를 맡았습니다. 그렇게 흩어졌고... 로스락시온은 뒤도 돌아보지 않았습니다.', 66384),
(283528, 'koKR', '지금 황혼비행 수출선이 항구에 정박해 있다는 거 들었어?', '지금 황혼비행 수출선이 항구에 정박해 있다는 거 들었어?', 66384),
(283527, 'koKR', '비밀에 안 빠져 사는 타이드본 선원을 본 적 있나?', '비밀에 안 빠져 사는 타이드본 선원을 본 적 있나?', 66384),
(283503, 'koKR', '더 많은 힘. 모두 공허와 하나가 되리라.', '', 66384),
(283462, 'koKR', '', '나는 빛만개의 위협을 잘 알고 있네. 하지만 장로들의 마음을 달래지 못하면 자네는 하란다르에서 두 적을 동시에 상대해야 할 걸세.', 66384),
(283437, 'koKR', '나루는 빛에서 탄생한 존재입니다. 필멸자들의 나약한 마음을 북돋아 주는 희망과 힘의 봉화지요. 인간 세상에선 신과 같은 존재이고, 당신이나 저보다 훨씬 높은 곳에 있는 존재들입니다.\n\n그런 나루를 에테리얼이나 포식의 군단이 어디서 어떻게 붙잡았는지는 모릅니다. 멀리 떨어진 세계에서 납치해 온 건지, 아니면 수천 년 전 흩어진 드레나이 분파와 함께 있던 나루를 잡아 온 건지. 가증스러운 이탈자들 같으니. 아무튼 이단 따위는 지금의 사태에 비하면 사소한 문제입니다.\n\n최악의 사태가 벌어지기 전에 나루를 구해야 합니다. 나루의 광휘가 우리 편에 있다면, 공허폭풍의 종말은 반드시 찾아옵니다.', '', 66384),
(283434, 'koKR', '시간을 허비할 여유가 없습니다. 한순간의 지체가 곧 패배로 이어질 수 있습니다.', '', 66384),
(283426, 'koKR', '\"빛만개\" 따위는 위협이 안 돼. 네가 저지른 이단적 만행을 덮어줄 이유는 없다.', '', 66384),
(283423, 'koKR', '', '용사가 찾을 걸세. 자네부터 안전한 곳으로 가야 하네.', 66384),
(283416, 'koKR', '오르웨냐? 이자들은 누구지? 대체 무슨 짓을 한 거야?', '', 66384),
(283414, 'koKR', '이렇게 구속된 게 대체 얼마 만인지 모르겠군. 게다가 이토록 독특한 방식이라니!\n\n이 물질은 뭐라 불러야 할까? 빛접목? 곰곰이 생각해 보니 네 친구의 빛벼림과도 일맥상통하는 면이 있군.', '', 66384),
(283411, 'koKR', '그건 내가 하고 싶은 말이야! 내가 기억하는 한 외부인이 이 깊은 뿌리를 거닌 적은 없거든.\n\n<눈을 가늘게 뜨고 오르웨냐를 힐끔거리는 쿠파알>\n\n난 하라시르의 뿌리감시관 쿠파알이다. 새로이 생겨난 위대한 뿌리를 보살피지. 지상인들이 아미드랏실이라 명명한, 가장 먼 나무의 뿌리를 말이야.', '', 66384),
(283407, 'koKR', '에이, 이제 몸 좀 풀렸는데.', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(283406, 'koKR', '', '좋아. 근데 내가 다 잡았잖아! 가로채면 안 되지.', 66384),
(283404, 'koKR', '', '용사님이 울부짖는 능선에서 움직이실 동안 주변을 살펴봤습니다. 이곳에는 공허의 피조물들이 비정상적으로 몰려 있습니다.', 66384),
(283403, 'koKR', '', '하라시르 정착지 주민들이 이 뿌리를 돌본다네. 일종의 지름길이라고 할 수 있지.', 66384),
(283402, 'koKR', '', '조심하게. 자네를 침입자로 간주할 걸세.', 66384),
(283398, 'koKR', '그대는 옳은 선택을 했소. 어쩔 수 없는 선택이었지만. 드디어 제대로 된 반격을 시작할 수 있겠군.', '', 66384),
(283379, 'koKR', '', '로스락시온을 막아야 합니다. 마엘라, 다른 이들을 울부짖는 능선으로 데려가세요.', 66384),
(283378, 'koKR', '놈이 공결탑을 손상시키면, 마력 폭발이 일어나 네가 그토록 아끼는 실버문이 사라질 거다.', '', 66384),
(283368, 'koKR', '알레리아, 제정신입니까?', '', 66384),
(283367, 'koKR', '', '이게 데시무스의 계획이었군요. 테르미나스의 시선을 이쪽으로 묶어 두죠, $p 님.', 66384),
(283364, 'koKR', '서로 싸우든지, 죽든지. 이 나약한 미끼들은 내 친히 해치워 주겠다.', '', 66384),
(283363, 'koKR', '역시 공허의 계략인 줄도 몰랐나 보군요!', '', 66384),
(283362, 'koKR', '', '아니, 뭔가 이상해. 데시무스는 이런 구경거리를 놓칠 성격이 아니야.', 66384),
(283361, 'koKR', '이해가 안 되는군요. 배신하려면 언제든지 할 수 있었을 텐데요.', '', 66384),
(283360, 'koKR', '데시무스를 믿은 건 정신 나간 짓이었습니다!', '', 66384),
(283357, 'koKR', '', '무기를 준비하세요. 일단 돌파구를 만들고, 데시무스는 그다음에 처리하죠.', 66384),
(283356, 'koKR', '', '내가 뭘 놓친 거지? 왜 지금까지 기다리다 우리를 배신한 거야?', 66384),
(283349, 'koKR', '견장을 확보하십시오. 우리가 뒤를 맡겠습니다.', '', 66384),
(283348, 'koKR', '', '함께 움직이죠. 누구도 혼자 싸우게 두지 말고, 한 사람도 버리지 마세요.', 66384),
(283347, 'koKR', '그럼 희생에 무감해지지 마십시오! 모두 같은 목적을 위해 싸우고 있잖습니까.', '', 66384),
(283346, 'koKR', '전 수천 년 동안 빛을 섬겨 왔습니다. 희생의 의미라면 당신보다 더 잘 압니다.', '', 66384),
(283345, 'koKR', '빛도 무해하기만 한 건 아닙니다. 전 그 분노를 느꼈고, 빛이 어떤 희생을 치르게 하는지도 봤습니다.', '', 66384),
(283344, 'koKR', '공허는 타락과 혼란을 부르고, 친구를 적으로 만들며, 올바른 것을 왜곡합니다.', '', 66384),
(283343, 'koKR', '공허는 어디에도 충성하지 않습니다!', '', 66384),
(283342, 'koKR', '위기라니요? 제 말을 무시하고 도마나르의 말을 믿는 겁니까?', '', 66384),
(283341, 'koKR', '', '여기 남아, 로스락시온. 그대는 이미 한 번 임무를 위기로 몰아넣었어.', 66384),
(283339, 'koKR', '감당할 만한 손실이었습니다. 공허 엘프들도 위험을 알고 있었습니다.', '', 66384),
(283338, 'koKR', '', '사람들을 버리고 온 거야?', 66384),
(283337, 'koKR', '감동이네. 조언 하나 해주지. 순종하는 척하는 도마나르는 절대 믿지 마라.', '', 66384),
(283336, 'koKR', '', '잠깐! 네 힘에 굴복하겠다. 널 섬기게 해다오. 우리가 함께라면...', 66384),
(283335, 'koKR', '', '토렌티아에게 도전해 인장을 빼앗으세요. 아라토르, 요새 상부에서 다른 이들과 합류하자.', 66384),
(283333, 'koKR', '포로 중 몇 명은 아제로스 출신이 아닙니다. 얼마나 많은 세계가 공허의 폭력에 시달린 걸까요?', '', 66384),
(283332, 'koKR', '', '저희가 따라가겠습니다. 렌도레이, 날 따라와라.', 66384),
(283331, 'koKR', '', '지금은 혼자 행동할 때가 아니야!', 66384),
(283330, 'koKR', '세베룸은 제가 쫓겠습니다. 당신과 이 공허의 피조물이 참호를 맡는 걸로 하지요.', '', 66384),
(283329, 'koKR', '', '토렌티아는 참호를 지키고, 세베룸은 요새 상부를 지키고 있더군요.', 66384),
(283328, 'koKR', '', '테르미나스가 자리를 비운 동안에는 부관들이 금고의 출입을 통제하고 있습니다.', 66384),
(283327, 'koKR', '우주는 향연이다, 빛의 존재여. 왜 즐기지 않나?', '', 66384),
(283326, 'koKR', '단순한 굶주림 이상의 목적을 따르는 자도 있다, 짐승아.', '', 66384),
(283325, 'koKR', '나는 주인을 섬기지 않는다. 우리 모두 자기 욕망에 충실할 뿐이지.', '', 66384),
(283324, 'koKR', '공허에 충성 따위는 없다 이건가? 시시하다는 이유로 주인을 배신할 생각을 해?', '', 66384),
(283323, 'koKR', '텅 빈 공백만을 남기려는 거지. 그보다 더 따분한 일이 있겠느냐?', '', 66384),
(283322, 'koKR', '잘아타스는 너희 세상을, 모든 세계를, 심지어 별들까지 삼켜버릴 작정이다.', '', 66384),
(283321, 'koKR', '비정한 우주에서 너희의 밝게 타오르는 투쟁을 지켜보는 건... 진미가 따로 없더군.', '', 66384),
(283320, 'koKR', '목적도 없는 존재지. 모든 공허의 괴물들이 그렇듯이.', '', 66384),
(283319, 'koKR', '나는 열망에서 태어난 존재다.', '', 66384),
(283318, 'koKR', '그렇게까지 돕고 싶은 이유가 뭐지?', '', 66384),
(283316, 'koKR', '포식의 견장을 훔친 뒤, 공결탑에 들어가 폭풍을 약화시켜라. 아, 테르미나스에게 굴욕을 주는 거다.', '', 66384),
(283315, 'koKR', '마침 놈은 여기서 바쁘게 움직이고 있으니, 금고는 무방비겠군.', '', 66384),
(283314, 'koKR', '\"군주\" 테르미나스. 놈이 암연지 성채에 견장을 두고 있지.', '', 66384),
(283313, 'koKR', '그걸 손에 넣으면 공결탑에 들어가 작동을 멈출 수 있다. 그럼 연쇄 작용이 일어나 다른 탑들도 무력화될 거다.', '', 66384),
(283312, 'koKR', '폭풍을 약화시키는 열쇠는 포식의 견장이라는 유물이다.', '', 66384),
(283311, 'koKR', '그래서 소중한 실버문을 날려버릴 만큼의 마력 폭주를 일으키자고? 안전하게 정지시켜야 너희 가엾은 도시도 지킬 수 있다.', '', 66384),
(283310, 'koKR', '왜 공결탑을 정지시키기만 하라는 거지? 안에서부터 파괴해야지.', '', 66384),
(283307, 'koKR', '이리 와라, $p. 너한테 보여줄 게 많다.', '', 66384),
(283306, 'koKR', '내 집이라고 생각해. 그럼 폭풍을 약화시키는 방법을 알려주지.', '', 66384),
(283305, 'koKR', '아, 나머지 일행이 도착했군. 시간이 있었으면 널 저녁상에 올렸을 텐데.', '', 66384),
(283303, 'koKR', '저 괴물을 따라 더러운 소굴까지 가겠단 소립니까?', '', 66384),
(283197, 'koKR', '잘아타스는 압도적이야. 우리 종족은 가망이 없어.', '잘아타스는 압도적이야. 우리 종족은 가망이 없어.', 66384),
(283190, 'koKR', '', '전쟁 북이 울리면 지원군이 중앙 제단으로 모일 거야, 잔.', 66384),
(283179, 'koKR', '', '신성한 불꽃의 가호로 겨우 포식의 군단에 맞서 버텼습니다. 안두인이 부상자들을 치유할 수 있도록 제가 어둠의 물결을 막아냈죠.\n\n이 신성한 장소를 지키고자 다른 분들도 함께해 주셔서 기쁩니다. 제가 도울 수 있는 일이 있을까요?', 66384),
(283177, 'koKR', '반갑습니다, $p 님!\n\n이 어둠과 공허 속에서도 빛은 더욱 강하게 타오르고 있습니다. 언데드인 제 몸엔 언제나 그 고통이 따르지만, 포식의 군단은 저보다도 훨씬 더 그 분노에 취약합니다.', '', 66384),
(283169, 'koKR', '$p 님! 성스러운 빛이 추종자뿐만 아니라 아제로스의 용사님들까지 불렀군요.\n\n포위당해 숫자에서도 밀렸다고 생각했는데, 용사님이 와주신 덕분에 공격을 이어갈 수 있겠습니다!', '', 66384),
(283168, 'koKR', '', '공허의 야수입니다! 조심하세요!', 66384),
(283159, 'koKR', '공허폭풍이 도시를 두려움에 떨게하는 건 그리 이상한 일이 아니에요.', '', 66384),
(283125, 'koKR', '허튼수작이라도 부리면 빛으로 태워버리겠다, 괴물.', '', 66384),
(283123, 'koKR', '대단한 힘과 지혜로군! 네 말을 거스를 만큼 멍청하진 않아.', '', 66384),
(283120, 'koKR', '안 돼! 추격하십시오! ', '', 66384),
(283119, 'koKR', '아, 참으로 달콤한 유혈극이었다! 그런데 이제 슬슬 물러나야겠어.', '', 66384),
(283118, 'koKR', '용사님, 놈의 애완동물을 먼저 처리하십시오! ', '', 66384),
(283117, 'koKR', '아제로스인이라! 아주 훌륭한 전리품이 되겠구나.', '', 66384),
(283113, 'koKR', '놈을 포로로 삼겠다니? 차라리 소멸시켜도 모자란 판에.', '', 66384),
(283112, 'koKR', '', '자기들끼리 속박한다고? 흥미롭네요. 일부는 자발적으로 그렇게 하는 것 같아요. ', 66384),
(283111, 'koKR', '용사님, 이 더러운 괴물들은 우리 상대가 되지 못합니다! ', '', 66384),
(283110, 'koKR', '용사님, 바로 앞입니다! 함께 쓰러뜨립시다!', '', 66384),
(283109, 'koKR', '', '신중해야 해. 나 혼자 잠입하려는 시도는 모두 실패했어.', 66384),
(283108, 'koKR', '신중할 때는 지났습니다. 놈들의 우두머리를 찾아 필요한 정보를 뽑아내야 합니다!', '', 66384),
(283107, 'koKR', '', '여기 오면 안 돼, 아라토르. 공허의 기운이 너무 강력해.', 66384),
(283105, 'koKR', '알레리아. 이 임무의 지휘권은 제게 있습니다. 다만, 당신의 도움은 환영합니다. ', '', 66384),
(283099, 'koKR', '이게 바로 알레리아가 당신을 보호하려 했던 이유입니다, 아라토르. 저 너머의 어둠 때문이지요. ', '', 66384),
(283097, 'koKR', '훨씬 끔찍해... 우리가 텔로그러스의 공허에서 처음 변했을 때보다 더 심각해. 그래도... 그래도 견뎌낼게요, 히에론. ', '', 66384),
(283096, 'koKR', '', '물에 빠져 허우적대는 기분이군요. 그래도 금방 헤엄치는 법을 배울 겁니다. ', 66384),
(283095, 'koKR', '', '에버던! 안 돼! 젠장!', 66384),
(283094, 'koKR', '', '정찰을 해야 해... 그래. 먼저 정찰을...', 66384),
(283093, 'koKR', '먼저 지형을 파악해야 합니다. 갑시다! ', '', 66384),
(283088, 'koKR', '차원문이 열렸습니다. 용기를 내시길... 저편에는 어둠만이 기다리고 있으니까요.', '', 66384),
(283085, 'koKR', '렌도레이는 공허에 맞설 가장 강한 무기가 될지도 모릅니다. 제가 여러분 모두를 지키겠습니다. ', '', 66384),
(283078, 'koKR', '로스락시온 총사령관은 무수한 이계의 전장에서 싸워 온 자요. 그래서 이번 임무의 지휘를 맡겼소. ', '', 66384),
(283077, 'koKR', '용사님, 주문 정렬을 도와주십시오. 혹시 무슨 일이 생기면 우리를 마법학자의 정원으로 되돌려 보내는 고정 장치가 될 겁니다.', '', 66384),
(283076, 'koKR', '그대는 해야 할 일을 했소, 엄브릭. 공허폭풍을 막으려면 안으로 들어가야 하오. ', '', 66384),
(283070, 'koKR', '이 성벽을 다시 보는 것도 참 오랜만이군요.', '', 66384),
(283069, 'koKR', '위험하긴 합니다, 섭정님. 하지만 실버문의 포위를 끝낼 유일한 방법이기도 합니다. ', '', 66384),
(283068, 'koKR', '공허의 유물을 이용해 폭풍을 뚫겠다니... 위험해 보이는군, 엄브릭.', '', 66384),
(283067, 'koKR', '용사님, 폭풍 속으로 들어갈 길을 찾았습니다. 하지만... 쉽지 않아요.', '', 66384),
(283055, 'koKR', '실로 흥미롭군. 계속 기대를 뛰어넘고 있어.', '', 66384),
(283054, 'koKR', '', '넌 힘을 원하지, 데시무스? 잘아타스는 네가 원하는 걸 주지 않겠지만, 쓰러뜨리면 얻을 수도 있어. 우리와 함께하자.', 66384),
(283053, 'koKR', '...들켰나?', '', 66384),
(283052, 'koKR', '', '동맹을 얻을 수 있다면 괜히 적을 만들 필요는 없죠. 데시무스는 보이는 것 이상의 존재예요.', 66384),
(283051, 'koKR', '둘 다 무기를 거두십시오! 싸워야 할 적은 이미 넘쳐납니다!', '', 66384),
(283050, 'koKR', '나는 빛 속에서 다시 태어났다! 너야말로 진실을 보지 못하고 있다!', '', 66384),
(283049, 'koKR', '어둠을 보고 펄쩍 뛰고, 속임수를 멸시해? 참 독특한 나스레짐이로군, 로스락시온.', '', 66384),
(283048, 'koKR', '당신은 성기사입니다, 아라토르. 데시무스를 괴물로 봐야 합니다!', '', 66384),
(283046, 'koKR', '움직여야 합니다!', '', 66384),
(283045, 'koKR', '네놈이 지금까지 우리를 속였겠다! 사라져라, 데시무스!', '', 66384),
(283044, 'koKR', '용사님도 느끼고 있지 않습니까. 곧 닥쳐올 배신을. 무엇을 해야 할지 제가 잘 압니다.', '', 66384),
(283043, 'koKR', '어쩌다 일이 이 지경에 이른 겁니까? 빛의 군대를 이 세상에 불러들이려던 계획은 한 치도 진행되지 못했습니다.', '', 66384),
(283042, 'koKR', '네가 다음에 어떤 폭력을 쏟아낼지 보고 싶군.', '', 66384),
(283041, 'koKR', '너와 윈드러너 모두 대단하군. 기나긴 세월을 여행하며 이렇게 뛰어난 필멸자를 보긴 처음이다.', '', 66384),
(283040, 'koKR', '아스트레, 정신 잃으면 안 돼. 내 손을 잡아.', '', 66384),
(283038, 'koKR', '', '속삭임의 유혹이 점점 강해지지만, 견뎌내야 합니다. 그래야 임무를 완료할 수 있으니까요.', 66384),
(283023, 'koKR', '알겠습니다. 그렇게 하겠습니다.', '', 66384),
(283022, 'koKR', '', '아라토르, 데시무스에게 해가 가지 않도록 반드시 지켜야 해. 우리가 필요한 답은 놈에게 있어. 날 믿어다오.', 66384),
(283021, 'koKR', '어머니, 상처가 너무 큽니다. 지금은 물러나 회복하셔야 합니다.', '', 66384),
(283014, 'koKR', '', '아라토르! 안 돼!', 66384),
(283013, 'koKR', '공허가 너무 강합니다!', '', 66384),
(283012, 'koKR', '', '이젠 답이 없어요! 싸워야 합니다!', 66384),
(283010, 'koKR', '안 돼! 이런... 반드시...!', '', 66384),
(283009, 'koKR', '', '가장 찬란한 빛이 가장 긴 그림자를 드리우노라.', 66384),
(283008, 'koKR', '절대로 용납할 수 없다!', '', 66384),
(283004, 'koKR', '', '안 돼, 로스락시온! 용사님, 시야를 좀 빌려주세요.', 66384),
(283003, 'koKR', '시간이 너무 걸리는군. 비키십시오. 제가 저것들을 박살 내겠습니다.', '', 66384),
(283002, 'koKR', '잘아타스, 네 은근한 협박은 더 듣지 않겠다! 너는 나루를 가져라. 나는 내 몫을 받아 갈 테니!', '', 66384),
(283001, 'koKR', '', '당신의 적들은 빠르게 움직이고 있어요, 살라다르. 늦기 전에 나루를 다시 타락시키려면, 더 서둘러야 할 거예요.', 66384),
(283000, 'koKR', '', '알레리아가 죽어야 한다니 아쉽네요. 그자의 어둠의 나루가 이 나루보다 훨씬 강력한 무기가 될 텐데.', 66384),
(282998, 'koKR', '놈들은 날 막지 못한다! 이번만큼은! 어둠수호병이여, 모두 쳐라!', '', 66384),
(282996, 'koKR', '', '그 열정을 적에게만 쏟아, 로스락시온. 그리고 난 적이 아니라는 걸 잊지 마.', 66384),
(282995, 'koKR', '아라토르, 당신의 어머니와 오만한 사냥개를 주시하십시오. 빛의 손길에서 벗어나게 해서는 안 됩니다.', '', 66384),
(282994, 'koKR', '보십시오! 저 보호막 안에 갇혀 있습니다!', '', 66384),
(282993, 'koKR', '나루에게서 떨어져라, 공허의 피조물아. 너는 그 빛을 받을 자격이 없다.', '', 66384),
(282991, 'koKR', '이대로 두면 안 됩니다. 저도 함께하겠습니다, 로스락시온.', '', 66384),
(282990, 'koKR', '나루를 사로잡았다니요? 순수한 빛의 존재를 저 괴물들에게 넘길 수는 없습니다!', '', 66384),
(282989, 'koKR', '윈드러너 따위는 내가 나루를 공허로 물들이는 걸 막지 못한다! 약속받은 힘은 반드시 내 차지가 되리라!', '', 66384),
(282988, 'koKR', '빛은 반드시 승리합니다. 데시무스가 맞설 힘은 없다시피 할 겁니다.', '', 66384),
(282987, 'koKR', '빛 속에서 불타버려라, 악귀야!', '', 66384),
(282986, 'koKR', '', '그럼 그 여자를 제거하는 게 당신에게도 이득이겠죠? 한참 멋대로 돌아다니게 놔둔 건 당신이니까요.', 66384),
(282985, 'koKR', '네 덫을 내가 못 볼 거라 생각했나? 미드아르가 잘못되면 내 동족이 어떤 위험에 처할지 모른다고 생각했나?', '', 66384),
(282984, 'koKR', '', '살라다르, 참 배은망덕하네요. 제가 귀한 선물을 베풀어 주지 않았던가요? 지배자로서의 자격을 증명할 기회 말이에요.', 66384),
(282983, 'koKR', '이건 약속과 다르지 않느냐! 우린 끝없이 고통받는데, 네 괴물들은 감시만 하고 있지 않나!', '', 66384),
(282982, 'koKR', '무슨 상관입니까? 필요한 것만 챙기고 대장간을 완전히 불태우십시오. 놈들의 비밀도 함께 타버리게 말입니다.', '', 66384),
(282981, 'koKR', '', '잘아타스가 이유 없이 적을 놓아줄 리 없어요. 에테리얼들이 이곳에서 뭘 하고 있는지 알아내 주세요.', 66384),
(282977, 'koKR', '저도 그 말씀을 드리려던 참이었습니다.', '', 66384),
(282976, 'koKR', '', '우리가 용기를 확보하고 방해하겠습니다. 가까이 붙어 있어, 아라토르.', 66384),
(282974, 'koKR', '에테리얼이라. 잘아타스가 놈들을 끌어들인 게 그렇게 오래전 일은 아니지.', '', 66384),
(282970, 'koKR', '', '정찰대가 남쪽에서 에테리얼의 마나괴철로를 발견했습니다. 다만, 놈들이 뭘 꾸미고 있는지는 아직 모릅니다.', 66384),
(282950, 'koKR', '', '하란다르는 위험한 곳일세.', 66384),
(282688, 'koKR', '', '운 좋은 줄 아세요. 그렇게 시간이 지났는데도 당신 집은 압류 안 했다고요, 선스트라이크.', 66384),
(282683, 'koKR', '', '앞으로는 \"깃털 뽑힌 불사조\"에 출입 금지입니다. 안녕히 가세요.', 66384),
(282544, 'koKR', '흠, 비슷하지.\n\n<기드윈이 뒷장으로 넘깁니다. 책에는 기드윈과 타레나가 여러 풍경과 관광지, 선술집에서 찍은 사진이 붙어 있습니다. 각 사진 밑에 짧은 설명이 달려 있습니다.>\n\n그냥 여행 일지이기도 하다네.', '', 66384),
(282531, 'koKR', '아, 그거 말인가. 여기 있네.\n\n<책을 꺼내 아무렇게나 한 장을 펼치는 기드윈>\n\n우리가 주문한 술을 모조리 기록으로 남겼다네... 아니, 기억나는 것만이라도.\n\n<자랑스럽게 한 항목을 가리키는 기드윈>\n\n이 주에는 주량 대결에서 사흘 연속으로 타레나를 이겼지!', '', 66384),
(282529, 'koKR', '부동산 시세 본 적 있소? 난 금리가 낮을 때 이곳을 샀다오. 지금은 모든 게 올라서 가치가 꽤 되오.\n\n하나 우린 늘 여행 중이니 관리하기 어렵소. 기드윈은 집을 팔자고 하더이다.\n\n짧은 기간 동안 임대해도 괜찮겠구려. \"비행 부동산\"이라고 하면 어떻겠소.\n\n아니, 이건 무슨 곡예단 이름 같군. 좀 더 고민해 보겠소.', '', 66384),
(282522, 'koKR', '도와줘서 정말 고맙네, $p. 기념품은 모두 부쳤으니, 이제 집만 정리하면 되겠군.', '', 66384),
(282516, 'koKR', '우린 지금 집을 정리하고 있소. 빚을 갚고 목걸이를 팔았더니, 조금 여윳돈이 생겨 수표로 받았지. 믿어지시오?\n\n<웃음을 터뜨리는 타레나>\n\n아마 물건에 얽힌 내력이 누군가에겐 흥미로웠던 모양이오.', '', 66384),
(282515, 'koKR', '왜 이렇게 두고 갔냐고? 아니면 왜 아무도 압류하지 않았냐고?\n\n<잠시 생각에 잠기는 기드윈>\n\n그 양반이 왜 이 집을 팔지 않았을까? 우린 거의 오지도 않는데. 텅 빈 채로 두고도 그동안 내내 유지비를 내고 있었어.\n\n아무튼 4차 대전쟁이 터졌을 때 우린 도망치듯 떠나야 했네. 청소할 겨를이 있을 리가.\n\n<거미를 흘끗 돌아보는 기드윈>\n\n분명 저 성가신 놈이 우리 물약을 뒤진 게 틀림없네.', '', 66384),
(282512, 'koKR', '난 다 치울 생각은 없네. 외상으로 달아놓은 술값을 치를 만한 것만 찾으면 돼.', '', 66384),
(282498, 'koKR', '어서 가세! 자네 농담도 한잔 걸치고 나면 그나마 참을 만하니까.', '', 66384),
(282497, 'koKR', '흠... 나야 들여보내 줄지도 모르오. 아마 그대는 안 될 것 같군. 키가 작아서.', '', 66384),
(282496, 'koKR', '그래. 여기 오는 것도 참 오래간만이야. 가시 돋친 샘에서 우릴 들여보내 주려나?', '', 66384),
(282495, 'koKR', '아! 참 많은 추억이 담겨 있지. 그리고 우스꽝스러웠던 모험도.', '', 66384),
(282494, 'koKR', '엉망진창이구먼. 그래도 옛날 여행 일지는 찾았네.', '', 66384),
(282492, 'koKR', '기드윈이 못마땅하다는 듯 낮게 중얼거립니다.', '', 66384),
(282491, 'koKR', '그래서 무슨 일이 있었소? 수염에 거미줄이 엉켜 있는데, 기드윈?', '', 66384),
(282490, 'koKR', '', '드디어. 감사해요. 이제 빚은 다 갚으신 걸로 해드리죠.', 66384),
(282487, 'koKR', '여기 있소. 이거면 밀린 외상과... 몇 년 쌓인 이자까지도 넉넉히 갚고도 남을 거요.', '', 66384),
(282408, 'koKR', '공허가 아닌, 오히려 빛 그 자체에 잠식당했습니다. 아무것도 보이지 않았지만... 불처럼 타오르는 힘을 쏟아냈죠. 정신을 차렸을 때 적은 모두 파괴된 뒤였습니다.\n\n죄송합니다, $p 님. 지금은 진정되었습니다. 실버문 주민을 돕기 위해 우리가 할 수 있는 일을 해야 합니다.', '', 66384),
(282366, 'koKR', '뭐? 난 교훈을 얻었네! 끈적한 거미줄엔 언제나 대비해야지.', '', 66384),
(282365, 'koKR', '아, 훨씬 낫구먼.', '', 66384),
(282338, 'koKR', '여기 이 친구가 기드윈이 돈을 찾는 걸 도와줄 거요. 오래 걸리진 않을 것이오.', '', 66384),
(282318, 'koKR', '$p 님, 도움이 필요하십니까?\n\n저도 함께 싸우겠습니다! 힘을 모아 포식의 군단을 몰아내야 합니다!', '$p 님, 도움이 필요하십니까?\n\n저도 함께 싸우겠습니다! 힘을 모아 포식의 군단을 몰아내야 합니다!', 66384),
(282078, 'koKR', '학생처럼 안 생겼는데. 여기서 뭐 하는 거지?', '학생처럼 안 생겼는데. 여기서 뭐 하는 거지?', 66384),
(282077, 'koKR', '지금 정신없는 거 안 보여?', '지금 정신없는 거 안 보여?', 66384),
(282076, 'koKR', '타이테일러가 나 고생하는 것 좀 알아주면 좋겠어... 선임 추종자 II로 승급할 수 있을지도!', '타이테일러가 나 고생하는 것 좀 알아주면 좋겠어... 선임 추종자 II로 승급할 수 있을지도!', 66384),
(282075, 'koKR', '뭐야, 네가 타이테일러의 새 장난감이냐?', '뭐야, 네가 타이테일러의 새 장난감이냐?', 66384),
(282074, 'koKR', '어디서 굴러먹던 놈이 뭘 보자는 거지?', '어디서 굴러먹던 놈이 뭘 보자는 거지?', 66384),
(282073, 'koKR', '지금 정신없는 거 안 보여? 뭐 때문에 온 거야?', '지금 정신없는 거 안 보여? 뭐 때문에 온 거야?', 66384),
(281893, 'koKR', '아, 나루... 설명하기 쉽지는 않지. 이들은 이 세상의 존재가 아니고, 사실 나도 그 기원에 대해 아는 바가 많지 않네. 다만 가장 단순하게 정의를 내려보자면, 나루는 성스러운 빛의 현신이자 자아를 지닌 마력의 존재라고 할 수 있네.\n\n나루와 가장 가까운 동맹은 드레나이일세. 먼 옛날 살게라스가 에레다르의 모성 아르거스에 접근했을 때, 예언자 벨렌은 무언가 잘못되었음을 직감했네. 그리고 도움을 청하는 기도를 올렸고, 이에 응답한 것이 바로 나루였어. 나루는 벨렌과 그 뜻에 동조하는 에레다르를 안전한 곳으로 데려가기로 했네.\n\n이들 에레다르는 나루의 도움을 받아 아르거스를 탈출했지. 이후, 이들은 스스로를 드레나이, 즉 \"추방자들\"이라 부르게 되었고, 나루와 드레나이는 떼려야 뗄 수 없는 동맹이 되었네.', '', 66384),
(281891, 'koKR', '캘타스 선스트라이더는 국왕 아나스테리안 선스트라이더의 외동아들이었지만, 단순한 왕자에 그치지 않았네. 강력한 마법사이기도 해서 달라란을 다스리는 6인의 의회에 들어갈 정도였지. 실제로 캘타스는 시간 대부분을 달라란에서 보냈어.\n\n그러나 3차 대전쟁 때 부왕이 전사하자, 캘타스는 혼자서 종족을 이끄는 책임을 맡게 되었네. 태양샘이 타락에 물든 상황이었기에 파괴할 수밖에 없었고, 귀환 후 살아남은 유민을 모아 스스로를 블러드 엘프라 칭했지. 쓰러져간 형제자매들을 기리는 의미로 말일세.\n\n하지만 안타깝게도, 캘타스는 종족을 구하겠다는 일념으로 인해 결국 더 어두운 길로 빠지고 말았네.', '', 66384),
(281794, 'koKR', '', '이 도시가 갈망하는 힘을 빼앗겠다고? 그렇다면 내 힘을 맛봐라!', 66384),
(281787, 'koKR', '', '이 벌레가!', 66384),
(281780, 'koKR', '여기서 끝내자, 리시엘!', '', 66384),
(281764, 'koKR', '', '실버문이 원하는 한, 지옥 마력을 끝없이 공급할 거다.', 66384),
(281459, 'koKR', '그게 다인가?', '', 66384),
(281458, 'koKR', '이번엔 또 뭐지?', '', 66384),
(281425, 'koKR', '', '놈들을 베어라! 저것들이 따라오면 네 목을 치겠다!', 66384),
(281394, 'koKR', '이건 진정한 패배가 아니오. 스스로 물러나는 것뿐!', '', 66384),
(281393, 'koKR', '안 돼! 이것으로 끝난 게 아니오!', '', 66384),
(281391, 'koKR', '넌 누구지? 어떻게 들어왔어?', '', 66384),
(281390, 'koKR', '', '허술하구나, 자엔. 정리하고 위에서 보자.', 66384),
(281369, 'koKR', '', '살아남으려면 뭐든지 해라!', 66384),
(281368, 'koKR', '', '널 본보기로 삼아 주지.', 66384),
(281223, 'koKR', '', '이게 그렇게 쉬울 줄 알았느냐?', 66384),
(280973, 'koKR', '마법학자의 정원.\n\n저는 이곳에서 젊은 시절을 보냈습니다. 처음으로 주문을 익힌 곳도 이곳이었지요. 한여름 무도회에서 타로파 골드베일과 춤을 췄을 때 느낀 감정은...\n\n<한숨을 내쉬는 엄브릭>\n\n그 시절은 지나갔습니다. 이곳은 변했고, 저 역시 변했습니다. 저와 제 동족은 이제 이곳에 설 자리가 없습니다.\n\n과거를 되돌릴 순 없지요. 렌도레이는 스스로의 전통을, 스스로의 가정을...\n\n그리고 미래를 만들어 나가야 합니다.', '', 66384),
(280968, 'koKR', '<통 옆면이 찌그러져 있습니다. 나무로 된 부분은 부러졌고, 금속 테두리는 일그러져 있습니다. 뚜껑이 단단히 고정되어 있습니다.>', '', 66384),
(280965, 'koKR', '우리 종족의 기억이 살아 있는 곳. 시련과 도전이 기다리는 곳이지.\n\n알른하라의 은총을 누릴 수 있지만, 역으로 파멸을 당할 수도 있다.', '', 66384),
(280963, 'koKR', '오르웨냐는 우리의 율법과 관습을 어겼다. 메아리의 소굴은 네게 우리의 방식을 알려줄 것이고, 스스로를 증명할 기회도 줄 거다.\n\n돌아온다면 알른하라께서 네게 머물 자격을 내리신 거지. 나는 네가 돌아올 거라 기대하지 않지만.', '', 66384),
(280955, 'koKR', '메아리의 소굴은 우리 종족의 기억이 깃든 장소 중 하나다. 선조들의 행적과 시련을 되새김으로써 배우고, 성장하며, 같은 역사를 반복하지 않게 되는 거지.\n\n이 그림들은 그 기억과 시련 속으로 들어가는 관문이다. 견뎌낸다면 하란다르와 우리 종족에 대해 더 깊이 이해하게 될 거다.\n\n돌을 만지면 환영이 발현될 거다. 알른하라의 가호가 함께하길.', '', 66384),
(280860, 'koKR', '', '공허조차도 이 순수한 힘 앞에는 버티지 못한다!', 66384),
(280803, 'koKR', '세월이 흐르면서 영혼 축제에 참여하는 이들이 점점 줄어들었지. 올해는 다들 기억이나 하고 있을까 싶더군.\n\n그래서 자네를 초대한 걸세. 모두의 힘을 모으면, 섬의 판다렌들을 다시 일깨울 수도 있지 않겠나.\n\n만약 이번이 마지막이 된다면, 그 또한 마지막이지. 나는 옛 방식을 고집할 만큼 어리석지 않네. 세상은 변해야 하고, 또 변할 수 있으니까.\n\n리 리는 내색하지 않지만, 누구보다 이 축제를 소중히 여기네. 그래서 나도 마음을 쏟는 거야.', '', 66384),
(280686, 'koKR', '평소보다 분주하군요. 서둘러야 해요.', '', 66384),
(280669, 'koKR', '<당신이 다가가자 축복의 제단이 활성화됩니다.>', '<당신이 다가가자 축복의 제단이 활성화됩니다.>', 66384),
(280628, 'koKR', '<열기구를 타고 스톰윈드로 갈 수 있습니다.>', '', 66384),
(280626, 'koKR', '붉은십자군이 이토록 활개 치고 있을 줄은 몰랐네, $p.\n\n수차례 부침을 겪고도 다시 세력을 키워내는군.', '', 66384),
(280596, 'koKR', '', '하라시르로 가세. 따뜻한 환영은 기대하지 않는 게 좋을 걸세.\n\n할두런의 상태를 확인하고, 출발할 준비가 됐는지 봐주게.', 66384),
(280573, 'koKR', '보면 아시겠지만, 이 일이 적성에 안 맞는 사람도 있습니다.', '', 66384),
(280572, 'koKR', '장비 오작동으로 몇몇 인원이 풀어헤쳐진 우주에 빠졌습니다. 위상 잠수부들을 현실로 데려와 주시겠어요?', '', 66384),
(280528, 'koKR', '골목이 평소보다 더 부산하군요. 눈에 띄지 않게 움직이죠.\n\n밀수 사업을 끝장내려면 부정한 빗물을 추적해야 합니다. 최근 지옥 마력 유동이 늘어난 것에 대해 이 구역의 불량배들이 무언가 알고 있다는 소문이 있습니다.\n\n놈들을 찾아가 수소문해 보세요. 대신 조심해야 합니다. 골목의 쥐떼는 절대 믿을 만한 놈들이 아니니까요.', '', 66384),
(280415, 'koKR', '$p, 자네의 도움은 태양샘에 큰 보탬이 되었네. 하지만 아라토르를 위해 할 일은 아직 더 남아 있지.\n\n망치 주둔지에서 친구를 만나려 하는데, 함께 가주겠나?', '', 66384),
(280389, 'koKR', '<우고우가 놀란 듯 코를 훌쩍이며 잠에서 깨어납니다. 찾아내긴 했지만, 낮잠을 방해한 것 같습니다!>', '', 66384),
(280349, 'koKR', '<다펑이 휘돌며 춤을 춥니다. 당신을 찾아 반가운 것 같습니다!>', '', 66384),
(280340, 'koKR', '', '공허는 우리를 강하게 하지만, 그 대가는 뭘까요?', 66384),
(280227, 'koKR', '', '여기가 어디라고 멋대로 기웃거려? 숨어 있지 말고 나와라!', 66384),
(280214, 'koKR', '미래가 암담하거늘... 정말 운명을 알 각오가 되어 있나?', '미래가 암담하거늘... 정말 운명을 알 각오가 되어 있나?', 66384),
(280009, 'koKR', '쓸모없기는!', '', 66384),
(280008, 'koKR', '완벽해! 보수? 사람들한테 얼굴도장 제대로 찍었잖아!', '', 66384),
(280003, 'koKR', '', '어둠수호병이 주둔지를 버렸군요. 하지만 놈들 성격상 곧 돌아올 겁니다.', 66384),
(279791, 'koKR', '수하 하나를 처리했군요. 잘했습니다. 이제 부정한 빗물로 가죠.\n\n근데 지금 모습 그대로 갔다간 곧바로 쫓겨날 거예요. 다행히 당신을 위해 변장 몇 개를... 챙겨뒀죠.\n\n이걸 착용하고 들어가세요. 밖에서는 제가 암살자들을 막고 있겠습니다.', '', 66384),
(279591, 'koKR', '동물들이 영구적인 상해를 입진 않았군요. 회수해 주셔서 감사합니다.', '', 66384),
(279589, 'koKR', '몇몇 생명체가 생태지구를 빠져나갔습니다. 황원에서는 살아남지 못할 거예요. 지금 당장 회수해 주세요!', '', 66384),
(279487, 'koKR', '늦었잖아. 손님들 기다리는 거 안 보여? 빨리 근무 시작해.', '', 66384),
(279110, 'koKR', '저는... 누님들이 돌아올 때까지 이 전당을 음악으로 채우겠습니다. 고맙습니다, 용사 여러분.', '', 66384),
(279109, 'koKR', '언젠가 누님들도 같은 선택을 할 수 있기를 바라요.', '', 66384),
(279108, 'koKR', '마침내... 이 전당에 머물던 영혼들이 평화를 찾았군요.', '', 66384),
(279102, 'koKR', '저깁니다! 우릴 괴롭히는 잠 못 드는 심장! 제발, 영면을 선사해 주세요.', '', 66384),
(279051, 'koKR', '이 유물로 이 첨탑에 평화를 돌려놓아야 해요. 그러면 누님들이 돌아올지도 모르죠.', '', 66384),
(279050, 'koKR', '해냈어요! 이제 마지막 과업만 남았군요.', '', 66384),
(279049, 'koKR', '알레리아 누님의 정찰 지도가 안에 있어요. 복수심 어린 혼령들을 불러낸 것 같군요. 지도는 꼭 필요합니다.', '', 66384),
(279014, 'koKR', '그럴 만했죠. 호드는 제 목숨을 앗아가고, 우리 고향을 유린했으니까요.', '', 66384),
(279013, 'koKR', '알레리아 누님은 거의 집착에 가까운 기세로 구 호드를 사냥했어요.', '', 66384),
(279011, 'koKR', '자, 이제 마지막 유물이 남았군요.', '', 66384),
(278997, 'koKR', '아름답군요! 베리사 누님이 떠오르네요. 누님도 가족이 위협받을 땐 매서웠죠.', '', 66384),
(278992, 'koKR', '이런. 용매가 제 하프를 훔쳐 간 것 같군요. 싸움 없이는 가까이 다가갈 수 없을 거예요.', '', 66384),
(278991, 'koKR', '제 하프의 잔잔한 선율은 베리사 누님께 이루 말할 수 없는 기쁨을 주었지요. 그 유물이 필요해요.', '', 66384),
(278990, 'koKR', '베리사는 우리 가문의 평화감시자였죠. 누님은 이곳의 정원을 오래도록 돌봤지만, 지금은 황야가 집어삼켰습니다.', '', 66384),
(278985, 'koKR', '자, 다음 유물을 찾으러 가죠.', '', 66384),
(278983, 'koKR', '실바나스는 때때로 허영심이 있었고 찬미받기를 좋아했지만, 숭배받기를 원하지는 않았습니다.', '', 66384),
(278964, 'koKR', '어머니의 활은 한때 실바나스에게 전부와도 같았어요. 제게 필요합니다.', '', 66384),
(278959, 'koKR', '실바나스는 어머니께 받은 활로 훈련했지요. 그런데 언데드 광신도들이 침입해, 그 활과 소지품들을 약탈하려 하고 있어요.', '', 66384),
(278952, 'koKR', '실바나스는 순찰대 사령관직을 원한 적 없었지만, 그 임무에 모든 것을 바쳤습니다... 자신의 목숨까지도요.', '', 66384),
(278951, 'koKR', '순찰대 사령관은 날카롭고 굳건했지만, 평화감시자는 평정을 지켰지요. 어떤 길을 선택하시겠어요?', '', 66384),
(278948, 'koKR', '누님이 마지막으로 이 전당을 찾았지만, 고향도, 유대도 모두 저버리고 말았어요. 우리가 이곳의 영혼들을 달랜다면, 다시 돌아올지도 모르죠.', '', 66384),
(278747, 'koKR', '제대로 싸우는 거 맞아?', '제대로 싸우는 거 맞아?', 66384),
(278746, 'koKR', '도망치는 건 금지라고!', '도망치는 건 금지라고!', 66384),
(278738, 'koKR', '싸워라! 싸워라! 싸워라!', '싸워라! 싸워라! 싸워라!', 66384),
(278737, 'koKR', '야! 당장 안 오냐?!', '야! 당장 안 오냐?!', 66384),
(278091, 'koKR', '납작하게 만들어 주마!', '', 66384),
(278090, 'koKR', '오늘의 일기 예보. 폭발을 동반한 흐림!', '', 66384),
(278089, 'koKR', '빗발치는 고통에서 허덕여라!', '', 66384),
(278085, 'koKR', '내 기계는 사유 재산이야!', '', 66384),
(278082, 'koKR', '더 이상 봐주지 않는다!', '', 66384),
(278080, 'koKR', '친구들에게 인사하라고!', '', 66384),
(278079, 'koKR', '이리 들어와! 가만히 서 있으라고 돈 주는 거 아니야!', '', 66384),
(278077, 'koKR', '시간 얼마 없다, 이 훼방꾼들아!', '', 66384);
INSERT INTO `broadcast_text_locale` (`ID`, `locale`, `Text_lang`, `Text1_lang`, `VerifiedBuild`) VALUES
(278076, 'koKR', '십 초 준다. 하나... 둘... 열!', '', 66384),
(277728, 'koKR', '여기 앉아서 보니까 네놈들 다 한주먹거리 같은데?', '', 66384),
(277722, 'koKR', '철권통치란 이런 거다!', '', 66384),
(277720, 'koKR', '갤리윅스가 서명한 구렁 소유 증서도 있어... 잠깐. 갤리웍스라고 써놨네? 아니다. 다 무슨 상관이야!', '', 66384),
(277719, 'koKR', '언더마인의 모든 것은 나 대지주의 소유다. 심지어 이 귀여운 모자까지도!', '', 66384),
(277712, 'koKR', '이봐! 내 변호사가 연락할 거다!', '', 66384),
(273690, 'koKR', '난 이 앞의 작은 강에서 수영을 배웠어.\n\n<아이사를 향해 장난스러운 미소를 짓는 지>\n\n훌륭한 스승을 뒀거든.', '', 66384),
(273689, 'koKR', '꼬마 우낏들이 거북이 경주 본다!\n\n너 바나나 많이 줬다. 우리 호젠 기쁘다, 기쁘다.\n\n<잠시 멈추고 다음 단어를 신중히 고르는 족장>\n\n너. 고맙다.', '', 66384),
(272879, 'koKR', '', '저기 보세요! 샹 시 수련장이에요!', 66384),
(272766, 'koKR', '돌아온 걸 환영한다, $c.\n\n흑요석 수호병단이 요람에서 실종된 동족을 찾고 있다. \n\n우리가 잠들었을 때와 지금 그대가 발을 딛고 있는 세상은 많이 다르다. 흑요석 수호병단은 아제로스를 양분하는 진영 중 하나인 얼라이언스의 일원이 됐지. \n\n그대의 의견에 간섭할 생각은 없어. 하지만 마음에 들 거다.', '', 66384),
(271219, 'koKR', '이걸 우리가 어떻게 다 옮겨?', '이걸 우리가 어떻게 다 옮겨?', 66384),
(271218, 'koKR', '과일은 안 돼! 축제에 써야 한단 말이야!', '과일은 안 돼! 축제에 써야 한단 말이야!', 66384),
(271217, 'koKR', '이쪽이네!', '이쪽이네!', 66384),
(271216, 'koKR', '작물에 손대지 마!', '작물에 손대지 마!', 66384),
(271215, 'koKR', '도와주게! 포위당했어!', '도와주게! 포위당했어!', 66384),
(271202, 'koKR', '양배추는 안 돼!', '양배추는 안 돼!', 66384),
(268910, 'koKR', '최근에 발견한 걸 엉뚱한 데 놓은 것 같습니다. 나중에 얘기 좀 할 수 있을까요?', '', 66384),
(267595, 'koKR', '', '서 있기만 하려니 피곤해. 토석인들이 싸우겠다는데 싸우게 두지. 이 만남의 목적을 이해하지 못하겠군.', 66384),
(264061, 'koKR', '', '오래는 못 버틸 것 같아요...', 66384),
(264059, 'koKR', '', '<숨소리>... 잠깐 숨 돌릴 시간이 필요해요...', 66384),
(262886, 'koKR', '', '내가 하겠다.', 66384),
(262676, 'koKR', '수레 중 하나가 광산을 떠나고 있다. 러피오스의 손아귀에 넘어가지 않도록 조심해라!', '', 66384),
(262675, 'koKR', '수레 하나만 훔치면 될 줄 알았어, 러피오스? 한심하기는!', '', 66384),
(262669, 'koKR', '해방자는 이 광석을 가질 자격이 없다. 너희 수레부터 기계 대변자의 것 아니더냐, 러피오스!', '', 66384),
(262657, 'koKR', '러피오스의 수하들이 수레를 가득 채웠군. 수레를 탈취해 화물을 빼돌려라!', '', 66384),
(262615, 'koKR', '형편없군.', '', 66384),
(262502, 'koKR', '광산 수레를 호위하고, 중앙에 있는 수정을 확보하는 데 집중해라. 실패는 용납하지 않아.', '', 66384),
(262501, 'koKR', '광산 수레에 바짝 붙어서 철로 중심에 있는 빛나는 수정을 챙기면 돼. 얼른 움직여라!', '', 66384),
(262496, 'koKR', '어둠이 있으라.', '', 66384),
(260596, 'koKR', '보나 마나 해방자 놈들은 저 귀중한 재료를 낭비하기만 할 거다. 그나마 빈손으로 떠나지 않아서 다행이군.', '', 66384),
(260594, 'koKR', '놀라운 성적이로군. 이 재료는 기계 대변자들이 좋은 곳에 쓸 거다.', '', 66384),
(260583, 'koKR', '이곳은 귀중한 재료를 채취하는 깊은광혈 협곡이다. 당신들 임무는 러피오스보다 먼저 가능한 한 많은 재료를 확보하는 거야.', '', 66384),
(260475, 'koKR', '광산에 수정이 있군! 우즈잭스가 도착하기 전에 챙겨라!', '', 66384),
(260467, 'koKR', '미안, 우즈잭스! 이 광석 수레는 해방자가 접수한다!', '', 66384),
(260466, 'koKR', '다들 수고했다. 우즈잭스의 하수인 놈들도 우리 수레를 함부로 건드리면 어떻게 되는지 알았을 거다!', '', 66384),
(260464, 'koKR', '우즈잭스가 채석장 밖으로 수레를 옮기고 있군. 우리가 빼앗자!', '', 66384),
(260463, 'koKR', '수레 한 대가 가득 찼군! 목적지에 도착해야 해!', '', 66384),
(260458, 'koKR', '역대급으로 많이 챙겨 나온 건 아니지만, 이 정도면 충분해. 고생 많았다.', '', 66384),
(260457, 'koKR', '수고했다! 이 정도면 카즈 알가르에서 웬만한 것들은 몽땅 수리할 수 있겠군.', '', 66384),
(260449, 'koKR', '깊은광혈 협곡에 온 것을 환영한다, 친구들! 오늘의 할 일은 말이지. 우즈잭스보다 먼저 자원과 보석을 최대한 긁어모으는 거다.', '', 66384),
(257598, 'koKR', '의지로 저항하고 있어요...', '', 66384),
(257597, 'koKR', '', '그만! 어둠이... 아파... 그만해!', 66384),
(251876, 'koKR', '일단 이 정도면 됐어요, 조수님! 일단 이번 발견을 연구한 다음에 돌아갈 거예요.', '', 66384),
(250925, 'koKR', '무언가 사악한 존재가 코볼트를 따라 이곳까지 왔어요. 양초를 이용해 어둠을 막더군요. \n\n양초의 불빛에서 너무 멀어지면 온몸의 힘이 빠져나갈 겁니다. 어떻게 알았냐고요, 저도 알고 싶진 않았네요.', '', 66384),
(250919, 'koKR', '코볼트는 항상 우리 체계에 오작동을 일으켰지만, 지하묘지를 공격할 만큼 대담한 적은 없었습니다.\n\n이곳에 있는 유물들을 노리는 것 같습니다. 정지를 선택한 사람들에게는 큰 의미가 있는 귀중한 물건들이죠.\n\n다만 우리의 보물 창고는 우리에게 별다른 가치가 없습니다... 비논리적으로 비치긴 하지만요. 우리가 소중히 여기기로 선택한 것이 아니라 주어진 물건으로 채워져 있죠. 유물을 되찾아오면 그 안에 있는 것을 드리겠습니다.', '', 66384),
(250436, 'koKR', '그냥 숨기나 하시오, 메레디.', '', 66384),
(250435, 'koKR', '', '얼마나 숙여요? 엎드려요?', 66384),
(250432, 'koKR', '숙이시오!', '', 66384),
(235955, 'koKR', '반갑네, 황천군주.\n\n우리 흑마법사가 이런 영예로운 행사에 초대받는 일은 흔치 않네. 아제로스와 호드를 안전하게 지키는 데 일조하지만, 어둠 속에 머무르며 제대로 된 인정도 못 받는 생활에 익숙했지.\n\n이런 변화는 자네 덕분이겠지.', '', 66384),
(214427, 'koKR', '너희 죄악은 영원토록 울려 퍼질 것이다.', '', 66384);
